# --------------------------------------------------------------------------- #
#  _do_rerun — defined EARLY (right after imports) on purpose.                 #
#                                                                              #
#  Streamlit runs this script top-to-bottom. Several tab helpers call          #
#  _do_rerun() while rendering — feature_menu (menu navigation) and the        #
#  documentation template picker (quick-start bundle buttons) — and those tabs #
#  execute long before the middle of the file. If _do_rerun were defined       #
#  further down, those call sites would raise NameError at click time and the  #
#  surrounding view would collapse to its fallback. Keeping the definition up  #
#  here guarantees every caller can see it.                                    #
# --------------------------------------------------------------------------- #
def _do_rerun():
    """Streamlit rerun that works across versions."""
    try:
        st.rerun()
    except Exception:
        try:
            st.experimental_rerun()
        except Exception:
            pass

# --------------------------------------------------------------------------- #
#  Central auto-instrumentation of ENGAGEMENT.
#
#  Many tabs never called ax.engage() manually, so their adoption funnel sat at
#  0% even when people clearly used them. Rather than hand-instrument ~250
#  scattered inputs, we wrap Streamlit's numeric-entry widgets once here: the
#  first time a user puts a number into whichever tab is active, it counts as
#  engagement for that feature (deduped once-per-session inside auto_engage).
#  Wrapping is idempotent and fully guarded — telemetry can never break a
#  widget or change its return value.
# --------------------------------------------------------------------------- #
def _ax_engage_cb(_feature, _user_cb, _user_args, _user_kwargs):
    """on_change/on_click handler: Streamlit calls this ONLY when the widget's
    value actually changes (a real user edit), not on every rerun — so it's an
    accurate engagement signal free of the cross-tab contamination that plagues
    compare-on-render. Fires engagement for the feature the widget belongs to,
    then calls through to any user-supplied callback."""
    try:
        if _feature:
            _axn.auto_engage(_feature, action="input")
    except Exception:
        pass
    if _user_cb is not None:
        return _user_cb(*(_user_args or ()), **(_user_kwargs or {}))


def _ax_wrap_input(_orig):
    def _wrapped(*args, **kwargs):
        # Attach an on_change callback that fires engagement for the ACTIVE tab
        # only when the user genuinely changes this widget. Streamlit fires
        # on_change on real edits, not on rerun, so this is contamination-free.
        # A key is required to attach the callback; when the widget has none we
        # mint one that is STABLE across reruns (feature + label + widget type),
        # so Streamlit keeps the widget's state correctly. Keyless widgets have
        # no external session_state consumer, so adding a key is safe.
        try:
            _af = st.session_state.get("_ax_last_active_tab")
            if _af:
                if not kwargs.get("key"):
                    _lbl = kwargs.get("label")
                    if _lbl is None:
                        for _a in args:
                            if isinstance(_a, str):
                                _lbl = _a
                                break
                    kwargs["key"] = f"_axk_{_af}_{_orig.__name__}_{_lbl}"
                _user_cb = kwargs.get("on_change")
                _user_args = kwargs.get("args")
                _user_kwargs = kwargs.get("kwargs")
                kwargs["on_change"] = _ax_engage_cb
                kwargs["args"] = (_af, _user_cb, _user_args, _user_kwargs)
                kwargs["kwargs"] = None
        except Exception:
            pass
        return _orig(*args, **kwargs)
    return _wrapped


def _ax_wrap_button(_orig):
    def _wrapped(*args, **kwargs):
        _res = _orig(*args, **kwargs)
        # A button click is a deliberate action on the active tab.
        #  • Always count it as engagement (the user did something here).
        #  • If the tab was ALREADY engaged this session (the user had entered/
        #    changed inputs first), treat the click as running those inputs —
        #    i.e. a completion. This captures "input a number, then click Run"
        #    on tabs that compute inline with no spinner or chart (e.g.
        #    Integration's mass/CG push). require_engaged=True keeps pure-nav
        #    buttons (reset, discard) on a fresh tab from fabricating a
        #    completion, since those fire before any input engagement.
        try:
            if _res is True:
                _af = st.session_state.get("_ax_last_active_tab")
                if _af:
                    _already = _axn.has_engaged(_af)
                    _axn.auto_engage(_af, action="click")
                    if _already:
                        _axn.auto_complete(_af, action="run",
                                           require_engaged=True)
        except Exception:
            pass
        return _res
    return _wrapped


def _ax_wrap_download(_orig):
    def _wrapped(*args, **kwargs):
        _res = _orig(*args, **kwargs)
        # A download click means a useful artifact was produced and taken away —
        # a genuine completion for the active tab (also back-fills engagement).
        try:
            if _res is True:
                _af = st.session_state.get("_ax_last_active_tab")
                if _af:
                    _axn.auto_complete(_af, action="export", require_engaged=False)
        except Exception:
            pass
        return _res
    return _wrapped


def _ax_wrap_result(_orig):
    def _wrapped(*args, **kwargs):
        # A result render (chart/plot) means the entered numbers ran and
        # produced output. Count it as completion for the active tab, but ONLY
        # if the user already engaged this tab this session (require_engaged) —
        # so a tab that draws a default chart on open, before any input, doesn't
        # fabricate a completion. Fully guarded; never affects the render.
        try:
            _af = st.session_state.get("_ax_last_active_tab")
            if _af:
                _axn.auto_complete(_af, action="result", require_engaged=True)
        except Exception:
            pass
        return _orig(*args, **kwargs)
    return _wrapped

if not getattr(st, "_ax_input_patched", False):
    # Most widgets in this app are called as CONTAINER methods —
    # `col.number_input(...)`, `tab.button(...)`, `_ac[0].number_input(...)` —
    # which resolve through the DeltaGenerator CLASS, so patching the class
    # covers all of those. BUT `st.number_input(...)` and friends are methods
    # already BOUND to the root container at import time, so they do NOT go
    # through the class lookup — those we must patch on the `st` module too.
    # We therefore patch BOTH: the class (for container calls) and the module
    # (for direct st.* calls).
    from streamlit.delta_generator import DeltaGenerator as _AxDG

    _ax_input_names = ("number_input", "slider", "selectbox", "radio",
                       "multiselect", "select_slider", "checkbox", "toggle",
                       "text_input", "text_area", "date_input", "time_input",
                       "color_picker")
    for _mname in _ax_input_names:
        if hasattr(_AxDG, _mname):
            setattr(_AxDG, _mname, _ax_wrap_input(getattr(_AxDG, _mname)))
        # module-level st.<widget> is a separately-bound reference — patch it too
        if hasattr(st, _mname):
            setattr(st, _mname, _ax_wrap_input(getattr(st, _mname)))
    # Buttons: a click is deliberate engagement (and completion if already
    # engaged) on the active tab.
    if hasattr(_AxDG, "button"):
        _AxDG.button = _ax_wrap_button(_AxDG.button)
    if hasattr(st, "button"):
        st.button = _ax_wrap_button(st.button)
    # Download/export: a genuine completion — a useful result was produced.
    if hasattr(_AxDG, "download_button"):
        _AxDG.download_button = _ax_wrap_download(_AxDG.download_button)
    if hasattr(st, "download_button"):
        st.download_button = _ax_wrap_download(st.download_button)
    # Result render (chart/plot) = the entered numbers ran and produced output.
    # For reactive tabs (EV, Cost, Roll, Tire, …) that recompute on input change
    # without a spinner, this is the "the number ran" completion signal, gated
    # on prior engagement so a default chart on open doesn't fabricate one.
    if hasattr(_AxDG, "plotly_chart"):
        _AxDG.plotly_chart = _ax_wrap_result(_AxDG.plotly_chart)
    if hasattr(st, "plotly_chart"):
        st.plotly_chart = _ax_wrap_result(st.plotly_chart)

    st._ax_input_patched = True

# --------------------------------------------------------------------------- #
#  Central auto-instrumentation of COMPLETION.
#
#  "Completion" = the entered numbers actually ran and produced a result. Heavy
#  tabs run their compute inside `st.spinner(...)`, so entering (and exiting)
#  a spinner is a reliable, universal "a computation ran" signal. We wrap it to
#  auto_complete the active feature once per session. auto_complete also
#  back-fills engagement, so completions can never sit below engagements.
#  Fully guarded; the spinner still behaves exactly as before.
# --------------------------------------------------------------------------- #
if not getattr(st, "_ax_spinner_patched", False):
    import contextlib as _ax_ctxlib
    _ax_orig_spinner = st.spinner

    @_ax_ctxlib.contextmanager
    def _ax_spinner(*args, **kwargs):
        with _ax_orig_spinner(*args, **kwargs):
            yield
        # runs only if the spinner body completed without raising — i.e. the
        # computation finished and a result was produced.
        try:
            _af = st.session_state.get("_ax_last_active_tab")
            if _af:
                _axn.auto_complete(_af, action="run", require_engaged=True)
        except Exception:
            pass

    st.spinner = _ax_spinner
    st._ax_spinner_patched = True

# --------------------------------------------------------------------------- #
#  Cached compute layer.
#
#  Streamlit re-executes this entire script top-to-bottom on EVERY widget
#  interaction, and it runs the body of every `with tab:` block regardless of
#  which tab is visible. Without caching, that meant the thermal warm-up
#  integration (~30 s) and the GGV envelope (~2 s) were recomputed on every
#  rerun — that is why the app "took forever". These wrappers memoize the heavy
#  physics on their actual inputs, so they only recompute when something that
#  affects the result changes. Args are kept hashable (dicts/tuples/floats) so
#  cache_data can key on them.
# --------------------------------------------------------------------------- #

@st.cache_data(show_spinner=False, ttl=120, max_entries=5)
def _cached_thermal_warmup(coeffs, fnomin, enable_mu, cold_pa,
                           alpha_deg, Fz, v_x, gamma_deg,
                           ambient_c, track_c, duration_s, dt):
    _lt = tire_mod.PacejkaLateral(coeffs=dict(coeffs), FNOMIN=fnomin)
    _tp = thermal_mod.ThermalParams(enable_mu_feedback=bool(enable_mu),
                                    cold_pressure_pa=float(cold_pa))
    _tm = thermal_mod.ThermalTireModel(lateral=_lt, params=_tp)
    return thermal_mod.simulate_warmup(
        model=_tm, alpha_deg=float(alpha_deg), Fz=float(Fz), v_x=float(v_x),
        gamma_deg=float(gamma_deg), ambient_c=float(ambient_c),
        track_c=float(track_c), duration_s=float(duration_s), dt=float(dt))


# A .kicad_pcb can be multi-MB, and parsing it into the segment/via/footprint
# mesh is the expensive part. Keying the parse on the *text itself* means the
# whole process shares one parsed board per unique file: if three people open
# the same board (or one person triggers ten reruns) it is parsed once and the
# rest are cache hits. cache_data returns a copy each call, so no session ever
# mutates another's board. max_entries bounds the RAM this can hold and evicts
# LRU; ttl lets stale boards fall out. The hard size guard below keeps a single
# pathological upload from being parsed at all. Text is the cache key (hashable),
# so this is a module-level function, never a closure over a widget.
_PCB_MAX_BYTES = 24 * 1024 * 1024      # 24 MB — larger than any real FSAE board

@st.cache_data(show_spinner=False, ttl=600, max_entries=6)
def _cached_parse_kicad(text: str):
    """Parse once per unique board text, shared across sessions. Returns the
    PcbBoard, or raises ValueError (surfaced to the user) on a bad file."""
    from suspension import pcb_doctor as _pdr
    return _pdr.parse_kicad_pcb(text)


# Frame Planner: the triangulation / load-path audit walks every bay of the
# frame graph on every rerun (st.tabs executes the tab body regardless of which
# tab is visible). The audit depends ONLY on the frame dict, so key it on the
# canonical JSON of that dict: geometry edits recompute, every other widget
# interaction anywhere in the app is a cache hit and re-renders UI only.
@st.cache_data(show_spinner=False, ttl=600, max_entries=8)
def _cached_frame_audit(frame_json: str):
    _g = tf_mod.FrameGraph.from_dict(json.loads(frame_json))
    return {"quads": _g.untriangulated_quads(),
            "landings": _g.midspan_landings(),
            "tris": _g.triangulated_nodes()}


# RAM watchdog: below the soft limit this is one cheap file read; as the session
# approaches the 1 GB Community-Cloud ceiling it sheds Streamlit's data cache
# (recomputable results only) so a viewer never hits the "over its resource
# limits" page. Runs once per rerun, near the top. (First touch of `_mem`
# imports only suspension.mem_utils via the lazy layer — not the whole stack.)
_mem.memory_guard()

