def metric(label, value, unit="", cls=""):
    # Convert the displayed number + unit into the user's chosen unit system.
    # The model stays metric; only this presentation layer converts. Compound
    # units (e.g. "°/10mm", "N/mm @35") get bespoke handling.
    if unit in ("°/10mm",) or str(unit).startswith("N/mm"):
        value, unit = units_mod.convert_compound(str(value), unit)
    else:
        value = units_mod.convert_value_str(str(value), unit)
        unit = units_mod.label(unit)
    return f"""<div class="metric"><span class="k">{label}</span>
    <span class="v {cls}">{value}<span class="u"> {unit}</span></span></div>"""


def umetric(container, label, value_num, unit="", *, fmt="{:.0f}", **kwargs):
    """Unit-aware wrapper around Streamlit's native ``.metric``. Pass the metric
    (SI) NUMBER and its metric unit; this converts BOTH to the active unit system
    before display, so native metric widgets honour the imperial toggle instead
    of staying stuck on metric. ``container`` is the column/st object to draw on.

    Example: ``umetric(_mt[0], "Rotor mass", m_kg, "kg", fmt="{:.0f}")`` shows kg
    in metric and lb in US automatically.
    """
    try:
        disp = units_mod.from_metric(float(value_num), unit)
        u = units_mod.label(unit)
        val_str = fmt.format(disp)
        text = f"{val_str} {u}".strip()
    except Exception:
        text = f"{value_num} {unit}".strip()
    return container.metric(label, text, **kwargs)


def uconv_series(values, unit, *, delta=False):
    """Convert a whole metric data series to the active unit system, for plotting.
    Pair with ``units_mod.ulabel`` on the axis title so the curve and its axis
    always agree. ``delta=True`` for difference quantities (gradients) so the
    temperature offset is not applied."""
    fn = units_mod.from_metric_delta if delta else units_mod.from_metric
    try:
        return [fn(float(v), unit) for v in values]
    except Exception:
        return list(values)


def uval(value_num, unit, *, fmt="{:.0f}", delta=False):
    """Return a ``"<converted_value> <label>"`` string for an inline f-string.

    Converts a metric (SI) number and its unit to the active system, so dynamic
    captions/markdown that splice a value next to a hardcoded unit honour the
    imperial toggle. ``delta=True`` for differences (no temperature offset)."""
    fn = units_mod.from_metric_delta if delta else units_mod.from_metric
    try:
        disp = fn(float(value_num), unit)
        return f"{fmt.format(disp)} {units_mod.label(unit)}"
    except Exception:
        return f"{value_num} {unit}"


def _install_unit_aware_messages():
    """Route every message-channel string (metric/caption/error/warning/
    success/info) through units_mod.ulabel + usentence at render time, on every
    container (st.*, columns, sidebar, expanders).

    Why a choke point instead of 200 per-site edits: the convention (uval /
    uconv_series / unum) is applied at ~350 sites but has drifted at dozens of
    older message strings ("… 180 MPa > 120 MPa …", fade-test °C summaries) and
    would drift again. usentence converts ONLY metric-token+number pairs and
    ulabel only bare metric tokens, and both are no-ops in metric mode — so
    already-converted strings (e.g. built with uval → "507 lb") pass through
    untouched, half-converted strings get their remaining metric halves fixed,
    and deliberate metric references without numbers stay as written.

    Failure-safe: if a future Streamlit rename breaks the patch, the except
    leaves the original methods in place — displays fall back to metric,
    exactly today's behaviour.
    """
    if st.session_state.get("_unit_msgs_patched"):
        return
    try:
        from streamlit.delta_generator import DeltaGenerator as _DG

        def _conv(x):
            if isinstance(x, str):
                return units_mod.usentence(units_mod.ulabel(x))
            return x

        def _wrap(fn, nstr):
            def _f(self, *a, **kw):
                a = tuple(_conv(v) for v in a[:nstr]) + a[nstr:]
                for k in ("label", "value", "delta", "body", "help"):
                    if isinstance(kw.get(k), str):
                        kw[k] = _conv(kw[k])
                return fn(self, *a, **kw)
            return _f

        # (method, how many leading positional args are display strings)
        for name, nstr in (("metric", 3), ("caption", 1), ("error", 1),
                           ("warning", 1), ("success", 1), ("info", 1)):
            orig = getattr(_DG, name, None)
            if orig is not None and not getattr(orig, "_unit_aware", False):
                w = _wrap(orig, nstr)
                w._unit_aware = True
                setattr(_DG, name, w)
        st.session_state["_unit_msgs_patched"] = True
    except Exception:
        pass       # fall back to unpatched (metric) displays


_install_unit_aware_messages()


def unum(container, label_with_unit, lo, hi, val, unit, *, step=None, key=None,
         fmt=None, **kw):
    """Unit-aware ``number_input``. The label keeps its parenthesised unit and
    switches it with the toggle (via ``ulabel``). The min/max/value/step convert
    to the active unit for display, and the result converts back to metric so
    downstream code always sees SI.

    If ``key`` is provided, a shadow session-state key tracks the metric value
    and the unit system it was stored in. When the user switches units, the
    widget key is overwritten with the re-converted value *before* the widget
    instantiates, so it doesn't mis-interpret old display-unit state.
    """
    lbl = units_mod.ulabel(label_with_unit)
    d_lo = units_mod.from_metric(float(lo), unit)
    d_hi = units_mod.from_metric(float(hi), unit)
    d_val = units_mod.from_metric(float(val), unit)
    if key is not None:
        shadow = f"_u_{key}"
        cur_sys = units_mod.current_system()
        if shadow in st.session_state:
            old_metric, old_sys = st.session_state[shadow]
            if old_sys != cur_sys:
                d_val = units_mod.from_metric(old_metric, unit)
                st.session_state[key] = d_val
            elif key in st.session_state:
                d_val = float(st.session_state[key])
    extra = {}
    if step is not None:
        extra["step"] = units_mod.from_metric_delta(float(step), unit)
    if fmt is not None:
        extra["format"] = fmt
    if key is not None:
        extra["key"] = key
    # Safety net: a stored/default value outside [lo,hi] makes Streamlit's
    # number_input raise ("value N is greater than max_value M"). Clamp the
    # displayed value into range so an out-of-range stored number can never
    # crash the widget; downstream range/rules checks flag it separately.
    d_val = min(max(d_val, d_lo), d_hi)
    if key is not None and key in st.session_state:
        try:
            st.session_state[key] = min(max(float(st.session_state[key]), d_lo), d_hi)
        except (TypeError, ValueError):
            pass
    result = container.number_input(lbl, d_lo, d_hi, value=d_val, **extra, **kw)
    metric_result = units_mod.to_metric(float(result), unit)
    if key is not None:
        st.session_state[f"_u_{key}"] = (metric_result, units_mod.current_system())
    return metric_result


def uslider(container, label_with_unit, lo, hi, val, unit, *, step=None,
            key=None, **kw):
    """Unit-aware ``slider``. Same idea as ``unum`` but for sliders."""
    lbl = units_mod.ulabel(label_with_unit)
    d_lo = units_mod.from_metric(float(lo), unit)
    d_hi = units_mod.from_metric(float(hi), unit)
    d_val = units_mod.from_metric(float(val), unit)
    if key is not None:
        shadow = f"_u_{key}"
        cur_sys = units_mod.current_system()
        if shadow in st.session_state:
            old_metric, old_sys = st.session_state[shadow]
            if old_sys != cur_sys:
                d_val = units_mod.from_metric(old_metric, unit)
                st.session_state[key] = d_val
            elif key in st.session_state:
                d_val = float(st.session_state[key])
    extra = {}
    if step is not None:
        extra["step"] = units_mod.from_metric_delta(float(step), unit)
    if key is not None:
        extra["key"] = key
    result = container.slider(lbl, d_lo, d_hi, d_val, **extra, **kw)
    metric_result = units_mod.to_metric(float(result), unit)
    if key is not None:
        st.session_state[f"_u_{key}"] = (metric_result, units_mod.current_system())
    return metric_result


# --------------------------------------------------------------------------- #
#  Generic-topology hardpoint editing
# --------------------------------------------------------------------------- #
# The double-wishbone path edits a `Hardpoints` set. EVERY other topology compiles
# to a `Mechanism` with a dict of named points (ground / free / carried). We let
# the user edit those point coordinates live too: build the base mechanism, apply
# the user's per-topology coordinate overrides, then re-compile and solve. Edits
# are stored per topology so each architecture keeps its own geometry.

# Friendly labels + role grouping. Point names come from topologies.py; this maps
# the terse internal names to something a student can read. Anything not listed
# falls back to the raw name, so new templates still edit fine.
