def _from_links_default():
    """A raw double-wishbone expressed through the free-form `from_links` builder.
    Gives the 'Experimental / free-form' topology a sensible, solvable starting
    geometry (it ships without an example(), so selecting it used to crash)."""
    chassis = {"ufi": [-100, 240, 280.8], "uri": [130, 240, 299.2],
               "lfi": [-110, 200, 122.5], "lri": [140, 200, 117.5],
               "tri": [100, 230, 160]}
    free = {"uo": [12, 540, 300], "lo": [-5, 575, 110], "tro": [90, 560, 150]}
    carried = {"wc": ("upright", [0, 600, 228]), "cp": ("upright", [0, 605, 0])}
    links = [("ufi", "uo", "upper_fore"), ("uri", "uo", "upper_aft"),
             ("lfi", "lo", "lower_fore"), ("lri", "lo", "lower_aft"),
             ("tri", "tro", "tie_rod")]
    return topo_mod.from_links(
        chassis, free, carried, links, carrier_body="upright",
        carrier_defining=["uo", "lo", "tro"], wheel_center="wc",
        contact_patch="cp", drive_point="wc", steer_point="tro",
        static_camber=-1.3, label="experimental")


def build_base_mechanism(topo_key):
    """Fresh, unedited Mechanism for a topology key (no user overrides applied)."""
    if topo_key == "from_links":
        return _from_links_default()
    return topo_mod.example(topo_key)


def mechanism_point_coords(topo_key):
    """name -> (role, [x,y,z]) for every editable point of the base mechanism."""
    mech = build_base_mechanism(topo_key)
    out = {}
    for nm, p in mech.points.items():
        out[nm] = (p.role, [float(c) for c in np.asarray(p.pos, float).ravel()])
    return out


def render_generic_point_editor(topo_key):
    """Live x/y/z editor for every point of a non-wishbone topology. Stores the
    edited coordinates in st.session_state['topo_hp'][topo_key]; returns that
    dict (name -> [x,y,z]). Re-seeds from the template the first time a topology
    is opened, and offers a reset."""
    base = mechanism_point_coords(topo_key)
    store = st.session_state.setdefault("topo_hp", {})
    if topo_key not in store:
        store[topo_key] = {nm: list(xyz) for nm, (role, xyz) in base.items()}
    coords = store[topo_key]
    # Heal any drift between a saved project and the current template (new/removed
    # points) so the editor never KeyErrors.
    for nm, (role, xyz) in base.items():
        coords.setdefault(nm, list(xyz))
    for nm in list(coords.keys()):
        if nm not in base:
            del coords[nm]

    if st.button("↺ Reset to template", key=f"topo_reset_{topo_key}",
                 width='stretch'):
        store[topo_key] = {nm: list(xyz) for nm, (role, xyz) in base.items()}
        st.rerun()

    # group by role for a readable layout
    by_role = {"ground": [], "free": [], "carried": []}
    for nm, (role, _xyz) in base.items():
        by_role.get(role, by_role["free"]).append(nm)
    for role in ("ground", "free", "carried"):
        names = by_role[role]
        if not names:
            continue
        st.markdown(f"###### {_ROLE_HEADERS[role]}")
        _u_len = units_mod.label("mm")
        _c_step = 0.1 if units_mod.is_us() else 2.0
        _c_fmt = "%.2f" if units_mod.is_us() else "%.1f"
        for nm in names:
            label = _POINT_LABELS.get(nm, nm)
            with st.expander(f"{label}  ·  {nm}", expanded=False):
                v = coords[nm]
                cols = st.columns(3)
                nv = []
                for i, ax in enumerate("xyz"):
                    _disp = cols[i].number_input(
                        f"{ax} ({_u_len})",
                        value=units_mod.from_metric(float(v[i]), "mm"), step=_c_step,
                        key=f"topo_{topo_key}_{nm}_{ax}", format=_c_fmt)
                    nv.append(units_mod.to_metric(_disp, "mm"))
                coords[nm] = nv
    return coords


def mechanism_with_overrides(topo_key, coords):
    """Build the base mechanism for the topology and move its points to the
    user-edited coordinates, ready to compile + solve."""
    mech = build_base_mechanism(topo_key)
    for nm, xyz in (coords or {}).items():
        if nm in mech.points:
            mech.points[nm].pos = np.asarray(xyz, float)
    mech._compiled = False
    return mech


PROJECT_PATH = os.path.join(os.getcwd(), "project.json")


def _active_workspace_ctx():
    """The WorkspaceContext set by the sign-in gate (auth_ui.require_workspace),
    or None when Supabase isn't configured (legacy local single-user mode).
    Reads from session_state so every store constructor — cached or ad-hoc —
    sees the same tenant binding for this session."""
    return st.session_state.get("_kx_workspace_ctx")


def _make_store():
    """Single construction point for the project store. Tenant-aware:

      * Workspace context present (user signed in, workspace chosen)
            -> a store whose ENTIRE persistence surface is scoped to that
               workspace: writes are stamped workspace_id, reads filter by it,
               and Supabase RLS re-enforces membership on the server. This is
               the Option-B tenant wall; the anon key alone can no longer read
               or write project rows.
      * No context (Supabase not configured)
            -> the legacy local JSON store, unchanged, for laptops and tests.

    Every call site goes through here so no path can accidentally fall back to
    the old anon-key ProjectStore(PROJECT_PATH) once tenancy is active.
    """
    ctx = _active_workspace_ctx()
    if ctx is not None:
        from suspension.workspace import workspace_store
        return workspace_store(ctx, root=os.getcwd())
    return project_mod.ProjectStore(PROJECT_PATH)


def get_store():
    """Return the project store, cached in session_state for the life of the
    session.

    Why cache instead of reconstructing from disk every rerun: on ephemeral hosts
    (Streamlit Cloud) the working directory can be read-only or wiped, so a
    `save()` to the local JSON file may be rejected. If we rebuilt the store from
    disk on the next rerun, the trace/wire just added would vanish and the PCB and
    harness checks would forever say "nothing to check". Holding the live store in
    session_state means edits persist for the session regardless of whether the
    backend write succeeded; `save()` still runs for cross-session persistence
    where the backend allows it.

    The cache is keyed by the active workspace id, so switching workspaces in the
    picker rebuilds the store against the new tenant rather than serving the
    previous tenant's cached data.
    """
    ctx = _active_workspace_ctx()
    ws_key = ctx.workspace_id if ctx is not None else "__local__"
    cached = st.session_state.get("_project_store")
    if cached is None or st.session_state.get("_project_store_ws") != ws_key:
        _switching = ("_project_store_ws" in st.session_state
                      and st.session_state.get("_project_store_ws") != ws_key)
        cached = _make_store()
        st.session_state["_project_store"] = cached
        st.session_state["_project_store_ws"] = ws_key
        # Integration ledger travels WITH the project now. Seed the session
        # copy from the loaded store; on a workspace SWITCH with no saved
        # ledger, reset to blank rather than leaking the previous tenant's
        # declarations into this one.
        _saved_led = getattr(cached, "ledger", {}) or {}
        if _saved_led:
            st.session_state.ledger = dict(_saved_led)
        elif _switching:
            st.session_state.ledger = interfaces_mod.blank_ledger().as_dict()
    return cached


# --------------------------------------------------------------------------- #
#  Store-agnostic CAD-library accessors.
#
#  The Team CAD library reads the shared store via cad_files_for()/cad_subsystems().
#  Those methods live on ProjectStore — but on a deployment where project.py is an
#  older revision than this app file, the method may be ABSENT, and calling it at
#  module render time raises a redacted AttributeError that takes the whole page
#  down (this exact crash: `_cad_store.cad_files_for(None)`). These helpers make
#  the render path independent of the store's method surface: they read the raw
#  `cad_files` list defensively and do the filtering/sorting here, so the CAD
#  library degrades to "empty" rather than crashing when the store is stale or
#  half-built. Behaviour matches ProjectStore.cad_files_for / .cad_subsystems.
# --------------------------------------------------------------------------- #
def _store_cad_files(store, subsystem=None):
    """Library entries newest-first, optionally filtered by subsystem tag
    (case-insensitive). Works whether or not the store defines cad_files_for.
    Never raises."""
    # Prefer the store's own method when it exists and works (keeps a single
    # source of truth on stores that have it); fall back to reading the list.
    meth = getattr(store, "cad_files_for", None)
    if callable(meth):
        try:
            return meth(subsystem)
        except Exception:
            pass
    files = list(getattr(store, "cad_files", None) or [])
    if subsystem:
        s = str(subsystem).strip().lower()
        files = [c for c in files if (getattr(c, "subsystem", "") or "").lower() == s]
    return sorted(files, key=lambda c: getattr(c, "ts", ""), reverse=True)


def _store_cad_subsystems(store):
    """Unique, sorted subsystem tags in the library. Never raises."""
    meth = getattr(store, "cad_subsystems", None)
    if callable(meth):
        try:
            return meth()
        except Exception:
            pass
    tags = set()
    for c in (getattr(store, "cad_files", None) or []):
        t = (getattr(c, "subsystem", "") or "").strip()
        if t:
            tags.add(t)
    return sorted(tags)


def publish_ledger(led_dict):
    """THE way to update the Integration ledger: set the session copy AND
    persist it with the project, so declarations survive restarts and show up
    in Project history ("suspension: wheel_rate 28 → 31 by lead@…"). Before
    this, the ledger lived only in session_state and evaporated whenever
    Streamlit Cloud recycled the process."""
    st.session_state["ledger"] = led_dict
    _s = get_store()
    _s.ledger = dict(led_dict)
    return save_store(_s)


