def _freetext_hook(freetext: str, tool_id: str) -> str:
    """Return EVERY contextual sentence whose keywords the freetext note
    matches for this tool_id (joined, de-duplicated, table order), else "".
    A note like "rear bump steer is a mess and the camber curve drifts" gets
    both the bump-steer and the camber hook — nothing applicable is dropped.
    Case-insensitive.  Pure Python, zero imports beyond builtins."""
    if not freetext:
        return ""
    ft_lower = freetext.lower()
    hits: list[str] = []
    for keywords, tid, advice in _FREETEXT_KEYWORDS:
        if tid not in (tool_id, "any"):
            continue
        if any(kw in ft_lower for kw in keywords) and advice not in hits:
            hits.append(advice)
    return " ".join(hits)


def _freetext_matched_tools(freetext: str) -> list[str]:
    """Every tool id the freetext note's keywords touch, in canonical tab
    order.  Drives the note-aware toolbox expansion: if the note mentions
    something a tool covers, that tool joins the briefing even when no
    selected goal would have included it.  Pure Python."""
    if not freetext:
        return []
    ft_lower = freetext.lower()
    matched = {tid for keywords, tid, _adv in _FREETEXT_KEYWORDS
               if tid != "any" and any(kw in ft_lower for kw in keywords)}
    return [t for t in _FULL_ORDER if t in matched]


def _freetext_tokens(freetext: str) -> list[str]:
    """Lower-cased content words (len >= 4) from the note, for marking which
    feature bullets relate to what the member actually typed.  A tiny
    stop-list keeps glue words from lighting every bullet.  Pure Python."""
    if not freetext:
        return []
    _stop = {"with", "that", "this", "have", "from", "when", "what",
             "about", "really", "please", "very", "into", "onto", "then",
             "than", "there", "their", "they", "some", "much", "mess",
             "issue", "problem", "still", "just", "like", "want", "need",
             "keeps", "keep", "gets", "goes", "during", "every", "also"}
    _word, _out = [], []
    for ch in freetext.lower():
        if ch.isalnum() or ch == "-":
            _word.append(ch)
        else:
            if _word:
                w = "".join(_word)
                if len(w) >= 4 and w not in _stop and w not in _out:
                    _out.append(w)
                _word = []
    if _word:
        w = "".join(_word)
        if len(w) >= 4 and w not in _stop and w not in _out:
            _out.append(w)
    return _out


def _brief_goal_options(roles):
    """(key, label, tab_ids) goal options for the selected subteam blend."""
    _opts, _seen = [], set()
    for _r in (roles or ["everyone"]):
        for _g in _ROLE_GOALS.get(_r, []):
            if _g[0] not in _seen:
                _seen.add(_g[0])
                _opts.append(_g)
    if not _opts:
        _opts = list(_ROLE_GOALS["everyone"])
    return _opts


def _build_briefing(roles, purpose_key, goal_keys, freetext, style="visual"):
    """Compile the questionnaire answers into the briefing payload."""
    _opts = {k: (lab, ids) for k, lab, ids in _brief_goal_options(roles)}
    _goal_keys = [k for k in (goal_keys or []) if k in _opts] or list(_opts)[:1]
    _tabs = []
    for _k in _goal_keys:
        for _t in _opts[_k][1]:
            if _t not in _tabs:
                _tabs.append(_t)
    for _t in _BRIEF_PURPOSE_MAP.get(purpose_key, ("", [], ""))[1]:
        if _t not in _tabs:
            _tabs.append(_t)
    # The optional note expands the toolbox: any tool whose keywords the note
    # matches joins the plan, so a member who types "pack overheats in
    # endurance" gets the accumulator, EV and lap-time tools even if none of
    # the tapped goals would have pulled them in. Tracked separately so the
    # briefing can say WHY each of these tools is in the plan.
    _ft = (freetext or "").strip()
    _note_tabs = [t for t in _freetext_matched_tools(_ft) if t not in _tabs]
    _tabs.extend(_note_tabs)
    # Handover pair always closes the plan; keep it out of the core list.
    _core = [t for t in _FULL_ORDER
             if t in _tabs and t not in ("integration", "validation")]
    return {
        "roles": list(roles or ["everyone"]),
        "purpose": purpose_key,
        "goals": [(_k, _opts[_k][0]) for _k in _goal_keys],
        "active_goal_keys": _goal_keys,          # NEW — carried for feature lookup
        "freetext": _ft,
        "note_tabs": _note_tabs,                 # NEW — tools the note added
        "style": style,
        "core_tabs": _core,
    }


def _render_brief_questionnaire(roles):
    """Questions 2 & 3 of the landing questionnaire (Q1 = the picker above)."""
    st.markdown(
        '<div style="max-width:860px;margin:1.2rem auto 0;">'
        '<div style="font-size:1.05rem;font-weight:600;">'
        '🧭 Two quick taps and KinematiK builds your toolkit</div>'
        '<p class="hint" style="line-height:1.5;margin-top:.2rem;">'
        'You\'ll get exactly which tools to open, in what order, why each one — '
        'and why doing it here first means ANSYS / MATLAB / ADAMS only ever '
        '<b>validate</b> your design instead of debugging your inputs. '
        'Or skip straight in.</p></div>', unsafe_allow_html=True)

    _pu_labels = [lab for _k, lab, _ids, _l in _BRIEF_PURPOSES]
    _go_opts = _brief_goal_options(roles)
    _go_labels = [lab for _k, lab, _ids in _go_opts]

    _pills = getattr(st, "pills", None)
    st.markdown("**2 · What are you using KinematiK for?**")
    if _pills:
        _pu_sel = st.pills("purpose", _pu_labels, selection_mode="single",
                           default=_pu_labels[0], key="kk_brief_purpose",
                           label_visibility="collapsed")
    else:
        _pu_sel = st.radio("purpose", _pu_labels, horizontal=True,
                           key="kk_brief_purpose", label_visibility="collapsed")
    st.markdown("**3 · What's the goal?** *(pick as many as apply)*")
    # If the member changes subteams mid-questionnaire the goal options change;
    # drop any previously-picked labels that no longer exist so the widget
    # never sees an out-of-options value.
    _go_kw = {"key": "kk_brief_goals", "label_visibility": "collapsed"}
    if "kk_brief_goals" in st.session_state:
        _prev = st.session_state["kk_brief_goals"]
        _prev = _prev if isinstance(_prev, list) else [_prev]
        st.session_state["kk_brief_goals"] = [v for v in _prev
                                              if v in _go_labels]
    else:
        _go_kw["default"] = _go_labels[:1]
    if _pills:
        _go_sel = st.pills("goal", _go_labels, selection_mode="multi", **_go_kw)
    else:
        _go_sel = st.multiselect("goal", _go_labels, **_go_kw)
    _ft = st.text_input("Anything specific? (optional)",
                        key="kk_brief_freetext",
                        placeholder="e.g. our rear bump steer is a mess / "
                                    "pack overheats in endurance …")

    # Q4 — are you a visual thinker? Drives whether the briefing renders a
    # live concept visual (graph / 3D) under every recommended tool, and
    # whether plain-English glosses are added for newcomers.
    _STYLE_OPTS = [
        ("visual",  "👁️ Yes — show me graphs & 3D"),
        ("numbers", "🔢 No — just give me the numbers"),
        ("new",     "🌱 I'm brand new — visuals + plain English"),
    ]
    _st_labels = [lab for _k, lab in _STYLE_OPTS]
    st.markdown("**4 · Are you a visual thinker?**")
    if _pills:
        _st_sel = st.pills("style", _st_labels, selection_mode="single",
                           default=_st_labels[0], key="kk_brief_style",
                           label_visibility="collapsed")
    else:
        _st_sel = st.radio("style", _st_labels, horizontal=True,
                           key="kk_brief_style", label_visibility="collapsed")

    _b1, _b2 = st.columns([1.6, 1.0])
    if _b1.button("⚡ Build my toolkit & enter", type="primary",
                  use_container_width=True):
        _pu_key = next((k for k, lab, _i, _l in _BRIEF_PURPOSES
                        if lab == _pu_sel), _BRIEF_PURPOSES[0][0])
        _sel = _go_sel if isinstance(_go_sel, list) else [_go_sel]
        _go_keys = [k for k, lab, _i in _go_opts if lab in (_sel or [])]
        _st_key = next((k for k, lab in _STYLE_OPTS if lab == _st_sel),
                       "visual")
        st.session_state["kk_briefing"] = _build_briefing(
            roles, _pu_key, _go_keys, _ft, style=_st_key)
        st.session_state["kk_briefing_open"] = True
        st.session_state["kk_entered"] = True
        st.session_state["kk_brief_pending"] = False
        st.rerun()
    if _b2.button("Skip — take me straight in", use_container_width=True):
        st.session_state["kk_entered"] = True
        st.session_state["kk_brief_pending"] = False
        st.rerun()


def _render_briefing_panel():
    """Post-entry: the compiled briefing, pinned above the tabs, dismissible."""
    _bf = st.session_state.get("kk_briefing")
    if not _bf:
        # Skipped or dismissed — keep a one-tap way back, tucked in a corner.
        _bc = st.columns([1.0, 3.2])[0]
        if _bc.button("🧭 Get my mission briefing",
                      help="Answer three one-tap questions and get a personal "
                           "plan: which tools, in what order, and why."):
            st.session_state["kk_brief_pending"] = True
            st.session_state["kk_entered"] = False
            st.rerun()
        return
    _open = bool(st.session_state.pop("kk_briefing_open", False))
    with st.expander("🧭 Your mission briefing — what to use, in what order, "
                     "and why", expanded=_open):
        _pu = _BRIEF_PURPOSE_MAP.get(_bf.get("purpose"))
        _names = " + ".join(_ROLE_LABELS.get(r, r).split(" / ")[0]
                            for r in _bf.get("roles", []))
        st.markdown(f"**{_names}** · " + (_pu[0] if _pu else ""))
        if _pu:
            st.markdown(_pu[2])
        if _bf.get("freetext"):
            _nt = [t for t in _bf.get("note_tabs", []) if t in _TAB_META]
            _nt_msg = ""
            if _nt:
                _nt_names = ", ".join(
                    f"{_TAB_META[t][0]} {_TAB_META[t][1]}" for t in _nt)
                _nt_msg = (f" Because of it, {_nt_names} "
                           f"{'joins' if len(_nt) == 1 else 'join'} your "
                           "toolbox below — look for the 💬 badge.")
            st.caption(f"Your words: “{_bf['freetext']}” — keep that in mind as "
                       "you work through the plan below; the Validation tab is "
                       "where you'll pin it down as a formal check." + _nt_msg)
        st.markdown("**Goals:** " + " · ".join(
            f"*{lab}*" for _k, lab in _bf.get("goals", [])))
        _style = _bf.get("style", "visual")
        if _style == "new":
            st.info("🌱 **New here? Perfect.** Every tool below comes with a "
                    "plain-English line and a live picture of the physics. "
                    "Nothing you click in KinematiK can break anything — "
                    "every value has a sensible default, so play freely.")
        st.divider()

        # Collect all active goal keys once, outside the inner function.
        _active_goals = _bf.get("active_goal_keys", [])
        _freetext = _bf.get("freetext", "")

        def _brief_tool_block(_n, _tid):
            """One recommended tool: header / what / plain-English / why / vs /
            goal-specific features / freetext hook / visual."""
            _em, _lab = _TAB_META[_tid]
            _need, _why, _vs = _BRIEF_TOOLS[_tid]
            _cat = _CAT_LABEL.get(_ID_CATEGORY.get(_tid, ""), "")

            # --- header + what-you-do-here ---
            _hdr = f"**{_n}. {_em} {_lab}**  ·  find it under **{_cat}**"
            if _tid in _bf.get("note_tabs", []):
                _hdr += "  ·  💬 *in your toolbox because of your note*"
            _parts = [_hdr, _need]

            # --- plain-English gloss for newcomers ---
            if _style == "new" and _tid in _BRIEF_SIMPLE:
                _parts.append(f"🌱 *In plain English:* {_BRIEF_SIMPLE[_tid]}")

            # --- strategic why + vs ---
            _parts.append(f"**Why you need it:** {_why}")
            _parts.append(
                f"> **Why here, not MATLAB/ANSYS/OptimumK etc.:** {_vs}")

            # --- feature deep-dive: goal-specific first, full list otherwise
            # Collect every feature bullet that applies to any active goal for
            # this tool, de-duplicating across multiple goals.
            _feat_seen: set[str] = set()
            _feat_lines: list[str] = []
            for _gk in _active_goals:
                for _feat in _BRIEF_GOAL_FEATURES.get((_gk, _tid), []):
                    if _feat not in _feat_seen:
                        _feat_seen.add(_feat)
                        _feat_lines.append(_feat)

            # No goal-tailored copy for this (goal, tool) combination — the
            # handover pair, purpose-added tabs and note-added tools land
            # here.  Fall back to the tool's COMPLETE feature list so every
            # rendered block always covers every applicable feature.
            _feat_hdr = ("**What this tool does for your goal — "
                         "feature by feature:**")
            if not _feat_lines:
                _feat_lines = list(_BRIEF_TOOL_FEATURES.get(_tid, []))
                _feat_hdr = "**Everything this tool does for you:**"

            if _feat_lines:
                # Star the bullets that relate to what the member typed in
                # the optional note, so their own words visibly steer the
                # briefing down to the feature level.
                _toks = _freetext_tokens(_freetext)
                _starred = False
                _rendered = []
                for _f in _feat_lines:
                    _fl = _f.lower()
                    if _toks and any(_t in _fl for _t in _toks):
                        _rendered.append(f"- ⭐ {_f}")
                        _starred = True
                    else:
                        _rendered.append(f"- {_f}")
                _parts.append(_feat_hdr)
                # Render as a tight bullet list inline in the markdown block.
                _parts.append("\n".join(_rendered))
                if _starred:
                    _parts.append("*⭐ = relates directly to your note.*")

            # --- freetext contextual hook ---
            _hook = _freetext_hook(_freetext, _tid)
            if _hook:
                _parts.append(f"💬 *Your note:* {_hook}")

            st.markdown("\n\n".join(_parts))

            # --- live concept visual (visual / new modes) ---
            if _style in ("visual", "new"):
                # Lazy import + full guard: a visual can never block the text.
                try:
                    from suspension.brief_visuals import concept_figure
                    _fig, _cap = concept_figure(_tid)
                    if _fig is not None:
                        st.plotly_chart(
                            _fig, width="stretch",
                            key=f"brief_fig_{_tid}",
                            config={"displaylogo": False,
                                    "displayModeBar": False})
                        # RAM hygiene: Streamlit has serialized the figure;
                        # drop the Python-side object immediately so 23
                        # figures never coexist with the tab bodies below.
                        try:
                            _mem.release_figure(_fig)
                        except Exception:
                            pass
                        _fig = None
                        if _cap:
                            st.caption(_cap)
                except Exception:
                    pass

        for _i, _tid in enumerate(_bf.get("core_tabs", []), start=1):
            if _tid not in _TAB_META or _tid not in _BRIEF_TOOLS:
                continue
            _brief_tool_block(_i, _tid)
        # The handover pair always closes the plan.
        _n0 = len(_bf.get("core_tabs", []))
        for _j, _tid in enumerate(("integration", "validation"), start=_n0 + 1):
            _brief_tool_block(_j, _tid)
        st.divider()
        st.markdown(
            "**The point of all this:** the most expensive error class isn't a "
            "bad simulation — it's a wrong input reaching a good simulator. "
            "Iterate here (a change costs seconds, not a meshing afternoon), "
            "let Integration keep every subteam's numbers consistent, run the "
            "Validation handover — and then open ANSYS / ADAMS / MATLAB "
            "**once**, to confirm a design you already trust. "
            "⚠️ Always validate with the full-fidelity tools before "
            "manufacturing; KinematiK gets you to the right question, they "
            "give you the right answer.")
        _c1, _c2 = st.columns(2)
        if _c1.button("🔁 Retake the questionnaire", use_container_width=True):
            st.session_state["kk_brief_pending"] = True
            st.session_state["kk_entered"] = False
            st.rerun()
        if _c2.button("✕ Dismiss briefing", use_container_width=True):
            st.session_state.pop("kk_briefing", None)
            st.rerun()
    # One sweep after the panel: reclaim figure arrays before tab bodies run.
    try:
        _mem.maybe_collect(force=True)
    except Exception:
        pass


_team_keys = [k for k in _BLENDABLE if k != "everyone"]
_default = [r for r in _roles if r in _team_keys]

_pcar, _pctl = st.columns([1.0, 1.05], gap="large")

with _pctl:
    st.markdown("#### Who are you on the team?")
    st.caption("Pick your subteam(s) — the parts you own light up on the car. "
               "Drag the car to spin it. Blend as many subteams as you wear.")
    _picked = st.multiselect(
        "Your subteam(s)",
        _team_keys,
        default=_default,
        format_func=lambda k: _ROLE_LABELS[k],
        label_visibility="collapsed",
        placeholder="Pick your subteam(s) — blend as many as you own",
        disabled=_show_all,
        help="Choose one or more subteams. Their tabs are combined and shown up "
             "front; everything else tucks into “⋯ More tools”. Own brakes *and* "
             "electronics? Pick both. Leave empty to just see the shared tabs. "
             "“All tabs” overrides this with the full 21-tab view.")
    _picked_norm = _normalize_roles(_picked)
    if not _show_all and _picked_norm != _roles:
        st.session_state.kk_roles = _picked_norm
        if _has_picked:
            st.session_state.kk_entered = True   # a real choice was made
        else:
            # LANDING FLOW: don't drop straight into the tabs. Picking a
            # subteam is question 1 of the mission briefing — reveal the two
            # remaining one-tap questions below (always skippable) so the
            # member enters with a personal "use this, here's why" plan.
            st.session_state.kk_brief_pending = True
        _roles = _picked_norm
        st.rerun()

    # Colour each selection chip to its subteam's team colour (same palette as
    # the on-car labels), so "Brakes" reads orange, "Electrics" blue, etc. —
    # not Streamlit's default amber. Chips render in the order the user picked
    # them, so we target them by nth-of-type and recolour per selected role.
    if _picked and not _show_all:
        _chip_rules = []
        for _ix, _rk in enumerate(_picked, start=1):
            _bg = _ROLE_COLOR.get(_rk, "#8d99a6")
            # Target the nth tag chip. baseweb renders each selected value as a
            # [data-baseweb="tag"] sibling in pick order, so nth-of-type maps 1:1
            # onto _picked. Recolour background + border to the team colour.
            _sel = (f'[data-testid="stMultiSelect"] [data-baseweb="tag"]'
                    f':nth-of-type({_ix})')
            _chip_rules.append(
                f'{_sel}{{background:{_bg}!important;border-color:{_bg}!important;}}')
        # Dark, readable text + matching close-button "×" on every coloured chip
        # (the team colours are bright, so near-black foreground reads best).
        _chip_rules.append(
            '[data-testid="stMultiSelect"] [data-baseweb="tag"],'
            '[data-testid="stMultiSelect"] [data-baseweb="tag"] *'
            '{color:#0b0d10!important;font-weight:600!important;}')
        _chip_rules.append(
            '[data-testid="stMultiSelect"] [data-baseweb="tag"] svg'
            '{fill:#0b0d10!important;stroke:#0b0d10!important;}')
        st.markdown("<style>" + "".join(_chip_rules) + "</style>",
                    unsafe_allow_html=True)

    if _show_all:
        st.caption("Showing all 22 tabs")
    elif _roles == ["everyone"]:
        st.caption("Showing shared tabs only")
    else:
        _names = " + ".join(_ROLE_LABELS[r].split(" / ")[0] for r in _roles)
        st.caption(f"Showing **{_names}** + shared tabs")

    # --- analytics: start the usage-telemetry session (fire-and-forget) ----- #
    # Records foot traffic, individual use, latency, errors, retention and the
    # hours-saved ROI automatically. No-ops with no Supabase configured, and can
    # be killed entirely via the KINEMATIK_ANALYTICS=off secret.
    #
    # Two identities, on purpose:
    #   session_id  — minted fresh every browser SESSION, so EVERY logon (incl.
    #                 a returning user) produces a new session_start event.
    #   visitor_id  — durable per BROWSER (cookie, read server-side), so a
    #                 returning visitor is recognised across visits even if they
    #                 never type their name. This is what makes retention / return
    #                 counts correct rather than every visit looking brand-new.
    try:
        # Durable visitor id — resolved SERVER-SIDE and SYNCHRONOUSLY on the
        # very first render (see suspension/visitor_id.py for design notes):
        #   1. request cookie (st.context.cookies)  -> returning visitor
        #   2. ?kvid= query param                   -> legacy carry-over
        #   3. ip+ua fingerprint (st.context)       -> first visit / no cookie
        #   4. minted uuid                          -> last resort
        # Whatever resolves is persisted browser-side (cookie + localStorage)
        # by a tiny fire-and-forget JS snippet — with NO page reload.
        #
        # WHY THE REWRITE: the old scheme resolved the id in the browser and
        # carried it back via ?kvid= + window.location.reload(). That reload
        # tore down the WebSocket and booted a SECOND Streamlit session on
        # every fresh visit — the app visibly loaded twice, and analytics
        # logged two session_starts under two DIFFERENT visitor_ids (fp-/ses-
        # in the doomed pre-reload session, ls- in the reloaded one),
        # permanently double-counting every new user. The CookieManager
        # component added yet another rerun of its own. Both are gone. The id
        # is now known BEFORE session_start fires, so the wait-N-renders
        # deferral is gone too and the event always carries a durable id.
        from suspension.visitor_id import resolve_visitor_id as _rvid
        _vid, _vid_kind = _rvid(st)
        if _vid:
            _axn.set_visitor_id(_vid)
            st.session_state["_ax_resolved_vid"] = _vid
            st.session_state["_ax_resolved_vid_kind"] = _vid_kind

        _ax_subteam = (_roles[0] if _roles and _roles != ["everyone"]
                       else "unknown")
        # is_new_member is best-effort: true only on the very first run of THIS
        # browser session (a fresh visit). Cross-visit "new vs returning" is
        # derived properly in SQL from visitor_id, not from this flag.
        # `source` records HOW this session arrived, recorded truthfully at
        # write time and never collapsed here — merging is a read-time choice,
        # so the raw distinction stays recoverable:
        #   "invite"  — this session redeemed a workspace invite link. It may be
        #               an existing organic user OR someone genuinely new; the
        #               event does NOT claim which. Don't read "invite" as "new".
        #   "organic" — arrived without an invite token (direct visit / bookmark
        #               / shared URL that isn't a ?join= link).
        # For a blended headcount, COALESCE at query time; for a credible
        # adoption story, report the breakdown rather than the merged total. Any
        # claim like "this term's invitees were all prior organic users" is an
        # interpretation — keep it as an annotation beside the numbers, not a
        # transformation baked into the records where it can't be checked.
        if not st.session_state.get("_ax_returning", False):
            _axn.init(member=st.session_state.get("_ax_member"),
                      subteam=_ax_subteam,
                      is_new_member=True,
                      source="invite" if st.session_state.get("_ax_invite_join")
                             else "organic")
            st.session_state["_ax_returning"] = True
            # Auto-recover any events buffered locally during a past DB outage,
            # once per session, without needing a manual button click.
            try:
                _axn.auto_replay_once()
            except Exception:
                pass
    except Exception:
        pass

    if st.button("Show all tabs" if not _show_all else "Back to focus mode",
                 use_container_width=True,
                 help="Toggle between your focused (blended) tab set and the full "
                      "21-tab view."):
        st.session_state.kk_show_all = not _show_all
        st.session_state.kk_entered = True
        st.session_state.kk_brief_pending = False
        st.rerun()

    # Explicit "just browsing" entry so an EMPTY subteam pick is a deliberate
    # choice (shared tabs only), not the "haven't chosen yet" state. Only shown
    # while the member hasn't entered yet.
    if not _has_picked:
        if st.button("Just looking — show me the shared tabs",
                     use_container_width=True,
                     help="Enter with the shared tabs only; you can pick a "
                          "subteam any time to pull your own tools up front."):
            st.session_state.kk_roles = ["everyone"]
            st.session_state.kk_entered = True
            st.session_state.kk_brief_pending = False
            st.rerun()

with _pcar:
    # Union the 3D subsystems owned by the currently selected roles. When "All
    # tabs" is on, or nothing real is picked, pass None so the whole car shows
    # at full brightness rather than ghosting everything.
    _glow = set()
    if not _show_all:
        for _r in _roles:
            _glow |= _ROLE_TO_3D.get(_r, set())
    _hl = (_glow or None)

    try:
        # Build a VehicleParams the same way the Model tab does, so the picker
        # car is sized to *this* team's wheelbase/track. Fall back to defaults
        # if state isn't populated yet.
        try:
            _vp_pick_kwargs = {
                k: v for k, v in st.session_state.get("vp", {}).items()
                if k in VehicleParams.__dataclass_fields__}
            _vp_pick = VehicleParams(**_vp_pick_kwargs)
        except Exception:
            _vp_pick = VehicleParams()
        # Build kwargs defensively: only pass show_cg if the installed
        # build_full_car_figure actually accepts it. This keeps the picker
        # working even if a deployment has an older fullcar3d.py that predates
        # the show_cg parameter (otherwise we'd hit a TypeError and the whole
        # preview would fall back to "unavailable").
        _car_kwargs = dict(vp=_vp_pick, highlight_subsystem=_hl, height=340)
        try:
            import inspect as _inspect
            if "show_cg" in _inspect.signature(
                    fullcar_mod.build_full_car_figure).parameters:
                _car_kwargs["show_cg"] = False
        except Exception:
            pass
        _fig_pick = fullcar_mod.build_full_car_figure(**_car_kwargs)
        _fig_pick.update_layout(
            margin=dict(l=0, r=0, t=0, b=0),
            showlegend=False,
            paper_bgcolor="rgba(0,0,0,0)",
        )
        # Float a bright label on each lit subteam, anchored at the centroid of
        # the parts it owns (exposed by build_full_car_figure as
        # .subsys_centroids). One label per selected role — not per mesh — so a
        # four-corner subsystem like Suspension gets a single tag, not four.
        # Bright accent hues (not the car's dark body colours) keep the text
        # legible against the matte tub.
        # Labels use the shared team-colour palette (_ROLE_COLOR), the same
        # source the dropdown chips read, so the picker is colour-consistent.
        _ROLE_LABEL_COLOR = _ROLE_COLOR
        # subsys_centroids() only exists in newer fullcar3d.py; if a deployment
        # has an older copy, skip the floating labels rather than crash.
        if hasattr(fullcar_mod, "subsys_centroids"):
            _cents = fullcar_mod.subsys_centroids(_fig_pick)
        else:
            _cents = {}
        for _r in _roles:
            _parts = _ROLE_TO_3D.get(_r, set())
            if not _parts:
                continue
            # Average the centroids of every 3D subsystem this role lights, so a
            # role spanning two bodies (powertrain = motor + cooling) lands one
            # label between them.
            _pcs = [_cents[p] for p in _parts if p in _cents]
            if not _pcs:
                continue
            _cx = sum(c[0] for c in _pcs) / len(_pcs)
            _cy = sum(c[1] for c in _pcs) / len(_pcs)
            _cz = sum(c[2] for c in _pcs) / len(_pcs)
            _short = _ROLE_LABELS[_r].split(" / ")[0]
            _col = _ROLE_LABEL_COLOR.get(_r, "#ffffff")
            _fig_pick.add_trace(go.Scatter3d(
                x=[_cx], y=[_cy], z=[_cz + 90.0],   # lift slightly above the part
                mode="text",
                text=[f"<b>{_short}</b>"],
                textposition="middle center",
                textfont=dict(color=_col, size=13, family="JetBrains Mono"),
                hoverinfo="skip", showlegend=False, name=f"label_{_r}",
            ))
        st.plotly_chart(
            _fig_pick, width="stretch", key="role_pick_car3d",
            config={"scrollZoom": True, "displaylogo": False,
                    "displayModeBar": False})
        # The 3D full-car figure is the single heaviest object in a rerun (all
        # its mesh coordinate arrays). Once Streamlit has it, drop the Python
        # side and force one collect so those arrays don't coexist with every
        # other tab's figures (st.tabs runs them all).
        _mem.release_figure(_fig_pick)
        _mem.maybe_collect(force=True)
        if _hl:
            _lit = " + ".join(_ROLE_LABELS[r].split(" / ")[0] for r in _roles
                              if _ROLE_TO_3D.get(r))
            st.caption(f"Lit up: **{_lit}** — that's the metal you own.")
        else:
            st.caption("Pick a subteam to light up the parts you own.")
    except Exception as _e:
        # The picker must never block the app: if the 3D car can't build (bad
        # state, missing dep), fall back to the dropdown alone — but surface the
        # actual error so the cause is diagnosable rather than a silent "broke".
        st.caption("3D preview unavailable — pick your subteam(s) on the right.")
        with st.expander("Why is the 3D preview unavailable?", expanded=False):
            st.exception(_e)

# ========================================================================== #
#  GATE: don't show the tabs until the member has chosen who they are.
#  Everything below (category strip, sub-tabs, all 25 tab bodies) is skipped
#  until a deliberate choice is made — so a member lands on the picker, not on
#  a wall of tabs. The picker + 3D car above have already rendered; we simply
#  stop here with a prompt until they pick.
# ========================================================================== #
if not _has_picked:
    _brief_roles = [r for r in _roles if r != "everyone"]
    if _brief_roles and st.session_state.get("kk_brief_pending"):
        # Question 1 (subteam) is answered — reveal questions 2 & 3 and the
        # build/skip buttons. This is the mission-briefing questionnaire.
        try:
            _render_brief_questionnaire(_brief_roles)
        except Exception:
            # The questionnaire must never trap a member on the landing page.
            st.session_state["kk_entered"] = True
            st.session_state["kk_brief_pending"] = False
            st.rerun()
    else:
        st.markdown(
            '<div style="max-width:640px;margin:1.4rem auto 0;text-align:center;">'
            '<div style="font-size:1.05rem;font-weight:600;margin-bottom:.3rem;">'
            '👆 Pick your subteam to begin</div>'
            '<p class="hint" style="line-height:1.5;">Choose the subteam(s) you '
            'own above, then answer two one-tap questions — what you\'re here '
            'for and what the goal is — and KinematiK hands you a personal plan: '
            'which tools, in what order, and why, so ANSYS/MATLAB only ever '
            '<b>validate</b> your work. You can change this any time, or choose '
            '<b>Just looking</b> to browse the shared tabs.</p></div>',
            unsafe_allow_html=True)
    # Fill the Design-status board into its reserved top-of-page slot before we
    # stop for the landing page. _vc_collect isn't defined this early, so the
    # board self-degrades to the Registry rollup here; on the full tabbed pages
    # it's filled again below with the subsystem verdicts included.
    try:
        if _STATUS_DASHBOARD_SLOT is not None:
            _render_status_dashboard(_STATUS_DASHBOARD_SLOT)
    except Exception:
        pass
    st.stop()

# --- Mission briefing panel: the compiled questionnaire answer, pinned ------ #
#     above the category strip until dismissed. Never allowed to block the app.
try:
    _render_briefing_panel()
except Exception:
    pass

# --- Decide which ids are primary (own strip) vs folded into "More". ------- #
if _show_all:
    _primary_ids = list(_FULL_ORDER)
    _more_ids = []
else:
    # Union every selected team's tabs (canonical order), then the shared spine.
    _own = []
    for _r in _roles:
        for _i in _ROLE_TABS.get(_r, []):
            if _i not in _own:
                _own.append(_i)
    # Keep the unioned tabs in canonical full order so the strip reads sensibly
    # no matter what combination is picked.
    _own = [_i for _i in _FULL_ORDER if _i in _own]
    _primary_ids = []
    for _i in _own + _SHARED_IDS:
        if _i not in _primary_ids:
            _primary_ids.append(_i)
    _more_ids = [_i for _i in _FULL_ORDER if _i not in _primary_ids]

def _tab_label(_id):
    _em, _lab = _TAB_META[_id]
    return f"{_em}  {_lab}"

# --- Build the actual Streamlit tab widgets. ------------------------------- #
# Every one of the 21 tab bodies below still executes; we just route each id's
# container either into the top strip or into the nested "More tools" strip.
#
# on_change="rerun" + a key turns on each returned container's `.open` flag
# (Streamlit >=1.5x): a real, server-side "is THIS tab the one currently
# selected" signal, with no DOM scraping. We don't use it to skip rendering
# (every tab body still runs unconditionally, exactly as before — other state
# on the page depends on that) — we use it ONLY to log accurate tab_open
# events, see _TabOpenProxy below. Without this, _id_to_container[_id].open
# is always None and every tab body executing every run would make tab_open
# fire identically for all 24 features on every interaction, which is not
# usage data — see _ax_active_ids below for how that signal is consumed.
_id_to_container = {}

# STRICT FILTER: a member sees ONLY their subteam's tabs (_ROLE_TABS) plus the
# shared spine (_SHARED_IDS) — together that's _primary_ids. Everything else
# (_more_ids) is NOT shown in the nav. But every tab BODY below still executes
# (other page state depends on that), so non-shown tabs get a real container
# that simply isn't placed in any visible strip. In "All tabs" power mode,
# _primary_ids is already the full list, so nothing is hidden.
_visible_ids = list(_primary_ids)          # shown in the category nav
_hidden_ids = [i for i in _FULL_ORDER if i not in _visible_ids]

# One off-screen host for every hidden tab's body. st.container() renders but we
# never surface it in a tab strip, so the member never sees these tabs while
# their bodies still run and keep shared state consistent.
if _hidden_ids:
    _hidden_host = st.container()
    with _hidden_host:
        # Kept collapsed and unlabeled; purely a home for non-applicable tab
        # bodies so they execute without cluttering the member's view.
        _hidden_expander = st.expander(
            "⋯ Other tools (outside your subteam)", expanded=False)

def _cat_ordered(cat_key):
    """VISIBLE tab ids for one category, in the member's priority order."""
    return [i for i in _visible_ids if _ID_CATEGORY.get(i) == cat_key]

# Build the category strip, then a sub-tab strip inside each non-empty category.
# Only categories that contain at least one VISIBLE tab appear.
_cats_nonempty = [(ck, cem, clab) for ck, cem, clab, _ in _TAB_CATEGORIES
                  if _cat_ordered(ck)]

_cat_labels = [f"{cem}  {clab}" for ck, cem, clab in _cats_nonempty]
_cat_tabs = st.tabs(_cat_labels, on_change="rerun", key="_cat_tabs_nav")

_cat_container = {}   # category_key -> its outer tab container (for .open gating)
for _ci, (_ck, _cem, _clab) in enumerate(_cats_nonempty):
    _cat_container[_ck] = _cat_tabs[_ci]
    _sub_ids = _cat_ordered(_ck)
    with _cat_tabs[_ci]:
        if len(_sub_ids) == 1:
            # a single-tool category needs no sub-strip; render straight in
            _id_to_container[_sub_ids[0]] = _cat_tabs[_ci]
        else:
            _sub_labels = [_tab_label(i) for i in _sub_ids]
            _sub = st.tabs(_sub_labels, on_change="rerun",
                           key=f"_subtabs_{_ck}")
            for _si, _sid in enumerate(_sub_ids):
                _id_to_container[_sid] = _sub[_si]

# Give every HIDDEN (non-applicable) tab a container inside the off-screen
# expander, so its body still executes (shared state depends on it) but it never
# appears in the member's category nav. Reachable if a member expands "Other
# tools", but out of the way by default.
if _hidden_ids:
    with _hidden_expander:
        st.caption("These are outside your subteam. They still run in the "
                   "background so the shared numbers stay consistent; open one "
                   "only if you need it. Pick that subteam in the selector to "
                   "bring its tools up front properly.")
        _hidden_sub = st.tabs([_tab_label(i) for i in _hidden_ids],
                              on_change="rerun", key="_hidden_tabs_nav")
        for _hi, _hid in enumerate(_hidden_ids):
            _id_to_container[_hid] = _hidden_sub[_hi]


# Snapshot which feature id is genuinely the active tab THIS run, before
# wrapping containers below.
#
# CAREFUL: Streamlit's st.tabs() reports its FIRST tab as .open=True BY
# DEFAULT, even when the user isn't looking at that tab strip at all. With a
# nested "More tools" strip that means TWO containers report .open every run:
# the genuinely-selected top-strip tab AND the first inner More-tools tab
# (phantom). If both land in the active set, the single-active-tab dedup in
# _TabOpenProxy flip-flops between them by body-execution order, and real
# tabs (brakes, etc.) frequently never log a tab_open at all — which is why
# they went missing from per-feature use.
#
# Correct rule: an inner More-tools tab is only genuinely active when the
# outer "⋯ More tools" wrapper is ALSO the selected top tab. So we gate the
# inner-tab .open readings on the wrapper being open.
_ax_active_ids = set()
# A tab is genuinely active only when BOTH its category tab is the selected
# category AND it is the selected sub-tab within that category. This mirrors the
# old "More tools wrapper must be open" gate, generalised to N categories.
for _ck, _cem, _clab in _cats_nonempty:
    _cat_open = bool(getattr(_cat_container.get(_ck), "open", None))
    if not _cat_open:
        continue
    for _id in _cat_ordered(_ck):
        if getattr(_id_to_container.get(_id), "open", None):
            _ax_active_ids.add(_id)

# Map the stable ids back onto the legacy tab variable names the bodies below
# already use, so not a single tab body needs to change.




class _TabOpenProxy:
    """Wraps a Streamlit tab container so simply doing `with tab_X:` fires
    `ax.tab_open(feature)` automatically — the single point that makes EVERY
    tab instrumented, instead of relying on each of the ~24 tab bodies to
    remember to call it themselves. Proxies every other attribute/call
    straight through to the real Streamlit container, so no tab body needs
    to change.

    IMPORTANT: every tab body executes on every Streamlit script-run
    regardless of which tab is visually selected (Streamlit tabs are not
    lazy here — see the comment above _id_to_container). Without a real
    "is this tab actually selected" signal, naively logging tab_open on
    every `with tab_X:` would fire identically for all 24 features on every
    click anywhere in the app — that looks like real foot traffic but
    isn't. `_ax_active_ids` (built just above from each container's `.open`,
    enabled via `on_change="rerun"` on the underlying `st.tabs()` calls) is
    the real signal: it is True only for the tab the user is actually
    looking at this run.

    Logs at most once per genuine switch into the tab, not once per
    script-run while the user keeps interacting with widgets inside a tab
    they're already on (which would inflate "opens" into "every click while
    on this tab")."""

    __slots__ = ("_container", "_feature")

    def __init__(self, container, feature: str):
        object.__setattr__(self, "_container", container)
        object.__setattr__(self, "_feature", feature)

    def __enter__(self):
        _key = self._feature
        _is_active = _key in _ax_active_ids
        _last_active = st.session_state.get("_ax_last_active_tab")
        if _is_active and _last_active != _key:
            # Use the per-feature session flag as the single source of truth for
            # "an open was already logged for this feature this session" — shared
            # with any solver-side backfill (e.g. kinematics). This prevents the
            # proxy and the backfill from EACH logging an open (which caused
            # tab_open to fire ~2x per session where it fired at all).
            if not st.session_state.get(f"_ax_open_{_key}"):
                try:
                    _axn.tab_open(_key)
                    st.session_state[f"_ax_open_{_key}"] = True
                except Exception:
                    pass  # telemetry must never break the tab itself
        if _is_active:
            st.session_state["_ax_last_active_tab"] = _key
        return self._container.__enter__()

    def __exit__(self, *exc):
        return self._container.__exit__(*exc)

    def __getattr__(self, name):
        return getattr(self._container, name)


for _id in list(_id_to_container.keys()):
    _id_to_container[_id] = _TabOpenProxy(_id_to_container[_id], _id)



def _subsystem_default_placement(subsys_key):
    """Sensible default (x, y, z) in mm for an imported part, so it lands roughly
    where that subsystem actually sits on the car before the user fine-tunes.

    Coordinate system matches fullcar3d: x = +forward from mid-wheelbase,
    y = +right of centreline, z = up from ground. Positions scale with the
    declared wheelbase/track so they stay sensible if the car geometry changes.
    """
    _vp = st.session_state.get("vp", {})
    wb = float(_vp.get("wheelbase", 1550.0) or 1550.0)
    tf = float(_vp.get("track_front", 1200.0) or 1200.0)
    tr = float(_vp.get("track_rear", 1180.0) or 1180.0)
    x_front, x_rear = wb / 2.0, -wb / 2.0
    _r = 228.0  # nominal tyre radius (mm), the hub/centre height fullcar3d uses

    # Mirror the body positions fullcar3d renders (see build_full_car_figure).
    _map = {
        # front-right corner, hub height
        "suspension":       (x_front, tf / 2.0 * 0.9, _r),
        "brakes":           (x_front, tf / 2.0 * 0.9, _r),
        # front wing: ahead of the front axle, low to the floor
        "aerodynamics":     (x_front + _r * 1.62, 0.0, _r * 0.4),
        # traction motor: just ahead of the rear axle, on centreline
        "powertrain":       (x_rear + _r * 1.05, 0.0, _r * 1.1),
        # sidepod radiator: right-hand pod, mid-car
        "cooling":          (x_rear + _r * 2.4, tr / 2.0 * 0.7, _r * 1.1),
        # accumulator / HV box: behind the cockpit, low and central
        "electrics":        (x_rear + _r * 2.6, 0.0, _r * 0.8),
        # logger pod: near the cockpit, up high
        "data-acquisition": (x_front - wb * 0.1, 0.0, _r * 1.4),
    }
    return _map.get(subsys_key, (0.0, 0.0, 250.0))


# --------------------------------------------------------------------------- #
#  CAD part "slots" — the named built-in bodies a user can drop a real part
#  into.  Picking one in the "Which part is this?" dropdown sets (a) the colour
#  the imported mesh renders in, (b) the subsystem it lights up as, (c) the
#  target position + envelope to snap / fit to, and (d) which dummy placeholder
#  body can be hidden once the real CAD replaces it.  The display name MUST match
#  the ``name=`` a body is drawn with in fullcar3d.build_full_car_figure so that
#  part_overrides can hide the dummy.
# --------------------------------------------------------------------------- #
_CAD_PART_SLOTS = {
    # label shown in dropdown : (subsystem key, dummy body display-name or None)
    # Chassis is first so it's the default selection — a dummy-backed slot, so
    # the "Replace the dummy" checkbox is live immediately instead of greyed out.
    "Chassis":                  ("chassis",           "Space frame"),
    "Front wing":               ("aerodynamics",      "Front wing"),
    "Rear wing":                ("aerodynamics",      "Rear wing"),
    "Sidepod / bodywork":       ("cooling",           "Sidepod (cooling)"),
    "Radiator":                 ("cooling",           "Radiator core"),
    "Motor / inverter":         ("powertrain",        "Motor + inverter"),
    "Accumulator / battery":    ("electrics",         "Accumulator"),
    "Brake disc / caliper":     ("brakes",            "Brake disc"),
    "Data logger":              ("data-acquisition",  "Data logger"),
    "Suspension package":       ("suspension",        None),
    "Custom / unassigned":      ("(custom / unassigned)", None),
}


def _cad_slot_target(slot_label):
    """Return (centre_xyz, envelope_lwh, subsys_key, dummy_name) for a slot.

    When the slot maps to a real placeholder body (e.g. the monocoque), we
    measure that body's ACTUAL footprint on the current car and use it as the
    target, so a replacing CAD fills the same space the placeholder occupied
    (the monocoque spans ~2 m nose-to-tail — far bigger than the generic
    per-subsystem guess). For slots without a placeholder we fall back to
    fullcar_mod.suggest_part_geometry, and to a neutral mid-car box on error.
    """
    subsys, dummy = _CAD_PART_SLOTS.get(slot_label,
                                        ("(custom / unassigned)", None))
    _sub_for = subsys if subsys != "(custom / unassigned)" else "chassis"
    try:
        _vp_s = VehicleParams(**{k: v for k, v in st.session_state.vp.items()
                                 if k in set(VehicleParams.__dataclass_fields__.keys())})
    except Exception:
        _vp_s = VehicleParams()
    try:
        _led_s = interfaces_mod.IntegrationLedger.from_dict(st.session_state.ledger)
    except Exception:
        _led_s = None

    # Preferred: the placeholder body's real footprint on this car.
    if dummy is not None:
        try:
            _fp = st.session_state.get("_dummy_footprints", {}).get(dummy)
            if _fp is None:
                _fig0 = fullcar_mod.build_full_car_figure(vp=_vp_s, ledger=_led_s)
                _fp = fullcar_mod.dummy_body_footprint(_fig0, dummy)
                _cache = st.session_state.get("_dummy_footprints", {})
                _cache[dummy] = _fp
                st.session_state["_dummy_footprints"] = _cache
            if _fp:
                centre = (float(_fp["x_mm"]), float(_fp["y_mm"]),
                          float(_fp["z_mm"]))
                env = (float(_fp["l_mm"]), float(_fp["w_mm"]), float(_fp["h_mm"]))
                return centre, env, subsys, dummy
        except Exception:
            pass

    # Fallback: the per-subsystem suggested envelope.
    try:
        _g = fullcar_mod.suggest_part_geometry(_vp_s, _sub_for, ledger=_led_s)
        centre = (float(_g["x_mm"]), float(_g["y_mm"]), float(_g["z_mm"]))
        env = (float(_g["l_mm"]), float(_g["w_mm"]), float(_g["h_mm"]))
    except Exception:
        centre, env = (0.0, 0.0, 250.0), (300.0, 200.0, 200.0)
    return centre, env, subsys, dummy


def _cad_fit_scale(part_lwh, envelope_lwh):
    """Uniform scale so a part's bounding box fits INSIDE the slot envelope
    without poking out (the largest factor keeping every axis within the area)."""
    ratios = []
    for p, e in zip(part_lwh, envelope_lwh):
        if p and p > 1e-6 and e and e > 1e-6:
            ratios.append(float(e) / float(p))
    if not ratios:
        return 1.0
    return max(0.01, min(ratios))


def _cad_fill_scale(part_lwh, envelope_lwh):
    """Uniform scale so a part FILLS the slot envelope along its dominant axis.

    For "replace this body" the user wants the CAD to occupy the same space the
    placeholder did — a chassis should span nose-to-tail. A pure inside-fit is
    driven by the tightest axis and leaves a long part far too short, so here we
    match the part's LONGEST extent to the envelope's LONGEST extent, keeping
    true shape. The part may then sit slightly taller/thinner than the
    placeholder, which is expected — it's the real geometry.
    """
    p_max = max((float(v) for v in part_lwh if v and v > 1e-6), default=0.0)
    e_max = max((float(v) for v in envelope_lwh if v and v > 1e-6), default=0.0)
    if p_max <= 1e-6 or e_max <= 1e-6:
        return 1.0
    return max(0.01, e_max / p_max)


# ========================================================================== #
#  Team CAD library ⇄ 3D model bridge — "quick assembly" preview
#
#  Publishing a parseable CAD file to the shared library also places it on the
#  full-car 3D model: the file is meshed, snapped into its subsystem's slot
#  (the exact footprint its dummy placeholder occupies), scaled true-shape to
#  fill that envelope, and the dummy it replaces is hidden. Every slot whose
#  CAD hasn't been uploaded yet keeps its dummy, so the car always reads as a
#  whole — like a SolidWorks quick assembly, but as a live preview that
#  completes itself as the library fills up. A chassis upload uses the
#  renderer's `define_car` mode, so the entire car is proportioned around the
#  real tub. Pure preview: nothing here feeds any calculation.
# ========================================================================== #

_LIB_MESH_EXTS = {"step", "stp", "stl", "obj", "glb"}
_LIB_SLD_EXTS = {"sldprt", "sldasm"}   # SolidWorks native — geometry is locked

_SLD_ADVICE = ("SolidWorks native files keep their geometry locked — no "
               "browser can mesh them. In SolidWorks: **File ▸ Save As ▸ "
               "STEP (.step)** (10 seconds), publish that, and the real "
               "shape replaces the stand-in.")


def _lib_ext(cf):
    return (getattr(cf, "name", "") or "").rsplit(".", 1)[-1].lower()


def _lib_is_sld(cf):
    return (getattr(cf, "kind", "file") == "file"
            and _lib_ext(cf) in _LIB_SLD_EXTS)

# Library subsystem tag -> part slot. Tags with several plausible slots fall
# through to the filename guess below.
_LIB_TAG_SLOT = {
    "chassis": "Chassis",
    "suspension": "Suspension package",
    "ev": "Motor / inverter",
    "powertrain": "Motor / inverter",
    "accumulator": "Accumulator / battery",
    "SES": "Accumulator / battery",
    "electronics": "Data logger",
    "brakes": "Brake disc / caliper",
    "bodywork": "Sidepod / bodywork",
}

_LIB_NAME_HINTS = [           # first match wins, checked on the lower filename
    ("rear wing", "Rear wing"), ("rearwing", "Rear wing"),
    ("front wing", "Front wing"), ("frontwing", "Front wing"),
    ("wing", "Front wing"), ("radiator", "Radiator"),
    ("sidepod", "Sidepod / bodywork"), ("body", "Sidepod / bodywork"),
    ("spaceframe", "Chassis"), ("space frame", "Chassis"),
    ("monocoque", "Chassis"), ("chassis", "Chassis"), ("frame", "Chassis"),
    ("tub", "Chassis"), ("accum", "Accumulator / battery"),
    ("battery", "Accumulator / battery"), ("pack", "Accumulator / battery"),
    ("motor", "Motor / inverter"), ("inverter", "Motor / inverter"),
    ("brake", "Brake disc / caliper"), ("rotor", "Brake disc / caliper"),
    ("caliper", "Brake disc / caliper"), ("logger", "Data logger"),
    ("upright", "Suspension package"), ("wishbone", "Suspension package"),
    ("suspension", "Suspension package"),
]


def _lib_slot_for(cf):
    """Best part slot for a library file: filename hints, then subsystem tag."""
    _low = (getattr(cf, "name", "") or "").lower()
    for _ch in ("_", "-", "."):
        _low = _low.replace(_ch, " ")
    for _hint, _slot in _LIB_NAME_HINTS:
        if _hint in _low:
            return _slot
    return _LIB_TAG_SLOT.get(getattr(cf, "subsystem", "") or "",
                             "Custom / unassigned")


def _lib_injected_ids():
    """{library file id -> index} of parts already placed from the library."""
    return {p.get("lib_id"): i
            for i, p in enumerate(st.session_state.get("car3d_custom_parts", []))
            if p.get("lib_id")}


def _lib_parseable(cf):
    return (getattr(cf, "kind", "file") == "file"
            and (getattr(cf, "name", "") or "").rsplit(".", 1)[-1].lower()
            in _LIB_MESH_EXTS)


def _lib_inject_cad(cf):
    """Mesh a library file and snap it into its slot on the 3D model.

    Returns (ok, message). Skips silently-never: every failure explains itself
    so publishing to the library can never be blocked by the preview.
    """
    # SolidWorks native file: geometry can't be extracted, but the user still
    # deserves to SEE their part on the car. Place a clearly-marked amber
    # provisional stand-in in its slot (hover names their file), except the
    # chassis — the dummy monocoque already IS the chassis stand-in, so an
    # amber box there would only make the car read worse.
    if _lib_is_sld(cf):
        if cf.id in _lib_injected_ids():
            return True, f"**{cf.name}** is already on the 3D model."
        _slot = _lib_slot_for(cf)
        for _q in st.session_state.get("car3d_custom_parts", []):
            if (_q.get("from_library") and not _q.get("provisional")
                    and _q.get("lib_slot") == _slot):
                return True, (f"Real CAD already occupies the **{_slot}** "
                              f"slot; **{cf.name}** stays library-only. "
                              + _SLD_ADVICE)
        if _slot == "Chassis":
            return True, (f"**{cf.name}** is in the library; the dummy "
                          f"spaceframe stands in for it on the 3D model. "
                          + _SLD_ADVICE)
        try:
            _centre, _env, _subsys, _dummy = _cad_slot_target(_slot)
            if "car3d_custom_parts" not in st.session_state:
                st.session_state.car3d_custom_parts = []
            st.session_state.car3d_custom_parts.append(dict(
                name=cf.name.rsplit(".", 1)[0] + " (SLDPRT)",
                subsys=_subsys, shape="box", provisional=True,
                replaces_drawnames=([_dummy] if _dummy else []),
                lib_id=cf.id, from_library=True, lib_slot=_slot,
                x_mm=float(_centre[0]), y_mm=float(_centre[1]),
                z_mm=float(_centre[2]),
                l_mm=float(_env[0]), w_mm=float(_env[1]), h_mm=float(_env[2])))
            st.session_state.pop("_dummy_footprints", None)
            return True, (f"**{cf.name}** placed as an amber PROVISIONAL "
                          f"stand-in in the **{_slot}** slot. " + _SLD_ADVICE)
        except Exception as _se:
            return False, f"Couldn't place a stand-in for **{cf.name}** ({_se})."
    if not _lib_parseable(cf):
        return False, (f"**{cf.name}** can't be meshed here — export STEP "
                       "(File ▸ Save As ▸ STEP in SolidWorks) to see it on "
                       "the car.")
    if cf.id in _lib_injected_ids():
        return True, f"**{cf.name}** is already on the 3D model."
    try:
        import base64 as _b64i, tempfile as _tf, os as _os
        _sfx = "." + cf.name.rsplit(".", 1)[-1].lower()
        with _tf.NamedTemporaryFile(delete=False, suffix=_sfx) as _f:
            _f.write(_b64i.b64decode(cf.data_b64))
            _path = _f.name
        try:
            _payload = chassis_mod.load_part_mesh(_path, max_faces=4000)
        finally:
            try:
                _os.unlink(_path)
            except Exception:
                pass
        _slot = _lib_slot_for(cf)
        # Upgrade path: a real mesh arriving in a slot evicts any provisional
        # SolidWorks stand-in holding that slot (e.g. the .sldprt published
        # earlier), so the amber box gives way to the real geometry.
        try:
            _kept, _skipset = [], st.session_state.setdefault(
                "cad_lib_sync_skip", set())
            for _q in st.session_state.get("car3d_custom_parts", []):
                if (_q.get("from_library") and _q.get("provisional")
                        and _q.get("lib_slot") == _slot):
                    _skipset.add(_q.get("lib_id"))   # don't re-seat on resync
                else:
                    _kept.append(_q)
            st.session_state.car3d_custom_parts = _kept
        except Exception:
            pass
        _centre, _env, _subsys, _dummy = _cad_slot_target(_slot)
        _sz = [float(v) for v in _payload["size_mm"]]
        _is_chassis = (_slot == "Chassis")
        # True-shape fill of the slot envelope; the renderer's define_car mode
        # handles the chassis itself (whole car proportioned around the tub).
        _scale = 1.0 if _is_chassis else _cad_fill_scale(_sz, _env)
        if "car3d_custom_parts" not in st.session_state:
            st.session_state.car3d_custom_parts = []
        st.session_state.car3d_custom_parts.append(dict(
            name=cf.name.rsplit(".", 1)[0], subsys=_subsys,
            shape="mesh", mesh=_payload, axis_map="z_up",
            yaw_deg=0.0, mesh_scale=float(_scale),
            define_car=_is_chassis,
            replaces_drawnames=([_dummy] if _dummy else []),
            lib_id=cf.id, from_library=True, lib_slot=_slot,
            x_mm=float(_centre[0]), y_mm=float(_centre[1]),
            z_mm=float(_centre[2]),
            l_mm=_sz[0] * _scale, w_mm=_sz[1] * _scale, h_mm=_sz[2] * _scale))
        st.session_state.pop("_dummy_footprints", None)
        _where = ("the whole car now assembles around it — if it reads "
                  "backwards or lies on its side, fix it with the ↻ 180° / "
                  "up-axis controls under “On the car now” on the 3D tab"
                  if _is_chassis else
                  f"snapped into the **{_slot}** slot"
                  + (f", its dummy “{_dummy}” hidden" if _dummy else ""))
        return True, (f"**{cf.name}** placed on the 3D model — {_where}. "
                      "Remaining dummies stay until their CAD is uploaded.")
    except Exception as _e:
        return False, (f"Couldn't mesh **{cf.name}** ({_e}). STEP is the most "
                       "reliable SolidWorks export.")


def _lib_eject_cad(lib_id):
    """Remove a library file's part from the 3D model (its dummy returns)."""
    # Respect the user's choice: autosync must not put it straight back.
    st.session_state.setdefault("cad_lib_sync_skip", set()).add(lib_id)
    _idx = _lib_injected_ids().get(lib_id)
    if _idx is not None:
        try:
            st.session_state.car3d_custom_parts.pop(_idx)
        except Exception:
            pass


def _lib_autosync(cad_store):
    """Make the 3D model mirror the CAD library — no button required.

    The library persists across sessions; `car3d_custom_parts` does not. So on
    every render of the 3D model (and of the library itself) we reconcile:
      * every meshable library file not yet on the car is injected into its
        slot (the assembly completes itself as the library fills up), unless
        the user explicitly took that part off the car this session;
      * any car part whose library file was deleted is ejected (its dummy
        returns) — the library is the source of truth.
    Fully guarded and idempotent; a parse failure marks the file as skipped
    for this session so it never loops.
    """
    try:
        _files = _store_cad_files(cad_store, None)
    except Exception:
        return
    _live_ids = {f.id for f in _files}
    _skip = st.session_state.setdefault("cad_lib_sync_skip", set())
    # Eject parts whose library file is gone.
    _parts = st.session_state.get("car3d_custom_parts", [])
    _keep = [p for p in _parts
             if not (p.get("from_library") and p.get("lib_id") not in _live_ids)]
    if len(_keep) != len(_parts):
        st.session_state.car3d_custom_parts = _keep
    # Inject everything meshable that isn't on the car yet.
    _on = _lib_injected_ids()
    for _f in _files:
        if (_f.id in _on) or (_f.id in _skip) \
                or not (_lib_parseable(_f) or _lib_is_sld(_f)):
            continue
        try:
            _ok, _ = _lib_inject_cad(_f)
        except Exception:
            _ok = False
        if not _ok:
            _skip.add(_f.id)   # don't retry a bad file every rerun


def _lib_snap_overrides(base_overrides):
    """Snap neighbouring dummies onto injected CAD — the assembly closes up.

    A CAD part fills its slot true-shape (longest axis matched), so on its
    other axes it can be shorter/longer than the dummy it replaced, leaving a
    gap or an overlap with the bodies that used to abut that dummy. This walks
    the recorded part boxes from the last render: any dummy whose fore/aft
    face touched the replaced dummy's face (with real y/z overlap) is
    translated along x so it now touches the CAD's actual face — one hop only,
    clamped to ±250 mm, purely visual. User edits from the part editor are
    applied ON TOP (their dx adds), so manual nudges always win.
    """
    try:
        _boxes = st.session_state.get("car3d_part_boxes") or {}
        _parts = [p for p in st.session_state.get("car3d_custom_parts", [])
                  if p.get("from_library") and not p.get("define_car")
                  and (p.get("replaces_drawnames") or [])]
        if not _boxes or not _parts:
            return base_overrides
        _replaced = set()
        for _p in _parts:
            _replaced.update(_p.get("replaces_drawnames") or [])
        _ov = {k: dict(v) for k, v in (base_overrides or {}).items()}
        _TOL, _CLAMP = 60.0, 250.0

        def _ivl(c, s, ax):
            return c[ax] - s[ax] / 2.0, c[ax] + s[ax] / 2.0

        def _olap(a, b):
            return min(a[1], b[1]) - max(a[0], b[0]) > 1.0

        for _p in _parts:
            _cx, _cl = float(_p.get("x_mm", 0)), float(_p.get("l_mm", 0))
            _cad_lo, _cad_hi = _cx - _cl / 2.0, _cx + _cl / 2.0
            for _dn in (_p.get("replaces_drawnames") or []):
                _db = _boxes.get(_dn)
                if not _db:
                    continue
                _dlo, _dhi = _ivl(_db["centre"], _db["size"], 0)
                _dy = _ivl(_db["centre"], _db["size"], 1)
                _dz = _ivl(_db["centre"], _db["size"], 2)
                for _nm, _nb in _boxes.items():
                    if _nm in _replaced or _nm == _dn:
                        continue
                    if not (_olap(_ivl(_nb["centre"], _nb["size"], 1), _dy)
                            and _olap(_ivl(_nb["centre"], _nb["size"], 2), _dz)):
                        continue
                    _nlo, _nhi = _ivl(_nb["centre"], _nb["size"], 0)
                    _dx = None
                    if abs(_nlo - _dhi) < _TOL:      # neighbour sat in front
                        _dx = _cad_hi - _nlo
                    elif abs(_nhi - _dlo) < _TOL:    # neighbour sat behind
                        _dx = _cad_lo - _nhi
                    if _dx is None or abs(_dx) < 3.0:
                        continue
                    _dx = max(-_CLAMP, min(_CLAMP, _dx))
                    _e = _ov.setdefault(_nm, {})
                    _e["dx"] = float(_e.get("dx", 0.0)) + float(_dx)
        return _ov
    except Exception:
        return base_overrides


def _fitfc_geom_fingerprint():
    """Cheap, stable fingerprint of everything the background car assembly
    depends on (vehicle params, ledger, topology + hardpoints, part overrides,
    library parts, tire width). Mesh vertex arrays are folded to their sizes —
    hashing megabytes of CAD every run would defeat the point of the cache.
    Returns None if anything refuses to serialise; None simply means rebuild."""
    import hashlib as _hl
    try:
        def _lite(parts):
            out = []
            for p in parts or []:
                q = {k: v for k, v in p.items() if k != "mesh"}
                m = p.get("mesh")
                if m is not None:
                    try:
                        q["_mesh_n"] = (len(m.get("x") or []),
                                        len(m.get("i") or []))
                    except Exception:
                        q["_mesh_n"] = "?"
                out.append(q)
            return out
        blob = json.dumps(dict(
            vp=st.session_state.get("vp"),
            ledger=st.session_state.get("ledger"),
            topology=st.session_state.get("topology", "double_wishbone"),
            hp=st.session_state.get("hp"),
            preset=globals().get("preset"),
            topo_coords=repr(globals().get("_topo_coords")),
            tire_w=st.session_state.get("car3d_tirew", 180.0),
            overrides=st.session_state.get("car3d_overrides", {}),
            parts=_lite(st.session_state.get("car3d_custom_parts")),
        ), sort_keys=True, default=str)
        return _hl.sha1(blob.encode()).hexdigest()
    except Exception:
        return None


def _fitfc_car_boxes():
    """Assemble the full car HEADLESSLY and return (instance_boxes, merged_boxes).

    This is what lets the Fit forecast run accurate clearance / interference
    checks without anyone ever opening the 3D Model tab: it calls the SAME
    ``build_full_car_figure`` the 3D view uses, fed from the same live session
    state (vehicle params, integration ledger, chosen topology, part
    overrides, published library parts, dummy suppressions), then throws the
    figure away and keeps only the drawn boxes. Every layer is forced ON
    regardless of the 3D view's visibility toggles — a visually hidden sidepod
    still occupies real space, so the forecast must reason about it. The
    ground plane is skipped (cosmetic, registers no box anyway) and results
    are memoised on a fingerprint of the inputs so back-to-back forecast runs
    on an unchanged car cost one dict lookup, not a rebuild.

    Side effect, deliberate: a successful build refreshes the shared
    ``car3d_part_boxes`` / ``car3d_part_instances`` caches, so the CAD snap
    tools and alignment read-outs downstream see the same fresh geometry."""
    _fp = _fitfc_geom_fingerprint()
    _cache = st.session_state.get("_fitfc_geom_cache")
    if _fp and _cache and _cache.get("fp") == _fp:
        return _cache["inst"], _cache["merged"]
    try:
        _lib_autosync(get_store())     # model mirrors the CAD library first
    except Exception:
        pass
    _vpf = set(VehicleParams.__dataclass_fields__.keys())
    _vp = VehicleParams(**{k: v for k, v in st.session_state.vp.items()
                           if k in _vpf})
    _led = interfaces_mod.IntegrationLedger.from_dict(st.session_state.ledger)
    _topo = st.session_state.get("topology", "double_wishbone")
    if _topo == "double_wishbone":
        _kw = dict(hp_front=Hardpoints.from_dict(st.session_state.hp))
    else:
        # `kin` is the live topology-aware kinematics the whole app runs on.
        _kw = dict(corner_front=globals().get("kin"))
    _sup, _sup_p = set(), set()
    for _p in st.session_state.get("car3d_custom_parts", []):
        if _p.get("replaces_subsys"):
            _sup.add(_p["replaces_subsys"])
        for _dn in (_p.get("replaces_drawnames") or []):
            _sup_p.add(_dn)
        if _p.get("replaces_drawname"):
            _sup_p.add(_p["replaces_drawname"])
        if _p.get("replaces_dummy"):
            _sup_p.add(_p["replaces_dummy"])
    _fig = fullcar_mod.build_full_car_figure(
        vp=_vp, ledger=_led,
        show_tires=True, show_brakes=True, show_aero=True, show_cooling=True,
        show_powertrain=True, show_electrics=True, show_bodywork=True,
        show_floor=False,
        tire_width_mm=float(st.session_state.get("car3d_tirew", 180.0)
                            or 180.0),
        part_overrides=_lib_snap_overrides(
            dict(st.session_state.get("car3d_overrides", {}) or {})),
        custom_parts=st.session_state.get("car3d_custom_parts", []),
        suppress_subsystems=_sup, suppress_parts=_sup_p, **_kw)
    _inst = dict(getattr(_fig, "_part_instance_boxes", {}) or {})
    _merged = dict(getattr(_fig, "_part_boxes", {}) or {})
    if _merged:
        st.session_state.car3d_part_boxes = dict(_merged)
    if _inst:
        st.session_state.car3d_part_instances = dict(_inst)
    if _fp:
        st.session_state["_fitfc_geom_cache"] = dict(fp=_fp, inst=_inst,
                                                     merged=_merged)
    return _inst, _merged


def _subsystem_cad_import(subsys_key, *, key_prefix, title=None):
    """Render a compact CAD/sketch importer scoped to ONE subsystem.

    Imported parts are appended to the SAME shared ``car3d_custom_parts`` list
    the full-car 3D Model tab reads, so a part dropped here shows up on the
    full car immediately (and vice-versa). ``subsys_key`` is the fullcar3d
    subsystem tag (e.g. "brakes", "aerodynamics") so the part lights up with the
    right team. ``key_prefix`` namespaces the Streamlit widget keys per tab.
    """
    if "car3d_custom_parts" not in st.session_state:
        st.session_state.car3d_custom_parts = []

    _label = (subsys_key or "this subsystem").replace("-", " ")
    with st.expander(title or f"📥  Import {_label} CAD / sketch — shows on the "
                     "full car instantly", expanded=False):
        st.markdown(
            '<p class="hint" style="margin:2px 0 6px;">Drop a SolidWorks part or '
            'a quick sketch (STEP / STL / OBJ / GLB). The real shape renders on '
            'the full-car 3D model, tagged to <b>' + _label + '</b> so it lights '
            'up with your subteam. STEP is the most reliable SolidWorks export '
            '(File ▸ Save As ▸ STEP).</p>', unsafe_allow_html=True)

        _up = st.file_uploader(
            f"Upload {_label} CAD / sketch",
            type=["step", "stp", "stl", "obj", "glb"],
            key=f"{key_prefix}_cad_up")
        if _up is None:
            return

        _sig_key = f"{key_prefix}_cad_sig"
        _payload_key = f"{key_prefix}_cad_payload"
        _name_key = f"{key_prefix}_cad_name_default"
        _sig = f"{_up.name}:{_up.size}"
        if st.session_state.get(_sig_key) != _sig:
            try:
                import tempfile as _tf, os as _os
                _sfx = "." + _up.name.split(".")[-1]
                with _tf.NamedTemporaryFile(delete=False, suffix=_sfx) as _f:
                    _f.write(_up.getbuffer())
                    _cad_path = _f.name
                with st.spinner("Reading geometry…"):
                    _payload = chassis_mod.load_part_mesh(_cad_path, max_faces=4000)
                _os.unlink(_cad_path)
                st.session_state[_payload_key] = _payload
                st.session_state[_sig_key] = _sig
                st.session_state[_name_key] = _up.name.rsplit(".", 1)[0]
            except Exception as _ce:
                st.session_state[_payload_key] = None
                st.error("Couldn't read that CAD (" + str(_ce) + "). STEP is the "
                         "most reliable export from SolidWorks; for STEP make sure "
                         "the cascadio package is installed in the deployment.")

        _payload = st.session_state.get(_payload_key)
        if not _payload:
            return

        _sz = _payload["size_mm"]
        _unit_note = ("" if _payload["unit_scale"] == 1.0 else
                      " · auto-scaled ×%g (looked like %s)" % (
                          _payload["unit_scale"],
                          "metres" if _payload["unit_scale"] == 1000 else "inches"))
        _szu = [units_mod.from_metric(_v, "mm") for _v in _sz]
        st.markdown(
            f'<p class="hint">Loaded <b>{_payload["triangles"]} triangles</b>, '
            f'bounding box <b>{_szu[0]:.0f}×{_szu[1]:.0f}×{_szu[2]:.0f} {units_mod.label("mm")}</b>'
            f'{_unit_note}. Set where it sits and which way is up, then add it.</p>',
            unsafe_allow_html=True)

        _cc = st.columns([3, 2])
        _cad_name = _cc[0].text_input(
            "Part name", key=f"{key_prefix}_cad_name",
            value=st.session_state.get(_name_key, f"{_label} part"))
        _cad_axis = _cc[1].selectbox(
            "Up axis in CAD", ["z_up", "y_up", "x_up"],
            key=f"{key_prefix}_cad_axis",
            help="Which axis points UP in your CAD. SolidWorks is often Y-up; if "
                 "the part lies on its side, switch this.")

        _dx, _dy, _dz = _subsystem_default_placement(subsys_key)
        _cp = st.columns(4)
        _cad_x = unum(_cp[0], "Centre x (mm)", -1500, 1500, _dx, "mm",
                       step=10.0, key=f"{key_prefix}_cad_x")
        _cad_y = unum(_cp[1], "Centre y (mm)", -900, 900, _dy, "mm",
                       step=10.0, key=f"{key_prefix}_cad_y")
        _cad_z = unum(_cp[2], "Centre z (mm)", 0, 1500, _dz, "mm",
                       step=10.0, key=f"{key_prefix}_cad_z")
        _cad_yaw = _cp[3].number_input("Yaw °", -180.0, 180.0, value=0.0,
                                       step=15.0, key=f"{key_prefix}_cad_yaw")
        st.caption("Pre-placed where this subsystem sits on the car — nudge to "
                   "line it up exactly.")

        if st.button(f"Add to car ({_label})", key=f"{key_prefix}_cad_add",
                     type="primary"):
            _ax = st.session_state.get(f"{key_prefix}_cad_axis", "z_up")
            _sx, _sy, _sz2 = _sz
            if _ax == "y_up":
                _L, _W, _H = _sx, _sz2, _sy
            elif _ax == "x_up":
                _L, _W, _H = _sz2, _sy, _sx
            else:
                _L, _W, _H = _sx, _sy, _sz2
            st.session_state.car3d_custom_parts.append(dict(
                name=(_cad_name.strip() or f"{_label} part"), subsys=subsys_key,
                shape="mesh", mesh=_payload, axis_map=_ax,
                yaw_deg=float(_cad_yaw), mesh_scale=1.0,
                x_mm=float(_cad_x), y_mm=float(_cad_y), z_mm=float(_cad_z),
                l_mm=float(_L), w_mm=float(_W), h_mm=float(_H)))
            st.session_state.car3d_focus = subsys_key
            st.session_state.pop(_sig_key, None)
            st.success(f"Added to the full-car model under **{_label}**. "
                       "Open the 3D Model tab to see it placed.")
            st.rerun()

        # Show what this subsystem already has on the car, with quick removal.
        _mine = [(_i, _p) for _i, _p in
                 enumerate(st.session_state.car3d_custom_parts)
                 if _p.get("subsys") == subsys_key]
        if _mine:
            st.markdown('<p class="hint" style="margin:8px 0 2px;">On the car for '
                        f'<b>{_label}</b>:</p>', unsafe_allow_html=True)
            for _idx, _p in _mine:
                _r = st.columns([6, 1])
                _r[0].caption(f"• {_p.get('name', 'part')}")
                if _r[1].button("✕", key=f"{key_prefix}_rm_{_idx}",
                                help="Remove from the car"):
                    st.session_state.car3d_custom_parts.pop(_idx)
                    st.rerun()


# ========================================================================== #
#  Manufacturing Process Library  (shared Excel/CSV knowledge base)
# ========================================================================== #
#  Lives inside every subsystem tab except Cost/BOM. The team's shared workbook
#  (process_library.xlsx, next to project.json) is read once on first use and
#  cached; typing a component/process filters it down to relevant articles —
#  each with a one-line summary so you click the right one — scoped to this
#  subsystem's pool plus cross-team "general" rows. Anyone can add a row, which
#  is written straight back to disk so the next teammate sees it.

def _proclib_load(force=False):
    """Load (and cache in session) the shared process library DataFrame."""
    if force or "proclib_df" not in st.session_state:
        try:
            st.session_state.proclib_df = proclib_mod.load_library()
        except Exception as _e:
            st.session_state.proclib_df = proclib_mod.seed_dataframe()
            st.session_state.proclib_load_err = str(_e)
    # Always overwrite seed rows with current canonical URLs so stale cached
    # files or session state can never surface old / broken links.
    try:
        st.session_state.proclib_df = proclib_mod._apply_seed_links(
            st.session_state.proclib_df)
    except Exception:
        pass
    return st.session_state.proclib_df


def _proclib_chip_words(df, subsystem_key, n=6):
    """A handful of real example terms drawn from THIS pool, for one-tap chips.

    New members often don't know the vocabulary to type. We seed the chips with
    actual terms from their own subsystem's articles so the very first tap lands
    on something relevant. We prefer the most *distinctive* word in each
    component name (skipping generic leads like "Brake" / "Any") so the chips
    span the pool instead of all starting with the same word.
    """
    try:
        pool = proclib_mod.filter_library(df, "", subsystem=subsystem_key,
                                           include_general=False)
    except Exception:
        pool = df.iloc[0:0]

    _generic = {"any", "brake", "the", "a", "an"}
    words = []
    seen = set()
    for _i in range(len(pool)):
        comp = str(pool.iloc[_i]["Component"]).strip()
        head = comp.split("/")[0].strip()
        if not head:
            continue
        toks = [t for t in head.split() if t]
        # Pick the first non-generic token; fall back to the leading token.
        pick = next((t for t in toks if t.lower() not in _generic), toks[0])
        key = pick.lower()
        if key in seen:
            continue
        seen.add(key)
        words.append(pick)
        if len(words) >= n:
            break
    return words


def _render_proclib_questionnaire(df, subsystem_key, *, key_prefix):
    """A tap-only 'What are you developing?' flow for a subsystem.

    Two quick questions, both answered by tapping (no typing, no vocabulary
    needed): (1) which component are you making? — options are the real parts in
    this subsystem's pool; (2) optionally, which process/approach? — options are
    the processes the library actually has for that part. We then show the
    matching article cards. This is the gentlest possible on-ramp for a brand-new
    member who doesn't yet know what to search for.
    """
    _label = proclib_mod.SUBSYSTEM_LABELS.get(subsystem_key, subsystem_key)
    _comps = proclib_mod.components_for(df, subsystem_key, include_general=False)
    if not _comps:
        return

    with st.expander("🧭  Not sure where to start? Tell us what you're making",
                     expanded=False):
        st.markdown(
            '<p class="hint" style="margin:0 0 6px;">Answer one or two quick '
            "questions \u2014 just tap \u2014 and we'll pull up exactly the "
            f"resources for what you're building in <b>{_label}</b>. No need to "
            "know the right words to search for.</p>",
            unsafe_allow_html=True)

        _ckey = f"{key_prefix}_quiz_comp"
        _comp = st.radio(
            "**1. What are you developing or manufacturing?**",
            ["\u2014 pick one \u2014"] + _comps,
            key=_ckey, index=0)

        if _comp and _comp != "\u2014 pick one \u2014":
            _procs = proclib_mod.processes_for(df, subsystem_key, _comp,
                                               include_general=False)
            _proc_choice = None
            if len(_procs) > 1:
                _proc_choice = st.radio(
                    "**2. Which approach are you leaning toward?** "
                    "(optional \u2014 pick *Show me everything* if unsure)",
                    ["Show me everything"] + _procs,
                    key=f"{key_prefix}_quiz_proc", index=0)
                if _proc_choice == "Show me everything":
                    _proc_choice = None

            _rows = proclib_mod.rows_for(df, subsystem_key, _comp, _proc_choice,
                                         include_general=False)
            st.markdown(
                f'<p class="hint" style="margin:8px 0 4px;">Here\u2019s what the '
                f"library has for <b>{_comp}</b>"
                + (f" \u00b7 <i>{_proc_choice}</i>" if _proc_choice else "")
                + f" \u2014 {len(_rows)} resource"
                + ("s" if len(_rows) != 1 else "") + ":</p>",
                unsafe_allow_html=True)
            _proclib_render_cards(_rows, show_subsystem=False)

            st.markdown(
                '<p class="hint" style="margin:6px 0 0;">Don\u2019t see your '
                "exact part? Use the search box below, or add the resource you "
                "wish existed at the bottom of this panel.</p>",
                unsafe_allow_html=True)


def _proclib_render_cards(res, *, show_subsystem):
    """Render article rows as cards: bold component·process, 2-sentence summary,
    tagged link. Shared by the questionnaire, browse, and search paths so every
    link is presented identically (and always with its summary)."""
    if len(res) == 0:
        return
    for _i in range(len(res)):
        _row = res.iloc[_i]
        _comp = str(_row["Component"]).strip() or "\u2014"
        _proc = str(_row["Process"]).strip()
        _summ = str(_row["Summary"]).strip()
        _link = str(_row["Link"]).strip()
        _rsub = str(_row["Subsystem"]).strip().lower()
        _rsub_lbl = proclib_mod.SUBSYSTEM_LABELS.get(_rsub, _rsub)
        _head = f"**{_comp}**" + (f" \u00b7 {_proc}" if _proc else "")
        _tagline = (f'<span class="hint">[{_rsub_lbl}]</span> '
                    if (show_subsystem or _rsub == "general") else "")
        st.markdown(_tagline + _head, unsafe_allow_html=True)
        # Every link carries its 1-2 sentence summary, right above it.
        if _summ:
            st.markdown(
                f'<p class="hint" style="margin:2px 0 2px;">{_summ}</p>',
                unsafe_allow_html=True)
        else:
            st.markdown('<p class="hint" style="margin:2px 0 2px; '
                        'font-style:italic;">(No summary yet \u2014 add one so '
                        "teammates know what this covers.)</p>",
                        unsafe_allow_html=True)
        if _link:
            st.markdown(f"[Open resource \u2197]({_link})")
        st.markdown(
            '<hr style="margin:6px 0; border:none; '
            'border-top:1px solid rgba(128,128,128,.18);">',
            unsafe_allow_html=True)


def _mb_disclaimer_banner():
    """A permanent, always-on banner shown ABOVE the myth-buster / sanity-check
    input — rendered unconditionally on every run (never tied to a button
    click), so the 'validate in the real tools' reminder is always visible.

    Defined here, ABOVE the render functions that call it, because Streamlit
    executes this file top-to-bottom every run and the sanity-check surfaces are
    invoked before the interpreter would reach a later definition.

    Uses st.warning (a native Streamlit component) rather than raw HTML so it
    cannot be hidden by page CSS or stripped by the markdown sanitiser.
    """
    st.warning(
        "⚠️ **The hour before ANSYS, SolidWorks & MATLAB.** This is a fast, "
        "deterministic **screening** tool — it does **not** run FEA, CFD or a "
        "full vehicle sim. Always validate anything you'll design, cut, order "
        "or sign off in the real tools — **ANSYS/CFD** (structural, thermal, "
        "flow), **SolidWorks** (geometry, fit, mass), **MATLAB/Simulink** "
        "(lap-time, dynamics) — and confirm rule limits against the current "
        "season's official rulebook.")


def render_myth_check(subsystem_key, *, key_prefix, context=None,
                      placeholder=None):
    """Generic inline 'sanity-check a claim' box, wired to the deterministic
    myth-buster and (optionally) a live result context for this subsystem.

    Same engine and plain-language output as the brakes 'Bust it →' button, so any
    tab can let a member test an assumption against real numbers in one line —
    without leaving the tab or opening the full Myth-buster view. `context` is the
    optional live-result dict the rules can check the claim against; None falls back
    to the physics/rule answer.
    """
    _ph = placeholder or "e.g. a common assumption you want to sanity-check"
    _mb_disclaimer_banner()
    _c = st.columns([3, 1])
    _claim = _c[0].text_input(
        f"Sanity-check a {subsystem_key.replace('-', ' ')} assumption",
        key=f"{key_prefix}_myth_claim", placeholder=_ph,
        label_visibility="visible")
    _go = _c[1].button("Bust it →", key=f"{key_prefix}_myth_go",
                       help="Check this claim against the deterministic myth-buster "
                            "(and your live numbers where available). No AI.")
    _state_key = f"{key_prefix}_myth_result"
    if _go and _claim.strip():
        try:
            from suspension import mythbuster as _mb
            # Map the tab's subsystem key onto the reasoner's discipline ids so
            # the general-knowledge fallback prioritises the right channel. Only
            # attach the hint when it won't disturb a live-context dict the rules
            # need (we pass it as a separate arg via a small wrapper dict).
            _disc_hint = {"brakes": "brakes", "aero": "aerodynamics",
                          "aerodynamics": "aerodynamics", "cooling": "cooling",
                          "electrics": "electrics", "powertrain": "powertrain",
                          "chassis": "chassis", "suspension": "suspension",
                          "tyre": "suspension", "tire": "suspension"}.get(
                              subsystem_key, None)
            _ctx = context
            if _disc_hint and context is None:
                _ctx = {"_discipline": _disc_hint}
            elif _disc_hint and isinstance(context, dict) \
                    and "_discipline" not in context:
                _ctx = dict(context)
                _ctx["_discipline"] = _disc_hint
            _res = _mb.check(_claim, context=_ctx)
            _vraw = getattr(_res, "verdict", "unknown")
            _v = getattr(_vraw, "value", _vraw)
            # Capture what was sanity-checked so the Documentation report can
            # list the assumptions this member busted in this subsystem.
            _verdict_label = {"myth": "MYTH (false)", "true": "TRUE",
                              "depends": "DEPENDS", "unknown": "no match"}.get(
                                  _v, str(_v))
            record_activity(subsystem_key, "myth",
                            f"\u201c{_claim.strip()}\u201d \u2192 {_verdict_label}")
            # Persist so the verdict (and its disclaimer) survive Streamlit
            # reruns instead of vanishing the moment the page re-renders.
            st.session_state[_state_key] = {"v": _v, "expl": _res.explanation}
        except Exception as _me:
            st.session_state.pop(_state_key, None)
            st.warning(f"Couldn't run the myth-buster: {_me}")

    # Render the persisted verdict every run, with the validation disclaimer
    # attached directly beneath it so the "validate in the real tools" note is
    # always alongside the outcome.
    _saved = st.session_state.get(_state_key)
    if _saved:
        _v = _saved["v"]
        _fn = {"myth": st.error, "true": st.success,
               "depends": st.warning}.get(_v, st.info)
        _head = {"myth": "❌ Not true for your setup",
                 "true": "✅ True — checks out",
                 "depends": "⚠️ It depends — worth a closer look",
                 "unknown": "Couldn't match that to a known check"}.get(_v, _v)
        _fn(f"**{_head}**\n\n{_saved['expl']}")


def render_provisional_note(is_example, verdict, detail=""):
    """Shared 'this is example data, not your car yet' banner.

    A verdict computed on default/placeholder inputs shouldn't alarm a member who
    hasn't entered their own numbers. When `is_example` is True this shows a neutral
    provisional note instead of a hard pass/fail and returns True (caller then skips
    its own verdict banner); otherwise returns False.
    """
    if not is_example:
        return False
    st.info(f"▶ Provisional (example numbers): would be **{verdict}**"
            + (f" — {detail}" if detail else "")
            + ". Enter your own inputs to check your actual subsystem — nothing here "
              "is your car yet.")
    return True


_ACTIVITY_KEY = "_kinematik_activity_log"


def record_activity(subsystem, kind, summary, *, detail=None):
    """Record one thing the user did in a subsystem, for the Documentation report.

    ``kind`` is a short category ("myth", "material", "condition", "calculation",
    …). ``summary`` is a one-line human description; ``detail`` is optional extra
    text. Entries are de-duplicated (same subsystem+kind+summary won't pile up on
    reruns) and time-stamped, kept in session_state so the per-subsystem report
    can list exactly what was done — myths busted, materials chosen, conditions
    applied, calculations run — without each tab re-implementing capture.
    """
    import datetime as _dt
    try:
        _log = st.session_state.setdefault(_ACTIVITY_KEY, {})
        _rows = _log.setdefault(str(subsystem), [])
        _sig = (str(kind), str(summary))
        for _r in _rows:
            if (_r.get("kind"), _r.get("summary")) == _sig:
                _r["ts"] = f"{_dt.datetime.now():%Y-%m-%d %H:%M}"
                _r["count"] = _r.get("count", 1) + 1
                if detail:
                    _r["detail"] = detail
                return
        _rows.append({
            "kind": str(kind),
            "summary": str(summary),
            "detail": detail,
            "ts": f"{_dt.datetime.now():%Y-%m-%d %H:%M}",
            "count": 1,
        })
    except Exception:
        pass  # activity capture must never break a tab


def get_activity(subsystem):
    """Return the recorded activity rows for one subsystem (newest last)."""
    try:
        return list(st.session_state.get(_ACTIVITY_KEY, {}).get(
            str(subsystem), []))
    except Exception:
        return []


_ACTIVITY_KIND_HEADINGS = [
    ("myth", "Assumptions sanity-checked (myth-buster)"),
    ("material", "Materials used"),
    ("condition", "Conditions applied"),
    ("calculation", "Calculations run"),
    ("optimisation", "Optimisations run"),
    ("note", "Other actions"),
]


def _activity_sections(subsystem):
    """Turn recorded activity into report ``extra_sections`` — a list of
    (heading, [markdown lines]) grouped by kind, in a sensible fixed order.
    Returns [] if nothing was recorded, so the report simply omits it."""
    rows = get_activity(subsystem)
    if not rows:
        return []
    by_kind = {}
    for r in rows:
        by_kind.setdefault(r.get("kind", "note"), []).append(r)
    sections = []
    seen_kinds = set()
    for kind, heading in _ACTIVITY_KIND_HEADINGS:
        group = by_kind.get(kind)
        if not group:
            continue
        seen_kinds.add(kind)
        lines = []
        for r in group:
            _c = r.get("count", 1)
            _times = f" _(\u00d7{_c})_" if _c and _c > 1 else ""
            _dtl = f" — {r['detail']}" if r.get("detail") else ""
            _ts = f"  \u00b7 {r['ts']}" if r.get("ts") else ""
            lines.append(f"- {r.get('summary','')}{_dtl}{_times}{_ts}")
        sections.append((heading, lines))
    # any kinds we didn't have an explicit heading for
    for kind, group in by_kind.items():
        if kind in seen_kinds:
            continue
        lines = [f"- {r.get('summary','')}" for r in group]
        sections.append((kind.title(), lines))
    return sections


def _logged_record_sections(subsystem_key):
    """Pull everything the user has LOGGED for this subsystem into report sections.

    This is what makes the documentation near-complete on its own: every decision
    logged to the Handover (via log_decision_now / any tab's "Log this…" button)
    and every Lead Note addressed to or from this subsystem is folded straight
    into the report. The member then only tweaks wording before exporting the PDF,
    instead of re-typing what they already recorded elsewhere.

    Returns a list of (heading, [markdown lines]); [] if nothing is logged, so an
    empty subsystem simply omits these sections. Never raises — a reporting
    convenience must not break the documentation tab.
    """
    sections = []
    try:
        _store = get_store()
    except Exception:
        return sections

    # --- Handover decisions logged for this subsystem ---------------------- #
    try:
        _decs = _store.search_decisions(team=subsystem_key)
    except Exception:
        _decs = []
    # Don't echo the "…subsystem report generated" rows a previous export wrote —
    # that would nest the whole report inside itself on the next generation.
    _decs = [d for d in _decs
             if "subsystem report generated" not in (d.title or "").lower()]
    if _decs:
        lines = []
        for d in _decs:
            _date = f"  ·  {d.date}" if getattr(d, "date", "") else ""
            _part = f" [{d.part}]" if getattr(d, "part", "") else ""
            _who = f" — _{d.author}_" if getattr(d, "author", "") \
                and d.author not in ("auto", subsystem_key) else ""
            lines.append(f"- **{d.title}**{_part}: {d.rationale}{_who}{_date}")
        sections.append(("Decisions logged to Handover", lines))

    # --- Lead notes to/from this subsystem --------------------------------- #
    try:
        _notes = [n for n in _store.notes
                  if n.to_team == subsystem_key or n.from_team == subsystem_key]
        _notes = sorted(_notes, key=lambda n: getattr(n, "ts", ""), reverse=True)
    except Exception:
        _notes = []
    if _notes:
        lines = []
        for n in _notes:
            _dir = ("→ " + integ_mod.TEAMS.get(n.to_team, {}).get(
                        "label", n.to_team)
                    if n.from_team == subsystem_key
                    else "from " + integ_mod.TEAMS.get(n.from_team, {}).get(
                        "label", n.from_team))
            _flags = []
            if getattr(n, "is_request", False):
                _flags.append("request")
            if getattr(n, "urgent", False):
                _flags.append("urgent")
            _status = getattr(n, "status", "open")
            _flags.append(_status)
            _flagstr = f" _({', '.join(_flags)})_" if _flags else ""
            lines.append(f"- {_dir}: {n.message}{_flagstr}")
        sections.append(("Cross-team notes (Lead Notes)", lines))

    return sections


def render_subsystem_documentation(subsystem_key, *, key_prefix,
                                   extra_sections=None, title_name=None):
    """Generic per-subsystem Documentation view: PDF report + optional handover log.

    Every subsystem publishes the same shape of data to the INTEGRATION ledger
    (mass, CG, loads, thermal, rationale, owner...), so ONE helper builds a clean
    report for ANY of them — no per-tab copy-paste. A tab calls this with its
    subsystem key; it assembles the declared ledger interface (only fields actually
    filled), rationale/owner/estimate flag, any live cross-team findings touching
    this subsystem, plus any `extra_sections` the tab passes — a list of
    (heading, [lines]) for results that don't live in the ledger. It then offers a
    PDF + Markdown download and, if chosen, records the report in the Handover via
    the same log_decision_now used everywhere else.

    This is the streamline-the-team feature generalised: a member finishes their
    analysis and captures it — for their binder and for next year — without leaving
    the tab or hand-writing notes.
    """
    _name = title_name or subsystem_key.replace("-", " ").title()

    # Auto-captured activity (myths busted, materials, conditions, calculations)
    # is appended after any sections the tab explicitly passed, so the report
    # reflects everything the user actually did in this subsystem this session.
    _auto_sections = _activity_sections(subsystem_key)
    _all_extra = list(extra_sections or []) + _auto_sections

    def _build_md():
        import datetime as _dt
        L = [f"# Elbee Racing — {_name} Subsystem Report",
             f"_Generated {_dt.datetime.now():%Y-%m-%d %H:%M} from KinematiK._", ""]
        try:
            _led = interfaces_mod.IntegrationLedger.from_dict(
                st.session_state.get("ledger", {}) or {})
            _it = _led.get(subsystem_key)
        except Exception:
            _led, _it = None, None
        if _it is not None and _it.declared_fields():
            L.append("## Declared to INTEGRATION")
            for _f in _it.declared_fields():
                _lbl = interfaces_mod.FIELD_LABELS.get(_f, (_f, ""))[0]
                L.append(f"- {_lbl}: "
                         f"**{interfaces_mod._fmt_val(_f, getattr(_it, _f))}**")
            if _it.is_estimate:
                L.append("- _Marked ESTIMATE — placeholder data, not yet confirmed._")
            if getattr(_it, "rationale", ""):
                L.append(f"- Rationale: {_it.rationale}")
            if getattr(_it, "owner", ""):
                L.append(f"- Owner: {_it.owner}")
            if getattr(_it, "updated_on", ""):
                L.append(f"- Last updated: {_it.updated_on}")
            L.append("")
        for _heading, _lines in _all_extra:
            if _lines:
                L.append(f"## {_heading}")
                L.extend(_lines)
                L.append("")
        if _led is not None:
            try:
                _finds = interfaces_mod.findings_for(
                    _led.check_all(), subsystem_key)
                if _finds:
                    L.append("## Cross-team checks (live)")
                    for _fd in _finds:
                        _sv = getattr(_fd.severity, "value", _fd.severity)
                        L.append(f"- [{str(_sv).upper()}] {_fd.message}")
                    L.append("")
            except Exception as _cx_e:
                # A handover that silently OMITS the cross-team checks reads as
                # "no findings" — worse than admitting they couldn't run.
                L.append("## Cross-team checks (live)")
                L.append(f"- [WARNING] Could not compute live cross-team checks "
                         f"for this handover ({type(_cx_e).__name__}). Re-open "
                         f"Integration and re-export before relying on this "
                         f"document.")
                L.append("")
        if len(L) <= 3:
            L.append(f"_No {_name.lower()} results recorded yet — work through this "
                     f"subsystem's views and publish to INTEGRATION first, then come "
                     f"back here to generate the report._")
        return "\n".join(L)

    _md = _build_md()
    with st.expander("Preview the report", expanded=False):
        st.markdown(_md)

    _mode = st.radio(
        "What should this do?",
        [f"Just create a PDF for the {_name.lower()} subsystem",
         "Create the PDF **and** record it in the Handover"],
        key=f"{key_prefix}_doc_mode")

    _cols = st.columns([2, 3])
    _safe = subsystem_key.replace("-", "_")
    _pdf_ok = False
    try:
        import tempfile as _tf3
        import os as _os3
        _pdf_path = _os3.path.join(_tf3.gettempdir(), f"elbee_{_safe}_report.pdf")
        project_mod.render_pdf(_md, _pdf_path)
        with open(_pdf_path, "rb") as _pf:
            _pdf_bytes = _pf.read()
        _pdf_ok = True
    except Exception as _pe:
        _cols[0].warning(f"PDF unavailable: {_pe}")

    if _pdf_ok:
        _cols[0].download_button(
            f"⬇ {_name} report (.pdf)", _pdf_bytes,
            file_name=f"elbee_{_safe}_report.pdf", mime="application/pdf",
            width='stretch', key=f"{key_prefix}_doc_pdf")
        _cols[1].download_button(
            f"⬇ {_name} report (.md)", _md.encode("utf-8"),
            file_name=f"elbee_{_safe}_report.md", mime="text/markdown",
            width='stretch', key=f"{key_prefix}_doc_md")

    if _mode.startswith("Create the PDF **and**"):
        if st.button("✓ Record this report in the Handover",
                     key=f"{key_prefix}_doc_log"):
            _ok = log_decision_now(
                subsystem_key, f"{_name} subsystem report generated",
                _md, author=subsystem_key)
            if _ok:
                st.success("Recorded in the Handover — visible in the Weight & "
                           "Handover tab and carried into the season handover report.")
            else:
                st.warning("Couldn't write to the Handover log (backend offline) — "
                           "the PDF above is still yours to download.")


# === BEGIN spliced Verdict Center / Docs templates / Mesh+DXF ===
# ============================================================================
#  Feature-menu drill-down (Tab -> Sub-tab -> Feature)
#
#  Feature-collection tabs (aero, brakes, 3D model, integration, DFMEA…) used a
#  horizontal radio that landed the member straight on the first feature's full
#  content — a wall of controls before they'd chosen anything. This helper turns
#  that into the sketch the team drew: land on a short MENU of feature names with
#  NOTHING expanded; pick one; only that feature renders, with a "← All <tab>
#  tools" control to step back. Same features, same code per feature — only how
#  they're surfaced changes, so a member sees a handful of names instead of a
#  screen of everything at once.
# ============================================================================
def feature_menu(tab_key, features, *, title=None, intro=None, columns=3,
                 descriptions=None):
    """Render a feature menu and return the chosen feature name, or None while
    the member is still on the menu.

    features:      list of feature names (the same strings the tab already
                   dispatches on, so wiring is a one-line swap from a radio).
    descriptions:  optional {name: one-line hint} shown under each menu button.
    Usage:
        _pick = feature_menu("brakes", [...], title="Brakes tools")
        if _pick == "Bias & lock-up": ...
    Nothing is shown until the member picks; picking is remembered per tab in
    session_state so reruns keep the chosen feature open."""
    _state_key = f"_featmenu_{tab_key}"
    _active = st.session_state.get(_state_key)

    # If a feature is active, show a compact header + back control, then let the
    # caller render that feature.
    if _active in features:
        _hc = st.columns([1, 4])
        if _hc[0].button("← All tools", key=f"{_state_key}_back",
                         help="Back to this tab's feature menu"):
            st.session_state[_state_key] = None
            _do_rerun()
            return None
        _hc[1].markdown(
            f'<div style="font-family:\'JetBrains Mono\',monospace;'
            f'font-size:.8rem;letter-spacing:.06em;color:var(--dim);'
            f'padding-top:.45rem;">{title or tab_key} ▸ '
            f'<b style="color:var(--text,#d8d8e0)">{_active}</b></div>',
            unsafe_allow_html=True)
        st.markdown('<hr style="margin:6px 0 10px;border:none;'
                    'border-top:1px solid rgba(128,128,128,.15);">',
                    unsafe_allow_html=True)
        return _active

    # Otherwise render the menu — nothing expanded.
    if title:
        st.markdown(f"###### {title}")
    if intro:
        st.markdown(f'<p class="hint" style="margin:-2px 0 8px;">{intro}</p>',
                    unsafe_allow_html=True)
    st.caption("Pick a tool to open it — nothing loads until you choose, so you "
               "see a short list instead of everything at once.")
    descriptions = descriptions or {}
    _cols = st.columns(columns)
    for _i, _name in enumerate(features):
        with _cols[_i % columns]:
            if st.button(_name, key=f"{_state_key}_pick_{_i}",
                         use_container_width=True):
                st.session_state[_state_key] = _name
                _do_rerun()
                return _name
            _d = descriptions.get(_name)
            if _d:
                st.markdown(
                    f'<p class="hint" style="margin:-6px 0 10px;font-size:.72rem;'
                    f'color:var(--dim);">{_d}</p>', unsafe_allow_html=True)
    return None


# --------------------------------------------------------------------------- #
#  0.  Small shared helpers                                                    #
# --------------------------------------------------------------------------- #
# Human labels + emoji for the eight subsystem channels, reused everywhere so
# the Verdict Center, the docs templates and the mesh/DXF picker all speak the
# same language.
_VC_SUBSYS = [
    ("suspension",       "🩷", "Suspension / Dynamics"),
    ("aerodynamics",     "💛", "Aerodynamics"),
    ("powertrain",       "❤️", "Powertrain"),
    ("electrics",        "💙", "Electrics"),
    ("brakes",           "🧡", "Brakes"),
    ("cooling",          "🩵", "Cooling"),
    ("chassis",          "💜", "Chassis / Frame"),
    ("data-acquisition", "💚", "Data Acquisition"),
]
_VC_LABEL = {k: lab for k, _e, lab in _VC_SUBSYS}
_VC_EMOJI = {k: e for k, e, _lab in _VC_SUBSYS}


def _vc_disclaimer(where="this"):
    """The 'double-check before you cut' footer.  Kept in one place so every
    surface that produces a verdict, a report or an export carries the same
    honest reminder that KinematiK is a screening tool, not the final word."""
    st.markdown(
        '<hr style="border:none;border-top:1px solid rgba(128,128,128,.18);'
        'margin:14px 0 8px;">', unsafe_allow_html=True)
    st.markdown(
        '<p class="hint" style="font-size:.72rem;line-height:1.5;'
        'color:var(--dim);margin:0;">'
        '⚠️ <b>Double-check before you commit.</b> '
        f'{where.capitalize()} is a fast screening result from declared numbers '
        'and simple rules — not a substitute for your own FEA/CFD, a bench test, '
        'or a second set of eyes. Confirm anything you\'re about to cut, order or '
        'sign off against the real analysis and your team lead.</p>',
        unsafe_allow_html=True)


# --------------------------------------------------------------------------- #
#  1.  Per-subsystem verdict:  works / closer-look / attention                 #
# --------------------------------------------------------------------------- #
def _vc_collect(subsys_key):
    """Gather everything known about ONE subsystem and bucket it into three
    honest lists — (works, closer_look, attention) — from the live ledger
    findings, the declared interface, and this session's activity log.

    Returns a dict:
        {"works": [...], "closer": [...], "attention": [...],
         "declared": int, "verdict": "green|amber|red|empty"}
    Pure data; the renderer below turns it into boxes.
    """
    works, closer, attention = [], [], []
    declared = 0
    try:
        _led = interfaces_mod.IntegrationLedger.from_dict(
            st.session_state.get("ledger", {}) or {})
    except Exception:
        _led = None

    # --- declared interface: what this subsystem has actually committed ---- #
    _it = None
    if _led is not None:
        try:
            _it = _led.get(subsys_key)
        except Exception:
            _it = None
    if _it is not None:
        try:
            _fields = _it.declared_fields()
        except Exception:
            _fields = []
        declared = len(_fields)
        if _fields and not getattr(_it, "is_estimate", False):
            works.append(
                f"{len(_fields)} interface number(s) declared and marked final.")
        elif _fields and getattr(_it, "is_estimate", False):
            closer.append(
                f"{len(_fields)} number(s) declared but still flagged "
                f"**estimate** — confirm and untick once CAD/measured.")
        else:
            closer.append("Nothing declared to Integration yet — enter this "
                          "subsystem's key numbers so the car-level checks can "
                          "see it.")
        if _fields and not getattr(_it, "rationale", ""):
            closer.append("No design rationale recorded — judges ask for the "
                          "'why', and it goes straight into the report.")
        if _fields and not getattr(_it, "owner", ""):
            closer.append("No owner set on this interface.")

    # --- live cross-team findings that touch this subsystem ---------------- #
    if _led is not None:
        try:
            _finds = interfaces_mod.findings_for(_led.check_all(), subsys_key)
        except Exception:
            _finds = []
        for _f in _finds:
            _sv = str(getattr(_f.severity, "value", _f.severity)).lower()
            if _sv in ("fail",):
                attention.append(_f.message)
            elif _sv in ("warning", "warn"):
                closer.append(_f.message)
            elif _sv in ("missing",):
                closer.append(_f.message)
            elif _sv in ("ok",):
                works.append(_f.message)
            # 'info' is intentionally dropped from the three-box view to reduce noise

    # --- a failing myth recorded this session ------------------------------ #
    _myth = st.session_state.get("mb_last_result_dict")
    if _myth and _myth.get("verdict") == "myth" \
            and (_myth.get("discipline") or "") == subsys_key:
        attention.append("A checked assumption came back FALSE for this "
                         "subsystem — see the sanity-check below.")

    # --- session activity: myths busted true / calcs run ------------------- #
    try:
        for _row in get_activity(subsys_key):
            _s = _row.get("summary", "")
            if _row.get("kind") == "myth" and "TRUE" in _s:
                works.append(f"Assumption held up: {_s}")
            elif _row.get("kind") == "myth" and "MYTH" in _s:
                attention.append(f"Assumption failed: {_s}")
    except Exception:
        pass

    # de-dup while preserving order
    def _uniq(seq):
        seen, out = set(), []
        for x in seq:
            if x not in seen:
                seen.add(x)
                out.append(x)
        return out
    works, closer, attention = _uniq(works), _uniq(closer), _uniq(attention)

    if attention:
        verdict = "red"
    elif closer:
        verdict = "amber"
    elif works:
        verdict = "green"
    else:
        verdict = "empty"
    return {"works": works, "closer": closer, "attention": attention,
            "declared": declared, "verdict": verdict}


def _vc_box(title, emoji, items, accent, empty_msg):
    """Render one of the three coloured boxes inside a subsystem card."""
    _inner = ""
    if items:
        _lis = "".join(
            f'<li style="margin:0 0 4px;line-height:1.45;">{i}</li>'
            for i in items)
        _inner = (f'<ul style="margin:6px 0 0;padding-left:1.1rem;'
                  f'font-size:.85rem;color:var(--text,#d8d8e0);">{_lis}</ul>')
    else:
        _inner = (f'<p style="margin:6px 0 0;font-size:.8rem;color:var(--dim);'
                  f'font-style:italic;">{empty_msg}</p>')
    st.markdown(
        f'<div style="border:1px solid {accent}44;border-left:4px solid {accent};'
        f'border-radius:8px;padding:10px 12px;margin:0 0 10px;'
        f'background:{accent}0d;">'
        f'<div style="font-family:\'JetBrains Mono\',monospace;font-size:.7rem;'
        f'letter-spacing:.1em;text-transform:uppercase;color:{accent};'
        f'font-weight:600;">{emoji} {title}'
        f'<span style="color:var(--dim);font-weight:400;"> · {len(items)}</span>'
        f'</div>{_inner}</div>', unsafe_allow_html=True)


def render_subsystem_verdict_card(subsys_key):
    """One subsystem's full three-box verdict: works / closer look / attention."""
    data = _vc_collect(subsys_key)
    _emoji = _VC_EMOJI.get(subsys_key, "•")
    _name = _VC_LABEL.get(subsys_key, subsys_key.title())
    _dot = {"green": "🟢", "amber": "🟡", "red": "🔴", "empty": "⚪"}[data["verdict"]]
    _head = {"green": "Looks clear on what's declared",
             "amber": "Usable, but some things need a closer look",
             "red": "Needs attention before you commit",
             "empty": "Nothing to check yet — declare this subsystem's numbers"
             }[data["verdict"]]
    st.markdown(
        f"#### {_emoji} {_name} &nbsp; {_dot}")
    st.caption(_head)

    _vc_box("This works", "✅", data["works"], "#37e0d0",
            "No confirmed-good items yet.")
    _vc_box("Take a closer look", "🔎", data["closer"], "#ffb02e",
            "Nothing flagged as soft right now.")
    _vc_box("Pay attention to this", "🛑", data["attention"], "#ff5a52",
            "No hard problems detected. ✔")


