def _render_export_empty_state(subsystem_key, name):
    """Structured, non-dead-end empty state for the Mesh & DXF export.

    Replaces the old flat blue paragraph (which told people to go to a tab they
    were often already inside, and buried a developer aside about the rotor
    exporter). Instead: a clear 'waiting, not broken' line, numbered steps in
    the app's own visual language, and a live checklist of exactly which inputs
    are still missing so the member can see how close the export is."""
    hint = _EXPORT_SOURCE_HINT.get(subsystem_key)
    if not hint:
        st.info("**Waiting on real geometry.** Run this subsystem's tab tool "
                "first — the DXF is built from your computed numbers, so it "
                "stays empty until those exist.")
        return

    where = hint["where"]
    steps = hint.get("steps", [])
    needs = hint.get("needs", [])

    # What's already been entered vs. what's still missing. We read whatever the
    # owning tab / 3D-part entry has published so far, so a half-filled subsystem
    # shows a partial checklist rather than an all-or-nothing wall.
    geom = get_export_geometry(subsystem_key) or {}

    def _have(dict_key):
        v = geom.get(dict_key)
        return v is not None and v != "" and v != 0

    # NOTE: the hint strings below are trusted, hard-coded app constants (never
    # user input) and intentionally contain inline HTML (e.g. <b>…</b>, &mdash;),
    # so we render them as-authored rather than HTML-escaping them.
    _step_html = "".join(
        f'<div class="es-step"><span class="es-n">{i+1}</span>'
        f'<span class="es-t">{s}</span></div>'
        for i, s in enumerate(steps))

    _check_html = ""
    if needs:
        _rows = ""
        for label, dkey in needs:
            done = _have(dkey)
            _mark = "✓" if done else "○"
            _cls = "es-done" if done else "es-todo"
            _rows += (f'<li class="{_cls}"><span class="es-mark">{_mark}</span>'
                      f'{label}</li>')
        _check_html = (
            '<div class="es-check-h">What the export needs</div>'
            f'<ul class="es-check">{_rows}</ul>')

    st.markdown(
        f'''
<div class="es-card">
  <div class="es-head">
    <span class="es-badge">Waiting on numbers</span>
    <span class="es-lead">The DXF is built from the real numbers <b>you</b> enter
      in your tab &mdash; the app draws the section from them, it never guesses.
      So an empty export isn&rsquo;t an error; it just means those inputs
      aren&rsquo;t filled in yet.</span>
  </div>
  <div class="es-where">Enter them in <b>{where}</b>:</div>
  {_step_html}
  {_check_html}
  <div class="es-foot">Fill the inputs above and they tick off here. Once
    they&rsquo;re all in, the short-list and DXF appear on their own.</div>
</div>
''',
        unsafe_allow_html=True)


def render_mesh_and_dxf(subsystem_key, *, key_prefix, candidates=None,
                        title_name=None):
    """Short-list to mesh + DXF export, specialised per subsystem.

    Each subsystem exports the ACTUAL 2-D section it takes into CAD — an airfoil
    for aero, a mount/flange plate with its real bolt PCD for suspension /
    powertrain / brakes, a segment box for the accumulator, a radiator core face
    for cooling, a node gusset for chassis, a sensor bracket for data-acq. The
    geometry comes from what the owning tab PUBLISHED via
    publish_export_geometry() — no invented defaults. If a tab hasn't run its
    tool yet the export honestly gates (exactly like the brakes rotor exporter,
    which shows nothing until you optimise). Every profile is checked for self-
    intersection so it imports into SolidWorks as one clean closed contour ready
    to extrude and validate in ANSYS. Callers may inject bespoke `candidates`
    (e.g. the brakes rotor Pareto short-list)."""
    _name = title_name or _VC_LABEL.get(subsystem_key,
                                        subsystem_key.replace("-", " ").title())

    if not candidates:
        try:
            candidates = _subsystem_profile_candidates(subsystem_key)
        except Exception:
            candidates = []

    st.markdown(f"###### 📐 Short-list to mesh &amp; export — {_name}")

    if subsystem_key == "brakes":
        st.caption("The full rotor short-list (mass-vs-temp Pareto) and its "
                   "half-section DXF live in the 🛑 Brakes tab optimiser. Below "
                   "is the caliper-mount bracket section, once the tab has it.")

    if not candidates:
        _render_export_empty_state(subsystem_key, _name)
        return

    # --- the short-list table (what's worth meshing) ----------------------- #
    _rows = []
    for c in candidates:
        _r = {"Section": c.get("label", "?")}
        _r.update({k: v for k, v in (c.get("meta") or {}).items()
                   if v is not None})
        _rows.append(_r)
    st.markdown("**Short-list to mesh** — each row is a real section from your "
                "computed numbers; confirm in Ansys / your FEA:")
    st.dataframe(_rows, width="stretch", hide_index=True)

    # --- DXF export per short-listed geometry ------------------------------ #
    st.markdown("**Export to CAD (DXF)** — imports into SolidWorks as one closed "
                "sketch; extrude/revolve, then mesh in ANSYS:")
    _labels = {i: c.get("label", f"section {i+1}")
               for i, c in enumerate(candidates)}
    # Tie the widget key to the current candidate set (labels + count). When the
    # upstream geometry changes — e.g. the scale ratio moves and the chord goes
    # 1666.67 -> 1250 mm — the key changes, so Streamlit drops the stale pick and
    # the dropdown re-derives from THIS run's candidates. Without this the
    # selectbox can keep displaying a label the short-list table no longer shows.
    _sig = str(hash(tuple(_labels.values())) & 0xFFFFFF)
    _pick = st.selectbox("Section to export", options=list(_labels.keys()),
                         format_func=lambda i: _labels[i],
                         key=f"{key_prefix}_gdxf_pick_{_sig}")
    _cand = candidates[_pick]
    _notes = list(_cand.get("notes", [])) or [
        f"{k}: {v}" for k, v in (_cand.get("meta") or {}).items() if v is not None]

    # SolidWorks-import guard: warn on any self-intersecting closed profile.
    _clean, _warns = _validate_candidate_geometry(_cand)
    if not _clean:
        st.warning("⚠️ This section may not import as a clean closed contour "
                   "(" + "; ".join(_warns) + "). Check it in SolidWorks before "
                   "extruding.")
    else:
        st.caption("✓ Profile checked: single closed contour, holes as separate "
                   "loops, units embedded — imports ready to extrude.")

    _dxf_kwargs = _cand.get("dxf_kwargs")
    if _dxf_kwargs:
        _dxf = _generic_dxf_bytes(_cand.get("label", _name),
                                  notes=_notes, **_dxf_kwargs)
    else:
        _dxf = _generic_dxf_bytes(_cand.get("label", _name),
                                  _cand.get("profile_mm", [(0, 0)]),
                                  notes=_notes)
    _safe = subsystem_key.replace("-", "_")
    st.download_button(
        "⬇ Download DXF", data=_dxf,
        file_name=f"kinematik_{_safe}_{_pick+1}.dxf",
        mime="application/dxf", key=f"{key_prefix}_gdxf_dl")
    # Immediately free up the memory holding those DXF text blocks. The del is
    # the actual win; the collection is throttled so it doesn't stall every
    # rerun (st.tabs runs this tab's code on every interaction).
    del _dxf
    _mem.maybe_collect()
    _vc_disclaimer(f"the {_name.lower()} section")
# === END spliced block ===


# --------------------------------------------------------------------------- #
#  Documentation template library                                             #
# --------------------------------------------------------------------------- #
# A small library of ready-to-use documentation blocks, each an entry of
# (id, label, icon, default_on, short_markdown_skeleton). A member ticks the
# ones they want; KinematiK merges them with the declared interface numbers +
# session activity into one report — so nobody starts from a blank page or hunts
# for the right headings.
#
# Defined HERE (above render_documentation_expander / render_documentation_center
# and above every subsystem tab that calls them) on purpose: Streamlit runs the
# script top-to-bottom, so the data must exist before the first tab renders.
# Placing it lower in the file raised NameError at those early call sites, which
# dropped every subsystem to the simple fallback report.
# Each entry is (id, label, icon, default_on, skeleton_markdown, group).
# `group` sorts the section into one of three families in the picker:
