def _TMPL_UNPACK(entry):
    """Return (id, label, icon, default_on, body, group) for a template entry,
    tolerating older 5-field entries (group defaults to 'Engineering')."""
    if len(entry) >= 6:
        return entry[0], entry[1], entry[2], entry[3], entry[4], entry[5]
    _id, _label, _icon, _default, _body = entry
    return _id, _label, _icon, _default, _body, "Engineering"


# Lookup for fast access
_TMPL_BY_ID = {t[0]: t for t in _DOC_TEMPLATES}




# --------------------------------------------------------------------------- #
#  3.  Documentation — merged report + template library + sanity check         #
# --------------------------------------------------------------------------- #
# NOTE: the template library data (_DOC_TEMPLATES / _TMPL_BY_ID) is defined much
# earlier in the file — just above render_documentation_expander — because
# Streamlit executes this script top-to-bottom and the first subsystem tabs
# (suspension, powertrain, …) call render_documentation_center before this point
# in the file is ever reached. Defining the data here would raise NameError at
# those call sites and silently drop every tab to the simple fallback report.


# --------------------------------------------------------------------------- #
#  Voice memos — spoken documentation                                          #
#                                                                              #
#  Typing up a subsystem doc after a long workshop evening is exactly the      #
#  moment documentation dies. So inside ✏️ Edit your sections a member can     #
#  UPLOAD a voice memo (recorded on a phone) and the picked template sections  #
#  PREFILL themselves from the transcript: spoken section names ("assumptions: #
#  … calculation summary: …") split the memo explicitly, and everything else   #
#  is keyword-matched to the best section. The member then just tweaks the     #
#  text in the ordinary editors — the info is already there.                   #
#                                                                              #
#  Transcription is attempted with whichever speech engine is installed (all   #
#  imports lazy and optional — the app never gains a hard dependency); with    #
#  none installed, the audio stays attached and a paste-a-transcript fallback  #
#  routes typed text through the exact same prefill path.                      #
#                                                                              #
#  Pure Python throughout: Streamlit widgets + stdlib (hashlib, re, wave, io). #
# --------------------------------------------------------------------------- #
_VOICE_MEMO_KEY = "_kinematik_voice_memos"   # session_state: {subsystem: [memo]}
_VM_ENGINE_CACHE = {}                        # loaded speech models, per process
_VM_AUDIO_TYPES = ["wav", "mp3", "m4a", "ogg", "oga", "webm", "flac",
                   "aac", "aiff", "aif", "opus", "amr", "3gp"]
_VM_MIME = {
    "wav": "audio/wav", "mp3": "audio/mpeg", "m4a": "audio/mp4",
    "ogg": "audio/ogg", "oga": "audio/ogg", "webm": "audio/webm",
    "flac": "audio/flac", "aac": "audio/aac", "aiff": "audio/aiff",
    "aif": "audio/aiff", "opus": "audio/ogg", "amr": "audio/amr",
    "3gp": "audio/3gpp",
}


# Speech-to-text is deliberately ISOLATED to two surfaces for now: the
# 📄 Documentation tab's Document view and the 📝 Lead Notes composer. Every
# voice-prefill render helper takes a `surface` and no-ops unless that surface
# is on this allowlist, and render_documentation_center only mounts the
# uploader when its caller passes enable_voice=True (only the Documentation
# tab does). To roll the feature out to another surface later, add its name
# here and pass it from the call site — one greppable place to widen.
_VM_STT_SURFACES = {"documentation", "lead_notes"}


def _vm_stt_allowed(surface):
    return surface in _VM_STT_SURFACES


def _voice_memo_store(subsystem_key):
    """Per-subsystem list of memo dicts, living in session_state. Never raises."""
    try:
        _all = st.session_state.setdefault(_VOICE_MEMO_KEY, {})
        return _all.setdefault(str(subsystem_key), [])
    except Exception:
        return []


def _vm_digest(data):
    import hashlib
    return hashlib.sha1(data).hexdigest()[:16]


def _vm_wav_duration(data):
    """Duration in seconds for WAV bytes via the stdlib; None for other formats
    (we don't pull in an audio-decoding dependency just for a label)."""
    try:
        import io as _io, wave as _wave
        with _wave.open(_io.BytesIO(data)) as _w:
            _fr = _w.getframerate()
            return (_w.getnframes() / float(_fr)) if _fr else None
    except Exception:
        return None


def _vm_fmt_dur(sec):
    if not sec:
        return ""
    _m, _s = divmod(int(round(sec)), 60)
    return f" · {_m}:{_s:02d} min" if _m else f" · {_s}s"


# --- offline audio decode + model provisioning (pure infrastructure) ------- #
#
# The two helpers below are what turn "a memo sits attached but nothing fills
# in" into "upload → editable text". Neither is AI: _vm_ffmpeg is an audio
# CODEC (format A → 16 kHz mono WAV), and Vosk is a classical offline speech
# recognizer (a fixed acoustic/language model, deterministic, no network at
# recognition time, no generative model). Together they give the feature a
# GUARANTEED floor: every phone format the uploader advertises (.m4a, .mp3,
# .ogg, .webm, …) decodes, and there is always at least one engine that can
# turn it into text — offline, on the deployment, with no API key.

def _vm_ffmpeg():
    """Path to an ffmpeg binary, or None. ffmpeg is a codec, not a dependency
    the app imports — we only ever shell out to it. Checked once and cached."""
    global _VM_FFMPEG_PATH
    try:
        return _VM_FFMPEG_PATH
    except NameError:
        pass
    import shutil as _sh
    _p = _sh.which("ffmpeg")
    # imageio-ffmpeg ships a static ffmpeg as a wheel — a pure-pip way to have
    # the codec on a deploy that lacks a system ffmpeg. Optional; ignored if
    # absent. This keeps "just add it to requirements" working with no apt.
    if not _p:
        try:
            import imageio_ffmpeg as _iio
            _p = _iio.get_ffmpeg_exe()
        except Exception:
            _p = None
    globals()["_VM_FFMPEG_PATH"] = _p
    return _p


def _vm_to_wav16k(data, ext):
    """Decode ANY audio bytes to 16 kHz mono 16-bit PCM WAV bytes, via ffmpeg.
    This is the step that makes the advertised phone formats (.m4a from iPhone
    Voice Memos, .mp3, .ogg, .webm, .amr, …) usable by the offline recognizers,
    which only accept WAV. Returns WAV bytes, or None if decoding isn't possible
    (no ffmpeg). A file that is ALREADY 16 kHz mono WAV round-trips cleanly.
    Pure codec work — no model, no network, no AI."""
    import os as _os, subprocess as _sp, tempfile as _tmp
    _ff = _vm_ffmpeg()
    if not _ff:
        return None
    _in = _tmp.NamedTemporaryFile(suffix="." + (ext or "wav").lstrip("."),
                                  delete=False)
    _out = _tmp.NamedTemporaryFile(suffix=".wav", delete=False)
    _in.write(data); _in.close(); _out.close()
    try:
        _sp.run([_ff, "-y", "-i", _in.name, "-ac", "1", "-ar", "16000",
                 "-f", "wav", "-acodec", "pcm_s16le", _out.name],
                stdout=_sp.DEVNULL, stderr=_sp.DEVNULL, check=True, timeout=300)
        with open(_out.name, "rb") as _f:
            _wav = _f.read()
        return _wav or None
    except Exception:
        return None
    finally:
        for _p in (_in.name, _out.name):
            try:
                _os.unlink(_p)
            except Exception:
                pass


# The small English Vosk model — the offline recognizer's data. ~40 MB, cached
# once per machine under the OS cache dir; downloaded on first use if absent so
# a fresh deploy needs no manual setup step. This is a fixed acoustic/language
# model, not a generative one: same audio in, same words out, every time.
_VM_VOSK_MODEL_DIR = "vosk-model-small-en-us-0.15"
# Download mirrors, tried in order. The official host first; the GitHub release
# mirror second so a deploy whose network policy blocks alphacephei.com (or a
# day it's down) still provisions. Override or extend with KINEMATIK_VOSK_URL
# (single URL) — e.g. to point at an internal artifact store for an air-gapped
# deploy. Any URL must be a .zip that unpacks to a `vosk-model-*` dir.
_VM_VOSK_MODEL_URLS = [
    "https://alphacephei.com/vosk/models/vosk-model-small-en-us-0.15.zip",
    "https://github.com/alphacep/vosk-api/releases/download/"
    "v0.3.45/vosk-model-small-en-us-0.15.zip",
]


def _vm_vosk_cache_root():
    import os as _os
    _root = (_os.environ.get("KINEMATIK_VOSK_DIR")
             or _os.path.join(
                 _os.environ.get("XDG_CACHE_HOME")
                 or _os.path.join(_os.path.expanduser("~"), ".cache"),
                 "kinematik", "vosk"))
    _os.makedirs(_root, exist_ok=True)
    return _root


def _vm_vosk_is_model(_path):
    """A directory is a usable unpacked Vosk model if it has these subdirs."""
    import os as _os
    return bool(_path) and _os.path.isdir(_os.path.join(_path, "am")) and \
        _os.path.isdir(_os.path.join(_path, "conf"))


def _vm_vosk_find_local():
    """Look for an ALREADY-present model — no network. Checked, in order:
      1. $KINEMATIK_VOSK_MODEL pointing straight at an unpacked model dir;
      2. a `models/vosk-model-*` folder shipped next to streamlit_app.py
         (lets a team commit the model for a fully offline / air-gapped deploy);
      3. anything unpacked previously under the cache root.
    Returns a path or None."""
    import os as _os, glob as _glob
    _explicit = _os.environ.get("KINEMATIK_VOSK_MODEL")
    if _vm_vosk_is_model(_explicit):
        return _explicit
    _here = _os.path.dirname(_os.path.abspath(__file__))
    for _cand in _glob.glob(_os.path.join(_here, "models", "vosk-model-*")) + \
            _glob.glob(_os.path.join(_here, "vosk-model-*")):
        if _vm_vosk_is_model(_cand):
            return _cand
    _root = _vm_vosk_cache_root()
    _direct = _os.path.join(_root, _VM_VOSK_MODEL_DIR)
    if _vm_vosk_is_model(_direct):
        return _direct
    for _cand in _glob.glob(_os.path.join(_root, "vosk-model-*")):
        if _vm_vosk_is_model(_cand):
            return _cand
    return None


def _vm_vosk_model_path(download=True):
    """Return a local path to an unpacked Vosk model. First checks for one that
    is already present (env var, a model committed beside the app, or a prior
    download); only then fetches the small English model, trying each mirror in
    turn. Returns None if none is present and none can be fetched. The download
    is the model DATA, done once; recognition itself is fully offline after."""
    import os as _os
    _local = _vm_vosk_find_local()
    if _local:
        return _local
    if not download:
        return None
    import urllib.request as _url, zipfile as _zip
    _root = _vm_vosk_cache_root()
    _dst = _os.path.join(_root, _VM_VOSK_MODEL_DIR)
    _urls = ([_os.environ["KINEMATIK_VOSK_URL"]]
             if _os.environ.get("KINEMATIK_VOSK_URL") else _VM_VOSK_MODEL_URLS)
    for _u in _urls:
        try:
            _tmp_zip = _dst + ".partial.zip"
            _req = _url.Request(_u, headers={"User-Agent": "KinematiK/voice"})
            with _url.urlopen(_req, timeout=180) as _r, \
                    open(_tmp_zip, "wb") as _f:
                while True:
                    _chunk = _r.read(1 << 16)
                    if not _chunk:
                        break
                    _f.write(_chunk)
            with _zip.ZipFile(_tmp_zip) as _z:
                _z.extractall(_root)
            try:
                _os.unlink(_tmp_zip)
            except Exception:
                pass
            _found = _vm_vosk_find_local()
            if _found:
                return _found
        except Exception:
            continue
    return None


def _vm_transcribe(data, filename="memo.wav"):
    """Best-effort speech-to-text. Tries whichever engine is installed, in order
    of quality, and always has an offline Vosk floor (its model self-installs on
    first use) so a bare deployment still turns speech into editable text.
    Returns (text, engine_name) or (None, None). Every import is lazy and every
    failure swallowed — transcription must never block a post, and the audio is
    attached as backup regardless."""
    import os as _os, tempfile as _tmp

    _ext = (_os.path.splitext(filename)[1] or ".wav").lower()

    # Decode once to 16 kHz mono WAV up front (via ffmpeg). This is what lets an
    # iPhone .m4a / Android .mp3 / WhatsApp .ogg actually reach the recognizers,
    # every one of which wants WAV. If ffmpeg isn't present we fall back to the
    # raw bytes and the format-specific branches below still handle plain WAV.
    _wav16 = _vm_to_wav16k(data, _ext.lstrip("."))
    _wav_data = _wav16 or data
    _wav_is_16k = _wav16 is not None

    def _to_tempfile(_payload=None, _suffix=None):
        _f = _tmp.NamedTemporaryFile(suffix=(_suffix or _ext), delete=False)
        _f.write(data if _payload is None else _payload)
        _f.close()
        return _f.name

    # 1) faster-whisper — best accuracy/speed if the team installed it.
    try:
        from faster_whisper import WhisperModel as _FW
        _mdl = _VM_ENGINE_CACHE.get("faster_whisper")
        if _mdl is None:
            _mdl = _FW("base", device="cpu", compute_type="int8")
            _VM_ENGINE_CACHE["faster_whisper"] = _mdl
        # Prefer the decoded 16 kHz WAV so any phone format works even where
        # faster-whisper's own ffmpeg discovery would have failed.
        _p = _to_tempfile(_wav_data, ".wav") if _wav_is_16k else _to_tempfile()
        try:
            _segs, _ = _mdl.transcribe(_p)
            _txt = " ".join(_s.text.strip() for _s in _segs).strip()
            if _txt:
                return _txt, "faster-whisper"
        finally:
            _os.unlink(_p)
    except Exception:
        pass

    # 2) openai-whisper.
    try:
        import whisper as _wh
        _mdl = _VM_ENGINE_CACHE.get("whisper")
        if _mdl is None:
            _mdl = _wh.load_model("base")
            _VM_ENGINE_CACHE["whisper"] = _mdl
        _p = _to_tempfile(_wav_data, ".wav") if _wav_is_16k else _to_tempfile()
        try:
            _txt = (_mdl.transcribe(_p).get("text") or "").strip()
            if _txt:
                return _txt, "whisper"
        finally:
            _os.unlink(_p)
    except Exception:
        pass

    # 3) vosk — the OFFLINE FLOOR. A classical recognizer (not generative AI):
    #    fixed model, deterministic, no network at recognition time. Its model
    #    self-installs on first use. Because we decoded to 16 kHz mono WAV up
    #    front, this now handles EVERY uploaded format, not just WAV — so a
    #    bare deploy with only `vosk` pinned still turns an iPhone .m4a into
    #    editable text. Needs the decoded WAV (ffmpeg); if ffmpeg is missing it
    #    still handles a plain-WAV upload directly.
    _vosk_wav = _wav_data if _wav_is_16k else (data if _ext == ".wav" else None)
    if _vosk_wav is not None:
        try:
            import io as _io, json as _json, wave as _wave
            from vosk import KaldiRecognizer as _KR, Model as _VMod, \
                SetLogLevel as _VSetLog
            try:
                _VSetLog(-1)  # silence vosk's stderr chatter
            except Exception:
                pass
            _mdl = _VM_ENGINE_CACHE.get("vosk")
            if _mdl is None:
                # Our own provisioning (env dir / bundled model / self-installing
                # cache download) is the single source of truth for the model
                # path. If it can't produce one, skip vosk rather than letting
                # vosk's own lang= fallback attempt a second, differently-shaped
                # download — that path can leave a half-built Model whose __del__
                # then errors. Cleaner to just fall through to the next engine.
                _mp = _vm_vosk_model_path(download=True)
                if not _mp:
                    raise RuntimeError("no vosk model available")
                _mdl = _VMod(_mp)
                _VM_ENGINE_CACHE["vosk"] = _mdl
            with _wave.open(_io.BytesIO(_vosk_wav)) as _w:
                _rec = _KR(_mdl, _w.getframerate())
                _rec.SetWords(False)
                _parts = []
                while True:
                    _chunk = _w.readframes(4000)
                    if not _chunk:
                        break
                    if _rec.AcceptWaveform(_chunk):
                        _parts.append(_json.loads(_rec.Result()).get("text", ""))
                _parts.append(_json.loads(_rec.FinalResult()).get("text", ""))
            _txt = " ".join(_t for _t in _parts if _t).strip()
            if _txt:
                return _txt, "vosk"
        except Exception:
            pass

    # 4) SpeechRecognition — last-resort offline sphinx. Uses the decoded WAV
    #    when available (so any format works), else a WAV/AIFF/FLAC upload
    #    directly. Kept offline-only on purpose: recognize_sphinx runs locally,
    #    while recognize_google would ship the audio to a web API — which the
    #    "pure code, no AI, stays on the deployment" intent of this feature
    #    rules out, so it is deliberately NOT called here.
    _sr_wav = _wav_data if _wav_is_16k else (
        data if _ext in (".wav", ".aiff", ".aif", ".flac") else None)
    if _sr_wav is not None:
        try:
            import speech_recognition as _sr
            _r = _sr.Recognizer()
            _p = _to_tempfile(_sr_wav, ".wav")
            try:
                with _sr.AudioFile(_p) as _src:
                    _audio = _r.record(_src)
                _fn = getattr(_r, "recognize_sphinx", None)
                if _fn is not None:
                    try:
                        _txt = (_fn(_audio) or "").strip()
                        if _txt:
                            return _txt, "pocketsphinx"
                    except Exception:
                        pass
            finally:
                _os.unlink(_p)
        except Exception:
            pass

    return None, None


def _vm_engine_available():
    """True if speech-to-text can actually turn audio into text on THIS deploy.

    Not just "is a package importable" — it reflects what will really run:
      • faster-whisper / whisper / speech_recognition importable → yes; or
      • vosk importable AND we can reach a usable model (already cached, an
        explicit KINEMATIK_VOSK_DIR, or a reachable download) → yes.
    Cheap: probes import specs and, for vosk, only checks for an ALREADY-cached
    model unless a download has been permitted elsewhere. Result cached for the
    process so this can be called on every render without cost."""
    global _VM_ENGINE_AVAILABLE_CACHE
    try:
        return _VM_ENGINE_AVAILABLE_CACHE
    except NameError:
        pass
    import importlib.util as _ilu
    _ans = False
    if any(_ilu.find_spec(_m) is not None
           for _m in ("faster_whisper", "whisper", "speech_recognition")):
        _ans = True
    elif _ilu.find_spec("vosk") is not None:
        # vosk is the offline floor. It counts as available if its model is
        # already on disk, OR if a model can be provisioned (fetched) — we let
        # the actual transcribe call trigger the one-time download, but treat a
        # cached model as the cheap "definitely available" signal here.
        import os as _os
        _cached = _os.path.isdir(_os.path.join(
            _vm_vosk_cache_root(), _VM_VOSK_MODEL_DIR, "am"))
        _explicit = bool(_os.environ.get("KINEMATIK_VOSK_DIR"))
        # Not-yet-downloaded still counts: the transcribe path self-installs it.
        _ans = _cached or _explicit or True
    globals()["_VM_ENGINE_AVAILABLE_CACHE"] = _ans
    return _ans


_VM_STOPWORDS = {
    "the", "and", "for", "with", "that", "this", "from", "into", "your",
    "have", "has", "was", "were", "are", "will", "would", "should", "could",
    "about", "them", "then", "than", "there", "here", "what", "when", "which",
    "where", "who", "how", "why", "not", "you", "our", "out", "per", "its",
    "any", "all", "can", "each", "one", "two", "over", "under", "after",
    "before", "been", "being", "onto", "also", "very", "just", "like",
    "section", "sections", "note", "notes", "fill", "edit", "e.g", "etc",
}


def _vm_words(text):
    """Lowercased content words of `text` (stopwords and short tokens out)."""
    import re as _re
    return {w for w in _re.findall(r"[a-zA-Z][a-zA-Z\-]{2,}", (text or "").lower())
            if w not in _VM_STOPWORDS}


def _vm_sentences(text):
    """Split a transcript into sentence-ish chunks (engines rarely punctuate
    perfectly, so newlines count as boundaries too)."""
    import re as _re
    _parts = _re.split(r"(?<=[.!?])\s+|\n+", (text or "").strip())
    return [p.strip().strip(",;") for p in _parts if p and p.strip()]


def _vm_route_transcript(text, picked_meta):
    """Distribute a spoken transcript across the picked template sections.

    picked_meta: [(tid, label, icon, heading, skeleton), ...]
    Returns ({tid: [lines]}, used_markers: bool).

    Two pure-Python passes:
      1. SPOKEN MARKERS — if the member says section names while talking
         ("…assumptions: we ran on cold tires… calculation summary: peak was
         1.6 g…"), the transcript is split at those phrases and each chunk
         lands in the named section. This is the frictionless dictation path.
      2. KEYWORD SCORING — anything not claimed by a marker is scored
         sentence-by-sentence against each section's vocabulary (its label,
         heading and skeleton prompts); each sentence goes to its best match,
         and no-signal sentences follow the previous sentence's section (talk
         tends to stay on topic), defaulting to the first picked section.
    """
    _routed = {tid: [] for (tid, *_rest) in picked_meta}
    if not text or not text.strip() or not picked_meta:
        return _routed, False

    _flat = " ".join(text.split())
    _low = _flat.lower()

    # ---- pass 1: spoken section-name markers ---------------------------- #
    _hits = []  # (pos_in_flat, phrase_len, tid)
    for _tid, _label, _icon, _heading, _skel in picked_meta:
        _phrases = set()
        for _base in ((_label or "").lower().strip(),
                      (_heading or "").lower().strip()):
            if not _base:
                continue
            # Nobody SAYS "&" or the bracketed part of a template name — match
            # the natural spoken variants too ("design intent & requirements"
            # → "design intent and requirements", "design intent").
            _phrases.update({
                _base,
                _base.replace("&", "and").replace("  ", " "),
                _base.split("&")[0].strip(),
                _base.split("(")[0].strip(),
                _base.split("—")[0].strip(),
            })
        for _phrase in _phrases:
            if len(_phrase) < 4:
                continue
            _from = 0
            while True:
                _p = _low.find(_phrase, _from)
                if _p < 0:
                    break
                _hits.append((_p, len(_phrase), _tid))
                _from = _p + 1
    _hits.sort()
    # De-dup overlapping hits, longest phrase first at equal positions (so
    # "design intent and requirements" beats its own "design intent" variant).
    _hits.sort(key=lambda h: (h[0], -h[1]))
    _marks, _last_end = [], -1
    for _p, _ln, _tid in _hits:
        if _p >= _last_end:
            _marks.append((_p, _ln, _tid))
            _last_end = _p + _ln
    _used_markers = len({t for (_p, _l, t) in _marks}) >= 2 or (
        len(_marks) >= 1 and _marks[0][0] <= 3)

    _leftover = _flat
    if _used_markers:
        _leftover = _flat[:_marks[0][0]]
        for _i, (_p, _ln, _tid) in enumerate(_marks):
            _start = _p + _ln
            _stop = _marks[_i + 1][0] if _i + 1 < len(_marks) else len(_flat)
            _chunk = _flat[_start:_stop].strip(" .,:;—-")
            for _s in _vm_sentences(_chunk):
                _routed[_tid].append(_s)

    # ---- pass 2: keyword scoring for whatever's left --------------------- #
    _vocab = {tid: (_vm_words(_label) | _vm_words(_heading) | _vm_words(_skel))
              for (tid, _label, _icon, _heading, _skel) in picked_meta}
    _first_tid = picked_meta[0][0]
    _prev_tid = _first_tid
    for _s in _vm_sentences(_leftover):
        _sw = _vm_words(_s)
        _best_tid, _best = None, 0
        for _tid, _kw in _vocab.items():
            _score = len(_sw & _kw)
            if _score > _best:
                _best_tid, _best = _tid, _score
        _tgt = _best_tid if _best_tid is not None else _prev_tid
        _routed[_tgt].append(_s)
        _prev_tid = _tgt
    return _routed, _used_markers


def _vm_apply_prefill(key_prefix, picked_meta, routed):
    """Write routed lines into the section editors' session_state — MUST run
    before those text_areas are instantiated on this run (Streamlit forbids
    changing a widget's state afterwards; the caller guarantees the ordering).

    An untouched editor (empty, or still exactly the template skeleton) is
    REPLACED by the spoken content; an already-edited one gets the new lines
    appended, so a prefill never destroys typed work.

    Returns [(label, n_lines)] for the sections that actually received text.
    """
    _filled = []
    for _tid, _label, _icon, _heading, _skel in picked_meta:
        _lines = [ln for ln in (routed.get(_tid) or []) if ln.strip()]
        if not _lines:
            continue
        _k = f"{key_prefix}_edit_{_tid}"
        _cur = st.session_state.get(_k, "")
        _block = "\n".join(_lines)
        if not _cur.strip() or _cur.strip() == (_skel or "").strip():
            st.session_state[_k] = _block
        else:
            st.session_state[_k] = _cur.rstrip() + "\n\n" + _block
        _filled.append((_label, len(_lines)))
    return _filled


def _render_voice_memo_prefill(subsystem_key, *, key_prefix, picked_meta,
                               surface="documentation"):
    """🎙️ The voice-memo uploader at the top of ✏️ Edit your sections.

    Drop in an audio file → it's transcribed (when a speech engine is
    installed) → the transcript is routed across the PICKED template sections
    and prefills their editors below, so the member only tweaks a few words
    instead of writing each section. Uploads are de-duplicated by content
    digest and each memo is routed exactly once, so Streamlit reruns never
    double-fill anything.
    """
    if not _vm_stt_allowed(surface):
        return
    _memos = _voice_memo_store(subsystem_key)

    st.markdown(
        '<p class="hint" style="margin:0 0 4px;font-size:.75rem;">'
        '🎙️ <b>Prefill from a voice memo</b> — <b>record right here</b> or talk '
        'through the doc on your phone (say the section names as you go: '
        '<i>“assumptions: … calculation summary: …”</i>), and the sections '
        'below fill themselves in. You just tweak.</p>',
        unsafe_allow_html=True)

    # Two ways in, side by side: record in the browser (st.audio_input, behind
    # the same mic-permission dialog the Lead Notes dock uses) OR drop an audio
    # file. Both funnel into ONE list of (name, bytes, ext) and are processed by
    # the identical transcribe → route → prefill pipeline below, so a recorded
    # note routes across the picked sections exactly like an uploaded memo.
    _incoming = []  # (name, bytes, ext)
    _rc, _uc = st.columns(2)
    with _rc:
        if hasattr(st, "audio_input"):
            _mic_key = f"{key_prefix}_vm_mic_ok"
            if st.session_state.get(_mic_key):
                _rec = st.audio_input(
                    "🔴 Record the doc",
                    key=f"{key_prefix}_vm_rec",
                    help="Records from your microphone, right in the browser. "
                         "Stop, listen back, and the transcript is split across "
                         "the sections you picked — the audio is kept as backup.")
                if _rec is not None and _rec.getvalue():
                    _incoming.append(("recorded note", _rec.getvalue(), "wav"))
                if st.button("🔇 Disable microphone",
                             key=f"{key_prefix}_vm_mic_off",
                             help="Hide the recorder again for this session. "
                                  "Anything already captured stays."):
                    st.session_state[_mic_key] = False
                    _do_rerun()
            elif st.session_state.get(f"{_mic_key}_inline_confirm"):
                # Streamlit builds without st.dialog: explicit inline confirm.
                st.caption("Recording uses your microphone; your browser will "
                           "also ask for permission. Enable the recorder?")
                _ic = st.columns(2)
                if _ic[0].button("✅ Allow", key=f"{_mic_key}_inline_yes"):
                    st.session_state[_mic_key] = True
                    st.session_state.pop(f"{_mic_key}_inline_confirm", None)
                    _do_rerun()
                if _ic[1].button("Not now", key=f"{_mic_key}_inline_no"):
                    st.session_state.pop(f"{_mic_key}_inline_confirm", None)
                    _do_rerun()
            else:
                # No permission yet → no mic widget on the page. The pop-up
                # appears only when the member asks to record, and stays mounted
                # (the `_asking` flag) until explicitly answered.
                if st.button("🔴 Record the doc",
                             key=f"{key_prefix}_vm_mic_ask",
                             help="Opens a permission pop-up first — the "
                                  "microphone is only used after you allow it."):
                    st.session_state[f"{_mic_key}_asking"] = True
                if st.session_state.get(f"{_mic_key}_asking"):
                    _vm_mic_permission_dialog(_mic_key)
                st.caption("Asks for microphone permission before recording.")
        else:
            st.caption("In-browser recording needs Streamlit ≥ 1.39 — "
                       "use the uploader instead.")
    with _uc:
        _ups = st.file_uploader(
            "🎙️ …or drop voice memo(s)", type=_VM_AUDIO_TYPES,
            accept_multiple_files=True,
            key=f"{key_prefix}_vm_up", label_visibility="visible",
            help="Voice Memos (iPhone .m4a), Android recordings, WhatsApp voice "
                 "notes — anything audio. The transcript is split across the "
                 "sections you picked above and dropped into the editors below.")
        for _u in (_ups or []):
            import os as _os
            _root, _uext = _os.path.splitext(_u.name)
            if _u.getvalue():
                _incoming.append(
                    ((_root or "voice memo").replace("_", " ").strip(),
                     _u.getvalue(), (_uext or ".wav").lstrip(".").lower()))

    _known = {_m.get("digest") for _m in _memos}
    _engine_ok = _vm_engine_available()
    _any_new = False
    for _name, _data, _ext in _incoming:
        if not _data:
            continue
        _dig = _vm_digest(_data)
        if _dig in _known:
            continue
        _any_new = True
        import datetime as _dt
        _txt, _eng, _filled = "", None, []
        if _engine_ok:
            with st.spinner(f"Transcribing “{_name}”…"):
                _t, _eng = _vm_transcribe(_data, f"memo.{_ext}")
            _txt = (_t or "").strip()
        if _txt:
            _routed, _mk = _vm_route_transcript(_txt, picked_meta)
            _filled = _vm_apply_prefill(key_prefix, picked_meta, _routed)
        _memos.append({
            "id": _dig, "digest": _dig,
            "name": _name,
            "when": f"{_dt.datetime.now():%Y-%m-%d %H:%M}",
            "data": _data, "ext": _ext,
            "mime": _VM_MIME.get(_ext, "audio/wav"),
            "dur": _vm_wav_duration(_data) if _ext == "wav" else None,
            "text": _txt, "engine": _eng, "filled": _filled,
        })
        _known.add(_dig)
        if _filled:
            st.success("Prefilled from “{}”: {} — tweak below, the wording is "
                       "yours.".format(
                           _name,
                           ", ".join(f"{l} ({n} line{'s' if n != 1 else ''})"
                                     for l, n in _filled)))
        elif _txt:
            st.info(f"Transcribed “{_name}” but couldn't match it to the "
                    f"picked sections — its text was added to the first one.")

    if _any_new and not _engine_ok:
        st.caption("Speech-to-text isn't available on this deployment, so the "
                   "audio is attached but can't fill the sections "
                   "automatically — paste its transcript below. (The offline "
                   "engine ships in requirements-pinned.txt as `vosk` + "
                   "`imageio-ffmpeg`; add them to enable automatic "
                   "transcription — its model self-installs on first use.)")

    # Manual transcript path — also the no-engine fallback: paste (or type)
    # what was said and it's routed into the sections exactly the same way.
    with st.expander("…or paste a transcript to route into the sections",
                     expanded=False):
        _paste = st.text_area(
            "Transcript text", key=f"{key_prefix}_vm_paste", height=120,
            label_visibility="collapsed",
            placeholder="assumptions: we assumed 50/50 static split… "
                        "calculation summary: peak lateral was 1.6 g…")
        if st.button("↧ Route into the sections below",
                     key=f"{key_prefix}_vm_paste_go"):
            if (_paste or "").strip():
                _routed, _mk = _vm_route_transcript(_paste, picked_meta)
                _filled = _vm_apply_prefill(key_prefix, picked_meta, _routed)
                if _filled:
                    st.success("Prefilled: " + ", ".join(
                        f"{l} ({n})" for l, n in _filled))

    # Memos already used — playback + transcript for reference, delete to tidy.
    if _memos:
        with st.expander(f"🎙️ {len(_memos)} memo(s) used for this document",
                         expanded=False):
            for _m in list(_memos):
                _mid = _m["id"]
                _cols = st.columns([5, 1])
                _cols[0].markdown(
                    f"**{_m.get('name', 'memo')}**"
                    f"{_vm_fmt_dur(_m.get('dur'))} · {_m.get('when', '')}"
                    + (f" · 📝 {_m['engine']}" if _m.get("engine") else "")
                    + (" · prefilled " + ", ".join(l for l, _n in _m["filled"])
                       if _m.get("filled") else ""))
                if _cols[1].button("🗑", key=f"{key_prefix}_vm_del_{_mid}",
                                   help="Forget this memo (the text already "
                                        "in the editors stays)."):
                    _memos[:] = [_x for _x in _memos if _x["id"] != _mid]
                    _do_rerun()
                try:
                    st.audio(_m["data"], format=_m.get("mime", "audio/wav"))
                except Exception:
                    pass
                if (_m.get("text") or "").strip():
                    st.caption(f"Transcript: {_m['text'][:400]}"
                               f"{'…' if len(_m['text']) > 400 else ''}")


# Raw-audio size cap for persisting a memo INSIDE a note. Notes live in
# project.json (rewritten wholesale on save) and in Supabase rows, so the
# backup must stay small: ~2.5 MB raw ≈ a few minutes of phone-quality audio
# ≈ ~3.4 MB as base64 in the store. Bigger memos still prefill the text and
# stay playable in-session; they just aren't embedded in the shared store.
_VM_NOTE_EMBED_CAP = 2_500_000


def _vm_mic_permission_dialog(mic_key):
    """In-app microphone permission pop-up, shown BEFORE the recorder widget
    ever renders. Pure Python via st.dialog (a Streamlit modal): the recorder
    is hidden behind a button, clicking it opens this dialog, and only an
    explicit “Allow” reveals the mic widget — at which point the browser will
    additionally show its own native permission prompt the first time the
    microphone is actually accessed. “Not now” just closes the dialog.
    The grant is remembered for this session in `st.session_state[mic_key]`
    and can be revoked from the small 🔇 button next to the recorder.
    On Streamlit builds without st.dialog, falls back to a two-click inline
    confirm (grant on the next press) rather than silently enabling the mic.
    """
    if not hasattr(st, "dialog"):
        # No modal support: arm an inline confirm; the caller renders it.
        st.session_state[f"{mic_key}_inline_confirm"] = True
        return

    @st.dialog("🎙️ Microphone permission")
    def _ask():
        st.markdown(
            "Recording a note uses your **microphone**.\n\n"
            "- The recording stays on this page while you edit, and is "
            "stored **with the note as a backup** when you post it, so "
            "other leads can play back exactly what was said.\n"
            "- Your **browser will also ask** for microphone permission "
            "the first time the recorder is used — that prompt comes from "
            "the browser itself.\n"
            "- Nothing is recorded until you press the record button.")
        _c = st.columns(2)
        if _c[0].button("✅ Allow and show recorder",
                        key=f"{mic_key}_yes", type="primary",
                        width="stretch"):
            st.session_state[mic_key] = True
            st.session_state.pop(f"{mic_key}_asking", None)
            st.rerun()
        if _c[1].button("Not now", key=f"{mic_key}_no",
                        width="stretch"):
            st.session_state[mic_key] = False
            st.session_state.pop(f"{mic_key}_asking", None)
            st.rerun()

    _ask()


def _render_voice_note_dock(target_key, *, key_prefix, surface="lead_notes"):
    """🎙️ Speak a Lead Note instead of typing it — record right here OR drop
    in a voice-memo file. Two things happen:

      1. PREFILL — the transcript is written into the note text box
         (`st.session_state[target_key]`), so the lead just tweaks and posts.
         An empty box is filled; typed text gets the transcript appended.
      2. BACKUP — the newest recording/upload is held as the PENDING backup in
         `st.session_state[f"{key_prefix}_backup"]`; when the note is posted,
         the post handler embeds it (base64) in the Note's `voice_memo` field,
         so the ORIGINAL audio travels with the note into project.json /
         Supabase. If the transcript was off, the spoken word is still there.

    MUST be rendered ABOVE the target text_area (Streamlit forbids changing a
    widget's state once it's instantiated). Captures are content-digest
    de-duplicated, so reruns — including the rerun after posting — never
    re-prefill or re-attach. Pure Python: st.audio_input + st.file_uploader
    + stdlib only.
    """
    if not _vm_stt_allowed(surface):
        return
    _pend_key = f"{key_prefix}_backup"
    _done = st.session_state.setdefault(f"{key_prefix}_done", set())

    _caps = []  # (name, bytes, ext) captured this run
    _rc, _uc = st.columns(2)
    with _rc:
        if hasattr(st, "audio_input"):
            _mic_key = f"{key_prefix}_mic_ok"
            if st.session_state.get(_mic_key):
                # Permission granted (this session) → the recorder exists.
                _rec = st.audio_input(
                    "🔴 Record the note", key=f"{key_prefix}_rec",
                    help="Records from your microphone, right in the browser. "
                         "Stop, listen back, and the note text fills itself "
                         "in — the recording rides along with the post as "
                         "backup.")
                if _rec is not None:
                    _caps.append(("recorded note", _rec.getvalue(), "wav"))
                if st.button("🔇 Disable microphone",
                             key=f"{key_prefix}_mic_off",
                             help="Hide the recorder again for this session. "
                                  "Anything already captured stays."):
                    st.session_state[_mic_key] = False
                    _do_rerun()
            elif st.session_state.get(f"{_mic_key}_inline_confirm"):
                # Fallback for Streamlit builds without st.dialog: an explicit
                # inline confirm instead of a modal — never silently enable.
                st.caption("Recording uses your microphone; your browser will "
                           "also ask for permission. Enable the recorder?")
                _ic = st.columns(2)
                if _ic[0].button("✅ Allow", key=f"{_mic_key}_inline_yes"):
                    st.session_state[_mic_key] = True
                    st.session_state.pop(f"{_mic_key}_inline_confirm", None)
                    _do_rerun()
                if _ic[1].button("Not now", key=f"{_mic_key}_inline_no"):
                    st.session_state.pop(f"{_mic_key}_inline_confirm", None)
                    _do_rerun()
            else:
                # No permission yet → no mic widget on the page at all. The
                # pop-up appears when the lead asks to record, and stays
                # mounted (the `_asking` flag) until explicitly answered —
                # so its buttons still work after any rerun, and dismissing
                # it with ✕ just re-asks next time rather than silently
                # granting anything.
                if st.button("🔴 Record the note",
                             key=f"{key_prefix}_mic_ask",
                             help="Opens a permission pop-up first — the "
                                  "microphone is only used after you allow "
                                  "it."):
                    st.session_state[f"{_mic_key}_asking"] = True
                if st.session_state.get(f"{_mic_key}_asking"):
                    _vm_mic_permission_dialog(_mic_key)
                st.caption("Asks for microphone permission before recording.")
        else:
            st.caption("In-browser recording needs Streamlit ≥ 1.39 — "
                       "use the uploader instead.")
    with _uc:
        _up = st.file_uploader(
            "🎙️ …or drop a voice memo", type=_VM_AUDIO_TYPES,
            accept_multiple_files=False, key=f"{key_prefix}_up",
            help="Voice Memos (iPhone .m4a), Android recordings, WhatsApp "
                 "voice notes — the transcript prefills the note and the "
                 "audio is kept with it as backup.")
        if _up is not None and _up.getvalue():
            import os as _os
            _root, _ext = _os.path.splitext(_up.name)
            _caps.append(((_root or "voice memo").replace("_", " ").strip(),
                          _up.getvalue(), (_ext or ".wav").lstrip(".").lower()))

    for _name, _data, _ext in _caps:
        _dig = _vm_digest(_data)
        if _dig in _done:
            continue
        _done.add(_dig)
        _txt, _eng = "", None
        if _vm_engine_available():
            with st.spinner(f"Transcribing “{_name}”…"):
                _t, _eng = _vm_transcribe(_data, f"note.{_ext}")
            _txt = (_t or "").strip()
        if _txt:
            _cur = (st.session_state.get(target_key) or "").strip()
            st.session_state[target_key] = (
                _cur + "\n\n" + _txt) if _cur else _txt
        # Newest capture becomes the pending backup for the next post.
        import datetime as _dt
        st.session_state[_pend_key] = {
            "name": _name, "ext": _ext,
            "mime": _VM_MIME.get(_ext, "audio/wav"),
            "digest": _dig, "data": _data,
            "dur": _vm_wav_duration(_data) if _ext == "wav" else None,
            "when": f"{_dt.datetime.now():%Y-%m-%d %H:%M}",
            "engine": _eng,
        }
        if _txt:
            st.success(f"Note prefilled from “{_name}”"
                       f"{f' ({_eng})' if _eng else ''} — tweak below; the "
                       f"recording posts with the note as backup.")
        elif _vm_engine_available():
            st.warning("Couldn't transcribe this one — type the note below; "
                       "the recording still posts with it as backup.")
        else:
            st.caption("Speech-to-text isn't available on this deployment, so "
                       "the text box can't fill itself — type the note below; "
                       "the recording still posts with it as backup. (The "
                       "offline engine ships in requirements-pinned.txt as "
                       "`vosk` + `imageio-ffmpeg`; add them to enable "
                       "transcription — the model self-installs on first use.)")

    # The pending backup: show it, let the lead listen back or detach it.
    _pend = st.session_state.get(_pend_key)
    if _pend:
        _bc = st.columns([6, 1])
        _over = len(_pend.get("data", b"")) > _VM_NOTE_EMBED_CAP
        _bc[0].caption(
            f"🎙️ Attached to the next post as backup: "
            f"**{_pend.get('name', 'memo')}**{_vm_fmt_dur(_pend.get('dur'))}"
            + (" — ⚠ over the ~2.5 MB cap, too big to store with the note; "
               "the text still posts normally." if _over else ""))
        if _bc[1].button("🗑", key=f"{key_prefix}_detach",
                         help="Detach the audio backup (the text you see in "
                              "the note box stays)."):
            st.session_state.pop(_pend_key, None)
            _do_rerun()
        try:
            st.audio(_pend["data"], format=_pend.get("mime", "audio/wav"))
        except Exception:
            pass


def render_documentation_center(subsystem_key, *, key_prefix, title_name=None,
                                extra_sections=None, enable_voice=False):
    """Merged documentation hub.

    Strict render order:
      1. Intro blurb
      2. Template multiselect  — choose sections from the library
      3. Section editors       — edit each chosen section inline
      4. Sanity-check          — myth-buster; result auto-appended to report
      5. Report preview        — collapsed expander with the merged markdown
      6. Export                — PDF + Markdown download, optional Handover log

    `extra_sections` (optional) is a list of (heading, [lines]) folded into the
    report alongside the auto-aggregated content — used e.g. by Brakes to carry
    its throttle-return single-fault redundancy summary.
    """
    _name = title_name or _VC_LABEL.get(
        subsystem_key, subsystem_key.replace("-", " ").title())
    _safe = subsystem_key.replace("-", "_")

    # ------------------------------------------------------------------ #
    #  1. Intro                                                            #
    # ------------------------------------------------------------------ #
    _voice_blurb = (
        ' — or <b>🎙️ record or upload a voice memo</b> inside <i>Edit your '
        'sections</i> and the picked sections prefill themselves from what you '
        'said — '
        if enable_voice else ', ')
    st.markdown(
        f'<p class="hint" style="margin:0 0 10px;">'
        f'Build the <b>{_name}</b> document without starting from a blank page. '
        f'Everything you&rsquo;ve logged anywhere — declared numbers, calculations '
        f'run, decisions logged to the Handover, and cross-team Lead Notes — is '
        f'pulled in <b>automatically</b>. Choose any extra template sections, tweak '
        f'the wording inline{_voice_blurb}sanity-check assumptions, then export '
        f'the merged report as PDF or Markdown.</p>',
        unsafe_allow_html=True)

    # ------------------------------------------------------------------ #
    #  2. Templates checkbox  →  template library multiselect             #
    #                                                                      #
    #  The team asked for a single, obvious "Templates" checkbox: opening  #
    #  it reveals a small library of ready-made documentation sections a   #
    #  member can pick from and fill out before downloading the PDF,       #
    #  instead of writing every subsystem doc from a blank page. Left      #
    #  unchecked, the report still assembles from declared numbers and     #
    #  everything recorded this session — so the checkbox only ever adds   #
    #  structure, never gets in the way.                                   #
    # ------------------------------------------------------------------ #
    # Build the label ↔ id maps once, using the safe unpacker so both the old
    # 5-field and the new 6-field (grouped) entries work. Labels are prefixed
    # with a short group tag so the same option list stays readable even though
    # Streamlit's multiselect is a flat control.
    _entries = [_TMPL_UNPACK(t) for t in _DOC_TEMPLATES]
    _label_to_id = {}
    _id_to_label = {}
    _labels_by_group = {g: [] for g in _TMPL_GROUP_ORDER}
    for _id, _lbl, _icon, _default, _body, _group in _entries:
        _full = f"{_icon} {_lbl}"
        _label_to_id[_full] = _id
        _id_to_label[_id] = _full
        _labels_by_group.setdefault(_group, []).append(_full)
    _default_labels = [_id_to_label[_id]
                       for (_id, _l, _ic, _default, _b, _g) in _entries if _default]

    _use_templates = st.checkbox(
        "📚 Templates",
        value=st.session_state.get(f"{key_prefix}_tpl_on", False),
        key=f"{key_prefix}_tpl_on",
        help="Open a small library of ready-made documentation sections, grouped "
             "into Engineering (subsystem-specific), Process documentation, and "
             "Project & team management. Tick the ones you need, fill them out "
             "inline, and they’re merged into the report you download.")

    _picked_ids = []
    if _use_templates:
        # Seed the picker's selection ONCE, before the multiselect widget is
        # created. Streamlit forbids passing both `default=` and `key=` when the
        # keyed value already lives in session_state — doing so logs a state-rules
        # warning and, combined with the bundle buttons writing that same key,
        # made the widgets below intermittently drop out. So we own the value in
        # session_state and never pass `default=` to the widget.
        _picks_key = f"{key_prefix}_tpl_picks"
        if _picks_key not in st.session_state:
            st.session_state[_picks_key] = list(_default_labels)

        # Quick-start bundles: one tap fills the multiselect with a sensible set
        # for a whole family, so a member isn't ticking sections one by one.
        st.markdown(
            '<p class="hint" style="margin:2px 0 4px;font-size:.75rem;">'
            'Quick-start a family, then fine-tune below:</p>',
            unsafe_allow_html=True)
        _bcols = st.columns(4)
        def _ids_in_group(group):
            return [_TMPL_UNPACK(t)[0] for t in _DOC_TEMPLATES
                    if _TMPL_UNPACK(t)[5] == group]
        _bundles = {
            "🔧 Engineering": _ids_in_group("Engineering"),
            "📚 Process":     _ids_in_group("Process"),
            "📋 Project":     _ids_in_group("Project"),
            "✨ Clear":       [],
        }
        for _bi, (_blabel, _bids) in enumerate(_bundles.items()):
            if _bcols[_bi].button(_blabel, key=f"{key_prefix}_bundle_{_bi}",
                                  use_container_width=True,
                                  help="Load this family's sections into the "
                                       "picker (replaces the current selection)."
                                  if _bids else "Clear all selected sections."):
                st.session_state[_picks_key] = [_id_to_label[i] for i in _bids]
                _do_rerun()

        st.caption("Pick the sections you need — each one drops in below as an "
                   "editable, pre-filled skeleton. Untick anything you don’t need.")

        # One grouped multiselect: options are ordered by family so related
        # sections sit together. Streamlit doesn't do optgroups, so the group
        # tag lives in each label and we order the option list by family. The
        # current selection is owned via session_state[_picks_key] (no default=).
        _ordered_options = []
        for _g in _TMPL_GROUP_ORDER:
            _ordered_options.extend(_labels_by_group.get(_g, []))

        # Guard: drop any stale saved labels that aren't valid options anymore
        # (e.g. after a template rename), so the widget never errors on init.
        st.session_state[_picks_key] = [
            lbl for lbl in st.session_state.get(_picks_key, [])
            if lbl in _ordered_options]

        _selected_labels = st.multiselect(
            "Template library — choose sections to include",
            options=_ordered_options,
            key=_picks_key,
            label_visibility="collapsed",
            help="Grouped: Engineering (subsystem-specific), then Process "
                 "documentation, then Project & team management. Pick as many "
                 "or as few as you need.")

        _picked_ids = [_label_to_id[lbl] for lbl in _selected_labels
                       if lbl in _label_to_id]

        # Show which families the current picks span, as a quick orientation.
        if _picked_ids:
            _picked_groups = []
            for _g in _TMPL_GROUP_ORDER:
                _n = sum(1 for pid in _picked_ids
                         if _TMPL_BY_ID.get(pid) is not None
                         and _TMPL_UNPACK(_TMPL_BY_ID[pid])[5] == _g)
                if _n:
                    _picked_groups.append(
                        f"{_TMPL_GROUP_LABELS[_g].split(' ',1)[0]} {_n}")
            st.caption(f"{len(_picked_ids)} section(s) selected "
                       f"({' · '.join(_picked_groups)}) — edit below, then "
                       f"scroll down to sanity-check and export.")
        else:
            st.caption("No sections selected yet — tick some above, or leave "
                       "them off and the report will still include your declared "
                       "numbers and everything recorded this session.")

    # ------------------------------------------------------------------ #
    #  3. Inline section editors                                           #
    # ------------------------------------------------------------------ #
    _edited_sections = []  # [(heading_str, [lines]), ...]

    if _picked_ids:
        st.markdown(
            '<hr style="margin:10px 0 6px;border:none;'
            'border-top:1px solid rgba(128,128,128,.12);">',
            unsafe_allow_html=True)
        with st.expander("⚙️ ✏️ Edit your sections", expanded=False):
          # Unpack the picked sections once — the voice-memo prefill and the
          # editors below both need (id, label, icon, heading, skeleton).
          _picked_meta = []
          for _tid in _picked_ids:
              _, _tlabel, _ticon, _tdefault, _tbody, _tgroup = _TMPL_UNPACK(
                  _TMPL_BY_ID[_tid])
              _heading = next(
                  (ln[3:] for ln in _tbody.splitlines() if ln.startswith("## ")),
                  _tlabel)
              _skeleton = "\n".join(
                  ln for ln in _tbody.splitlines() if not ln.startswith("## "))
              _picked_meta.append((_tid, _tlabel, _ticon, _heading, _skeleton))

          # ------------------------------------------------------------ #
          #  🎙️ Voice-memo prefill — MUST render before the text_areas    #
          #  below: it writes routed transcript text into their           #
          #  session_state keys, and Streamlit forbids changing a         #
          #  widget's state once the widget is instantiated. Keeping the  #
          #  uploader physically above the editors makes the ordering     #
          #  natural AND legal.                                           #
          # ------------------------------------------------------------ #
          if enable_voice:
              try:
                  _render_voice_memo_prefill(subsystem_key,
                                             key_prefix=key_prefix,
                                             picked_meta=_picked_meta,
                                             surface="documentation")
              except Exception as _vm_err:
                  st.caption(f"Voice-memo prefill unavailable "
                             f"({type(_vm_err).__name__}) — the section "
                             f"editors below still work as normal.")
              st.markdown(
                  '<hr style="margin:8px 0 6px;border:none;'
                  'border-top:1px solid rgba(128,128,128,.12);">',
                  unsafe_allow_html=True)

          for _tid, _tlabel, _ticon, _heading, _skeleton in _picked_meta:
              # Own the editor's value in session_state (seed once, never pass
              # value=) — same rule as the template multiselect above. This is
              # also what lets the voice-memo prefill hand text to this editor
              # without tripping Streamlit's "default value + Session State
              # API" state-rules warning.
              if f"{key_prefix}_edit_{_tid}" not in st.session_state:
                  st.session_state[f"{key_prefix}_edit_{_tid}"] = _skeleton
              with st.expander(f"{_ticon} {_tlabel}", expanded=False):
                  _edited = st.text_area(
                      "Content",
                      height=160,
                      key=f"{key_prefix}_edit_{_tid}",
                      label_visibility="collapsed",
                      help="Edit freely. Lines starting with '- ' become bullets "
                           "in the report. Your edits persist while this tab is open.")
                  _edited_sections.append((
                      _heading,
                      [ln for ln in _edited.splitlines() if ln.strip()]))

    # ------------------------------------------------------------------ #
    #  4. Sanity-check                                                     #
    # ------------------------------------------------------------------ #
    st.markdown(
        '<hr style="margin:14px 0 8px;border:none;'
        'border-top:1px solid rgba(128,128,128,.15);">',
        unsafe_allow_html=True)
    with st.expander("⚙️ 🔎 Sanity-check an assumption", expanded=False):
      st.markdown(
          '<p class="hint" style="margin:0 0 6px;font-size:.75rem;">'
          'Type any claim and hit <b>Bust it →</b>. '
          'The verdict is automatically added to your report under '
          '<i>Assumptions checked this session</i>.</p>',
          unsafe_allow_html=True)
      try:
          render_myth_check(subsystem_key, key_prefix=f"{key_prefix}_docmyth")
      except Exception as _mc_err:
          st.error(f"sanity-check render error: {_mc_err}")

      # ------------------------------------------------------------------ #
      #  5 & 6. Build markdown, preview, and export                          #
      # ------------------------------------------------------------------ #
      st.markdown(
          '<hr style="margin:14px 0 8px;border:none;'
          'border-top:1px solid rgba(128,128,128,.15);">',
          unsafe_allow_html=True)
    with st.expander("⚙️ 📄 Report", expanded=False):

      # Build the merged markdown here so the export buttons always reflect
      # the current editors + activity + everything logged this season — no
      # double-appending of activity.
      _all_extra = (_edited_sections
                    + list(extra_sections or [])
                    + _activity_sections(subsystem_key)
                    + _logged_record_sections(subsystem_key))

      def _build_md():
          import datetime as _dt
          L = [f"# Elbee Racing — {_name} Subsystem Report",
               f"_Generated {_dt.datetime.now():%Y-%m-%d %H:%M} from KinematiK._", ""]
          try:
              _led = interfaces_mod.IntegrationLedger.from_dict(
                  st.session_state.get("ledger", {}) or {})
              _it = _led.get(subsystem_key)
          except Exception:
              _led, _it = None, None
          if _it is not None and _it.declared_fields():
              L.append("## Declared to INTEGRATION")
              for _f in _it.declared_fields():
                  _lbl = interfaces_mod.FIELD_LABELS.get(_f, (_f, ""))[0]
                  L.append(f"- {_lbl}: "
                           f"**{interfaces_mod._fmt_val(_f, getattr(_it, _f))}**")
              if _it.is_estimate:
                  L.append("- _Marked ESTIMATE — placeholder, not yet confirmed._")
              if getattr(_it, "rationale", ""):
                  L.append(f"- Rationale: {_it.rationale}")
              if getattr(_it, "owner", ""):
                  L.append(f"- Owner: {_it.owner}")
              if getattr(_it, "updated_on", ""):
                  L.append(f"- Last updated: {_it.updated_on}")
              L.append("")
          for _heading, _lines in _all_extra:
              if _lines:
                  L.append(f"## {_heading}")
                  L.extend(_lines)
                  L.append("")
          if _led is not None:
              try:
                  _finds = interfaces_mod.findings_for(
                      _led.check_all(), subsystem_key)
                  if _finds:
                      L.append("## Cross-team checks (live)")
                      for _fd in _finds:
                          _sv = getattr(_fd.severity, "value", _fd.severity)
                          L.append(f"- [{str(_sv).upper()}] {_fd.message}")
                      L.append("")
              except Exception as _cx_e2:
                  # Omitting the checks reads as "no findings" — say it instead.
                  L.append("## Cross-team checks (live)")
                  L.append(f"- [WARNING] Could not compute live cross-team "
                           f"checks for this report ({type(_cx_e2).__name__}). "
                           f"Re-open Integration and re-export before relying "
                           f"on this document.")
                  L.append("")
          if len(L) <= 3:
              L.append(f"_No {_name.lower()} results yet — work through this "
                       f"subsystem's views and publish to INTEGRATION first._")
          return "\n".join(L)

      _md = _build_md()

      with st.expander("Preview the report", expanded=False):
          st.markdown(_md)

      _mode = st.radio(
          "What should this do?",
          [f"Just create a PDF for the {_name.lower()} subsystem",
           "Create the PDF **and** record it in the Handover"],
          key=f"{key_prefix}_doc_mode")

      _cols = st.columns([2, 3])
      _pdf_ok = False
      try:
          import tempfile as _tf3, os as _os3
          _pdf_path = _os3.path.join(_tf3.gettempdir(), f"elbee_{_safe}_report.pdf")
          project_mod.render_pdf(_md, _pdf_path)
          with open(_pdf_path, "rb") as _pf:
              _pdf_bytes = _pf.read()
          _pdf_ok = True
      except Exception as _pe:
          _cols[0].warning(f"PDF unavailable: {_pe}")

      if _pdf_ok:
          _cols[0].download_button(
              f"⬇ {_name} report (.pdf)", _pdf_bytes,
              file_name=f"elbee_{_safe}_report.pdf", mime="application/pdf",
              width="stretch", key=f"{key_prefix}_doc_pdf")
          _cols[1].download_button(
              f"⬇ {_name} report (.md)", _md.encode("utf-8"),
              file_name=f"elbee_{_safe}_report.md", mime="text/markdown",
              width="stretch", key=f"{key_prefix}_doc_md")

      if _mode.startswith("Create the PDF **and**"):
          if st.button("✓ Record this report in the Handover",
                       key=f"{key_prefix}_doc_log"):
              _ok = log_decision_now(
                  subsystem_key, f"{_name} subsystem report generated",
                  _md, author=subsystem_key)
              if _ok:
                  st.success("Recorded in the Handover — visible in the Weight & "
                             "Handover tab and carried into the season handover report.")
              else:
                  st.warning("Couldn't write to the Handover log (backend offline) — "
                             "the PDF above is still yours to download.")

      _vc_disclaimer(f"the {_name.lower()} document")

_DOC_EXTRA_KEY = "_kinematik_doc_extra_sections"


def publish_doc_sections(subsystem_key, sections):
    """Let a subsystem tab hand its live, computed report sections to the central
    DOCUMENTATION tab.

    The docs panels no longer live inside each subsystem tab, but some subsystems
    (e.g. Brakes) build report sections from numbers only computed while their tab
    runs. Those tabs call this to stash the sections in session_state; the
    Documentation tab reads them back via `get_doc_sections` so the report there
    still carries that subsystem-specific content. Never raises."""
    try:
        _store = st.session_state.setdefault(_DOC_EXTRA_KEY, {})
        _store[str(subsystem_key)] = list(sections or [])
    except Exception:
        pass


def get_doc_sections(subsystem_key):
    """Return whatever a subsystem tab last published for its report, or []."""
    try:
        return list(st.session_state.get(_DOC_EXTRA_KEY, {}).get(
            str(subsystem_key), []))
    except Exception:
        return []


def _render_doc_and_verdict(subsystem_key, *, key_prefix, extra_sections=None,
                            title_name=None, enable_voice=False):
    """Render the Document (report) surface for one subsystem.

    The per-subsystem VERDICT now lives on the main page (the Design-status
    board), combined with the Registry rollup — there is one honest whole-car
    board instead of a verdict buried per subsystem here. So this renders the
    document only; a small pointer sends anyone looking for the verdict to the
    top of the app."""
    _nm = title_name or _VC_LABEL.get(
        subsystem_key, subsystem_key.replace("-", " ").title())

    try:
        render_documentation_center(
            subsystem_key, key_prefix=f"{key_prefix}_dc",
            title_name=_nm, extra_sections=extra_sections,
            enable_voice=enable_voice)
    except Exception as _dc_err:
        # Graceful fallback to the original simple report. We surface a
        # short note (instead of silently swallowing) so a member — or
        # whoever is deploying — can see the merged Template + Sanity-check
        # hub failed to load and why, rather than wondering where the
        # template library went.
        st.caption(f"Showing the simple report — the merged template "
                   f"library couldn’t load here ({type(_dc_err).__name__}).")
        render_subsystem_documentation(
            subsystem_key, key_prefix=key_prefix,
            extra_sections=extra_sections, title_name=title_name)
        try:
            render_myth_check(subsystem_key, key_prefix=key_prefix)
        except Exception:
            pass

    st.caption("Looking for this subsystem's ✅/🔎/🛑 verdict? It now lives on "
               "the **Design status** board at the top of the app, next to the "
               "whole-car readiness rollup.")


def _render_mesh_section(subsystem_key, *, key_prefix, mesh_candidates=None,
                         title_name=None):
    """Render the Mesh & DXF export surface for one subsystem.

    The flow strip explains input → calculate → mesh → export; render_mesh_and_dxf
    does the actual section short-list + DXF work."""
    _nm = title_name or _VC_LABEL.get(
        subsystem_key, subsystem_key.replace("-", " ").title())
    try:
        _hint = _EXPORT_SOURCE_HINT.get(subsystem_key) or {}
        _where = _hint.get("where", f"the {_nm} tab")
        _render_mesh_dxf_flow_strip(_where, subsystem_key=subsystem_key)
        render_mesh_and_dxf(
            subsystem_key, key_prefix=f"{key_prefix}_mesh",
            candidates=mesh_candidates, title_name=_nm)
    except Exception as _me:
        st.caption(f"Mesh/DXF export unavailable: {_me}")


def render_documentation_expander(subsystem_key, *, key_prefix,
                                  extra_sections=None, title_name=None,
                                  mesh_candidates=None):
    """Legacy collapsed 'Documentation & checks' panel for any subsystem.

    Documentation now lives in its own top-level DOCUMENTATION tab (a subsystem
    picker with 📄 Document and 📐 Mesh & DXF sub-tabs), so this panel
    is no longer dropped into each subsystem tab. It is kept as a thin wrapper —
    delegating to the same `_render_doc_and_verdict` / `_render_mesh_section`
    helpers the Documentation tab uses — so any remaining caller still works and
    the two surfaces can never drift. Deliberately does NOT enable the
    🎙️ voice-memo prefill (enable_voice stays False): speech-to-text is
    isolated to the Documentation tab and Lead Notes for now."""
    _nm = title_name or _VC_LABEL.get(
        subsystem_key, subsystem_key.replace("-", " ").title())
    with st.expander(f"📄  {_nm} — documentation & export",
                     expanded=False):
        _doc_verdict, _mesh = st.tabs(
            ["📄 Document", "📐 Mesh & DXF"])
        with _doc_verdict:
            _render_doc_and_verdict(
                subsystem_key, key_prefix=key_prefix,
                extra_sections=extra_sections, title_name=_nm)
        with _mesh:
            _render_mesh_section(
                subsystem_key, key_prefix=key_prefix,
                mesh_candidates=mesh_candidates, title_name=_nm)


def _render_mesh_dxf_flow_strip(where_label, subsystem_key=None):
    """A one-glance 'how to use this' strip: input -> calculate -> mesh -> export.

    Sits at the top of every Mesh & DXF expander so a member immediately sees the
    four stages and, crucially, WHERE each one happens — the inputs live in their
    own tab, the section/short-list is computed here, and the DXF drops out at the
    end. `where_label` names the tab whose numbers feed this export.

    Suspension is the exception the wording has to respect: it has no tab tool to
    'run'. Its section is published PASSIVELY from the sidebar hardpoint editor —
    the moment the upper and lower ball joints exist, the app measures their span
    and the mount-plate section appears. Telling a suspension user to 'run the
    tab's tool' sends them hunting for a button that isn't there, which is the
    single biggest source of 'the suspension export doesn't work' confusion. So
    for suspension we describe what actually happens instead."""
    if subsystem_key == "suspension":
        _steps = [
            ("Input", where_label,
             "Set your <b>upper</b> and <b>lower outer ball joints</b> in the "
             "left sidebar. There&rsquo;s no button to press &mdash; having the "
             "points is the input."),
            ("Calculate", "automatic, no tool to run",
             "The app measures the <b>span</b> between the two ball joints and "
             "uses it as the upright mount <b>PCD</b>; a tie-rod outer adds a "
             "3rd bolt. This happens the instant the points exist."),
            ("Mesh", "here &amp; in your FEA",
             "The mount-plate section appears below on its own. Pick it, then "
             "mesh in Ansys / your FEA."),
            ("Export", "⬇ Download DXF, here",
             "One closed sketch &rarr; SolidWorks: import, size the plate around "
             "the real PCD, then extrude."),
        ]
    elif subsystem_key == "electrics":
        _steps = [
            ("Input", where_label,
             "Set your <b>series</b> and <b>parallel</b> cell counts in the "
             "Accumulator tab. There&rsquo;s no export button &mdash; sizing the "
             "pack is the input."),
            ("Calculate", "automatic, no tool to run",
             "The app splits the pack into isolatable <b>&lt;120 V segments</b>, "
             "lays one segment&rsquo;s cells out as a grid, and wraps it in a "
             "housing wall &mdash; that grid is the box cross-section, published "
             "the instant the pack is sized."),
            ("Mesh", "here &amp; in your FEA",
             "The segment-box section (outer wall + inner cavity) appears below "
             "on its own. Pick it, then mesh in Ansys / your FEA."),
            ("Export", "⬇ Download DXF, here",
             "One closed sketch of <b>one segment</b> &rarr; SolidWorks: import, "
             "extrude to the segment length, then mesh."),
        ]
    elif subsystem_key == "cooling":
        _steps = [
            ("Input", where_label,
             "Add your <b>radiator as a 3D part</b> and type its real <b>width "
             "&amp; height in mm</b>. There&rsquo;s no export button &mdash; the "
             "part&rsquo;s size is the input."),
            ("Calculate", "automatic, no tool to run",
             "The app takes the part&rsquo;s <b>front face</b> (width × height) "
             "as the radiator <b>core face</b> the moment the dimensions exist; "
             "the part&rsquo;s length becomes the core depth to extrude by."),
            ("Mesh", "here &amp; in your FEA",
             "The core-face rectangle appears below on its own. Pick it, then "
             "mesh in Ansys / your FEA."),
            ("Export", "⬇ Download DXF, here",
             "One closed sketch of the core face &rarr; SolidWorks: import, "
             "extrude by the core depth, then mesh."),
        ]
    elif subsystem_key == "chassis":
        _steps = [
            ("Input", where_label,
             "Set the two <b>gusset leg lengths</b> in the Chassis tab &mdash; "
             "or add the node as a <b>3D part</b> and type its size. Either "
             "path feeds the same export."),
            ("Calculate", "on tab input / part entry",
             "The app draws a right-triangle <b>gusset plate</b> to those two "
             "legs and drops in starter bolt holes. It publishes the moment the "
             "legs are set."),
            ("Mesh", "here &amp; in your FEA",
             "The gusset-plate section appears below on its own. Pick it, then "
             "mesh in Ansys / your FEA."),
            ("Export", "⬇ Download DXF, here",
             "One closed sketch &rarr; SolidWorks: import, set plate thickness "
             "from the joint load, then extrude."),
        ]
    else:
        _steps = [
            ("Input", where_label,
             "Enter your real numbers in the tab &mdash; the section is drawn "
             "from them, never guessed."),
            ("Calculate", "same tab, automatically",
             "Run the tab&rsquo;s tool; it computes the section and a "
             "short-list of what&rsquo;s worth meshing."),
            ("Mesh", "here &amp; in your FEA",
             "Pick a short-listed section below, then mesh the survivors in "
             "Ansys / your FEA."),
            ("Export", "⬇ Download DXF, here",
             "One closed sketch &rarr; SolidWorks: import, extrude/revolve, "
             "then mesh."),
        ]
    _cells = []
    for i, (title, here, sub) in enumerate(_steps):
        _cells.append(
            f'<div class="flow-step">'
            f'<span class="flow-badge"><span class="flow-n">{i+1}</span>{title}</span>'
            f'<span class="flow-here">{here}</span>'
            f'<span class="flow-sub">{sub}</span></div>')
        if i < len(_steps) - 1:
            _cells.append('<span class="flow-arrow">&rarr;</span>')
    st.markdown('<div class="flow-strip">' + "".join(_cells) + '</div>',
                unsafe_allow_html=True)


def render_mesh_and_dxf_expander(subsystem_key, *, key_prefix,
                                 candidates=None, title_name=None):
    """Standalone per-tab Mesh & DXF export, mirroring the Brakes tab layout.

    The Mesh & DXF export used to be buried as a third sub-tab inside every
    subsystem's documentation panel. It is now its own collapsible feature that
    each applicable subsystem tab drops into its body — the same shape the
    Brakes tab already uses for its rotor short-list + DXF export. Same physics,
    same single source of truth (`render_mesh_and_dxf` still does the work); only
    the placement changes: a dedicated '📐 … — mesh & DXF export' expander that
    reads the tab's live, member-entered numbers.

    Call this once, near the bottom of a subsystem tab body, right beside its
    `render_documentation_expander(...)` call."""
    _nm = title_name or _VC_LABEL.get(
        subsystem_key, subsystem_key.replace("-", " ").title())
    with st.expander(f"📐  {_nm} — mesh & DXF export", expanded=False):
        _hint = _EXPORT_SOURCE_HINT.get(subsystem_key) or {}
        _where = _hint.get("where", f"the {_nm} tab")
        _render_mesh_dxf_flow_strip(_where, subsystem_key=subsystem_key)
        try:
            render_mesh_and_dxf(
                subsystem_key, key_prefix=f"{key_prefix}_mesh",
                candidates=candidates, title_name=_nm)
        except Exception as _me:
            st.caption(f"Mesh/DXF export unavailable: {_me}")


# Per-topology definition of the upright/carrier mount points — the outboard
# joints where the links meet the upright. These are the points the mount-plate
# export cares about: the PCD is the span across them and the bolt count is how
# many there are. The wishbone path stays on the editable `hp` dict; every other
# architecture reads its live points from the solved mechanism (kin.named_points),
# so the panel now tracks the selected topology instead of always showing
# wishbone ball-joints. Each entry: (point-name-in-mechanism, human label,
# is_optional). The first two non-optional points define the PCD span.
_UPRIGHT_MOUNTS = {
    "macpherson_strut": [("lo", "Lower ball joint", False),
                         ("sl", "Strut lower mount", False),
                         ("tro", "Tie-rod outer", True)],
    "multilink": [("out0", "Lower-fore link end", False),
                  ("out2", "Upper-camber link end", False),
                  ("out4", "Toe-link end", True)],
    "trailing_arm": [("hub", "Arm-to-hub joint", False),
                     ("wc", "Wheel centre", False)],
    "semi_trailing_arm": [("hub", "Arm-to-hub joint", False),
                          ("wc", "Wheel centre", False)],
    "solid_axle": [("lout0", "Lower link end", False),
                   ("lout2", "Upper link end", False),
                   ("lat", "Lateral-device end", True)],
    "twist_beam": [("hubL", "Trailing-arm hub", False),
                   ("beamL", "Beam attach", False)],
    "truck_steer_linkage": [("sp", "Spindle joint", False),
                            ("sa", "Steering-arm joint", False),
                            ("tri", "Tie-rod inner", True)],
    "from_links": [("upper_outer", "Upper outer", False),
                   ("lower_outer", "Lower outer", False),
                   ("tie_rod_outer", "Tie-rod outer", True)],
}


def render_suspension_hardpoint_summary(*, key_prefix="susp_hp"):
    """Bring the live hardpoint numbers INTO the suspension tab, for ANY topology.

    Suspension is the one subsystem whose export inputs (the outboard mount
    joints) live in the left sidebar, not in the tab body — which is exactly
    what confused members hunting for 'where the numbers come from'. This panel
    closes that gap: it shows the actual upright-mount points and the PCD + bolt
    count they derive (the very numbers the DXF export reads), and points plainly
    to the sidebar editor. On a double-wishbone it reads the editable `hp` dict;
    on every other architecture it reads the solved mechanism's live points so
    the tiles, PCD and bolt count follow the selected topology. It reads state
    only — the sidebar remains the single place you edit — so there's one source
    of truth, mirrored where people look first."""
    topo = st.session_state.get("topology", "double_wishbone")
    is_wb = (topo == "double_wishbone")

    def _fmt(v):
        if v is None or len(v) < 3:
            return None
        try:
            xs = [units_mod.from_metric(float(c), "mm") for c in v[:3]]
        except Exception:
            return None
        fmt = "%.1f" if _U_LEN == "in" else "%.0f"
        return "(" + ", ".join(fmt % c for c in xs) + f") {_U_LEN}"

    # Resolve the mount-point spec + a coordinate lookup for the active topology.
    if is_wb:
        _spec = [("upper_outer", "Upper ball joint", False),
                 ("lower_outer", "Lower ball joint", False),
                 ("tie_rod_outer", "Tie-rod outer", True)]
        _hp = st.session_state.get("hp", {}) or {}
        def _coord(name):
            return _hp.get(name)
        _src_txt = "SIDEBAR ▸ HARDPOINT EDITOR"
    else:
        _spec = _UPRIGHT_MOUNTS.get(topo)
        _named = {}
        try:
            _kin = globals().get("kin")
            if _kin is not None and hasattr(_kin, "named_points"):
                _named = {n: [float(c) for c in np.asarray(p, float).ravel()]
                          for n, p in _kin.named_points().items()}
        except Exception:
            _named = {}
        def _coord(name):
            return _named.get(name)
        _src_txt = f"SIDEBAR ▸ {_TOPO_LABELS.get(topo, topo).upper()}"

    _title_arch = ("from your hardpoints" if is_wb
                   else _TOPO_LABELS.get(topo, topo))

    # If we have no spec (unknown topology) or no live points, degrade gracefully.
    if not _spec:
        st.markdown(
            f'''
<div class="hp-card">
  <div class="hp-top">
    <span class="hp-ttl">📐 Upright mount — {_title_arch}</span>
    <span class="hp-src">{_src_txt} · {_U_LEN}</span>
  </div>
  <div class="hp-note">This architecture exports from a representative mount
  set. Edit its geometry in the left sidebar under <b>Suspension geometry
  (hardpoint editor)</b>.</div>
</div>
''',
            unsafe_allow_html=True)
        return

    # Build the point tiles + collect the two PCD-defining (non-optional) joints.
    _tiles = ""
    _pcd_pts = []
    for name, label, optional in _spec:
        v = _coord(name)
        disp = _fmt(v)
        if disp is None:
            _txt = "not set" + (" (optional)" if optional else "")
            _tiles += (f'<div class="hp-pt miss"><div class="l">{label}</div>'
                       f'<div class="v">{_txt}</div></div>')
        else:
            _tiles += (f'<div class="hp-pt"><div class="l">{label}</div>'
                       f'<div class="v">{disp}</div></div>')
            if not optional and len(_pcd_pts) < 2:
                _pcd_pts.append(v)

    # Derived numbers the export reads: span across the two primary mount joints
    # → PCD; total present mount points → bolt count.
    _pcd = None
    if len(_pcd_pts) == 2:
        try:
            a, b = _pcd_pts[0], _pcd_pts[1]
            _span = ((a[0]-b[0])**2 + (a[1]-b[1])**2 + (a[2]-b[2])**2) ** 0.5
            _pcd = units_mod.from_metric(float(_span), "mm")
        except Exception:
            _pcd = None
    _nb = sum(1 for name, _lbl, _opt in _spec if _coord(name) is not None)

    _pcd_fmt = "%.1f" if _U_LEN == "in" else "%.0f"
    _pcd_txt = (f'{_pcd_fmt % _pcd} {_U_LEN}' if _pcd is not None else "—")
    _pcd_cls = "" if _pcd is not None else "warn"

    _derived = (
        f'<div class="hp-derived">'
        f'<div class="hp-d"><span class="k">Mount PCD (span)</span>'
        f'<span class="n {_pcd_cls}">{_pcd_txt}</span></div>'
        f'<div class="hp-d"><span class="k">Bolt count</span>'
        f'<span class="n">{_nb}</span></div>'
        f'</div>')

    # Status note: name the exact next action, in the sidebar, where it happens.
    if _pcd is None:
        if is_wb:
            _note = ('<div class="hp-note">Set the <b>upper</b> and <b>lower ball '
                     'joints</b> to define the mount PCD. Edit them in the left '
                     'sidebar under <b>Suspension geometry (hardpoint editor) → '
                     'Pickup coordinates</b>.</div>')
        else:
            _note = ('<div class="hp-note">Move the outboard mount points in the '
                     'left sidebar under <b>Suspension geometry (hardpoint '
                     'editor)</b> to define the mount PCD for this '
                     'architecture.</div>')
    else:
        _note = ('<div class="hp-note"><span class="hp-here">✓ feeding the '
                 'export</span> &nbsp;These are the numbers the Mesh &amp; DXF '
                 'exporter reads. Edit any point in the left sidebar under '
                 '<b>Suspension geometry (hardpoint editor)</b> and this '
                 'updates live.</div>')

    st.markdown(
        f'''
<div class="hp-card">
  <div class="hp-top">
    <span class="hp-ttl">📐 Upright mount — {_title_arch}</span>
    <span class="hp-src">{_src_txt} · {_U_LEN}</span>
  </div>
  <div class="hp-grid">{_tiles}</div>
  {_derived}
  {_note}
</div>
''',
        unsafe_allow_html=True)


def render_process_library(subsystem_key, *, key_prefix, title=None):
    """Render the 'how is this made?' search box + results inside a tab.

    Designed to be frictionless for a brand-new member who does NOT yet know
    manufacturing vocabulary: the search box is always visible (no hunting in an
    expander), the subsystem's articles are shown immediately even before you
    type anything, and one-tap example chips run a real search for you. Results
    are scoped to ``subsystem_key`` plus shared "general" rows; ``key_prefix``
    keeps widget keys unique so the feature can live in many tabs at once.
    """
    _label = proclib_mod.SUBSYSTEM_LABELS.get(subsystem_key, subsystem_key)
    df = _proclib_load()


    # Gate: only show the process library if the user opts in.
    _show_pl = st.checkbox(
        "New on this part / not sure how to approach it?",
        key=f"{key_prefix}_proclib_gate",
        value=False,
    )
    if _show_pl:
        _qkey = f"{key_prefix}_proclib_q"
        # A pending chip tap writes the query here, before the text_input is built.
        _pending = st.session_state.pop(f"{_qkey}__pending", None)
        if _pending is not None:
            st.session_state[_qkey] = _pending

        # --- Always-visible header + search box (no outer expander to click). --- #
        st.markdown(
            '<p class="hint" style="margin:6px 0 4px;">🛠️ <b>New to this part? '
            'Not sure how it\u2019s made?</b> Type what you\u2019re working on below '
            "\u2014 a component (<i>upright, wishbone, busbar, rotor</i>) or a "
            "process (<i>carbon layup, TIG, bonding</i>) \u2014 or just tap one of "
            "the examples. Real resources appear instantly, each with a one-line "
            "summary so you click the right one.</p>",
            unsafe_allow_html=True)

        # Tap-only questionnaire on-ramp (sits above the search box).
        _render_proclib_questionnaire(df, subsystem_key, key_prefix=key_prefix)

        _qcol, _btncol = st.columns([7, 1])
        _q = _qcol.text_input(
            "Search the process library",
            key=_qkey,
            placeholder="e.g. upright, carbon layup, busbar welding, brake rotor…",
            label_visibility="collapsed")
        if _btncol.button("Clear", key=f"{key_prefix}_proclib_clear",
                          help="Clear the search and browse the whole pool again."):
            st.session_state[f"{_qkey}__pending"] = ""
            st.rerun()

        # --- One-tap example chips, pulled from THIS subsystem's real articles. -- #
        _chips = _proclib_chip_words(df, subsystem_key, n=6)
        if _chips:
            st.markdown('<p class="hint" style="margin:6px 0 2px;">Try:</p>',
                        unsafe_allow_html=True)
            _ccols = st.columns(len(_chips))
            for _ci, _word in enumerate(_chips):
                if _ccols[_ci].button(_word, key=f"{key_prefix}_chip_{_ci}",
                                      use_container_width=True):
                    st.session_state[f"{_qkey}__pending"] = _word
                    st.rerun()

        _all_pool = st.checkbox(
            "Search every subsystem (not just this one)",
            key=f"{key_prefix}_proclib_all", value=False)

        _sub = None if _all_pool else subsystem_key
        try:
            _res = proclib_mod.filter_library(df, _q, subsystem=_sub,
                                              include_general=True)
        except Exception:
            _res = df.iloc[0:0]

        _total_pool = len(proclib_mod.filter_library(df, "", subsystem=_sub,
                                                     include_general=True))
        if not _q.strip():
            # Empty box: browse the whole pool right away — no dead end for someone
            # who doesn't know what to type yet.
            st.caption(f"Showing all {_total_pool} articles for {_label} "
                       "(plus shared basics). Type or tap above to narrow it down.")
        else:
            st.caption(f"{len(_res)} of {_total_pool} articles match "
                       f"\u201c{_q.strip()}\u201d.")

        if len(_res) == 0 and _q.strip():
            st.info("No matches yet. Try a shorter or more general word (e.g. just "
                    "\u201cweld\u201d or \u201ccarbon\u201d), tap a *Try* chip, or "
                    "tick *Search every subsystem*. Still nothing? Add the resource "
                    "you wish existed at the bottom \u2014 the next new member will "
                    "thank you.")
        else:
            # Card per article: bold component + process, 2-sentence summary, link.
            _proclib_render_cards(_res, show_subsystem=_all_pool)

        # ---- Add to the shared library (anyone on the team) ---------------- #
        with st.expander("➕  Add an article to the shared library", expanded=False):
                st.markdown(
                    '<p class="hint" style="margin:0 0 6px;">Found a good resource, '
                    "or know how a part is really made here? Add it — it saves to the "
                    "team's shared workbook so everyone sees it on their next "
                    "load.</p>", unsafe_allow_html=True)
                _c1, _c2 = st.columns(2)
                _f_comp = _c1.text_input("Component", key=f"{key_prefix}_pl_comp",
                                         placeholder="e.g. Upright / Knuckle")
                _f_proc = _c2.text_input("Process", key=f"{key_prefix}_pl_proc",
                                         placeholder="e.g. 5-axis CNC")
                _sub_keys = list(proclib_mod.SUBSYSTEMS)
                _def_idx = _sub_keys.index(subsystem_key) if subsystem_key in _sub_keys else len(_sub_keys) - 1
                _f_sub = st.selectbox(
                    "Subsystem pool", _sub_keys, index=_def_idx,
                    format_func=lambda k: proclib_mod.SUBSYSTEM_LABELS.get(k, k),
                    key=f"{key_prefix}_pl_sub")
                _f_summ = st.text_input(
                    "Summary (1\u20132 sentences: what it covers + why it helps)",
                    key=f"{key_prefix}_pl_summ",
                    placeholder="What does the article cover, and why is it useful "
                                "to someone making this part?")
                _f_link = st.text_input("Link (URL)", key=f"{key_prefix}_pl_link",
                                        placeholder="https://…")
                _c3, _c4 = st.columns(2)
                _f_tags = _c3.text_input("Extra search tags (optional)",
                                         key=f"{key_prefix}_pl_tags",
                                         placeholder="comma, separated, keywords")
                _f_who = _c4.text_input("Your name (optional)",
                                        key=f"{key_prefix}_pl_who",
                                        placeholder="so the team knows who to ask")
                if st.button("Add to library", key=f"{key_prefix}_pl_add"):
                    if not _f_comp.strip() and not _f_proc.strip():
                        st.warning("Give at least a component or a process.")
                    elif not _f_link.strip():
                        st.warning("Add a link so the article is actually reachable.")
                    else:
                        try:
                            st.session_state.proclib_df = proclib_mod.append_row(
                                _f_comp, _f_proc, _f_sub, _f_summ, _f_link,
                                tags=_f_tags, added_by=_f_who)
                            st.success("Added to the shared library. Reloading…")
                            st.rerun()
                        except Exception as _e:
                            st.error(f"Couldn't save: {_e}")

        # Download the whole workbook for offline reference / backup.
        try:
            _full = _proclib_load()
            _csv = _full.to_csv(index=False)
            st.download_button(
                "⬇️  Download the full library (CSV)", _csv,
                file_name="process_library.csv", mime="text/csv",
                key=f"{key_prefix}_proclib_dl")
        except Exception:
            pass


def _render_rotor_thermal(_bt, _mass, kin):
    """The Brakes ▸ Rotor thermal view. `_bt` is the imported brake_thermal
    module (already verified present by the caller), `_mass` the live car mass,
    `kin` the current kinematics object for the optional lap-sim coupling."""
    _bt_mod_le = _bt.lap_brake_energy
    st.markdown(
        '<p class="hint"><b>Triage your Ansys runs.</b> This is a fast 0-D '
        'energy balance — single-mass rotor, the same lumped-thermal approach '
        'as the tyre model — so you can sweep dozens of rotor geometries here '
        'in milliseconds and only mesh the 2–3 survivors. It is <b>not</b> an '
        'FEA: no temperature field, no coning, no vane flow, no stress. Use it '
        'to <b>narrow the design space</b>, then take the short-list to Ansys.</p>',
        unsafe_allow_html=True)

    _tc = st.columns(4)
    _uSpd = units_mod.label("km/h")
    _uLen = units_mod.label("mm")
    _tk_v0_disp = _tc[0].number_input(
        f"Stop from ({_uSpd})", units_mod.from_metric(40.0, "km/h"),
        units_mod.from_metric(140.0, "km/h"),
        value=units_mod.from_metric(100.0, "km/h"),
        step=units_mod.from_metric_delta(5.0, "km/h"),
        help="Top speed of the hardest single stop on track.")
    _tk_v0 = units_mod.to_metric(_tk_v0_disp, "km/h")   # km/h (model takes km/h→/3.6)
    _tk_bias = _tc[1].slider("Front bias (%)", 50, 80,
                             int(st.session_state.get("brake_front_bias_pct", 62)),
                             1, help="Front axle's share of braking energy — from "
                             "the Bias & lock-up view.") / 100.0
    _tk_dia_disp = _tc[2].number_input(
        f"Rotor ⌀ ({_uLen})", units_mod.from_metric(180.0, "mm"),
        units_mod.from_metric(320.0, "mm"), value=units_mod.from_metric(220.0, "mm"),
        step=units_mod.from_metric_delta(5.0, "mm"), key="bt_dia")
    _tk_dia = units_mod.to_metric(_tk_dia_disp, "mm")
    _tk_th_disp = _tc[3].number_input(
        f"Rotor thickness ({_uLen})", units_mod.from_metric(3.0, "mm"),
        units_mod.from_metric(12.0, "mm"), value=units_mod.from_metric(5.0, "mm"),
        step=units_mod.from_metric_delta(0.5, "mm"),
        format="%.2f" if units_mod.is_us() else "%.1f", key="bt_th")
    _tk_th = units_mod.to_metric(_tk_th_disp, "mm")

    _tc2 = st.columns(4)
    _tk_vent = _tc2[0].slider("Vented fraction", 0.0, 0.6, 0.0, 0.05,
                              help="0 = solid disc. Raise to approximate the "
                              "material removed by cooling vanes/slots.")
    _tk_area = _tc2[1].slider("Cooling-area factor", 1.5, 4.0, 2.4, 0.1,
                              help="≈2 = both faces of a solid disc; higher for a "
                              "vented/vaned rotor with more wetted area.")
    # If the lap-sim button ran on the previous rerun, it parked results in
    # staging keys. Apply them to the widget keys HERE — before the widgets are
    # instantiated — which is the only point Streamlit allows writing a widget's
    # state key. Then clear the staging flag so manual edits aren't overwritten.
    if st.session_state.pop("brake_lap_apply", False):
        if "brake_lap_pwr" in st.session_state:
            st.session_state["bt_pwr"] = st.session_state["brake_lap_pwr"]
        if "brake_lap_air" in st.session_state:
            st.session_state["bt_air"] = units_mod.from_metric(
                st.session_state["brake_lap_air"], "km/h")
    st.session_state.setdefault("bt_pwr", 1200.0)
    st.session_state.setdefault("bt_air", units_mod.from_metric(55.0, "km/h"))
    _tk_pwr = _tc2[2].number_input("Avg brake power / front rotor",
                                   200.0, 8000.0, step=100.0, key="bt_pwr",
                                   help="Time-averaged power into ONE front rotor "
                                   "over the stint. Type it, or pull it from a lap "
                                   "sim below.")
    _uAir = units_mod.label("km/h")
    _tk_air_disp = _tc2[3].number_input(
        f"Airflow speed ({_uAir})",
        units_mod.from_metric(20.0, "km/h"),
        units_mod.from_metric(120.0, "km/h"),
        step=units_mod.from_metric_delta(5.0, "km/h"),
        key="bt_air",
        help="Representative car speed during braking — "
        "sets convection. Auto-filled from the lap sim's "
        "mean braking speed.")
    _tk_air = units_mod.to_metric(_tk_air_disp, "km/h")   # km/h (model takes km/h→/3.6)

    # ---- pull the average braking power straight from a lap sim -----------
    st.markdown('<p class="hint" style="margin:6px 0 2px;border-top:1px solid '
                'var(--line);padding-top:8px;"><b>Or compute it from a real lap</b> '
                '— the velocity trace already implies exactly how much energy the '
                'brakes dump per lap.</p>', unsafe_allow_html=True)
    if st.button("Run lap sim → average braking power", key="bt_runlap"):
        try:
            _vd_b = VehicleDynamics(
                VehicleParams(**{k: v for k, v in st.session_state.vp.items()
                                 if k in VehicleParams.__dataclass_fields__}),
                front_kin=kin, rear_kin=kin,
                tire=globals().get("_live_tire_lap"))
            _lp = lapsim_mod.LapSimParams(mass=float(_mass))
            _sim_b = lapsim_mod.LapSimulator(_vd_b, params=_lp)
            _res_b = _sim_b.simulate(lapsim_mod.autocross_track(laps=1))
            if _res_b.ok:
                _lbe = _bt_mod_le(
                    _res_b.distance, _res_b.speed, mass_kg=float(_mass),
                    front_bias=_tk_bias, lap_time_s=_res_b.lap_time,
                    long_g=_res_b.long_g)
                st.session_state["brake_lap_pwr"] = float(min(max(
                    round(_lbe.p_front_avg_w, 0), 200.0), 8000.0))
                st.session_state["brake_lap_air"] = float(min(max(
                    round(_lbe.v_brake_mean_ms * 3.6, 0), 20.0), 120.0))
                st.session_state["brake_lap_apply"] = True
                st.session_state["brake_lap_meta"] = (
                    f"{_res_b.lap_time:.1f} s lap · {uval(_lbe.q_lap_j/1000, 'kJ')} "
                    f"braking/lap · {_lbe.n_brake_samples} brake samples · peak "
                    f"{uval(_lbe.p_front_peak_w/1000, 'kW')}/rotor")
                st.rerun()
            else:
                st.warning("Lap sim couldn't run on the default autocross with "
                           "this car — type the average power instead.")
        except Exception as _le:
            st.warning(f"Couldn't run the lap sim ({_le}). Type the average power "
                       "instead.")
    if st.session_state.get("brake_lap_meta"):
        st.caption("From lap sim: " + st.session_state["brake_lap_meta"]
                   + ". Power & airflow above are filled from this lap.")

    _bt_params = _bt.BrakeThermalParams(area_factor=float(_tk_area))
    _bt_model = _bt.BrakeThermalModel(_bt_params)

    _single = _bt_model.single_stop(
        mass_kg=_mass, v0_ms=_tk_v0 / 3.6, front_bias=_tk_bias,
        diameter_mm=_tk_dia, thickness_mm=_tk_th, vented_fraction=_tk_vent)
    _equil = _bt_model.equilibrium(
        p_brake_avg_w=_tk_pwr, v_work_ms=_tk_air / 3.6, diameter_mm=_tk_dia)

    _mt = st.columns(4)
    umetric(_mt[0], "Energy / front rotor", _single.q_per_rotor_j / 1000, "kJ",
            help="Kinetic energy this one rotor absorbs in the stop.")
    umetric(_mt[1], "Rotor mass (est)", _single.rotor_mass_kg, "kg", fmt="{:.2f}",
            help="First-order friction-ring mass from ⌀, thickness and vented "
            "fraction — a thermal-capacity estimate, not a CAD mass.")
    umetric(_mt[2], "Single-stop peak", _single.T_peak_c, "°C",
            help="Bulk temperature after one stop from a cold rotor.")
    umetric(_mt[3], "Endurance equilibrium", _equil.T_equilibrium_c, "°C",
            help="Steady-state temp where convection+radiation balance the "
            "average braking power. This is the fade-relevant number.")

    _eq_disp = units_mod.from_metric(_equil.T_equilibrium_c, "°C")
    _eq_u = units_mod.label("°C")
    if _equil.T_equilibrium_c > 650:
        st.error(f"Equilibrium ~{_eq_disp:.0f} {_eq_u} — grey iron "
                 "fades/glazes hard here. Bigger ⌀, more vent area, or a higher-"
                 "temp rotor material; this geometry likely needs Ansys to confirm "
                 "it survives a stint.")
    elif _equil.T_equilibrium_c > 500:
        st.warning(f"Equilibrium ~{_eq_disp:.0f} {_eq_u} — into the fade-"
                   "risk band for an iron rotor. Worth meshing to check the "
                   "hot-spot, not just the bulk.")
    else:
        st.success(f"Equilibrium ~{_eq_disp:.0f} {_eq_u} — bulk thermal "
                   "load looks manageable. Mesh to confirm the hot-spot and "
                   "coning, but this geometry is a sensible candidate.")

    _sweep = _bt_model.mass_temp_sweep(
        mass_kg=_mass, v0_ms=_tk_v0 / 3.6, front_bias=_tk_bias,
        thickness_mm=_tk_th, dia_min_mm=180.0, dia_max_mm=300.0, n=25,
        vented_fraction=_tk_vent)
    _is_us = units_mod.is_us()
    # mass axis: g in metric, lb in US; temp axis: °C / °F
    _mass_unit_lbl = "lb" if _is_us else "g"
    _tmp_unit_lbl = units_mod.label("°C")
    _dia_unit_lbl = units_mod.label("mm")

    def _mass_disp(kg):
        return units_mod.from_metric(kg, "kg") if _is_us else kg * 1000.0

    def _dia_disp(mm):
        return units_mod.from_metric(mm, "mm")

    _fig_mt = go.Figure()
    _fig_mt.add_trace(go.Scatter(
        x=[_mass_disp(r["rotor_mass_kg"]) for r in _sweep],
        y=[units_mod.from_metric(r["T_peak_c"], "°C") for r in _sweep],
        mode="lines+markers", line=dict(color=AMBER, width=3),
        text=[f"⌀{_dia_disp(r['diameter_mm']):.1f} {_dia_unit_lbl}"
              for r in _sweep],
        hovertemplate="%{text}<br>%{x:.1f} " + _mass_unit_lbl
        + "<br>%{y:.0f} " + _tmp_unit_lbl + "<extra></extra>",
        name="single-stop peak"))
    _fig_mt.add_trace(go.Scatter(
        x=[_mass_disp(_single.rotor_mass_kg)],
        y=[units_mod.from_metric(_single.T_peak_c, "°C")],
        mode="markers", marker=dict(color=CYAN, size=13, symbol="diamond"),
        name="your rotor", hovertemplate="your rotor<extra></extra>"))
    _fig_mt.update_layout(**PLOT_LAYOUT,
                          title="Mass ↔ peak-temp frontier (single stop) — pick "
                          "the knee, mesh those",
                          xaxis_title=f"rotor mass ({_mass_unit_lbl})",
                          yaxis_title=f"single-stop peak temp ({_tmp_unit_lbl})",
                          height=360)
    st.plotly_chart(_fig_mt, width="stretch")

    # ---- Transient: temperature trace through a repeated-stop fade test -----
    st.markdown('<p class="hint" style="margin:10px 0 2px;border-top:1px solid '
                'var(--line);padding-top:10px;"><b>Fade test — does it cook over a '
                'stint?</b> Repeated hard stops with cooling between them. The '
                'single-stop number misses thermal <i>accumulation</i>; this '
                'shows the rotor (and pad) climbing run to run.</p>',
                unsafe_allow_html=True)
    _ft = st.columns(4)
    _ft_mat = _ft[0].selectbox("Rotor material",
                               list(_bt.ROTOR_MATERIALS.keys()),
                               format_func=lambda k: _bt.ROTOR_MATERIALS[k].name,
                               key="bt_mat")
    _ft_n = _ft[1].number_input("Stops in the test", 3, 30, value=10, step=1,
                                key="bt_nstops")
    _ft_gap = _ft[2].number_input("Cooling gap (s)", 2.0, 20.0, value=6.0,
                                  step=1.0, key="bt_gap",
                                  help="Seconds of cruise-cooling between stops.")
    _ft_duct = _ft[3].slider("Brake-duct airflow gain", 1.0, 3.0, 1.0, 0.1,
                             key="bt_duct", help="1.0 = no duct. A good cooling "
                             "duct raises local airflow 2–3×.")

    # Capture the material + test conditions for the Documentation report.
    try:
        record_activity("brakes", "material",
                        f"Rotor material: {_bt.ROTOR_MATERIALS[_ft_mat].name}")
        record_activity("brakes", "condition",
                        f"Fade test: {int(_ft_n)} stops, {_ft_gap:g}s cooling gap, "
                        f"{_ft_duct:g}× duct airflow")
    except Exception:
        pass

    _tn = _bt.TwoNodeParams(
        rotor_mat=_ft_mat, diameter_mm=_tk_dia, thickness_mm=_tk_th,
        vented_fraction=_tk_vent, area_factor=float(_tk_area),
        duct_gain=float(_ft_duct))
    _pw, _vs, _dt = _bt.fade_test_power_series(
        mass_kg=_mass, v0_ms=_tk_v0 / 3.6, front_bias=_tk_bias,
        n_stops=int(_ft_n), gap_s=float(_ft_gap))
    _trace = _bt.TwoNodeRotorPad(_tn).simulate(_pw, _dt, v_series=_vs)

    _ftm = st.columns(3)
    umetric(_ftm[0], "Rotor peak (fade)", _trace.T_rotor_peak_c, "°C")
    umetric(_ftm[1], "Pad peak (fade)", _trace.T_pad_peak_c, "°C",
            help="Pads fade on THEIR temperature — track this, not just the "
            "rotor.")
    umetric(_ftm[2], "Material ceiling", _trace.material_T_max_c, "°C",
            delta=("OVER" if _trace.over_material_limit else "ok"),
            delta_color=("inverse" if _trace.over_material_limit else "normal"))

    try:
        record_activity(
            "brakes", "calculation",
            f"Fade test result: rotor peak {_trace.T_rotor_peak_c:.0f}°C, "
            f"pad peak {_trace.T_pad_peak_c:.0f}°C vs "
            f"{_bt.ROTOR_MATERIALS[_ft_mat].name} limit "
            f"{_trace.material_T_max_c:.0f}°C "
            f"({'OVER LIMIT' if _trace.over_material_limit else 'within limit'})")
    except Exception:
        pass

    _fig_ft = go.Figure()
    _fig_ft.add_trace(go.Scatter(x=_trace.t_s,
                                 y=uconv_series(_trace.T_rotor_c, "°C"),
                                 mode="lines",
                                 line=dict(color=RED, width=2.5), name="rotor"))
    _fig_ft.add_trace(go.Scatter(x=_trace.t_s,
                                 y=uconv_series(_trace.T_pad_c, "°C"),
                                 mode="lines",
                                 line=dict(color=AMBER, width=2), name="pad"))
    _fig_ft.add_hline(y=units_mod.from_metric(_trace.material_T_max_c, "°C"),
                      line_dash="dot", line_color="#ff5a52",
                      annotation_text=f"{_bt.ROTOR_MATERIALS[_ft_mat].name} limit")
    _fig_ft.update_layout(**PLOT_LAYOUT, title="Fade test — rotor & pad temperature",
                          xaxis_title="time (s)",
                          yaxis_title=units_mod.ulabel("temperature (°C)"),
                          height=340)
    st.plotly_chart(_fig_ft, width="stretch")
    if _trace.over_material_limit:
        st.error(f"Rotor exceeds the {_bt.ROTOR_MATERIALS[_ft_mat].name} service "
                 f"limit ({units_mod.from_metric(_trace.material_T_max_c, '°C'):.0f} "
                 f"{units_mod.label('°C')}) during the test — this "
                 "material/geometry won't survive the stint. Bigger ⌀, vent it, "
                 "add duct airflow, or change material.")

    # ---- 1-D through-thickness: surface spike + crack-risk screen -----------
    with st.expander("🔬 Surface-vs-core gradient & thermal-crack screen "
                     "(1-D through-thickness)"):
        st.markdown('<p class="hint">The lumped trace above is the rotor\'s '
                    '<i>average</i>. In a hard stop the friction <b>surface</b> '
                    'spikes far hotter than the core — and that gradient is what '
                    'cracks rotors. This resolves temperature through the '
                    'thickness (1-D) and screens crack risk from the surface-to-'
                    'core ΔT. Still 1-D: no hot-spot location or vane-root '
                    'stress — that\'s Ansys. A screening number, flagged '
                    'synthesized.</p>', unsafe_allow_html=True)
        _od = _bt.OneDRotor(_tn, n_nodes=12).simulate(_pw, _dt, v_series=_vs)
        _odm = st.columns(4)
        _surf_delta = units_mod.from_metric_delta(
            _od.T_surface_peak_c - _trace.T_rotor_peak_c, "°C")
        umetric(_odm[0], "Surface peak", _od.T_surface_peak_c, "°C",
                delta=f"+{_surf_delta:.0f} vs bulk",
                help="The friction face runs this much hotter than the average "
                "the lumped model reports.")
        # Peak gradient is a temperature DIFFERENCE — convert factor-only.
        _grad_disp = units_mod.from_metric_delta(_od.dT_gradient_peak_c, "°C")
        _odm[1].metric("Peak gradient", f"{_grad_disp:.0f} {units_mod.label('°C')}",
                       help="Surface minus core — the driver of thermal cracking.")
        umetric(_odm[2], "Thermal stress", _od.sigma_peak_mpa, "MPa",
                help=f"Screening estimate vs ~"
                f"{units_mod.from_metric(_od.sigma_limit_mpa, 'MPa'):.0f} "
                f"{units_mod.label('MPa')} for this material.")
        _risk_color = {"low": "normal", "elevated": "off", "high": "inverse"}
        _odm[3].metric("Crack risk", _od.crack_risk.upper(),
                       delta=("watch" if _od.crack_risk != "low" else "ok"),
                       delta_color=_risk_color.get(_od.crack_risk, "normal"))

        _fig_1d = go.Figure()
        _fig_1d.add_trace(go.Scatter(x=_od.t_s,
                                     y=uconv_series(_od.T_surface_c, "°C"),
                                     mode="lines",
                                     line=dict(color=RED, width=2.5),
                                     name="surface"))
        _fig_1d.add_trace(go.Scatter(x=_od.t_s,
                                     y=uconv_series(_od.T_core_c, "°C"),
                                     mode="lines",
                                     line=dict(color=CYAN, width=2),
                                     name="core"))
        _fig_1d.update_layout(**PLOT_LAYOUT,
                              title="Through-thickness: surface vs core temperature",
                              xaxis_title="time (s)",
                              yaxis_title=units_mod.ulabel("temperature (°C)"),
                              height=320)
        st.plotly_chart(_fig_1d, width="stretch")
        if _od.crack_risk == "high":
            st.error("HIGH thermal-crack risk: the surface-to-core gradient drives "
                     "stress near this material's limit. Thinner section, higher-"
                     "conductivity material, or gentler duty — and definitely mesh "
                     "this one in Ansys before committing.")
        elif _od.crack_risk == "elevated":
            st.warning("Elevated crack risk — worth meshing to check the surface "
                       "stress, not just the bulk temperature.")

    # ---- Material comparison: same test, every material ---------------------
    with st.expander("Compare rotor materials on this exact fade test"):
        _rows = []
        _mc_uT = units_mod.label("°C")
        _mc_uM = "lb" if units_mod.is_us() else "g"
        for _mk in _bt.ROTOR_MATERIALS:
            _tt = _bt.TwoNodeRotorPad(_bt.TwoNodeParams(
                rotor_mat=_mk, diameter_mm=_tk_dia, thickness_mm=_tk_th,
                vented_fraction=_tk_vent, area_factor=float(_tk_area),
                duct_gain=float(_ft_duct))).simulate(_pw, _dt, v_series=_vs)
            _m = _bt.ROTOR_MATERIALS[_mk]
            _mass_disp = (round(units_mod.from_metric(_tt.rotor_mass_kg, "kg"), 2)
                          if units_mod.is_us() else round(_tt.rotor_mass_kg * 1000))
            _rows.append({
                "Material": _m.name,
                f"Rotor mass ({_mc_uM})": _mass_disp,
                f"Peak rotor ({_mc_uT})": round(
                    units_mod.from_metric(_tt.T_rotor_peak_c, "°C")),
                f"Ceiling ({_mc_uT})": round(
                    units_mod.from_metric(_m.T_max_c, "°C")),
                "Verdict": "⚠ over limit" if _tt.over_material_limit else "ok",
            })
        st.dataframe(_rows, width="stretch", hide_index=True)
        st.caption("Lighter isn't free: carbon-carbon and Al-MMC cut mass hard "
                   "but Al-MMC's low ceiling can be exceeded under heavy braking, "
                   "and carbon only works once it's hot. Read mass AND verdict "
                   "together.")

    # ---- Cooling-duct spec: invert the equilibrium --------------------------
    with st.expander("What cooling duct do I need?"):
        _dt_c = st.columns(2)
        _duct_uT = units_mod.label("°C")
        # Input shows/accepts the active unit; we store the metric value.
        _tgt_default = units_mod.from_metric(500.0, "°C")
        _tgt_lo = units_mod.from_metric(200.0, "°C")
        _tgt_hi = units_mod.from_metric(700.0, "°C")
        _tgt_step = units_mod.from_metric_delta(25.0, "°C")
        _T_tgt_disp = _dt_c[0].number_input(
            f"Target rotor temp ({_duct_uT})", _tgt_lo, _tgt_hi,
            value=_tgt_default, step=_tgt_step, key="bt_ttgt",
            help="Keep the rotor at/below this over the stint.")
        _T_tgt = units_mod.to_metric(_T_tgt_disp, "°C")   # back to °C for the model
        _req = _bt.required_duct_gain(
            p_brake_avg_w=_tk_pwr, v_work_ms=_tk_air / 3.6, diameter_mm=_tk_dia,
            T_target_c=float(_T_tgt))
        if _req["achievable_unducted"]:
            _dt_c[1].success(f"No duct needed — the bare rotor holds "
                             f"{_T_tgt_disp:.0f} {_duct_uT} at this power.")
        else:
            _dt_c[1].warning(f"Need a duct raising airflow ≈"
                             f"{_req['required_duct_gain']:.1f}× "
                             f"(h {_req['h_unducted_w_m2K']:.0f}→"
                             f"{_req['h_needed_w_m2K']:.0f} W/m²K) to hold "
                             f"{_T_tgt_disp:.0f} {_duct_uT}.")

    # ---- ROTOR OPTIMISER: own the loop, mesh only the winners ---------------
    st.markdown('<p class="hint" style="margin:12px 0 2px;border-top:2px solid '
                'var(--accent);padding-top:10px;"><b>🎯 Optimise the rotor — '
                'instead of forty Ansys runs.</b> Searches diameter × thickness × '
                'vent × material for the <b>lightest rotor that still survives</b> '
                'your fade test, runs the whole space in ~1 s, and hands you the '
                'winner plus the mass-vs-temp Pareto front. Mesh the 2–3 knee '
                'points — not the whole sweep.</p>', unsafe_allow_html=True)

    _oc = st.columns(4)
    _opt_uT = units_mod.label("°C")
    _opt_Tcon_disp = _oc[0].number_input(
        f"Max allowed rotor temp ({_opt_uT})",
        units_mod.from_metric(300.0, "°C"), units_mod.from_metric(1000.0, "°C"),
        value=units_mod.from_metric(600.0, "°C"),
        step=units_mod.from_metric_delta(25.0, "°C"), key="bt_opt_tcon",
        help="The constraint: peak rotor temp over the fade test must stay "
        "below this.")
    _opt_Tcon = units_mod.to_metric(_opt_Tcon_disp, "°C")
    _opt_mats = _oc[1].multiselect("Materials to search",
                                   list(_bt.ROTOR_MATERIALS.keys()),
                                   default=["grey_cast_iron", "steel"],
                                   format_func=lambda k: _bt.ROTOR_MATERIALS[k].name,
                                   key="bt_opt_mats")
    _opt_nstops = _oc[2].number_input("Fade-test stops", 4, 20, value=8, step=1,
                                      key="bt_opt_nstops")
    _opt_fine = _oc[3].checkbox("Fine grid", value=False, key="bt_opt_fine",
                                help="Denser search (slower, ~3–4 s) for a "
                                "smoother Pareto front.")
    _opt_crack = st.checkbox("Also screen thermal-crack risk (1-D, slower ~8 s)",
                             value=False, key="bt_opt_crack",
                             help="Runs the through-thickness model on every "
                             "candidate too, and rejects HIGH crack-risk "
                             "geometries — narrows the mesh short-list further.")

    # ---- Pin dimensions: optimise material + vent at a KNOWN disc size ------
    # If the team already knows the rotor diameter and thickness (common once the
    # upright/caliper package is frozen), they don't want the lightest disc in the
    # whole space — they want the lightest material + vent combination AT THEIR
    # dimensions. Pinning collapses the diameter and thickness sweeps to a single
    # value each (steps=1), so the optimiser searches only material × vent.
    _opt_pin = st.checkbox(
        "Pin disc dimensions (optimise material + vent only)",
        value=False, key="bt_opt_pin",
        help="Hold diameter and thickness fixed at known values and search only "
             "material and vent fraction. Use this once the disc size is frozen "
             "and you just need to pick material and how much to vent/slot it.")
    _opt_dia_fix = None
    _opt_th_fix = None
    if _opt_pin:
        _pc = st.columns(2)
        _opt_dia_fix = unum(_pc[0], "Rotor diameter (mm)", 180.0, 320.0,
                            float(st.session_state.get("bt_opt_dia_fix", 240.0)),
                            "mm", step=2.0, key="bt_opt_dia_fix",
                            help="Your known outer diameter. Held fixed; the "
                                 "optimiser won't sweep it.")
        _opt_th_fix = unum(_pc[1], "Rotor thickness (mm)", 3.0, 12.0,
                           float(st.session_state.get("bt_opt_th_fix", 5.0)),
                           "mm", step=0.5, key="bt_opt_th_fix",
                           help="Your known disc thickness. Held fixed; the "
                                "optimiser won't sweep it.")
        _opt_vent_steps = st.slider(
            "Vent fractions to search", 2, 9, 6, 1, key="bt_opt_vent_steps",
            help="How many vent fractions (0 → 50%) to evaluate at your fixed "
                 "size. More steps = finer resolution on how much to vent/slot.")

    if st.button("🎯 Optimise rotor", key="bt_opt_run", type="primary"):
        if not _opt_mats:
            st.warning("Pick at least one material to search.")
        else:
            try:
                _axn.engage("brakes", "optimise_rotor")
            except Exception:
                pass
            _spin = ("Searching the design space (with crack screen)…"
                     if _opt_crack else "Searching the design space…")
            with st.spinner(_spin):
                _steps = ((14, 8) if _opt_fine else (10, 6))
                if _opt_pin:
                    # Collapse diameter & thickness to the fixed values (steps=1)
                    # and sweep only vent fraction across the chosen resolution.
                    _opt_kwargs = dict(
                        dia_range=(float(_opt_dia_fix), float(_opt_dia_fix)),
                        dia_steps=1,
                        th_range=(float(_opt_th_fix), float(_opt_th_fix)),
                        th_steps=1,
                        vent_steps=int(_opt_vent_steps),
                    )
                else:
                    _opt_kwargs = dict(dia_steps=_steps[0], th_steps=_steps[1])
                try:
                    _optres = _bt.optimise_rotor(
                        mass_kg=_mass, v0_ms=_tk_v0 / 3.6, front_bias=_tk_bias,
                        T_constraint_c=float(_opt_Tcon), materials=_opt_mats,
                        n_stops=int(_opt_nstops), area_factor=float(_tk_area),
                        duct_gain=float(st.session_state.get("bt_duct", 1.0)),
                        screen_cracks=bool(_opt_crack), **_opt_kwargs)
                except Exception as _opt_e:
                    try:
                        _axn.error("brakes", _opt_e, kind="optimise_rotor_failed")
                    except Exception:
                        pass
                    raise
            st.session_state["bt_opt_result"] = _optres
            st.session_state["bt_opt_had_crack"] = bool(_opt_crack)
            try:
                _axn.complete("brakes", "optimise_rotor")
            except Exception:
                pass

    _optres = st.session_state.get("bt_opt_result")
    if _optres is not None:
        _uT = units_mod.label("°C")
        _uL = units_mod.label("mm")
        _uM = "lb" if units_mod.is_us() else "g"

        def _T(c):  # absolute temperature
            return units_mod.from_metric(c, "°C")

        def _Td(c):  # temperature difference (margin)
            return units_mod.from_metric_delta(c, "°C")

        def _L(mm):
            return units_mod.from_metric(mm, "mm")

        def _M(kg):
            return units_mod.from_metric(kg, "kg") if units_mod.is_us() else kg * 1000.0

        if _optres.best is None:
            st.error(f"No rotor in the searched space stays under "
                     f"{_T(_optres.constraint_c):.0f} {_uT} over {int(_opt_nstops)} "
                     f"stops ({_optres.n_evaluated} candidates checked). Raise the "
                     "temp limit, add brake-duct airflow, vent the rotor, or accept "
                     "a bigger/heavier disc — then re-optimise.")
        else:
            _b = _optres.best
            _bm = _bt.ROTOR_MATERIALS[_b.material]
            st.success(
                f"**Lightest rotor that survives:** {_bm.name}, "
                f"⌀{_L(_b.diameter_mm):.1f} × {_L(_b.thickness_mm):.2f} {_uL}, "
                f"vent {_b.vented_fraction:.0%} → "
                f"**{_M(_b.rotor_mass_kg):.{1 if units_mod.is_us() else 0}f} {_uM}**, "
                f"peak {_T(_b.T_rotor_peak_c):.0f} {_uT} "
                f"({_Td(_b.margin_c):.0f} {_uT} under the {_T(_b.T_limit_c):.0f} "
                f"{_uT} limit). Searched {_optres.n_evaluated} geometries; "
                f"{len(_optres.feasible)} feasible.")

            # Pareto scatter: every candidate, feasible vs not, Pareto front, winner
            _fig_op = go.Figure()
            _infeas = [c for c in _optres.candidates if not c.feasible]
            _feas = _optres.feasible
            if _infeas:
                _fig_op.add_trace(go.Scatter(
                    x=[_M(c.rotor_mass_kg) for c in _infeas],
                    y=[_T(c.T_rotor_peak_c) for c in _infeas], mode="markers",
                    marker=dict(color=DIM, size=5, opacity=0.4),
                    name="over limit", hoverinfo="skip"))
            if _feas:
                _fig_op.add_trace(go.Scatter(
                    x=[_M(c.rotor_mass_kg) for c in _feas],
                    y=[_T(c.T_rotor_peak_c) for c in _feas], mode="markers",
                    marker=dict(color=CYAN, size=6, opacity=0.55),
                    name="feasible", hoverinfo="skip"))
            _fig_op.add_trace(go.Scatter(
                x=[_M(c.rotor_mass_kg) for c in _optres.pareto],
                y=[_T(c.T_rotor_peak_c) for c in _optres.pareto],
                mode="lines+markers", line=dict(color=AMBER, width=3),
                marker=dict(size=7),
                text=[f"{_bt.ROTOR_MATERIALS[c.material].name} "
                      f"⌀{_L(c.diameter_mm):.1f} {_L(c.thickness_mm):.2f}{_uL} "
                      f"vent{c.vented_fraction:.0%}"
                      for c in _optres.pareto],
                hovertemplate="%{text}<br>%{x:.1f} " + _uM + "<br>%{y:.0f} " + _uT
                + "<extra></extra>",
                name="Pareto front (mesh these)"))
            _fig_op.add_trace(go.Scatter(
                x=[_M(_b.rotor_mass_kg)], y=[_T(_b.T_rotor_peak_c)],
                mode="markers", marker=dict(color=RED, size=15, symbol="star"),
                name="lightest feasible", hovertemplate="winner<extra></extra>"))
            _fig_op.add_hline(y=_T(_optres.constraint_c), line_dash="dash",
                              line_color="#ff5a52",
                              annotation_text=f"limit {_T(_optres.constraint_c):.0f}{_uT}")
            _fig_op.update_layout(**PLOT_LAYOUT,
                                  title="Design space — every rotor, the Pareto "
                                  "front, and the winner",
                                  xaxis_title=f"rotor mass ({_uM})",
                                  yaxis_title=f"peak rotor temp over fade test ({_uT})",
                                  height=420)
            st.plotly_chart(_fig_op, width="stretch")

            # the handful worth meshing: knee of the feasible Pareto front
            _had_crack = st.session_state.get("bt_opt_had_crack", False)
            _knee = _optres.pareto[:6]
            _uT = units_mod.label("°C")       # °C or °F
            _uL = units_mod.label("mm")       # mm or in
            _uM = units_mod.label("kg")       # kg or lb
            _uS = units_mod.label("MPa")      # MPa or ksi

            def _cT(c_celsius):
                return round(units_mod.from_metric(c_celsius, "°C"))

            def _cL(mm):
                return round(units_mod.from_metric(mm, "mm"), 1)

            _rows = []
            for c in _knee:
                _row = {
                    "Material": _bt.ROTOR_MATERIALS[c.material].name,
                    f"⌀ ({_uL})": _cL(c.diameter_mm),
                    f"Thick ({_uL})": _cL(c.thickness_mm),
                    "Vent": f"{c.vented_fraction:.0%}",
                    f"Mass ({_uM})": round(
                        units_mod.from_metric(c.rotor_mass_kg, "kg"), 2),
                    f"Peak ({_uT})": _cT(c.T_rotor_peak_c),
                    # margin is a temperature DIFFERENCE: factor only, no +32 offset
                    f"Margin ({_uT})": round(
                        units_mod.from_metric_delta(c.margin_c, "°C")),
                }
                if _had_crack:
                    _row[f"Surface ({_uT})"] = _cT(c.T_surface_peak_c)
                    _row[f"Stress ({_uS})"] = round(
                        units_mod.from_metric(c.sigma_peak_mpa, "MPa"), 1)
                    _row["Crack"] = c.crack_risk
                _rows.append(_row)
            st.markdown("**Short-list to mesh in Ansys** (lightest feasible "
                        "geometries):")
            st.dataframe(_rows, width="stretch", hide_index=True)
            _extra = (" Crack-risk was screened too, so these survivors are clear "
                      "on both bulk temperature AND surface-gradient stress."
                      if _had_crack else "")
            st.caption("These are 0-D/transient survivors — confirm the hot-spot, "
                       "coning and stress in Ansys on this short-list. The model "
                       "found them; the FEA verifies them." + _extra)

            # ---- EXPORT TO CAD (DXF) --------------------------------------- #
            st.markdown("---")
            st.markdown("##### 📐 Export to CAD")
            st.markdown(
                '<p class="hint">Generate a 2-D DXF profile for each short-list '
                'rotor. Drop the file straight into SolidWorks / Fusion 360 / FreeCAD '
                'as a sketch, revolve it to get the 3-D solid, then mesh in Ansys — '
                'zero manual geometry entry.</p>',
                unsafe_allow_html=True)

            _dxf_sel_labels = {
                i: (f"{_bt.ROTOR_MATERIALS[c.material].name} "
                    f"⌀{_cL(c.diameter_mm):.1f} × {_cL(c.thickness_mm):.2f} {_uL} "
                    f"vent {c.vented_fraction:.0%}")
                for i, c in enumerate(_knee)
            }
            _dxf_pick = st.selectbox(
                "Rotor to export",
                options=list(_dxf_sel_labels.keys()),
                format_func=lambda i: _dxf_sel_labels[i],
                key="bt_dxf_pick",
                help="Pick one of the short-listed geometries; the DXF will contain "
                     "the half-section profile ready for revolution.")

            def _make_rotor_dxf(cand) -> bytes:
                """Build a minimal DXF R12 with the rotor half-section profile."""
                _dxf_is_us = units_mod.is_us()
                _r_mm   = cand.diameter_mm / 2.0
                _h_mm   = cand.thickness_mm
                _hub_mm = _r_mm * 0.25
                _vnt_mm = _r_mm * cand.vented_fraction

                def _cv(mm_val):
                    return units_mod.from_metric(mm_val, "mm")

                r      = _cv(_r_mm)
                h      = _cv(_h_mm)
                hub_r  = _cv(_hub_mm)
                vent_r = _cv(_vnt_mm)
                _gap   = _cv(5.0)
                _th    = _cv(4.0)
                _ts    = _cv(5.5)
                _insunits = "1" if _dxf_is_us else "4"
                _unit_lbl = "in" if _dxf_is_us else "mm"
                mat_name  = _bt.ROTOR_MATERIALS[cand.material].name

                lines = []
                def L(*parts):
                    lines.append("".join(str(p) for p in parts))

                L("  0\nSECTION")
                L("  2\nHEADER")
                L("  9\n$ACADVER")
                L("  1\nAC1009")
                L("  9\n$INSUNITS")
                L(" 70\n", _insunits)
                L("  0\nENDSEC")
                L("  0\nSECTION")
                L("  2\nTABLES")
                L("  0\nTABLE")
                L("  2\nLAYER")
                L(" 70\n3")
                for lyr, col in (("PROFILE", 7), ("CENTRELINE", 1), ("ANNOTATION", 3)):
                    L("  0\nLAYER")
                    L("  2\n", lyr)
                    L(" 70\n0")
                    L(" 62\n", col)
                    L("  6\nCONTINUOUS")
                L("  0\nENDTAB")
                L("  0\nENDSEC")
                L("  0\nSECTION")
                L("  2\nENTITIES")
                profile_pts = [(hub_r, 0.0), (r, 0.0), (r, h), (hub_r, h)]
                L("  0\nPOLYLINE")
                L("  8\nPROFILE")
                L(" 66\n1")
                L(" 70\n1")
                L(" 10\n0.0")
                L(" 20\n0.0")
                L(" 30\n0.0")
                for px, py in profile_pts:
                    L("  0\nVERTEX")
                    L("  8\nPROFILE")
                    L(" 10\n", f"{px:.5f}")
                    L(" 20\n", f"{py:.5f}")
                    L(" 30\n0.0")
                L("  0\nSEQEND")
                L("  8\nPROFILE")
                L("  0\nLINE")
                L("  8\nCENTRELINE")
                L(" 10\n0.0")
                L(" 20\n", f"{-_gap:.5f}")
                L(" 30\n0.0")
                L(" 11\n", f"{r * 1.1:.5f}")
                L(" 21\n", f"{-_gap:.5f}")
                L(" 31\n0.0")
                if cand.vented_fraction > 0:
                    L("  0\nLINE")
                    L("  8\nANNOTATION")
                    L(" 10\n", f"{vent_r:.5f}")
                    L(" 20\n0.0")
                    L(" 30\n0.0")
                    L(" 11\n", f"{vent_r:.5f}")
                    L(" 21\n", f"{h:.5f}")
                    L(" 31\n0.0")
                if _dxf_is_us:
                    _od_str  = f"OD {r*2:.4f} in  thick {h:.4f} in  vent {cand.vented_fraction:.0%}"
                    _hub_str = f"hub bore ~{hub_r*2:.4f} in (25% OD, adjust to PCD)"
                    _ax_str  = f"Units: in  |  Revolve about centre-line (Y={-_gap:.4f})"
                else:
                    _od_str  = f"OD {r*2:.1f} mm  thick {h:.2f} mm  vent {cand.vented_fraction:.0%}"
                    _hub_str = f"hub bore ~{hub_r*2:.1f} mm (25% OD, adjust to PCD)"
                    _ax_str  = f"Units: mm  |  Revolve about centre-line (Y={-_gap:.1f})"
                _rotor_ann = [f"KinematiK Rotor - {mat_name}", _od_str, _hub_str, _ax_str]
                _rtag = _kk_frame_tag()
                if _rtag:
                    _rotor_ann.append(_rtag)
                for ti, txt in enumerate(_rotor_ann):
                    L("  0\nTEXT")
                    L("  8\nANNOTATION")
                    L(" 10\n0.0")
                    L(" 20\n", f"{h + _gap + ti * _ts:.5f}")
                    L(" 30\n0.0")
                    L(" 40\n", f"{_th:.5f}")
                    L("  1\n", txt)
                L("  0\nENDSEC")
                L("  0\nEOF")
                return "\n".join(lines).encode("ascii", errors="replace")

            _dxf_cand = _knee[_dxf_pick]
            _dxf_is_us = units_mod.is_us()
            if _dxf_is_us:
                _fn_d = units_mod.from_metric(_dxf_cand.diameter_mm, "mm")
                _fn_t = units_mod.from_metric(_dxf_cand.thickness_mm, "mm")
                _fn_unit = "in"
            else:
                _fn_d = _dxf_cand.diameter_mm
                _fn_t = _dxf_cand.thickness_mm
                _fn_unit = "mm"
            _dxf_fname = (
                f"rotor_{_bt.ROTOR_MATERIALS[_dxf_cand.material].name}"
                f"_D{_fn_d:.{'3f' if _dxf_is_us else '0f'}}"
                f"_T{_fn_t:.{'4f' if _dxf_is_us else '1f'}}"
                f"_{_fn_unit}"
                f"_V{int(_dxf_cand.vented_fraction*100)}pct.dxf"
            )
            _dxf_bytes = _make_rotor_dxf(_dxf_cand)
            _dxf_col_a, _dxf_col_b = st.columns([2, 3])
            _dxf_col_a.download_button(
                "⬇ Download DXF",
                data=_dxf_bytes,
                file_name=_dxf_fname,
                mime="application/dxf",
                key="bt_dxf_download",
                help=(
                    "DXF R12 in inches ($INSUNITS=1) — open in SolidWorks, "
                    "Fusion 360, FreeCAD, or AutoCAD. Revolve the profile "
                    "around the centre-line to get the 3-D solid."
                    if _dxf_is_us else
                    "DXF R12 in millimetres ($INSUNITS=4) — open in SolidWorks, "
                    "Fusion 360, FreeCAD, or AutoCAD. Revolve the profile "
                    "around the centre-line to get the 3-D solid."
                ))
            # Immediately free up the memory holding those DXF text blocks. The
            # del frees it now; the collection is throttled to avoid a per-rerun
            # stall (st.tabs executes this code on every interaction).
            del _dxf_bytes
            _mem.maybe_collect()
            if _dxf_is_us:
                _od_in  = units_mod.from_metric(_dxf_cand.diameter_mm, "mm")
                _th_in  = units_mod.from_metric(_dxf_cand.thickness_mm, "mm")
                _hub_in = units_mod.from_metric(_dxf_cand.diameter_mm * 0.25, "mm")
                _mass_lb = units_mod.from_metric(_dxf_cand.rotor_mass_kg, "kg")
                _Tpk_f  = units_mod.from_metric(_dxf_cand.T_rotor_peak_c, "°C")
                _mg_f   = units_mod.from_metric_delta(_dxf_cand.margin_c, "°C")
                _cfg_lines = [
                    "# KinematiK rotor configuration script (imperial)",
                    "# Paste into your CAD macro / Python-OCC / FreeCAD script.",
                    f"material      = '{_bt.ROTOR_MATERIALS[_dxf_cand.material].name}'",
                    f"outer_dia_in  = {_od_in:.5f}   # {_dxf_cand.diameter_mm:.2f} mm",
                    f"thickness_in  = {_th_in:.5f}   # {_dxf_cand.thickness_mm:.3f} mm",
                    f"vented_frac   = {_dxf_cand.vented_fraction:.3f}",
                    f"hub_dia_in    = {_hub_in:.5f}   # ~25% OD, set to actual PCD",
                    f"mass_est_lb   = {_mass_lb:.4f}   # {_dxf_cand.rotor_mass_kg:.4f} kg",
                    f"T_peak_f      = {_Tpk_f:.1f}   # {_dxf_cand.T_rotor_peak_c:.1f} °C",
                    f"margin_f      = {_mg_f:.1f}   # {_dxf_cand.margin_c:.1f} °C",
                ]
            else:
                _cfg_lines = [
                    "# KinematiK rotor configuration script (metric)",
                    "# Paste into your CAD macro / Python-OCC / FreeCAD script.",
                    f"material     = '{_bt.ROTOR_MATERIALS[_dxf_cand.material].name}'",
                    f"outer_dia_mm = {_dxf_cand.diameter_mm:.2f}",
                    f"thickness_mm = {_dxf_cand.thickness_mm:.3f}",
                    f"vented_frac  = {_dxf_cand.vented_fraction:.3f}",
                    f"hub_dia_mm   = {_dxf_cand.diameter_mm * 0.25:.2f}  # ~25% OD, set to actual PCD",
                    f"mass_est_kg  = {_dxf_cand.rotor_mass_kg:.4f}",
                    f"T_peak_c     = {_dxf_cand.T_rotor_peak_c:.1f}",
                    f"margin_c     = {_dxf_cand.margin_c:.1f}",
                ]
            _dxf_col_b.download_button(
                "⬇ Download config (.py)",
                data="\n".join(_cfg_lines).encode(),
                file_name=_dxf_fname.replace(".dxf", "_config.py"),
                mime="text/x-python",
                key="bt_dxf_cfg_download",
                help="Drop into your SolidWorks / FreeCAD Python macro or "
                     "store alongside the DXF as a record of the design intent.")

    if _single.synthesized:
        st.caption("⚠ Synthesized: equations are exact energy balances, but "
                   "material c_p/density, convection h and the heat-split are "
                   "representative (uncalibrated) values. Right shape, invented "
                   "magnitudes — triage with these, confirm absolute temperatures "
                   "in Ansys.")


def _render_mount_bolt_check(key_prefix, *, default_ext_n=2000.0,
                             default_base="Aluminium 6061",
                             ledger_subsys=None, context_label="this mount"):
    """A self-contained preloaded-bolt check for ANY mounting joint — the same
    VDI 2230 / Shigley solver the Brakes ▸ Bolt view uses, factored out so the
    pedal-box, accumulator and other mount tabs get the identical tool instead of
    each member re-deriving bolt torque in a spreadsheet and meshing a guess.

    `key_prefix` namespaces the widgets so several copies coexist. If
    `ledger_subsys` is given, a declare-button writes the clamp force + torque
    spec into that subsystem's interface, exactly like the brakes view.
    """
    st.markdown(
        f'<p class="hint" style="margin:0 0 6px;">Same wall the brakes team hit: '
        f'<b>{context_label}</b> is clamped by bolt torque, and the only stress the '
        'FEA shows is a ring at the holes because the preload was a guess. Spec the '
        'torque here first (preload, bolt stress vs proof, joint separation, head '
        'crush) — then let the sim <i>verify</i> it.</p>', unsafe_allow_html=True)

    c = st.columns(4)
    g = c[0].selectbox("Bolt grade", list(bolt_mod.BOLT_GRADES.keys()), index=1,
                       key=f"{key_prefix}_grade")
    d = c[1].selectbox("Thread", list(bolt_mod.METRIC_COARSE.keys()), index=1,
                       format_func=lambda x: f"M{x:.0f}", key=f"{key_prefix}_dia")
    K = c[2].selectbox("Nut factor K", [0.20, 0.15, 0.12],
                       format_func=lambda k: {0.20: "0.20 — dry",
                                              0.15: "0.15 — light oil",
                                              0.12: "0.12 — anti-seize"}[k],
                       key=f"{key_prefix}_K",
                       help="Lubrication state — the biggest preload scatter source.")
    T = unum(c[3], "Assembly torque (N·m)", 2.0, 40.0,
             float(st.session_state.get(f"{key_prefix}_torque", 8.0)), "N·m",
             step=0.5, key=f"{key_prefix}_torque")

    c2 = st.columns(4)
    base = c2[0].selectbox("Clamped base material",
                           ["Aluminium 6061", "Aluminium 7075", "Steel 4130",
                            "Steel mild"],
                           index=["Aluminium 6061", "Aluminium 7075", "Steel 4130",
                                  "Steel mild"].index(default_base)
                           if default_base in ["Aluminium 6061", "Aluminium 7075",
                                               "Steel 4130", "Steel mild"] else 0,
                           key=f"{key_prefix}_base",
                           help="Softer clamped face — sets the head-bearing crush "
                                "limit.")
    chas = c2[1].selectbox("Other face material",
                           ["Aluminium 6061", "Aluminium 7075", "Steel 4130",
                            "Steel mild"], key=f"{key_prefix}_chas")
    grip = unum(c2[2], "Grip / stack (mm)", 3.0, 30.0, 8.0, "mm", step=0.5,
                key=f"{key_prefix}_grip")
    headd = unum(c2[3], "Head/washer ⌀ (mm)", 8.0, 24.0, float(d) * 1.8, "mm",
                 step=0.5, key=f"{key_prefix}_headd",
                 help="A bigger washer spreads the crush — the hardened-washer fix.")

    c3 = st.columns([1, 1])
    extN = unum(c3[0], "External tensile load / bolt (N)", 0.0, 20000.0,
                float(default_ext_n), "N", step=50.0, key=f"{key_prefix}_extN",
                help="Pull-off load this ONE bolt's region reacts, before prying.")
    pry = c3[1].slider("Prying factor", 1.0, 3.0, 1.0, 0.1,
                       key=f"{key_prefix}_pry",
                       help="1.0 = even share. >1 = a moment levers extra tension "
                            "into the far-edge bolt (a peeling base). >1 flags the "
                            "result as an estimate.")

    try:
        fast = bolt_mod.Fastener(grade=g, nominal_d_mm=float(d), K_factor=float(K),
                                 head_dia_mm=float(headd),
                                 hole_dia_mm=float(d) * 1.1)
        stack = bolt_mod.ClampedStack(base_material=base, chassis_material=chas,
                                      grip_mm=float(grip))
        jr = bolt_mod.analyze_joint(fast, stack, assembly_torque_Nm=float(T),
                                    external_tensile_N=float(extN),
                                    prying_factor=float(pry))
    except Exception as _e:
        st.error(f"Couldn't analyse the joint: {_e}")
        return

    pf = jr.sigma_bolt / max(jr.sigma_proof, 1e-6)
    m = st.columns(4)
    umetric(m[0], "Preload from torque", jr.F_preload, "N",
            help="Set the FEA bolt-preload to this clamp force.")
    m[1].metric("Bolt stress vs proof", f"{pf*100:.0f}%",
                delta=f"{(pf-0.75)*100:+.0f}% vs 75% cap", delta_color="inverse")
    m[2].metric("Separation margin", f"{jr.separation_safety:.2f}×",
                delta=("closed" if not jr.separated else "GAPPED"),
                delta_color=("normal" if not jr.separated else "inverse"))
    if jr.sigma_bearing is not None:
        m[3].metric("Head bearing vs crush",
                    f"{jr.sigma_bearing:.0f}/{jr.bearing_allow:.0f} MPa",
                    delta=("OK" if not jr.bearing_yield else "CRUSHES"),
                    delta_color=("normal" if not jr.bearing_yield else "inverse"))

    sound = (not jr.separated and pf <= 0.75 and not (jr.bearing_yield or False))
    if jr.separated:
        st.error(f"✗ Joint separates: {uval(extN,'N')} pull-off exceeds the "
                 f"{uval(jr.F_sep,'N')} gap-opening load. Raise torque, go up a "
                 "bolt size, or add bolts.")
    elif pf > 0.75:
        st.error(f"✗ Over-torqued: the bolt sits at {pf*100:.0f}% of proof before "
                 "the load is fully on — it yields at install. This is the red "
                 "ring the FEA shows; fix it here.")
    elif jr.bearing_yield:
        st.error(f"✗ Head crushes the base: {jr.sigma_bearing:.0f} MPa > "
                 f"{jr.bearing_allow:.0f} MPa. Fit a hardened steel washer or a "
                 "harder base.")
    else:
        st.success(f"✓ Sound spec: preload {uval(jr.F_preload,'N')}, "
                   f"{pf*100:.0f}% of proof, {jr.separation_safety:.1f}× "
                   "separation margin, no crush. Set the FEA preload to the clamp "
                   "force and the sim should confirm it.")
    if jr.is_estimate:
        st.info(f"⚠ Prying factor {jr.prying_factor:.1f} → ESTIMATE. The bolt "
                "mechanics are exact; only the load amplification is assumed "
                "(comes from the bracket stiffness / a hand-calc or FEA).")
    if jr.notes:
        st.caption(jr.notes)

    if sound and ledger_subsys:
        if st.button(f"📌 Declare this torque spec into the INTEGRATION ledger",
                     key=f"{key_prefix}_declare",
                     help="Records the clamp force as the mount load and the torque "
                          "+ bolt spec in the rationale, so the structures member "
                          "sees the real number."):
            try:
                _led = interfaces_mod.IntegrationLedger.from_dict(
                    st.session_state.ledger)
                _it = (_led.get(ledger_subsys)
                       or interfaces_mod.SubsystemInterface(name=ledger_subsys))
                _it.mount_load_n = round(jr.F_preload, 0)
                _it.mounts_on = "chassis"
                _it.is_estimate = bool(jr.is_estimate)
                _it.rationale = (
                    f"{context_label} bolt spec: M{d:.0f} {g}, K={K:.2f}, "
                    f"torque {uval(T,'N·m')} → preload {uval(jr.F_preload,'N')}/bolt "
                    f"({pf*100:.0f}% of proof), separation {jr.separation_safety:.1f}×. "
                    "Set FEA bolt-preload to the clamp force.")
                _it.updated_by = ledger_subsys
                _led.set(_it)
                publish_ledger(_led.as_dict())
                st.success(f"Declared {uval(jr.F_preload,'N')}/bolt clamp force for "
                           f"{ledger_subsys}.")
                st.rerun()
            except Exception as _e:
                st.warning(f"Couldn't declare: {_e}")


