# --------------------------------------------------------------------------- #
#  Aero mount-point overlay for the full-car view. Companion to the AERO tab's
#  "Mounting & bonding designer": lights up WHERE each aero element attaches to
#  the chassis, anchored to the ACTUAL drawn geometry (the figure's _part_boxes),
#  so it stays put when the user resizes the wings or the wheelbase changes.
#  Markers are tagged customdata="aerodynamics" so clicking one zooms to the
#  aero package like clicking any other body. Load-path lines run from each
#  mount to the primary-structure target (front bulkhead, main hoop / rear
#  bulkhead, lower rails) — a visual restatement of the tab's rule of thumb:
#  aero mounts to the CHASSIS, never the bodywork.
def _add_aero_mount_overlay(fig, *, selected_el=None, n_selected=None):
    _pbx = getattr(fig, "_part_boxes", None) or {}
    _mono = _pbx.get("Space frame") or _pbx.get("Spaceframe") or _pbx.get("Monocoque")
    if not _mono:
        # The dummy chassis body wasn't drawn this render (Bodywork layer off,
        # typical once real chassis CAD replaces it). Anchor to the user's own
        # chassis part instead — its drawn box is in _part_boxes under the
        # part's name (provisional stand-ins draw with an “(awaiting CAD)”
        # suffix, so try both spellings).
        for _cp in st.session_state.get("car3d_custom_parts", []):
            if not (_cp.get("define_car") or _cp.get("lib_slot") == "Chassis"
                    or _cp.get("subsys") == "chassis"):
                continue
            _nm = str(_cp.get("name") or "")
            _mono = _pbx.get(_nm) or _pbx.get(_nm + " (awaiting CAD)")
            if _mono:
                break
    if not _mono:
        return 0
    _mc = np.array(_mono["centre"], float)
    _ms = np.array(_mono["size"], float)
    _x_front_bh = _mc[0] + _ms[0] / 2.0      # front bulkhead face
    _x_rear_bh = _mc[0] - _ms[0] / 2.0       # rear bulkhead face
    _z_rail = _mc[2] - _ms[2] / 2.0          # lower-rail height
    _hoop = _pbx.get("Roll hoop")

    _DEF_N = {"Front wing": 4, "Rear wing": 4,
              "Undertray / floor + diffuser": 8,
              "Sidepods / bodywork panels": 6}

    def _npts(el):
        if selected_el == el and n_selected:
            return max(2, int(n_selected))
        return _DEF_N[el]

    _sets = []   # (element, pts Nx3, path target per point or None, note)
    _fw = _pbx.get("Front wing")
    if _fw:
        c, s = np.array(_fw["centre"], float), np.array(_fw["size"], float)
        n = _npts("Front wing")
        ys = np.linspace(-0.35, 0.35, n) * s[1]
        pts = np.column_stack([np.full(n, c[0] - s[0] / 2.0), ys,
                               np.full(n, c[2] + s[2] * 0.25)])
        tgt = np.column_stack([np.full(n, _x_front_bh), ys * 0.5,
                               np.full(n, _mc[2])])
        _sets.append(("Front wing", pts, tgt,
                      "bracket / swan-neck to FRONT BULKHEAD"))
    _rw = _pbx.get("Rear wing")
    if _rw:
        c, s = np.array(_rw["centre"], float), np.array(_rw["size"], float)
        n = _npts("Rear wing")
        ys = np.linspace(-0.30, 0.30, n) * s[1]
        pts = np.column_stack([np.full(n, c[0]), ys,
                               np.full(n, c[2] - s[2] / 2.0)])
        # target: main hoop top if drawn, else rear bulkhead top
        if _hoop:
            hc = np.array(_hoop["centre"], float)
            hs = np.array(_hoop["size"], float)
            tz, tx = hc[2] + hs[2] / 2.0, hc[0] - hs[0] * 0.3
        else:
            tz, tx = _mc[2] + _ms[2] / 2.0, _x_rear_bh
        tgt = np.column_stack([np.full(n, tx), ys * 0.6, np.full(n, tz)])
        _sets.append(("Rear wing", pts, tgt,
                      "upright / swan-neck to MAIN HOOP + rear bulkhead"))
    # Undertray rails: the floor bolts to the chassis lower rails themselves —
    # mounts alternate left/right along the monocoque bottom edge, no path line.
    n = _npts("Undertray / floor + diffuser")
    xs = np.linspace(_mc[0] - 0.45 * _ms[0], _mc[0] + 0.45 * _ms[0], n)
    ys = np.where(np.arange(n) % 2 == 0, 1.0, -1.0) * (_ms[1] / 2.0) * 0.95
    pts = np.column_stack([xs, ys, np.full(n, _z_rail)])
    _sets.append(("Undertray / floor + diffuser", pts, None,
                  "rubber-isolated tab on LOWER RAIL"))
    _sp = _pbx.get("Sidepod (cooling)")
    if _sp:
        c, s = np.array(_sp["centre"], float), np.array(_sp["size"], float)
        n = _npts("Sidepods / bodywork panels")
        half = max(2, n // 2)
        xs = np.tile(np.linspace(c[0] - 0.35 * s[0], c[0] + 0.35 * s[0], half), 2)[:n]
        ys = np.concatenate([np.full(half, s[1] / 2.0 * 0.9),
                             np.full(half, -s[1] / 2.0 * 0.9)])[:n]
        pts = np.column_stack([xs, ys, np.full(n, c[2] + s[2] / 2.0)])
        tgt = np.column_stack([xs, np.sign(ys) * (_ms[1] / 2.0),
                               np.full(n, _mc[2])])
        _sets.append(("Sidepods / bodywork panels", pts, tgt,
                      "DZUS / quarter-turn to chassis tab"))

    _total = 0
    for _el, _p, _t, _note in _sets:
        _is_sel = (selected_el == _el)
        _n = len(_p)
        fig.add_trace(go.Scatter3d(
            x=_p[:, 0], y=_p[:, 1], z=_p[:, 2], mode="markers",
            name=f"⚓ {_el} mounts",
            marker=dict(size=(9 if _is_sel else 6),
                        color="#ffd93b",
                        opacity=(1.0 if _is_sel else 0.55),
                        symbol="diamond",
                        line=dict(color="#ffffff",
                                  width=(2 if _is_sel else 0))),
            customdata=[["aerodynamics", _el, ""]] * _n,
            hovertemplate=(f"<b>{_el}</b> — mount %{{pointNumber}}"
                           f" of {_n}<br>{_note}<extra></extra>"),
            showlegend=True))
        if _t is not None:
            lx, ly, lz = [], [], []
            for _i in range(_n):
                lx += [_p[_i, 0], _t[_i, 0], None]
                ly += [_p[_i, 1], _t[_i, 1], None]
                lz += [_p[_i, 2], _t[_i, 2], None]
            fig.add_trace(go.Scatter3d(
                x=lx, y=ly, z=lz, mode="lines",
                line=dict(color="#ffd93b", width=(5 if _is_sel else 2),
                          dash="dot"),
                opacity=(0.9 if _is_sel else 0.35),
                hoverinfo="skip", showlegend=False))
        _total += _n
    return _total


# --------------------------- FULL CAR 3D ----------------------------------- #
# A LIVE Formula car assembled from every subsystem's current declaration. The
# figure is rebuilt from session state on every rerun, so the instant any tab
# edits geometry, vehicle params, or its interface in the ledger, the body that
# subsystem owns changes here — wings scale with downforce, sidepods with cooling
# airflow, the engine block with power, the battery with its envelope/mass, brake
# discs with brake torque, and the CG marker with the declared mass roll-up.
with tab_car:
  if st.session_state.get("model3d_view", "Full car") == "Full car":
    st.markdown(
        '<p class="hint" style="margin:0 0 8px;">The whole car, live. '
        '<b>Drag</b> to rotate, scroll to zoom, <b>click a part</b> to zoom in. '
        'Tools and details are below the model.</p>',
        unsafe_allow_html=True)

    # ---- compact control strip (sits directly above the car) ------------- #
    _SUBSYS_CHOICES = ["(whole car)", "suspension", "aerodynamics", "powertrain",
                       "cooling", "electrics", "brakes", "chassis",
                       "data-acquisition"]
    hc1, hc2, hc3, hc4 = st.columns([2, 1, 1, 1])
    _hl_choice = hc1.selectbox(
        "Spotlight subsystem", _SUBSYS_CHOICES, index=0, key="car3d_highlight",
        help="Glow your subsystem and dim the rest, to see your part in the whole car.")
    _highlight = None if _hl_choice == "(whole car)" else _hl_choice
    _prev_hl = st.session_state.get("_car3d_hl_prev")
    if _hl_choice != _prev_hl:
        st.session_state._car3d_hl_prev = _hl_choice
        if _hl_choice == "(whole car)":
            st.session_state.pop("car3d_focus", None)
    _tire_w = hc2.number_input("Tire width mm", value=180.0, min_value=80.0,
                               max_value=320.0, step=10.0, key="car3d_tirew")
    _show_floor = hc3.checkbox("Ground", value=True, key="car3d_floor")
    if hc4.button("Reset zoom", key="car3d_resetzoom",
                  help="Pull the camera back out to the whole-car view."):
        st.session_state.pop("car3d_focus", None)
        st.session_state.pop("car3d_plot", None)

    with st.expander("Layers", expanded=False):
        lc = st.columns(4)
        _show_tires = lc[0].checkbox("Tires", True, key="car3d_tires")
        _show_brakes = lc[0].checkbox("Brakes", True, key="car3d_brakes")
        _show_aero = lc[1].checkbox("Aero (wings)", True, key="car3d_aero")
        _show_cool = lc[1].checkbox("Cooling (sidepods)", True, key="car3d_cool")
        _show_pt = lc[2].checkbox("Powertrain", True, key="car3d_pt")
        _show_el = lc[2].checkbox("Electrics", True, key="car3d_el")
        _show_body = lc[3].checkbox("Bodywork (spaceframe + hoops)", True, key="car3d_body")
        # “⚓ Show these mount points on the 3D car” (Aerodynamics tab) raises
        # car3d_aeromounts_req. A keyed checkbox IGNORES its value= argument
        # once the widget owns its session state, so the request must be written
        # INTO the widget's own key BEFORE the checkbox is instantiated — the
        # only way a button on another tab can switch it on after first render.
        st.session_state.setdefault(
            "car3d_aeromounts",
            bool(st.session_state.get("car3d_aeromounts_on", False)))
        if st.session_state.pop("car3d_aeromounts_req", False):
            st.session_state["car3d_aeromounts"] = True
        _show_mounts = lc[3].checkbox(
            "⚓ Aero mount points",
            key="car3d_aeromounts",
            help="Show where each aero element attaches to the chassis — the "
                 "mount points and their load paths into primary structure. "
                 "Companion to Aerodynamics → Mounting & bonding designer.")
        st.session_state["car3d_aeromounts_on"] = bool(_show_mounts)

    # The car renders HERE, directly under the controls. Streamlit fills a
    # container in the order it was CREATED, not called, so we reserve this slot
    # now and draw the figure into it after the part-editing tools below have
    # written their values to session_state. This is what puts the model first
    # and pushes every tool/panel below it — far less to scroll past.
    _car_slot = st.container()

    st.markdown('<p class="hint" style="margin:10px 0 2px;font-family:JetBrains Mono;'
                'font-size:.7rem;letter-spacing:.12em;color:#6f7d8c;">PART TOOLS</p>',
                unsafe_allow_html=True)

    # ===================================================================== #
    #  DROP YOUR PART ON THE CAR  —  the frictionless "does it fit" path.    #
    # ===================================================================== #
    # The recurring sub-team question ("here's a radiator 289×124, how does it
    # sit on the car / does it fit / which way up?") answered in three numbers.
    # Type the part's REAL size in mm and roughly where it goes, hit add, and it
    # appears on the car immediately — clickable, colour-matched to its team,
    # with a live clearance read. No scale factors, no CAD export, no waiting on
    # someone else's file. This is deliberately the first thing on the tab.
    if "car3d_custom_parts" not in st.session_state:
        st.session_state.car3d_custom_parts = []

    # Seed the entry-form fields once. After this, each widget owns its key, so we
    # never pass both value= and a session_state default (which makes Streamlit
    # warn and ignore the value). Presets write straight into these keys + rerun.
    _CP_DEFAULTS = dict(car3d_cp_name="My part",
                        car3d_cp_subsys="(custom / unassigned)",
                        car3d_cp_shape="box", car3d_cp_l=200.0, car3d_cp_w=150.0,
                        car3d_cp_h=100.0, car3d_cp_x=0.0, car3d_cp_y=0.0,
                        car3d_cp_z=250.0)
    for _k, _v in _CP_DEFAULTS.items():
        if _k not in st.session_state:
            st.session_state[_k] = _v

    # One-tap starting points drawn from real parts the teams are juggling, so a
    # lead who is skeptical of "yet another tool" gets a result on the first click
    # and can edit the numbers after, instead of facing an empty form.
    _PART_PRESETS = {
        "— pick a starting point —": None,
        "Radiator — Koolance HX-240YC (289×124×34)":
            dict(name="Radiator (HX-240YC)", subsys="cooling",
                 l_mm=289.0, w_mm=124.0, h_mm=34.0, x_mm=-150.0, y_mm=0.0,
                 z_mm=320.0, shape="box"),
        "Accumulator — 3 modules (320×330×280)":
            dict(name="Accumulator", subsys="electrics",
                 l_mm=320.0, w_mm=330.0, h_mm=280.0, x_mm=100.0, y_mm=0.0,
                 z_mm=190.0, shape="box"),
        "Traction motor (Ø150×200)":
            dict(name="Traction motor", subsys="powertrain",
                 l_mm=200.0, w_mm=150.0, h_mm=150.0, x_mm=-620.0, y_mm=0.0,
                 z_mm=200.0, shape="cylinder"),
        "Blank box (edit the numbers)":
            dict(name="My part", subsys="(custom / unassigned)",
                 l_mm=200.0, w_mm=150.0, h_mm=100.0, x_mm=0.0, y_mm=0.0,
                 z_mm=250.0, shape="box"),
    }
    _CP_SUBSYS = ["(custom / unassigned)", "cooling", "powertrain", "electrics",
                  "aerodynamics", "brakes", "chassis", "suspension"]
    # SIMPLIFIED: replace by SUBSYSTEM. The picker value is
    # (subsys_key, display, anchor_part_key, [draw-names to hide]). Replacing a
    # subsystem hides all its procedural bodies; the rest stay as dummies.
    _SUB_CATALOG = fullcar_mod.subsystem_catalog()  # (key, display, [drawnames])
    _SUB_ANCHOR = fullcar_mod.SUBSYS_ANCHOR_PART
    _PART_PICK = {"(not replacing a subsystem)": None}
    for _sk, _sdisp, _sdn in _SUB_CATALOG:
        _PART_PICK[_sdisp] = (_sk, _sdisp, _SUB_ANCHOR.get(_sk), list(_sdn))
    _PART_PICK_LABELS = list(_PART_PICK.keys())

    with st.expander("➕  Drop your part on the car — type its size in mm, see it fit",
                     expanded=False):
        st.markdown(
            '<p class="hint">Got a part with real dimensions \u2014 a radiator off a '
            'spec sheet, an accumulator box, a motor? Put its <b>actual size in '
            'millimetres</b> here and roughly where it sits, and it lands on the car '
            'right away so you can see how it fits and which way it should face. '
            'These are real mm, not scale factors. It draws as a clickable body in '
            'your team\u2019s colour; this is a packaging sketch, not a collision '
            'check \u2014 the build-day go/no-go still lives in the INTEGRATION '
            'tab.</p>', unsafe_allow_html=True)

        # ---- UPLOAD A REAL CAD / SKETCH ------------------------------------ #
        # The team can drop their actual SolidWorks part (or a quick sketch
        # exported as STEP/STL) and the REAL geometry renders on the car — not a
        # box approximation. We load + normalise the mesh once, cache it in
        # session_state keyed by the part name, then add it as a mesh-backed
        # custom part that flows through the same renderer as everything else.
        st.markdown('<p class="hint" style="margin:2px 0 4px;"><b>Have the actual '
                    'CAD?</b> Drop a SolidWorks part or a quick sketch '
                    '(STEP / STL / OBJ / GLB) and the real shape renders on the car '
                    '\u2014 not just a box.</p>', unsafe_allow_html=True)
        _cad_up = st.file_uploader(
            "Upload CAD / sketch", type=["step", "stp", "stl", "obj", "glb"],
            key="car3d_cad_up",
            help="STEP is most reliable from SolidWorks (File ▸ Save As ▸ STEP). "
                 "STL/OBJ/GLB also work for a quick sketch.")
        if _cad_up is not None:
            # Load + normalise only once per uploaded file (keyed by name+size).
            _sig = f"{_cad_up.name}:{_cad_up.size}"
            if st.session_state.get("car3d_cad_sig") != _sig:
                try:
                    import tempfile as _tf, os as _os
                    _sfx = "." + _cad_up.name.split(".")[-1]
                    with _tf.NamedTemporaryFile(delete=False, suffix=_sfx) as _f:
                        _f.write(_cad_up.getbuffer())
                        _cad_path = _f.name
                    with st.spinner("Reading geometry…"):
                        _payload = chassis_mod.load_part_mesh(_cad_path, max_faces=4000)
                    _os.unlink(_cad_path)
                    st.session_state.car3d_cad_payload = _payload
                    st.session_state.car3d_cad_sig = _sig
                    st.session_state.car3d_cad_name_default = \
                        _cad_up.name.rsplit(".", 1)[0]
                except Exception as _ce:
                    st.session_state.car3d_cad_payload = None
                    st.error(
                        "Couldn't read that CAD (" + str(_ce) + "). STEP is the most "
                        "reliable export from SolidWorks; for a STEP make sure the "
                        "cascadio package is installed in the deployment.")

            _payload = st.session_state.get("car3d_cad_payload")
            if _payload:
                _sz = _payload["size_mm"]
                _unit_note = ("" if _payload["unit_scale"] == 1.0 else
                              " · auto-scaled ×%g (looked like %s)" % (
                                  _payload["unit_scale"],
                                  "metres" if _payload["unit_scale"] == 1000 else "inches"))
                st.markdown(
                    f'<p class="hint">Loaded <b>{_payload["triangles"]} triangles</b>, '
                    f'bounding box <b>{_sz[0]:.0f}\u00d7{_sz[1]:.0f}\u00d7{_sz[2]:.0f} '
                    f'mm</b>{_unit_note}. Pick the part it represents, then snap or '
                    'type where it sits.</p>', unsafe_allow_html=True)

                # Seed position fields once so the number_inputs own their keys.
                for _k, _v in dict(car3d_cad_x=0.0, car3d_cad_y=0.0,
                                   car3d_cad_z=250.0).items():
                    if _k not in st.session_state:
                        st.session_state[_k] = _v

                _cc = st.columns([3, 3])
                _cad_name = _cc[0].text_input(
                    "Part name", key="car3d_cad_name",
                    value=st.session_state.get("car3d_cad_name_default", "CAD part"))
                _cad_pick_lbl = _cc[1].selectbox(
                    "Which part is this? (sets colour + snap target)",
                    _PART_PICK_LABELS, key="car3d_cad_pick",
                    help="Pick the body this CAD represents. It sets the colour and "
                         "gives you a one-tap Snap to drop it exactly where that "
                         "part's placeholder sits. You choose below whether to hide "
                         "the placeholder.")
                _cad_pick = _PART_PICK.get(_cad_pick_lbl)
                # tuple = (subsys_key, display, anchor_part_key, [drawnames])
                _cad_sub = _cad_pick[0] if _cad_pick else "(custom / unassigned)"
                _is_part = _cad_pick is not None

                # Resolve this car's anchor for the chosen subsystem's representative
                # body, so position fields and the Snap button use real coordinates.
                try:
                    _vp_cad = VehicleParams(**{k: v for k, v in st.session_state.vp.items()
                                               if k in set(VehicleParams.__dataclass_fields__.keys())})
                except Exception:
                    _vp_cad = VehicleParams()
                try:
                    _led_cad = interfaces_mod.IntegrationLedger.from_dict(st.session_state.ledger)
                except Exception:
                    _led_cad = None
                _anchor = (fullcar_mod.part_anchor(_vp_cad, _cad_pick[2], ledger=_led_cad)
                           if _is_part else None)

                # The generic anchor above is a rough per-subsystem GUESS. The
                # real dummy a member sees is drawn at its true position (e.g. the
                # monocoque spans ~2 m and sits nowhere near the guess), which is
                # exactly why a snapped CAD part landed "aligned" yet visibly off.
                # Prefer the REAL union box of the actual drawn bodies this
                # subsystem owns — measured from the last render into
                # car3d_part_boxes — so Snap and the alignment read-out track what
                # is actually on screen. Fall back to the guess only when the
                # measured boxes aren't available yet (first render).
                if _is_part:
                    try:
                        _dns_a = _cad_pick[3] or []
                        _pbx_a = st.session_state.get("car3d_part_boxes", {}) or {}
                        # If the real boxes haven't been measured yet (first
                        # render, before the Model tab has drawn the car), build
                        # one figure now and measure the bodies we need, caching
                        # per-body so this stays cheap on reruns. This makes the
                        # FIRST snap land correctly rather than on the guess.
                        _need = [d for d in _dns_a if d not in _pbx_a]
                        if _need:
                            _fpc = st.session_state.get("_dummy_footprints", {})
                            _missing = [d for d in _need if d not in _fpc]
                            if _missing:
                                _fig_a = fullcar_mod.build_full_car_figure(
                                    vp=_vp_cad, ledger=_led_cad)
                                for _d in _missing:
                                    _fpc[_d] = fullcar_mod.dummy_body_footprint(
                                        _fig_a, _d)
                                st.session_state["_dummy_footprints"] = _fpc
                            # merge measured footprints into a boxes-like view
                            for _d in _need:
                                _fp = _fpc.get(_d)
                                if _fp:
                                    _pbx_a = dict(_pbx_a)
                                    _pbx_a[_d] = dict(
                                        centre=[_fp["x_mm"], _fp["y_mm"],
                                                _fp["z_mm"]],
                                        size=[_fp["l_mm"], _fp["w_mm"],
                                              _fp["h_mm"]])
                        _los_a, _his_a = [], []
                        for _dn in _dns_a:
                            _b = _pbx_a.get(_dn)
                            if _b:
                                _bc = _b["centre"]; _bs = _b["size"]
                                _los_a.append([_bc[i] - _bs[i] / 2 for i in range(3)])
                                _his_a.append([_bc[i] + _bs[i] / 2 for i in range(3)])
                        if _los_a:
                            _lo_a = [min(p[i] for p in _los_a) for i in range(3)]
                            _hi_a = [max(p[i] for p in _his_a) for i in range(3)]
                            _anchor = {
                                "x_mm": (_lo_a[0] + _hi_a[0]) / 2.0,
                                "y_mm": (_lo_a[1] + _hi_a[1]) / 2.0,
                                "z_mm": (_lo_a[2] + _hi_a[2]) / 2.0,
                                "l_mm": _hi_a[0] - _lo_a[0],
                                "w_mm": _hi_a[1] - _lo_a[1],
                                "h_mm": _hi_a[2] - _lo_a[2],
                                "shape": (_anchor or {}).get("shape", "box"),
                            }
                    except Exception:
                        pass  # keep the guessed anchor on any trouble

                # Initialise the position/scale widget keys ONCE, and flush any
                # pending writes from the Snap / Fit-scale / pick-changed actions
                # BEFORE the widgets are created (Streamlit forbids assigning to a
                # widget's key after the widget exists in the same run).
                for _k, _dv in (("car3d_cad_x", 0.0), ("car3d_cad_y", 0.0),
                                ("car3d_cad_z", 250.0), ("car3d_cad_scale", 1.0),
                                ("car3d_cad_yaw", 0.0)):
                    if _k not in st.session_state:
                        st.session_state[_k] = _dv
                _pend = st.session_state.pop("_car3d_cad_pending", None)
                if _pend:
                    for _k, _v in _pend.items():
                        st.session_state[_k] = _v

                # When the picked part changes, queue its anchor centre so the CAD
                # starts in the right neighbourhood (flushed on the next run).
                if st.session_state.get("_car3d_cad_pick_prev") != _cad_pick_lbl:
                    st.session_state._car3d_cad_pick_prev = _cad_pick_lbl
                    if _anchor:
                        st.session_state._car3d_cad_pending = dict(
                            car3d_cad_x=units_mod.from_metric(float(_anchor["x_mm"]), "mm"),
                            car3d_cad_y=units_mod.from_metric(float(_anchor["y_mm"]), "mm"),
                            car3d_cad_z=units_mod.from_metric(float(_anchor["z_mm"]), "mm"))
                        st.rerun()

                _o1 = st.columns([2, 2, 2])
                _cad_axis = _o1[0].selectbox(
                    "Orientation", ["auto", "z_up", "y_up", "x_up"],
                    key="car3d_cad_axis",
                    format_func=lambda v: {
                        "auto": "Auto-align to the slot",
                        "z_up": "Z is up", "y_up": "Y is up", "x_up": "X is up"}[v],
                    help="Auto rotates the part by a clean 90° to line its longest "
                         "side up with the slot — never distorts. Override with a "
                         "fixed up-axis if needed.")
                _cad_scale = _o1[1].number_input(
                    "Scale ×", min_value=0.05, max_value=20.0, step=0.05,
                    key="car3d_cad_scale",
                    help="Multiplier on the real CAD size. Leave at 1.0 to keep its "
                         "true dimensions; use “Fit scale” to match the slot.")
                _cad_yaw = _o1[2].number_input(
                    "Yaw °", -180.0, 180.0, step=15.0, key="car3d_cad_yaw",
                    help="Spin about the car's vertical axis to line it up.")

                # One-click: compute the uniform scale that makes the CAD match the
                # chosen part's slot, WITHOUT letting the renderer auto-balloon. The
                # user gets a real number they can then see and fine-tune.
                if _is_part and _anchor and st.button(
                        "↧ Fit scale to the “%s” area" % _cad_pick[1],
                        key="car3d_cad_fitscale",
                        help="Sets the scale × so your CAD fills the space that "
                             "subsystem occupies, at true proportions. Nudge after."):
                    try:
                        # Union the actual placeholder boxes of ALL bodies this
                        # subsystem owns (e.g. chassis = monocoque+hoop+driver), so
                        # the CAD fills the real area you see, not one sub-part.
                        _pbx = st.session_state.get("car3d_part_boxes", {})
                        _dns = _cad_pick[3]
                        _los, _his = [], []
                        for _d in _dns:
                            _b = _pbx.get(_d)
                            if _b:
                                _c = _b["centre"]; _s2 = _b["size"]
                                _los.append([_c[i] - _s2[i] / 2 for i in range(3)])
                                _his.append([_c[i] + _s2[i] / 2 for i in range(3)])
                        if _los:
                            _lo = [min(p[i] for p in _los) for i in range(3)]
                            _hi = [max(p[i] for p in _his) for i in range(3)]
                            _slotd = sorted([_hi[i] - _lo[i] for i in range(3)])
                            _ctr = [(_lo[i] + _hi[i]) / 2 for i in range(3)]
                        else:
                            _slotd = sorted([float(_anchor["l_mm"]),
                                             float(_anchor["w_mm"]), float(_anchor["h_mm"])])
                            _ctr = [_anchor["x_mm"], _anchor["y_mm"], _anchor["z_mm"]]
                        _rawd = sorted([float(x) for x in _sz])
                        _factor = _slotd[1] / _rawd[1] if _rawd[1] > 1e-6 else 1.0
                        st.session_state._car3d_cad_pending = dict(
                            car3d_cad_scale=round(_factor, 3),
                            car3d_cad_x=units_mod.from_metric(float(_ctr[0]), "mm"),
                            car3d_cad_y=units_mod.from_metric(float(_ctr[1]), "mm"),
                            car3d_cad_z=units_mod.from_metric(float(_ctr[2]), "mm"))
                        st.rerun()
                    except Exception:
                        pass

                # Live placed size at the current scale + orientation.
                _sx, _sy, _sz2 = _sz
                _axis_now = st.session_state.get("car3d_cad_axis", "auto")
                if _axis_now == "y_up":
                    _Lr, _Wr, _Hr = _sx, _sz2, _sy
                elif _axis_now == "x_up":
                    _Lr, _Wr, _Hr = _sz2, _sy, _sx
                else:
                    _Lr, _Wr, _Hr = _sx, _sy, _sz2
                _Lr, _Wr, _Hr = _Lr * _cad_scale, _Wr * _cad_scale, _Hr * _cad_scale

                st.markdown('<p class="hint" style="margin:6px 0 2px;"><b>Position of '
                            'its centre (mm)</b> — x: −rear / +front, y: +right, '
                            'z: up. Type coordinates, or Snap to the part below.</p>',
                            unsafe_allow_html=True)
                _cp = st.columns([2, 2, 2, 2])
                _cad_x = unum(_cp[0], "Centre x (mm)", -2000, 2000, 0, "mm",
                              step=10.0, key="car3d_cad_x")
                _cad_y = unum(_cp[1], "Centre y (mm)", -1200, 1200, 0, "mm",
                              step=10.0, key="car3d_cad_y")
                _cad_z = unum(_cp[2], "Centre z (mm)", -200, 2000, 250, "mm",
                              step=10.0, key="car3d_cad_z")
                if _cp[3].button("⌖ Snap to part", key="car3d_cad_snap",
                                 disabled=not _is_part,
                                 help="Drop the centre exactly onto the chosen "
                                      "part's position, so it lines up with the car."):
                    if _anchor:
                        st.session_state._car3d_cad_pending = dict(
                            car3d_cad_x=units_mod.from_metric(float(_anchor["x_mm"]), "mm"),
                            car3d_cad_y=units_mod.from_metric(float(_anchor["y_mm"]), "mm"),
                            car3d_cad_z=units_mod.from_metric(float(_anchor["z_mm"]), "mm"))
                        st.rerun()

                # Alignment read-out: how far the current centre is from the target
                # part's anchor, so the user can see when it lines up.
                if _anchor:
                    _dx = _cad_x - _anchor["x_mm"]
                    _dy = _cad_y - _anchor["y_mm"]
                    _dz = _cad_z - _anchor["z_mm"]
                    _off = (_dx**2 + _dy**2 + _dz**2) ** 0.5
                    _al_col = "#5ad17a" if _off < 15 else ("#ffd166" if _off < 150 else "#ff6b5a")
                    _al_txt = ("aligned with its slot" if _off < 15 else
                               "offset %.0f mm from the %s slot (Δ %+.0f, %+.0f, %+.0f)"
                               % (_off, _cad_pick[1], _dx, _dy, _dz))
                    st.markdown(
                        f'<div style="border:1px solid var(--line);border-left:4px '
                        f'solid {_al_col};border-radius:8px;padding:6px 12px;margin:4px 0;">'
                        f'<span style="font-size:.9rem;">Placed size '
                        f'<b>{_Lr:.0f}×{_Wr:.0f}×{_Hr:.0f} mm</b> · '
                        f'<span style="color:{_al_col};">{_al_txt}</span></span></div>',
                        unsafe_allow_html=True)

                _rc = st.columns([3, 2])
                _cad_replace = _rc[0].checkbox(
                    (f"Replace the dummy “{_cad_pick[1]}” (hide its placeholder)"
                     if _is_part else "Pick a subsystem above to replace it"),
                    value=_is_part, key="car3d_cad_replace", disabled=not _is_part,
                    help="On: every dummy body of that subsystem is hidden so only "
                         "your CAD shows there — the rest of the car stays as dummy "
                         "suggestions. Off: your CAD sits alongside the dummy.")
                _cad_mass = _rc[1].number_input(
                    "Mass kg (moves CG)", min_value=0.0, max_value=300.0,
                    value=0.0, step=0.5, key="car3d_cad_mass",
                    help="If set, this part's weight is folded into the gold CG "
                         "marker so the car re-balances as parts firm up.")

                _cad_autofit = st.checkbox(
                    "Auto-size into the area (uniform, true shape) — otherwise keep "
                    "real CAD size", value=True, key="car3d_cad_autofit",
                    disabled=not _is_part,
                    help="On (default): uniformly scaled to fill that subsystem's "
                         "area — handy when the real size is unknown. Off: draws at "
                         "real exported size × the scale above. Never distorts.")

                if st.button("Add CAD part to car", key="car3d_cad_add",
                             type="primary"):
                    _ax = st.session_state.get("car3d_cad_axis", "auto")
                    _hide = bool(_cad_replace and _is_part)
                    _fit = bool(_cad_autofit and _is_part)
                    _skey = _cad_pick[0] if _is_part else None      # subsystem
                    _apart = _cad_pick[2] if _is_part else None      # anchor part
                    _dns = _cad_pick[3] if _is_part else []          # draw-names
                    st.session_state.car3d_custom_parts.append(dict(
                        name=(_cad_name.strip() or "CAD part"), subsys=_cad_sub,
                        shape="mesh", mesh=_payload, axis_map=_ax,
                        yaw_deg=float(_cad_yaw), mesh_scale=float(_cad_scale),
                        fit_to_envelope=_fit, fit_mode="fit",
                        replaces_part=_apart,
                        replaces_drawnames=(_dns if _hide else []),
                        replaces_subsys=(_skey if _hide else None),
                        snap_part=_apart, mass_kg=float(_cad_mass),
                        x_mm=float(_cad_x), y_mm=float(_cad_y), z_mm=float(_cad_z),
                        l_mm=float(_Lr), w_mm=float(_Wr), h_mm=float(_Hr)))
                    st.session_state.car3d_focus = (
                        _cad_sub if _cad_sub != "(custom / unassigned)" else None)
                    st.session_state.pop("car3d_cad_sig", None)
                    st.rerun()

        st.markdown('<p class="hint" style="margin:8px 0 2px;border-top:1px solid '
                    'var(--line);padding-top:8px;"><b>Or sketch it by hand</b> with '
                    'dimensions:</p>', unsafe_allow_html=True)

        _pp = st.selectbox("Quick start", list(_PART_PRESETS.keys()), index=0,
                           key="car3d_cp_preset")
        if st.session_state.get("_car3d_cp_preset_prev") != _pp:
            st.session_state._car3d_cp_preset_prev = _pp
            _seed = _PART_PRESETS.get(_pp)
            if _seed:
                st.session_state.car3d_cp_name = _seed["name"]
                st.session_state.car3d_cp_subsys = _seed["subsys"]
                st.session_state.car3d_cp_l = _seed["l_mm"]
                st.session_state.car3d_cp_w = _seed["w_mm"]
                st.session_state.car3d_cp_h = _seed["h_mm"]
                st.session_state.car3d_cp_x = _seed["x_mm"]
                st.session_state.car3d_cp_y = _seed["y_mm"]
                st.session_state.car3d_cp_z = _seed["z_mm"]
                st.session_state.car3d_cp_shape = _seed["shape"]
                st.rerun()

        _r1 = st.columns([3, 2, 1])
        _cp_name = _r1[0].text_input("Part name", key="car3d_cp_name")
        _cp_sub = _r1[1].selectbox(
            "Belongs to", _CP_SUBSYS, key="car3d_cp_subsys",
            help="Colours the part in this team\u2019s hue and lets the spotlight / "
                 "click-to-zoom treat it as that subsystem.")
        _cp_shape = _r1[2].selectbox("Shape", ["box", "cylinder"],
                                     key="car3d_cp_shape",
                                     help="Cylinder: length is L, diameter is W (e.g. a motor).")

        st.markdown('<p class="hint" style="margin:6px 0 2px;"><b>Size (mm)</b> '
                    '\u2014 L is fore\u2013aft, W is left\u2013right, H is up. For a '
                    'cylinder, L = length and W = diameter.</p>',
                    unsafe_allow_html=True)
        _sz = st.columns(3)
        _cp_l = unum(_sz[0], "Length L (mm)", 1, 3000, 100, "mm",
                     step=5.0, key="car3d_cp_l")
        _cp_w = unum(_sz[1], "Width W (mm)", 1, 2000, 100, "mm",
                     step=5.0, key="car3d_cp_w")
        _cp_h = unum(_sz[2], "Height H (mm)", 1, 2000, 100, "mm",
                     step=5.0, key="car3d_cp_h")

        st.markdown('<p class="hint" style="margin:6px 0 2px;"><b>Position of its '
                    'centre</b> \u2014 x: \u2212 toward rear axle / + toward '
                    'front, y: + to the right, z: up from the ground. Leave at 0,0,250 '
                    'and nudge from there.</p>', unsafe_allow_html=True)
        _ps = st.columns(3)
        _cp_x = unum(_ps[0], "Centre x (mm)", -1500, 1500, 0, "mm",
                     step=10.0, key="car3d_cp_x")
        _cp_y = unum(_ps[1], "Centre y (mm)", -900, 900, 0, "mm",
                     step=10.0, key="car3d_cp_y")
        _cp_z = unum(_ps[2], "Centre z (mm)", 0, 1500, 250, "mm",
                     step=10.0, key="car3d_cp_z")

        # Live fit read on the part being entered — answers "does it fit?" BEFORE
        # you even add it, against the car's wheelbase/track/hoop-height envelope.
        try:
            _vp_fit = VehicleParams(**{k: v for k, v in st.session_state.vp.items()
                                       if k in set(VehicleParams.__dataclass_fields__.keys())})
        except Exception:
            _vp_fit = VehicleParams()
        _draft = dict(name=_cp_name, subsys=_cp_sub, l_mm=_cp_l, w_mm=_cp_w,
                      h_mm=_cp_h, x_mm=_cp_x, y_mm=_cp_y, z_mm=_cp_z, shape=_cp_shape)
        _fit = fullcar_mod.custom_part_fit(_vp_fit, _draft)
        _fit_color = {"ok": "#5ad17a", "tight": "#ffd166", "over": "#ff6b5a"}[_fit["status"]]
        _fit_word = {"ok": "Fits the envelope", "tight": "Tight \u2014 check it",
                     "over": "Pokes outside the car"}[_fit["status"]]
        st.markdown(
            f'<div style="border:1px solid var(--line);border-left:4px solid '
            f'{_fit_color};border-radius:8px;padding:8px 12px;margin:4px 0;">'
            f'<b style="color:{_fit_color};">{_fit_word}.</b> '
            f'<span style="font-size:.9rem;">' + "; ".join(_fit["messages"]) +
            '.</span><br><span class="hint" style="font-size:.82rem;">Quick '
            'envelope read against wheelbase, track and hoop height \u2014 not a '
            'collision check. Confirm real clearances in INTEGRATION.</span></div>',
            unsafe_allow_html=True)

        _ab = st.columns([1, 1, 3])
        if _ab[0].button("Add to car", key="car3d_cp_add", type="primary"):
            st.session_state.car3d_custom_parts.append(dict(_draft))
            st.session_state.car3d_focus = _cp_sub if _cp_sub != "(custom / unassigned)" else None
            st.rerun()
        if _ab[1].button("Clear all", key="car3d_cp_clearall",
                         disabled=not st.session_state.car3d_custom_parts):
            st.session_state.car3d_custom_parts = []
            st.rerun()

        # The parts already on the car, each removable. Keeps the list honest and
        # lets a team pull a part once they've seen it doesn't belong there.
        if st.session_state.car3d_custom_parts:
            st.markdown('<p class="hint" style="margin:8px 0 2px;"><b>On the car '
                        'now:</b></p>', unsafe_allow_html=True)
            for _ci, _cpd in enumerate(list(st.session_state.car3d_custom_parts)):
                _lc = st.columns([5, 1])
                _tag = (' <span style="color:#ffd166;">· awaiting CAD</span>'
                        if _cpd.get("provisional") else '')
                _is_mesh = _cpd.get("shape") == "mesh" and _cpd.get("mesh")
                _mtag = (' <span style="color:#37e0d0;">· CAD mesh</span>'
                         if _is_mesh else '')
                _f = lambda v: units_mod.from_metric(float(v), "mm")
                _ul = units_mod.label("mm")
                _lc[0].markdown(
                    f'<span style="font-size:.9rem;">\u2022 <b>{_cpd["name"]}</b> '
                    f'({_cpd["subsys"]}) \u2014 {_f(_cpd.get("l_mm",0)):.0f}\u00d7'
                    f'{_f(_cpd.get("w_mm",0)):.0f}\u00d7{_f(_cpd.get("h_mm",0)):.0f} {_ul} @ '
                    f'({_f(_cpd.get("x_mm",0)):.0f}, {_f(_cpd.get("y_mm",0)):.0f}, '
                    f'{_f(_cpd.get("z_mm",0)):.0f}){_mtag}{_tag}</span>',
                    unsafe_allow_html=True)
                if _lc[1].button("Remove", key=f"car3d_cp_rm_{_ci}"):
                    st.session_state.car3d_custom_parts.pop(_ci)
                    st.rerun()
                # Orientation + nudge for imported CAD meshes. The library
                # autosync places CAD with yaw 0 / z-up; when a frame comes in
                # BACKWARDS or lying on its side, these fix it without
                # re-exporting. Mutations land in session_state before the
                # figure builds (the car draws into _car_slot after this
                # section), so they take effect on the same run. Keys use the
                # library id where present so state survives list reordering.
                if _is_mesh:
                    _pk = str(_cpd.get("lib_id") or f"idx{_ci}")
                    _oc = st.columns([1.1, 1.1, 1.8, 1.3, 1.3, 1.3])
                    if _oc[0].button("↻ 180°", key=f"car3d_cp_flip_{_pk}",
                                     help="Spin this CAD half a turn about z — "
                                          "the fix when an imported frame "
                                          "reads backwards on the car."):
                        _cpd["yaw_deg"] = (float(_cpd.get("yaw_deg", 0.0)
                                                 or 0.0) + 180.0) % 360.0
                    if _oc[1].button("↻ +90°", key=f"car3d_cp_yaw90_{_pk}",
                                     help="Rotate 90° about z (vertical)."):
                        _cpd["yaw_deg"] = (float(_cpd.get("yaw_deg", 0.0)
                                                 or 0.0) + 90.0) % 360.0
                    _AXES = ["z_up", "y_up", "x_up"]
                    _ax_now = _cpd.get("axis_map", "z_up")
                    _ax_new = _oc[2].selectbox(
                        "Up axis", _AXES,
                        index=_AXES.index(_ax_now if _ax_now in _AXES
                                          else "z_up"),
                        key=f"car3d_cp_ax_{_pk}",
                        help="If the part lies on its side, the CAD was "
                             "exported with a different up axis — switch it "
                             "here (SolidWorks exports are often y-up).")
                    if _ax_new != _ax_now:
                        _cpd["axis_map"] = _ax_new
                    for _col, _dk, _dlbl, _dhelp in (
                            (_oc[3], "dx_mm", "Δx mm", "Nudge fore(+)/aft(−)"),
                            (_oc[4], "dy_mm", "Δy mm", "Nudge right(+)/left(−)"),
                            (_oc[5], "dz_mm", "Δz mm", "Nudge up(+)/down(−)")):
                        _dv = _col.number_input(
                            _dlbl, min_value=-2000.0, max_value=2000.0,
                            value=float(_cpd.get(_dk, 0.0) or 0.0), step=10.0,
                            key=f"car3d_cp_{_dk}_{_pk}", help=_dhelp)
                        if _dv != float(_cpd.get(_dk, 0.0) or 0.0):
                            _cpd[_dk] = float(_dv)

    # ===================================================================== #
    #  WAITING ON A PART?  —  unblock the missing-CAD handoff.               #
    # ===================================================================== #
    # The other recurring stall: a part lives in someone else's CAD that never
    # arrives ("I'll ask for the CAD again / one day they'll send it") or shows
    # up wrong (a mirror of the original). Dependent work freezes because there's
    # nothing to package around. This panel breaks that: declare the missing part
    # with a best-guess size NOW and a translucent stand-in lands on the car so
    # your work continues; when the real CAD finally arrives, drop it on the same
    # request and it auto-reads the true dimensions, tells you if your guess was
    # off (catching the mirror / wrong-size handoff), and replaces the stand-in
    # in place — keeping the position you already worked out.
    if "car3d_part_requests" not in st.session_state:
        st.session_state.car3d_part_requests = []

    _open_reqs = [r for r in st.session_state.car3d_part_requests
                  if not r.get("resolved")]
    with st.expander(
            "⏳  Waiting on a part? Place a stand-in so you're not blocked"
            + (f"  ·  {len(_open_reqs)} open" if _open_reqs else ""),
            expanded=False):
        st.markdown(
            '<p class="hint">A part stuck in someone else\u2019s CAD shouldn\u2019t '
            'freeze your work. Put your <b>best-guess</b> size and position here and '
            'a clearly-marked translucent stand-in goes on the car right away, so '
            'you can keep packaging around it. When the real CAD lands, attach it to '
            'this request \u2014 it reads the true L\u00d7W\u00d7H automatically, '
            'warns you if it\u2019s a different size or looks <b>mirrored</b> from '
            'your guess, and swaps the stand-in for the real part without losing the '
            'spot you placed it.</p>', unsafe_allow_html=True)

        # Seed the request-form fields once so a "suggest" button can fill them
        # (a widget can't take both value= and a session_state-owned key).
        _RQ_DEFAULTS = dict(car3d_rq_l=200.0, car3d_rq_w=150.0, car3d_rq_h=100.0,
                            car3d_rq_x=0.0, car3d_rq_y=0.0, car3d_rq_z=250.0)
        for _k, _v in _RQ_DEFAULTS.items():
            if _k not in st.session_state:
                st.session_state[_k] = _v

        _rq = st.columns([3, 2, 2])
        _rq_name = _rq[0].text_input("Part you're waiting on", key="car3d_rq_name",
                                     placeholder="e.g. Radiator core")
        _rq_sub = _rq[1].selectbox("For subsystem", _CP_SUBSYS, key="car3d_rq_subsys")
        _rq_owner = _rq[2].text_input("Owed by (team / person)", key="car3d_rq_owner",
                                      placeholder="e.g. Powertrain / Joe")

        # ---- FALLBACK: no idea how big it should be? Let the system propose a
        # target. This is the deepest version of the unblock — a team that can't
        # even guess gets car-scaled x/y/z dimensions to design TOWARD, derived
        # from this car's wheelbase/track/tyre and FSAE-typical proportions.
        _sg1, _sg2 = st.columns([2, 3])
        if _sg1.button("💡 Suggest target dimensions", key="car3d_rq_suggest",
                       help="No guess? Fill the boxes with a size the car can "
                            "actually fit for this subsystem — a number to strive "
                            "toward until the real part exists."):
            try:
                _vp_sg = VehicleParams(**{k: v for k, v in st.session_state.vp.items()
                                          if k in set(VehicleParams.__dataclass_fields__.keys())})
            except Exception:
                _vp_sg = VehicleParams()
            _sub_for = _rq_sub if _rq_sub != "(custom / unassigned)" else "chassis"
            try:
                _led_sg = interfaces_mod.IntegrationLedger.from_dict(st.session_state.ledger)
            except Exception:
                _led_sg = None
            _sg = fullcar_mod.suggest_part_geometry(_vp_sg, _sub_for, ledger=_led_sg)
            st.session_state.car3d_rq_l = float(_sg["l_mm"])
            st.session_state.car3d_rq_w = float(_sg["w_mm"])
            st.session_state.car3d_rq_h = float(_sg["h_mm"])
            st.session_state.car3d_rq_x = float(_sg["x_mm"])
            st.session_state.car3d_rq_y = float(_sg["y_mm"])
            st.session_state.car3d_rq_z = float(_sg["z_mm"])
            st.session_state.car3d_rq_suggest_basis = _sg
            st.rerun()

        _sgb = st.session_state.get("car3d_rq_suggest_basis")
        if _sgb:
            _decl = (" Kept your declared " + "/".join(_sgb["from_declared"])
                     + " from the ledger." if _sgb.get("from_declared") else "")
            _sg2.markdown(
                '<div style="border:1px solid var(--line);border-left:4px solid '
                '#9b8cff;border-radius:8px;padding:6px 12px;margin-top:26px;">'
                '<span style="font-size:.86rem;"><b>Suggested target</b> '
                f'\u2014 {_sgb["l_mm"]:.0f}\u00d7{_sgb["w_mm"]:.0f}\u00d7{_sgb["h_mm"]:.0f} '
                'mm. <span class="hint">' + "; ".join(_sgb["basis"]) + "." + _decl +
                ' A goal to build toward, not a spec.</span></span></div>',
                unsafe_allow_html=True)

        st.markdown('<p class="hint" style="margin:6px 0 2px;"><b>Best-guess size '
                    '(mm)</b> \u2014 a rough box is fine, or use the suggestion above; '
                    'you\u2019ll replace it with the real one.</p>',
                    unsafe_allow_html=True)
        _rs = st.columns(3)
        _rq_l = unum(_rs[0], "Guess L (mm)", 1, 3000, 100, "mm",
                     step=5.0, key="car3d_rq_l")
        _rq_w = unum(_rs[1], "Guess W (mm)", 1, 2000, 100, "mm",
                     step=5.0, key="car3d_rq_w")
        _rq_h = unum(_rs[2], "Guess H (mm)", 1, 2000, 100, "mm",
                     step=5.0, key="car3d_rq_h")
        _rp = st.columns(3)
        _rq_x = unum(_rp[0], "Centre x (mm)", -1500, 1500, 0, "mm",
                     step=10.0, key="car3d_rq_x")
        _rq_y = unum(_rp[1], "Centre y (mm)", -900, 900, 0, "mm",
                     step=10.0, key="car3d_rq_y")
        _rq_z = unum(_rp[2], "Centre z (mm)", 0, 1500, 250, "mm",
                     step=10.0, key="car3d_rq_z")

        if st.button("Place stand-in & log the request", key="car3d_rq_add",
                     type="primary"):
            _pid = "req_%d_%s" % (
                len(st.session_state.car3d_part_requests),
                _datetime.datetime.now().strftime("%H%M%S%f"))
            _stand = dict(name=(_rq_name.strip() or "Awaited part"),
                          subsys=_rq_sub, l_mm=_rq_l, w_mm=_rq_w, h_mm=_rq_h,
                          x_mm=_rq_x, y_mm=_rq_y, z_mm=_rq_z, shape="box",
                          provisional=True, req_id=_pid)
            st.session_state.car3d_custom_parts.append(_stand)
            st.session_state.car3d_part_requests.append(dict(
                req_id=_pid, name=_stand["name"], subsys=_rq_sub,
                owner=_rq_owner.strip(), guess=dict(l_mm=_rq_l, w_mm=_rq_w, h_mm=_rq_h),
                suggested=bool(_sgb),
                placed_on=_datetime.date.today().isoformat(), resolved=False))
            st.session_state.car3d_focus = (_rq_sub if _rq_sub != "(custom / unassigned)"
                                            else None)
            st.session_state.pop("car3d_rq_suggest_basis", None)
            st.rerun()

        # ---- open requests: each can take the real CAD and be reconciled ---- #
        if _open_reqs:
            st.markdown('<p class="hint" style="margin:10px 0 4px;"><b>Open requests '
                        '\u2014 attach the CAD when it arrives:</b></p>',
                        unsafe_allow_html=True)
        for _req in _open_reqs:
            _rid = _req["req_id"]
            _g = _req.get("guess", {})
            st.markdown(
                f'<div style="border:1px solid var(--line);border-left:4px solid '
                f'#ffd166;border-radius:8px;padding:8px 12px;margin:4px 0;">'
                f'<b>{_req["name"]}</b> \u2014 for <i>{_req["subsys"]}</i>'
                + (f', owed by <b>{_req["owner"]}</b>' if _req.get("owner") else '')
                + f' \u00b7 stand-in {units_mod.from_metric(_g.get("l_mm",0),"mm"):.0f}\u00d7{units_mod.from_metric(_g.get("w_mm",0),"mm"):.0f}'
                f'\u00d7{units_mod.from_metric(_g.get("h_mm",0),"mm"):.0f} {units_mod.label("mm")} \u00b7 since {_req.get("placed_on","")}'
                '</div>', unsafe_allow_html=True)

            _cad = st.file_uploader(
                f"Drop the real CAD for \u201c{_req['name']}\u201d (STEP / STL / OBJ / GLB)",
                type=["step", "stp", "stl", "obj", "glb"],
                key=f"car3d_rq_cad_{_rid}")
            if _cad is not None:
                try:
                    import tempfile as _tf, os as _os
                    _sfx = "." + _cad.name.split(".")[-1]
                    with _tf.NamedTemporaryFile(delete=False, suffix=_sfx) as _f:
                        _f.write(_cad.getbuffer())
                        _cad_path = _f.name
                    with st.spinner("Reading the arrived CAD…"):
                        _payload_r = chassis_mod.load_part_mesh(_cad_path, max_faces=4000)
                    _os.unlink(_cad_path)
                    _real = dict(l_mm=_payload_r["size_mm"][0],
                                 w_mm=_payload_r["size_mm"][1],
                                 h_mm=_payload_r["size_mm"][2],
                                 centre_mm=[0.0, 0.0, 0.0])
                    _rec = fullcar_mod.reconcile_part(_g, _real)
                    _col = {"match": "#5ad17a", "resize": "#ffd166",
                            "mirrored": "#ff6b5a", "new": "#5ad17a"}[_rec["status"]]
                    _word = {"match": "Matches your stand-in",
                             "resize": "Different size than your guess",
                             "mirrored": "Looks mirrored / wrong orientation",
                             "new": "Placing the real part"}[_rec["status"]]
                    st.markdown(
                        f'<div style="border:1px solid var(--line);border-left:4px '
                        f'solid {_col};border-radius:8px;padding:8px 12px;margin:4px 0;">'
                        f'<b style="color:{_col};">{_word}.</b> '
                        f'<span style="font-size:.9rem;">Real part reads '
                        f'<b>{units_mod.from_metric(_real["l_mm"],"mm"):.0f}\u00d7{units_mod.from_metric(_real["w_mm"],"mm"):.0f}'
                        f'\u00d7{units_mod.from_metric(_real["h_mm"],"mm"):.0f} {units_mod.label("mm")}</b> ({_payload_r["triangles"]} '
                        f'triangles). ' + " ".join(_rec["messages"])
                        + ' The real geometry will replace the stand-in box.'
                        + '</span></div>', unsafe_allow_html=True)

                    _kx = st.checkbox("Keep my stand-in's position (recommended)",
                                      value=True, key=f"car3d_rq_keep_{_rid}")
                    _ax_r = st.selectbox(
                        "Up axis in CAD", ["z_up", "y_up", "x_up"],
                        key=f"car3d_rq_axis_{_rid}",
                        help="If the part comes in lying on its side, switch this.")
                    if st.button(f"Confirm & replace stand-in for \u201c{_req['name']}\u201d",
                                 key=f"car3d_rq_confirm_{_rid}", type="primary"):
                        # Turn the stand-in into the confirmed REAL MESH, in place.
                        for _p in st.session_state.car3d_custom_parts:
                            if _p.get("req_id") == _rid:
                                _p["shape"] = "mesh"
                                _p["mesh"] = _payload_r
                                _p["axis_map"] = _ax_r
                                _p["yaw_deg"] = 0.0
                                _p["mesh_scale"] = 1.0
                                _p["l_mm"] = _real["l_mm"]
                                _p["w_mm"] = _real["w_mm"]
                                _p["h_mm"] = _real["h_mm"]
                                _p["provisional"] = False
                                break
                        _req["resolved"] = True
                        _req["real"] = _real
                        _req["verdict"] = _rec["status"]
                        st.session_state.car3d_focus = (
                            _req["subsys"] if _req["subsys"] != "(custom / unassigned)"
                            else None)
                        st.rerun()
                except Exception as _ce:
                    st.error(
                        "Couldn't read that CAD (" + str(_ce) + "). STEP is most "
                        "reliable; if it's a STEP make sure cascadio is installed. "
                        "You can keep using the stand-in meanwhile.")

            _rcols = st.columns([1, 4])
            if _rcols[0].button("Cancel request", key=f"car3d_rq_cancel_{_rid}"):
                st.session_state.car3d_custom_parts = [
                    _p for _p in st.session_state.car3d_custom_parts
                    if _p.get("req_id") != _rid]
                st.session_state.car3d_part_requests = [
                    _r for _r in st.session_state.car3d_part_requests
                    if _r["req_id"] != _rid]
                st.rerun()

        # Resolved history — a short record of which guesses were right, and which
        # handoffs came back mirrored/resized, so the team sees its own pattern.
        _done = [r for r in st.session_state.car3d_part_requests if r.get("resolved")]
        if _done:
            st.markdown('<p class="hint" style="margin:10px 0 2px;"><b>Resolved:'
                        '</b></p>', unsafe_allow_html=True)
            for _r in _done:
                _vc = {"match": "#5ad17a", "resize": "#ffd166",
                       "mirrored": "#ff6b5a", "new": "#5ad17a"}.get(
                    _r.get("verdict", "match"), "#8d99a6")
                st.markdown(
                    f'<span style="font-size:.88rem;">\u2713 <b>{_r["name"]}</b> '
                    f'(<span style="color:{_vc};">{_r.get("verdict","resolved")}</span>) '
                    f'\u2014 now confirmed on the car.</span>', unsafe_allow_html=True)


    with st.expander("ⓘ  About this view — and the build-day check it is *not*",
                     expanded=False):
        st.markdown(
            '<span style="font-size:.92rem;line-height:1.5;">This is the assembled car '
            'as a <i>picture</i>: it shows where every subsystem sits and lets you '
            'resize or reposition a body to explore packaging. Moving a part here '
            'changes the <b>drawing</b>, not the real car \u2014 it will not catch a '
            'collision on build day. For a team that can manufacture only once, the '
            'check that actually protects the build lives in the '
            '<b>INTEGRATION tab \u2192 \u201cMount-point clash\u201d</b> view: declare '
            'each subsystem\u2019s reserved volume and where its parts bolt on, and the '
            '<b>manufacturing-readiness board</b> there gives a single go/no-go \u2014 '
            'red if parts physically overlap (do not cut), amber for thin clearances to '
            'decide deliberately, green when the car will assemble. It flags anything '
            'still based on an <i>estimate</i> so you know what to confirm before '
            'sign-off.</span>', unsafe_allow_html=True)

    # ---- Edit parts: per-part size & position overrides ------------------- #
    # Each part the car draws can be nudged in x/y/z (mm) and resized (uniform
    # or per-axis), on top of whatever its subsystem numbers produced. These are
    # pure presentation overrides held in session_state["car3d_overrides"] and
    # handed to build_full_car_figure as part_overrides; the underlying
    # engineering declarations are untouched. Keys are the parts' draw names.
    _PART_EDIT = {
        "Front wing":        "aerodynamics",
        "Rear wing":         "aerodynamics",
        "Sidepod (cooling)": "cooling",
        "Radiator core":     "cooling",
        "Motor + inverter":  "powertrain",
        "Accumulator":       "electrics",
        "Space frame":       "chassis",
        "Spaceframe":        "chassis",
        "Monocoque":         "chassis",
        "Roll hoop":         "chassis",
        "Driver":            "chassis",
        "Tire":              "suspension",
        "Brake disc":        "brakes",
        "Data logger":       "data-acquisition",
    }
    if "car3d_overrides" not in st.session_state:
        st.session_state.car3d_overrides = {}

    # Widget-state keys a single part owns. The number inputs / slider / checkbox
    # cache their own value in session_state under these keys, and once a key
    # exists Streamlit ignores the `value=`/`default=` we pass on later runs. So
    # a reset that only clears car3d_overrides[part] gets instantly overwritten by
    # the stale widget values on the same rerun. To make resets actually stick we
    # must also drop these keys so the widgets re-seed from the cleared override.
    def _ov_widget_keys(part):
        return [f"car3d_ov_dx_{part}", f"car3d_ov_dy_{part}", f"car3d_ov_dz_{part}",
                f"car3d_ov_sx_{part}", f"car3d_ov_sy_{part}", f"car3d_ov_sz_{part}",
                f"car3d_ov_scale_{part}"]

    def _clear_ov_widgets(parts):
        for _p in parts:
            for _k in _ov_widget_keys(_p):
                st.session_state.pop(_k, None)
        st.session_state.pop("car3d_ov_adv", None)
        st.session_state.pop("car3d_plot", None)

    with st.expander("Edit parts — size & position", expanded=False):
        st.markdown(
            '<p class="hint">Nudge any part\u2019s <b>location</b> (x: rear\u2194front, '
            'y: left\u2194right, z: down\u2194up, in mm) and its <b>size</b> right '
            'beside it (uniform, or per-axis under \u201cAdvanced\u201d). These are '
            'view overrides on top of your subsystem numbers \u2014 they move and '
            'resize the body in the model without changing any declared '
            'engineering value. Tires and brake discs resize at all four corners '
            'at once.</p>', unsafe_allow_html=True)

        _ep1, _ep2 = st.columns([3, 1])
        _part = _ep1.selectbox("Part", list(_PART_EDIT.keys()), key="car3d_editpart")
        if _ep2.button("Reset all parts", key="car3d_ov_resetall",
                       help="Clear every part override and return all parts to "
                            "their computed size and place."):
            _clear_ov_widgets(_PART_EDIT.keys())
            st.session_state.car3d_overrides = {}
            st.rerun()

        _cur = dict(st.session_state.car3d_overrides.get(_part, {}))
        _adv = st.checkbox("Advanced (per-axis scale)", key="car3d_ov_adv",
                           value=any(k in _cur for k in ("sx", "sy", "sz")))

        # Location on the left, size on the right — the two live side by side.
        _loc_col, _size_col = st.columns(2)

        with _loc_col:
            st.markdown('<p class="hint" style="margin-bottom:2px;"><b>Location'
                        '</b></p>', unsafe_allow_html=True)
            _dx = unum(st, "Move x (mm)", -1500, 1500,
                       float(_cur.get("dx", 0.0)), "mm", step=10.0,
                       key=f"car3d_ov_dx_{_part}")
            _dy = unum(st, "Move y (mm)", -1500, 1500,
                       float(_cur.get("dy", 0.0)), "mm", step=10.0,
                       key=f"car3d_ov_dy_{_part}")
            _dz = unum(st, "Move z (mm)", -1500, 1500,
                       float(_cur.get("dz", 0.0)), "mm", step=10.0,
                       key=f"car3d_ov_dz_{_part}")

        _new = dict(dx=_dx, dy=_dy, dz=_dz)

        with _size_col:
            st.markdown('<p class="hint" style="margin-bottom:2px;"><b>Size</b>'
                        '</p>', unsafe_allow_html=True)
            if _adv:
                _sx = st.number_input(
                    "Scale x", value=float(_cur.get("sx", _cur.get("scale", 1.0))),
                    min_value=0.2, max_value=4.0, step=0.05,
                    key=f"car3d_ov_sx_{_part}")
                _sy = st.number_input(
                    "Scale y", value=float(_cur.get("sy", _cur.get("scale", 1.0))),
                    min_value=0.2, max_value=4.0, step=0.05,
                    key=f"car3d_ov_sy_{_part}")
                _sz = st.number_input(
                    "Scale z", value=float(_cur.get("sz", _cur.get("scale", 1.0))),
                    min_value=0.2, max_value=4.0, step=0.05,
                    key=f"car3d_ov_sz_{_part}")
                _new.update(sx=_sx, sy=_sy, sz=_sz)
            else:
                _scl = st.slider(
                    "Size (uniform scale)", min_value=0.2, max_value=4.0,
                    value=float(_cur.get("scale", _cur.get("sx", 1.0))),
                    step=0.05, key=f"car3d_ov_scale_{_part}")
                _new["scale"] = _scl

        if st.button(f"Reset \u201c{_part}\u201d", key=f"car3d_ov_reset_{_part}"):
            st.session_state.car3d_overrides.pop(_part, None)
            _clear_ov_widgets([_part])
            st.rerun()

        # Persist only meaningful (non-identity) overrides so the dict stays clean.
        _is_identity = (_new.get("dx", 0) == 0 and _new.get("dy", 0) == 0
                        and _new.get("dz", 0) == 0
                        and all(_new.get(k, 1.0) == 1.0
                                for k in ("scale", "sx", "sy", "sz") if k in _new))
        if _is_identity:
            st.session_state.car3d_overrides.pop(_part, None)
        else:
            st.session_state.car3d_overrides[_part] = _new

        _active = st.session_state.car3d_overrides
        if _active:
            st.markdown('<p class="hint" style="margin-bottom:2px;">Active part '
                        'overrides:</p>', unsafe_allow_html=True)
            _summ = []
            for _pn, _o in _active.items():
                _mv = [f"{ax}{_o[k]:+.0f}" for ax, k in
                       (("x", "dx"), ("y", "dy"), ("z", "dz"))
                       if _o.get(k)]
                if "scale" in _o and _o["scale"] != 1.0:
                    _mv.append(f"×{_o['scale']:.2f}")
                for ax, k in (("sx", "sx"), ("sy", "sy"), ("sz", "sz")):
                    if _o.get(k, 1.0) != 1.0:
                        _mv.append(f"{ax}×{_o[k]:.2f}")
                _summ.append(f"<b>{_pn}</b>: {', '.join(_mv) if _mv else 'none'}")
            st.markdown('<p class="hint">' + " &nbsp;·&nbsp; ".join(_summ) + '</p>',
                        unsafe_allow_html=True)
    _part_overrides = dict(st.session_state.car3d_overrides)

    with _car_slot:
      try:
          _vp_fields_car = set(VehicleParams.__dataclass_fields__.keys())
          _vp_kwargs_car = {k: v for k, v in st.session_state.vp.items()
                            if k in _vp_fields_car}
          _vp_car = VehicleParams(**_vp_kwargs_car)
          _led_car = interfaces_mod.IntegrationLedger.from_dict(st.session_state.ledger)

          # Reflect the CHOSEN suspension architecture. For double wishbone we hand
          # the renderer the live Hardpoints; for every other topology we hand it
          # the already-solved topology-aware kinematics (`kin`), which reports its
          # own member set. `kin` and `_topo` are the live objects the whole app is
          # running on, so the full car always matches the topology in the sidebar.
          _topo_now = st.session_state.get("topology", "double_wishbone")
          _topo_lbl = globals().get("_TOPO_LABELS", {}).get(_topo_now, _topo_now)
          if _topo_now == "double_wishbone":
              _hp_car = Hardpoints.from_dict(st.session_state.hp)
              _car_kwargs = dict(hp_front=_hp_car)
          else:
              # `kin` is the GenericKinematics solved above for this topology.
              _car_kwargs = dict(corner_front=kin)

          # The clicked part (if any) drives both the spotlight and the camera
          # zoom. A click from a previous run is stored in car3d_focus; choosing a
          # subsystem in the spotlight picker also zooms to it. "(whole car)"
          # clears the zoom back to the wide shot.
          _focus = st.session_state.get("car3d_focus")
          if _highlight:
              _focus = _highlight
          # A CAD part that replaces a subsystem hides ALL that subsystem's dummy
          # bodies (its draw-names). Other subsystems stay on as dummy
          # suggestions. Build the suppression sets from every custom part.
          # Library ⇄ 3D autosync: the model mirrors the CAD library — parts
          # published in ANY session appear, deleted ones eject their dummy back.
          try:
              _lib_autosync(get_store())
          except Exception:
              pass
          _suppress = set()
          _suppress_parts = set()
          for _p in st.session_state.get("car3d_custom_parts", []):
              if _p.get("replaces_subsys"):
                  _suppress.add(_p["replaces_subsys"])
              for _dn in (_p.get("replaces_drawnames") or []):
                  _suppress_parts.add(_dn)
              # Back-compat with any single-draw-name parts (older sessions).
              if _p.get("replaces_drawname"):
                  _suppress_parts.add(_p["replaces_drawname"])
              if _p.get("replaces_dummy"):
                  _suppress_parts.add(_p["replaces_dummy"])
          _fig_car = fullcar_mod.build_full_car_figure(
              vp=_vp_car, ledger=_led_car, topology_label=_topo_lbl,
              show_tires=_show_tires, show_brakes=_show_brakes,
              show_aero=_show_aero, show_cooling=_show_cool,
              show_powertrain=_show_pt, show_electrics=_show_el,
              show_bodywork=_show_body, show_floor=_show_floor,
              highlight_subsystem=_focus,
              focus_subsystem=_focus, tire_width_mm=float(_tire_w),
              part_overrides=_lib_snap_overrides(_part_overrides),
              custom_parts=st.session_state.get("car3d_custom_parts", []),
              suppress_subsystems=_suppress,
              suppress_parts=_suppress_parts,
              **_car_kwargs)
          # Stash the actual drawn part boxes so the CAD form (which runs before
          # this build on the next rerun) can fit a part to its REAL placeholder,
          # not just the rough anchor. Read from the prior run; refreshes on redraw.
          try:
              st.session_state.car3d_part_boxes = dict(_fig_car._part_boxes)
          except Exception:
              pass
          # Per-instance boxes (one per copy of a multi-corner body) feed the
          # CAD library's Fit forecast, so clearance / interference reasons
          # about a single tire, not a ring spanning the whole car.
          try:
              st.session_state.car3d_part_instances = dict(
                  _fig_car._part_instance_boxes)
          except Exception:
              pass

          # ---- Aero mount-point overlay (from the Mounting designer) ------ #
          # Anchored to the REAL drawn part boxes, so the anchors track wing
          # resizes and wheelbase changes. The element currently selected in
          # Aerodynamics → Mounting & bonding designer is emphasised, and its
          # mount COUNT there drives how many markers appear on that element.
          if _show_mounts:
              try:
                  _n_shown = _add_aero_mount_overlay(
                      _fig_car,
                      selected_el=st.session_state.get("aero_mnt_el"),
                      n_selected=st.session_state.get("aero_mnt_n"))
                  if _n_shown:
                      st.caption(
                          f"⚓ {_n_shown} aero mount points shown — gold diamonds; "
                          "dotted lines are the load path into primary structure "
                          "(front bulkhead, main hoop, lower rails). Size them in "
                          "Aerodynamics → Mounting & bonding designer.")
                  else:
                      st.caption(
                          "⚓ Mount points need a chassis body to anchor to — "
                          "turn the “Bodywork (spaceframe + hoops)” layer on, "
                          "or put a chassis CAD on the car, and they'll appear.")
              except Exception:
                  pass

          # ---- Assembly Completion Index (Master Assembly engine) --------- #
          # Volume-weighted share of the car's boundary volume occupied by
          # true CAD vs dummy placeholders, κ-discounted by fit confidence.
          # Live by design: dummy volumes track hardpoints, so the number
          # legitimately moves when geometry moves — signal, not a bug.
          try:
              from suspension import master_assembly as _ma_mod
              _aci_res = _ma_mod.aci_from_part_boxes(
                  getattr(_fig_car, "_part_boxes", {}) or {},
                  st.session_state.get("car3d_custom_parts", []))
              if _aci_res["total_volume_mm3"] > 0:
                  st.progress(
                      max(0.0, min(1.0, float(_aci_res["aci"]))),
                      text=(f"Assembly Completion Index · "
                            f"{_aci_res['aci'] * 100:.1f}%  ·  "
                            f"{_aci_res['n_cad']} of {_aci_res['n_slots']} "
                            f"bodies are true CAD (volume-weighted)"))
          except Exception:
              pass

          # Native Streamlit selection events (streamlit>=1.49): a click returns the
          # picked point, whose customdata carries the subsystem id we tagged each
          # body with. We store it and rerun so build_full_car_figure reframes the
          # camera onto that part — i.e. clicking a part auto-zooms.
          _sel = st.plotly_chart(_fig_car, width='stretch', key="car3d_plot",
                                 on_select="rerun",
                                 selection_mode=("points",),
                                 config={"scrollZoom": True, "displaylogo": False})
          st.markdown(
              f'<p class="hint" style="margin:2px 0 0;">Suspension: '
              f'<b>{_topo_lbl}</b>'
              + (f' · zoomed on <b>{_focus}</b> — click another part to move, or '
                 '“Reset zoom” to pull back.' if _focus else
                 ' · <b>click a part to zoom in.</b>')
              + '</p>', unsafe_allow_html=True)
          try:
              _pts = (_sel or {}).get("selection", {}).get("points", [])
          except Exception:
              _pts = []
          if _pts:
              # customdata is [subsystem, part_key, corner] per point. The
              # Full-car view zooms by SUBSYSTEM, so take element 0. Stay
              # backward-compatible with a bare-string customdata just in case.
              _cd = _pts[0].get("customdata")
              if isinstance(_cd, (list, tuple)):
                  _clicked = _cd[0][0] if (_cd and isinstance(_cd[0], (list, tuple))) else _cd[0]
              else:
                  _clicked = _cd
              if _clicked and _clicked != st.session_state.get("car3d_focus"):
                  st.session_state.car3d_focus = _clicked
                  st.rerun()

          # Live influence read-out + sizing notes, tucked away so the model
          # itself stays the focus. Open it when you want the detail.
          _rows = fullcar_mod.influence_summary(_vp_car, _led_car, topology_label=_topo_lbl)
          with st.expander("Live influence & sizing notes", expanded=False):
              st.markdown('<p class="hint" style="margin-bottom:4px;"><b>What each '
                          'subsystem\u2019s current declaration is doing to the model '
                          'right now:</b></p>', unsafe_allow_html=True)
              import pandas as _pd
              _df_inf = _pd.DataFrame(_rows)[["subsystem", "status", "detail"]]
              st.dataframe(_df_inf, hide_index=True, width='stretch')
              _uL = units_mod.label("mm")
              _wb = units_mod.from_metric(_vp_car.wheelbase, "mm")
              _tf = units_mod.from_metric(_vp_car.track_front, "mm")
              _tr = units_mod.from_metric(_vp_car.track_rear, "mm")
              st.markdown(
                  f'<p class="hint">Wheelbase <b>{_wb:.0f} {_uL}</b> · '
                  f'front/rear track <b>{_tf:.0f}/{_tr:.0f} {_uL}</b>. '
                  'Bodies with a declared envelope are drawn at their reserved size; bodies '
                  'sized from a performance number (downforce, power, airflow, brake torque) '
                  'are labelled "(sized from \u2026)" \u2014 they show direction of change, not '
                  'a CFD/analysis result. Declare masses + CG positions for every subsystem '
                  'in the INTEGRATION tab to make the gold CG marker reflect the real car.</p>',
                  unsafe_allow_html=True)
      except Exception as _e:
          st.error(f"Could not assemble the full-car view: {_e}")

# --------------------------- HEATMAP 3D ------------------------------------ #
# The whole car shaded by a physical metric so the powertrain↔cooling↔electrics
# coupling is legible at a glance: where heat piles up, where the LV draw goes,
# where the mass sits. Same assembled car as Full car, recoloured by load and
# outlined in magenta wherever a subsystem exceeds what the car can carry. The
# numbers come straight from the INTEGRATION ledger, so the picture and the
# warnings below it never disagree — it's a design-review tool, not decoration.
with tab_car:
  if st.session_state.get("model3d_view", "Full car") == "Heatmap":
    _MK = {"Heat": "heat", "Electrical": "power", "Mass": "mass"}
    _mk_label = st.radio(
        "Metric", list(_MK.keys()), horizontal=True, key="heat3d_metric",
        help="Heat = waste heat each subsystem dumps (cooling has to remove it); "
             "Electrical = continuous LV draw (supply has to feed it); "
             "Mass = where the weight sits (drives CG and the mass budget).")
    _metric = _MK[_mk_label]

    try:
        _vp_fields_h = set(VehicleParams.__dataclass_fields__.keys())
        _vp_kwargs_h = {k: v for k, v in st.session_state.vp.items()
                        if k in _vp_fields_h}
        _vp_h = VehicleParams(**_vp_kwargs_h)
        _led_h = interfaces_mod.IntegrationLedger.from_dict(st.session_state.ledger)

        _topo_now_h = st.session_state.get("topology", "double_wishbone")
        _topo_lbl_h = globals().get("_TOPO_LABELS", {}).get(_topo_now_h, _topo_now_h)
        if _topo_now_h == "double_wishbone":
            _car_kwargs_h = dict(hp_front=Hardpoints.from_dict(st.session_state.hp))
        else:
            _car_kwargs_h = dict(corner_front=kin)

        _hm = fullcar_mod.subsystem_metrics(_vp_h, _led_h, _metric)

        # If nothing's been declared for this metric yet, say so plainly — the
        # heatmap is only as good as the INTEGRATION numbers behind it.
        if not _hm["values"]:
            st.info(
                f"No **{_mk_label.lower()}** numbers declared yet. Enter "
                f"{'heat rejection' if _metric=='heat' else 'electrical draw' if _metric=='power' else 'subsystem masses'} "
                "for powertrain, cooling and electrics in the INTEGRATION tab and "
                "they'll light up here.")

        st.markdown(
            f'<p class="hint" style="margin:6px 0 8px;">Each body is shaded by its '
            f'<b>{_hm["label"].lower()}</b>. Cool = light load, hot = heavy load. '
            f'Bodies outlined in <span style="color:#ff2bd6;font-weight:600;">'
            f'magenta</span> exceed what the car can carry. {_hm["blurb"]}</p>',
            unsafe_allow_html=True)

        # Mirror the Full-car view: a CAD part that replaces a subsystem hides
        # that subsystem's dummy bodies here too, so the heatmap shades the real
        # geometry rather than a leftover placeholder.
        _suppress_h = set()
        _suppress_parts_h = set()
        for _p in st.session_state.get("car3d_custom_parts", []):
            if _p.get("replaces_subsys"):
                _suppress_h.add(_p["replaces_subsys"])
            for _dn in (_p.get("replaces_drawnames") or []):
                _suppress_parts_h.add(_dn)
            if _p.get("replaces_drawname"):
                _suppress_parts_h.add(_p["replaces_drawname"])
            if _p.get("replaces_dummy"):
                _suppress_parts_h.add(_p["replaces_dummy"])
        _fig_h = fullcar_mod.build_full_car_figure(
            vp=_vp_h, ledger=_led_h, topology_label=_topo_lbl_h,
            heatmap=_hm,
            custom_parts=st.session_state.get("car3d_custom_parts", []),
            part_overrides=dict(st.session_state.get("car3d_overrides", {})),
            suppress_subsystems=_suppress_h,
            suppress_parts=_suppress_parts_h,
            height=560, **_car_kwargs_h)
        st.plotly_chart(_fig_h, width='stretch', key="heat3d_plot",
                        config={"scrollZoom": True, "displaylogo": False})

        # ---- legend: colour ramp + the actual ranked numbers -------------- #
        _vmax = _hm["vmax"]
        _unit = _hm["unit"]
        _cap = _hm["capacity"]
        # gradient bar
        _stops = ", ".join(
            "%s %d%%" % (fullcar_mod.heat_color(t / 10.0), t * 10)
            for t in range(11))
        _cap_txt = ""
        if _cap:
            if _metric == "heat":
                _cap_txt = (f" · cooling can move <b>{uval(_cap, 'm³/s', fmt='{:.3f}')}</b> of airflow")
            elif _metric == "power":
                _cap_txt = f" · LV supply <b>{_cap:.0f} W</b>"
            else:
                _cap_txt = f" · mass target <b>{uval(_cap, 'kg')}</b>"
        st.markdown(
            f'<div style="margin:6px 0 2px;">'
            f'<div style="height:12px;border-radius:6px;border:1px solid var(--line);'
            f'background:linear-gradient(90deg,{_stops});"></div>'
            f'<div class="hint" style="display:flex;justify-content:space-between;'
            f'margin-top:2px;"><span>0 {_unit}</span>'
            f'<span>peak {_vmax:.0f} {_unit}{_cap_txt}</span></div></div>',
            unsafe_allow_html=True)

        # ranked contributions (the "where is it" table)
        if _hm["values"]:
            _ranked = sorted(_hm["values"].items(), key=lambda kv: -kv[1])
            _total = sum(_hm["values"].values())
            import pandas as _pd_h
            _df_h = _pd_h.DataFrame([
                dict(Subsystem=s.replace("-", " ").title(),
                     **{_hm["label"]: f"{v:.0f} {_unit}"},
                     Share=f"{100*v/_total:.0f}%",
                     Status=("⚠ over budget" if _hm["over"].get(s) else "ok"))
                for s, v in _ranked])
            st.dataframe(_df_h, hide_index=True, width='stretch')
            st.markdown(
                f'<p class="hint" style="margin:2px 0 0;">Total declared '
                f'{_hm["label"].lower()}: <b>{_total:.0f} {_unit}</b>'
                + (f' against a {_cap:.0f} {_unit} budget.' if (_cap and _metric!="heat")
                   else '.') + '</p>', unsafe_allow_html=True)

        # ---- warnings straight from the ledger checks --------------------- #
        if _hm["warnings"]:
            st.markdown('<p class="hint" style="margin:8px 0 2px;"><b>What this '
                        'means for the car:</b></p>', unsafe_allow_html=True)
            for _w in _hm["warnings"]:
                _sev = _w.get("severity", "info")
                if _sev == "fail":
                    st.error(_w["message"])
                elif _sev == "warning":
                    st.warning(_w["message"])
                else:
                    st.info(_w["message"])
        elif _hm["values"]:
            st.success(
                f"No {_mk_label.lower()} conflicts flagged — declared "
                f"{_hm['label'].lower()} sits within the car's budget.")
    except Exception as _eh:
        st.error(f"Could not build the heatmap view: {_eh}")


# =========================================================================== #
#  CHASSIS DOCS & SHARED CAD  —  three panels at the foot of the 3D Model tab. #
#    1. 🗄️ Team CAD library     — publish/browse/download shared CAD & docs.   #
#    2. 📸 SES location pack      — HV/LV positions -> ortho views + coord CSV.  #
#    3. 🧮 Suspension -> Ansys     — hardpoints CSV + BEAM188 APDL torsion deck. #
#  Files persist through the existing project store (get_store()), so they      #
#  survive restarts on Supabase and locally via project.json.                   #
# =========================================================================== #
with tab_car:
    import base64 as _b64
    st.markdown("---")
    st.markdown("### 🗃️ CHASSIS DOCS & SHARED CAD")
    st.warning("⚠️ **LEADS ONLY** — To preserve stability, access restricted to LEADS ONLY",
               icon="🔒")
    st.caption("Everyone's CAD in one place, the SES location pack, and a "
               "ready-to-run ANSYS torsion deck — all from the shared 3D model.")

    _cad_store = get_store()

    # ----------------------------------------------------------------- #
    #  1 · Team CAD library
    # ----------------------------------------------------------------- #
    with st.expander("🗄️ Team CAD library — a place to find everyone else's "
                     "SolidWorks files", expanded=False):
        st.caption("Publish STEP / SLDPRT / SLDASM / STL / DXF / PNG etc. "
                   f"(up to {cadshare_mod.CAD_EMBED_LIMIT_BYTES // (1024*1024)} MB "
                   "embedded, or share a link for big assemblies). Everyone can "
                   "browse, filter, and download.")

        _SUBSYS_TAGS = ["general", "suspension", "chassis", "aero", "ev",
                        "accumulator", "electronics", "SES", "powertrain",
                        "brakes", "bodywork"]

        _pub = st.columns([2.2, 1.3, 1.5])
        _up = _pub[0].file_uploader(
            "File to publish",
            type=["step", "stp", "sldprt", "sldasm", "stl", "dxf", "dwg",
                  "igs", "iges", "png", "jpg", "jpeg", "pdf", "x_t", "x_b",
                  "f3d", "3mf", "obj"],
            key="cad_pub_file")
        _pub_sub = _pub[1].selectbox("Subsystem", _SUBSYS_TAGS, key="cad_pub_sub")
        _pub_who = _pub[2].text_input("Your name", key="cad_pub_who")
        _pub_note = st.text_input("Note (optional)", key="cad_pub_note",
                                  placeholder="e.g. rev C, matches drawing 204-A")

        _big_link = st.text_input(
            "…or share a LINK to a big assembly (GrabCAD / Drive / OneDrive)",
            key="cad_pub_link",
            placeholder="https://…  (use this when the file is over the size cap)")

        if st.button("Publish to library", type="primary", key="cad_pub_btn"):
            try:
                if _up is not None:
                    _bytes = _up.getvalue()
                    if not cadshare_mod.within_embed_limit(len(_bytes)):
                        st.error(
                            f"{_up.name} is {cadshare_mod.human_size(len(_bytes))} — "
                            f"over the {cadshare_mod.CAD_EMBED_LIMIT_BYTES//(1024*1024)} MB "
                            "embed cap. Share it as a link instead (paste a URL above "
                            "and publish without a file).")
                    else:
                        _cad_store.add_cad_file(project_mod.CADFile(
                            name=_up.name, subsystem=_pub_sub,
                            uploader=_pub_who.strip(), kind="file",
                            data_b64=_b64.b64encode(_bytes).decode("ascii"),
                            size_bytes=len(_bytes), note=_pub_note.strip()))
                        _persisted = save_store(_cad_store)
                        # Library ⇄ 3D model bridge: place it on the car too.
                        _msg3d = ""
                        try:
                            _newest = _store_cad_files(_cad_store, None)[0]
                            _ok3d, _msg3d = _lib_inject_cad(_newest)
                            _msg3d = "  \n" + _msg3d
                        except Exception:
                            pass
                        _tail = ("" if _persisted else
                                 "  \n_In the library for everyone this session; "
                                 "the cross-session save is degraded (see the "
                                 "warning above) but your file is not lost._")
                        st.success(f"Published {_up.name} "
                                   f"({cadshare_mod.human_size(len(_bytes))})."
                                   + _msg3d + _tail)
                        _do_rerun()
                elif _big_link.strip():
                    _nm = _big_link.strip().rstrip("/").split("/")[-1] or "assembly link"
                    _cad_store.add_cad_file(project_mod.CADFile(
                        name=_nm, subsystem=_pub_sub, uploader=_pub_who.strip(),
                        kind="link", link=_big_link.strip(), size_bytes=0,
                        note=_pub_note.strip()))
                    save_store(_cad_store)
                    st.success("Shared the link in the library.")
                    _do_rerun()
                else:
                    st.warning("Choose a file or paste a link first.")
            except Exception as _ce:
                st.error(f"Couldn't publish: {_ce}")

        st.markdown("##### Library")
        _all_files = _store_cad_files(_cad_store, None)
        if not _all_files:
            st.info("Nothing shared yet. Be the first to publish a file above.")
        else:
            try:
                _lib_autosync(_cad_store)   # model mirrors the library
            except Exception:
                pass
            _injected = _lib_injected_ids()
            _meshable = [f for f in _all_files if _lib_parseable(f)]
            _pending = [f for f in _meshable if f.id not in _injected]
            st.caption("🧩 **Quick assembly:** every meshable file here "
                       "(STEP/STL/OBJ/GLB) can be placed on the full-car 3D "
                       "model — it snaps into its subsystem's slot, replaces "
                       "that dummy, and the remaining dummies keep the car "
                       "whole until their CAD arrives. A chassis upload "
                       "re-proportions the entire car around the real tub. "
                       "Preview only — it feeds no calculation.")
            if _pending and st.button(
                    f"🧩 Assemble library on the 3D model "
                    f"({len(_pending)} file(s) to place)",
                    key="cad_lib_assemble_all"):
                _oks, _fails = 0, []
                for _pf in _pending:
                    _okp, _msgp = _lib_inject_cad(_pf)
                    if _okp:
                        _oks += 1
                    else:
                        _fails.append(_msgp)
                if _oks:
                    st.success(f"Placed {_oks} part(s) on the 3D model — open "
                               "the 3D Model tab to see the assembly.")
                for _fm in _fails:
                    st.warning(_fm)
                if _oks:
                    _do_rerun()
            _subs = ["(all)"] + _store_cad_subsystems(_cad_store)
            _filt = st.selectbox("Filter by subsystem", _subs, key="cad_lib_filter")
            _shown = (_all_files if _filt == "(all)"
                      else _store_cad_files(_cad_store, _filt))
            st.caption(f"{len(_shown)} of {len(_all_files)} file(s)")
            for _cf in _shown:
                _row = st.columns([2.8, 1.2, 1.1, 1.0, 1.1, 0.8])
                _meta = f"`{_cf.subsystem}`"
                if _cf.uploader:
                    _meta += f" · {_cf.uploader}"
                if _cf.note:
                    _meta += f" · _{_cf.note}_"
                _row[0].markdown(f"**{_cf.name}**  \n{_meta}")
                _row[1].caption(_cf.ts.replace("T", " "))
                if _cf.kind == "link":
                    _row[2].markdown(f"[open link]({_cf.link})")
                else:
                    _row[2].caption(cadshare_mod.human_size(_cf.size_bytes))
                    try:
                        _row[3].download_button(
                            "Download", data=_b64.b64decode(_cf.data_b64),
                            file_name=_cf.name, key=f"cad_dl_{_cf.id}")
                    except Exception:
                        _row[3].caption("—")
                # Library ⇄ 3D bridge controls for this file.
                if _cf.id in _injected:
                    if _row[4].button("On car ✓ (remove)",
                                      key=f"cad_3d_off_{_cf.id}",
                                      help="Take this part off the 3D model — "
                                           "its dummy placeholder returns."):
                        _lib_eject_cad(_cf.id)
                        _do_rerun()
                elif _lib_parseable(_cf):
                    if _row[4].button("→ 3D model", key=f"cad_3d_on_{_cf.id}",
                                      help="Snap this part into its slot on "
                                           "the full-car 3D model."):
                        _ok1, _msg1 = _lib_inject_cad(_cf)
                        (st.success if _ok1 else st.warning)(_msg1)
                        if _ok1:
                            _do_rerun()
                elif _lib_is_sld(_cf):
                    _row[4].caption("SLDPRT/SLDASM — export STEP "
                                    "(File ▸ Save As) for the real shape")
                elif _cf.kind != "link":
                    _row[4].caption("STEP to view in 3D")
                if _row[5].button("Remove", key=f"cad_rm_{_cf.id}"):
                    _lib_eject_cad(_cf.id)
                    _cad_store.remove_cad_file(_cf.id)
                    save_store(_cad_store)
                    _do_rerun()

    # ----------------------------------------------------------------- #
    #  1b · Fit forecast — will this CAD assemble, before anyone opens
    #       SolidWorks? The fast alternative to the 3D preview: pick a
    #       library file and get (a) a 0–100 "assembles-as-is" realism
    #       score with the deductions itemised, (b) the concrete messages
    #       SolidWorks will produce (Interference Detection hits, surface-
    #       body imports, mirrored parts, clearance flags) predicted from
    #       the mesh + this car's live slot envelopes — the car is
    #       assembled headlessly in the background on every run, so the
    #       checks never depend on the 3D tab having been opened — and (c) a
    #       performance overview under a chosen load case — mass, whole-car
    #       CG shift, per-mount fastener utilisation, lap-time feel, and a
    #       subsystem capacity proxy. Mesh-level forecast, not a mate
    #       solver: provenance is printed on every number.
    # ----------------------------------------------------------------- #
    with st.expander("🔮 Fit forecast — will this CAD assemble in SolidWorks?",
                     expanded=False):
        st.markdown(
            '<p class="hint" style="margin:0 0 6px;">The quick <b>what-if</b> '
            'for a library part: instead of eyeballing the 3D preview, this '
            'reads the geometry itself, assembles the whole car in the '
            'background, and predicts what the SolidWorks '
            'master assembly will say — fit realism, interference against '
            'every body on the car, mirrored-'
            'part risk — plus how it will behave under a design load case. '
            'Millimetre-level mesh forecast in milliseconds; the real mate '
            'solve and FEA stay the sign-off.</p>', unsafe_allow_html=True)

        _fc_files = [f for f in _store_cad_files(_cad_store, None)
                     if _lib_parseable(f)]
        if not _fc_files:
            st.info("No meshable CAD in the library yet — publish a STEP / "
                    "STL / OBJ / GLB above and the forecast runs on it here.")
        else:
            _fc_by = {f"{f.name}  ·  {f.subsystem}": f for f in _fc_files}
            _fc_c = st.columns([2.6, 1.6, 1.5, 1.0])
            _fc_pick = _fc_c[0].selectbox("Library file", list(_fc_by.keys()),
                                          key="fitfc_file")
            _fc_mat = _fc_c[1].selectbox(
                "Material (mass)", list(fitfc_mod.MATERIAL_DENSITY.keys()),
                index=1, key="fitfc_mat")
            _fc_case = _fc_c[2].selectbox(
                "Load case", list(fitfc_mod.LOAD_CASES.keys()), key="fitfc_case")
            _fc_nm = int(_fc_c[3].number_input("Mounts", 1, 16, 4, 1,
                                               key="fitfc_mounts"))
            _fc_run = st.button("Run fit forecast", type="primary",
                                key="fitfc_run")

            if _fc_run:
                _cfp = _fc_by[_fc_pick]
                try:
                    # mesh payload — session cache so re-running with a new
                    # load case / material doesn't re-tessellate the STEP.
                    _mc = st.session_state.setdefault("fitfc_mesh_cache", {})
                    _pay = _mc.get(_cfp.id)
                    if _pay is None:
                        import tempfile as _tf, os as _os
                        _sfx = "." + _cfp.name.rsplit(".", 1)[-1].lower()
                        with _tf.NamedTemporaryFile(delete=False,
                                                    suffix=_sfx) as _f:
                            _f.write(_b64.b64decode(_cfp.data_b64))
                            _pth = _f.name
                        try:
                            with st.spinner("Reading the geometry…"):
                                _pay = chassis_mod.load_part_mesh(
                                    _pth, max_faces=6000)
                        finally:
                            try:
                                _os.unlink(_pth)
                            except Exception:
                                pass
                        if len(_mc) >= 4:          # cap the RAM this holds
                            _mc.pop(next(iter(_mc)))
                        _mc[_cfp.id] = _pay

                    # this car's slot for the part + neighbours. The car is
                    # assembled HEADLESSLY right here (same builder as the 3D
                    # view, figure discarded, boxes kept), so the forecast
                    # always reasons on fresh, accurate geometry — no visit
                    # to the 3D tab required. Per-instance boxes are strongly
                    # preferred: they give one box per COPY of a body (each
                    # tire separately) and let a plate-like dummy (the 8 mm
                    # radiator core) resolve to its CONTAINER's interior — the
                    # space a real part must actually fit. Merged boxes are
                    # the fallback; a failed background build falls back to
                    # the caches from any prior render rather than silently
                    # dropping the clearance checks.
                    _slot = _lib_slot_for(_cfp)
                    _ctr, _env, _ssub, _dummy = _cad_slot_target(_slot)
                    with st.spinner("Assembling the car in the background…"):
                        try:
                            _inst, _mrg = _fitfc_car_boxes()
                        except Exception:
                            _inst, _mrg = {}, {}
                    if not _inst:
                        _inst = dict(st.session_state
                                     .get("car3d_part_instances") or {})
                    if not _mrg:
                        _mrg = dict(st.session_state
                                    .get("car3d_part_boxes") or {})
                    _rslot = fitfc_mod.resolve_slot(
                        _dummy, _inst, fallback_env=_env, fallback_centre=_ctr)
                    _env2, _ctr2 = _rslot["env"], _rslot["centre"]
                    _nbx = _inst or _mrg
                    _skip = {_dummy or "", _rslot.get("container") or "",
                             _cfp.name.rsplit(".", 1)[0],
                             _cfp.name.rsplit(".", 1)[0] + " (awaiting CAD)"}
                    _base_kg = 220.0
                    try:
                        _base_kg = float(interfaces_mod.IntegrationLedger
                                         .from_dict(st.session_state.ledger)
                                         .mass_rollup().get("total_kg", 0)
                                         or 220.0)
                    except Exception:
                        pass
                    st.session_state["fitfc_result"] = dict(
                        file=_cfp.name, slot=_slot, had_nbx=bool(_nbx),
                        container=_rslot.get("container"),
                        res=fitfc_mod.full_forecast(
                            _pay, _env2, _ctr2, _nbx, exclude=tuple(_skip),
                            material=_fc_mat, load_case=_fc_case,
                            n_mounts=_fc_nm, base_mass_kg=_base_kg,
                            subsys=_ssub))
                except Exception as _fe:
                    st.session_state.pop("fitfc_result", None)
                    st.error(f"Couldn't forecast {_cfp.name} ({_fe}). STEP is "
                             "the most reliable SolidWorks export.")

            _fr = st.session_state.get("fitfc_result")
            if _fr and _fr.get("file") == _fc_pick.split("  ·  ")[0]:
                _R = _fr["res"]
                _rs, _fit, _msh = _R["realism"], _R["fit"], _R["mesh"]
                _pf = _R["performance"]
                _scol = ("#5ad17a" if _rs["score"] >= 85 else
                         "#ffd166" if _rs["score"] >= 65 else "#ff5a52")
                st.markdown(
                    f'<div style="border:1px solid var(--line);border-left:5px '
                    f'solid {_scol};border-radius:12px;padding:10px 14px;'
                    f'margin:6px 0;"><span style="font-family:JetBrains Mono;'
                    f'font-size:1.6rem;font-weight:600;color:{_scol};">'
                    f'{_rs["score"]:.0f}<span style="font-size:.9rem;"> / 100'
                    f'</span></span> &nbsp;<b>{_rs["grade"]}</b>'
                    f'<span class="hint"> — {_fr["slot"]} slot, placed size '
                    f'{_fit["placed_mm"][0]:.0f}×{_fit["placed_mm"][1]:.0f}×'
                    f'{_fit["placed_mm"][2]:.0f} mm in a '
                    f'{_fit["slot_mm"][0]:.0f}×{_fit["slot_mm"][1]:.0f}×'
                    f'{_fit["slot_mm"][2]:.0f} mm space '
                    f'({_fit["fill"]*100:.0f}% fill, best orientation)</span>'
                    '</div>', unsafe_allow_html=True)
                if _rs["deductions"]:
                    st.markdown('<p class="hint" style="margin:2px 0;">' +
                                " &nbsp;·&nbsp; ".join(
                                    f"−{p} {r}" for p, r in _rs["deductions"])
                                + '</p>', unsafe_allow_html=True)

                st.markdown("**What SolidWorks will say:**")
                for _m in _R["solidworks"]:
                    _mc2 = {"stop": "#ff5a52", "warn": "#ffd166",
                            "ok": "#5ad17a"}[_m["severity"]]
                    _ic = {"stop": "⛔", "warn": "⚠️", "ok": "✅"}[_m["severity"]]
                    st.markdown(
                        f'<div style="border:1px solid var(--line);'
                        f'border-left:4px solid {_mc2};border-radius:8px;'
                        f'padding:6px 10px;margin:3px 0;font-size:.88rem;">'
                        f'{_ic} {_m["text"]}</div>', unsafe_allow_html=True)
                if not _fr.get("had_nbx"):
                    # Should essentially never happen: the forecast assembles
                    # the car itself in the background. Only reachable if that
                    # build failed AND no prior geometry was cached.
                    st.caption("Clearance / interference checks were skipped "
                               "this run — the background car assembly failed "
                               "and no cached geometry was available. Re-run "
                               "the forecast to try again.")
                else:
                    _bits = []
                    if _fr.get("container"):
                        _bits.append(f"space taken as the {_fr['container']} "
                                     "interior (the dummy is a thin stand-in)")
                    if _fit.get("contained_in"):
                        _bits.append("nested inside "
                                     + ", ".join(_fit["contained_in"])
                                     + " — by design")
                    if _fit.get("tightest_neighbors"):
                        _bits.append("closest neighbours: " + ", ".join(
                            f"{n} ({g:.0f} mm)" for n, g in
                            _fit["tightest_neighbors"][:4]))
                    if _bits:
                        st.caption("  ·  ".join(_bits) + ".")

                st.markdown(f"**Under {_pf['load_case']}:**")
                _pm = st.columns(4)
                _pm[0].metric("Part mass", f"{_pf['mass_kg']:.2f} kg",
                              help=_pf["mass_note"])
                _dc = _pf["cg_shift_mm"]
                _pm[1].metric("Car CG shift",
                              f"{_dc[0]:+.1f}/{_dc[1]:+.1f}/{_dc[2]:+.1f} mm",
                              help="x/y/z shift of the whole-car CG when this "
                                   "mass lands at its slot centre.")
                _pm[2].metric("Per-mount load",
                              f"{_pf['per_mount_n']:.0f} N",
                              help=f"{_pf['inertial_force_n']:.0f} N inertial "
                                   f"over {_pf['n_mounts']} mounts.")
                _pm[3].metric("Lap-time feel", f"+{_pf['lap_delta_s']:.2f} s",
                              help=_pf["lap_note"])
                _ut = float(_pf["fastener_util"])
                st.progress(min(1.0, _ut),
                            text=f"Fastener utilisation {_ut*100:.0f}% — "
                                 + _pf["fastener_note"]
                                 + ("  ·  OVER — add mounts or step up the "
                                    "bolt" if _ut > 1.0 else ""))
                if _pf.get("capacity_proxy"):
                    _cx = _pf["capacity_proxy"]
                    st.caption(f"**{_cx['label']}:** {_cx['value']} — "
                               f"{_cx['note']}.")

    # ----------------------------------------------------------------- #
    #  2 · SES location pack
    # ----------------------------------------------------------------- #
    with st.expander("📸 SES location pack — HV & LV positions, ortho views, "
                     "coordinate table", expanded=False):
        st.caption("SES wants CAD pictures of where components sit — HV "
                   "accumulator and LV battery most of all. Enter their box "
                   "centres; every part already placed on the 3D model is "
                   "included automatically. Download each view as PNG (camera "
                   "icon) and the coordinate table as CSV.")

        _hvc = st.columns(3)
        _hv_x = _hvc[0].number_input("HV accumulator x (mm)", value=-150.0,
                                     step=5.0, key="ses_hv_x")
        _hv_y = _hvc[1].number_input("HV accumulator y (mm)", value=0.0,
                                     step=5.0, key="ses_hv_y")
        _hv_z = _hvc[2].number_input("HV accumulator z (mm)", value=180.0,
                                     step=5.0, key="ses_hv_z")
        _lvc = st.columns(3)
        _lv_x = _lvc[0].number_input("LV battery x (mm)", value=200.0,
                                     step=5.0, key="ses_lv_x")
        _lv_y = _lvc[1].number_input("LV battery y (mm)", value=150.0,
                                     step=5.0, key="ses_lv_y")
        _lv_z = _lvc[2].number_input("LV battery z (mm)", value=120.0,
                                     step=5.0, key="ses_lv_z")

        # Parts already placed on the shared 3D model (subsystem centroids).
        _placed = {}
        try:
            _hp_cur = st.session_state.get("hp", {}) or {}
            _vp_fields_s = set(VehicleParams.__dataclass_fields__.keys())
            _vp_kwargs_s = {k: v for k, v in st.session_state.vp.items()
                            if k in _vp_fields_s}
            _vp_s = VehicleParams(**_vp_kwargs_s)
            _led_s = interfaces_mod.IntegrationLedger.from_dict(st.session_state.ledger)
            _figS = fullcar_mod.build_full_car_figure(vp=_vp_s, ledger=_led_s)
            if hasattr(fullcar_mod, "subsys_centroids"):
                _placed = fullcar_mod.subsys_centroids(_figS) or {}
        except Exception:
            _placed = {}

        _rows = cadshare_mod.ses_location_rows(
            hv=(_hv_x, _hv_y, _hv_z), lv=(_lv_x, _lv_y, _lv_z), placed=_placed)

        # Apply any coordinate overrides the user edited in the table below.
        # Done here — before the plots — so everything stays in sync.
        _ses_ov_pre = st.session_state.get("ses_overrides", {})
        if _ses_ov_pre and _rows:
            class _OvRow:
                __slots__ = ("name", "category", "x_mm", "y_mm", "z_mm")
                def __init__(self, _r, _ov):
                    self.name     = _r.name
                    self.category = _r.category
                    self.x_mm     = float(_ov.get("x_mm", _r.x_mm))
                    self.y_mm     = float(_ov.get("y_mm", _r.y_mm))
                    self.z_mm     = float(_ov.get("z_mm", _r.z_mm))
            _rows = [_OvRow(_r, _ses_ov_pre.get(_r.name, {})) for _r in _rows]

        if not _rows:
            st.info("Enter HV/LV positions above to build the pack.")
        else:
            # Three dimensioned orthographic views: side (x-z), top (x-y),
            # front (y-z). Each is its own plotly figure with a camera icon
            # (Streamlit's built-in download-as-PNG on the modebar).
            import math as _math

            _CAT_COLORS = {"HV": "#ff4b4b", "LV": "#f5a623"}
            _OTHER_COLOR = "#4cc9f0"

            def _label_offset(_hx, _vy, _cx, _cy, _is_key):
                """Return (dx, dy, textanchor_x, textanchor_y) for a label
                placed radially outward from the point-cloud centroid.
                Key components get a longer leader line."""
                _dx = _hx - _cx
                _dy = _vy - _cy
                _dist = _math.hypot(_dx, _dy) or 1.0
                _reach = 90 if _is_key else 65
                _nx = _dx / _dist
                _ny = _dy / _dist
                # Anchor text on the far side of the leader tip
                _ax = "left" if _nx >= 0 else "right"
                _ay = "top" if _ny <= 0 else "bottom"
                return _nx * _reach, _ny * _reach, _ax, _ay

            def _ortho(_ax_h, _ax_v, _h_lab, _v_lab, _title):
                _fig = go.Figure()

                # Sort so HV/LV render on top (added last)
                _sorted_rows = sorted(
                    _rows,
                    key=lambda _r: 0 if _r.category not in ("HV", "LV") else 1)

                # Point-cloud centroid for outward label placement
                _xs = [getattr(_r, _ax_h) for _r in _sorted_rows]
                _ys = [getattr(_r, _ax_v) for _r in _sorted_rows]
                _cx = sum(_xs) / len(_xs) if _xs else 0.0
                _cy = sum(_ys) / len(_ys) if _ys else 0.0

                # --- grouped marker traces (one per category, for a clean legend) ---
                _groups = {}
                for _r in _sorted_rows:
                    _groups.setdefault(_r.category, []).append(_r)

                _cat_order = sorted(
                    _groups.keys(),
                    key=lambda c: 0 if c == "HV" else 1 if c == "LV" else 2)

                _cat_labels = {"HV": "HV accumulator", "LV": "LV battery"}

                for _cat in _cat_order:
                    _grp = _groups[_cat]
                    _is_key = _cat in ("HV", "LV")
                    _col = _CAT_COLORS.get(_cat, _OTHER_COLOR)
                    _sz = 18 if _is_key else 10
                    _gxs = [getattr(_r, _ax_h) for _r in _grp]
                    _gys = [getattr(_r, _ax_v) for _r in _grp]
                    _htexts = [
                        (f"<b>{_r.name}</b><br>"
                         f"x = {_r.x_mm:.0f} mm<br>"
                         f"y = {_r.y_mm:.0f} mm<br>"
                         f"z = {_r.z_mm:.0f} mm")
                        for _r in _grp]
                    _fig.add_trace(go.Scatter(
                        x=_gxs, y=_gys,
                        mode="markers",
                        marker=dict(
                            size=_sz, color=_col,
                            line=dict(width=1.5 if _is_key else 1.0,
                                      color="rgba(255,255,255,0.35)"),
                            symbol="circle",
                            opacity=1.0 if _is_key else 0.85,
                        ),
                        name=_cat_labels.get(_cat, "other subsystems"),
                        legendgroup=_cat,
                        hovertemplate="%{customdata}<extra></extra>",
                        customdata=_htexts,
                        showlegend=True,
                    ))

                # --- leader lines + floating labels (annotations) ---
                for _r in _sorted_rows:
                    _hx = getattr(_r, _ax_h)
                    _vy = getattr(_r, _ax_v)
                    _is_key = _r.category in ("HV", "LV")
                    _col = _CAT_COLORS.get(_r.category, _OTHER_COLOR)
                    _dx, _dy, _tax, _tay = _label_offset(_hx, _vy, _cx, _cy, _is_key)
                    _fig.add_annotation(
                        x=_hx, y=_vy,
                        ax=_hx + _dx, ay=_vy + _dy,
                        axref="x", ayref="y",
                        xref="x", yref="y",
                        text=f"<b>{_r.name}</b>" if _is_key else _r.name,
                        showarrow=True,
                        arrowhead=0,
                        arrowwidth=1.0 if _is_key else 0.7,
                        arrowcolor=_col if _is_key else "rgba(180,210,230,0.45)",
                        font=dict(
                            size=11 if _is_key else 9.5,
                            color="#ffffff" if _is_key else "#b0c8dc",
                            family="monospace" if _is_key else "sans-serif",
                        ),
                        align="left",
                        xanchor=_tax,
                        yanchor=_tay,
                        bgcolor="rgba(18,22,32,0.72)" if _is_key else "rgba(18,22,32,0.55)",
                        borderpad=3,
                    )

                # Zero-reference crosshairs
                _fig.add_hline(y=0, line_width=1,
                               line_dash="dot", line_color="rgba(255,255,255,0.18)")
                _fig.add_vline(x=0, line_width=1,
                               line_dash="dot", line_color="rgba(255,255,255,0.18)")

                _fig.update_layout(
                    title=dict(text=_title,
                               font=dict(size=13, color="#e0e8f0", family="monospace"),
                               x=0.5, xanchor="center"),
                    height=440,
                    legend=dict(
                        orientation="h",
                        yanchor="bottom", y=1.02,
                        xanchor="left", x=0,
                        font=dict(size=10, color="#c8d8e8"),
                        bgcolor="rgba(0,0,0,0)",
                        itemsizing="constant",
                    ),
                    xaxis=dict(
                        title=dict(text=_h_lab,
                                   font=dict(size=11, color="#7a9bb8")),
                        gridcolor="rgba(255,255,255,0.06)",
                        zerolinecolor="rgba(255,255,255,0.22)",
                        tickfont=dict(size=9, color="#6a8ba8"),
                        tickformat=".0f",
                    ),
                    yaxis=dict(
                        title=dict(text=_v_lab,
                                   font=dict(size=11, color="#7a9bb8")),
                        scaleanchor="x", scaleratio=1,
                        gridcolor="rgba(255,255,255,0.06)",
                        zerolinecolor="rgba(255,255,255,0.22)",
                        tickfont=dict(size=9, color="#6a8ba8"),
                        tickformat=".0f",
                    ),
                    margin=dict(l=14, r=14, t=56, b=14),
                    template="plotly_dark",
                    paper_bgcolor="rgba(14,17,24,1)",
                    plot_bgcolor="rgba(20,24,34,1)",
                    hoverlabel=dict(
                        bgcolor="#1a1f2e",
                        font_size=12,
                        font_family="monospace",
                        bordercolor="rgba(255,255,255,0.18)"),
                )
                return _fig

            _v1, _v2, _v3 = st.columns(3)
            with _v1:
                st.plotly_chart(_ortho("x_mm", "z_mm", "x — rear (mm)",
                                       "z — up (mm)", "Side view (x–z)"),
                                use_container_width=True, key="ses_side")
            with _v2:
                st.plotly_chart(_ortho("x_mm", "y_mm", "x — rear (mm)",
                                       "y — right (mm)", "Top view (x–y)"),
                                use_container_width=True, key="ses_top")
            with _v3:
                st.plotly_chart(_ortho("y_mm", "z_mm", "y — right (mm)",
                                       "z — up (mm)", "Front view (y–z)"),
                                use_container_width=True, key="ses_front")

            st.caption("Use each plot's camera icon to save the view as PNG. "
                       "Hover any dot for exact coordinates.")

            # --- editable coordinate table -----------------------------------
            # Edits to x/y/z are stored in session_state["ses_overrides"]
            # (dict: component name -> {x_mm, y_mm, z_mm}) and are applied
            # to _rows BEFORE the plots render (see the override block above),
            # so plots, CSV, and this table are always in sync.
            import pandas as _pd_ses

            _overrides = st.session_state.setdefault("ses_overrides", {})

            # _rows already has overrides baked in — just show current values.
            _tbl_df = _pd_ses.DataFrame([
                {"component": _r.name, "category": _r.category,
                 "x_mm": round(_r.x_mm, 1),
                 "y_mm": round(_r.y_mm, 1),
                 "z_mm": round(_r.z_mm, 1)}
                for _r in _rows])

            st.caption("Edit any x / y / z cell — changes update the plots "
                       "and CSV on the next interaction.")

            _edited_tbl = st.data_editor(
                _tbl_df,
                hide_index=True,
                use_container_width=True,
                key="ses_coord_editor",
                column_config={
                    "component": st.column_config.TextColumn(
                        "component", disabled=True),
                    "category": st.column_config.TextColumn(
                        "category", disabled=True),
                    "x_mm": st.column_config.NumberColumn(
                        "x_mm (rear +)", format="%.1f", step=1.0),
                    "y_mm": st.column_config.NumberColumn(
                        "y_mm (right +)", format="%.1f", step=1.0),
                    "z_mm": st.column_config.NumberColumn(
                        "z_mm (up +)", format="%.1f", step=1.0),
                },
            )

            # Persist edits into session_state so the next rerun picks them up
            for _, _erow in _edited_tbl.iterrows():
                _overrides[_erow["component"]] = {
                    "x_mm": float(_erow["x_mm"]),
                    "y_mm": float(_erow["y_mm"]),
                    "z_mm": float(_erow["z_mm"]),
                }
            st.session_state["ses_overrides"] = _overrides

            _ses_csv = cadshare_mod.ses_location_csv(_rows)

            _rc = st.columns([1, 1, 1])
            if _rc[0].button("↺ Reset coordinate edits", key="ses_reset_edits"):
                st.session_state["ses_overrides"] = {}
                _do_rerun()

            _sc = st.columns(2)
            _sc[0].download_button("Download coordinate table (CSV)",
                                   data=_ses_csv, file_name="ses_locations.csv",
                                   key="ses_csv_dl")
            if _sc[1].button("Publish CSV to library (tagged SES)",
                             key="ses_csv_pub"):
                _cad_store.add_cad_file(project_mod.CADFile(
                    name="ses_locations.csv", subsystem="SES",
                    uploader="", kind="file",
                    data_b64=_b64.b64encode(_ses_csv.encode()).decode("ascii"),
                    size_bytes=len(_ses_csv), note="component location table"))
                save_store(_cad_store)
                st.success("Published to the CAD library under SES.")
                _do_rerun()

            st.caption("Tip: screenshots you upload to the library can be "
                       "SES-tagged too, so the whole pack collects in one place.")

    # ----------------------------------------------------------------- #
    #  3 · Suspension → Ansys export
    # ----------------------------------------------------------------- #
    with st.expander("🧮 Suspension → Ansys export — hardpoints CSV + BEAM188 "
                     "APDL torsion deck", expanded=False):
        st.caption("Live hardpoints CSV plus a generated APDL .inp deck "
                   "(BEAM188 line bodies, tube section & material from the "
                   "Compliance tab, frame tubes auto-included if a Frame "
                   "Planner frame is loaded).")

        _hp_now = st.session_state.get("hp", {}) or {}
        if not _hp_now:
            st.info("No hardpoints in the session yet — set geometry on the "
                    "suspension tabs first.")
        else:
            # Section + material from the Compliance tab (fallback to the FSAE
            # default 3/4\" 4130, 0.9 mm if that tab hasn't been visited).
            _mat_name = st.session_state.get("comp_mat", "Steel 4130")
            _od_mm = float(st.session_state.get("comp_od", 19.05))
            _wall_mm = float(st.session_state.get("comp_wall", 0.9))
            _mat = MATERIALS.get(_mat_name)
            _E_pa = (float(_mat.E) * 1e6) if _mat else 205e9   # MPa -> Pa
            _rho = float(getattr(_mat, "rho", 7850.0)) if _mat else 7850.0

            _section = cadshare_mod.BeamSection(od_m=_od_mm * 1e-3,
                                                wall_m=_wall_mm * 1e-3)
            _material = cadshare_mod.BeamMaterial(
                name=_mat_name, E_pa=_E_pa, rho_kg_m3=_rho)

            # Frame Planner frame, if one is loaded (shared session state).
            _frame_obj = None
            _fd = st.session_state.get("tf_frame")
            if _fd:
                try:
                    _frame_obj = tf_mod.FrameGraph.from_dict(_fd)
                except Exception:
                    _frame_obj = None

            _counts = cadshare_mod.apdl_counts(_hp_now, frame=_frame_obj)
            _msg = (f"Section: {_mat_name}, OD {_od_mm:g} mm × {_wall_mm:g} mm "
                    f"wall. Will generate **{_counts['links']} suspension links**")
            if _counts["frame_tubes"]:
                _msg += f" + **{_counts['frame_tubes']} frame tubes**"
            else:
                _msg += " (no frame loaded — load one in Frame Planner to include it)"
            _msg += f", {_counts['keypoints']} keypoints."
            st.markdown(_msg)

            _hp_csv = cadshare_mod.hardpoints_csv(_hp_now)
            try:
                _deck = cadshare_mod.build_apdl_deck(
                    _hp_now, _section, _material, frame=_frame_obj,
                    title=f"KinematiK torsional stiffness — {_cad_store.team_name}")
            except Exception as _ae:
                _deck = None
                st.error(f"Couldn't build the APDL deck: {_ae}")

            _ec = st.columns(2)
            _ec[0].download_button("Download hardpoints CSV", data=_hp_csv,
                                   file_name="hardpoints.csv", key="ans_hp_dl")
            if _deck is not None:
                _ec[1].download_button("Download APDL deck (.inp)", data=_deck,
                                       file_name="torsional_stiffness.inp",
                                       key="ans_inp_dl")

            _pc = st.columns(2)
            if _pc[0].button("Publish hardpoints CSV to library (suspension)",
                             key="ans_hp_pub"):
                _cad_store.add_cad_file(project_mod.CADFile(
                    name="hardpoints.csv", subsystem="suspension", kind="file",
                    data_b64=_b64.b64encode(_hp_csv.encode()).decode("ascii"),
                    size_bytes=len(_hp_csv), note="live hardpoints export"))
                save_store(_cad_store)
                st.success("Published hardpoints.csv under suspension.")
                _do_rerun()
            if _deck is not None and _pc[1].button(
                    "Publish APDL deck to library (suspension)", key="ans_inp_pub"):
                _cad_store.add_cad_file(project_mod.CADFile(
                    name="torsional_stiffness.inp", subsystem="suspension",
                    kind="file",
                    data_b64=_b64.b64encode(_deck.encode()).decode("ascii"),
                    size_bytes=len(_deck), note="BEAM188 torsion deck"))
                save_store(_cad_store)
                st.success("Published torsional_stiffness.inp under suspension.")
                _do_rerun()

            if _deck is not None:
                with st.expander("Preview the APDL deck", expanded=False):
                    st.code(_deck, language="text")

            st.markdown("**Suspension CAD feed** (library, filtered to suspension):")
            _susp_files = _store_cad_files(_cad_store, "suspension")
            if not _susp_files:
                st.caption("No suspension CAD shared yet — publish the CSV/deck "
                           "above, or drop a wishbone STEP in the Team CAD library.")
            else:
                for _sf in _susp_files:
                    _sr = st.columns([3.5, 1.4, 1.1])
                    _sr[0].markdown(f"**{_sf.name}**"
                                    + (f" · _{_sf.note}_" if _sf.note else ""))
                    if _sf.kind == "link":
                        _sr[1].markdown(f"[open link]({_sf.link})")
                    else:
                        _sr[1].caption(cadshare_mod.human_size(_sf.size_bytes))
                        try:
                            _sr[2].download_button(
                                "Download", data=_b64.b64decode(_sf.data_b64),
                                file_name=_sf.name, key=f"ans_feed_dl_{_sf.id}")
                        except Exception:
                            _sr[2].caption("—")


# =========================================================================== #
#  AERODYNAMICS  —  surfaces the in-house aero stack as a frictionless tool.   #
# =========================================================================== #
# FSAE aero subteams (USC's included) design front/rear wings, a diffuser and the
# floor to trade drag for downforce, and study ground effect + balance. KinematiK
# already ships a real aero stack (analytic surrogate, 3D source-panel potential
# flow, virtual wind tunnel, pressure-tap correlation); this tab puts the runnable
# parts in front of the user with no solver, no mesh, no license — three views:
#   1) Downforce & ground effect — force vs speed and vs ride height, live.
#   2) Wing & diffuser sizing — size elements to a downforce target, see drag cost.
#   3) Aero map — the attitude sweep (ride height × yaw) that feeds the lap sim.
# Coefficients come from suspension.aero.ReferenceAeroModel; forces use the same
# F = ½·ρ·(−C_L·A)·V² convention as the lap-sim aero coupling, so numbers here and
# in LAP TIME agree. Provenance is shouted: this is a trend/plumbing surrogate, not
# a Navier–Stokes result — the panel method + Fluent deck are the correlation path.
with tab_aero:
  try:
    render_process_library("aero", key_prefix="aero_pl")
  except Exception:
    pass

  try:
    _subsystem_cad_import("aerodynamics", key_prefix="aero")
    _RHO = 1.225  # kg/m³, sea-level ISA — same default as the aero coupling
    st.markdown(
        '<p class="hint" style="margin:0 0 6px;">Trade <b>drag for downforce</b> and '
        'see it on the car. Downforce grows with speed² and as the floor nears the '
        'ground (ground effect); every count of downforce costs drag. These are live '
        'analytic trends — instant, no solver — meant for direction and sizing. The '
        'panel-method solve on your STL and the Fluent verification deck (already in '
        'KinematiK) are the correlation path for absolute numbers.</p>',
        unsafe_allow_html=True)

    # Reference area: prefer the vehicle's declared frontal area, else an FSAE-typical
    # 1.0 m². This is the area C_L/C_D are normalised to, so forces scale with it.
    _aero_area = float(st.session_state.vp.get("frontal_area_m2", 0.0) or 0.0)
    _ac = st.columns([1, 1, 1, 1])
    _aero_area = _ac[0].number_input(
        "Reference area A (m²)", 0.5, 2.0,
        value=(_aero_area if _aero_area > 0 else 1.0), step=0.05,
        help="Planform/frontal area the coefficients are referenced to. FSAE cars "
             "are ~1.0 m². Forces scale linearly with this.")
    _aero_v = _ac[1].number_input(
        f"Speed ({units_mod.label('km/h')})", 10.0, 140.0, value=60.0, step=5.0,
        help="A typical FSAE corner is 40–70 km/h; the endurance straight ~100+.")
    _aero_v_ms = _aero_v / 3.6
    _aero_ride = _ac[2].number_input(
        f"Ride height ({units_mod.label('mm')})", 10.0, 70.0, value=30.0, step=2.5,
        help="Front floor clearance. Lower = more ground effect, to a floor.")
    _aero_yaw = _ac[3].number_input(
        "Yaw / sideslip (°)", 0.0, 12.0, value=0.0, step=1.0,
        help="In a corner the car runs a few degrees of sideslip; downforce is "
             "lost and drag gained with yaw.")

    _aero_model = _AeroRefModel()

    def _aero_forces(ride_mm, yaw_deg, v_ms, area):
        """(downforce_N, drag_N, c_lift, c_drag, front_balance) at an attitude."""
        cl, cd, cs, fb = _aero_model._coeffs(
            _AeroAttitude(ride_height_mm=ride_mm, yaw_deg=yaw_deg, speed_ms=v_ms))
        q = 0.5 * _RHO * v_ms * v_ms
        downforce = q * (-cl * area)   # -C_L*A is positive for downforce
        drag = q * (cd * area)
        return downforce, drag, cl, cd, fb

    _view = feature_menu("aerodynamics",
        ["Downforce & ground effect", "Wing & diffuser sizing",
         "Aero map (attitude sweep)", "Scale model planning",
         "Plug & layup build planner", "Mounting & bonding designer"],
        title="Aerodynamics tools",
        descriptions={
            "Downforce & ground effect": "Downforce, drag, L/D at attitude",
            "Wing & diffuser sizing": "Element sizing & diffuser geometry",
            "Aero map (attitude sweep)": "Ride/yaw attitude sweep map",
            "Scale model planning": "Wind-tunnel scale + full-size chord (DXF source)",
            "Plug & layup build planner":
                "Foam slice templates + BOM + cure-aware build-day schedule",
            "Mounting & bonding designer":
                "Where & how to attach aero to the car — loads, brackets, bonds"})

    # Live headline numbers at the chosen attitude — shared across the tools.
    # Only rendered once a tool is picked, so the menu stays clean.
    if _view:
      _df, _dr, _cl, _cd, _fb = _aero_forces(_aero_ride, _aero_yaw, _aero_v_ms, _aero_area)
      _ld = (_df / _dr) if _dr else 0.0
      mcol = st.columns(4)
      umetric(mcol[0], "Downforce", _df, "N", help="≈ %.0f kgf of grip-adding load" % (_df/9.81))
      umetric(mcol[1], "Drag", _dr, "N")
      mcol[2].metric("Efficiency L/D", f"{_ld:.2f}", help="Downforce per unit drag — higher is better.")
      mcol[3].metric("Aero balance", f"{_fb*100:.0f}% front",
                     help="Share of downforce on the front axle. ~45% front is a typical FSAE target.")

      try:
        record_activity(
            "aerodynamics", "condition",
            f"Evaluated at {units_mod.from_metric(_aero_v_ms*3.6,'km/h'):.0f} "
            f"km/h, ride {_aero_ride:g}, yaw {_aero_yaw:g}°")
        record_activity(
            "aerodynamics", "calculation",
            f"Aero: downforce {_df:.0f} N, drag {_dr:.0f} N, L/D {_ld:.2f}, "
            f"balance {_fb*100:.0f}% front (Cl {_cl:.2f}, Cd {_cd:.2f})")
      except Exception:
        pass

    # ---------------------------------------------------------------- VIEW 1 #
    if _view == "Downforce & ground effect":
        gcol = st.columns(2)
        _uSpd = units_mod.label("km/h")
        _uF = units_mod.label("N")
        _uLn = units_mod.label("mm")
        # (a) force vs speed
        _vs = np.linspace(20, 120, 40)  # km/h
        _dfs, _drs = [], []
        for v in _vs:
            d, r, *_ = _aero_forces(_aero_ride, _aero_yaw, v / 3.6, _aero_area)
            _dfs.append(d); _drs.append(r)
        _vs_u = [units_mod.from_metric(v, "km/h") for v in _vs]
        f1 = go.Figure()
        f1.add_trace(go.Scatter(x=_vs_u,
                                y=[units_mod.from_metric(v, "N") for v in _dfs],
                                name=f"Downforce ({_uF})",
                                line=dict(color="#37e0d0", width=3)))
        f1.add_trace(go.Scatter(x=_vs_u,
                                y=[units_mod.from_metric(v, "N") for v in _drs],
                                name=f"Drag ({_uF})",
                                line=dict(color="#ff9f43", width=3)))
        f1.add_vline(x=units_mod.from_metric(_aero_v, "km/h"),
                     line=dict(color="#6f7d8c", dash="dot"))
        f1.update_layout(
            title="Force vs speed (∝ V²)", xaxis_title=f"speed ({_uSpd})",
            yaxis_title=f"force ({_uF})", height=340,
            paper_bgcolor="rgba(0,0,0,0)", plot_bgcolor="rgba(0,0,0,0)",
            font=dict(color="#cdd6df", size=11), margin=dict(l=0, r=0, t=36, b=0),
            legend=dict(bgcolor="rgba(0,0,0,0)"))
        gcol[0].plotly_chart(f1, width='stretch', key="aero_fvs")
        # (b) ground effect: downforce vs ride height
        _hs = np.linspace(12, 60, 40)
        _dfh = [_aero_forces(h, _aero_yaw, _aero_v_ms, _aero_area)[0] for h in _hs]
        f2 = go.Figure()
        f2.add_trace(go.Scatter(
            x=[units_mod.from_metric(h, "mm") for h in _hs],
            y=[units_mod.from_metric(v, "N") for v in _dfh], name="Downforce",
            line=dict(color="#5ad17a", width=3),
            fill="tozeroy", fillcolor="rgba(90,209,122,0.12)"))
        f2.add_vline(x=units_mod.from_metric(_aero_ride, "mm"),
                     line=dict(color="#6f7d8c", dash="dot"))
        f2.update_layout(
            title="Ground effect: downforce vs ride height",
            xaxis_title=f"ride height ({_uLn})  ← lower = closer to ground",
            yaxis_title=f"downforce ({_uF}) @ %.0f {_uSpd}" % units_mod.from_metric(_aero_v, "km/h"),
            height=340,
            paper_bgcolor="rgba(0,0,0,0)", plot_bgcolor="rgba(0,0,0,0)",
            font=dict(color="#cdd6df", size=11), margin=dict(l=0, r=0, t=36, b=0),
            legend=dict(bgcolor="rgba(0,0,0,0)"))
        f2.update_xaxes(autorange="reversed")
        gcol[1].plotly_chart(f2, width='stretch', key="aero_ge")
        st.markdown(
            '<p class="hint">Downforce scales with the square of speed, so the aero '
            'package earns its drag mostly in the fast parts of the lap — and lowering '
            'the car strengthens the floor\u2019s ground effect until it saturates. '
            'Push the ride height down and watch the green curve climb; that\u2019s the '
            'physics the panel-method solve reproduces from your actual floor geometry, '
            'not a tuned constant.</p>', unsafe_allow_html=True)

    # ---------------------------------------------------------------- VIEW 2 #
    elif _view == "Wing & diffuser sizing":
        st.markdown(
            '<p class="hint">Size the aero package to a <b>downforce target</b> and see '
            'the drag it costs and the balance it lands. A first-order sizing: element '
            'area × its lift coefficient sets each surface\u2019s contribution; the '
            'diffuser multiplies floor load through ground effect. Use it to set the '
            'target the wing leads then design to in CFD.</p>', unsafe_allow_html=True)
        sc = st.columns(3)
        _target = sc[0].number_input(
            "Downforce target @ %.0f %s" % (
                units_mod.from_metric(_aero_v, "km/h"), units_mod.label("km/h")),
            100.0, 2000.0, value=max(300.0, round(_df, -1)),
            step=25.0)
        _split = sc[1].slider("Front/rear split (% front)", 30, 60, 45, 1,
                              help="Aero balance target. Match it to your mechanical "
                                   "balance so the car doesn't change character with speed.")
        _diff_gain = sc[2].slider("Diffuser/floor share (%)", 0, 60, 35, 5,
                                  help="Fraction of downforce from the floor + diffuser "
                                       "rather than the wings. Floor downforce is far "
                                       "cheaper in drag — FSAE-legal and efficient.")
        q = 0.5 * _RHO * _aero_v_ms * _aero_v_ms * _aero_area
        # element cl needed to hit the target, given the floor share
        _wing_force = _target * (1 - _diff_gain / 100.0)
        _floor_force = _target * (_diff_gain / 100.0)
        _cl_needed = (_target / q) if q else 0.0
        # drag model: wings ~ induced + profile (k·cl²+cd0); floor cheaper
        _cd0 = 0.9
        _wing_cl = (_wing_force / q) if q else 0.0
        _floor_cl = (_floor_force / q) if q else 0.0
        _wing_drag = q * (_cd0 * 0.4 + 0.13 * _wing_cl * _wing_cl)
        _floor_drag = q * (0.05 + 0.03 * _floor_cl * _floor_cl)
        _tot_drag = _wing_drag + _floor_drag
        _ld_sized = (_target / _tot_drag) if _tot_drag else 0.0
        rc = st.columns(4)
        rc[0].metric("Total C_L·A needed", f"{_cl_needed*_aero_area:.2f} m²"
                     if False else f"{_cl_needed:.2f}",
                     help="Effective lift coefficient at this area to hit the target.")
        umetric(rc[1], "Wings carry", _wing_force, "N", delta=f"{100-_diff_gain}%")
        umetric(rc[2], "Floor/diffuser carry", _floor_force, "N", delta=f"{_diff_gain}%")
        umetric(rc[3], "Drag cost", _tot_drag, "N", delta=f"L/D {_ld_sized:.2f}")
        # bar: front vs rear contribution
        _uF = units_mod.label("N")
        _uSpd = units_mod.label("km/h")
        fbar = go.Figure()
        fbar.add_trace(go.Bar(
            x=["Front axle", "Rear axle"],
            y=[units_mod.from_metric(_target * _split / 100.0, "N"),
               units_mod.from_metric(_target * (100 - _split) / 100.0, "N")],
            marker_color=["#37e0d0", "#ff9f43"]))
        fbar.update_layout(
            title="Downforce split to hit %0.0f %s @ %.0f %s" % (
                units_mod.from_metric(_target, "N"), _uF,
                units_mod.from_metric(_aero_v, "km/h"), _uSpd),
            yaxis_title=f"downforce ({_uF})", height=300,
            paper_bgcolor="rgba(0,0,0,0)", plot_bgcolor="rgba(0,0,0,0)",
            font=dict(color="#cdd6df", size=11), margin=dict(l=0, r=0, t=36, b=0))
        st.plotly_chart(fbar, width='stretch', key="aero_split")
        st.info("Tip: pushing the floor/diffuser share up buys downforce at a fraction "
                "of the wing's drag — it's the efficient, FSAE-legal way to add load. "
                "Set this target, then the wing lead designs the element stack to it in "
                "CFD and verifies with the Fluent deck.")
        # offer to write the target into the car's declared downforce (closes the loop)
        if st.button("Use this as the car's declared downforce",
                     key="aero_set_downforce",
                     help="Writes (downforce, speed) into the aerodynamics interface so "
                          "the 3D model wings, lap sim and heatmap all reflect it."):
            try:
                _led_a = interfaces_mod.IntegrationLedger.from_dict(st.session_state.ledger)
                _it = _led_a.get("aerodynamics") or interfaces_mod.SubsystemInterface(name="aerodynamics")
                _it.downforce_n_at_v = (float(_target), float(_aero_v_ms))
                _it.drag_n_at_v = (float(_tot_drag), float(_aero_v_ms))
                _led_a.set(_it)
                publish_ledger(_led_a.as_dict())
                st.success("Declared. The aero wings, lap sim and heatmap now use "
                           f"{uval(_target, 'N')} @ {uval(_aero_v, 'km/h')}.")
                st.rerun()
            except Exception as _e2:
                st.warning(f"Couldn't write it: {_e2}")

    # ---------------------------------------------------------------- VIEW 3 #
    elif _view == "Aero map (attitude sweep)":
        st.markdown(
            '<p class="hint">The <b>aero map</b>: how downforce, drag and balance move '
            'as the car changes attitude through a lap — ride height (bumps, braking '
            'dive, ground effect) crossed with yaw (sideslip in corners). This is the '
            'map the lap sim queries at every point on track. A flat, predictable map '
            'is a fast, drivable car; cliffs in it are where drivers lose confidence.</p>',
            unsafe_allow_html=True)
        _hs = np.linspace(15, 55, 24)
        _yaws = np.linspace(0, 8, 24)
        _what = st.radio("Show", ["Downforce (N)", "Drag (N)", "Aero balance (% front)"],
                         horizontal=True, key="aero_map_what")
        Z = np.zeros((len(_yaws), len(_hs)))
        for iy, yw in enumerate(_yaws):
            for ih, h in enumerate(_hs):
                d, r, cl, cd, fb = _aero_forces(h, yw, _aero_v_ms, _aero_area)
                Z[iy, ih] = (d if _what.startswith("Downforce")
                             else r if _what.startswith("Drag") else fb * 100.0)
        _is_force = not _what.startswith("Aero")   # Downforce/Drag are in N
        if _is_force:
            Z = np.array([[units_mod.from_metric(v, "N") for v in row] for row in Z])
        _uLn = units_mod.label("mm")
        _uF = units_mod.label("N")
        _uSpd = units_mod.label("km/h")
        _cbar_title = (_uF if _is_force else "% front")
        _scale = ("Tealrose" if _what.startswith("Aero") else
                  "Viridis" if _what.startswith("Downforce") else "Inferno")
        fh = go.Figure(data=go.Heatmap(
            x=[units_mod.from_metric(h, "mm") for h in _hs], y=_yaws, z=Z,
            colorscale=_scale, colorbar=dict(title=_cbar_title)))
        fh.add_trace(go.Scatter(x=[units_mod.from_metric(_aero_ride, "mm")],
                                y=[_aero_yaw], mode="markers",
                                marker=dict(color="#ffffff", size=11, symbol="x"),
                                name="current", showlegend=False))
        fh.update_layout(
            title="%s vs ride height × yaw @ %.0f %s" % (
                _what, units_mod.from_metric(_aero_v, "km/h"), _uSpd),
            xaxis_title=f"ride height ({_uLn})", yaxis_title="yaw / sideslip (°)",
            height=440, paper_bgcolor="rgba(0,0,0,0)", plot_bgcolor="rgba(0,0,0,0)",
            font=dict(color="#cdd6df", size=11), margin=dict(l=0, r=0, t=36, b=0))
        st.plotly_chart(fh, width='stretch', key="aero_map")
        st.markdown(
            '<p class="hint">The white × is your current attitude. Watch downforce fall '
            'and drag rise toward higher yaw — that\u2019s the car stalling in sideslip — '
            'and downforce build toward lower ride height. To go further, run the same '
            'attitude grid through the <b>panel-method solver on your STL</b> (it solves '
            'the real flow, ground image and all) and correlate it against the virtual '
            'wind tunnel + Fluent deck — all already in KinematiK.</p>',
            unsafe_allow_html=True)

    # ---------------------------------------------------------------- VIEW 4 #
    elif _view == "Scale model planning":
        st.markdown(
            '<p class="hint">Plan a <b>scaled-model wind tunnel run</b> before you test. '
            'Three decisions quietly mortgage every scaled-model correlation: '
            '<b>Reynolds similitude</b> (does the wind tunnel run fast enough to match the '
            'flow regime?), <b>build tolerance</b> (does the machining/print error '
            'swamp the coefficient you are trying to measure?), and <b>mount alignment</b> '
            '(did a weld-tab shift the incidence after you fixed the Dzus holes?). '
            'Fill in your scale decision and the as-built deviations — the plan tells you '
            'whether the coefficient will transfer, and what uncertainty band to carry '
            'into the correlation. All three feed directly into '
            '<code>TunnelProvenance</code> / <code>PhysicalAeroMap</code> so a scaled '
            'coefficient is never silently read as a full-car number.</p>',
            unsafe_allow_html=True)

        with st.expander("1 · Scale decision", expanded=False):
            # ── 1. Geometry ──────────────────────────────────────────────────── #
            _sc_cols = st.columns([1, 1, 1, 1])
            _sc_ratio = _sc_cols[0].number_input(
                "Scale ratio (model/full)", 0.10, 1.0, value=0.4, step=0.05,
                help="0.4 = 40% = 1:2.5 model.  Full-size dimensions are recovered as "
                     "scaled ÷ ratio — the two can never drift apart.")
            _sc_chord = _sc_cols[1].number_input(
                "Scaled chord (mm)", 50.0, 2000.0, value=500.0, step=10.0,
                help="Streamwise reference length OF THE MODEL.  Sets the Reynolds number.")
            _sc_height = _sc_cols[2].number_input(
                "Scaled height (mm)", 0.0, 1000.0, value=260.0, step=5.0,
                help="Spanwise height of the scaled article (optional — used for blockage "
                     "and frontal area, not similitude).")
            _sc_width = _sc_cols[3].number_input(
                "Scaled width (mm)", 0.0, 1000.0, value=250.0, step=5.0,
                help="Depth / width of the scaled article.")

            try:
                _spec = ScaleSpec(
                    ratio=_sc_ratio,
                    scaled_chord_mm=_sc_chord,
                    scaled_height_mm=_sc_height if _sc_height > 0 else None,
                    scaled_width_mm=_sc_width if _sc_width > 0 else None,
                )
                _sm_cols = st.columns(3)
                _sm_cols[0].info(f"**Scale:** {_spec.label()}")
                _sm_cols[1].info(f"**Full-size chord:** {_spec.full_chord_mm:.0f} mm")
                if _spec.full_height_mm is not None and _spec.full_width_mm is not None:
                    _sm_cols[2].info(
                        f"**Full-size envelope:** {_spec.full_height_mm:.0f} × "
                        f"{_spec.full_width_mm:.0f} mm (H × W)")
                # Publish the REAL full-size wing chord for the DXF exporter: the
                # airfoil section a member extrudes to span, at two typical FSAE
                # thicknesses to mesh both.
                try:
                    publish_export_geometry("aerodynamics", {
                        "chord_mm": float(_spec.full_chord_mm),
                        "thickness_fracs": [0.12, 0.16],
                        "source": f"scale model {_spec.label()}",
                    })
                except Exception:
                    pass
            except ValueError as _sve:
                st.error(f"Scale spec error: {_sve}")
                _spec = None

        if _spec is not None:

            with st.expander("2 · Reynolds similitude", expanded=False):
                # ── 2. Similitude ─────────────────────────────────────────────── #
                _sim_cols = st.columns([1, 1, 1])
                _full_speed_kmh = _sim_cols[0].number_input(
                    "Full-size race speed (km/h)", 10.0, 200.0, value=60.0, step=5.0,
                    help="The on-track speed you want the scaled run to reproduce. "
                         "FSAE corners are 40–70 km/h; endurance straight ~100+.")
                _tunnel_max_kmh = _sim_cols[1].number_input(
                    "Tunnel max speed (km/h)", 10.0, 300.0, value=160.0, step=5.0,
                    help="Your tunnel's ceiling. A 40%-scale model at 60 km/h full-size "
                         "needs 150 km/h to match Reynolds — check the tunnel can reach it.")
                _temp_c = _sim_cols[2].number_input(
                    "Air temperature (°C)", -10.0, 50.0, value=15.0, step=1.0,
                    help="Shop / tunnel temperature. Kinematic viscosity varies ~5% over "
                         "a typical seasonal range — worth getting right.")

                _sim = SimilitudePlan.match_reynolds(
                    _spec,
                    full_speed_ms=_full_speed_kmh / 3.6,
                    tunnel_max_speed_ms=_tunnel_max_kmh / 3.6,
                    temp_c=_temp_c,
                )
                _sim_metric_cols = st.columns(4)
                _sim_metric_cols[0].metric(
                    "Full-size Re", f"{_sim.full_reynolds:.2e}",
                    help="Reynolds number the full-size part sees at race speed.")
                _sim_metric_cols[1].metric(
                    "Matched tunnel speed",
                    f"{_sim.matched_speed_ms * 3.6:.0f} km/h",
                    help="Speed the tunnel must reach to give the model the same Re.")
                _sim_metric_cols[2].metric(
                    "Achieved Re", f"{_sim.achieved_reynolds:.2e}",
                    delta=f"{(_sim.reynolds_match_ratio - 1.0) * 100:+.0f}% vs full-size",
                    delta_color="normal" if _sim.reachable else "inverse",
                    help="Re the model will actually see at the tunnel's achievable speed.")
                _sim_metric_cols[3].metric(
                    "Re match", f"{_sim.reynolds_match_ratio * 100:.0f}%",
                    help="1.0 = perfect similitude; below ~80% the coefficient may not "
                         "transfer reliably.")
                if _sim.reachable and not _sim.warnings:
                    st.success(f"✅ {_sim.verdict}")
                elif _sim.reachable:
                    st.warning(f"⚠️ {_sim.verdict}")
                else:
                    st.error(f"❌ {_sim.verdict}")


            with st.expander("3 · Build tolerance budget", expanded=False):
                # ── 3. Build tolerance ────────────────────────────────────────── #
                st.markdown(
                    '<p class="hint">Enter the <em>as-built</em> deviations from the CAD '
                    'for your scaled part. Leave a field at 0 to omit that source. '
                    'An <b>unmeasured build has unknown, not zero, uncertainty</b> — the '
                    'report says so explicitly.</p>',
                    unsafe_allow_html=True)
                _tol_cols = st.columns([1, 1, 1, 1])
                _dev_chord = _tol_cols[0].number_input(
                    "Chord deviation (mm)", 0.0, 50.0, value=0.0, step=0.5,
                    help="Streamwise chord built long or short of nominal. "
                         "~1:1 fractional error on C_l reference.")
                _dev_camber = _tol_cols[1].number_input(
                    "Camber / LE deviation (mm)", 0.0, 20.0, value=0.0, step=0.5,
                    help="Leading-edge or camber-line off the CAD — the big one on a "
                         "moldless / 3-D-printed part. ~3× chord-fraction onto C_l.")
                _dev_span = _tol_cols[2].number_input(
                    "Span deviation (mm)", 0.0, 50.0, value=0.0, step=0.5,
                    help="Span (height) built off-nominal. ~1:1 onto C_l via planform area.")
                _dev_wave = _tol_cols[3].number_input(
                    "Surface waviness (mm)", 0.0, 5.0, value=0.0, step=0.1,
                    help="Print-layer steps / weave print-through. Trips the boundary layer "
                         "and loads heavily onto C_d (~2.5×), little onto C_l.")

                _budget = ToleranceBudget(_spec)
                if _dev_chord > 0:
                    _budget.add_chord_deviation_mm(_dev_chord)
                if _dev_camber > 0:
                    _budget.add_camber_deviation_mm(_dev_camber)
                if _dev_span > 0 and _sc_height > 0:
                    _budget.add_span_deviation_mm(_dev_span, _sc_height)
                if _dev_wave > 0:
                    _budget.add_surface_waviness_mm(_dev_wave)
                _tol_report = _budget.report()

                _tol_m = st.columns(2)
                _tol_m[0].metric(
                    "C_L uncertainty (build)",
                    f"±{_tol_report.cl_uncertainty_frac * 100:.1f}%",
                    help="RSS of all entered deviation sources on the lift coefficient.")
                _tol_m[1].metric(
                    "C_D uncertainty (build)",
                    f"±{_tol_report.cd_uncertainty_frac * 100:.1f}%",
                    help="RSS of all entered deviation sources on the drag coefficient.")
                with st.expander("Tolerance breakdown", expanded=False):
                    st.code(_tol_report.summary, language=None)


            with st.expander("4 · Mount alignment (the Dzus-weld lesson)", expanded=False):
                # ── 4. Mount alignment ────────────────────────────────────────── #
                st.markdown(
                    '<p class="hint">Mounting tabs can move during welding — '
                    '<b>do not drill or finalise Dzus holes before welding is complete.</b> '
                    'Enter the as-built incidence error and any fore/aft shift; they fold '
                    'into the same uncertainty band as the build tolerance above.</p>',
                    unsafe_allow_html=True)
                _mnt_cols = st.columns(2)
                _mnt_inc = _mnt_cols[0].number_input(
                    "Incidence error (°)", 0.0, 10.0, value=0.0, step=0.25,
                    help="As-built pitch / angle-of-attack of the element vs the CAD. "
                         "Even 1° shifts C_l measurably on a high-load FSAE element.")
                _mnt_pos = _mnt_cols[1].number_input(
                    "Fore/aft position error (mm)", 0.0, 50.0, value=0.0, step=1.0,
                    help="How far the element sits forward/aft of its design station.")
                _mount = MountAlignment(
                    incidence_error_deg=_mnt_inc,
                    position_error_mm=_mnt_pos,
                )
                st.info(_mount.status())


            with st.expander("5 · Scaled run plan & provenance", expanded=False):
                # ── 5. Combined plan & provenance ─────────────────────────────── #
                _plan = ScaledRunPlan(similitude=_sim, tolerance=_budget, mount=_mount)
                _plan_cols = st.columns(3)
                _plan_cols[0].metric(
                    "Run speed",
                    f"{_sim.achievable_speed_ms * 3.6:.0f} km/h",
                    help="Tunnel speed to use for this scaled run.")
                _plan_cols[1].metric(
                    "Model Re", f"{_plan.tunnel_reynolds():.2e}",
                    help="Reynolds number the model will see — carry this into TunnelProvenance.")
                _plan_cols[2].metric(
                    "Combined C_L uncertainty",
                    f"±{_plan.combined_cl_uncertainty_frac() * 100:.1f}%",
                    help="Build tolerance and mount error combined in quadrature. A CFD "
                         "correlation that lands inside this band has confirmed nothing the "
                         "build didn't already allow.")
                with st.expander("Full run-plan report", expanded=True):
                    st.code(_plan.report(), language=None)


            with st.expander("6 · Record wind tunnel results → Physical Aero Map", expanded=False):
                # ── 6. Tunnel provenance & physical aero map ──────────────────── #
                st.markdown(
                    '<p class="hint">After the wind tunnel run, log your measured coefficients '
                    'here. The run-plan settings above (scale, Reynolds, uncertainty) are '
                    'automatically carried into every measurement as <b>provenance</b> — '
                    'no copy-pasting needed. The resulting Physical Aero Map feeds straight '
                    'into the lap sim.</p>',
                    unsafe_allow_html=True)

                # Facility inputs — the few fields the plan doesn't already know
                _prov_cols = st.columns([2, 1, 1])
                _prov_facility = _prov_cols[0].text_input(
                    "Tunnel facility name", value="in-house tunnel",
                    key="sm_prov_facility",
                    help="Name of the wind tunnel used for this run (appears in all "
                         "downstream provenance labels).")
                _prov_ground = _prov_cols[1].selectbox(
                    "Tunnel floor type",
                    ["moving-belt", "fixed-floor", "suction-fixed"],
                    key="sm_prov_ground",
                    help="Moving belt is the only ground-effect-true state. "
                         "Fixed floor underpredicts underbody downforce — flagged in provenance.")
                _prov_blk = _prov_cols[2].checkbox(
                    "Blockage-corrected", value=True, key="sm_prov_blk",
                    help="Were the coefficients corrected for solid + wake blockage? "
                         "Uncorrected coefficients are inflated by the test-section walls.")

                _GS_SM = {"moving-belt": wt_mod.GroundState.MOVING_BELT,
                          "fixed-floor": wt_mod.GroundState.FIXED_FLOOR,
                          "suction-fixed": wt_mod.GroundState.SUCTION_FIXED}

                # Build TunnelProvenance from the plan (no manual copy required)
                _sm_prov = wt_mod.TunnelProvenance(
                    facility=_prov_facility or "tunnel",
                    ground_state=_GS_SM[_prov_ground],
                    model_scale=_plan.model_scale(),
                    blockage_corrected=bool(_prov_blk),
                    reynolds=_plan.tunnel_reynolds(),
                    reference_area_m2=float(_aero_area),
                    reference_length_m=float(_sc_chord) / 1000.0,
                    notes=_plan.provenance(),
                )
                st.info(f"**Provenance status:** {_sm_prov.status()}")

                # Wheelbase for ride-height → attitude conversion
                _prov_wb_cols = st.columns([1, 1, 2])
                _sm_wb = _prov_wb_cols[0].number_input(
                    "Wheelbase (mm)", 1000.0, 2000.0, value=1550.0, step=10.0,
                    key="sm_prov_wb",
                    help="Distance between front and rear ride-height reference planes.")
                _sm_ref_len = _prov_wb_cols[1].number_input(
                    "Reference length (mm)", 100.0, 2000.0,
                    value=float(_sc_chord), step=10.0,
                    key="sm_prov_reflen",
                    help="Streamwise reference length for coefficient normalisation — "
                         "defaults to the scaled chord above.")

                # Measured points: upload CSV or enter manually
                st.markdown("**Add measured points**")
                _input_mode = st.radio(
                    "How do you want to enter results?",
                    ["Upload CSV", "Enter manually"],
                    horizontal=True, key="sm_input_mode")

                _phys_map = wt_mod.PhysicalAeroMap(
                    _sm_prov,
                    reference_area_m2=float(_aero_area),
                    reference_length_m=float(_sm_ref_len) / 1000.0,
                    wheelbase_mm=float(_sm_wb),
                )

                if _input_mode == "Upload CSV":
                    st.markdown(
                        '<p class="hint">One row per ride-height point. '
                        'Required columns: <code>front_mm, rear_mm, speed_ms, c_lift, c_drag</code>. '
                        'Optional: <code>aero_balance_front</code>. '
                        'Sign convention: <b>c_lift negative = downforce</b>.</p>',
                        unsafe_allow_html=True)
                    _sm_csv = st.file_uploader(
                        "Physical aero-map CSV", type=["csv"], key="sm_phys_csv")
                    if _sm_csv is not None:
                        try:
                            import csv as _csv2, io as _io3
                            _raw2 = _sm_csv.getvalue().decode("utf-8", errors="replace")
                            _rdr2 = _csv2.DictReader(_io3.StringIO(_raw2))
                            _n_rows2 = 0
                            for _row2 in _rdr2:
                                def _f2(k, d=None):
                                    v = (_row2.get(k) or "").strip()
                                    return float(v) if v not in ("", None) else d
                                _bal2 = _f2("aero_balance_front", None)
                                _rh2 = wt_mod.RideHeights(
                                    front_mm=_f2("front_mm", 30.0),
                                    rear_mm=_f2("rear_mm", 30.0),
                                    speed_ms=_f2("speed_ms", 20.0),
                                    wheelbase_mm=float(_sm_wb))
                                _phys_map.add_measurement(
                                    _rh2,
                                    c_lift=_f2("c_lift"),
                                    c_drag=_f2("c_drag"),
                                    aero_balance_front=_bal2)
                                _n_rows2 += 1
                            st.success(
                                f"✅ Loaded {len(_phys_map)} measurement(s) from {_n_rows2} row(s).")
                        except Exception as _e_csv:
                            st.error(f"Couldn't parse CSV: {_e_csv}")

                else:  # Manual entry
                    st.markdown(
                        '<p class="hint">Enter one measurement point at a time. '
                        'Sign convention: <b>c_lift negative = downforce</b>.</p>',
                        unsafe_allow_html=True)
                    _man_cols = st.columns([1, 1, 1, 1, 1, 1])
                    _man_front = _man_cols[0].number_input(
                        "Front RH (mm)", 10.0, 150.0, value=30.0, step=2.5,
                        key="sm_man_front")
                    _man_rear = _man_cols[1].number_input(
                        "Rear RH (mm)", 10.0, 150.0, value=30.0, step=2.5,
                        key="sm_man_rear")
                    _man_speed = _man_cols[2].number_input(
                        "Speed (m/s)", 5.0, 100.0,
                        value=float(round(_sim.achievable_speed_ms, 1)),
                        step=1.0, key="sm_man_speed",
                        help="Defaults to the planned tunnel speed from section 2.")
                    _man_cl = _man_cols[3].number_input(
                        "C_lift (−ve = downforce)", -5.0, 5.0, value=-1.0, step=0.05,
                        key="sm_man_cl")
                    _man_cd = _man_cols[4].number_input(
                        "C_drag", 0.0, 5.0, value=0.3, step=0.01,
                        key="sm_man_cd")
                    _man_bal = _man_cols[5].number_input(
                        "Aero balance (0–1, opt.)", 0.0, 1.0, value=0.45, step=0.01,
                        key="sm_man_bal",
                        help="Front aero balance fraction. Leave at 0 to omit.")

                    if st.button("➕ Add this point", key="sm_man_add"):
                        _rh_man = wt_mod.RideHeights(
                            front_mm=float(_man_front),
                            rear_mm=float(_man_rear),
                            speed_ms=float(_man_speed),
                            wheelbase_mm=float(_sm_wb))
                        _bal_val = float(_man_bal) if _man_bal > 0 else None
                        if "sm_manual_points" not in st.session_state:
                            st.session_state["sm_manual_points"] = []
                        st.session_state["sm_manual_points"].append({
                            "front_mm": float(_man_front),
                            "rear_mm": float(_man_rear),
                            "speed_ms": float(_man_speed),
                            "c_lift": float(_man_cl),
                            "c_drag": float(_man_cd),
                            "aero_balance_front": _bal_val,
                        })
                        st.rerun()

                    # Replay stored manual points into the map
                    for _mp in st.session_state.get("sm_manual_points", []):
                        _rh_mp = wt_mod.RideHeights(
                            front_mm=_mp["front_mm"], rear_mm=_mp["rear_mm"],
                            speed_ms=_mp["speed_ms"], wheelbase_mm=float(_sm_wb))
                        _phys_map.add_measurement(
                            _rh_mp, c_lift=_mp["c_lift"], c_drag=_mp["c_drag"],
                            aero_balance_front=_mp["aero_balance_front"])

                    if st.session_state.get("sm_manual_points"):
                        _pts_display = [
                            {k: (f"{v:.3f}" if isinstance(v, float) and v is not None else v)
                             for k, v in p.items()}
                            for p in st.session_state["sm_manual_points"]]
                        st.dataframe(_pts_display, use_container_width=True)
                        if st.button("🗑 Clear all manual points", key="sm_man_clear"):
                            st.session_state["sm_manual_points"] = []
                            st.rerun()

                # Show summary of whatever map we have
                if len(_phys_map) > 0:
                    st.success(
                        f"**Physical Aero Map ready** — {len(_phys_map)} point(s) · "
                        f"scale {_plan.model_scale():.0%} · Re={_plan.tunnel_reynolds():.2e} · "
                        f"combined C_L uncertainty ±{_plan.combined_cl_uncertainty_frac()*100:.1f}%")

                    # Summary table of measured points
                    with st.expander("Measured points", expanded=True):
                        _rows = []
                        for _pt in _phys_map.measured_points():
                            from suspension.aero.windtunnel import attitude_to_ride_heights
                            _rh_out = attitude_to_ride_heights(_pt.attitude, float(_sm_wb))
                            _rows.append({
                                "Front (mm)": f"{_rh_out.front_mm:.1f}",
                                "Rear (mm)": f"{_rh_out.rear_mm:.1f}",
                                "Speed (m/s)": f"{_rh_out.speed_ms:.1f}",
                                "C_lift": f"{_pt.c_lift:.4f}",
                                "C_drag": f"{_pt.c_drag:.4f}",
                                "Aero bal.": (
                                    f"{_pt.aero_balance_front:.3f}"
                                    if _pt.aero_balance_front is not None else "—"),
                            })
                        st.dataframe(_rows, use_container_width=True)

                    # Store in session state so other tabs (e.g. Validation) can use it
                    st.session_state["sm_physical_aero_map"] = _phys_map
                    st.markdown(
                        '<p class="hint">This Physical Aero Map is now available in the '
                        '<b>Validation → Wind tunnel (CFD calibration)</b> tab for '
                        'correlation against your CFD runs.</p>',
                        unsafe_allow_html=True)
                else:
                    st.info("Add measured points above to build the Physical Aero Map.")


    # ---------------------------------------------------------------- VIEW 5 #
    # Plug & layup build planner — the shop-floor half of the scaled programme:
    # foam slice plan + 1:1 templates, computed ordering list (CSV), cure-aware
    # build-day schedule, and the two part-scrapping hard gates. All the logic
    # lives in suspension/aero/plug_builder.py (tested, import-light); this hook
    # only mounts the panel so the app file stays navigable.
    elif _view == "Plug & layup build planner":
        try:
            from suspension.aero import plug_builder as _pb_mod
            _pb_mod.render_streamlit_panel()
            try:
                record_activity("aerodynamics", "calculation",
                                "Planned plug & layup build (slice/BOM/schedule/gate)")
            except Exception:
                pass
        except Exception as _e_pb:
            st.error(f"Plug & layup planner failed: {_e_pb}")

    # ---------------------------------------------------------------- VIEW 6 #
    # Mounting & bonding designer — answers the question every aero subteam hits
    # late in the year ("where — and HOW — do we actually attach this to the
    # car?") without anyone having to trawl past-project archives or forums.
    # Three layers, each one step more quantitative:
    #   1) Playbook — per element, the conventional FSAE answer (mount to the
    #      CHASSIS, not the bodywork), the usual hardware, and the why.
    #   2) Mount-load calculator — takes the live aero model's forces at a
    #      design speed, adds a gust/transient factor and a safety factor,
    #      spreads them over the element's mount points, and compares against
    #      the rulebook push-test so the bracket is sized by the governing
    #      load instead of a guess.
    #   3) Attachment sizer — bolts, bonded pads and rivnuts/inserts checked
    #      against that per-mount load, with the classic failure modes called
    #      out (the bolt is almost never the weak link; the insert/laminate is).
    # It ends with a copy-paste status summary so "give the team an update"
    # takes one click, not an evening of research.
    elif _view == "Mounting & bonding designer":
        st.markdown(
            '<p class="hint">Where — and how — the aero package <b>attaches to the '
            'car</b>. The short answer every experienced FSAE team converges on: '
            'mount every load-bearing aero device to the <b>chassis (primary '
            'structure)</b>, never to bodywork. Bodywork panels flex, so a wing '
            'hung off them loses angle-of-attack at speed, flutters, and fails the '
            'rules push-test; the chassis gives a stiff, known load path straight '
            'into the structure the suspension already reacts against. Below: the '
            'per-element playbook, the actual loads your mounts must carry, and '
            'sized hardware to carry them.</p>', unsafe_allow_html=True)

        # ---------------- 1) the playbook: what teams conventionally do ---- #
        _MOUNT_PLAYBOOK = {
            "Front wing": dict(
                icon="🛫", share=0.30, mounts=4,
                to="Chassis — front bulkhead / nose structure",
                never="The nose-cone skin alone — it's non-structural, flexes, "
                      "and pulls fasteners through under load",
                hw="Two machined-Al brackets or swan-necks off the front bulkhead, "
                   "plus quick-release pins (or DZUS) so the nose still comes off "
                   "fast at tech inspection without unbolting the wing",
                why="Downforce goes straight into primary structure; wing pitch "
                    "stays fixed under load, which keeps the front axle's share of "
                    "downforce (aero balance) where you designed it."),
            "Rear wing": dict(
                icon="🪽", share=0.40, mounts=4,
                to="Chassis — main hoop and/or rear bulkhead uprights",
                never="Engine cover or bodywork panels, and never into the "
                      "impact-attenuator crush zone",
                hw="Twin CNC'd Al uprights or swan-neck plates clamped/tabbed to "
                   "the main hoop; a bolt-hole pattern or jack-screw for "
                   "angle-of-attack changes between events",
                why="Largest single aero load on the car on a tall moment arm — it "
                    "needs the stiffest structure available. A stiff mount is what "
                    "keeps the aero map honest: no flutter, no AoA washout at the "
                    "end of the straight."),
            "Undertray / floor + diffuser": dict(
                icon="🛹", share=0.25, mounts=8,
                to="Chassis — lower frame rails on ≥6 spread-out tabs, "
                   "rubber-isolated",
                never="Hanging off the sidepods or off suspension members",
                hw="Bolted tabs with rubber grommets (or quarter-turns for "
                   "service); pin the front edge, slot the rear holes so the "
                   "panel can move thermally and in kerb strikes",
                why="The load is distributed suction plus point kerb strikes — "
                    "many small mounts beat two big ones, and rubber isolation "
                    "stops kerb hits cracking the laminate around a hard bolt."),
            "Sidepods / bodywork panels": dict(
                icon="🧩", share=0.05, mounts=6,
                to="Chassis tabs + adjacent panels (non-structural)",
                never="As a load path for wing or floor forces",
                hw="DZUS / quarter-turn fasteners or bonded studs; foam tape "
                   "along free edges to stop buzzing",
                why="They carry mostly their own inertia and small pressure "
                    "loads — fast removal for radiator/accumulator access "
                    "matters more than stiffness here."),
        }
        _pb_cols = st.columns(2)
        for _pi, (_pel, _pd) in enumerate(_MOUNT_PLAYBOOK.items()):
            _pb_cols[_pi % 2].markdown(
                f'<div style="background:#141c24;border:1px solid #2a3743;'
                f'border-left:3px solid #ffd93b;border-radius:10px;'
                f'padding:.7rem .95rem;margin:.3rem 0;">'
                f'<div style="font-weight:700;color:#e7ecf1;font-size:.92rem;'
                f'margin-bottom:.3rem;">{_pd["icon"]} {_pel}</div>'
                f'<p style="margin:.15rem 0;font-size:.8rem;line-height:1.55;'
                f'color:#c4cdd6;"><b style="color:#5ad17a;">Mount to:</b> '
                f'{_pd["to"]}</p>'
                f'<p style="margin:.15rem 0;font-size:.8rem;line-height:1.55;'
                f'color:#c4cdd6;"><b style="color:#ff6b6b;">Never:</b> '
                f'{_pd["never"]}</p>'
                f'<p style="margin:.15rem 0;font-size:.8rem;line-height:1.55;'
                f'color:#c4cdd6;"><b style="color:#37e0d0;">Typical hardware:</b> '
                f'{_pd["hw"]}</p>'
                f'<p style="margin:.15rem 0 0;font-size:.78rem;line-height:1.5;'
                f'color:#a8b4bf;">{_pd["why"]}</p></div>',
                unsafe_allow_html=True)
        st.caption(
            "Rules note: aero devices must survive the scrutineering push-test — "
            "classically 200 N spread over ≥ 225 cm² with ≤ 10 mm deflection, and "
            "a 50 N point load in any direction with ≤ 25 mm deflection. Numbers "
            "move year to year: verify against the current-year FSAE/FS rulebook "
            "(T.7 / Aerodynamic Devices) before freezing the design.")

        # ---------------- front-end stack-up (nose vs IA) ------------------ #
        # The recurring nose question ("does the nose cone go in front of the
        # impact attenuator — the little honeycomb thing?") answered once, with
        # a picture, so it never has to be asked in the channel again.
        with st.expander(
                "🥅 Front-end stack-up — nose cone vs impact attenuator "
                "(what goes where)", expanded=False):
            st.markdown(
                '<p class="hint">Front-to-back order of the nose: '
                '<b>nose-cone skin</b> (outermost, non-structural bodywork) → '
                '<b>impact attenuator</b> (the honeycomb/foam crush block, '
                'mounted forward of the bulkhead) → <b>anti-intrusion plate</b> '
                '→ <b>front bulkhead</b> (primary structure). So yes — from the '
                'outside the nose cone is the front-most thing, and the '
                'honeycomb IA lives <i>inside</i> it. The nose is a cover, not '
                'a structure: it carries no wing load, and <b>nothing may be '
                'mounted to the IA</b> — it must be free to crush. The front '
                'wing\u2019s brackets route <b>around</b> the IA to the '
                'bulkhead.</p>', unsafe_allow_html=True)

            _fe = go.Figure()
            # chassis / monocoque stub
            _fe.add_shape(type="rect", x0=-560, x1=0, y0=120, y1=430,
                          fillcolor="#22303c", line=dict(color="#3a4a58"))
            # front bulkhead
            _fe.add_shape(type="rect", x0=0, x1=26, y0=100, y1=445,
                          fillcolor="#8fa3b5", line=dict(color="#c7d3de"))
            # anti-intrusion plate
            _fe.add_shape(type="rect", x0=26, x1=34, y0=108, y1=437,
                          fillcolor="#ff9f43", line=dict(color="#ffbd7a"))
            # impact attenuator (honeycomb block)
            _fe.add_shape(type="rect", x0=34, x1=234, y0=165, y1=360,
                          fillcolor="rgba(255,217,59,.28)",
                          line=dict(color="#ffd93b", width=2))
            for _hx in range(58, 234, 24):   # honeycomb hint lines
                _fe.add_shape(type="line", x0=_hx, x1=_hx, y0=165, y1=360,
                              line=dict(color="rgba(255,217,59,.45)", width=1))
            # nose-cone skin (curved cover over the IA)
            _t = np.linspace(0, 1, 40)
            _nx = 0 + _t * 330
            _nz_top = 445 - 205 * _t ** 1.6
            _nz_bot = 100 + 140 * _t ** 1.6
            _fe.add_trace(go.Scatter(
                x=np.concatenate([_nx, _nx[::-1]]),
                y=np.concatenate([_nz_top, _nz_bot[::-1]]),
                mode="lines", line=dict(color="#37e0d0", width=4),
                name="Nose-cone skin", hoverinfo="name"))
            # front wing + bracket routing AROUND the IA
            _fe.add_shape(type="rect", x0=140, x1=430, y0=55, y1=92,
                          fillcolor="#b48cff", line=dict(color="#d3bcff"))
            _fe.add_trace(go.Scatter(
                x=[240, 60, 18], y=[92, 148, 260], mode="lines",
                line=dict(color="#5ad17a", width=4),
                name="Wing bracket → bulkhead", hoverinfo="name"))
            # ground
            _fe.add_shape(type="line", x0=-560, x1=470, y0=0, y1=0,
                          line=dict(color="#3a4a58", width=2, dash="dot"))
            _ANN = [
                (340, 300, "① Nose-cone skin<br>(bodywork — a cover)", "#37e0d0"),
                (134, 395, "② Impact attenuator<br>(honeycomb — must crush free,"
                           "<br>mount NOTHING to it)", "#ffd93b"),
                (30, 470, "③ Anti-intrusion plate", "#ff9f43"),
                (-90, 470, "④ Front bulkhead<br>(primary structure)", "#c7d3de"),
                (330, 30, "Front wing — brackets route<br>AROUND the IA to ④",
                 "#b48cff"),
            ]
            for _ax, _ay, _txt, _ac in _ANN:
                _fe.add_annotation(x=_ax, y=_ay, text=_txt, showarrow=False,
                                   font=dict(color=_ac, size=11))
            _fe.update_layout(
                title="Nose stack-up, side view (forward →)",
                height=380, showlegend=False,
                paper_bgcolor="rgba(0,0,0,0)", plot_bgcolor="rgba(0,0,0,0)",
                font=dict(color="#cdd6df", size=11),
                margin=dict(l=0, r=0, t=36, b=0),
                xaxis=dict(visible=False, range=[-600, 520]),
                yaxis=dict(visible=False, range=[-30, 510],
                           scaleanchor="x", scaleratio=1))
            st.plotly_chart(_fe, width='stretch', key="aero_mnt_nose")
            st.markdown(
                '<p class="hint" style="font-size:.78rem;">Rules anchors '
                '(classic values — verify the current rulebook): the IA is at '
                'least <b>200 mm long × 200 mm wide × 100 mm high</b>, mounted '
                'forward of the bulkhead on an anti-intrusion plate (~1.5 mm '
                'steel or 4 mm aluminium), and must absorb ~<b>7350 J</b> with '
                'average deceleration ≤ 20 g and peak ≤ 40 g. Consequences for '
                'aero: leave <b>crush clearance</b> between the IA face and the '
                'nose skin (the nose must not stop the IA crushing), keep the '
                'nose <b>quick-release</b> so scrutineers can see the IA and '
                'wing brackets, and never react wing loads through the nose '
                'skin or the IA — bulkhead only.</p>',
                unsafe_allow_html=True)

        # ---------------- 2) mount-load calculator ------------------------- #
        st.markdown("##### What your mounts actually have to carry")
        _mlc = st.columns(4)
        _uSpd = units_mod.label("km/h")
        _m_v = _mlc[0].number_input(
            f"Design speed ({_uSpd})", 40.0, 140.0, value=max(_aero_v, 100.0),
            step=5.0, key="aero_mnt_v",
            help="Size the mounts at the fastest thing the car does — the "
                 "endurance straight — not the average corner.")
        _m_gust = _mlc[1].slider(
            "Gust / transient factor", 1.0, 2.5, 1.5, 0.1, key="aero_mnt_gust",
            help="Real cars see gusts, wake hits, kerb strikes and pitch "
                 "transients above the steady CFD number. 1.5 is a common "
                 "student-team choice.")
        _m_fos = _mlc[2].slider(
            "Safety factor on hardware", 1.0, 4.0, 2.0, 0.25, key="aero_mnt_fos",
            help="Applied on top of the gust factor when sizing the fastener/"
                 "bond. Bonded joints usually get more than bolted ones.")
        _m_el = _mlc[3].selectbox(
            "Element to size", list(_MOUNT_PLAYBOOK.keys()), key="aero_mnt_el")
        _m_pd = _MOUNT_PLAYBOOK[_m_el]
        _m_n = st.slider(
            "Mount points on this element", 2, 12, int(_m_pd["mounts"]), 1,
            key="aero_mnt_n",
            help="Discrete attachment points sharing the load. Assumed evenly "
                 "shared — a real bracket layout won't be perfectly even, which "
                 "is part of what the safety factor covers.")

        _m_df, _m_dr, *_ = _aero_forces(_aero_ride, _aero_yaw, _m_v / 3.6,
                                        _aero_area)
        _m_share = float(_m_pd["share"])
        _el_down = _m_df * _m_share * _m_gust          # N, design vertical
        _el_drag = _m_dr * _m_share * _m_gust          # N, design longitudinal
        _per_v = _el_down / _m_n
        _per_d = _el_drag / _m_n
        _per_res = float(np.hypot(_per_v, _per_d))
        # rulebook push-test, spread over the same mounts (200 N distributed)
        _per_rule = 200.0 / _m_n
        _per_gov = max(_per_res, _per_rule)
        _gov_src = ("aero load @ speed" if _per_res >= _per_rule
                    else "rules push-test")

        _mm = st.columns(4)
        umetric(_mm[0], f"{_m_el} carries", _el_down, "N",
                delta=f"{_m_share*100:.0f}% of car × gust {_m_gust:g}",
                help="Design vertical load on the whole element at the design "
                     "speed, including the gust factor.")
        umetric(_mm[1], "Per-mount resultant", _per_res, "N",
                help="Vertical + drag combined at one attachment point, "
                     "evenly shared.")
        umetric(_mm[2], "Rules test per mount", _per_rule, "N",
                help="The 200 N scrutineering push spread over the same points.")
        umetric(_mm[3], "Governing design load", _per_gov * _m_fos, "N",
                delta=f"{_gov_src} × FOS {_m_fos:g}",
                help="What each fastener/bond must carry: the larger of the "
                     "aero load and the rules test, times your safety factor.")

        # ---------------- 3) attachment method sizer ----------------------- #
        st.markdown("##### Will the hardware carry it?")
        _need = _per_gov * _m_fos  # N per mount, incl. FOS
        # Reference single-shear capacities, grade 8.8, through the thread
        # (0.6 × 800 MPa on the tensile stress area) — deliberately simple.
        _BOLT_CAP = {"M5": 6800.0, "M6": 9650.0, "M8": 17600.0}
        # Reference pull-out/bearing of the *soft side* — the actual weak links.
        _WEAK_CAP = {
            "Rivnut (Al, in 1.5 mm tube wall)": 900.0,
            "Rivnut (steel, in 1.5 mm tube wall)": 1800.0,
            "Potted insert in sandwich panel": 1500.0,
            "Quick-release pin (8 mm, double shear)": 12000.0,
        }
        _hc = st.columns([1.1, 1])
        with _hc[0]:
            _rows = []
            for _bn, _bc in _BOLT_CAP.items():
                _rows.append((f"{_bn} bolt, single shear (8.8)", _bc))
            _rows += list(_WEAK_CAP.items())
            for _hn, _hcapn in _rows:
                _ut = (_need / _hcapn) if _hcapn else 9.9
                _ok = _ut <= 1.0
                _col = "#5ad17a" if _ut <= 0.5 else ("#ffd93b" if _ok
                                                     else "#ff6b6b")
                _lbl = ("OK" if _ut <= 0.5 else
                        ("marginal" if _ok else "undersized"))
                st.markdown(
                    f'<div style="display:flex;justify-content:space-between;'
                    f'align-items:center;background:#10171e;border:1px solid '
                    f'#242f3a;border-radius:8px;padding:.4rem .7rem;'
                    f'margin:.18rem 0;">'
                    f'<span style="font-size:.8rem;color:#c4cdd6;">{_hn}</span>'
                    f'<span style="font-family:monospace;font-size:.76rem;'
                    f'color:{_col};">{_ut*100:.0f}% used · {_lbl}</span></div>',
                    unsafe_allow_html=True)
            st.caption(
                "Reference capacities for orientation, not certification — the "
                "bolt is almost never the weak link. What fails on student cars "
                "is the rivnut spinning/pulling out of a thin tube wall, the "
                "laminate crushing in bearing around an un-bushed hole, or an "
                "insert tearing out of a sandwich core. Size THOSE, pot inserts "
                "properly, and put large washers or bonded doublers behind "
                "composite panels.")
        with _hc[1]:
            st.markdown("**Bonded joint instead of (or with) bolts?**")
            _adh = st.number_input(
                "Adhesive design allowable (MPa)", 0.2, 5.0, 1.5, 0.1,
                key="aero_mnt_adh",
                help="Datasheet lap-shear for structural epoxies/methacrylates "
                     "is 10–25 MPa, but peel sensitivity, surface prep, "
                     "temperature and fatigue knock the usable design value "
                     "down to ~1–2 MPa. Never design a bond to the datasheet "
                     "number.")
            _area_mm2 = _need / _adh   # N / (N/mm²) = mm²
            _side = float(np.sqrt(_area_mm2))
            st.metric("Bond area needed per mount", f"{_area_mm2:,.0f} mm²",
                      delta=f"≈ {_side:.0f} × {_side:.0f} mm pad")
            st.markdown(
                '<p class="hint" style="font-size:.78rem;">Bond design rules of '
                'thumb: load the adhesive in <b>shear, never peel</b>; abrade + '
                'solvent-wipe both faces; control the bond-line to ~0.2–0.5 mm; '
                'and back every bonded aero mount up with a mechanical fastener '
                'or safety wire — scrutineers (and physics) like redundancy.</p>',
                unsafe_allow_html=True)

        # ---------------- copy-paste status update ------------------------- #
        with st.expander("📋 Copy-paste update for the team channel",
                         expanded=False):
            _upd = (
                f"Aero mounting plan — {_m_el}\n"
                f"• Mounts to: {_m_pd['to']}\n"
                f"• Hardware: {_m_pd['hw']}\n"
                f"• Design load: {_el_down:.0f} N downforce on the element at "
                f"{_m_v:.0f} km/h (incl. ×{_m_gust:g} gust), shared over "
                f"{_m_n} mounts → {_per_res:.0f} N per mount "
                f"({_per_gov*_m_fos:.0f} N with FOS {_m_fos:g}).\n"
                f"• Governing case: {_gov_src}.\n"
                f"• Rules check: 200 N / ≥225 cm² push ≤10 mm and 50 N point "
                f"≤25 mm deflection (verify current rulebook).\n"
                + ("• Nose stack-up: nose-cone skin (cover) over the honeycomb "
                   "impact attenuator → anti-intrusion plate → front bulkhead. "
                   "Wing brackets route around the IA to the bulkhead; nothing "
                   "mounts to the IA and the nose carries no wing load.\n"
                   if _m_el == "Front wing" else "")
                + f"Source: KinematiK → Aerodynamics → Mounting & bonding designer.")
            st.code(_upd, language=None)
            st.caption("Paste this in the channel — it's the update, the "
                       "numbers, and where they came from, in one block.")

        # ---------------- see it on the car -------------------------------- #
        if st.button("⚓ Show these mount points on the 3D car",
                     key="aero_mnt_show3d",
                     help="Turns on the mount-point layer in the 3D MODEL tab: "
                          "gold diamonds at each attachment, dotted load-path "
                          "lines into the chassis. The element and mount count "
                          "you chose here are emphasised there."):
            st.session_state["car3d_aeromounts_req"] = True
            st.session_state["car3d_aeromounts_on"] = True
            st.success(
                f"Mount overlay is ON. Open the **🏎️ 3D Model** tab — "
                f"{_m_el} is highlighted with your {_m_n} mount points; the "
                "dotted lines show the load path into the chassis. Toggle it "
                "any time under Layers → “⚓ Aero mount points”.")

        try:
            record_activity(
                "aerodynamics", "calculation",
                f"Sized {_m_el} mounting: {_per_res:.0f} N/mount at "
                f"{_m_v:.0f} km/h over {_m_n} mounts (gov: {_gov_src}, "
                f"FOS {_m_fos:g})")
        except Exception:
            pass

    with st.expander("How honest is this? (provenance)", expanded=False):
        _prov = _aero_model.provenance()
        st.markdown(
            f"**Backend:** {_prov.backend} · **fidelity:** {_prov.fidelity.value} · "
            f"**correlated:** {'yes' if _prov.is_correlated else 'no'}  \n"
            f"{_prov.notes}")
        st.markdown(
            "The upgrade path, all shipped in KinematiK and runnable without a paid "
            "license: a **3D source-panel potential-flow solve** on your actual floor/"
            "wing STL (ground effect emerges from geometry, not a constant), a "
            "**Virtual Wind Tunnel** that sweeps ride heights and writes the identical "
            "points for ANSYS Fluent verification, **pressure-tap correlation** that "
            "maps measured C_p onto the wing to find stall, and a **DAQ front-end** that "
            "cleans force-balance + pressure-scanner data. This tab is the fast trend "
            "layer that sits on top of all of it.")
  except Exception as _eaero:
    st.error(f"Could not build the aero workspace: {_eaero}")

# =========================================================================== #
#  EV POWERTRAIN  —  architecture choice + energy budget for the electric car. #
# =========================================================================== #
# USC is an ELECTRIC team; their powertrain/drivetrain subteams pick a motor
# architecture and must finish endurance on the pack. KinematiK already ships an
# EV lap simulator that runs the QSS lap for each architecture (single motor+diff,
# two-motor axle split, four-motor torque vectoring), layers architecture-aware
# traction limits and a full energy budget (regen included), and reports — HONESTLY
# — whether the pack outlasts the event and what torque vectoring is worth. This
# tab puts that decision in front of the user on the live car and track.
with tab_ev:
  try:
    render_process_library("powertrain", key_prefix="ev_pl")
  except Exception:
    pass
  try:
    _subsystem_cad_import("powertrain", key_prefix="ev")
    _subsystem_cad_import("cooling", key_prefix="ev_cooling")
    st.markdown(
        '<p class="hint" style="margin:0 0 6px;">Pick the <b>motor architecture</b> and '
        'size the pack. KinematiK runs the same lap on each option, with each one '
        'carrying its own weight (more motors = more mass), its own usable drive grip '
        'on corner exit, and a full <b>energy budget with regen</b> — then tells you '
        'which is fastest <i>and</i> whether it finishes endurance. Torque-vectoring\u2019s '
        'yaw benefit is reported separately and never quietly folded into the lap time.</p>',
        unsafe_allow_html=True)

    try:
        _veh_ev = veh
    except Exception:
        _veh_ev = None

    if _veh_ev is None:
        st.warning("The vehicle model isn't available — fix the linkage/geometry first.")
    else:
        # ---- controls ---------------------------------------------------- #
        ec = st.columns(4)
        _arch_labels = {
            "Single motor + diff": ev_mod.Powertrain.SINGLE_DIFF,
            "Two motors (axle split)": ev_mod.Powertrain.TWO_AXLE,
            "Four motors (torque vectoring)": ev_mod.Powertrain.FOUR_TV,
        }
        _picked = ec[0].multiselect(
            "Architectures to compare", list(_arch_labels.keys()),
            default=list(_arch_labels.keys()),
            help="The three EV architectures an FSAE team realistically chooses between.")
        _event = ec[1].selectbox(
            "Event", ["Autocross (1 lap)", "Endurance (22 km)", "Acceleration (75 m)"],
            help="Endurance is the energy-limited event — where the pack size bites.")
        _pack_kwh = ec[2].number_input(
            "Pack energy (kWh)", 1.0, 12.0, value=6.5, step=0.25,
            help="Usable pack is this × usable fraction. FSAE-EV packs are ~5–8 kWh.")
        _power_kw = unum(ec[3], "Power cap (kW)", 20, 80, 60, "kW", step=5.0,
                         help="FS rules cap tractive power at 80 kW; many EV cars run lower to save energy.")

        ec2 = st.columns(4)
        _regen_on = ec2[0].checkbox("Regen", value=True,
                                    help="Capture braking energy back into the pack.")
        _regen_eff = ec2[1].slider("Regen capture %", 0, 80, 55, 5,
                                   help="Round-trip efficiency of braking energy recovered.") / 100.0
        _usable_frac = ec2[2].slider("Pack usable %", 80, 98, 92, 1,
                                     help="Fraction of nameplate energy actually usable.") / 100.0
        _use_aero = ec2[3].checkbox("Use declared aero", value=True,
                                    help="Fold the aerodynamics tab's declared downforce/drag "
                                         "into the lap (cl_a / cd_a). Otherwise no aero.")

        # ---- build params + track --------------------------------------- #
        _ev_params = ev_mod.EVParams(
            pack_energy_kwh=float(_pack_kwh), pack_usable_frac=float(_usable_frac),
            regen_enabled=bool(_regen_on), regen_eff=float(_regen_eff))
        _base = lapsim_mod.LapSimParams(power_w=float(_power_kw) * 1000.0)
        # fold declared aero into the lap if asked and present
        if _use_aero:
            try:
                _led_ev = interfaces_mod.IntegrationLedger.from_dict(st.session_state.ledger)
                _ait = _led_ev.get("aerodynamics")
                _area_ev = float(st.session_state.vp.get("frontal_area_m2", 0.0) or 1.0)
                _rho = 1.225
                if _ait is not None and getattr(_ait, "downforce_n_at_v", None):
                    _dN, _dV = _ait.downforce_n_at_v
                    if _dV and _dV > 0:
                        _base.cl_a = (2.0 * float(_dN)) / (_rho * _dV * _dV)
                if _ait is not None and getattr(_ait, "drag_n_at_v", None):
                    _gN, _gV = _ait.drag_n_at_v
                    if _gV and _gV > 0:
                        _base.cd_a = (2.0 * float(_gN)) / (_rho * _gV * _gV)
            except Exception:
                # The user ASKED for their declared aero. Running the lap on
                # default coefficients while the toggle says "aero: on" is a
                # wrong number wearing a right label — say so, loudly.
                st.warning(
                    "⚠ Couldn't read the declared aero from the Integration "
                    "ledger — this lap is running WITHOUT your downforce/drag "
                    "(default Cl·A / Cd·A). Re-declare aero in Integration, "
                    "then re-run.")

        if _event.startswith("Autocross"):
            _track = lapsim_mod.autocross_track(laps=1)
        elif _event.startswith("Endurance"):
            # ~22 km endurance over a ~1 km lap → ~22 laps on the same layout.
            _track = lapsim_mod.autocross_track(laps=1)
            try:
                _track.laps = 22
            except Exception:
                pass
        else:
            _track = lapsim_mod.acceleration_track()

        _archs = [_arch_labels[p] for p in _picked] or list(ev_mod.Powertrain)
        _sim = ev_mod.EVLapSimulator(_veh_ev, base_params=_base, ev=_ev_params)
        _cmp = _sim.compare(_track, architectures=_archs)
        _best = _cmp.best_on_time()

        # ---- ranked comparison table ------------------------------------ #
        st.markdown('<p class="hint" style="margin:8px 0 2px;"><b>Architecture '
                    'comparison</b> on the same car & track:</p>', unsafe_allow_html=True)
        _rows = []
        _base_t = (_best.event_time if _best else float("nan"))
        for r in sorted(_cmp.results, key=lambda r: (not r.ok, r.event_time if r.ok else 9e9)):
            if not r.ok or not np.isfinite(r.event_time):
                _rows.append(dict(Architecture=r.architecture.label(), **{
                    "Lap (s)": "—", "Event (s)": "run failed", "Δ": "—",
                    "Energy (kWh)": "—", "Pack": "—", "Mass (kg)": "—",
                    "TV yaw (s/lap)": "—"}))
                continue
            _delta = r.event_time - _base_t
            _fin = ("✓ finishes" if r.finishes_event
                    else f"✗ empty @ {r.laps_until_empty:.1f} laps")
            _rows.append(dict(
                Architecture=r.architecture.label() + (" ★" if r is _best else ""),
                **{"Lap (s)": f"{r.lap_time:.2f}",
                   "Event (s)": f"{r.event_time:.2f}",
                   "Δ": ("best" if abs(_delta) < 1e-6 else f"+{_delta:.2f}"),
                   "Energy (kWh)": f"{r.energy_full_event_kwh:.2f}",
                   "Pack": _fin, "Mass (kg)": f"{r.effective_mass_kg:.1f}",
                   "TV yaw (s/lap)": (f"−{r.tv_yaw_benefit_s:.2f}*"
                                      if r.tv_yaw_benefit_s > 0 else "—")}))
        import pandas as _pd_ev
        st.dataframe(_pd_ev.DataFrame(_rows), hide_index=True, width='stretch')
        if _best:
            st.success(f"Fastest that finishes: **{_best.architecture.label()}** — "
                       f"{_best.event_time:.2f} s event, {_best.energy_full_event_kwh:.2f} kWh "
                       f"of a {_pack_kwh*_usable_frac:.2f} kWh usable pack.")
        st.caption("★ = fastest event time. * the TV-yaw column is an UPPER-BOUND benefit "
                   "from left/right torque vectoring, shown separately because a "
                   "quasi-steady lap can't resolve closed-loop yaw control — never added "
                   "into the lap time above.")

        # ---- energy vs laps: does the pack last? ------------------------ #
        gcol = st.columns(2)
        fe = go.Figure()
        _usable_kwh = _pack_kwh * _usable_frac
        _colors = {"single_diff": "#37e0d0", "two_axle": "#ffb02e", "four_tv": "#ff5a52"}
        _maxlaps = 1
        for r in _cmp.results:
            if not r.ok or not np.isfinite(r.energy_per_lap_kwh) or r.energy_per_lap_kwh <= 0:
                continue
            _nl = int(max(2, min(40, np.ceil(_usable_kwh / r.energy_per_lap_kwh) + 2)))
            _maxlaps = max(_maxlaps, _nl)
            xs = list(range(0, _nl + 1))
            ys = [r.energy_per_lap_kwh * x for x in xs]
            fe.add_trace(go.Scatter(
                x=xs, y=ys, name=r.architecture.label(),
                line=dict(color=_colors.get(r.architecture.value, "#9b8cff"), width=3)))
        fe.add_hline(y=_usable_kwh, line=dict(color="#e7ecf1", dash="dash"),
                     annotation_text="usable pack", annotation_position="top left")
        fe.update_layout(
            title="Cumulative energy vs laps — where each pack runs dry",
            xaxis_title="laps", yaxis_title="energy used (kWh)", height=360,
            paper_bgcolor="rgba(0,0,0,0)", plot_bgcolor="rgba(0,0,0,0)",
            font=dict(color="#cdd6df", size=11), margin=dict(l=0, r=0, t=36, b=0),
            legend=dict(bgcolor="rgba(0,0,0,0)"))
        gcol[0].plotly_chart(fe, width='stretch', key="ev_energy")

        # ---- motor torque/power curve (illustrative deployment) --------- #
        # A representative constant-power envelope: torque falls as 1/wheelspeed
        # above base speed, capped by a traction-limited torque at low speed.
        _v = np.linspace(1, 30, 60)  # m/s
        _wheel_r = 0.228
        _P = float(_power_kw) * 1000.0
        _F_power = _P / np.maximum(_v, 0.5)             # tractive force from power
        _F_tract = float(getattr(_base, "mass", 230.0)) * 9.81 * 1.4  # ~grip-limited
        _F = np.minimum(_F_power, _F_tract)
        _uSpd = units_mod.label("km/h")
        _uF = units_mod.label("N")
        _uPw = units_mod.label("kW")
        _v_kmh = _v * 3.6
        fp = go.Figure()
        fp.add_trace(go.Scatter(
            x=[units_mod.from_metric(v, "km/h") for v in _v_kmh],
            y=[units_mod.from_metric(float(f), "N") for f in _F],
            name="Deployable tractive force",
            line=dict(color="#5ad17a", width=3),
            fill="tozeroy", fillcolor="rgba(90,209,122,0.10)"))
        fp.add_trace(go.Scatter(
            x=[units_mod.from_metric(v, "km/h") for v in _v_kmh],
            y=[units_mod.from_metric(float(f), "N") for f in _F_power],
            name="Power-limited",
            line=dict(color="#6f7d8c", width=1, dash="dot")))
        fp.add_hline(y=units_mod.from_metric(float(_F_tract), "N"),
                     line=dict(color="#ff9f43", dash="dot"),
                     annotation_text="grip limit", annotation_position="top right")
        fp.update_layout(
            title="Tractive force envelope @ %.1f %s" % (
                units_mod.from_metric(_power_kw, "kW"), _uPw),
            xaxis_title=f"speed ({_uSpd})",
            yaxis_title=f"force at the tyres ({_uF})", height=360,
            paper_bgcolor="rgba(0,0,0,0)", plot_bgcolor="rgba(0,0,0,0)",
            font=dict(color="#cdd6df", size=11), margin=dict(l=0, r=0, t=36, b=0),
            legend=dict(bgcolor="rgba(0,0,0,0)"))
        gcol[1].plotly_chart(fp, width='stretch', key="ev_torque")

        st.markdown(
            '<p class="hint">The energy plot is the endurance decision: any line that '
            'crosses the dashed pack line before the event distance <b>does not finish</b> '
            'without derating (shedding power, which costs lap time). More motors buy '
            'corner-exit grip and yaw control but carry weight and can draw more energy — '
            'this is exactly the trade your powertrain lead defends to the design judges. '
            'To push further, the same architectures run through the <b>TRANSIENT</b> solver '
            'and correlate in <b>VALIDATION</b> against a real acceleration run.</p>',
            unsafe_allow_html=True)

        if _cmp.warnings or any(r.warnings for r in _cmp.results):
            with st.expander("Notes & honesty flags from the run", expanded=False):
                for w in _cmp.warnings:
                    st.caption("• " + w)
                for r in _cmp.results:
                    for w in (r.warnings or []):
                        st.caption(f"• [{r.architecture.label()}] {w}")

        # =================================================================== #
        #  MOTOR FACE — DXF EXPORT INPUTS                                      #
        # =================================================================== #
        # These three numbers are what the Mesh & DXF tab needs to draw the
        # motor-mount flange. They live here so the user can see and fill them
        # in the same tab where they do the rest of their powertrain work.
        # publish_export_geometry() is called immediately on every rerun so the
        # DXF tab always has fresh values — no button to press.
        st.markdown("---")
        st.markdown("### 📐 Motor face — DXF export inputs")
        st.markdown(
            '<p class="hint" style="margin:0 0 8px;">The <b>Mesh &amp; DXF</b> panel '
            'draws your motor-mount flange from these three numbers. Fill them in '
            'here and the export unlocks automatically — no separate step.</p>',
            unsafe_allow_html=True)
        # Local default for peak torque — the shared _def_peak_tq is defined
        # later (inside the _pt_tabs block), so read the same store directly
        # here to stay self-contained and avoid a forward reference.
        try:
            _mf_store = getattr(get_store(), "ev_excel_params", {}) or {}
            _mf_motor = _mf_store.get("motor", {}) if isinstance(_mf_store, dict) else {}
            _mf_def_tq = float(_mf_motor.get("motor_peak_torque_nm", 230.0) or 230.0)
        except Exception:
            _mf_def_tq = 230.0
        with st.expander("📐 Enter motor face dimensions", expanded=True):
            _mf_cols = st.columns(4)
            _mf_bore = _mf_cols[0].number_input(
                "Motor bore ⌀ (mm)",
                min_value=10.0, max_value=500.0,
                value=float(st.session_state.get("_mf_bore_mm", 80.0)),
                step=1.0, key="mf_bore_mm",
                help="Inner bore diameter of the motor face — the central clearance "
                     "hole the shaft passes through. From your motor datasheet.")
            _mf_pcd = _mf_cols[1].number_input(
                "Bolt PCD (mm)",
                min_value=20.0, max_value=800.0,
                value=float(st.session_state.get("_mf_pcd_mm", 160.0)),
                step=1.0, key="mf_pcd_mm",
                help="Pitch-circle diameter of the motor-face bolt pattern. "
                     "From the motor datasheet or measured face-to-face.")
            _mf_nbolts = int(_mf_cols[2].number_input(
                "Number of bolts",
                min_value=2, max_value=12,
                value=int(st.session_state.get("_mf_n_bolts", 4)),
                step=1, key="mf_n_bolts",
                help="Bolt count on the motor-face flange — typically 4 for FSAE motors."))
            _mf_tq = _mf_cols[3].number_input(
                "Peak torque (N·m)",
                min_value=1.0, max_value=2000.0,
                value=float(st.session_state.get("_mf_peak_tq", _mf_def_tq)),
                step=5.0, key="mf_peak_tq",
                help="Motor peak torque used to size the flange wall thickness. "
                     "Matches the value on your motor datasheet.")
            # Cache the values so they survive reruns without the expander open
            st.session_state["_mf_bore_mm"] = _mf_bore
            st.session_state["_mf_pcd_mm"]  = _mf_pcd
            st.session_state["_mf_n_bolts"] = _mf_nbolts
            st.session_state["_mf_peak_tq"] = _mf_tq
            # Publish immediately — the DXF tab reads this every rerun
            if _mf_bore > 0 and _mf_pcd > 0:
                try:
                    publish_export_geometry("powertrain", {
                        "bore_d_mm":      round(float(_mf_bore), 1),
                        "pcd_mm":         round(float(_mf_pcd), 1),
                        "n_bolts":        int(_mf_nbolts),
                        "hole_d_mm":      9.0,
                        "peak_torque_nm": float(_mf_tq) if _mf_tq > 0 else None,
                        "source":         "EV Powertrain tab — motor face inputs",
                    })
                    st.success(
                        f"✓ Motor face locked in: ⌀{_mf_bore:g} mm bore, "
                        f"{_mf_pcd:g} mm PCD, {_mf_nbolts} bolts, "
                        f"{_mf_tq:g} N·m — the Mesh & DXF panel will now draw "
                        "the flange.")
                except Exception as _mf_err:
                    st.warning(f"Couldn't publish motor face geometry: {_mf_err}")
            else:
                st.info("Enter bore diameter and bolt PCD above to unlock the DXF export.")

        # =================================================================== #
        #  POWERTRAIN INTEGRATION  —  retire the Excel/screenshot workflow.    #
        # =================================================================== #
        # Everything below replaces a specific artifact the powertrain sub-team
        # still keeps in Excel or as a slide screenshot, and — crucially — wires
        # the result into the INTEGRATION ledger so the cross-team checks
        # (driveline torque, HV voltage, thermal, mount loads) finally include
        # powertrain. This is what makes their traditional, siloed flow obsolete.
        st.markdown("---")
        st.markdown("### 🔗 Make it the single source of truth")
        st.markdown(
            '<p class="hint" style="margin:0 0 6px;">The powertrain numbers you '
            'commit here flow straight into the car-wide <b>INTEGRATION</b> ledger, '
            'so every other sub-team reads the same truth — no more re-keying '
            'the spreadsheet, screenshotting a spec sheet, or finding out at '
            'assembly that the motor torque overloads the driveline. Each panel '
            'below replaces something the team still does by hand.</p>',
            unsafe_allow_html=True)

        # representative motor numbers for the integration tools; defaults are
        # FSAE-EV-typical and clearly editable.
        _arch_best_label = (_best.architecture.label() if _best
                            else "Single motor + diff")
        _n_motors = (_best.architecture.n_motors() if _best else 1)

        _pt_tabs = st.tabs([
            "📈 Power & RPM explained",
            "⚙️ Gear ratio & sprocket",
            "🌡️ Cooling rig & fan",
            "📤 Publish to ledger",
            "🔀 Cross-team checks",
            "📋 Live spec sheet",
        ])

        # ---------- shared motor inputs (used across the panels) ----------- #
        # Pull stored Excel params if the team already imported their workbook,
        # so this is pre-filled from their own data when available.
        try:
            _ev_store = getattr(get_store(), "ev_excel_params", {}) or {}
        except Exception:
            _ev_store = {}
        _motor_store = _ev_store.get("motor", {}) if isinstance(_ev_store, dict) else {}
        _pack_store = _ev_store.get("pack", {}) if isinstance(_ev_store, dict) else {}
        _def_peak_tq = float(_motor_store.get("motor_peak_torque_nm", 230.0) or 230.0)
        _def_peak_pw = float(_motor_store.get("motor_peak_power_kw", float(_power_kw)) or _power_kw)
        _def_redline = float(_motor_store.get("motor_max_rpm", 6000.0) or 6000.0)
        _def_redline = min(max(_def_redline, 3000.0), 30000.0)
        _def_hv_v = float(_pack_store.get("pack_voltage_v", 400.0) or 400.0)
        _def_wheel_r = float(_motor_store.get("wheel_diam_in", 18.0) or 18.0) * 0.0254 / 2.0
        if not (0.15 <= _def_wheel_r <= 0.30):
            _def_wheel_r = 0.228

        # ================================================================= #
        #  PANEL 0 — Power & RPM explained  (kills the chat-thread confusion) #
        # ================================================================= #
        # Resolves the exact misunderstanding between the chassis and powertrain
        # leads: "are we limiting rpm to 7k because power can't exceed 80 kW?" and
        # "peak 80 kW AND 80 kW continuous, not sure how that works." Both are
        # answered here with the team's own numbers, on one curve, so nobody has
        # to litigate it in Discord again.
        with _pt_tabs[0]:
            st.markdown(
                '<p class="hint" style="margin:0 0 6px;">A motor\u2019s <b>power cap and '
                'its RPM limit are two different things</b>, and that trips teams up '
                'constantly. Set your three datasheet numbers and KinematiK draws the '
                'real envelope: where peak power is reached (<b>base speed</b>), how '
                'torque falls while power stays flat to redline, and what '
                '<b>peak vs continuous</b> actually means under the FSAE 80 kW cap.</p>',
                unsafe_allow_html=True)

            mcol = st.columns(4)
            _me_tq = unum(mcol[0], "Peak torque (N·m)", 20.0, 600.0,
                          _def_peak_tq, "N·m", step=5.0, key="pti_me_tq")
            _me_pw = unum(mcol[1], "Peak power (kW)", 10.0, 200.0,
                          _def_peak_pw, "kW", step=5.0, key="pti_me_pw")
            _me_rl = mcol[2].number_input("Redline (rpm)", 3000.0, 30000.0,
                                          value=_def_redline, step=500.0, key="pti_me_rl")
            _me_cont = mcol[3].slider("Continuous power (% of peak)", 30, 100, 70, 5,
                                      key="pti_me_cont",
                                      help="What cooling lets you sustain. Always ≤ peak "
                                           "— this is the thermal limit, set by the "
                                           "cooling rig, not a separate higher number.")

            try:
                _env = pti_mod.motor_envelope(
                    _me_tq, _me_pw, _me_rl,
                    continuous_frac=_me_cont / 100.0)
                # Make the live envelope available to the cross-discipline
                # myth-buster (Integration tab) so powertrain claims typed there
                # check against the same numbers shown here.
                st.session_state["pti_last_envelope"] = _env

                # --- dual-axis torque + power vs RPM ---------------------- #
                # Torque axis respects the active unit system (N·m or lbf·ft).
                _tq_label = units_mod.label("N·m")        # "N·m" or "lbf·ft"
                _pw_label = units_mod.label("kW")          # "kW"  or "hp"
                _tq_values = [units_mod.from_metric(float(v), "N·m")
                               for v in _env.torque_nm]
                _pw_values = list(_env.power_kw)           # kW stays on right axis
                import plotly.graph_objects as _go_m
                fm = _go_m.Figure()
                fm.add_trace(_go_m.Scatter(
                    x=_env.rpm, y=_tq_values,
                    name=f"Torque ({_tq_label})",
                    line=dict(color="#37e0d0", width=3)))
                fm.add_trace(_go_m.Scatter(
                    x=_env.rpm, y=_pw_values, name=f"Power ({_pw_label})", yaxis="y2",
                    line=dict(color="#ff9f43", width=3)))
                # FSAE cap line on the power axis
                fm.add_trace(_go_m.Scatter(
                    x=[_env.rpm.min(), _env.rpm.max()],
                    y=[_env.rule_cap_kw, _env.rule_cap_kw], yaxis="y2",
                    name=f"FSAE {_env.rule_cap_kw:.0f} kW cap", mode="lines",
                    line=dict(color="#ff5a52", width=1.5, dash="dash")))
                # continuous power band
                fm.add_trace(_go_m.Scatter(
                    x=[_env.rpm.min(), _env.rpm.max()],
                    y=[_env.continuous_power_kw, _env.continuous_power_kw], yaxis="y2",
                    name=f"Continuous {_env.continuous_power_kw:.0f} kW", mode="lines",
                    line=dict(color="#9b8cff", width=1.5, dash="dot")))
                # base-speed marker
                fm.add_vline(x=_env.base_speed_rpm,
                             line=dict(color="#e7ecf1", width=1.2, dash="dot"),
                             annotation_text=f"base speed {_env.base_speed_rpm:.0f} rpm",
                             annotation_position="top")
                fm.update_layout(
                    title="Motor envelope — power flat to redline, torque falls; "
                          "power ≠ rpm limit",
                    xaxis_title="motor speed (rpm)",
                    yaxis=dict(title=f"torque ({_tq_label})", color="#37e0d0"),
                    yaxis2=dict(title=f"power ({_pw_label})", color="#ff9f43",
                                overlaying="y", side="right"),
                    height=380, paper_bgcolor="rgba(0,0,0,0)",
                    plot_bgcolor="rgba(0,0,0,0)", font=dict(color="#cdd6df", size=11),
                    margin=dict(l=0, r=0, t=80, b=0),
                    legend=dict(bgcolor="rgba(0,0,0,0)", orientation="h",
                                yanchor="bottom", y=1.02))
                st.plotly_chart(fm, width='stretch', key="pti_envelope")

                _em = st.columns(4)
                _em[0].markdown(metric("Base speed",
                    f"{_env.base_speed_rpm:.0f}", "rpm"), unsafe_allow_html=True)
                _em[1].markdown(metric("Power @ redline",
                    f"{_env.power_at_redline_kw():.0f}", "kW"), unsafe_allow_html=True)
                _em[2].markdown(metric("Peak (usable)",
                    f"{_env.peak_power_kw:.0f}", "kW"), unsafe_allow_html=True)
                _em[3].markdown(metric("Continuous",
                    f"{_env.continuous_power_kw:.0f}", "kW"), unsafe_allow_html=True)

                try:
                    record_activity(
                        "powertrain", "calculation",
                        f"Motor envelope: base speed {_env.base_speed_rpm:.0f} rpm, "
                        f"peak {_env.peak_power_kw:.0f} kW, continuous "
                        f"{_env.continuous_power_kw:.0f} kW vs "
                        f"{_env.rule_cap_kw:.0f} kW FSAE cap"
                        f"{' (OVER CAP)' if getattr(_env,'over_cap',False) else ''}")
                except Exception:
                    pass

                # --- the two plain-language answers ----------------------- #
                st.markdown("##### Does capping power cap RPM?")
                st.info(_env.explanation())
                st.markdown("##### What does 'peak vs continuous' mean?")
                st.info(_env.peak_vs_continuous_note())
                if _env.over_cap:
                    for _nt in _env.notes:
                        if "exceeds the FSAE" in _nt:
                            st.error(_nt)

                # --- myth buster: user types their assumption, math checks it --- #
                st.markdown("##### Myth buster")
                st.markdown(
                    '<p class="hint" style="margin:0 0 8px;">Type any assumption '
                    'about this motor \u2014 RPM limits, power caps, torque at a speed, '
                    'top speed, continuous power \u2014 and the math will tell you '
                    'whether it holds against these numbers. No AI.</p>',
                    unsafe_allow_html=True)

                _fd_ctx = float(st.session_state.get("_pti_final_drive", 3.5))

                _mb_col1, _mb_col2 = st.columns([5, 1])
                _mb_input = _mb_col1.text_input(
                    "Your assumption",
                    placeholder='e.g. "80 kW cap means we limit RPM to 7000" '
                                'or "torque at 5000 rpm is 150 Nm"',
                    label_visibility="collapsed",
                    key="pti_myth_input")
                _mb_check = _mb_col2.button(
                    "Check it \u2192", key="pti_myth_btn", use_container_width=True)

                _vcfg_mb = {
                    "myth":    dict(label="\u274c Myth",    bg="#1f1214", border="#5a2422",
                                   accent="#ff5a52", badge_bg="#3d1a18"),
                    "depends": dict(label="\u26a0\ufe0f Depends", bg="#171510", border="#5a4317",
                                   accent="#ffb02e", badge_bg="#3a2c10"),
                    "true":    dict(label="\u2705 True",    bg="#0f1c1a", border="#1f4d49",
                                   accent="#37e0d0", badge_bg="#0e2a27"),
                    "unknown": dict(label="\u2753 Unknown",  bg="#131318", border="#303050",
                                   accent="#9b8cff", badge_bg="#1a1a2e"),
                }

                def _render_verdict_card(claim_text, result):
                    _v = _vcfg_mb.get(result.verdict, _vcfg_mb["unknown"])
                    import re as _re2
                    _hl = _re2.sub(
                        r'(\b\d[\d\s,.]*(?:kW|rpm|km/h|N\u00b7m|%|:\d)?)',
                        lambda m: (
                            '<span style="font-family:\'JetBrains Mono\',monospace;'
                            'font-weight:600;color:' + _v["accent"] + ';">'
                            + m.group() + '</span>'),
                        result.explanation)
                    st.markdown(
                        f'<div style="background:{_v["bg"]};border:1px solid {_v["border"]};'
                        f'border-left:3px solid {_v["accent"]};border-radius:12px;'
                        f'padding:.85rem 1.1rem;margin:.4rem 0;">'
                        f'<div style="display:flex;align-items:center;gap:.6rem;margin-bottom:.45rem;">'
                        f'<span style="font-family:\'JetBrains Mono\',monospace;font-size:.68rem;'
                        f'font-weight:700;letter-spacing:.1em;text-transform:uppercase;'
                        f'background:{_v["badge_bg"]};color:{_v["accent"]};'
                        f'border:1px solid {_v["border"]};border-radius:6px;'
                        f'padding:.15rem .5rem;white-space:nowrap;flex:0 0 auto;">{_v["label"]}</span>'
                        f'<span style="font-size:.85rem;font-style:italic;color:#8d99a6;">'
                        f'\u201c{claim_text}\u201d</span></div>'
                        f'<p style="margin:0;font-size:.83rem;line-height:1.65;color:#c4cdd6;">{_hl}</p>'
                        f'</div>',
                        unsafe_allow_html=True)

                # show result for the current input
                _checked_input = st.session_state.get("pti_myth_checked_input", "")
                _checked_result = st.session_state.get("pti_myth_checked_result", None)

                if _mb_check and _mb_input.strip():
                    _result = pti_mod.check_assumption(
                        _mb_input, _env,
                        gear_final_drive=_fd_ctx,
                        wheel_r_m=_def_wheel_r)
                    st.session_state["pti_myth_checked_input"] = _mb_input
                    st.session_state["pti_myth_checked_result"] = _result
                    _checked_input = _mb_input
                    _checked_result = _result
                elif _mb_check and not _mb_input.strip():
                    st.caption("Type an assumption first.")

                if _checked_result is not None:
                    _render_verdict_card(_checked_input, _checked_result)

                # reference myths (collapsed)
                with st.expander("Reference — known myths for these numbers", expanded=False):
                    _ref_checks = pti_mod.power_rpm_myth_checks(
                        _env, gear_final_drive=_fd_ctx, wheel_r_m=_def_wheel_r)
                    for _rc in _ref_checks:
                        _rv = _vcfg_mb.get(_rc.verdict, _vcfg_mb["unknown"])
                        import re as _re3
                        _rhl = _re3.sub(
                            r'(\b\d[\d\s,.]*(?:kW|rpm|km/h|N\u00b7m|%|:\d)?)',
                            lambda m: (
                                '<span style="font-family:\'JetBrains Mono\',monospace;'
                                'font-weight:600;color:' + _rv["accent"] + ';">'
                                + m.group() + '</span>'),
                            _rc.correction)
                        st.markdown(
                            f'<div style="background:{_rv["bg"]};border:1px solid {_rv["border"]};'
                            f'border-left:3px solid {_rv["accent"]};border-radius:10px;'
                            f'padding:.75rem 1rem;margin:.35rem 0;">'
                            f'<div style="display:flex;align-items:center;gap:.5rem;margin-bottom:.35rem;">'
                            f'<span style="font-family:\'JetBrains Mono\',monospace;font-size:.65rem;'
                            f'font-weight:700;letter-spacing:.1em;text-transform:uppercase;'
                            f'background:{_rv["badge_bg"]};color:{_rv["accent"]};'
                            f'border:1px solid {_rv["border"]};border-radius:5px;'
                            f'padding:.12rem .45rem;white-space:nowrap;flex:0 0 auto;">{_rv["label"]}</span>'
                            f'<span style="font-size:.84rem;font-weight:600;color:#e7ecf1;">{_rc.claim}</span></div>'
                            f'<p style="margin:0;font-size:.8rem;line-height:1.6;color:#a8b4bf;">{_rhl}</p>'
                            f'</div>',
                            unsafe_allow_html=True)
                st.caption("Share this tab in the channel instead of re-explaining: it "
                           "answers the power-vs-rpm and peak-vs-continuous questions "
                           "with the actual motor numbers, so the thread doesn\u2019t "
                           "happen twice.")
            except Exception as _mee:
                st.warning(f"Motor envelope unavailable: {_mee}")

        # ================================================================= #
        #  PANEL 1 — Gear-ratio solver + sprocket                             #
        # ================================================================= #
        with _pt_tabs[1]:
            st.markdown(
                '<p class="hint" style="margin:0 0 6px;">The <b>gear-ratio '
                'solver</b> sweeps final-drive ratios against '
                'your real motor curve and the actual car mass, then picks the optimum '
                'for what you\u2019re chasing. Pick the objective, set the motor, and read '
                'the winner \u2014 then size the output-shaft sprocket and get the tooth '
                'force your FEA has to clear (the slide-4 task).</p>',
                unsafe_allow_html=True)

            gcol = st.columns(4)
            _gm_tq = unum(gcol[0], "Motor peak torque (N·m)", 20.0, 600.0,
                          _def_peak_tq, "N·m", step=5.0, key="pti_gm_tq")
            _gm_pw = unum(gcol[1], "Motor peak power (kW)", 10.0, 200.0,
                          _def_peak_pw, "kW", step=5.0, key="pti_gm_pw")
            _gm_rl = gcol[2].number_input("Redline (rpm)", 3000.0, 30000.0,
                                          value=_def_redline, step=500.0,
                                          key="pti_gm_rl")
            _gm_wr = unum(gcol[3], "Loaded wheel radius (m)", 0.15, 0.30,
                          _def_wheel_r, "m", step=0.005, fmt="%.3f", key="pti_gm_wr")

            gcol2 = st.columns(4)
            _g_obj_label = gcol2[0].selectbox(
                "Optimise for", [o.label() for o in pti_mod.GearObjective],
                index=2, key="pti_g_obj",
                help="Acceleration wants a shorter (numerically larger) ratio; top "
                     "speed a taller one; balanced is the autocross/endurance pick.")
            _g_obj = next(o for o in pti_mod.GearObjective
                          if o.label() == _g_obj_label)
            _g_lo = gcol2[1].number_input("Sweep from", 1.5, 8.0, value=2.5,
                                          step=0.25, key="pti_g_lo")
            _g_hi = gcol2[2].number_input("Sweep to", 1.5, 10.0, value=5.0,
                                          step=0.25, key="pti_g_hi")
            _g_n = int(gcol2[3].number_input("Steps", 4, 30, value=11, step=1,
                                             key="pti_g_n"))

            try:
                _mmap = lap_mod.MotorMap.from_peak(
                    _gm_tq, _gm_pw, _gm_rl, final_drive=3.5, wheel_radius_m=_gm_wr)
                _veh_mass = float(getattr(_veh_ev, "mass_kg", None)
                                  or st.session_state.vp.get("mass_kg", 230.0) or 230.0)
                # add the architecture mass delta so the gear choice is on the
                # actual car the user is comparing
                if _best is not None:
                    _veh_mass = float(_best.effective_mass_kg)
                _solver = pti_mod.GearRatioSolver(
                    _mmap, mass_kg=_veh_mass, wheel_r_m=_gm_wr,
                    drivetrain_eff=0.90, mu=1.4)
                _ratios = list(np.linspace(min(_g_lo, _g_hi), max(_g_lo, _g_hi), _g_n))
                _sweep = _solver.sweep(_ratios, _g_obj)

                import pandas as _pd_g
                st.dataframe(_pd_g.DataFrame(_sweep.as_table()),
                             hide_index=True, width='stretch')
                if _sweep.best is not None:
                    _b = _sweep.best
                    st.success(
                        f"Best final drive for **{_g_obj.label()}**: "
                        f"**{_b.final_drive:.2f}:1** — 0–75 m in {_b.accel_0_75_s:.2f} s, "
                        f"top speed {_b.top_speed_kmh:.0f} km/h "
                        f"({'redline-limited' if _b.redline_limited else 'power/drag-limited'}).")
                    for _nt in _b.notes:
                        st.caption("• " + _nt)
                    # stash the chosen ratio for the other panels / ledger
                    st.session_state["_pti_final_drive"] = float(_b.final_drive)
                    st.session_state["_pti_peak_tq"] = float(_gm_tq)
                    st.session_state["_pti_peak_pw"] = float(_gm_pw)
                    st.session_state["_pti_hv_v"] = float(_def_hv_v)

                # --- sprocket / output-shaft design (slide 4) ------------- #
                st.markdown("##### Output-shaft sprocket")
                scol = st.columns(3)
                _chain_label = scol[0].selectbox(
                    "Chain", list(pti_mod.CHAIN_PITCH_MM.keys()), index=1,
                    key="pti_chain")
                _motor_teeth = int(scol[1].number_input(
                    "Motor pinion teeth", 9, 30, value=14, step=1, key="pti_pinion"))
                _fd_for_sprk = float(st.session_state.get(
                    "_pti_final_drive", _sweep.best.final_drive if _sweep.best else 3.5))
                scol[2].metric("Designing for ratio", f"{_fd_for_sprk:.2f}:1")

                _sd = pti_mod.sprocket_design(
                    _fd_for_sprk, _gm_tq, _chain_label, motor_sprocket_teeth=_motor_teeth)
                _sm = st.columns(4)
                _sm[0].markdown(metric("Driven teeth",
                    f"{_sd.driven_sprocket_teeth}", ""), unsafe_allow_html=True)
                _sm[1].markdown(metric("Driven pitch Ø",
                    f"{_sd.driven_pitch_dia_mm:.0f}", "mm"), unsafe_allow_html=True)
                _sm[2].markdown(metric("Chain tension",
                    f"{_sd.chain_tension_n:.0f}", "N"), unsafe_allow_html=True)
                _sm[3].markdown(metric("Tooth force (FEA)",
                    f"{_sd.tooth_force_n:.0f}", "N"), unsafe_allow_html=True)
                _out_tq = pti_mod.driveline_peak_torque_nm(_fd_for_sprk, _gm_tq)
                st.caption(
                    f"Actual integer-tooth ratio {_sd.actual_ratio:.2f}:1 "
                    f"({_motor_teeth}→{_sd.driven_sprocket_teeth} teeth). "
                    f"Output-shaft peak torque ≈ **{_out_tq:.0f} N·m** — that\u2019s the "
                    f"load the sprocket FEA and the driveline rating must clear. "
                    f"The **{_sd.tooth_force_n:.0f} N** tooth force is your FEA input.")
                for _w in _sd.warnings:
                    st.warning(_w)
                st.session_state["_pti_out_torque"] = float(_out_tq)
                st.session_state["_pti_sprocket"] = dict(
                    motor=_motor_teeth, driven=_sd.driven_sprocket_teeth,
                    tension=float(_sd.chain_tension_n))
            except Exception as _ge:
                st.warning(f"Gear solver unavailable: {_ge}")

        # ================================================================= #
        #  PANEL 2 — Cooling test rig + SPAL fan operating point             #
        # ================================================================= #
        with _pt_tabs[2]:
            st.markdown(
                '<p class="hint" style="margin:0 0 6px;">The <b>cooling test rig</b> '
                'exists to pin down one number: how much the coolant '
                'loop resists flow. KinematiK takes the rig\u2019s <b>SPAL VA14-AP11/C-34A</b> '
                'fan curve, crosses it with that loop restriction to find the real '
                'operating airflow, and checks it against the heat your motor and pack '
                'actually reject. The placeholder radiator CAD stops being a guess.</p>',
                unsafe_allow_html=True)

            ccol = st.columns(4)
            _heat_default = pti_mod.estimate_motor_heat_w(
                float(_gm_pw if '_gm_pw' in dir() else _power_kw))
            _heat_w = ccol[0].number_input(
                "Heat to reject — motor+inverter (W)", 200.0, 20000.0,
                value=float(round(_heat_default, 0)), step=100.0, key="pti_heat",
                help="Estimated from (1−efficiency) over an endurance duty cycle; "
                     "replace with a measured dyno/thermal number when you have it.")
            _pack_heat_w = ccol[1].number_input(
                "Pack heat add (W)", 0.0, 10000.0, value=600.0, step=100.0,
                key="pti_packheat",
                help="Accumulator joule heating that shares the loop, if any.")
            _rig_flow = ccol[2].number_input(
                "Rig measured flow (m³/h)", 50.0, 700.0, value=400.0, step=10.0,
                key="pti_rigflow",
                help="A point you read off the cooling test rig: airflow…")
            _rig_dp = ccol[3].number_input(
                "…at static pressure (Pa)", 10.0, 349.0, value=150.0, step=10.0,
                key="pti_rigdp", help="…and the static pressure at that flow. "
                "KinematiK backs out the loop restriction k = Δp/Q².")

            ccol2 = st.columns(2)
            _air_dt = ccol2[0].slider("Design air-side ΔT (°C)", 5, 40, 20, 1,
                                      key="pti_airdt",
                                      help="Temperature rise of the air through the "
                                           "radiator core at the design point.")
            try:
                _fan = pti_mod.FanCurve.spal_default()
                _k = pti_mod.system_k_from_point(_rig_flow, _rig_dp)
                _op = pti_mod.cooling_operating_point(
                    _fan, _k, heat_to_reject_w=float(_heat_w + _pack_heat_w),
                    air_delta_t_c=float(_air_dt))

                # fan curve + system curve + operating point plot
                import plotly.graph_objects as _go_c
                _qs = np.linspace(0, _fan.flow_m3h.max(), 200)
                fc = _go_c.Figure()
                fc.add_trace(_go_c.Scatter(
                    x=_fan.flow_m3h, y=_fan.dp_pa, name="SPAL fan curve",
                    line=dict(color="#37e0d0", width=3)))
                fc.add_trace(_go_c.Scatter(
                    x=_qs, y=_k * _qs * _qs, name="System resistance (your loop)",
                    line=dict(color="#ff9f43", width=2, dash="dot")))
                fc.add_trace(_go_c.Scatter(
                    x=[_op.flow_m3h], y=[_op.static_pressure_pa],
                    name="Operating point", mode="markers",
                    marker=dict(color="#ff5a52", size=12, symbol="x")))
                fc.update_layout(
                    title="Fan vs loop — where the cooling actually runs",
                    xaxis_title="airflow (m³/h)", yaxis_title="static pressure (Pa)",
                    height=340, paper_bgcolor="rgba(0,0,0,0)",
                    plot_bgcolor="rgba(0,0,0,0)", font=dict(color="#cdd6df", size=11),
                    margin=dict(l=0, r=0, t=36, b=0),
                    legend=dict(bgcolor="rgba(0,0,0,0)"))
                ccol2[1].plotly_chart(fc, width='stretch', key="pti_fan")

                _om = st.columns(4)
                _om[0].markdown(metric("Operating airflow",
                    f"{_op.flow_m3h:.0f}", "m³/h"), unsafe_allow_html=True)
                _om[1].markdown(metric("= airflow",
                    f"{_op.flow_cms:.3f}", "m³/s"), unsafe_allow_html=True)
                _om[2].markdown(metric("Cooling capacity",
                    f"{_op.cooling_capacity_w:.0f}", "W"), unsafe_allow_html=True)
                _om[3].markdown(metric("Margin",
                    f"{_op.margin_w:+.0f}", "W"), unsafe_allow_html=True)

                try:
                    record_activity(
                        "cooling", "condition",
                        f"Heat load {(_heat_w+_pack_heat_w):.0f} W "
                        f"(motor+inverter {_heat_w:.0f} W, pack {_pack_heat_w:.0f} W), "
                        f"air-side ΔT {_air_dt:g}°C, rig point "
                        f"{_rig_flow:g} m³/h @ {_rig_dp:g} Pa")
                    record_activity(
                        "cooling", "calculation",
                        f"Cooling operating point: {_op.flow_m3h:.0f} m³/h, "
                        f"capacity {_op.cooling_capacity_w:.0f} W, margin "
                        f"{_op.margin_w:+.0f} W "
                        f"({'adequate' if _op.adequate else 'UNDER-COOLED'})")
                except Exception:
                    pass

                if _op.adequate:
                    st.success(
                        f"At {_op.flow_m3h:.0f} m³/h the fan carries "
                        f"{_op.cooling_capacity_w:.0f} W vs {_heat_w+_pack_heat_w:.0f} W "
                        f"needed — **adequate** with {_op.margin_w:.0f} W to spare.")
                else:
                    st.error(
                        f"**Under-cooled by {-_op.margin_w:.0f} W.** The loop is too "
                        "restrictive for this fan at the design ΔT.")
                for _w in _op.warnings:
                    st.caption("• " + _w)
                # stash cooling airflow requirement for the ledger publish
                st.session_state["_pti_cooling_cms"] = float(_op.flow_cms)
                st.session_state["_pti_heat_w"] = float(_heat_w)
                st.caption("This airflow is what powertrain *requires*; publishing it "
                           "to the ledger lets the cross-team thermal check confirm "
                           "the cooling package can actually move it.")
            except Exception as _ce:
                st.warning(f"Cooling operating point unavailable: {_ce}")

            # ---- Radiator core face — DXF export inputs ------------------- #
            # The Cooling Mesh & DXF tab draws the radiator core face from
            # these two numbers. They live here alongside the rig inputs so the
            # user enters all cooling geometry in one place.
            st.markdown("---")
            st.markdown("#### 📐 Radiator core face — DXF export inputs")
            st.markdown(
                '<p class="hint" style="margin:0 0 8px;">The <b>Mesh &amp; DXF</b> panel '
                'draws your radiator core face from these dimensions. Fill them in '
                'once and the export unlocks automatically.</p>',
                unsafe_allow_html=True)
            _rc_cols = st.columns(3)
            _rc_w = _rc_cols[0].number_input(
                "Core width (mm)",
                min_value=50.0, max_value=1000.0,
                value=float(st.session_state.get("_rc_w_mm", 280.0)),
                step=5.0, key="rc_w_mm",
                help="Width of the radiator core face — the dimension across the "
                     "car. From your radiator datasheet or sizing calculation.")
            _rc_h = _rc_cols[1].number_input(
                "Core height (mm)",
                min_value=50.0, max_value=1000.0,
                value=float(st.session_state.get("_rc_h_mm", 200.0)),
                step=5.0, key="rc_h_mm",
                help="Height of the radiator core face. Together with width this "
                     "defines the cross-section the DXF will draw.")
            _rc_depth = _rc_cols[2].number_input(
                "Core depth (mm)",
                min_value=0.0, max_value=200.0,
                value=float(st.session_state.get("_rc_depth_mm", 32.0)),
                step=1.0, key="rc_depth_mm",
                help="Radiator core depth (thickness). Used for notes on the DXF "
                     "— does not change the 2D face outline.")
            st.session_state["_rc_w_mm"]     = _rc_w
            st.session_state["_rc_h_mm"]     = _rc_h
            st.session_state["_rc_depth_mm"] = _rc_depth
            if _rc_w > 0 and _rc_h > 0:
                try:
                    publish_export_geometry("cooling", {
                        "core_w_mm":    round(float(_rc_w), 1),
                        "core_h_mm":    round(float(_rc_h), 1),
                        "core_depth_mm": round(float(_rc_depth), 1) or None,
                        "source": "Cooling rig tab — core face inputs",
                    })
                    st.success(
                        f"✓ Radiator core face locked in: {_rc_w:g} × {_rc_h:g} mm "
                        f"({_rc_depth:g} mm deep) — the Mesh & DXF panel will now draw "
                        "the core face.")
                except Exception as _rc_err:
                    st.warning(f"Couldn't publish radiator core geometry: {_rc_err}")
            else:
                st.info("Enter core width and height above to unlock the cooling DXF export.")

        # ================================================================= #
        #  PANEL 3 — Publish powertrain to the integration ledger           #
        # ================================================================= #
        with _pt_tabs[3]:
            st.markdown(
                '<p class="hint" style="margin:0 0 6px;">This is the step the team '
                'has been missing. <b>Every other sub-team publishes their numbers to '
                'the ledger; powertrain didn\u2019t</b> — which is exactly why the '
                'miscommunication happens. Press the button and powertrain\u2019s torque, '
                'power, HV voltage, mass, heat and mount loads become visible to the '
                'whole car, and the cross-team checks start including you.</p>',
                unsafe_allow_html=True)

            pcol = st.columns(4)
            _pub_tq = unum(pcol[0], "Peak motor torque (N·m)", 20.0, 600.0,
                           float(st.session_state.get("_pti_peak_tq", _def_peak_tq)),
                           "N·m", step=5.0, key="pti_pub_tq")
            _pub_out_tq = unum(pcol[1], "Output-shaft torque (N·m)", 20.0, 3000.0,
                               float(st.session_state.get("_pti_out_torque",
                                     pti_mod.driveline_peak_torque_nm(3.5, _pub_tq))),
                               "N·m", step=10.0, key="pti_pub_outtq",
                               help="Peak torque after the gear reduction — what the "
                                    "driveline must survive. From the gear panel.")
            _pub_pw = unum(pcol[2], "Peak power (kW)", 10.0, 200.0,
                           float(st.session_state.get("_pti_peak_pw", _def_peak_pw)),
                           "kW", step=5.0, key="pti_pub_pw",
                           help="Motor's declared peak. May exceed the FSAE 80 kW "
                                "tractive cap — the car must electronically limit to "
                                "80 kW, which the envelope and rules checks enforce.")
            _pub_hv = unum(pcol[3], "HV voltage (V)", 60.0, 600.0,
                           float(st.session_state.get("_pti_hv_v", _def_hv_v)),
                           "V", step=4.0, key="pti_pub_hv")

            pcol2 = st.columns(4)
            _pub_mass = unum(pcol2[0], "Motor+drivetrain mass (kg)", 5.0, 80.0,
                             18.0 + 6.0 * (_n_motors - 1), "kg", step=0.5,
                             key="pti_pub_mass")
            _pub_heat = unum(pcol2[1], "Heat reject (W)", 100.0, 20000.0,
                             float(st.session_state.get("_pti_heat_w",
                                   pti_mod.estimate_motor_heat_w(_pub_pw))),
                             "W", step=100.0, key="pti_pub_heat")
            _pub_cool = pcol2[2].number_input(
                "Cooling airflow req (m³/s)", 0.0, 2.0,
                value=float(st.session_state.get("_pti_cooling_cms", 0.10)),
                step=0.01, format="%.3f", key="pti_pub_cool")
            _pub_mounts = int(pcol2[3].number_input(
                "Mount points", 2, 8, value=4, step=1, key="pti_pub_mounts"))

            pcol3 = st.columns(3)
            _pub_mount_load = unum(pcol3[0], "Peak mount load (N)", 100.0, 20000.0,
                                   float(round(_pub_out_tq / 0.15, 0)), "N", step=100.0,
                                   key="pti_pub_mountload",
                                   help="Peak reaction the motor/diff mount feeds into "
                                        "the chassis (≈ torque / mount arm). The chassis "
                                        "check compares this to what they designed for.")
            _pub_owner = pcol3[1].text_input("Owner", value="", key="pti_pub_owner",
                                             placeholder="who owns these numbers")
            _pub_est = pcol3[2].checkbox("These are estimates", value=True,
                                         key="pti_pub_est",
                                         help="Leave on until the numbers come from CAD "
                                              "/ measurement. The board flags estimates "
                                              "so nothing looks more certain than it is.")
            _pub_rationale = st.text_input(
                "Rationale (the 'why' judges ask for)", value="", key="pti_pub_why",
                placeholder="e.g. torque from motor datasheet peak; mass from CAD; "
                            "heat from endurance duty estimate")

            if st.button("📤 Publish powertrain to the INTEGRATION ledger",
                         key="pti_publish", type="primary"):
                try:
                    _led_pt = interfaces_mod.IntegrationLedger.from_dict(
                        st.session_state.ledger)
                    _it = (_led_pt.get("powertrain")
                           or interfaces_mod.SubsystemInterface(name="powertrain"))
                    _it.peak_torque_nm = float(_pub_tq)
                    _it.peak_power_kw = float(_pub_pw)
                    _it.voltage_v = float(_pub_hv)
                    _it.mass_kg = float(_pub_mass)
                    _it.heat_reject_w = float(_pub_heat)
                    _it.cooling_airflow_cms = float(_pub_cool)
                    _it.mount_load_n = float(_pub_mount_load)
                    _it.mount_points = int(_pub_mounts)
                    _it.mounts_on = "chassis"
                    _it.is_estimate = bool(_pub_est)
                    _it.owner = _pub_owner
                    _it.rationale = _pub_rationale
                    import datetime as _dt_pt
                    _it.updated_on = _dt_pt.date.today().isoformat()
                    _led_pt.set(_it)
                    # also record the driveline torque limit so the check has a
                    # rating to compare the output torque against
                    _led_pt.driveline_torque_limit_nm = float(_pub_out_tq)
                    publish_ledger(_led_pt.as_dict())
                    if float(_pub_pw) > pti_mod.FSAE_TRACTIVE_POWER_CAP_KW + 1e-6:
                        st.error(
                            f"⚠️ Declared peak power {_pub_pw:.0f} kW exceeds the FSAE "
                            f"{pti_mod.FSAE_TRACTIVE_POWER_CAP_KW:.0f} kW tractive cap. "
                            "The controller must limit tractive power to 80 kW — "
                            "publish the capped figure so the whole team plans to the "
                            "real ceiling.")
                    st.success(
                        f"Published. Powertrain now declares {_pub_tq:.0f} N·m motor "
                        f"torque, {_pub_pw:.0f} kW, {_pub_hv:.0f} V, {_pub_mass:.1f} kg, "
                        f"{_pub_heat:.0f} W heat. The driveline-torque, HV-voltage, "
                        "thermal and mount-load checks now include powertrain — see the "
                        "Cross-team checks tab and the INTEGRATION tab.")
                    st.rerun()
                except Exception as _pe:
                    st.warning(f"Couldn't publish: {_pe}")

        # ================================================================= #
        #  PANEL 4 — Cross-team checks (powertrain's findings, live)         #
        # ================================================================= #
        with _pt_tabs[4]:
            st.markdown(
                '<p class="hint" style="margin:0 0 6px;">The cross-team physics checks '
                'that touch powertrain, run live against whatever\u2019s in the ledger right '
                'now. Red is a real conflict to resolve <i>before</i> assembly; this is '
                'the miscommunication, made visible.</p>',
                unsafe_allow_html=True)
            try:
                _led_chk = interfaces_mod.IntegrationLedger.from_dict(
                    st.session_state.ledger)
                _all_find = _led_chk.check_all()
                _pt_find = interfaces_mod.findings_for(_all_find, "powertrain")
                if not _led_chk.get("powertrain") or not _led_chk.get("powertrain").declared_fields():
                    st.info("Powertrain hasn\u2019t published anything yet — use the "
                            "**Publish to ledger** tab first, then these checks light up.")
                elif not _pt_find:
                    st.success("No powertrain-related findings — nothing flagged.")
                else:
                    _sev_icon = {"fail": "🔴", "warn": "🟠", "missing": "🟡",
                                 "info": "🔵", "ok": "🟢"}
                    for _f in sorted(_pt_find,
                                     key=lambda f: {"fail": 0, "warn": 1, "missing": 2,
                                                    "info": 3, "ok": 4}.get(
                                                    str(getattr(f.severity, "value",
                                                        f.severity)), 5)):
                        _sv = str(getattr(_f.severity, "value", _f.severity))
                        _ic = _sev_icon.get(_sv, "•")
                        _who = ", ".join(_f.subsystems) if _f.subsystems else "—"
                        st.markdown(f"{_ic} **{_f.check}** ({_who}) — {_f.message}")
                st.caption("Full car-wide view, including non-powertrain rules, lives "
                           "in the INTEGRATION tab.")
            except Exception as _ke:
                st.warning(f"Couldn't run cross-team checks: {_ke}")

        # ================================================================= #
        #  PANEL 5 — Live spec sheet (replaces the screenshot)              #
        # ================================================================= #
        with _pt_tabs[5]:
            st.markdown(
                '<p class="hint" style="margin:0 0 6px;">The <b>Design EV Spec Sheet</b>, '
                'generated from the numbers you\u2019ve committed instead of a screenshot '
                'that goes stale the moment anything changes. Export it for a design '
                'review; it always reflects the current ledger.</p>',
                unsafe_allow_html=True)
            try:
                _led_spec = interfaces_mod.IntegrationLedger.from_dict(
                    st.session_state.ledger)
                _pt_iface = _led_spec.get("powertrain")
                _spr = st.session_state.get("_pti_sprocket", {})
                _spec_rows = pti_mod.powertrain_spec_sheet(
                    architecture=_arch_best_label,
                    power_kw=float(getattr(_pt_iface, "peak_power_kw", None)
                                   or _power_kw),
                    peak_torque_nm=float(getattr(_pt_iface, "peak_torque_nm", None)
                                         or st.session_state.get("_pti_peak_tq", _def_peak_tq)),
                    hv_voltage_v=float(getattr(_pt_iface, "voltage_v", None)
                                       or _def_hv_v),
                    pack_kwh=float(_pack_kwh),
                    final_drive=float(st.session_state.get("_pti_final_drive", 3.5)),
                    motor_teeth=_spr.get("motor"),
                    driven_teeth=_spr.get("driven"),
                    chain_tension_n=_spr.get("tension"),
                    driveline_torque_nm=st.session_state.get("_pti_out_torque"),
                    motor_mass_kg=float(getattr(_pt_iface, "mass_kg", None) or 0) or None,
                    heat_reject_w=float(getattr(_pt_iface, "heat_reject_w", None) or 0) or None,
                    cooling_flow_cms=float(getattr(_pt_iface, "cooling_airflow_cms", None) or 0) or None,
                    is_estimate=bool(getattr(_pt_iface, "is_estimate", True)),
                )
                import pandas as _pd_s
                _spec_df = _pd_s.DataFrame(_spec_rows)
                st.dataframe(_spec_df, hide_index=True, width='stretch')
                st.download_button(
                    "⬇️ Download spec sheet (CSV)",
                    data=_spec_df.to_csv(index=False).encode("utf-8"),
                    file_name="FSAE_EV_Powertrain_Spec_Sheet.csv",
                    mime="text/csv", key="pti_spec_dl")
                if _pt_iface is None or not _pt_iface.declared_fields():
                    st.info("Publish to the ledger first for a fully-populated, "
                            "single-source-of-truth spec sheet.")

                # --- answer slide 9: auto-fill the DFMEA from this analysis --- #
                st.markdown("##### Stop hand-writing the DFMEA")
                st.markdown(
                    '<p class="hint" style="margin:0 0 6px;">The team\u2019s open question '
                    'is whether DFMEAs are worth the time. They are when the tool fills '
                    'them: KinematiK turns the analysis above \u2014 chain tension, cooling '
                    'margin, mount load \u2014 into ready-to-edit DFMEA rows with the real '
                    'numbers already in the cause and evidence fields. You edit real '
                    'rows on the <b>DFMEA</b> tab instead of starting from blank.</p>',
                    unsafe_allow_html=True)
                if st.button("➕ Auto-fill DFMEA rows from this analysis",
                             key="pti_dfmea_gen"):
                    try:
                        _spr2 = st.session_state.get("_pti_sprocket", {})
                        _sd_obj = None
                        if _spr2:
                            _sd_obj = pti_mod.sprocket_design(
                                float(st.session_state.get("_pti_final_drive", 3.5)),
                                float(st.session_state.get("_pti_peak_tq", _def_peak_tq)),
                                motor_sprocket_teeth=int(_spr2.get("motor", 14)))
                        _cool_obj = None
                        try:
                            _fan2 = pti_mod.FanCurve.spal_default()
                            _k2 = pti_mod.system_k_from_point(
                                float(st.session_state.get("pti_rigflow", 400.0)),
                                float(st.session_state.get("pti_rigdp", 150.0)))
                            _cool_obj = pti_mod.cooling_operating_point(
                                _fan2, _k2,
                                heat_to_reject_w=float(st.session_state.get("_pti_heat_w", 2000.0)),
                                air_delta_t_c=float(st.session_state.get("pti_airdt", 20)))
                        except Exception:
                            pass
                        _new_rows = pti_mod.dfmea_rows_from_analysis(
                            sprocket=_sd_obj, cooling=_cool_obj,
                            output_torque_nm=st.session_state.get("_pti_out_torque"),
                            mount_load_n=(float(getattr(_pt_iface, "mount_load_n", 0) or 0)
                                          or None),
                            owner=str(getattr(_pt_iface, "owner", "") or ""))
                        if "dfmea_rows" not in st.session_state:
                            st.session_state.dfmea_rows = dfmea_mod.seed_rows()
                        st.session_state.dfmea_rows = (
                            st.session_state.dfmea_rows + _new_rows)
                        st.success(
                            f"Added {len(_new_rows)} evidence-backed rows to the DFMEA "
                            "tab — open it to review and assign owners/dates.")
                    except Exception as _de:
                        st.warning(f"Couldn't generate DFMEA rows: {_de}")
            except Exception as _se:
                st.warning(f"Couldn't build the spec sheet: {_se}")

  except Exception as _eev:
    st.error(f"Could not build the EV powertrain workspace: {_eev}")

# =========================================================================== #
#  ACCUMULATOR  —  design the HV battery pack to the FSAE-EV rules.            #
# =========================================================================== #
# An electric team's accumulator subteam picks a cell, chooses a series/parallel
# topology, and must clear the hard FSAE-EV electrical rules: the tractive system
# stays under 600 V, the pack never outputs more than 80 kW, and every isolatable
# SEGMENT carries < 120 V static and < 6 MJ of energy (EV3.3.3 / EV1). This tab
# sizes the pack from the cell up — voltage, energy, capacity, mass, peak C-rate —
# checks every rule, suggests a compliant segmentation, draws the pack grid, and
# hands the layout straight to KinematiK's per-cell thermal model and the ledger.
with tab_accum:
  try:
    render_process_library("electrics", key_prefix="accum_pl")
  except Exception:
    pass

  try:
    _subsystem_cad_import("electrics", key_prefix="accum")
    st.markdown(
        '<p class="hint" style="margin:0 0 6px;">Build the <b>HV accumulator</b> from the '
        'cell up and clear the rules in one place. Pick a cell, choose how many in '
        '<b>series</b> (sets voltage) and <b>parallel</b> (sets capacity & shares current), '
        'and KinematiK sizes the pack and checks the hard FSAE-EV limits: tractive system '
        '< 600 V, ≤ 80 kW, and every isolatable segment < 120 V and < 6 MJ. '
        '<span style="opacity:0.5;">(build: pack-v2)</span></p>',
        unsafe_allow_html=True)

    # ---- cell chooser: presets + custom -------------------------------- #
    # Representative datasheet-scale numbers for cells FSAE-EV teams actually use.
    # (nominal V, capacity Ah, mass g, internal R mΩ, max continuous discharge A)
    _CELLS = {
        "Molicel P28A (21700)": (3.6, 2.8, 70.0, 14.0, 35.0),
        "Molicel P42A (21700)": (3.6, 4.2, 70.0, 10.0, 45.0),
        "Samsung 40T (21700)":  (3.6, 4.0, 70.0, 12.0, 35.0),
        "Sony/Murata VTC6 (18650)": (3.6, 3.0, 47.0, 13.0, 30.0),
        "LG HG2 (18650)":       (3.6, 3.0, 48.0, 20.0, 20.0),
        "Custom…": None,
    }
    cc = st.columns(4)
    _cell_name = cc[0].selectbox("Cell", list(_CELLS.keys()),
                                 help="Representative datasheet-scale specs; set Custom to type your own.")
    _spec = _CELLS[_cell_name]
    if _spec is None:
        _cv = cc[1].number_input("Cell nominal V", 2.5, 4.2, value=3.6, step=0.1)
        _cah = cc[2].number_input("Cell capacity (Ah)", 1.0, 8.0, value=4.0, step=0.1)
        _cg = cc[3].number_input("Cell mass (g)", 20.0, 120.0, value=70.0, step=1.0)
        cc2 = st.columns(4)
        _cr = cc2[0].number_input("Internal R (mΩ)", 5.0, 60.0, value=12.0, step=1.0)
        _cmax_a = cc2[1].number_input("Max cont. discharge (A)", 5.0, 60.0, value=35.0, step=1.0)
    else:
        _cv, _cah, _cg, _cr, _cmax_a = _spec
        cc[1].metric("Nominal", f"{_cv:.1f} V")
        cc[2].metric("Capacity", f"{_cah:.1f} Ah")
        cc[3].metric("Max cont.", f"{_cmax_a:.0f} A/cell")

    # ---- topology ------------------------------------------------------- #
    tc = st.columns(4)
    _series = tc[0].number_input("Series (sets voltage)", 1, 200, value=140, step=1,
                                 key="accum_series",
                                 help="Cells in series. Pack nominal V = series × cell V.")
    _parallel = tc[1].number_input("Parallel (sets capacity)", 1, 20, value=5, step=1,
                                   key="accum_parallel",
                                   help="Cells in parallel per series group. Pack Ah = parallel × cell Ah; "
                                        "per-cell current = pack current / parallel.")
    _power_cap_kw = unum(tc[2], "Power cap (kW)", 20, 80, 80, "kW", step=5.0,
                         key="accum_power_cap",
                         help="FSAE caps tractive power at 80 kW; the pack must deliver it.")
    _auto_peak = tc[3].checkbox("Auto peak current", value=True, key="accum_auto_peak",
                                help="Derive peak pack current from the power cap at pack "
                                     "voltage. Uncheck to type it in.")

    # ---- derived pack numbers ------------------------------------------ #
    _pack_v = _series * _cv
    _pack_ah = _parallel * _cah
    _pack_wh = _pack_v * _pack_ah
    _pack_kwh = _pack_wh / 1000.0
    _n_cells = int(_series * _parallel)
    _pack_mass = _n_cells * (_cg / 1000.0)
    if _auto_peak:
        _peak_pack_a = (_power_cap_kw * 1000.0) / max(_pack_v, 1.0)
    else:
        _derived = (_power_cap_kw * 1000.0) / max(_pack_v, 1.0)
        _peak_pack_a = st.number_input(
            "Peak pack current (A)", 50.0, 600.0,
            value=float(min(600.0, max(50.0, _derived))), step=10.0,
            key="accum_peak_a_v2",
            help="Peak current the pack must deliver.")
    _per_cell_a = _peak_pack_a / max(_parallel, 1)
    _c_rate = _per_cell_a / max(_cah, 1e-6)
    _max_power_kw = (_pack_v * _peak_pack_a) / 1000.0
    # I²R heat in the pack at peak (all cells): per-cell I²·R × n_cells
    _pack_heat_w = _n_cells * (_per_cell_a ** 2) * (_cr / 1000.0)

    m = st.columns(5)
    m[0].metric("Pack voltage", f"{_pack_v:.0f} V")
    m[1].metric("Pack energy", f"{_pack_kwh:.2f} kWh")
    m[2].metric("Pack capacity", f"{_pack_ah:.1f} Ah")
    m[3].metric("Cell count", f"{_n_cells}", f"{_series}s{_parallel}p")
    umetric(m[4], "Pack mass", _pack_mass, "kg", fmt="{:.1f}",
            help="Cells only — add ~30–50% for housing, BMS, bus bars, cooling.")

    try:
        record_activity(
            "electrics", "calculation",
            f"Accumulator: {_series}s{_parallel}p, {_pack_v:.0f} V, "
            f"{_pack_kwh:.2f} kWh, {_pack_ah:.1f} Ah, {_n_cells} cells, "
            f"{_pack_mass:.1f} kg (cells), C-rate {_c_rate:.1f}")
    except Exception:
        pass

    # Publish the REAL segment-box section for the DXF exporter. Segment = one
    # isolatable < 120 V block; cells laid out as a series×parallel grid on an
    # 18650 footprint (18 mm pitch) with a housing wall. This is the container
    # cross-section a member extrudes to segment length, then meshes.
    try:
        _seg_series = max(1, int(140.0 / max(_cv, 1e-6)))     # cells to stay <120 V
        _seg_series = min(_seg_series, _series)
        _cell_pitch = 20.0    # mm, 18650 ⌀18 + 2 mm holder web
        _wall = 8.0
        _cols_grid = _seg_series
        _rows_grid = _parallel
        _seg_w = _cols_grid * _cell_pitch + 2 * _wall
        _seg_h = _rows_grid * _cell_pitch + 2 * _wall
        publish_export_geometry("electrics", {
            "seg_w_mm": round(_seg_w, 1), "seg_h_mm": round(_seg_h, 1),
            "wall_mm": _wall, "n_cells": _n_cells,
            "config": f"{_series}s{_parallel}p "
                      f"(segment {_seg_series}s{_parallel}p)",
            "source": f"accumulator {_series}s{_parallel}p",
        })
    except Exception:
        pass

    m2 = st.columns(4)
    m2[0].metric("Per-cell current", f"{_per_cell_a:.0f} A",
                 help="Pack current shared across the parallel cells — this drives I²R heat.")
    m2[1].metric("Cell C-rate", f"{_c_rate:.1f} C",
                 delta=("within cell limit" if _per_cell_a <= _cmax_a else "OVER cell limit"),
                 delta_color=("normal" if _per_cell_a <= _cmax_a else "inverse"))
    umetric(m2[2], "Deliverable power", _max_power_kw, "kW")
    umetric(m2[3], "Pack I²R heat @ peak", _pack_heat_w / 1000, "kW", fmt="{:.1f}",
                 help="Resistive heat the whole pack makes at peak current — the cooling load.")

    # ---- FSAE-EV rules checks ------------------------------------------ #
    st.markdown('<p class="hint" style="margin:10px 0 2px;"><b>FSAE-EV rules check</b> '
                '(EV1 / EV3.3.3):</p>', unsafe_allow_html=True)
    _checks = []
    # 600 V system limit (use max charge voltage ~4.2 V/cell as worst case)
    _pack_v_max = _series * 4.2
    _checks.append((
        _pack_v_max < 600.0,
        f"System voltage < 600 V — pack tops out at {_pack_v_max:.0f} V "
        f"(at 4.2 V/cell full charge).",
        f"Pack reaches {_pack_v_max:.0f} V at full charge, over the 600 V limit. "
        f"Reduce series count below {int(600/4.2)}."))
    # 80 kW power
    _checks.append((
        _max_power_kw <= 80.0 + 1e-6,
        f"Tractive power ≤ 80 kW — deliverable {uval(_max_power_kw, 'kW')} at peak current.",
        f"Deliverable power {uval(_max_power_kw, 'kW')} exceeds the 80 kW cap; "
        f"the BMS/inverter must limit current."))
    # cell current within rating
    _checks.append((
        _per_cell_a <= _cmax_a + 1e-6,
        f"Per-cell current {_per_cell_a:.0f} A ≤ cell rating {_cmax_a:.0f} A.",
        f"Per-cell current {_per_cell_a:.0f} A exceeds the cell's {_cmax_a:.0f} A "
        f"rating — add parallel cells (more p) to share the load."))
    # segmentation: each segment < 120 V and < 6 MJ
    # smallest number of segments that satisfies both limits
    import math as _math
    _seg_by_v = _math.ceil(_pack_v_max / 120.0)
    _seg_energy_mj = (_pack_wh * 3600.0 / 1e6)
    _seg_by_e = _math.ceil(_seg_energy_mj / 6.0)
    _n_segments = max(_seg_by_v, _seg_by_e, 1)
    _seg_v = _pack_v_max / _n_segments
    _seg_mj = _seg_energy_mj / _n_segments
    _checks.append((
        _seg_v < 120.0 and _seg_mj < 6.0,
        f"Segments: split into {_n_segments} → {_seg_v:.0f} V & {_seg_mj:.2f} MJ each "
        f"(both under the 120 V / 6 MJ segment limits).",
        f"Need at least {_n_segments} isolatable segments to stay under 120 V & 6 MJ each."))

    _all_ok = all(ok for ok, _, _ in _checks)
    for ok, ok_msg, bad_msg in _checks:
        if ok:
            st.success("✓ " + ok_msg)
        else:
            st.error("✗ " + bad_msg)
    if _all_ok:
        st.markdown(
            f'<p class="hint">This pack is rules-legal as configured: <b>{_series}s{_parallel}p</b>, '
            f'<b>{_pack_v:.0f} V</b> nominal, <b>{_pack_kwh:.2f} kWh</b>, <b>{uval(_pack_mass, "kg")}</b> '
            f'of cells, in <b>{_n_segments} segments</b>. Build the accumulator container around this '
            f'and the structural/SES work follows.</p>', unsafe_allow_html=True)

    # ---- pack grid visual, coloured by segment ------------------------- #
    st.markdown('<p class="hint" style="margin:10px 0 2px;"><b>Pack layout</b> — '
                f'{_n_cells} cells in {_n_segments} segments:</p>', unsafe_allow_html=True)
    # lay series groups left→right, parallel stacked vertically; colour by segment
    _groups_per_seg = max(1, _math.ceil(_series / _n_segments))
    gx, gy, gc, gt = [], [], [], []
    _seg_palette = ["#37e0d0", "#ffb02e", "#ff5a52", "#9b8cff", "#5ad17a",
                    "#ff9f43", "#6cc4ff", "#e06cff", "#c2410c", "#33d6a6"]
    for s in range(int(_series)):
        seg_idx = s // _groups_per_seg
        for p in range(int(_parallel)):
            gx.append(s)
            gy.append(p)
            gc.append(_seg_palette[seg_idx % len(_seg_palette)])
            gt.append(f"series {s+1}, parallel {p+1} · segment {seg_idx+1}")
    fgrid = go.Figure(go.Scatter(
        x=gx, y=gy, mode="markers",
        marker=dict(size=max(4, min(13, 700 // max(_series, 1))),
                    color=gc, line=dict(width=0)),
        text=gt, hoverinfo="text"))
    fgrid.update_layout(
        title=f"{_series}s × {_parallel}p — colour = isolatable segment (<120 V, <6 MJ each)",
        xaxis_title="series position (→ voltage)", yaxis_title="parallel",
        height=260, paper_bgcolor="rgba(0,0,0,0)", plot_bgcolor="rgba(0,0,0,0)",
        font=dict(color="#cdd6df", size=10), margin=dict(l=0, r=0, t=36, b=0),
        showlegend=False)
    fgrid.update_yaxes(dtick=1)
    st.plotly_chart(fgrid, width='stretch', key="accum_grid")

    # ---- actions: write to ledger / thermal --------------------------- #
    ac = st.columns(2)
    if ac[0].button("Declare this pack in the INTEGRATION ledger",
                    key="accum_declare",
                    help="Writes pack voltage and mass into the electrics interface and "
                         "the accumulator system voltage, so the heatmap, mass roll-up "
                         "and electrical checks all use it."):
        try:
            _led_ac = interfaces_mod.IntegrationLedger.from_dict(st.session_state.ledger)
            _it = _led_ac.get("electrics") or interfaces_mod.SubsystemInterface(name="electrics")
            _it.mass_kg = round(float(_pack_mass) * 1.4, 1)  # +40% for housing/BMS/bus bars
            _it.voltage_v = float(_pack_v)
            _it.heat_reject_w = round(float(_pack_heat_w), 0)
            _led_ac.set(_it)
            _led_ac.accumulator_voltage_v = float(_pack_v)
            publish_ledger(_led_ac.as_dict())
            st.success(f"Declared: {_pack_v:.0f} V, "
                       f"{units_mod.from_metric(_pack_mass*1.4, 'kg'):.0f} "
                       f"{units_mod.label('kg')} (incl. housing), "
                       f"{uval(_pack_heat_w/1000, 'kW', fmt='{:.1f}')} heat. The heatmap, mass roll-up and "
                       "electrical checks now use this pack.")
            st.rerun()
        except Exception as _e3:
            st.warning(f"Couldn't declare: {_e3}")
    ac[1].caption("Per-cell transient thermal — which cell cooks first and where to put "
                  "the fan — runs from this layout via KinematiK's pack-thermal model "
                  "(see the pack_thermal module / demo_pack_thermal).")

    # ---- ACCUMULATOR MOUNT BOLTS ------------------------------------------- #
    #  The Discord thread flagged that the acc mounts hit the SAME bolt-torque
    #  wall the brakes pedal did ("an issue that acc mounts are facing"). The
    #  accumulator is heavy and the rules demand its mounts survive big decel
    #  loads, so the same VDI 2230 check belongs here — same tool, same honesty.
    with st.expander("🔩 Accumulator mount-bolt torque & FoS "
                     "(the bolt-preload check, same as Brakes)"):
        try:
            _acc_mass = float(st.session_state.get("accum_pack_mass_est",
                                                   _pack_mass if "_pack_mass" in
                                                   dir() else 8.0))
        except Exception:
            _acc_mass = 8.0
        # FSAE EV rules: accumulator mounts are designed to a high decel (≥ 20 g
        # in some load cases). Use a representative 20 g pull-off as the default
        # external load, divided over a typical bolt count, so the seed is honest.
        _acc_nbolt = st.columns(3)[0].number_input(
            "Accumulator mount bolts", 4, 12, 6, 1, key="accum_bolt_n",
            help="Bolts carrying the pack. FSAE-EV requires the mounts survive "
                 "high decel load cases.")
        _acc_g = st.columns(3)[0].slider(
            "Design decel (g)", 5.0, 40.0, 20.0, 1.0, key="accum_bolt_g",
            help="The load case the mounts are designed to. EV rules call out "
                 "demanding decel cases for the accumulator container.")
        _acc_extN = (_acc_mass * 9.81 * _acc_g) / max(_acc_nbolt, 1)
        _render_mount_bolt_check(
            "accum_bolt", default_ext_n=float(round(_acc_extN, 0)),
            default_base="Aluminium 6061", ledger_subsys="electrics",
            context_label=f"the accumulator container mount "
                          f"(~{_acc_mass:.0f} kg pack at {_acc_g:.0f} g)")
  except Exception as _eac:
    st.error(f"Could not build the accumulator workspace: {_eac}")

# =========================================================================== #
#  BRAKES  —  bias, lock-up, and the hydraulic chain to size the system.       #
# =========================================================================== #
# Every FSAE car must pass a brake test: lock all four wheels and stop in a
# straight line. The brakes subteam sizes the pedal → master cylinder → caliper →
# pad → rotor chain to do that and sets the front/rear bias so the car is stable
# under braking (front locks slightly before rear). This tab does both from the
# live car: dynamic load transfer sets the ideal bias and the lock-all-four check;
# the hydraulic chain sizes the parts and reports the pedal force a driver needs.
with tab_brake:
  try:
    render_process_library("brakes", key_prefix="brake_pl")
  except Exception:
    pass
  try:
    _subsystem_cad_import("brakes", key_prefix="brake")
    try:
        _vp_b = VehicleParams(**{k: v for k, v in st.session_state.vp.items()
                                 if k in set(VehicleParams.__dataclass_fields__.keys())})
    except Exception:
        _vp_b = VehicleParams()
    _g = 9.81
    _mass = float(_vp_b.mass)
    _cgh = float(_vp_b.cg_height)
    _wb = float(_vp_b.wheelbase)
    _wdf = float(_vp_b.weight_dist_front)
    _mu = float(getattr(_vp_b, "mu_peak", 1.5))

    st.markdown(
        '<p class="hint" style="margin:0 0 6px;">Size the brakes to <b>lock all four '
        'wheels</b> (the FSAE brake test) and set a stable <b>front/rear bias</b>. Under '
        'braking, weight shifts forward, so the front needs more brake than its static '
        'share — and you want the front to lock <i>just</i> before the rear so the car '
        'stays straight. Everything below comes from the live car\u2019s mass, CG height '
        'and wheelbase.</p>', unsafe_allow_html=True)

    _bview = feature_menu("brakes",
                          ["Bias & lock-up", "Hydraulic sizing",
                           "Bolt & bracket FoS", "Pedal box & throttle",
                           "Rotor thermal", "Documentation"],
                          title="Brakes tools",
                          descriptions={
                              "Bias & lock-up": "Front/rear bias, decel, lock-up margin",
                              "Hydraulic sizing": "Master cylinder, pedal ratio, line pressure",
                              "Bolt & bracket FoS": "Mount bolt + bracket safety factors",
                              "Pedal box & throttle": "Pedal geometry & throttle bench",
                              "Rotor thermal": "Rotor temp, optimiser, mesh & DXF export",
                              "Documentation": "Report, verdict, export for brakes"})

    _wheel_r_mm = st.session_state.get("brake_wheel_r", 228.0)

    # =================================================================== #
    if _bview == "Bias & lock-up":
        bc = st.columns(4)
        _decel = bc[0].slider("Decel target (g)", 0.8, 2.0, 1.4, 0.1,
                              help="The brake test needs the tyres at their limit. FSAE "
                                   "cars on slicks brake at ~1.4–1.8 g.")
        _bias = bc[1].slider("Front brake bias (%)", 50, 80, 65, 1,
                             help="Share of brake torque sent to the front axle. Set it "
                                  "near the ideal so the front locks just before the rear.") / 100.0
        st.session_state["brake_front_bias_pct"] = int(round(_bias * 100))
        _mu_b = bc[2].slider("Tyre μ (braking)", 1.0, 2.0, value=float(round(_mu, 2)), step=0.05,
                             help="Peak longitudinal grip. From the car's tyre model by default.")
        _wheel_r_mm = unum(bc[3], "Loaded tyre radius (mm)", 180, 280,
                           float(_wheel_r_mm), "mm", step=2.0,
                           help="Sets the brake torque needed at a given decel.")
        st.session_state.brake_wheel_r = _wheel_r_mm

        # static axle loads
        W = _mass * _g
        Wf_static = W * _wdf
        Wr_static = W * (1 - _wdf)
        # longitudinal load transfer at the decel target
        dW = _decel * W * (_cgh / _wb)
        Wf = Wf_static + dW
        Wr = max(Wr_static - dW, 0.0)
        # ideal bias = front's share of the dynamic normal load (matches lock-up)
        _ideal_bias = Wf / max(Wf + Wr, 1.0)
        # the decel the car can actually reach before EITHER axle locks given the bias.
        # brake force per axle is bias-limited; an axle locks when demanded force > μ·N.
        # demanded total decel force at decel a: F = a·W, split by bias.
        # find max a where front demand ≤ μ·Wf(a) AND rear demand ≤ μ·Wr(a).
        def _locks(a):
            dWa = a * W * (_cgh / _wb)
            Wfa = Wf_static + dWa
            Wra = max(Wr_static - dWa, 0.0)
            F = a * W
            Ff = F * _bias
            Fr = F * (1 - _bias)
            return (Ff > _mu_b * Wfa + 1e-6, Fr > _mu_b * Wra + 1e-6, Wfa, Wra)
        # sweep decel to find first lock
        _amax = 0.0
        _first = None
        for a in np.linspace(0.1, 2.2, 220):
            fl, rl, _, _ = _locks(a)
            if fl or rl:
                _amax = a
                _first = "front" if fl and not rl else ("rear" if rl and not fl else "both")
                break
        else:
            _amax = 2.2
            _first = "neither (raise decel)"

        mc = st.columns(4)
        mc[0].metric("Ideal front bias", f"{_ideal_bias*100:.0f}%",
                     help="Front share of the dynamic load at this decel — match the slider to it.")
        mc[1].metric("Your bias", f"{_bias*100:.0f}%",
                     delta=f"{(_bias-_ideal_bias)*100:+.0f}% vs ideal")
        mc[2].metric("Locks first", _first.title(),
                     help="You want FRONT first (stable). Rear-first is twitchy/unstable.")
        mc[3].metric("Max decel before lock", f"{_amax:.2f} g")

        # torque needed at each axle to lock at the decel target
        Tf_lock = _mu_b * Wf * (_wheel_r_mm / 1000.0)   # total front-axle torque to lock
        Tr_lock = _mu_b * Wr * (_wheel_r_mm / 1000.0)
        st.session_state.brake_Tf = Tf_lock / 2.0  # per corner
        st.session_state.brake_Tr = Tr_lock / 2.0

        # plot: brake-force distribution vs ideal (the classic brake-bias diagram)
        _as = np.linspace(0, 1.8, 60)
        _ideal_front = []
        for a in _as:
            dWa = a * W * (_cgh / _wb)
            Wfa = Wf_static + dWa
            Wra = max(Wr_static - dWa, 0.0)
            _ideal_front.append(Wfa / max(Wfa + Wra, 1.0) * 100)
        fb = go.Figure()
        fb.add_trace(go.Scatter(x=_as, y=_ideal_front, name="Ideal front bias",
                                line=dict(color="#37e0d0", width=3)))
        fb.add_hline(y=_bias * 100, line=dict(color="#ff9f43", dash="dash"),
                     annotation_text="your fixed bias", annotation_position="top left")
        fb.add_vline(x=_decel, line=dict(color="#6f7d8c", dash="dot"))
        fb.update_layout(
            title="Ideal front brake bias vs deceleration",
            xaxis_title="deceleration (g)", yaxis_title="front bias (%)", height=340,
            paper_bgcolor="rgba(0,0,0,0)", plot_bgcolor="rgba(0,0,0,0)",
            font=dict(color="#cdd6df", size=11), margin=dict(l=0, r=0, t=36, b=0),
            legend=dict(bgcolor="rgba(0,0,0,0)"))
        st.plotly_chart(fb, width='stretch', key="brake_bias")

        # FSAE lock-all-four verdict
        if _first == "front":
            st.success(f"✓ Stable bias: the front locks first (at {_amax:.2f} g), then the "
                       "rear — the car stays straight in the brake test. The hydraulic "
                       "sizing view checks you can actually generate the torque to lock all four.")
        elif _first == "rear":
            st.error(f"✗ Rear locks first (at {_amax:.2f} g) — unstable, the car will spin "
                     f"under heavy braking. Move bias forward (toward {_ideal_bias*100:.0f}%).")
        else:
            st.info(f"Both axles reach the limit together at ~{_amax:.2f} g — neutral. A "
                    "touch of extra front bias makes it stable.")
        _uM = units_mod.label("kg")
        _uTq = units_mod.label("N·m")
        _Wf = units_mod.from_metric(Wf / _g, "kg")
        _Wr = units_mod.from_metric(Wr / _g, "kg")
        _Wfs = units_mod.from_metric(Wf_static / _g, "kg")
        _Wrs = units_mod.from_metric(Wr_static / _g, "kg")
        _Tf = units_mod.from_metric(Tf_lock / 2, "N·m")
        _Tr = units_mod.from_metric(Tr_lock / 2, "N·m")
        st.markdown(
            f'<p class="hint">At {_decel:.1f} g the front axle carries '
            f'<b>{_Wf:.0f} {_uM}</b> and the rear <b>{_Wr:.0f} {_uM}</b> (static was '
            f'{_Wfs:.0f}/{_Wrs:.0f}). To lock the tyres you need '
            f'<b>{_Tf:.0f} {_uTq}</b> per front corner and <b>{_Tr:.0f} {_uTq}</b> '
            f'per rear corner — carried into the hydraulic sizing view.</p>',
            unsafe_allow_html=True)

    # =================================================================== #
    elif _bview == "Hydraulic sizing":
        st.markdown(
            '<p class="hint">Size the hydraulic chain to deliver the lock-up torque the '
            'bias view found, and see the <b>pedal force</b> a driver needs. The chain: '
            'pedal ratio multiplies foot force → master cylinder makes line pressure → '
            'caliper pistons clamp the pad → pad friction on the rotor makes torque.</p>',
            unsafe_allow_html=True)
        _Tf_need = float(st.session_state.get("brake_Tf", 380.0))
        _Tr_need = float(st.session_state.get("brake_Tr", 180.0))

        hc = st.columns(4)
        _axle = hc[0].selectbox("Sizing for", ["Front corner", "Rear corner"])
        _T_need = _Tf_need if _axle.startswith("Front") else _Tr_need
        _pedal_ratio = hc[1].number_input("Pedal ratio", 3.0, 8.0, value=5.0, step=0.25,
                                          help="Mechanical advantage of the brake pedal (lever).")
        st.session_state["brake_pedal_ratio"] = float(_pedal_ratio)
        _mc_dia = unum(hc[2], "Master cyl. ⌀ (mm)", 12, 25, 15.875, "mm", step=0.397,
                       help="Smaller bore = more line pressure for the same pedal force, "
                            "but more pedal travel. 5/8\" = 15.875 mm is common.")
        _pad_mu = hc[3].number_input("Pad friction μ", 0.3, 0.6, value=0.45, step=0.01,
                                     help="Brake pad coefficient of friction against the rotor.")

        hc2 = st.columns(4)
        _cal_pistons = hc2[0].number_input("Caliper pistons (per side)", 1, 4, value=2, step=1)
        _cal_dia = unum(hc2[1], "Caliper piston ⌀ (mm)", 20, 45, 30, "mm", step=1.0)
        _rotor_dia = unum(hc2[2], "Rotor ⌀ (mm)", 180, 300, 220, "mm", step=5.0,
                          help="Bigger rotor = more torque arm = less clamp needed.")
        st.session_state["brake_rotor_dia_mm"] = float(_rotor_dia)
        _pedal_force = unum(hc2[3], "Driver pedal force (N)", 100, 1200, 500, "N",
                            step=25.0, help="A strong driver can apply ~600–800 N.")
        st.session_state["brake_driver_pedal_force"] = float(_pedal_force)

        # hydraulic chain
        _A_mc = np.pi * (_mc_dia / 1000.0 / 2) ** 2          # master cyl area m²
        _A_cal = np.pi * (_cal_dia / 1000.0 / 2) ** 2 * _cal_pistons  # total caliper piston area
        _line_force = _pedal_force * _pedal_ratio            # N at master cyl pushrod
        _line_pressure = _line_force / max(_A_mc, 1e-9)      # Pa
        _clamp = _line_pressure * _A_cal                     # N clamp force (one pad pair)
        # effective radius ~ rotor radius minus a pad half-height; approx 0.92·outer R
        _r_eff = (_rotor_dia / 1000.0 / 2) * 0.92
        _T_made = 2 * _clamp * _pad_mu * _r_eff              # ×2 friction faces
        _ratio = _T_made / max(_T_need, 1e-6)

        m = st.columns(4)
        umetric(m[0], "Line pressure", _line_pressure / 1e5, "bar",
                help="Hydraulic pressure at this pedal force. Race systems run 30–80 bar.")
        umetric(m[1], "Clamp force", _clamp, "N")
        umetric(m[2], "Torque made", _T_made, "N·m",
                help="Brake torque this corner can generate at the chosen pedal force.")
        umetric(m[3], "Torque needed", _T_need, "N·m",
                delta=f"{(_ratio-1)*100:+.0f}% margin",
                delta_color=("normal" if _ratio >= 1 else "inverse"))

        # pedal force actually required to hit lock-up
        _pf_req = _pedal_force / max(_ratio, 1e-6)
        _uTq = units_mod.label("N·m")
        _uFc = units_mod.label("N")
        _Tm = units_mod.from_metric(_T_made, "N·m")
        _Tn = units_mod.from_metric(_T_need, "N·m")
        _pfr = units_mod.from_metric(_pf_req, "N")
        _pf = units_mod.from_metric(_pedal_force, "N")
        if _ratio >= 1.0:
            st.success(f"✓ This corner can lock the tyre: it makes {_Tm:.0f} {_uTq}, and "
                       f"only {_pfr:.0f} {_uFc} of pedal force is needed to reach the "
                       f"{_Tn:.0f} {_uTq} lock-up torque (you set {_pf:.0f} {_uFc}). "
                       "Combined with a front-first bias, the car passes the lock-all-four test.")
        else:
            st.error(f"✗ Under-sized: at {_pf:.0f} {_uFc} pedal force this corner only "
                     f"makes {_Tm:.0f} of the {_Tn:.0f} {_uTq} needed to lock. Drop the "
                     "master-cylinder bore, raise the pedal ratio, or fit a bigger rotor/caliper.")

        # bar: torque-made vs needed for this corner at the current driver pedal force
        fbar = go.Figure()
        fbar.add_trace(go.Bar(x=["This corner"], y=[_Tm], name="Torque made",
                              marker_color="#5ad17a"))
        fbar.add_trace(go.Bar(x=["This corner"], y=[_Tn], name="Torque to lock",
                              marker_color="#ff5a52"))
        fbar.update_layout(
            barmode="group", title="Brake torque made vs needed (%s)" % _axle.lower(),
            yaxis_title=f"torque ({_uTq})", height=300,
            paper_bgcolor="rgba(0,0,0,0)", plot_bgcolor="rgba(0,0,0,0)",
            font=dict(color="#cdd6df", size=11), margin=dict(l=0, r=0, t=36, b=0),
            legend=dict(bgcolor="rgba(0,0,0,0)"))
        st.plotly_chart(fbar, width='stretch', key="brake_torque")

        if st.button("Declare brake torque/corner in the INTEGRATION ledger",
                     key="brake_declare",
                     help="Writes the lock-up brake torque into the brakes interface so "
                          "the 3D model disc size, heatmap and checks use it."):
            try:
                _axn.engage("brakes", "declare_torque")
            except Exception:
                pass
            try:
                _led_b = interfaces_mod.IntegrationLedger.from_dict(st.session_state.ledger)
                _it = _led_b.get("brakes") or interfaces_mod.SubsystemInterface(name="brakes")
                _it.brake_torque_nm = round(max(_Tf_need, _Tr_need), 0)
                _led_b.set(_it)
                publish_ledger(_led_b.as_dict())
                st.success(f"Declared "
                           f"{units_mod.from_metric(max(_Tf_need,_Tr_need), 'N·m'):.0f} "
                           f"{units_mod.label('N·m')}/corner. The 3D brake "
                           "discs and heatmap now reflect it.")
                try:
                    _axn.complete("brakes", "declare_torque")
                except Exception:
                    pass
                st.rerun()
            except Exception as _e4:
                st.warning(f"Couldn't declare: {_e4}")
                try:
                    _axn.error("brakes", _e4, kind="declare_torque_failed")
                except Exception:
                    pass

    # =================================================================== #
    elif _bview == "Bolt & bracket FoS":
        # ---------------------------------------------------------------- #
        #  THE "OLD WAY" KILLER.
        #  Every brakes member on this team has hit the same wall: a pedal,
        #  caliper bracket or pedal-box foot is held together by BOLT TORQUE,
        #  and when you drop it into Ansys the only stress you see is a red
        #  ring around the bolt holes — because the preload you typed in was a
        #  guess. "I need to figure out how much torque we will need" is the
        #  pain point verbatim. The old way is: guess a torque, mesh it, see
        #  red, guess again. This view replaces the GUESS with a VDI 2230 /
        #  Shigley hand calc that gives the torque spec, the bolt working
        #  stress, the joint-separation margin and the head-bearing crush
        #  check in closed form — so Ansys becomes a VERIFICATION of a number
        #  you already trust, not the place you discover it.
        # ---------------------------------------------------------------- #
        st.markdown(
            '<p class="hint">The recurring brakes problem: a pedal, caliper '
            'bracket or pedal-box foot is clamped by <b>bolt torque</b>, and the '
            'only stress Ansys shows is a red ring at the bolt holes — because '
            'the preload was a guess. This view computes the <b>torque spec</b> '
            'from first principles (VDI&nbsp;2230 / Shigley): preload from '
            'torque, the bolt working stress, the load at which the joint '
            '<i>gaps open</i>, and whether the head crushes the aluminium. Get '
            'the number here, then let Ansys <i>verify</i> it instead of '
            'discovering it.</p>', unsafe_allow_html=True)

        _bb_mode = st.radio(
            "Check", ["Bolt preload & torque", "Bracket Factor-of-Safety"],
            horizontal=True, key="brake_bolt_mode", label_visibility="collapsed")

        # The braking event that actually loads these joints comes from the
        # Bias & lock-up view: the per-corner lock-up torque the tyre can apply.
        # That torque reacts through the caliper-mount bolts as a tangential
        # force at the rotor effective radius — the external load these bolts see.
        _Tf_corner = float(st.session_state.get("brake_Tf", 380.0))
        _Tr_corner = float(st.session_state.get("brake_Tr", 180.0))
        _reff_m = (st.session_state.get("brake_rotor_dia_mm", 220.0) / 1000.0 / 2) * 0.92

        # ================================================================ #
        if _bb_mode == "Bolt preload & torque":
            st.markdown("##### 🔩 Bolt preload from torque")
            st.markdown(
                '<p class="hint" style="margin:-2px 0 8px;">Pick the bolt and the '
                'joint it clamps. The external tensile load is what one bolt\'s '
                'region must hold; you can seed it from the live brake-torque '
                'reaction below, or type the pull-off load your hand-calc/FEA '
                'gives.</p>', unsafe_allow_html=True)

            _bbc = st.columns(4)
            _b_grade = _bbc[0].selectbox(
                "Bolt grade", list(bolt_mod.BOLT_GRADES.keys()), index=1,
                help="ISO 898-1 property class. 10.9 is the usual motorsport "
                     "socket-head choice.")
            _b_dia = _bbc[1].selectbox(
                "Thread", list(bolt_mod.METRIC_COARSE.keys()),
                index=1, format_func=lambda d: f"M{d:.0f}",
                help="Nominal diameter; the tensile stress-area comes from "
                     "ISO 898-1 metric-coarse.")
            _b_K = _bbc[2].selectbox(
                "Nut factor K", [0.20, 0.15, 0.12],
                format_func=lambda k: {0.20: "0.20 — dry", 0.15: "0.15 — light oil",
                                       0.12: "0.12 — anti-seize"}[k],
                help="The K in T = K·F·d. Lubrication state is the single biggest "
                     "source of preload scatter, so it is exposed, not hidden.")
            _b_torque = unum(_bbc[3], "Assembly torque (N·m)", 2.0, 40.0,
                             float(st.session_state.get("brake_bolt_torque", 8.0)),
                             "N·m", step=0.5, key="brake_bolt_torque",
                             help="The torque the bolt is installed to. This is the "
                                  "number you are trying to spec.")

            _bbc2 = st.columns(4)
            _b_base = _bbc2[0].selectbox(
                "Clamped base material", ["Aluminium 7075", "Aluminium 6061",
                                          "Steel 4130", "Steel mild"],
                help="The softer clamped face (pedal-box base / bracket). Sets the "
                     "head-bearing crush limit.")
            _b_chassis = _bbc2[1].selectbox(
                "Chassis face material", ["Aluminium 6061", "Aluminium 7075",
                                          "Steel 4130", "Steel mild"], index=0)
            _b_grip = unum(_bbc2[2], "Grip / stack thickness (mm)", 3.0, 30.0, 8.0,
                           "mm", step=0.5,
                           help="Total clamped thickness between head and nut.")
            _b_headd = unum(_bbc2[3], "Head/washer ⌀ (mm)", 8.0, 24.0,
                            float(_b_dia) * 1.8, "mm", step=0.5,
                            help="Outer bearing diameter of the head or washer — a "
                                 "bigger washer spreads the crush, exactly the fix "
                                 "the chassis lead suggested.")

            # external tensile load — seedable from the brake-torque reaction
            _bbc3 = st.columns([1, 1, 2])
            _axle_pick = _bbc3[0].selectbox("Reaction from", ["Front corner",
                                                              "Rear corner"],
                                            key="brake_bolt_axle")
            _n_mount = _bbc3[1].number_input("Mount bolts / caliper", 2, 6, 2, 1,
                                             key="brake_bolt_nmount",
                                             help="Bolts sharing the caliper "
                                                  "reaction.")
            _T_corner = _Tf_corner if _axle_pick.startswith("Front") else _Tr_corner

            # Publish the REAL caliper-mount bracket section for the DXF exporter.
            # Everything here is a live brakes number: bolt count and bolt ⌀ from
            # the joint inputs, torque from the bias view. The one dimension the
            # exporter still needs — the mount bolt-circle diameter — has no other
            # home in the app, so we ask for it here (seeded to a typical radial-
            # mount span) rather than invent it. Without a PCD the export honestly
            # stays gated, exactly like the other subsystems.
            _cal_pcd = st.columns([1, 2])[0].number_input(
                "Caliper mount bolt PCD (mm)", 20.0, 200.0,
                value=float(st.session_state.get("brake_cal_pcd", 82.0)),
                step=1.0, key="brake_cal_pcd",
                help="Centre-to-centre span of the caliper mounting bolts (the "
                     "bolt-circle the bracket is drilled to). Measure it off your "
                     "caliper — a typical FSAE radial mount is ~80–90 mm. This "
                     "sizes the exported bracket blank in the Mesh & DXF panel.")
            try:
                _cal_bolt_d = float(_b_dia)
            except Exception:
                _cal_bolt_d = 8.0
            if _n_mount and _cal_pcd:
                try:
                    publish_export_geometry("brakes", {
                        "n_bolts": int(_n_mount),
                        "pcd_mm": round(float(_cal_pcd), 1),
                        "hole_d_mm": round(float(_cal_bolt_d), 1),
                        "brake_torque_nm": round(float(_T_corner), 1),
                        "source": f"brakes tab — caliper mount "
                                  f"({_axle_pick.lower()})",
                    })
                except Exception:
                    pass
            _F_react = _T_corner / max(_reff_m, 1e-3)        # tangential N at rotor
            _F_perbolt_seed = _F_react / max(_n_mount, 1)
            _seed_lbl = (f"Seed from braking: {uval(_T_corner, 'N·m')} corner torque "
                         f"→ {uval(_F_react, 'N')} at the rotor → "
                         f"{uval(_F_perbolt_seed, 'N')}/bolt")
            if _bbc3[2].button("↻ " + _seed_lbl, key="brake_bolt_seed",
                               help="Pull the external load straight from the live "
                                    "lock-up torque the Bias view computed."):
                st.session_state["brake_bolt_extN_val"] = float(round(_F_perbolt_seed, 0))
                st.session_state.pop("brake_bolt_extN", None)
                st.session_state.pop("_u_brake_bolt_extN", None)
                st.rerun()

            _b_extN = unum(st.columns(2)[0], "External tensile load / bolt (N)",
                           0.0, 20000.0,
                           float(st.session_state.get("brake_bolt_extN_val",
                                                      _F_perbolt_seed)),
                           "N", step=50.0, key="brake_bolt_extN",
                           help="Pull-off / separating load this ONE bolt's region "
                                "reacts, before prying. Seed it from braking above, "
                                "or enter your hand-calc value.")
            _b_pry = st.columns(3)[0].slider(
                "Prying factor", 1.0, 3.0, 1.0, 0.1, key="brake_bolt_pry",
                help="1.0 = even share, no prying. >1 = a bending moment levers "
                     "extra tension into the far-edge bolt (the peeling pedal-box "
                     "base). This is the genuinely FEA-shaped input — any value "
                     "above 1.0 flags the result as an estimate.")

            try:
                _fast = bolt_mod.Fastener(
                    grade=_b_grade, nominal_d_mm=float(_b_dia), K_factor=float(_b_K),
                    head_dia_mm=float(_b_headd),
                    hole_dia_mm=float(_b_dia) * 1.1)
                _stack = bolt_mod.ClampedStack(
                    base_material=_b_base, chassis_material=_b_chassis,
                    grip_mm=float(_b_grip))
                _jr = bolt_mod.analyze_joint(
                    _fast, _stack, assembly_torque_Nm=float(_b_torque),
                    external_tensile_N=float(_b_extN),
                    prying_factor=float(_b_pry))
            except Exception as _ejb:
                _jr = None
                st.error(f"Couldn't analyse the joint: {_ejb}")

            if _jr is not None:
                _proof_frac = _jr.sigma_bolt / max(_jr.sigma_proof, 1e-6)
                m = st.columns(4)
                umetric(m[0], "Preload from torque", _jr.F_preload, "N",
                        help="F = T/(K·d). This clamp force is what your Ansys "
                             "bolt-preload field should be set to.")
                m[1].metric("Bolt stress vs proof", f"{_proof_frac*100:.0f}%",
                            delta=f"{(_proof_frac-0.75)*100:+.0f}% vs 75% cap",
                            delta_color="inverse",
                            help="Working stress as a fraction of proof. Stay under "
                                 "~75% so the bolt doesn't yield at install + load.")
                m[2].metric("Joint separation margin",
                            f"{_jr.separation_safety:.2f}×",
                            help="External load to gap the joint ÷ load applied. "
                                 ">1 means the clamp stays closed (good fatigue).",
                            delta=("closed" if not _jr.separated else "GAPPED"),
                            delta_color=("normal" if not _jr.separated else "inverse"))
                if _jr.sigma_bearing is not None:
                    m[3].metric("Head bearing vs crush",
                                f"{_jr.sigma_bearing:.0f}/{_jr.bearing_allow:.0f} MPa",
                                delta=("OK" if not _jr.bearing_yield else "CRUSHES"),
                                delta_color=("normal" if not _jr.bearing_yield
                                             else "inverse"),
                                help="Bearing pressure under the head/washer vs the "
                                     "base material allowance. A bigger washer or a "
                                     "harder base fixes a crush.")

                # the verdict the team actually needs: a torque spec, or a fix
                if _jr.separated:
                    st.error(
                        f"✗ Joint SEPARATES at this load: the {uval(_b_extN,'N')} "
                        f"pull-off exceeds the {uval(_jr.F_sep,'N')} gap-opening "
                        "load, so the bolt takes the full raw load and spikes. "
                        "Raise the torque, go up a bolt size, or add bolts — then "
                        "re-check.")
                elif _proof_frac > 0.75:
                    st.error(
                        f"✗ Over-torqued: at {uval(_b_torque,'N·m')} the bolt sits "
                        f"at {_proof_frac*100:.0f}% of proof before the brake load "
                        "is fully on — it will yield at install. Drop the torque or "
                        "use a higher grade. This is exactly the red ring Ansys "
                        "shows; the fix is here, not in the mesh.")
                elif _jr.bearing_yield:
                    st.error(
                        f"✗ Head bearing crushes the base: "
                        f"{_jr.sigma_bearing:.0f} MPa > "
                        f"{_jr.bearing_allow:.0f} MPa allowable. Fit a hardened "
                        "steel washer to spread the load (the chassis lead's tip), "
                        "or use a harder base material.")
                else:
                    _hi_t = _b_torque * (0.75 / max(_proof_frac, 1e-6))
                    st.success(
                        f"✓ Torque spec is sound: at {uval(_b_torque,'N·m')} the "
                        f"preload is {uval(_jr.F_preload,'N')}, the bolt sits at "
                        f"{_proof_frac*100:.0f}% of proof, the joint stays clamped "
                        f"({_jr.separation_safety:.1f}× separation margin) and the "
                        "head doesn't crush the base. You have head-room to "
                        f"~{uval(_hi_t,'N·m')} before hitting the 75% proof cap. "
                        "Set your Ansys bolt-preload to the clamp force above and "
                        "the sim should confirm — not surprise — you.")
                if _jr.is_estimate:
                    st.info(
                        f"⚠ Prying factor {_jr.prying_factor:.1f} makes this an "
                        "ESTIMATE — the true lever ratio comes from the bracket's "
                        "stiffness/footprint (hand-calc or FEA). The bolt mechanics "
                        "above are exact; only the load amplification is assumed.")
                if _jr.notes:
                    st.caption(_jr.notes)

                # ---- DECLARE THE TORQUE SPEC INTO THE INTEGRATION LEDGER ---- #
                #  Mirrors the brake-torque declare in the Hydraulic view: once a
                #  defensible torque spec exists, push it to the ledger so the rest
                #  of the car (and the design-review board) sees the clamp force the
                #  structure must carry and the exact assembly torque + bolt spec —
                #  the provenance judges ask for, instead of a number in someone's
                #  head. Only offered when the joint is actually sound.
                _spec_ok = (not _jr.separated and _proof_frac <= 0.75
                            and not (_jr.bearing_yield or False))
                if _spec_ok:
                    _dc = st.columns([3, 2])
                    if _dc[0].button(
                            "📌 Declare this bolt torque spec in the INTEGRATION "
                            "ledger", key="brake_bolt_declare",
                            help="Writes the clamp force into the brakes interface "
                                 "mount load, and records the torque + bolt spec in "
                                 "the rationale so the board and the structures "
                                 "member see the exact number, not a guess."):
                        try:
                            _led_bb = interfaces_mod.IntegrationLedger.from_dict(
                                st.session_state.ledger)
                            _it_bb = (_led_bb.get("brakes")
                                      or interfaces_mod.SubsystemInterface(
                                          name="brakes"))
                            _it_bb.mount_load_n = round(_jr.F_preload, 0)
                            _it_bb.mount_points = int(_n_mount)
                            _it_bb.mounts_on = "chassis"
                            _it_bb.is_estimate = bool(_jr.is_estimate)
                            _spec_txt = (
                                f"Caliper-mount bolt spec ({_axle_pick.lower()}): "
                                f"M{_b_dia:.0f} {_b_grade}, K={_b_K:.2f}, "
                                f"torque {uval(_b_torque,'N·m')} → preload "
                                f"{uval(_jr.F_preload,'N')}/bolt "
                                f"({_proof_frac*100:.0f}% of proof), "
                                f"separation margin {_jr.separation_safety:.1f}×. "
                                "Set ANSYS bolt-preload to the clamp force above.")
                            _it_bb.rationale = _spec_txt
                            _it_bb.updated_by = "brakes"
                            _led_bb.set(_it_bb)
                            publish_ledger(_led_bb.as_dict())
                            st.success(
                                f"Declared {uval(_jr.F_preload,'N')}/bolt clamp "
                                f"force over {int(_n_mount)} mount bolts. The "
                                "structures member now sees the load the chassis "
                                "must carry, and the torque spec is on record.")
                            st.rerun()
                        except Exception as _edb:
                            st.warning(f"Couldn't declare: {_edb}")
                    _dc[1].caption("Keeps the spec out of someone's head and in "
                                   "the shared ledger.")

                # torque sweep: stress & separation margin vs assembly torque, so
                # the team SEES the safe torque window instead of guessing inside it
                _Tsweep = np.linspace(2.0, 40.0, 60)
                _sig, _sepm = [], []
                for _Tt in _Tsweep:
                    try:
                        _rr = bolt_mod.analyze_joint(
                            _fast, _stack, assembly_torque_Nm=float(_Tt),
                            external_tensile_N=float(_b_extN),
                            prying_factor=float(_b_pry))
                        _sig.append(_rr.sigma_bolt / _rr.sigma_proof * 100.0)
                        _sepm.append(min(_rr.separation_safety, 10.0))
                    except Exception:
                        _sig.append(float("nan")); _sepm.append(float("nan"))
                _Tdisp = [units_mod.from_metric(t, "N·m") for t in _Tsweep]
                _uT = units_mod.label("N·m")
                _fbt = go.Figure()
                _fbt.add_trace(go.Scatter(
                    x=_Tdisp, y=_sig, name="bolt stress (% of proof)",
                    line=dict(color="#ff9f43", width=3)))
                _fbt.add_trace(go.Scatter(
                    x=_Tdisp, y=_sepm, name="separation margin (×, capped 10)",
                    line=dict(color="#37e0d0", width=2, dash="dot"), yaxis="y2"))
                _fbt.add_hline(y=75, line=dict(color="#ff5a52", dash="dash"),
                               annotation_text="75% proof cap",
                               annotation_position="top left")
                _fbt.add_vline(
                    x=units_mod.from_metric(float(_b_torque), "N·m"),
                    line=dict(color="#6f7d8c", dash="dot"),
                    annotation_text="your torque")
                _fbt.update_layout(
                    title="Bolt stress & separation margin vs assembly torque",
                    xaxis_title=f"assembly torque ({_uT})",
                    yaxis=dict(title="bolt stress (% proof)", color="#ff9f43"),
                    yaxis2=dict(title="separation ×", overlaying="y", side="right",
                                color="#37e0d0", range=[0, 10]),
                    height=340, paper_bgcolor="rgba(0,0,0,0)",
                    plot_bgcolor="rgba(0,0,0,0)",
                    font=dict(color="#cdd6df", size=11),
                    margin=dict(l=0, r=0, t=36, b=0),
                    legend=dict(bgcolor="rgba(0,0,0,0)", orientation="h",
                                y=-0.25))
                st.plotly_chart(_fbt, width='stretch', key="brake_bolt_sweep")
                st.markdown(
                    '<p class="hint">The window between "too loose" (low '
                    'separation margin, left) and "yields at install" (crosses the '
                    '75% proof line, right) <b>is</b> your torque spec. Pick the '
                    'middle of it, then verify in Ansys with the preload set to the '
                    'clamp force — the sim should be boring.</p>',
                    unsafe_allow_html=True)

        # ================================================================ #
        else:   # Bracket Factor-of-Safety
            st.markdown("##### 📐 Bracket Factor-of-Safety (yield, FoS ≥ 1.5)")
            st.markdown(
                '<p class="hint" style="margin:-2px 0 8px;">The chassis-team rule '
                'is FoS&nbsp;≥&nbsp;1.5 on <b>yield</b> for every mount. Screen a '
                'caliper bracket or pedal tab here in five seconds and find which '
                'failure mode governs — root bending almost always wins, which is '
                'why the plate looks fine but the FEA lights up at the root. '
                'Passing here means the part is worth meshing; failing means fix '
                'it before you waste a sim.</p>', unsafe_allow_html=True)

            _kc = st.columns(4)
            _k_mat = _kc[0].selectbox(
                "Bracket material", list(bracket_mod.MATERIALS.keys()),
                help="Yield comes from this library — welded HAZ grades carry the "
                     "knock-down already.")
            _k_w = unum(_kc[1], "Width (mm)", 8.0, 80.0, 30.0, "mm", step=1.0,
                        help="Plate width across the bending section.")
            _k_t = unum(_kc[2], "Thickness (mm)", 1.0, 12.0, 3.175, "mm", step=0.25,
                        help="Plate thickness. 1/8 in = 3.175 mm — the sheet the "
                             "team is already simulating.")
            _k_lever = unum(_kc[3], "Lever arm to root (mm)", 0.0, 80.0, 20.0, "mm",
                            step=1.0,
                            help="Distance from the load line to the welded/bolted "
                                 "root. This arm is what creates the root bending "
                                 "moment that governs.")

            _kc2 = st.columns(4)
            _k_hole = unum(_kc2[0], "Bolt-hole ⌀ (mm)", 3.0, 14.0, 6.6, "mm",
                           step=0.1, help="Clearance hole — sets bearing & tear-out.")
            _k_edge = unum(_kc2[1], "Edge distance (mm)", 4.0, 30.0, 10.0, "mm",
                           step=0.5, help="Hole centre to nearest free edge "
                                          "(tear-out path).")
            _k_nb = _kc2[2].number_input("Bolts in pattern", 1, 6, 2, 1,
                                         help="Bolts sharing the direct load.")
            _k_shear = _kc2[3].selectbox(
                "Direct load is", ["Shear (in-plane)", "Tension (pull-off)"],
                help="How the non-bending part of the load hits the section.")

            # seed the load from the live caliper reaction
            _kc3 = st.columns([1, 2])
            _k_axle = _kc3[0].selectbox("Load from", ["Front corner", "Rear corner"],
                                        key="brake_brk_axle")
            _T_k = _Tf_corner if _k_axle.startswith("Front") else _Tr_corner
            _F_k_seed = _T_k / max(_reff_m, 1e-3)
            if _kc3[1].button(
                    f"↻ Seed load from braking: {uval(_F_k_seed,'N')} caliper "
                    "reaction", key="brake_brk_seed"):
                st.session_state["brake_brk_P_val"] = float(round(_F_k_seed, 0))
                st.session_state.pop("brake_brk_P", None)
                st.session_state.pop("_u_brake_brk_P", None)
                st.rerun()
            _k_P = unum(st.columns(2)[0], "Worst-case load on bracket (N)",
                        0.0, 20000.0,
                        float(st.session_state.get("brake_brk_P_val", _F_k_seed)),
                        "N", step=50.0, key="brake_brk_P",
                        help="The reaction the bracket carries. Seed from braking "
                             "or enter your own.")

            try:
                _brk = bracket_mod.Bracket(
                    name="brake bracket", material=_k_mat,
                    width_mm=float(_k_w), thickness_mm=float(_k_t),
                    P_N=float(_k_P), lever_arm_mm=float(_k_lever),
                    hole_dia_mm=float(_k_hole), edge_dist_mm=float(_k_edge),
                    n_bolts=int(_k_nb),
                    load_is_shear=_k_shear.startswith("Shear"))
                _kres = bracket_mod.screen_bracket(_brk, fos_target=1.5)
            except Exception as _ekb:
                _kres = None
                st.error(f"Couldn't screen the bracket: {_ekb}")

            if _kres is not None:
                _vmap = {"PASS": ("✓", st.success), "TIGHT": ("≈", st.warning),
                         "FAIL": ("✗", st.error), "INVALID": ("?", st.warning)}
                _vi, _vfn = _vmap.get(_kres.verdict, ("·", st.info))
                m = st.columns(3)
                m[0].metric("Min FoS (yield)", f"{_kres.min_fos:.2f}",
                            delta=f"{_kres.min_fos-1.5:+.2f} vs 1.5",
                            delta_color=("normal" if _kres.min_fos >= 1.5
                                         else "inverse"))
                m[1].metric("Governing mode", _kres.governing_mode.title())
                m[2].metric("Verdict", _kres.verdict)
                try:
                    record_activity("brakes", "material",
                                    f"Bracket material: {_k_mat}")
                    record_activity(
                        "brakes", "calculation",
                        f"Bracket FoS: min {_kres.min_fos:.2f} in "
                        f"{_kres.governing_mode} → {_kres.verdict}")
                except Exception:
                    pass
                _vfn(f"{_vi} {_kres.verdict}: minimum FoS {_kres.min_fos:.2f} in "
                     f"{_kres.governing_mode}. "
                     + ("Worth meshing — Ansys should confirm this margin."
                        if _kres.verdict in ("PASS", "TIGHT")
                        else "Fix it before you mesh: thicken the plate, shorten "
                             "the lever arm, or widen the section. Root bending "
                             "scales with t², so a thicker plate pays off fast."))

                # per-mode FoS bar — shows WHICH mode governs at a glance
                _modes = [mm for mm in _kres.modes]
                if _modes:
                    _fk = go.Figure()
                    _fk.add_trace(go.Bar(
                        x=[mm.fos if mm.fos < 20 else 20 for mm in _modes],
                        y=[mm.mode for mm in _modes], orientation="h",
                        marker_color=["#ff5a52" if mm.governs else "#5ad17a"
                                      for mm in _modes],
                        text=[f"{mm.fos:.2f}" for mm in _modes],
                        textposition="auto"))
                    _fk.add_vline(x=1.5, line=dict(color="#37e0d0", dash="dash"),
                                  annotation_text="FoS 1.5")
                    _fk.update_layout(
                        title="Factor of Safety by failure mode (capped at 20)",
                        xaxis_title="FoS on yield", height=300,
                        paper_bgcolor="rgba(0,0,0,0)", plot_bgcolor="rgba(0,0,0,0)",
                        font=dict(color="#cdd6df", size=11),
                        margin=dict(l=0, r=0, t=36, b=0))
                    st.plotly_chart(_fk, width='stretch', key="brake_brk_modes")
                if _kres.screening_only:
                    st.caption("Screening only — closed-form hand calc, no stress "
                               "concentration or weld-toe HAZ. A PASS here earns "
                               "the Ansys run; it doesn't replace it.")

    # =================================================================== #
    elif _bview == "Pedal box & throttle":
        # ---------------------------------------------------------------- #
        #  What the brakes / pedal-box lead asked for, in one place:
        #    (a) throttle return: TWO springs, and it must STILL return to
        #        closed if any ONE unhooks  ("needs to still bounce if even
        #        one unhooks") — the FSAE two-independent-return-spring rule,
        #        modelled as net closing torque with each spring removed;
        #    (b) "we don't know the spring constant" — back k out on the bench
        #        or from coil geometry, no magic default;
        #    (c) the brake pedal must withstand 2000 N — screened on the same
        #        FoS>=1.5-on-yield rule every other bracket uses.
        #  This is the Simulink-replacement: the redundancy logic and the
        #  pedal gate live next to the hydraulic chain, not in a side model.
        # ---------------------------------------------------------------- #
        try:
            from suspension import throttle_return as _tr
            from suspension import throttle_return_ingest as _ing
        except Exception as _tre:   # pragma: no cover - defensive UI guard
            _tr = None
            _ing = None
            st.error(f"Throttle-return module unavailable: {_tre}")

        if _tr is not None:
            _pv = st.radio(
                "Check", ["Throttle return springs", "Brake pedal 2000 N"],
                horizontal=True, key="pedal_view", label_visibility="collapsed")

            # ============================================================ #
            if _pv == "Throttle return springs":
                # Brief imperial read-out under a metric field so US members can read
                # the numbers, WITHOUT converting the inputs (spring specs stay in
                # mm / N·m / N·mm — unambiguous and matching datasheets — so the
                # safety calc never round-trips through a unit conversion).
                def _imp(container, metric_val, unit, fmt="{:.2f}"):
                    try:
                        if units_mod.is_us():
                            _iv = units_mod.from_metric(float(metric_val), unit)
                            container.caption(
                                f"≈ {fmt.format(_iv)} {units_mod.label(unit)}")
                    except Exception:
                        pass

                st.markdown(
                    '<p class="hint">FSAE requires <b>two</b> return springs, '
                    'arranged so the throttle still returns to <b>closed</b> if '
                    '<i>any one component fails</i> — including one spring coming '
                    'unhooked. Sensors (TPS/APPS) do <b>not</b> count. This view '
                    'models the <b>net closing torque</b> across pedal travel with '
                    'every single spring removed in turn: it passes only if the car '
                    'still shuts the throttle on one spring, with margin over '
                    'friction and cable drag.</p>', unsafe_allow_html=True)
                if units_mod.is_us():
                    st.caption("You're in US/Imperial — spring specs stay in mm / "
                               "N·mm / N·m (how spring datasheets read), with the "
                               "imperial equivalent shown under each field.")

                # ---- "We don't know k" — get it honestly -------------------
                with st.expander("Don't know the spring constant? Get it here "
                                 "(bench log, single measurement, or coil geometry)",
                                 expanded=False):
                    st.markdown(
                        '<p class="hint" style="margin:-2px 0 8px;">Three honest ways. '
                        'A <b>bench log</b> is best — upload the CSV and the rate is '
                        'fitted from the real part, no retyping, with the R² so you '
                        'can see how linear it actually is.</p>',
                        unsafe_allow_html=True)

                    # Boundary-breaker: fit k straight from a measured force/deflection
                    # log, so the number the redundancy check uses IS the real spring's
                    # rate, not something a human transcribed off the bench.
                    _blog = st.file_uploader(
                        "Bench log CSV (force + deflection columns)",
                        type=["csv", "tsv", "txt"], key="tr_bench_log",
                        help="Columns like 'force_N' and 'deflection_mm'. Hang several "
                             "known loads, record deflection at each. The rate is "
                             "least-squares fitted from the data.")
                    _bcol = st.columns(2)
                    _kgf = _bcol[0].checkbox(
                        "force column is mass in kgf", value=False, key="tr_bench_kgf",
                        help="Tick if you logged hung MASS (kg) rather than force (N).")
                    _bcol[1].download_button(
                        "⬇ Template CSV", key="tr_bench_template",
                        data=("deflection_mm,force_N\n0,0\n10,5\n20,10\n30,15\n"
                              "40,20\n50,25\n"),
                        file_name="throttle_spring_bench_log_template.csv",
                        mime="text/csv",
                        help="Fill in your measured deflection at each hung load, then "
                             "upload it above.")
                    if _blog is not None:
                        try:
                            _fit = _ing.spring_rate_from_bench_log(
                                _blog.getvalue(), force_in_kgf=_kgf)
                            for _ff in _fit.findings:
                                _sev = {"ok": st.success, "warning": st.warning,
                                        "fail": st.error,
                                        "missing": st.info}.get(_ff.severity.value,
                                                                st.info)
                                _sev(_ff.message)
                            if _fit.is_trustworthy:
                                st.session_state["tr_k_measured"] = _fit.k_N_per_m
                                st.caption(
                                    f"Using fitted k = {_fit.k_N_per_m:.0f} N/m "
                                    f"(R²={_fit.r_squared:.4f}, {_fit.n_points} pts). "
                                    "The spring inputs below are pre-filled from this.")
                            else:
                                st.caption("Fit not trustworthy — not feeding it "
                                           "forward. Fix the log or use another method.")
                        except Exception as _fe:
                            st.warning(f"Couldn't read the bench log: {_fe}")

                    st.markdown("---")
                    _kc = st.columns(2)
                    with _kc[0]:
                        st.markdown("**Single measurement:** one known load & travel")
                        _bf = st.number_input("Load hung (N)", 1.0, 500.0, 19.6,
                                              step=1.0, key="tr_bench_F",
                                              help="A labelled gym plate or a luggage "
                                                   "scale pulled to a mark.")
                        _imp(st, _bf, "N", "{:.1f}")
                        _bx = st.number_input("Deflection (mm)", 1.0, 300.0, 35.0,
                                              step=1.0, key="tr_bench_x")
                        _imp(st, _bx, "mm", "{:.2f}")
                        try:
                            _kb = _tr.k_from_deflection(_bf, _bx / 1000.0)
                            st.success(f"k = {_kb:.0f} N/m  (= {_kb/1000:.2f} N/mm)")
                            # A single point is weaker than a fitted log; only seed the
                            # default if a trustworthy log hasn't already set it.
                            st.session_state.setdefault("tr_k_measured", _kb)
                        except Exception as _ke:
                            st.warning(str(_ke))
                    with _kc[1]:
                        st.markdown("**Coil geometry** (datasheet or measure)")
                        _wd = st.number_input("Wire dia d (mm)", 0.2, 6.0, 1.2,
                                              step=0.1, key="tr_wire_d")
                        _imp(st, _wd, "mm", "{:.3f}")
                        _cd = st.number_input("Mean coil dia D (mm)", 2.0, 40.0, 9.0,
                                              step=0.5, key="tr_coil_D",
                                              help="Mean = outer dia − wire dia.")
                        _imp(st, _cd, "mm", "{:.3f}")
                        _na = st.number_input("Active coils Na", 1.0, 40.0, 6.0,
                                              step=0.5, key="tr_active_n",
                                              help="Total turns minus the dead end "
                                                   "coils (~2 for squared/ground ends).")
                        _wm = st.selectbox("Wire material",
                                           list(_tr.WIRE_SHEAR_MODULUS_PA.keys()),
                                           key="tr_wire_mat")
                        try:
                            _kg = _tr.k_compression_spring(
                                _wd / 1000.0, _cd / 1000.0, _na, material=_wm)
                            st.info(f"k = {_kg:.0f} N/m  (= {_kg/1000:.2f} N/mm)")
                        except Exception as _ge:
                            st.warning(str(_ge))

                st.markdown("##### Return springs on the pedal")
                st.markdown(
                    '<p class="hint" style="margin:-2px 0 8px;">Both springs are '
                    'checked as entered — the tool never assumes the backup matches '
                    'the primary, because the whole point is surviving the loss of '
                    '<i>either specific</i> spring. If your two springs really are the '
                    'same part, use <b>Copy primary → backup</b> to fill it fast, then '
                    'confirm the backup\'s arm/preload (they often differ even with an '
                    'identical spring). If a rate is a guess, leave <i>measured k?</i> '
                    'unticked.</p>', unsafe_allow_html=True)

                # Convenience only, NOT an assumption: this copies the primary's values
                # into the backup's input keys, then the backup is still shown and still
                # checked as its own spring. Nothing is cloned behind the user's back.
                if st.button("⧉ Copy primary → backup",
                             key="tr_copy_primary",
                             help="Pre-fill the backup with the primary's numbers so "
                                  "you can tweak from there. The backup is still shown "
                                  "and checked on its own values — this only saves "
                                  "typing, it does not assume they match."):
                    for _fld in ("k", "arm", "pre", "trav", "meas"):
                        _src = st.session_state.get(f"tr_{_fld}_primary")
                        if _src is not None:
                            st.session_state[f"tr_{_fld}_backup"] = _src
                    st.rerun()

                _k_seed = float(st.session_state.get("tr_k_measured", 500.0))
                _springs = []
                for _i, _nm in enumerate(("primary", "backup")):
                    st.markdown(f"**Spring {_i+1} — {_nm}**")
                    _sc = st.columns(5)
                    _sk = _sc[0].number_input(
                        f"rate k (N/mm) [{_nm}]", 0.05, 200.0,
                        round(_k_seed / 1000.0, 2), step=0.05, key=f"tr_k_{_nm}")
                    _imp(_sc[0], _sk, "N/mm", "{:.1f}")
                    _sarm = _sc[1].number_input(
                        f"moment arm (mm) [{_nm}]", 2.0, 120.0, 30.0, step=1.0,
                        key=f"tr_arm_{_nm}",
                        help="Perpendicular distance pivot→spring line of action.")
                    _imp(_sc[1], _sarm, "mm", "{:.2f}")
                    _spre = _sc[2].number_input(
                        f"preload stretch (mm) [{_nm}]", 0.0, 100.0, 15.0, step=1.0,
                        key=f"tr_pre_{_nm}",
                        help="How far the spring is stretched at the CLOSED stop — "
                             "this is what holds the pedal shut when released.")
                    _imp(_sc[2], _spre, "mm", "{:.2f}")
                    _strav = _sc[3].number_input(
                        f"extra stretch, closed→open (mm) [{_nm}]", 0.0, 120.0,
                        40.0, step=1.0, key=f"tr_trav_{_nm}")
                    _imp(_sc[3], _strav, "mm", "{:.2f}")
                    _smeas = _sc[4].checkbox(f"measured k? [{_nm}]", value=False,
                                             key=f"tr_meas_{_nm}")
                    _springs.append(_tr.ReturnSpring.from_linear_spring(
                        _nm, k_N_per_m=_sk * 1000.0, moment_arm_m=_sarm / 1000.0,
                        preload_stretch_m=_spre / 1000.0,
                        travel_stretch_m=_strav / 1000.0,
                        is_estimate=not _smeas))

                st.markdown("##### What fights the return (be generous)")
                _rc = st.columns(4)
                _fr = _rc[0].number_input("pivot friction (N·m)", 0.0, 5.0, 0.10,
                                          step=0.02, key="tr_fric",
                                          help="Worst-case Coulomb friction / stiction "
                                               "at the pivot and linkage.")
                _imp(_rc[0], _fr, "N·m", "{:.3f}")
                _cdg = _rc[1].number_input("cable/rod drag (N·m)", 0.0, 5.0, 0.05,
                                           step=0.02, key="tr_cable")
                _imp(_rc[1], _cdg, "N·m", "{:.3f}")
                _sd = _rc[2].number_input("sensor detent (N·m)", 0.0, 5.0, 0.02,
                                          step=0.02, key="tr_sensor",
                                          help="Any return-fighting torque from the "
                                               "TPS/APPS body. Sensors are not springs.")
                _imp(_rc[2], _sd, "N·m", "{:.3f}")
                _mt = _rc[3].number_input("margin target", 0.25, 4.0, 1.0, step=0.25,
                                          key="tr_margin",
                                          help="Required net closing authority over "
                                               "resistance in the worst single-failure "
                                               "case. 1.0 = clears resistance with 100% "
                                               "margin on the surviving spring.")
                _res = _tr.ReturnResistance(friction_Nm=_fr, cable_drag_Nm=_cdg,
                                            sensor_detent_Nm=_sd)

                _rr = _tr.check_return_redundancy(_springs, _res, margin_target=_mt)

                # Make the live result available to the cross-discipline mythbuster,
                # so a claim like "the springs are identical, backup's fine" is checked
                # against THESE numbers, not just physics.
                st.session_state["throttle_return_result"] = _rr

                # Frictionless framing: if the user hasn't entered their OWN numbers
                # yet (both springs still estimates, no bench-fitted rate), don't shout
                # a red FAIL at them on example data — say plainly it's provisional and
                # what to do. A FAIL should mean YOUR car fails, not "you haven't
                # started". The computation is unchanged; only the framing adapts.
                _on_example_data = (
                    _rr.is_estimate
                    and st.session_state.get("tr_k_measured") is None)
                if _on_example_data:
                    st.info(
                        f"▶ Provisional (example numbers): would be **{_rr.verdict}** — "
                        f"worst single-failure case {_rr.worst_case}, margin "
                        f"{_rr.worst_margin:.2f}. Enter your springs (or drop a bench "
                        f"log above) to check your actual throttle. Nothing here is "
                        f"your car yet.")
                else:
                    _vcol = {"PASS": st.success, "TIGHT": st.warning,
                             "FAIL": st.error, "INVALID": st.error}[_rr.verdict]
                    _vcol(f"{_rr.verdict} — worst single-failure case: {_rr.worst_case} "
                          f"(margin {_rr.worst_margin:.2f} over resistance)")

                # Table of every case
                try:
                    import pandas as _pd
                    _us = units_mod.is_us()
                    def _row(_c):
                        r = {
                            "case": _c.label,
                            "net closing @ closed (N·m)": round(_c.net_closed_Nm, 3),
                            "net closing @ open (N·m)": round(_c.net_open_Nm, 3),
                        }
                        if _us:
                            r["closed (lbf·ft)"] = round(
                                units_mod.from_metric(_c.net_closed_Nm, "N·m"), 3)
                            r["open (lbf·ft)"] = round(
                                units_mod.from_metric(_c.net_open_Nm, "N·m"), 3)
                        r["returns to closed?"] = ("yes" if _c.closes
                                                   else "NO — HANGS OPEN")
                        return r
                    _df = _pd.DataFrame([_row(_c) for _c in _rr.cases])
                    st.dataframe(_df, width='stretch', hide_index=True)
                except Exception:
                    for _c in _rr.cases:
                        st.write(f"{_c.label}: closed={_c.net_closed_Nm:.2f} "
                                 f"open={_c.net_open_Nm:.2f} "
                                 f"{'closes' if _c.closes else 'HANGS OPEN'}")

                for _f in _rr.findings:
                    _msev = {"ok": st.success, "warning": st.warning,
                             "fail": st.error}.get(_f.severity.value, st.info)
                    _msev(_f.message)
                for _n in _rr.notes:
                    st.caption("note: " + _n)

                # -------------------------------------------------------- #
                #  Transient return-time (snap-shut) — how FAST it closes,
                #  and whether stiction stalls it, with each spring removed.
                #  The redundancy table above is a torque balance; this is
                #  the dynamics: spin the throttle inertia against the spring.
                # -------------------------------------------------------- #
                with st.expander("Return time & snap (transient) — how fast does it "
                                 "actually close, with one spring gone?",
                                 expanded=False):
                    st.markdown(
                        '<p class="hint" style="margin:-2px 0 8px;">The table above is '
                        'a torque balance (does it close). This spins the throttle\'s '
                        'rotating <b>inertia</b> against the spring to time the '
                        '<b>snap-shut</b> — and catches a return that stalls on '
                        'stiction partway. Inertia is the unknown here, like the '
                        'spring rate was; estimate it from geometry or type a measured '
                        'value. Result is flagged as an estimate until the inertia '
                        'is real.</p>', unsafe_allow_html=True)

                    _ic = st.columns(4)
                    _plate_m = _ic[0].number_input(
                        "throttle plate mass (g)", 1.0, 200.0, 25.0, step=1.0,
                        key="snap_plate_m",
                        help="Mass of the throttle plate/flap.") / 1000.0
                    _imp(_ic[0], _plate_m * 1000.0, "g_mass", "{:.2f}")
                    _plate_r = _ic[1].number_input(
                        "plate half-width (mm)", 2.0, 60.0, 20.0, step=1.0,
                        key="snap_plate_r",
                        help="Half the plate width (rotation radius).") / 1000.0
                    _imp(_ic[1], _plate_r * 1000.0, "mm", "{:.2f}")
                    _refl_m = _ic[2].number_input(
                        "cable+pedal mass (g)", 0.0, 1000.0, 0.0, step=10.0,
                        key="snap_refl_m",
                        help="Optional: pedal/cable mass reflected to the shaft.") / 1000.0
                    _imp(_ic[2], _refl_m * 1000.0, "g_mass", "{:.2f}")
                    _refl_a = _ic[3].number_input(
                        "at arm (mm)", 0.0, 200.0, 0.0, step=5.0,
                        key="snap_refl_a",
                        help="Lever arm for that reflected mass.") / 1000.0
                    _imp(_ic[3], _refl_a * 1000.0, "mm", "{:.2f}")
                    _theta_open = st.number_input(
                        "throttle travel, closed→open (deg)", 10.0, 120.0, 90.0,
                        step=5.0, key="snap_theta_open")

                    _inertia = _tr.estimate_throttle_inertia(
                        plate_mass_kg=_plate_m, plate_radius_m=_plate_r,
                        cable_pedal_mass_kg=_refl_m, pedal_arm_m=_refl_a)
                    st.caption(f"Estimated rotating inertia ≈ {_inertia.I_kgm2:.2e} "
                               f"kg·m² (geometry estimate — replace with CAD "
                               f"mass-properties or a spin-down test to trust the ms).")

                    # Advanced physics: cable slack/backlash, nonlinear cam, aero.
                    # All default OFF, so the simple model is unchanged unless used.
                    _snap_model = None
                    with st.expander("Advanced: cable slack/backlash · nonlinear cam · "
                                     "aero load on the plate", expanded=False):
                        _ac = st.columns(2)
                        _lash_deg = _ac[0].number_input(
                            "cable backlash / dead band (deg)", 0.0, 45.0, 0.0,
                            step=1.0, key="snap_lash_deg",
                            help="Plate travel at the start of the return where the "
                                 "spring is taking up cable/linkage slack and isn't "
                                 "yet acting on the plate.")
                        _lash_frac = _ac[1].number_input(
                            "spring fraction reaching plate in that band", 0.0, 1.0,
                            0.0, step=0.1, key="snap_lash_frac",
                            help="0 = spring fully disconnected through the slack "
                                 "(plate unsprung there); 1 = no effect.")
                        st.markdown("**Nonlinear cam profile** (plate angle → torque "
                                    "multiplier; leave default for a linear mechanism)")
                        _cam_on = st.checkbox("use a cam profile", value=False,
                                              key="snap_cam_on")
                        _cam_profile = None
                        if _cam_on:
                            _cc = st.columns(3)
                            _m_closed = _cc[0].number_input(
                                "mult @ closed (0°)", 0.1, 3.0, 0.7, step=0.1,
                                key="snap_cam_closed")
                            _m_mid = _cc[1].number_input(
                                "mult @ mid", 0.1, 3.0, 1.0, step=0.1,
                                key="snap_cam_mid")
                            _m_open = _cc[2].number_input(
                                "mult @ open", 0.1, 3.0, 1.3, step=0.1,
                                key="snap_cam_open")
                            _cam_profile = [(0.0, _m_closed),
                                            (_theta_open / 2.0, _m_mid),
                                            (_theta_open, _m_open)]
                        st.markdown("**Aero load on the plate** (needs a real "
                                    "coefficient — defaults to zero and is flagged)")
                        _aec = st.columns(4)
                        _intake_v = _aec[0].number_input(
                            "intake speed (m/s)", 0.0, 120.0, 0.0, step=5.0,
                            key="snap_intake_v",
                            help="Airflow speed past the plate. If you set this but "
                                 "leave the coefficient at 0, aero is treated as zero "
                                 "and flagged — no invented number.")
                        _aero_coeff = _aec[1].number_input(
                            "aero torque coeff", 0.0, 10.0, 0.0, step=0.1,
                            key="snap_aero_coeff",
                            help="From a flow bench or CFD. 0 = aero off.")
                        _plate_A = _aec[2].number_input(
                            "plate area (cm²)", 0.0, 50.0, 0.0, step=0.5,
                            key="snap_plate_A") / 1e4
                        _aero_opens = _aec[3].checkbox(
                            "aero opens plate", value=True, key="snap_aero_opens",
                            help="Airflow tends to hold the plate OPEN (the dangerous "
                                 "case) rather than help it close.")
                        if (_lash_deg > 0 or _cam_profile is not None
                                or _intake_v > 0):
                            _snap_model = _tr.SnapModel(
                                backlash_deg=_lash_deg,
                                backlash_spring_frac=_lash_frac,
                                cam_profile=_cam_profile,
                                aero_torque_coeff=_aero_coeff,
                                aero_opens_plate=_aero_opens,
                                intake_speed_ms=_intake_v,
                                plate_area_m2=_plate_A,
                                plate_radius_m=_plate_r)

                    _snaps = _tr.simulate_return_snap_single_failures(
                        _springs, _inertia, _res, theta_open_deg=_theta_open,
                        model=_snap_model)
                    try:
                        import pandas as _pd2
                        _sd = _pd2.DataFrame([{
                            "case": _lbl,
                            "returns?": "yes" if _sr.returns else "NO — HANGS",
                            "return time": (f"{_sr.return_time_s*1000:.0f} ms"
                                            if _sr.returns
                                            else f"stalls @ {_sr.hung_at_deg:.0f}°"),
                            "peak speed (rad/s)": round(_sr.peak_speed_rad_s, 1),
                        } for _lbl, _sr in _snaps.items()])
                        st.dataframe(_sd, width='stretch', hide_index=True)
                    except Exception:
                        for _lbl, _sr in _snaps.items():
                            _t = (f"{_sr.return_time_s*1000:.0f} ms" if _sr.returns
                                  else f"HANGS @ {_sr.hung_at_deg:.0f}°")
                            st.write(f"{_lbl}: {_t}")

                    # surface the worst single-failure case's finding
                    _sf = {k: v for k, v in _snaps.items() if k.startswith("without")}
                    if _sf:
                        _worst = max(_sf.values(),
                                     key=lambda s: (0 if s.returns else 1,
                                                    s.return_time_s if s.returns else 0))
                        for _f in _worst.findings:
                            _msev = {"ok": st.success, "warning": st.warning,
                                     "fail": st.error}.get(_f.severity.value, st.info)
                            _msev(_f.message)

                # -------------------------------------------------------- #
                #  Manifold-pressure coupling + plate-flutter screen.
                #  Deeper physics for the ANSYS hand-off: the coupled plate+
                #  plenum ODE and a flutter stability screen. Both are honest
                #  about being SCREENS — flutter especially needs a real aero
                #  coefficient or it says so.
                # -------------------------------------------------------- #
                try:
                    from suspension import throttle_dynamics as _td
                except Exception:
                    _td = None
                if _td is not None:
                    with st.expander("Manifold coupling & plate flutter (pre-ANSYS "
                                     "screen)", expanded=False):
                        st.markdown(
                            '<p class="hint" style="margin:-2px 0 8px;">Two coupled '
                            'effects for the CFD/FEA hand-off: the <b>plate+manifold '
                            'pressure</b> ODE (does the developing vacuum change the '
                            'return, how deep does it go) and a <b>flutter</b> '
                            'stability screen. Both are <b>screens</b>, not '
                            'validation — flutter needs a real aero-damping '
                            'coefficient from CFD or a flow rig, and says so if you '
                            'don\'t have one. A green screen earns the ANSYS run; it '
                            'doesn\'t replace it.</p>', unsafe_allow_html=True)

                        _md1, _md2 = st.tabs(["Manifold coupling", "Flutter screen"])

                        with _md1:
                            _mc = st.columns(4)
                            _plenum = _mc[0].number_input(
                                "plenum volume (cc)", 100.0, 8000.0, 2000.0,
                                step=100.0, key="td_plenum") / 1e6
                            _bore = _mc[1].number_input(
                                "throttle bore area (cm²)", 1.0, 60.0, 15.0,
                                step=1.0, key="td_bore") / 1e4
                            _draw = _mc[2].number_input(
                                "engine airflow draw (kg/s)", 0.0, 0.3, 0.05,
                                step=0.01, key="td_draw",
                                help="Mean mass flow the engine pulls from the plenum "
                                     "at the operating point. 0 = engine off.")
                            _mtc = _mc[3].number_input(
                                "manifold torque coeff", 0.0, 1e-3, 0.0,
                                format="%.6f", step=1e-5, key="td_mtc",
                                help="Plate-side pressure torque per Pa of vacuum "
                                     "(from geometry/flow bench). 0 = pressure is "
                                     "tracked but not fed back as plate torque.")
                            _mp = _td.ManifoldParams(
                                plenum_volume_m3=_plenum, bore_area_m2=_bore,
                                engine_draw_kgps=_draw)
                            _cr = _td.simulate_coupled_return(
                                _springs, _inertia, _mp, _res,
                                theta_open_deg=_theta_open,
                                manifold_torque_coeff=_mtc)
                            _cc1, _cc2, _cc3 = st.columns(3)
                            _cc1.metric("return (coupled)",
                                        f"{_cr.return_time_s*1000:.0f} ms"
                                        if _cr.returns else "HANGS")
                            _cc2.metric("manifold vacuum (max)",
                                        f"{101.325 - _cr.min_manifold_kpa:.1f} kPa")
                            _cc3.metric("plate peak speed",
                                        f"{_cr.peak_speed_rad_s:.0f} rad/s")
                            for _f in _cr.findings:
                                _msev = {"ok": st.success, "warning": st.warning,
                                         "fail": st.error}.get(_f.severity.value,
                                                               st.info)
                                _msev(_f.message)
                            # plot the coupled trace if available
                            try:
                                import pandas as _pdc
                                if _cr.trace:
                                    _tr_df = _pdc.DataFrame(
                                        _cr.trace,
                                        columns=["t", "angle_deg", "omega",
                                                 "manifold_kPa"]).set_index("t")
                                    st.line_chart(_tr_df[["angle_deg",
                                                          "manifold_kPa"]])
                            except Exception:
                                pass

                        with _md2:
                            _fc = st.columns(4)
                            _ktheta = _fc[0].number_input(
                                "torsional stiffness (N·m/rad)", 0.1, 50.0, 2.0,
                                step=0.5, key="td_ktheta",
                                help="Return-spring rate about the axis + shaft.")
                            _cstruct = _fc[1].number_input(
                                "structural damping (N·m·s)", 0.0, 0.1, 0.001,
                                format="%.4f", step=0.001, key="td_cstruct")
                            _caero = _fc[2].number_input(
                                "aero damping coeff (N·m·s)", -0.05, 0.05, 0.0,
                                format="%.4f", step=0.001, key="td_caero",
                                help="From CFD or a flow rig. NEGATIVE = aero feeds "
                                     "energy in (flutter risk). 0 = aeroelastic part "
                                     "NOT modelled (the screen will say so).")
                            _crefv = _fc[3].number_input(
                                "aero ref speed (m/s)", 0.0, 120.0, 30.0, step=5.0,
                                key="td_crefv",
                                help="Speed the aero coeff was measured at.")
                            _fintake = st.number_input(
                                "intake speed to screen at (m/s)", 0.0, 120.0, 40.0,
                                step=5.0, key="td_fintake")

                            # Co-sim: source the aero-damping coefficient from CFD
                            # instead of typing it. Closes the loop honestly — the
                            # CFD run becomes the SOURCE of the number, with provenance.
                            try:
                                from suspension import throttle_flutter_cosim as _fco
                            except Exception:
                                _fco = None
                            if _fco is not None:
                                with st.expander("Get the aero-damping coefficient "
                                                 "from CFD co-sim (instead of typing "
                                                 "it)", expanded=False):
                                    st.markdown(
                                        '<p class="hint" style="margin:-2px 0 8px;">'
                                        'The flutter coefficient really comes from a '
                                        'forced-oscillation CFD study. This runs the '
                                        'co-sim seam: a <b>quasi-steady reference</b> '
                                        'model (trends/sign only — for wiring up the '
                                        'loop), or write a <b>real URANS/DES case</b> '
                                        'your team runs on their cluster and reads '
                                        'back. Either way the number carries its '
                                        'provenance.</p>', unsafe_allow_html=True)
                                    _bk = st.radio(
                                        "Backend", ["Quasi-steady reference (trends "
                                                    "only)", "External URANS/DES "
                                                    "(write case for cluster)"],
                                        key="fco_backend",
                                        label_visibility="collapsed")
                                    _oc = _fco.OscillationCase(
                                        mean_angle_deg=_theta_open / 2.0,
                                        intake_speed_ms=_fintake or 40.0,
                                        plate_radius_m=_plate_r,
                                        plate_area_m2=max(_plate_A, 1e-4)
                                        if 'snap_plate_A' in st.session_state
                                        else 1e-3)
                                    if _bk.startswith("Quasi"):
                                        _destab = st.checkbox(
                                            "known destabilising layout (negative "
                                            "damping)", value=False,
                                            key="fco_destab")
                                        if st.button("Run co-sim → coefficient",
                                                     key="fco_run"):
                                            _d = _fco.extract_flutter_derivative(
                                                _oc,
                                                backend=_fco.QuasiSteadyFlutterModel(
                                                    reduces_stability=_destab))
                                            if _d.c_aero_Nms is not None:
                                                # Store under NON-widget keys — writing
                                                # td_caero directly is illegal once its
                                                # number_input widget exists this run.
                                                st.session_state["td_caero_cosim"] = \
                                                    float(_d.c_aero_Nms)
                                                st.session_state["td_crefv_cosim"] = \
                                                    float(_d.ref_speed_ms)
                                                st.info(f"c_aero = {_d.c_aero_Nms:.3e} "
                                                        f"N·m·s — {_d.provenance.status()}")
                                                for _df in _d.findings:
                                                    st.caption(_df.message)
                                        # Show/clear any co-sim value in effect
                                        if "td_caero_cosim" in st.session_state:
                                            st.caption(
                                                "Using the co-sim coefficient "
                                                f"{st.session_state['td_caero_cosim']:.3e} "
                                                "N·m·s below (overrides the typed box). "
                                                "Clear it to type your own.")
                                            if st.button("Clear co-sim value",
                                                         key="fco_clear"):
                                                st.session_state.pop("td_caero_cosim",
                                                                     None)
                                                st.session_state.pop("td_crefv_cosim",
                                                                     None)
                                    else:
                                        st.caption(
                                            "Generates a forced-oscillation case in "
                                            "formats ANSYS uses — download, run it in "
                                            "Fluent/CFX (or a SolidWorks Flow "
                                            "transient study), and read the result "
                                            "back. KinematiK won't fake the solve.")
                                        _arts = _fco.ExternalCFDFlutterBackend(
                                        ).case_artifacts(_oc)
                                        # Offer each format as a direct download —
                                        # no server /tmp, no API round-trip needed.
                                        _labels = {
                                            ".jou": "⬇ Fluent journal (.jou)",
                                            ".csv": "⬇ Parameters (.csv)",
                                            ".txt": "⬇ Setup sheet (.txt)",
                                            ".json": "⬇ Case JSON (.json)",
                                        }
                                        _dl = st.columns(2)
                                        for _i, (_fn, _content) in enumerate(
                                                _arts.items()):
                                            _ext_key = "." + _fn.rsplit(".", 1)[-1]
                                            _mime = ("application/json"
                                                     if _ext_key == ".json"
                                                     else "text/csv"
                                                     if _ext_key == ".csv"
                                                     else "text/plain")
                                            _dl[_i % 2].download_button(
                                                _labels.get(_ext_key, f"⬇ {_fn}"),
                                                data=_content, file_name=_fn,
                                                mime=_mime,
                                                key=f"fco_dl_{_i}",
                                                use_container_width=True)
                                        st.caption(
                                            "Start with the **setup sheet** if you're "
                                            "meshing it, or the **Fluent journal** to "
                                            "script it. When the run is done, drop the "
                                            "`c_aero_Nms` into the result JSON and read "
                                            "it back to feed the flutter screen.")

                            # A co-sim result (stored under a non-widget key) wins
                            # over the typed box; otherwise use what was typed.
                            _caero_eff = st.session_state.get("td_caero_cosim", _caero)
                            _crefv_eff = st.session_state.get("td_crefv_cosim", _crefv)
                            _fp = _td.FlutterParams(
                                k_theta_Nm_per_rad=_ktheta, c_struct_Nms=_cstruct,
                                c_aero_Nms=_caero_eff,
                                c_aero_ref_speed_ms=_crefv_eff)
                            _fr = _td.screen_plate_flutter(
                                _inertia, _fp, intake_speed_ms=_fintake)
                            _fcc1, _fcc2 = st.columns(2)
                            _fcc1.metric("natural freq",
                                         f"{_fr.natural_freq_hz:.0f} Hz")
                            _fcc2.metric("damping ratio",
                                         f"{_fr.damping_ratio:.3f}")
                            for _f in _fr.findings:
                                _msev = {"ok": st.success, "warning": st.warning,
                                         "fail": st.error}.get(_f.severity.value,
                                                               st.info)
                                _msev(_f.message)

                try:
                    _mb_disclaimer_banner()
                except Exception:
                    pass
                _mbc = st.columns([3, 2])
                _claim = _mbc[0].text_input(
                    "Sanity-check a throttle assumption",
                    value="The two return springs are identical, so if one fails "
                          "the other is fine.",
                    key="throttle_myth_input",
                    help="Runs against the live result above via KinematiK's "
                         "cross-discipline myth-buster — the same engine on the "
                         "Myth-buster tab. Deterministic, no AI.")
                if _mbc[1].button("Bust it →", key="throttle_myth_btn",
                                  help="Check this claim against the numbers above."):
                    try:
                        from suspension import mythbuster as _mb
                        _mres = _mb.check(_claim,
                                          context={"brakes": {"return_result": _rr}})
                        # Unwrap the verdict (str-enum or str) inline — the shared
                        # helper is defined later in the file and isn't bound yet here.
                        _mvraw = getattr(_mres, "verdict", "unknown")
                        _mv = getattr(_mvraw, "value", _mvraw)
                        # Plain-language headline: answer the yes/no question first,
                        # in words a brakes lead reads at a glance — not "MYTH".
                        _mfn = {"myth": st.error, "true": st.success,
                                "depends": st.warning}.get(_mv, st.info)
                        _head = {
                            "myth": "❌ Not true for your throttle",
                            "true": "✅ True — your throttle checks out",
                            "depends": "⚠️ Only just — worth a closer look",
                            "unknown": "Couldn't match that to a known check",
                        }.get(_mv, _mv)
                        _mfn(f"**{_head}**\n\n{_mres.explanation}")
                        # "How it got this" in PLAIN terms: show the worst single-
                        # failure case as a force comparison a brakes lead understands
                        # — the surviving spring's closing effort vs the drag it must
                        # beat — instead of echoing an internal function name.
                        _worst_label = getattr(_rr, "worst_case", None)
                        _worst = None
                        for _c in getattr(_rr, "cases", []):
                            if _c.label == _worst_label:
                                _worst = _c
                                break
                        if _worst is not None:
                            _spring_name = _worst_label
                            if isinstance(_worst_label, str) and \
                                    _worst_label.startswith("without '"):
                                _spring_name = _worst_label[len("without '"):-1]
                            # net_closed/net_open already = spring closing torque
                            # minus drag at each end of travel; show the WORSE end so
                            # the number matches the verdict (a spring can clear drag
                            # at the closed stop but not wide open, or vice versa).
                            _drag = _res.total_Nm
                            _worst_net = min(_worst.net_closed_Nm, _worst.net_open_Nm)
                            _survivor = _worst_net + _drag
                            with st.expander("See the check"):
                                st.markdown(
                                    f"The toughest case is **if the {_spring_name} "
                                    f"spring fails**. At the hardest point in the "
                                    f"throttle's travel, the spring left has to shut "
                                    f"it against the friction and cable drag:")
                                _b1, _b2, _b3 = st.columns(3)
                                _b1.metric("surviving spring pushes",
                                           f"{_survivor:.2f} N·m")
                                _b2.metric("has to beat (drag)",
                                           f"{_drag:.2f} N·m")
                                _closes = _worst_net > 0
                                _b3.metric("spare force",
                                           f"{_worst_net:+.2f} N·m",
                                           "closes" if _closes else "won't close",
                                           delta_color="normal" if _closes
                                           else "inverse")
                                if units_mod.is_us():
                                    _cv = lambda v: units_mod.from_metric(v, "N·m")
                                    _b1.caption(f"≈ {_cv(_survivor):.2f} lbf·ft")
                                    _b2.caption(f"≈ {_cv(_drag):.2f} lbf·ft")
                                    _b3.caption(f"≈ {_cv(_worst_net):+.2f} lbf·ft")
                                st.caption("Computed live from the springs you entered "
                                           "above — no AI, just the numbers.")
                    except Exception as _me:
                        st.warning(f"Couldn't run the myth-buster: {_me}")

            # ============================================================ #
            else:   # Brake pedal 2000 N
                st.markdown(
                    '<p class="hint">FSAE Brake System: the <b>brake pedal shall '
                    'withstand 2000 N</b> applied at the pad without failure. This '
                    'screens the pedal as a levered member on the same '
                    '<b>FoS ≥ 1.5-on-yield</b> rule every other bracket uses, so you '
                    'get a PASS/TIGHT/FAIL in five seconds — before you mesh it. '
                    'It fails the obviously-undersized pedal instantly; a PASS earns '
                    'the SolidWorks/Ansys run, it does not replace it.</p>',
                    unsafe_allow_html=True)

                # Live continuity with Hydraulic sizing: if the team set a pedal
                # ratio there, the master-cylinder clevis sits at (arm / ratio) from
                # the pivot — show it so the two views describe one pedal, not two.
                _pratio = float(st.session_state.get("brake_pedal_ratio", 0.0))
                _dforce = float(st.session_state.get("brake_driver_pedal_force", 0.0))
                if _pratio > 0:
                    st.caption(
                        f"From Hydraulic sizing: pedal ratio {_pratio:.2f}"
                        + (f", driver force {units_mod.from_metric(_dforce,'N'):.0f} "
                           f"{units_mod.label('N')}" if _dforce > 0 else "")
                        + ". The MC pushrod clevis reacts at ≈ (lever arm ÷ ratio) "
                          "from the pivot; the 2000 N rule load is the structural case "
                          "regardless of driver force.")

                _pc = st.columns(4)
                _pmat = _pc[0].selectbox(
                    "Pedal material", list(bracket_mod.MATERIALS.keys()),
                    index=list(bracket_mod.MATERIALS.keys()).index(
                        "Aluminium 7075-T6")
                    if "Aluminium 7075-T6" in bracket_mod.MATERIALS else 0,
                    key="pedal_mat",
                    help="7075-T6 is the usual aluminium pedal stock.")
                _pw = unum(_pc[1], "Pedal width (mm)", 5.0, 120.0, 35.0, "mm",
                           step=1.0, key="pedal_w",
                           help="Section width resisting the bend.")
                _pt = unum(_pc[2], "Pedal thickness (mm)", 2.0, 40.0, 8.0, "mm",
                           step=0.5, key="pedal_t")
                _pl = unum(_pc[3], "Lever arm, pad→pivot (mm)", 10.0, 250.0, 90.0,
                           "mm", step=5.0, key="pedal_lever",
                           help="Distance from where the foot loads the pad to the "
                                "pedal pivot.")
                # Applied load. In imperial the lbf value converts back to newtons
                # and nudging it drifts off the exact rule figure — so offer a tickbox
                # to pin it to exactly 2000 N (the rule is defined in newtons).
                _pin_2000 = False
                if units_mod.is_us():
                    _lc = st.columns([3, 2])
                    with _lc[1]:
                        st.markdown("<div style='height:1.7rem'></div>",
                                    unsafe_allow_html=True)
                        _pin_2000 = st.checkbox(
                            "Rather apply exactly 2000 N (FSAE rule)?",
                            value=True, key="pedal_load_pin2000",
                            help="The FSAE rule load is defined as 2000 N. Tick this "
                                 "to screen at exactly 2000 N; untick to enter your "
                                 "own load in lbf.")
                    _load_container = _lc[0]
                else:
                    _load_container = st
                if _pin_2000:
                    _pload = float(_tr.BRAKE_PEDAL_RULE_LOAD_N)
                    _load_container.metric(
                        "Applied load", "2000 N",
                        f"≈ {units_mod.from_metric(_pload, 'N'):.0f} lbf — FSAE rule")
                else:
                    _pload = unum(_load_container, "Applied load (N)", 500.0, 5000.0,
                                  float(_tr.BRAKE_PEDAL_RULE_LOAD_N), "N", step=100.0,
                                  key="pedal_load",
                                  help="The rule load is 2000 N (≈450 lbf). Raise it "
                                       "only if your team screens at a self-imposed "
                                       "higher case load.")

                # Optional pivot-lug + weld geometry. Without these, only bending is
                # screened and a clean-looking pass is demoted to TIGHT — an
                # incomplete screen must not read as a validated pedal.
                with st.expander("Pivot lug & weld geometry — screen bearing, "
                                 "tear-out and weld (recommended before you trust a "
                                 "pass)", expanded=False):
                    st.markdown(
                        '<p class="hint" style="margin:-2px 0 8px;">A real pedal also '
                        'fails at the <b>pivot lug</b> (bolt bearing, tear-out to the '
                        'edge) and, if fabricated, at the <b>welds</b>. Leave these '
                        'blank and the screen checks bending only — and will flag that '
                        'it did, so a partial pass never poses as a clean one.</p>',
                        unsafe_allow_html=True)
                    _gc = st.columns(4)
                    _pbd = unum(_gc[0], "pivot bolt Ø (mm)", 0.0, 16.0, 0.0, "mm",
                                step=1.0, key="pedal_bolt", help="0 = not screened.")
                    _ped = unum(_gc[1], "edge distance (mm)", 0.0, 40.0, 0.0, "mm",
                                step=1.0, key="pedal_edge",
                                help="Hole centre → free edge. 0 = tear-out not "
                                     "screened.")
                    _pwl = unum(_gc[2], "weld leg (mm)", 0.0, 12.0, 0.0, "mm",
                                step=0.5, key="pedal_weld_leg",
                                help="0 = weld not screened.")
                    _pwL = unum(_gc[3], "weld length (mm)", 0.0, 200.0, 0.0, "mm",
                                step=5.0, key="pedal_weld_len")

                # Boundary-breaker (validation side): cross-check the TYPED dimensions
                # against the real CAD model's envelope + units, so a mistyped lever
                # arm (inches vs mm, extra digit) is caught against the source of
                # truth rather than silently screened.
                with st.expander("Cross-check these dimensions against your CAD "
                                 "(IGES) — catch a mistyped number", expanded=False):
                    st.markdown(
                        '<p class="hint" style="margin:-2px 0 8px;">Upload the pedal '
                        'IGES. KinematiK can\'t read the section thickness out of the '
                        'header (that solid geometry isn\'t there) — but it checks your '
                        'typed dimensions against the model\'s overall size and units, '
                        'which catches the transcription error that actually bites: '
                        'inches vs mm, or an extra zero.</p>', unsafe_allow_html=True)
                    _cadf = st.file_uploader(
                        "Pedal CAD (IGES / IGS, or a zip)",
                        type=["igs", "iges", "zip"], key="pedal_cad")
                    if _cadf is not None and _ing is not None:
                        try:
                            from suspension import cad_ingest as _ci
                            _manifest = _ci.ingest_bundle(_cadf.name, _cadf.getvalue())
                            _cc = _ing.crosscheck_pedal_against_cad(
                                _pw, _pt, _pl, _manifest)
                            for _cf in _cc.findings:
                                _sev = {"ok": st.success, "warning": st.warning,
                                        "fail": st.error,
                                        "missing": st.info}.get(_cf.severity.value,
                                                                st.info)
                                _sev(_cf.message)
                        except Exception as _ce:
                            st.warning(f"Couldn't cross-check against CAD: {_ce}")

                _pres = _tr.check_brake_pedal_2000N(
                    width_mm=_pw, thickness_mm=_pt, lever_arm_mm=_pl,
                    material=_pmat, load_N=_pload,
                    pivot_bolt_dia_mm=_pbd or None, edge_dist_mm=_ped or None,
                    weld_leg_mm=_pwl or None, weld_length_mm=_pwL or None)

                _pcol = {"PASS": st.success, "TIGHT": st.warning,
                         "FAIL": st.error, "INVALID": st.error}[_pres.verdict]
                _pcol(f"{_pres.verdict} — governing mode {_pres.governing_mode}, "
                      f"min FoS {_pres.min_fos:.2f} vs required "
                      f"{_pres.fos_target:.2f} at {_pload:.0f} N")
                for _f in _pres.findings:
                    _msev = {"ok": st.success, "warning": st.warning,
                             "fail": st.error}.get(_f.severity.value, st.info)
                    _msev(_f.message)
                for _n in _pres.notes:
                    st.caption("note: " + _n)
                if _pres.screening_only:
                    st.caption("Screening only — closed-form hand calc, no stress "
                               "concentration or 3-D pedal stiffness. A full-coverage "
                               "PASS here earns the Ansys run; it doesn't replace it.")

                # Frictionless handoff to the bolt view: the pedal-box mounting bolts
                # react the same 2000 N through the box feet. Seed that load with one
                # click instead of re-typing it, the same way the caliper-mount seed
                # works from the Bias view.
                st.markdown("")
                _mnt = st.columns([3, 2])
                _n_feet = _mnt[1].number_input(
                    "Pedal-box mount bolts", 2, 8, 4, step=1, key="pedal_box_nfeet",
                    help="Bolts sharing the 2000 N pedal-box reaction.")
                _F_perfoot = _pload / max(int(_n_feet), 1)
                if _mnt[0].button(
                        f"↻ Seed the Bolt view: {_pload:.0f} N ÷ {int(_n_feet)} "
                        f"= {_F_perfoot:.0f} N/bolt",
                        key="pedal_box_seed",
                        help="Push the pedal-box mount load into Bolt & bracket FoS so "
                             "you can spec the mounting-bolt torque without re-typing."):
                    st.session_state["brake_bolt_extN_val"] = float(round(_F_perfoot, 0))
                    st.session_state.pop("brake_bolt_extN", None)
                    st.session_state.pop("_u_brake_bolt_extN", None)
                    st.success("Seeded. Open Bolt & bracket FoS ▸ Bolt preload & torque "
                               "to spec the pedal-box mount bolts against this load.")

    # =================================================================== #
    elif _bview == "Rotor thermal":
        try:
            import suspension.brake_thermal as _bt
        except Exception:
            _bt = None
        if _bt is None:
            st.info("The rotor-thermal model isn't available in this deployment "
                    "yet — the `suspension/brake_thermal.py` module hasn't been "
                    "deployed. The rest of the Brakes workspace works; once that "
                    "file is pushed, this view will compute single-stop and "
                    "endurance rotor temperatures.")
        else:
            _render_rotor_thermal(_bt, float(_mass), kin)

    # =================================================================== #
    elif _bview == "Documentation":
        st.markdown(
            '<p class="hint">The full <b>brakes documentation &amp; verdict</b> — report '
            'builder, PDF export and Handover logging — now lives in the '
            '<b>📄 Documentation</b> tab (pick <i>Brakes</i> there). This keeps every '
            'subsystem\'s docs in one place. Everything you\'ve worked out here — bias, '
            'hydraulics, pedal box, throttle return — is carried over automatically, '
            'so you only tweak wording before downloading.</p>',
            unsafe_allow_html=True)

        # brakes-specific result sections that don't live in the ledger
        _bx = []
        _bias = st.session_state.get("brake_front_bias_pct")
        _rotor = st.session_state.get("brake_rotor_dia_mm")
        if _bias is not None or _rotor is not None:
            _l = []
            if _bias is not None:
                _l.append(f"- Front brake bias: **{_bias:.0f}%**")
            if _rotor is not None:
                _l.append(f"- Rotor diameter: **{_rotor:.0f} mm**")
            _bx.append(("Bias & lock-up", _l))
        _pratio = st.session_state.get("brake_pedal_ratio")
        _dforce = st.session_state.get("brake_driver_pedal_force")
        if _pratio is not None or _dforce is not None:
            _l = []
            if _pratio is not None:
                _l.append(f"- Pedal ratio: **{_pratio:.2f}**")
            if _dforce is not None:
                _l.append(f"- Driver pedal force: **{_dforce:.0f} N**")
            _bx.append(("Hydraulics & pedal", _l))
        if st.session_state.get("pedal_w") is not None:
            try:
                from suspension import throttle_return as _trd
                _pres_doc = _trd.check_brake_pedal_2000N(
                    width_mm=st.session_state.get("pedal_w", 35.0),
                    thickness_mm=st.session_state.get("pedal_t", 8.0),
                    lever_arm_mm=st.session_state.get("pedal_lever", 90.0),
                    material=st.session_state.get("pedal_mat", "Aluminium 7075-T6"),
                    load_N=2000.0
                    if st.session_state.get("pedal_load_pin2000", False)
                    else st.session_state.get("pedal_load", 2000.0))
                _l = [f"- Verdict: **{_pres_doc.verdict}** (min FoS "
                      f"{_pres_doc.min_fos:.2f} vs {_pres_doc.fos_target:.2f}, "
                      f"governing {_pres_doc.governing_mode})",
                      f"- Material {st.session_state.get('pedal_mat','?')}, "
                      f"{st.session_state.get('pedal_w',0):.0f}×"
                      f"{st.session_state.get('pedal_t',0):.0f} mm, lever "
                      f"{st.session_state.get('pedal_lever',0):.0f} mm"]
                if _pres_doc.screening_only:
                    _l.append("- _Screening only — a PASS earns the SolidWorks/Ansys "
                              "run, it does not replace it._")
                _bx.append(("Brake pedal — 2000 N rule", _l))
            except Exception as _pd_e:
                # A safety-rule verdict that silently vanishes from the handover
                # reads as "not applicable" — say it failed to compute instead.
                _bx.append(("Brake pedal — 2000 N rule",
                            [f"- ⚠ Verdict could not be computed for this "
                             f"document ({type(_pd_e).__name__}). Re-run the "
                             f"pedal check in the Brakes tab before relying on "
                             f"this handover."]))
        _rr_doc = st.session_state.get("throttle_return_result")
        if _rr_doc is not None:
            _l = [f"- Verdict: **{getattr(_rr_doc,'verdict','?')}** (worst "
                  f"single-failure case {getattr(_rr_doc,'worst_case','?')}, margin "
                  f"{getattr(_rr_doc,'worst_margin',float('nan')):.2f})"]
            for _c in getattr(_rr_doc, "cases", []):
                _l.append(f"  - {_c.label}: net closed {_c.net_closed_Nm:.2f} N·m, "
                          f"net open {_c.net_open_Nm:.2f} N·m — "
                          f"{'closes' if _c.closes else 'HANGS OPEN'}")
            _bx.append(("Throttle return springs — single-fault redundancy", _l))

        # Documentation now lives in the central DOCUMENTATION tab. Publish the
        # brakes-specific report sections there so they're not lost.
        publish_doc_sections("brakes", _bx)


  except Exception as _eb:
    st.error(f"Could not build the brakes workspace: {_eb}")

# =========================================================================== #
#  COST & BOM  —  the scored FSAE Cost & Manufacturing event, auto-seeded.     #
# =========================================================================== #
# FSAE scores a Cost event: an electronic Bill of Materials of every part on the
# car, organised into commodity sections, with standardized catalog costs for
# material ($/kg), processes ($/hole, $/cut, $/bend, $/hr labour) and fasteners —
# the point being to make teams feel their material and manufacturing choices as
# DOLLARS. The friction in real life is building the BOM from a blank sheet. This
# tab REMOVES that: it auto-seeds a starter BOM from the masses each subsystem has
# already declared in INTEGRATION, pre-fills standardized catalog costs, and lets
# the team edit inline — then rolls it up per commodity and against a target.
with tab_cost:
  try:
    # Standardized catalog rates (FSAE-cost-scale, editable in the UI). Material
    # $/kg by class; process rates per the cost tables; assembly labour $/hr.
    _MAT_RATES = {
        "Aluminium (6061/7075)": 12.0, "Steel (mild/4130)": 6.0,
        "Carbon fibre / composite": 90.0, "Titanium": 60.0,
        "Plastic / polymer": 15.0, "Electronics / PCB": 120.0,
        "Battery cells": 110.0, "Rubber / tyre": 18.0, "Other": 20.0,
    }
    # default material + make/buy guess per commodity, so the seed is sensible
    _COMMODITY_SEED = {
        "suspension": ("Steel (mild/4130)", "Make"),
        "aerodynamics": ("Carbon fibre / composite", "Make"),
        "powertrain": ("Electronics / PCB", "Buy"),
        "cooling": ("Aluminium (6061/7075)", "Make"),
        "electrics": ("Battery cells", "Buy"),
        "brakes": ("Steel (mild/4130)", "Buy"),
        "chassis": ("Steel (mild/4130)", "Make"),
        "data-acquisition": ("Electronics / PCB", "Buy"),
    }
    _PROC_RATES = dict(hole=0.35, cut=0.20, bend=0.05, labour_hr=35.0, machine_hr=70.0)

    st.markdown(
        '<p class="hint" style="margin:0 0 6px;">The FSAE <b>Cost event</b>, without the '
        'blank-sheet pain. KinematiK seeds a starter Bill of Materials from the masses '
        'every subsystem already declared in <b>INTEGRATION</b>, pre-fills standardized '
        'catalog costs, and lets you edit every row inline. It rolls up per commodity and '
        'against your target, so material and manufacturing choices show up as dollars.</p>',
        unsafe_allow_html=True)

    # ---- seed / load the BOM ------------------------------------------- #
    import pandas as _pd_c
    _led_c = interfaces_mod.IntegrationLedger.from_dict(st.session_state.ledger)

    def _seed_bom():
        rows = []
        for s in interfaces_mod.SUBSYSTEMS:
            it = _led_c.get(s)
            mass = float(getattr(it, "mass_kg", 0.0) or 0.0) if it else 0.0
            mat, mk = _COMMODITY_SEED.get(s, ("Other", "Make"))
            rate = _MAT_RATES.get(mat, 20.0)
            rows.append(dict(
                Commodity=s.replace("-", " ").title(),
                Part=f"{s.replace('-', ' ').title()} assembly",
                Qty=1,
                Material=mat,
                **{"Mass (kg)": round(mass, 2)},
                **{"Material $/kg": rate},
                **{"Process $": 0.0},
                **{"Fastener $": 0.0},
                Make_Buy=mk))
        return rows

    if "cost_bom" not in st.session_state:
        st.session_state.cost_bom = _seed_bom()

    tc = st.columns([1, 1, 2])
    if tc[0].button("↻ Re-seed from declared masses", key="cost_reseed",
                    help="Rebuild the starter BOM from the latest INTEGRATION masses. "
                         "Your manual edits are replaced."):
        st.session_state.cost_bom = _seed_bom()
        st.rerun()
    if tc[1].button("+ Add blank part", key="cost_addrow"):
        st.session_state.cost_bom.append(dict(
            Commodity="Suspension", Part="New part", Qty=1, Material="Other",
            **{"Mass (kg)": 0.0}, **{"Material $/kg": 20.0}, **{"Process $": 0.0},
            **{"Fastener $": 0.0}, Make_Buy="Make"))
        st.rerun()
    _target = tc[2].number_input("Cost target ($)", 1000.0, 50000.0,
                                 value=float(st.session_state.get("cost_target", 12000.0)),
                                 step=250.0, key="cost_target",
                                 help="Your team's cost ceiling. The roll-up flags if you're over.")

    st.markdown('<p class="hint" style="margin:8px 0 2px;">Edit any cell. '
                '<b>Part cost = Qty × (Mass × Material $/kg + Process $ + Fastener $)</b>. '
                'Add holes/cuts/bends as Process $ using the catalog rates below.</p>',
                unsafe_allow_html=True)

    _df = _pd_c.DataFrame(st.session_state.cost_bom)
    _edited = st.data_editor(
        _df, width='stretch', num_rows="dynamic", key="cost_editor",
        column_config={
            "Commodity": st.column_config.SelectboxColumn(
                "Commodity", options=[s.replace("-", " ").title()
                                      for s in interfaces_mod.SUBSYSTEMS], required=True),
            "Material": st.column_config.SelectboxColumn(
                "Material", options=list(_MAT_RATES.keys()), required=True),
            "Make_Buy": st.column_config.SelectboxColumn(
                "Make/Buy", options=["Make", "Buy"], required=True),
            "Qty": st.column_config.NumberColumn("Qty", min_value=1, step=1),
            "Mass (kg)": st.column_config.NumberColumn("Mass (kg)", min_value=0.0, step=0.1, format="%.2f"),
            "Material $/kg": st.column_config.NumberColumn("Material $/kg", min_value=0.0, step=1.0, format="$%.0f"),
            "Process $": st.column_config.NumberColumn("Process $", min_value=0.0, step=1.0, format="$%.2f"),
            "Fastener $": st.column_config.NumberColumn("Fastener $", min_value=0.0, step=0.5, format="$%.2f"),
        })
    # persist edits
    st.session_state.cost_bom = _edited.to_dict("records")

    # ---- roll-up -------------------------------------------------------- #
    _ed = _edited.copy()
    for c, d in [("Qty", 1), ("Mass (kg)", 0.0), ("Material $/kg", 0.0),
                 ("Process $", 0.0), ("Fastener $", 0.0)]:
        _ed[c] = _pd_c.to_numeric(_ed[c], errors="coerce").fillna(d)
    _ed["Part $"] = _ed["Qty"] * (_ed["Mass (kg)"] * _ed["Material $/kg"]
                                  + _ed["Process $"] + _ed["Fastener $"])
    _total = float(_ed["Part $"].sum())
    _by_comm = _ed.groupby("Commodity")["Part $"].sum().sort_values(ascending=False)

    rc = st.columns(3)
    rc[0].metric("Total car cost", f"${_total:,.0f}",
                 delta=f"${_total-_target:,.0f} vs target",
                 delta_color=("inverse" if _total > _target else "normal"))
    rc[1].metric("Parts in BOM", f"{len(_ed)}")
    rc[2].metric("Most expensive commodity",
                 _by_comm.index[0] if len(_by_comm) else "—",
                 f"${_by_comm.iloc[0]:,.0f}" if len(_by_comm) else None)

    gcol = st.columns([3, 2])
    # bar: cost by commodity
    fcost = go.Figure(go.Bar(
        x=_by_comm.values, y=_by_comm.index, orientation="h",
        marker_color="#37e0d0", text=[f"${v:,.0f}" for v in _by_comm.values],
        textposition="auto"))
    fcost.update_layout(
        title="Cost by commodity", xaxis_title="cost ($)", height=320,
        paper_bgcolor="rgba(0,0,0,0)", plot_bgcolor="rgba(0,0,0,0)",
        font=dict(color="#cdd6df", size=11), margin=dict(l=0, r=0, t=36, b=0))
    fcost.update_yaxes(autorange="reversed")
    gcol[0].plotly_chart(fcost, width='stretch', key="cost_by_comm")
    # make vs buy split
    _mb = _ed.groupby("Make_Buy")["Part $"].sum()
    fpie = go.Figure(go.Pie(
        labels=_mb.index.tolist(), values=_mb.values.tolist(), hole=0.5,
        marker=dict(colors=["#ffb02e", "#5ad17a"])))
    fpie.update_layout(
        title="Make vs Buy ($)", height=320,
        paper_bgcolor="rgba(0,0,0,0)", font=dict(color="#cdd6df", size=11),
        margin=dict(l=0, r=0, t=36, b=0), legend=dict(bgcolor="rgba(0,0,0,0)"))
    gcol[1].plotly_chart(fpie, width='stretch', key="cost_makebuy")

    if _total > _target:
        st.warning(f"Over target by ${_total-_target:,.0f}. The bar chart shows where the "
                   "money is — usually a composite or machined-aluminium choice. Try a "
                   "cheaper material class or a Buy part to see the cost drop live.")
    else:
        st.success(f"Under the ${_target:,.0f} target with ${_target-_total:,.0f} to spare.")

    # ---- catalog rates (editable reference) + export ------------------- #
    with st.expander("Standardized cost catalog (the rates the cells use)", expanded=False):
        st.markdown("**Material $/kg** — " + " · ".join(
            f"{k.split()[0]} ${v:.0f}" for k, v in _MAT_RATES.items()))
        st.markdown(f"**Process rates** — hole ${_PROC_RATES['hole']:.2f} · "
                    f"cut ${_PROC_RATES['cut']:.2f} · bend ${_PROC_RATES['bend']:.2f} · "
                    f"assembly labour ${_PROC_RATES['labour_hr']:.0f}/hr · "
                    f"machining ${_PROC_RATES['machine_hr']:.0f}/hr")
        st.caption("Add a part's holes/cuts/bends/labour into its Process $ cell, e.g. "
                   "8 holes × $0.35 + 18 min CNC × ($70/60) = $23.80. These mirror the "
                   "FSAE cost-table style; swap in your competition's exact catalog numbers.")

    _csv = _ed[["Commodity", "Part", "Qty", "Material", "Mass (kg)",
                "Material $/kg", "Process $", "Fastener $", "Make_Buy", "Part $"]].to_csv(index=False)
    if st.download_button("⬇ Export BOM as CSV", _csv, file_name="kinematik_cost_bom.csv",
                          mime="text/csv", key="cost_export",
                          help="The full Bill of Materials, ready to drop into your cost report."):
        try:
            _axn.export("cost", "bom_csv")
            _axn.complete("cost", "export_bom")
        except Exception:
            pass
    st.caption("Hierarchy follows the FSAE cost report: System (Commodity) → Part → "
               "Material / Process / Fastener. Mark each part Make or Buy; the roll-up "
               "and charts update live so the cost of every engineering choice is visible.")
  except Exception as _ecost:
    st.error(f"Could not build the cost workspace: {_ecost}")

# --------------------------------------------------------------------------- #
# ----- SUSPENSION vs CHASSIS (now a section of the merged INTEGRATION tab) ----- #
def _render_envelope_vs_chassis(subsys, led):
    """Static envelope-fit check of a non-suspension subsystem against the chassis."""
    it = led.get(subsys)
    have_env = it is not None and None not in (
        getattr(it, "env_x_mm", None), getattr(it, "env_y_mm", None),
        getattr(it, "env_z_mm", None))
    st.markdown(f'<p class="hint">Static fit check for <b>{subsys}</b>: does its '
                'envelope sit inside the chassis interior and clear the frame tubes? '
                'Unlike suspension, a statically-mounted subsystem doesn\'t move, so '
                'this checks the bounding box, not a travel sweep. The envelope comes '
                'from the subsystem\'s declaration in the cross-subsystem ledger — set '
                'it there if it\'s blank.</p>', unsafe_allow_html=True)

    if not have_env:
        st.markdown(f'<span class="tag warn">{subsys} has no envelope declared — add '
                    'env X/Y/Z (and optionally an origin) in the cross-subsystem '
                    'ledger first.</span>', unsafe_allow_html=True)
        return

    size = (float(it.env_x_mm), float(it.env_y_mm), float(it.env_z_mm))
    default_origin = getattr(it, "env_origin_mm", None)
    with st.expander("⚙️ Envelope placement (min corner, mm in the chassis frame)", expanded=False):
      pc = st.columns(3)
      ox = pc[0].number_input("origin x", value=float(default_origin[0]) if default_origin else 0.0,
                              step=10.0, key=f"env_ox_{subsys}")
      oy = pc[1].number_input("origin y", value=float(default_origin[1]) if default_origin else 0.0,
                              step=10.0, key=f"env_oy_{subsys}")
      oz = pc[2].number_input("origin z", value=float(default_origin[2]) if default_origin else 0.0,
                              step=10.0, key=f"env_oz_{subsys}")
      _es = [units_mod.from_metric(size[i], "mm") for i in range(3)]
      _eu = units_mod.label("mm")
      _ep = 2 if units_mod.is_us() else 0
      st.caption(f"Envelope size: {_es[0]:.{_ep}f} × {_es[1]:.{_ep}f} × {_es[2]:.{_ep}f} {_eu} "
                 "(from the ledger). Place its min corner above to match where it mounts.")

      up = st.file_uploader("Chassis CAD", type=["step", "stp", "stl", "obj", "glb"],
                            label_visibility="collapsed", key=f"env_cad_{subsys}")
      oc1, oc2, oc3, oc4 = st.columns(4)
      off_x = oc1.number_input("offset x", value=0.0, step=10.0, key=f"env_offx_{subsys}")
      off_y = oc2.number_input("offset y", value=0.0, step=10.0, key=f"env_offy_{subsys}")
      off_z = oc3.number_input("offset z", value=0.0, step=10.0, key=f"env_offz_{subsys}")
      cad_scale = oc4.number_input("scale (m→mm = 1000)", value=1.0, step=1.0, key=f"env_scale_{subsys}")

      if up is None:
          st.markdown('<p class="hint" style="padding-top:.5rem;">Waiting for a chassis '
                      'file (STEP most reliable). Same CAD as the suspension check — the '
                      'envelope is placed in the same frame.</p>', unsafe_allow_html=True)
          return

      import tempfile as _tf
      suffix = "." + up.name.split(".")[-1]
      with _tf.NamedTemporaryFile(suffix=suffix, delete=False) as f:
          f.write(up.getbuffer())
          cad_path = f.name
      try:
          with st.spinner(f"Loading chassis and fitting the {subsys} envelope…"):
              mesh = chassis_mod.load_chassis(cad_path, offset=(off_x, off_y, off_z),
                                              scale=cad_scale)
              summ = chassis_mod.mesh_summary(mesh)
              res = chassis_mod.envelope_fit_check(mesh, (ox, oy, oz), size,
                                                   name=subsys, warn_mm=8.0)

          vmap = {"CLEAR": ("good", "Envelope fits and clears the frame"),
                  "TIGHT": ("warn", "Within 8 mm of a tube — review before mounting"),
                  "COLLISION": ("bad", "Envelope intersects the frame — reposition or resize"),
                  "OUTSIDE": ("bad", "Envelope pokes outside the chassis interior")}
          vc = vmap.get(res["verdict"], ("warn", res["verdict"]))
          st.markdown(f'<div class="metric" style="margin:.4rem 0;">'
                      f'<span class="k">{subsys.upper()} FIT VERDICT</span>'
                      f'<span class="v {vc[0]}">{res["verdict"]}'
                      f'<span class="u"> · {vc[1]}</span></span></div>',
                      unsafe_allow_html=True)

          mc = st.columns(3)
          mc[0].markdown(metric("Min clearance to frame", f"{res['min_clearance_mm']:.1f}", "mm",
                                vc[0]), unsafe_allow_html=True)
          mc[1].markdown(metric("Contained in chassis", "yes" if res["contained"] else "no",
                                "", "good" if res["contained"] else "bad"), unsafe_allow_html=True)
          oob = ", ".join(res["oob_axes"]) if res["oob_axes"] else "—"
          mc[2].markdown(metric("Outside on axes", oob, "", "bad" if res["oob_axes"] else "good"),
                         unsafe_allow_html=True)

          # 3D overlay: chassis mesh + subsystem box surface
          st.markdown(f"###### {subsys} envelope overlaid on chassis")
          box_pts = chassis_mod.envelope_box_points((ox, oy, oz), size, step_mm=25.0)
          fig = go.Figure()
          vx, vy, vz = mesh.vertices[:, 0], mesh.vertices[:, 1], mesh.vertices[:, 2]
          i, j, k = mesh.faces[:, 0], mesh.faces[:, 1], mesh.faces[:, 2]
          fig.add_trace(go.Mesh3d(x=vx, y=vy, z=vz, i=i, j=j, k=k,
                        color="#5a6b7a", opacity=0.30, name="Chassis", flatshading=True))
          boxcolor = {"CLEAR": "#37e0d0", "TIGHT": AMBER, "COLLISION": RED, "OUTSIDE": RED}.get(
              res["verdict"], "#9b8cff")
          fig.add_trace(go.Scatter3d(x=box_pts[:, 0], y=box_pts[:, 1], z=box_pts[:, 2],
                        mode="markers", marker=dict(size=2.5, color=boxcolor),
                        name=f"{subsys} envelope"))
          fig.update_layout(
              paper_bgcolor="rgba(0,0,0,0)",
              scene=dict(
                  xaxis=dict(title="x", backgroundcolor="#0e1216", gridcolor="#1d242c", color="#8d99a6"),
                  yaxis=dict(title="y", backgroundcolor="#0e1216", gridcolor="#1d242c", color="#8d99a6"),
                  zaxis=dict(title="z", backgroundcolor="#0e1216", gridcolor="#1d242c", color="#8d99a6"),
                  aspectmode="data", camera=dict(eye=dict(x=1.6, y=-1.5, z=0.9))),
              font=dict(family="JetBrains Mono", color="#cdd6df", size=10),
              height=500, margin=dict(l=0, r=0, t=10, b=0),
              legend=dict(bgcolor="rgba(0,0,0,0)", font=dict(size=9)))
          st.plotly_chart(fig, width='stretch')

          _smm = [units_mod.from_metric(_v, "mm") for _v in summ["size_mm"]]
          st.markdown(f'<p class="hint">Chassis: {summ["triangles"]:,} triangles, '
                      f'{_smm[0]:.0f}×{_smm[1]:.0f}×{_smm[2]:.0f} {units_mod.label("mm")}. '
                      'If the envelope sits in the wrong place, adjust the origin or the '
                      'CAD offset so the frames align.</p>', unsafe_allow_html=True)

          if res["verdict"] in ("COLLISION", "TIGHT", "OUTSIDE"):
              sug = (f"{subsys}: envelope {res['verdict'].lower()} vs chassis "
                     f"(min clearance {uval(res['min_clearance_mm'], 'mm', fmt='{:.1f}')}"
                     + (f", outside on {', '.join(res['oob_axes'])}" if res["oob_axes"] else "")
                     + "). Flagged before mounting.")
              note = st.text_area("Decision note (edit before logging)", value=sug,
                                  height=80, key=f"env_note_{subsys}")
              if st.button("＋ Log this to handover", key=f"env_log_{subsys}"):
                  ok = log_decision_now(subsys, f"{subsys} {res['verdict'].lower()} vs chassis",
                                        note, author="INTEGRATION")
                  st.success("Logged to handover." if ok else
                             "Couldn't write to the handover log (backend offline) — verdict still stands.")
      except Exception as e:
          st.error(f"Could not process the chassis file: {e}")
      finally:
          try:
              os.unlink(cad_path)
          except Exception:
              pass


_MB_VCFG = {
    "myth":    dict(label="\u274c Myth",    bg="#1f1214", border="#5a2422",
                    accent="#ff5a52", badge_bg="#3d1a18"),
    "depends": dict(label="\u26a0\ufe0f Depends", bg="#171510", border="#5a4317",
                    accent="#ffb02e", badge_bg="#3a2c10"),
    "true":    dict(label="\u2705 True",    bg="#0f1c1a", border="#1f4d49",
                    accent="#37e0d0", badge_bg="#0e2a27"),
    "unknown": dict(label="\u2753 Unknown",  bg="#131318", border="#303050",
                    accent="#9b8cff", badge_bg="#1a1a2e"),
}

# Discipline labels for the picker. The engine's discipline ids map to the eight
# channels; we group tyres+balance under Suspension and structures under Chassis,
# matching how the rules register.
_MB_DISCIPLINES = [
    ("Any (auto-detect)", None),
    ("Powertrain",        "powertrain"),
    ("Suspension / tyres", "suspension"),
    ("Aerodynamics",      "aerodynamics"),
    ("Brakes",            "brakes"),
    ("Cooling",           "cooling"),
    ("Electrics",         "electrics"),
    ("Chassis / structures", "chassis"),
]


def _mb_verdict_value(result):
    """Return the verdict as a plain string whether it's a str-enum or str."""
    v = getattr(result, "verdict", "unknown")
    return getattr(v, "value", v)


def _mb_render_card(claim_text, result, *, compact=False):
    """Render one verdict card, reusing the powertrain myth-buster styling."""
    import re as _rem
    _v = _MB_VCFG.get(_mb_verdict_value(result), _MB_VCFG["unknown"])
    _disc = getattr(result, "discipline", "") or ""
    _prov = getattr(result, "provenance", "") or ""
    _hl = _rem.sub(
        r'(\b\d[\d\s,.]*(?:kW|rpm|km/h|N\u00b7m|V|A|\u00b0C|mm|kg|%|:\d)?)',
        lambda m: ('<span style="font-family:\'JetBrains Mono\',monospace;'
                   'font-weight:600;color:' + _v["accent"] + ';">'
                   + m.group() + '</span>'),
        getattr(result, "explanation", ""))
    _disc_chip = (
        f'<span style="font-family:\'JetBrains Mono\',monospace;font-size:.6rem;'
        f'font-weight:700;letter-spacing:.08em;text-transform:uppercase;'
        f'color:#8d99a6;margin-left:.4rem;">{_disc}</span>' if _disc else "")
    _prov_line = (
        f'<p style="margin:.4rem 0 0;font-size:.7rem;color:#7d8893;'
        f'font-family:\'JetBrains Mono\',monospace;">\u2514 {_prov}</p>'
        if _prov else "")
    _rad = "10px" if compact else "12px"
    st.markdown(
        f'<div style="background:{_v["bg"]};border:1px solid {_v["border"]};'
        f'border-left:3px solid {_v["accent"]};border-radius:{_rad};'
        f'padding:.85rem 1.1rem;margin:.4rem 0;">'
        f'<div style="display:flex;align-items:center;gap:.6rem;margin-bottom:.45rem;'
        f'flex-wrap:wrap;">'
        f'<span style="font-family:\'JetBrains Mono\',monospace;font-size:.68rem;'
        f'font-weight:700;letter-spacing:.1em;text-transform:uppercase;'
        f'background:{_v["badge_bg"]};color:{_v["accent"]};'
        f'border:1px solid {_v["border"]};border-radius:6px;'
        f'padding:.15rem .5rem;white-space:nowrap;flex:0 0 auto;">{_v["label"]}</span>'
        f'<span style="font-size:.85rem;font-style:italic;color:#8d99a6;">'
        f'\u201c{claim_text}\u201d</span>{_disc_chip}</div>'
        f'<p style="margin:0;font-size:.83rem;line-height:1.65;color:#c4cdd6;">{_hl}</p>'
        f'{_prov_line}'
        f'</div>',
        unsafe_allow_html=True)


def _mb_coerce_float(v):
    """Best-effort float from a ledger value that might be a number, a dict with
    a 'value' field, or a string like '42.0 mm'. Returns None if not numeric."""
    if v is None:
        return None
    if isinstance(v, (int, float)):
        return float(v)
    if isinstance(v, dict):
        return _mb_coerce_float(v.get("value", v.get("val")))
    import re as _re
    m = _re.search(r'-?\d[\d,]*\.?\d*', str(v))
    if m:
        try:
            return float(m.group(0).replace(",", ""))
        except ValueError:
            return None
    return None


def _mb_build_context():
    """Assemble the live context bundle the engine hands to whichever rule fires.

    Keyed by discipline so each rule gets the object it expects: the fitted tyre
    for suspension/tyre rules, the motor envelope for powertrain, vehicle params
    for balance. Everything is best-effort — a rule with no context degrades to a
    DEPENDS/UNKNOWN rather than crashing, by design.
    """
    ctx = {}
    # tyre (suspension rules)
    try:
        _tire = tire_mod.PacejkaLateral(
            coeffs=dict(st.session_state.get("tire_coeffs", {})),
            FNOMIN=float(st.session_state.get("tire_fnomin", 1100.0)))
        ctx["suspension"] = {"tire": _tire,
                             "veh": VehicleParams(**{
                                 k: v for k, v in st.session_state.get("vp", {}).items()
                                 if k in VehicleParams().__dict__})}
    except Exception:
        pass
    # powertrain envelope, if the powertrain tab has defined one this session
    try:
        from suspension.myth_rules.powertrain import PowertrainContext
        _env = st.session_state.get("pti_last_envelope")
        if _env is not None:
            ctx["powertrain"] = PowertrainContext(
                env=_env,
                gear_final_drive=float(st.session_state.get("_pti_final_drive", 3.5)))
    except Exception:
        pass
    # brakes: live throttle-return redundancy result, if the pedal-box view has
    # computed one this session. Lets the mythbuster refute "identical springs so
    # the backup is fine" against the ACTUAL per-spring numbers, not just theory.
    try:
        _rr = st.session_state.get("throttle_return_result")
        if _rr is not None:
            ctx["brakes"] = {"return_result": _rr}
    except Exception:
        pass
    return ctx


def render_mythbuster():
    """Cross-discipline myth-buster: any lead types an assumption, the math
    checks it against the live models and names the physics. The powertrain tab
    has had this for one discipline; this surfaces it for all eight, in the
    cross-discipline place (the Integration tab)."""
    from suspension import mythbuster as _mb

    # Activate the data-driven entity engine as a fallback under the hand-written
    # rules (idempotent). Its registry_lookup pulls VERIFIED declared values from
    # the Integration ledger so a formula that uses one scores higher confidence.
    try:
        from suspension import myth_bridge as _mb_bridge

        def _verified_lookup(key):
            """Resolve an entity's registry_key (e.g. 'aero.downforce_n') to a
            verified live number from the Integration ledger, or None."""
            led = st.session_state.get("integration_ledger") or {}
            # ledger is keyed by declared field; accept either dotted or leaf key
            if key in led:
                return _mb_coerce_float(led.get(key))
            leaf = key.split(".")[-1]
            for _k, _v in led.items():
                if str(_k).split(".")[-1] == leaf:
                    return _mb_coerce_float(_v)
            return None

        _mb_bridge.install_entity_engine(registry_lookup=_verified_lookup)
    except Exception:
        pass  # the hand-written rules still work without the entity engine

    st.markdown(
        '<p class="hint" style="margin:0 0 10px;">Type an assumption from <b>any</b> '
        'subsystem \u2014 tyres, aero, brakes, cooling, electrics, structures, '
        'powertrain \u2014 and the checker answers it. Registered claims are tested '
        'against the live models with exact numbers; anything else is assessed '
        'against a built-in physics / engineering / FSAE knowledge base. '
        '<b>No AI.</b> Same claim always gives the same answer, and every verdict '
        'shows the reasoning so it can\u2019t be argued away in a meeting. Share '
        'the verdict in the channel instead of re-running the argument.</p>',
        unsafe_allow_html=True)

    try:
        _mb_disclaimer_banner()
    except Exception:
        pass

    _labels = [l for l, _ in _MB_DISCIPLINES]
    _c1, _c2 = st.columns([2, 5])
    _pick = _c1.selectbox("Discipline", _labels, index=0,
                          key="mb_discipline", label_visibility="collapsed")
    _disc = dict(_MB_DISCIPLINES).get(_pick, None)

    _input = _c2.text_input(
        "Your assumption",
        placeholder='e.g. "twice the load gives twice the grip" \u00b7 '
                    '"more downforce always means a faster lap" \u00b7 '
                    '"a stronger chassis is a stiffer chassis"',
        label_visibility="collapsed", key="mb_input_xdisc")
    _go = st.button("Check it \u2192", key="mb_btn_xdisc")

    _ctx = _mb_build_context()
    # Tell the general-knowledge fallback which discipline the user picked (if
    # any) so it can prioritise topics from that channel before the generic
    # responders. Harmless to the registered rules, which ignore this key.
    if isinstance(_ctx, dict):
        _ctx["_discipline"] = _disc

    if _go and _input.strip():
        _ax = globals().get("_axn")
        try:
            if _ax is not None:
                _ax.engage("mythbuster", "check")
            import time as _t
            _t0 = _t.perf_counter()
            _res = _mb.check(_input, _ctx)
            if _ax is not None:
                _ax.render("mythbuster", int((_t.perf_counter() - _t0) * 1000),
                           "check")
            st.session_state["mb_last_input"] = _input
            st.session_state["mb_last_result_dict"] = _res.as_dict()
            # Capture into the subsystem activity log so the Documentation report
            # for that discipline lists this busted assumption. Map the checker's
            # discipline id (from the picked channel or the matched rule) onto a
            # subsystem key; fall back to the result's own discipline.
            _rd = _res.as_dict()
            _res_disc = _disc or _rd.get("discipline") or ""
            _disc_to_sub = {"aerodynamics": "aerodynamics", "brakes": "brakes",
                            "cooling": "cooling", "electrics": "electrics",
                            "powertrain": "powertrain", "chassis": "chassis",
                            "suspension": "suspension"}
            _sub = _disc_to_sub.get(_res_disc)
            if _sub:
                _vl = {"myth": "MYTH (false)", "true": "TRUE",
                       "depends": "DEPENDS", "unknown": "no match"}.get(
                           _rd.get("verdict"), _rd.get("verdict", ""))
                record_activity(_sub, "myth",
                                f"\u201c{_input.strip()}\u201d \u2192 {_vl}")
            if _ax is not None:
                _ax.complete("mythbuster", "check",
                             payload={"verdict": _res.as_dict().get("verdict")})
        except Exception as _e:
            if _ax is not None:
                _ax.error("mythbuster", _e)
            st.warning(f"Couldn't check that: {_e}")
    elif _go:
        st.caption("Type an assumption first.")

    # Render last result (persisted across reruns via its dict form).
    _last_in = st.session_state.get("mb_last_input", "")
    _last = st.session_state.get("mb_last_result_dict")
    if _last:
        _mb_render_card(_last_in, _MBDictResult(_last))

    # Reference myths for the selected discipline, evaluated against live context.
    _ref_disc = _disc or None
    with st.expander("Reference \u2014 known myths"
                     + (f" for {_pick}" if _disc else " across all disciplines"),
                     expanded=False):
        try:
            _refs = _mb.reference_myths(_ref_disc, _ctx, limit=12)
        except Exception:
            _refs = []
        if not _refs:
            st.caption("No reference myths registered for that discipline yet.")
        for _r in _refs:
            _claim = getattr(_r.matched_rule, "reference_claim", None) or _last_in
            # use the rule's own example claim where available
            _ex = _r.user_values  # not the claim; fall through to explanation
            _mb_render_card(_mb_reference_claim_for(_mb, _r), _r, compact=True)

    # ---- Add a myth from the UI (no code, no SQL) ------------------------ #
    with st.expander("➕ Add a myth your channel argues about", expanded=False):
        st.caption("The lead who owns a discipline owns its rules — and adds them "
                   "right here. Type the claim in plain language; KinematiK turns "
                   "it into a rule the checker uses from now on. No code, no SQL.")
        try:
            from suspension import myth_bridge as _mb_br
            _author = _mb_br.author()
            _ents = _mb_br.existing_entities()
            _backend_label = {"supabase": "saved to Supabase (shared with the team)",
                              "local": "saved locally (this install)",
                              "memory": "in-memory only"}.get(_author.backend, "")
            _af1, _af2 = st.columns(2)
            _src = _af1.text_input("More of this…", key="myth_src",
                                   placeholder="tyre pressure")
            _tgt = _af2.text_input("…affects this", key="myth_tgt",
                                   placeholder="grip")
            _ef1, _ef2, _ef3 = st.columns(3)
            _eff = _ef1.selectbox("Effect", ["increases", "decreases", "depends",
                                             "none"], index=2, key="myth_eff")
            _verd = _ef2.selectbox("Verdict the checker returns",
                                   ["depends", "true", "myth"], key="myth_verd")
            _disc_opts = ["shared", "suspension", "aerodynamics", "powertrain",
                          "electrics", "brakes", "chassis", "cooling"]
            _mdisc = _ef3.selectbox("Discipline", _disc_opts, key="myth_disc")
            _expl = st.text_area(
                "Explanation the checker shows", key="myth_expl", height=90,
                placeholder="Why it's true / a myth / depends — the reasoning a "
                            "teammate should see, plus where to verify it "
                            "(lap sim, skidpad, FEA).")
            _who = st.text_input("Your name (recorded as the author)",
                                 key="myth_author",
                                 value=st.session_state.get("_ax_member", ""))
            if _backend_label:
                st.caption(f"This rule will be {_backend_label}.")
            if st.button("Add this myth rule", type="primary", key="myth_add_btn"):
                if not (_src.strip() and _tgt.strip() and _expl.strip()):
                    st.warning("Fill in both quantities and an explanation.")
                else:
                    _ax = globals().get("_axn")
                    _r = _author.add_myth(
                        source_phrase=_src, target_phrase=_tgt, effect=_eff,
                        verdict=_verd, explanation=_expl, discipline=_mdisc,
                        existing_entities=_ents, author=_who.strip())
                    if _r.get("ok"):
                        _mb_br.refresh_entity_engine()
                        if _ax is not None:
                            _ax.complete("mythbuster", "add_rule")
                        _newp = (f" Created {', '.join(_r['created_entities'])}."
                                 if _r.get("created_entities") else "")
                        st.success(
                            f"Added — “more {_src.strip()} → {_tgt.strip()}” is now "
                            f"checkable.{_newp} Try asking it above.")
                    else:
                        st.error(f"Couldn't save the rule: {_r.get('error')}")
        except Exception as _myth_e:
            st.caption(f"Authoring unavailable right now: {_myth_e}")

    # Always-on validation disclaimer: the myth-buster is the fast first pass,
    # not the final word. Name the real tools so it's unambiguous.
    _mb_validation_disclaimer()


def _mb_validation_disclaimer(compact: bool = False):
    """The 'validate in the real tools' reminder for the Myth-Buster.

    Kept in one place so every myth-buster surface (the full view and the
    inline per-subsystem checks) carries the same honest reminder: this is a
    deterministic screening pass, the hour BEFORE you open the analysis
    packages — not a replacement for them.

    ``compact=True`` renders a tight one-line note meant to sit DIRECTLY under a
    verdict card (no divider, small margin) so the disclaimer travels with the
    outcome; ``compact=False`` is the fuller footer for the bottom of a view.
    """
    if compact:
        st.markdown(
            '<p class="hint" style="font-size:.7rem;line-height:1.5;'
            'color:var(--dim);margin:6px 2px 2px;">'
            '⚠️ <b>Screening result — the hour before ANSYS, SolidWorks &amp; '
            'MATLAB.</b> Deterministic sanity check, not FEA/CFD or a full sim. '
            'Validate anything you\'ll design, cut, order or sign off in the real '
            'tools, and confirm rule limits against the current rulebook.</p>',
            unsafe_allow_html=True)
        return
    st.markdown(
        '<hr style="border:none;border-top:1px solid rgba(128,128,128,.18);'
        'margin:14px 0 8px;">', unsafe_allow_html=True)
    st.markdown(
        '<p class="hint" style="font-size:.72rem;line-height:1.55;'
        'color:var(--dim);margin:0;">'
        '⚠️ <b>This is the hour before ANSYS, SolidWorks and MATLAB — not a '
        'replacement for them.</b> The myth-buster is a fast, deterministic '
        'sanity check against declared numbers and encoded physics/FSAE rules: '
        'it catches bad assumptions early and settles arguments, but it does '
        'not run FEA, CFD or a full vehicle sim. Always validate anything you\'re '
        'about to design, cut, order or sign off in the real tools — '
        '<b>ANSYS / CFD</b> for structural &amp; thermal &amp; flow, '
        '<b>SolidWorks</b> for geometry, fit and mass properties, '
        '<b>MATLAB / Simulink</b> for lap-time and dynamics — and confirm rule '
        'limits against the current season\'s official rulebook.</p>',
        unsafe_allow_html=True)


def _mb_reference_claim_for(_mb, result):
    """Best-effort: recover the example claim text that produced a reference
    result, so the card shows the claim, not a blank."""
    rule = next((r for r in _mb.all_rules() if r.name == result.matched_rule), None)
    if rule is not None:
        ex = getattr(rule.check, "reference_claim", None)
        if ex:
            return ex
    return "(reference)"


class _MBDictResult:
    """Adapt a stored result-dict back to the attribute interface the card
    renderer expects (Streamlit reruns lose the live object)."""
    def __init__(self, d):
        self.verdict = d.get("verdict", "unknown")
        self.matched_rule = d.get("matched_rule", "")
        self.explanation = d.get("explanation", "")
        self.discipline = d.get("discipline", "")
        self.provenance = d.get("provenance", "")
        self.user_values = d.get("user_values", {})




# (_do_rerun is defined near the top of the file, right after the imports, so
#  that tab helpers which call it during render can always see it.)



#
#    * a Verdict Center with an OVERVIEW page (the whole-car picture) and one
#      sub-tab PER SUBSYSTEM, each a single tidy box that answers three things:
#          ✅ This works
#          🔎 Take a closer look
#          🛑 Pay attention to this
#    * a Documentation view that MERGES the report + a small LIBRARY of ready
#      templates a member ticks on/off, with the sanity-check (myth-buster)
#      built in, and a "double-check before you cut" disclaimer at the bottom;
#    * a generic "short-list to mesh + export DXF" affordance any subsystem
#      can offer, mirroring the brakes rotor exporter.
#
#  Everything is deterministic and reads the SAME single source of truth (the
#  Integration ledger, the registry, the activity log) the rest of the app uses.
# ============================================================================


# --------------------------------------------------------------------------- #
#  2.  The Verdict Center — Overview page + per-subsystem sub-tabs             #
# --------------------------------------------------------------------------- #
def render_verdict_center():
    """The reorganised myth-buster / verdict home.

    Top level: a small radio that behaves like arrows to different pages —
        Overview · one page per subsystem · Sanity-check (myth-buster)
    The Overview is the whole-car picture (a box per subsystem); each subsystem
    page is its own tidy three-box verdict; the Sanity-check page is the full
    deterministic myth-buster (unchanged engine)."""
    st.markdown(
        '<p class="hint" style="margin:0 0 10px;">One place to see <b>how the car '
        'is doing</b>. Start on <b>Overview</b> for the whole-car picture, then '
        'step into any subsystem for the detail — each one tells you plainly '
        'what works, what to look at, and what needs attention. '
        'The <b>Sanity-check</b> page is the deterministic myth-buster.</p>',
        unsafe_allow_html=True)

    # Page picker — the "arrows to different pages" the request asked for.
    _pages = ["📋 Overview"] + [
        f"{_VC_EMOJI[k]} {_VC_LABEL[k]}" for k, _e, _l in _VC_SUBSYS
    ] + ["🔎 Sanity-check (myth-buster)"]
    _page = st.radio("Verdict page", _pages, horizontal=True,
                     label_visibility="collapsed", key="vc_page_nav")

    # ---- OVERVIEW --------------------------------------------------------- #
    if _page == "📋 Overview":
        _all = {k: _vc_collect(k) for k, _e, _l in _VC_SUBSYS}
        _counts = {"green": 0, "amber": 0, "red": 0, "empty": 0}
        for d in _all.values():
            _counts[d["verdict"]] += 1
        _worst = ("red" if _counts["red"] else
                  "amber" if _counts["amber"] else
                  "green" if _counts["green"] else "empty")
        _c = {"green": "#37e0d0", "amber": "#ffb02e",
              "red": "#ff5a52", "empty": "#9b8cff"}[_worst]
        _dot = {"green": "🟢", "amber": "🟡", "red": "🔴", "empty": "⚪"}[_worst]
        _msg = {"green": "Every declared subsystem is clear.",
                "amber": "Some subsystems need a closer look.",
                "red": "At least one subsystem needs attention.",
                "empty": "Declare some subsystem numbers to light this up."}[_worst]
        st.markdown(
            f'<div class="card" style="border-left:4px solid {_c};display:flex;'
            f'align-items:center;gap:1rem;margin:.2rem 0 .8rem;">'
            f'<div style="font-size:1.6rem;line-height:1">{_dot}</div>'
            f'<div style="flex:1"><div style="font-family:\'JetBrains Mono\';'
            f'font-size:.7rem;letter-spacing:.14em;text-transform:uppercase;'
            f'color:var(--dim)">Whole-car verdict</div>'
            f'<div style="font-weight:600;font-size:1.05rem;color:{_c}">{_msg}'
            f'</div></div>'
            f'<div style="text-align:right;font-family:\'JetBrains Mono\'">'
            f'<div style="font-size:.8rem;color:#37e0d0">🟢 {_counts["green"]} clear</div>'
            f'<div style="font-size:.8rem;color:#ffb02e">🟡 {_counts["amber"]} watch</div>'
            f'<div style="font-size:.8rem;color:#ff5a52">🔴 {_counts["red"]} attention</div>'
            f'</div></div>', unsafe_allow_html=True)

        with st.expander("⚙️ Per-subsystem", expanded=False):
          st.caption("Tap a subsystem's page above for the detail. Worst-first.")
          _rank = {"red": 0, "amber": 1, "green": 2, "empty": 3}
          _ordered = sorted(_VC_SUBSYS, key=lambda t: _rank[_all[t[0]]["verdict"]])
          _cols = st.columns(2)
          for _i, (k, _e, _l) in enumerate(_ordered):
              d = _all[k]
              _dot2 = {"green": "🟢", "amber": "🟡", "red": "🔴",
                       "empty": "⚪"}[d["verdict"]]
              _cc = {"green": "#37e0d0", "amber": "#ffb02e",
                     "red": "#ff5a52", "empty": "#9b8cff"}[d["verdict"]]
              _headline = (d["attention"][0] if d["attention"] else
                           d["closer"][0] if d["closer"] else
                           d["works"][0] if d["works"] else
                           "Nothing declared yet.")
              with _cols[_i % 2]:
                  st.markdown(
                      f'<div style="border:1px solid {_cc}44;border-left:4px solid {_cc};'
                      f'border-radius:8px;padding:10px 12px;margin:0 0 10px;'
                      f'background:{_cc}0d;min-height:88px;">'
                      f'<div style="font-weight:600;font-size:.92rem;">'
                      f'{_e} {_l} &nbsp;{_dot2}</div>'
                      f'<div style="font-size:.75rem;color:var(--dim);margin-top:2px;">'
                      f'✅ {len(d["works"])} · 🔎 {len(d["closer"])} · '
                      f'🛑 {len(d["attention"])}</div>'
                      f'<div style="font-size:.8rem;margin-top:6px;'
                      f'line-height:1.4;">{_headline}</div>'
                      f'</div>', unsafe_allow_html=True)
          _vc_disclaimer("this overview")
          return

    # ---- SANITY-CHECK (full myth-buster, unchanged engine) ---------------- #
    if _page.startswith("🔎"):
        render_mythbuster()
        # render_mythbuster() already ends with the tool-validation disclaimer
        # (validate in ANSYS / SolidWorks / MATLAB), so no second footer here.
        return

    # ---- a single subsystem page ------------------------------------------ #
    for k, _e, _l in _VC_SUBSYS:
        if _page == f"{_e} {_l}":
            render_subsystem_verdict_card(k)
            # inline sanity-check scoped to this subsystem. render_myth_check
            # carries its own tool-validation disclaimer (validate in ANSYS /
            # SolidWorks / MATLAB) once a check runs.
            with st.expander("⚙️ Sanity-check an assumption here", expanded=False):
              try:
                  render_myth_check(k, key_prefix=f"vc_{k}")
              except Exception:
                  pass
            # footer for the subsystem verdict card as a whole.
            _vc_disclaimer(f"the {_l.lower()} verdict")
            return

# --------------------------------------------------------------------------- #
#  4.  Generic "short-list to mesh + export DXF" for any subsystem             #
def render_suspension_vs_chassis():
    _IFm = interfaces_mod
    _led_cad = _IFm.IntegrationLedger.from_dict(st.session_state.ledger)
    # Any physical subsystem can be checked against the chassis. Suspension is
    # special — it MOVES, so it gets a swept-clearance check. Every other physical
    # subsystem is statically mounted, so it gets an envelope-fit check (does the
    # part's bounding box sit inside the frame and clear the tubes). Data-acquisition
    # is excluded: it's wiring/loggers with no meaningful rigid envelope to fit.
    _CAD_SUBSYSTEMS = [s for s in _IFm.SUBSYSTEMS if s != "data-acquisition"]
    subsys = st.selectbox("Which subsystem to check against the chassis?",
                          _CAD_SUBSYSTEMS,
                          index=_CAD_SUBSYSTEMS.index("suspension"),
                          key="cad_subsystem")

    if subsys != "suspension":
        _render_envelope_vs_chassis(subsys, _led_cad)
        return

    st.markdown('<p class="hint">Load the team\'s chassis CAD (STEP or STL) to check '
                'two things before you cut tube: do the inboard pickups land on the '
                'frame (fit), and does the moving linkage clear the chassis through '
                'full travel (clearance). Coordinates must share the suspension origin '
                '— use the offset boxes to align the CAD if needed.</p>',
                unsafe_allow_html=True)

    up = st.file_uploader("Chassis CAD", type=["step", "stp", "stl", "obj", "glb"],
                          label_visibility="collapsed")
    oc1, oc2, oc3, oc4 = st.columns(4)
    off_x = oc1.number_input("offset x", value=0.0, step=10.0)
    off_y = oc2.number_input("offset y", value=0.0, step=10.0)
    off_z = oc3.number_input("offset z", value=0.0, step=10.0)
    cad_scale = oc4.number_input("scale (m→mm = 1000)", value=1.0, step=1.0)

    if up is None:
        st.markdown('<p class="hint" style="padding-top:.5rem;">Waiting for a chassis '
                    'file. Don\'t have the CAD handy? Export it from your assembly as '
                    'STEP — that\'s the most reliable format here.</p>',
                    unsafe_allow_html=True)
    else:
        import tempfile as _tf
        suffix = "." + up.name.split(".")[-1]
        with _tf.NamedTemporaryFile(suffix=suffix, delete=False) as f:
            f.write(up.getbuffer())
            cad_path = f.name
        try:
            with st.spinner("Loading chassis and sweeping the linkage…"):
                mesh = chassis_mod.load_chassis(
                    cad_path, offset=(off_x, off_y, off_z), scale=cad_scale)
                summ = chassis_mod.mesh_summary(mesh)
                fit = chassis_mod.fit_check(hp, mesh, tol_mm=12.0)
                clr = chassis_mod.clearance_check(kin, mesh, warn_mm=8.0)

            verdict = clr["verdict"]
            vcolor = {"CLEAR": ("good", "Linkage clears the chassis"),
                      "TIGHT": ("warn", "Clearance below 8 mm — review before fab"),
                      "COLLISION": ("bad", "Linkage hits the chassis — fix geometry")}[verdict]
            st.markdown(f'<div class="metric" style="margin:.4rem 0;">'
                        f'<span class="k">CLEARANCE VERDICT</span>'
                        f'<span class="v {vcolor[0]}">{verdict}'
                        f'<span class="u"> · {vcolor[1]}</span></span></div>',
                        unsafe_allow_html=True)

            cL, cR = st.columns(2)
            with cL:
                with st.expander("⚙️ Inboard pickup fit", expanded=False):
                  for r in fit:
                      tag = "good" if r["mountable"] else "bad"
                      note = "on frame" if r["mountable"] else "off frame"
                      st.markdown(metric(r["label"], f"{r['distance_mm']:.1f}",
                                         f"mm · {note}", tag), unsafe_allow_html=True)
            with cR:
                with st.expander("⚙️ Link clearance (min over travel)", expanded=False):
                  order = sorted(clr["per_link"].items(),
                                 key=lambda kv: kv[1]["min_clearance_mm"])
                  for link, v in order:
                      tag = ("bad" if v["collision"] else
                             "warn" if v["warning"] else "good")
                      label = link.replace("_", " ")
                      st.markdown(metric(label, f"{v['min_clearance_mm']:.1f}", "mm", tag),
                                  unsafe_allow_html=True)

            # 3D overlay: chassis mesh + swept linkage
            with st.expander("⚙️ Linkage swept through travel, overlaid on chassis", expanded=False):
              pts, names = chassis_mod.sweep_link_points(kin, -30, 30, 11)
              fig = go.Figure()
              vx, vy, vz = mesh.vertices[:, 0], mesh.vertices[:, 1], mesh.vertices[:, 2]
              i, j, k = mesh.faces[:, 0], mesh.faces[:, 1], mesh.faces[:, 2]
              fig.add_trace(go.Mesh3d(x=vx, y=vy, z=vz, i=i, j=j, k=k,
                            color="#5a6b7a", opacity=0.35, name="Chassis",
                            flatshading=True))
              names_arr = np.array(names)
              palette = {"upper_wishbone_front": CYAN, "upper_wishbone_rear": CYAN,
                         "lower_wishbone_front": AMBER, "lower_wishbone_rear": AMBER,
                         "upright": "#ffffff", "tie_rod": RED, "wheel_spindle": "#9b8cff"}
              for link in np.unique(names_arr):
                  m = names_arr == link
                  fig.add_trace(go.Scatter3d(
                      x=pts[m, 0], y=pts[m, 1], z=pts[m, 2], mode="markers",
                      marker=dict(size=2, color=palette.get(link, "#888")),
                      name=link.replace("_", " ")))
              fig.update_layout(
                  paper_bgcolor="rgba(0,0,0,0)",
                  scene=dict(
                      xaxis=dict(title="x", backgroundcolor="#0e1216", gridcolor="#1d242c", color="#8d99a6"),
                      yaxis=dict(title="y", backgroundcolor="#0e1216", gridcolor="#1d242c", color="#8d99a6"),
                      zaxis=dict(title="z", backgroundcolor="#0e1216", gridcolor="#1d242c", color="#8d99a6"),
                      aspectmode="data", camera=dict(eye=dict(x=1.6, y=-1.5, z=0.9))),
                  font=dict(family="JetBrains Mono", color="#cdd6df", size=10),
                  height=520, margin=dict(l=0, r=0, t=10, b=0),
                  legend=dict(bgcolor="rgba(0,0,0,0)", font=dict(size=9)))
              st.plotly_chart(fig, width='stretch')

              _smm2 = [units_mod.from_metric(_v, "mm") for _v in summ["size_mm"]]
              st.markdown(f'<p class="hint">Chassis mesh: {summ["triangles"]:,} triangles, '
                          f'bounding box {_smm2[0]:.0f}×{_smm2[1]:.0f}×'
                          f'{_smm2[2]:.0f} {units_mod.label("mm")}. If the linkage and chassis look '
                          f'misaligned above, adjust the offset boxes so the origins match.</p>',
                          unsafe_allow_html=True)

              if verdict in ("COLLISION", "TIGHT"):
                  worst = clr["worst_link"].replace("_", " ")
                  _uL = units_mod.label("mm")
                  _wc = units_mod.from_metric(clr['worst_clearance_mm'], "mm")
                  if verdict == "COLLISION":
                      sug = (f"Suspension: {worst} hits the chassis through travel "
                             f"(worst {_wc:.0f} {_uL}). Geometry "
                             f"adjusted / flagged before cutting tube.")
                  else:
                      sug = (f"Suspension: {worst} clears the chassis by only "
                             f"{_wc:.1f} {_uL} at full travel — tight. "
                             f"Reviewed before fabrication.")
                  st.markdown('<p class="hint" style="margin-top:.4rem;">⚑ Worth recording '
                              'for handover:</p>', unsafe_allow_html=True)
                  edited = st.text_area("Decision note (edit before logging)",
                                        value=sug, height=80, key="autocap_susp")
                  if st.button("＋ Log this to handover", key="autocap_susp_btn"):
                      log_decision_now("suspension",
                                       f"Suspension {verdict.lower()} vs chassis",
                                       edited, author="INTEGRATION")
                      st.success("Logged to project.json — visible in WEIGHT & HANDOVER.")

              sheet = chassis_mod.manufacturing_sheet(hp, kin)
              st.download_button("⬇ Manufacturing pickup schedule (.csv)", sheet,
                                 file_name="kinematik_pickups.csv", mime="text/csv")
        except Exception as e:
            st.error(f"Could not process the chassis file: {e}")
        finally:
            try:
                os.unlink(cad_path)
            except Exception:
                pass

# --------- MOUNT-POINT CLASH (section of the merged INTEGRATION tab) -------- #
def render_geometry_intake(store, geom):
    """
    Low-friction, guided data entry so the clash gate has real geometry to judge.

    The readiness board is honest, which means it stays NOT-READY until every
    subsystem declares (a) the volume it reserves — its keep-out box — and (b)
    where it bolts to the car — its mount points. This form walks ONE subsystem
    at a time through both in plain language, with defaults pre-filled, a running
    roster of who has entered data and who hasn't, and an estimate toggle so a
    team can declare a rough box now and confirm it later. It writes through the
    same store.set_keepout / set_mount_point the detailed editor uses, so nothing
    here is a parallel data path — it is just a friendlier door to the same ledger.
    """
    from suspension.mountpoints import MountPoint, KeepOut
    _SUBS = ["aerodynamics", "brakes", "chassis", "cooling",
             "data-acquisition", "electrics", "powertrain", "suspension"]
    _EMOJI = {"aerodynamics": "💛", "brakes": "🧡", "chassis": "💜", "cooling": "🩵",
              "data-acquisition": "💚", "electrics": "💙", "powertrain": "❤️",
              "suspension": "🩷"}

    # Who has declared anything yet — the roster that turns "enter your data" from
    # an abstract ask into a visible, finite checklist the team can close out.
    have_ko = {ko.owner_subsystem for ko in (geom.keepouts or {}).values()}
    have_mp = {mp.owner_subsystem for mp in (geom.points or {}).values()}
    entered = have_ko | have_mp
    missing = [s for s in _SUBS if s not in entered]

    with st.expander("① Start here — declare your subsystem's geometry "
                     f"({len(entered)}/8 teams in)",
                     expanded=bool(missing)):
        st.markdown(
            '<p class="hint">Two things make the clash gate work, and only your '
            'team knows them for your subsystem:<br>'
            '<b>1 · Your keep-out box</b> — the volume you reserve that nothing '
            'else may enter (your accumulator envelope, the cooling duct path, the '
            'roll-hoop tube, the driver\u2019s legroom). Give two opposite corners '
            'in car coordinates (x: rear\u2192front, y: left\u2192right, z: up), in mm.<br>'
            '<b>2 · Your mount points</b> — where your parts bolt to the car, and '
            'how much clearance they need. Each point names what it mounts onto.<br>'
            'Don\u2019t have exact numbers yet? Enter your best estimate and tick '
            '<i>estimated</i> \u2014 it still gets checked, just flagged as '
            'unconfirmed so you know to come back. The goal is to drive the '
            '\u201cstill estimated\u201d count to zero before anyone cuts material.</p>',
            unsafe_allow_html=True)

        # Roster line: green who's in, grey who's still missing.
        _in = " ".join(f"{_EMOJI[s]}{s}" for s in _SUBS if s in entered) or "—"
        _out = " ".join(f"{_EMOJI[s]}{s}" for s in missing) or "none 🎉 every team is in"
        st.markdown(
            f'<div style="border-left:3px solid var(--line);padding:6px 12px;margin:2px 0 8px;">'
            f'<span style="font-size:.84rem;color:#8d99a6;">entered:</span> '
            f'<span style="font-size:.86rem;">{_in}</span><br>'
            f'<span style="font-size:.84rem;color:#8d99a6;">still needed:</span> '
            f'<span style="font-size:.86rem;">{_out}</span></div>',
            unsafe_allow_html=True)

        # Pick the subsystem to enter — default to the first one still missing, so
        # the form naturally walks the team through the gaps.
        _default_idx = _SUBS.index(missing[0]) if missing else 0
        who = st.selectbox("Which subsystem are you entering?", _SUBS,
                           index=_default_idx, key="intake_who",
                           format_func=lambda s: f"{_EMOJI[s]} {s}")

        gi = st.columns(2)
        # ---- 1) keep-out box ---- #
        with gi[0]:
            st.markdown("**1 · Your keep-out box**")
            _kn = st.text_input("Name it", value=f"{who}-envelope",
                                key="intake_ko_name")
            lo_c = st.columns(3)
            lo = (lo_c[0].number_input("corner A — x", value=0.0, step=10.0, key="intake_lox"),
                  lo_c[1].number_input("y", value=-150.0, step=10.0, key="intake_loy"),
                  lo_c[2].number_input("z", value=0.0, step=10.0, key="intake_loz"))
            hi_c = st.columns(3)
            hi = (hi_c[0].number_input("corner B — x", value=200.0, step=10.0, key="intake_hix"),
                  hi_c[1].number_input("y", value=150.0, step=10.0, key="intake_hiy"),
                  hi_c[2].number_input("z", value=200.0, step=10.0, key="intake_hiz"))
            _ke = st.checkbox("These corners are estimated", value=True,
                              key="intake_ko_est",
                              help="Leave ticked until you've confirmed the volume "
                                   "from real CAD. Estimated boxes still get checked.")
            if st.button("Save my keep-out", key="intake_ko_save"):
                store.set_keepout(KeepOut(_kn, who, lo_mm=lo, hi_mm=hi,
                                          is_estimate=_ke))
                store.save()
                st.rerun()

        # ---- 2) a mount point ---- #
        with gi[1]:
            st.markdown("**2 · A mount point** (add one at a time)")
            _pn = st.text_input("Name it", value=f"{who}-mount-1",
                                key="intake_mp_name")
            _mo = st.selectbox("Bolts onto", _SUBS,
                               index=_SUBS.index("chassis"),
                               key="intake_mp_mounts",
                               format_func=lambda s: f"{_EMOJI[s]} {s}")
            p_c = st.columns(3)
            pxyz = (p_c[0].number_input("at — x", value=100.0, step=10.0, key="intake_px"),
                    p_c[1].number_input("y", value=0.0, step=10.0, key="intake_py"),
                    p_c[2].number_input("z", value=100.0, step=10.0, key="intake_pz"))
            _clr = st.number_input("Clearance it needs", 0.0, 100.0, value=8.0,
                                   step=1.0, key="intake_mp_clr",
                                   help="How far this point must stay from any other "
                                        "subsystem's keep-out. 5–10 mm is typical for "
                                        "a bolted bracket; more if a tool must reach in.")
            _pe = st.checkbox("This position is estimated", value=True,
                              key="intake_mp_est")
            if st.button("Save my mount point", key="intake_mp_save"):
                store.set_mount_point(MountPoint(_pn, xyz_mm=pxyz,
                                                 owner_subsystem=who,
                                                 mounts_on=_mo,
                                                 min_clearance_mm=_clr,
                                                 is_estimate=_pe))
                store.save()
                st.rerun()

        st.markdown(
            '<p class="hint" style="margin-top:6px;">Add as many mount points as '
            'your subsystem has. When every team has entered a box and its mounts, '
            'the readiness verdict below judges the real car \u2014 and the full '
            'editor under \u201cMount points / keep-out volumes\u201d lets you tweak '
            'or delete anything you\u2019ve saved.</p>', unsafe_allow_html=True)


def render_manufacturing_readiness(geom):
    """
    Whole-car go/no-go for a team that can only manufacture once.

    Consumes the SAME geom.check_clashes() findings as the clash board below — no
    parallel data path — and reshapes them into a single build-readiness verdict:

      * the ONLY hard STOP is physical interference (parts overlapping). It is
        owner-independent and needs no per-part tagging, so it stays zero-friction:
        the geometry itself decides.
      * thin-clearance shortfalls WARN, never stop — but a shortfall on ESTIMATED
        geometry is ranked above one on confirmed geometry, because a part that
        only just clears at a position you GUESSED is the one most likely to
        actually overlap once real dimensions land. The is_estimate flag already
        in the data does this for free — no one-shot list to maintain and rot.
      * estimates never block a green result; instead every row carries a separate
        confidence chip (confirmed vs est), and the pile of "est" chips IS the
        team's pre-manufacturing to-do list. When it's empty, the green is real.

    This is the lowest-friction design that still catches the collision that would
    cost the re-make: interference stops the build, everything else informs it.
    """
    from suspension.interfaces import Severity
    findings = geom.check_clashes()

    # Partition the real clash findings (ignore the synthetic OK/MISSING summary
    # rows check_clashes emits when there is nothing to check — the readiness
    # banner speaks to those states itself).
    interferences, clearances = [], []
    for f in findings:
        d = f.detail or {}
        if f.check == "clash-interference":
            interferences.append(f)
        elif f.check == "clash-clearance":
            clearances.append(f)

    n_pts = len(getattr(geom, "points", {}) or {})
    n_kos = len(getattr(geom, "keepouts", {}) or {})

    # ---- the single go/no-go banner ---- #
    if not n_pts or not n_kos:
        _verdict, _cls, _line = (
            "NOT READY — NO DATA", "warn",
            "No geometry to judge yet. Until every subsystem declares its mount "
            "points and keep-out volumes below, this board is green on a car that "
            "doesn't exist — the exact false confidence that loses a one-shot "
            "build. Populating the ledger is the highest-value thing the team can "
            "do; the gate is ready the moment the numbers are real.")
    elif interferences:
        _verdict, _cls = "DO NOT MANUFACTURE", "bad"
        _line = (f"{len(interferences)} hard interference(s) — parts physically "
                 "overlap. These will not assemble; fix the geometry before "
                 "anything is cut, drilled, or laid up.")
    elif clearances:
        _est_warn = sum(1 for f in clearances if (f.detail or {}).get("estimate"))
        _verdict, _cls = "BUILD WITH OPEN ITEMS", "warn"
        _line = (f"No interference. {len(clearances)} thin-clearance warning(s)"
                 + (f", {_est_warn} of them on geometry you marked estimated "
                    "(your highest real risk — confirm those positions first)"
                    if _est_warn else "")
                 + ". None of these stop the build, but each is a deliberate "
                 "decision, not an oversight.")
    else:
        _verdict, _cls = "CLEAR TO MANUFACTURE", "good"
        _line = (f"All {n_pts} mount point(s) clear every keep-out with margin and "
                 "no part overlaps another.")

    # ---- confidence: the to-do list that drains toward build day ---- #
    est_pts = [m.name for m in (geom.points or {}).values() if getattr(m, "is_estimate", False)]
    est_kos = [k.name for k in (geom.keepouts or {}).values() if getattr(k, "is_estimate", False)]
    n_est = len(est_pts) + len(est_kos)
    n_geo = n_pts + n_kos
    if n_geo:
        confirmed = n_geo - n_est
        if n_est == 0:
            _conf = (f"Confidence: all {n_geo} geometries confirmed — this verdict "
                     "rests on real numbers, not estimates.")
        else:
            _conf = (f"Confidence: {confirmed}/{n_geo} geometries confirmed · "
                     f"<b>{n_est} still estimated</b>. Those {n_est} are the "
                     "pre-manufacturing to-do list — a green result above is only "
                     "as trustworthy as these are real. Confirm them down to zero "
                     "before sign-off.")
    else:
        _conf = ""

    # ---- scope caveat: what the verdict CANNOT see yet -------------------- #
    # Framed as the check's blind spots, not a roster of who is late. A
    # subsystem that has declared no geometry is invisible to the clash check,
    # so any collision involving it is undetectable — that is a fact about the
    # VERDICT's coverage, not a judgement of the people. We deliberately do NOT
    # phrase this as "team X owes data": that pressures someone to enter a junk
    # estimate just to clear their name, which corrupts the ledger the whole gate
    # depends on. Naming the blind spots pressures the result's credibility (good)
    # without pressuring people to launder unknowns into fake-confirmed cells (bad).
    _ALL_SUBS = ["aerodynamics", "brakes", "chassis", "cooling",
                 "data-acquisition", "electrics", "powertrain", "suspension"]
    _EMOJI = {"aerodynamics": "💛", "brakes": "🧡", "chassis": "💜", "cooling": "🩵",
              "data-acquisition": "💚", "electrics": "💙", "powertrain": "❤️",
              "suspension": "🩷"}
    _declared = ({k.owner_subsystem for k in (geom.keepouts or {}).values()}
                 | {m.owner_subsystem for m in (geom.points or {}).values()})
    _blind = [s for s in _ALL_SUBS if s not in _declared]
    if _blind and n_geo:
        # Only meaningful once SOME data exists — when nothing is declared the
        # banner already says NO DATA, and repeating all eight names is noise.
        _names = " ".join(f"{_EMOJI[s]}{s}" for s in _blind)
        _scope = (
            f"Scope of this verdict: it covers {len(_declared)} of 8 subsystems. "
            f"It is <b>blind to {len(_blind)}</b> that have declared no geometry "
            f"yet \u2014 {_names}. Any collision involving those is undetectable "
            "here, so treat even a green result as provisional until they\u2019re "
            "in. This is a limit of what the check can see, not a tally of who\u2019s "
            "behind.")
    else:
        _scope = ""

    st.markdown(
        f'<div style="border:1px solid var(--line);border-left:5px solid var(--line);'
        f'border-radius:8px;padding:12px 16px;margin:6px 0 10px;">'
        f'<span class="tag {_cls}" style="font-size:.95rem;">{_verdict}</span><br>'
        f'<span style="font-size:.95rem;line-height:1.45;">{_line}</span>'
        + (f'<br><span style="font-size:.86rem;color:#8d99a6;line-height:1.4;">{_conf}</span>'
           if _conf else "")
        + (f'<br><span style="font-size:.86rem;color:#8d99a6;line-height:1.4;">{_scope}</span>'
           if _scope else "")
        + '</div>', unsafe_allow_html=True)

    # ---- ranked open items: interference first, then est-clearance, then rest -- #
    # Estimate-amplification: a shortfall on guessed geometry outranks the same
    # shortfall on confirmed geometry. Within each tier, tighter gaps come first.
    if interferences or clearances:
        def _rank(f):
            d = f.detail or {}
            if f.check == "clash-interference":
                return (0, -(d.get("penetration_mm") or 0.0))
            est = 1 if d.get("estimate") else 2     # estimated clearance before confirmed
            return (est, d.get("gap_mm") or 0.0)
        st.markdown('<p class="hint" style="margin:2px 0 4px;"><b>Open items</b>, '
                    'ranked by what most threatens the one-shot build:</p>',
                    unsafe_allow_html=True)
        _MP_EMOJI = {"aerodynamics": "💛", "brakes": "🧡", "chassis": "💜",
                     "cooling": "🩵", "data-acquisition": "💚", "electrics": "💙",
                     "powertrain": "❤️", "suspension": "🩷"}
        for f in sorted(interferences + clearances, key=_rank):
            d = f.detail or {}
            est = d.get("estimate")
            stop = f.check == "clash-interference"
            tag_cls = "bad" if stop else "warn"
            tag_txt = "STOP · INTERFERENCE" if stop else "WARN · CLEARANCE"
            conf_chip = ('<span class="tag warn" style="font-size:.7rem;">EST</span>'
                         if est else
                         '<span class="tag good" style="font-size:.7rem;">CONFIRMED</span>')
            who = " ↔ ".join(f"{_MP_EMOJI.get(x,'')}{x}" for x in f.subsystems) if f.subsystems else ""
            st.markdown(
                f'<div style="border-left:3px solid var(--line);padding:6px 12px;margin:4px 0;">'
                f'<span class="tag {tag_cls}">{tag_txt}</span> {conf_chip} '
                f'&nbsp;<span style="color:#8d99a6;font-size:.8rem">{who}</span><br>'
                f'<span style="font-size:.92rem">{f.message}</span></div>',
                unsafe_allow_html=True)


def render_mountpoint_clash():
    """
    The CAD→clash→CG chain, live: an aero member drags a single wing mounting point
    and we re-run the point-vs-keep-out clearance check (flagging the chassis master
    file clash) and re-roll the car CG through the integration ledger — in one call,
    persisted to the project store so it survives a restart.
    """
    from suspension.mountpoints import MountPoint, KeepOut, propagate_mount_move
    _MP_EMOJI = {"aerodynamics": "💛", "brakes": "🧡", "chassis": "💜", "cooling": "🩵",
                 "data-acquisition": "💚", "electrics": "💙", "powertrain": "❤️",
                 "suspension": "🩷"}
    _SUBS = ["aerodynamics", "brakes", "chassis", "cooling",
             "data-acquisition", "electrics", "powertrain", "suspension"]

    st.markdown('<p class="hint">This is the move an aero member actually makes: drag '
                'a single <b>wing mounting point</b> and see, immediately, whether it '
                'now <b>clashes with a chassis keep-out</b> (the clearance check the '
                'chassis engineer would otherwise catch at assembly) and what it does '
                'to the car <b>CG</b> the vehicle-dynamics model uses. Points and '
                'keep-outs persist with the project. It is a <i>geometric</i> check on '
                'declared points and boxes — not a CAD kernel — so a point that bolts '
                'onto a structure is allowed to touch it; everything else it must '
                'clear.</p>', unsafe_allow_html=True)

    store = get_store()
    geom = store.geometry
    if geom is None:
        st.error("The mount-point / keep-out geometry layer is unavailable in "
                 "this deployment (its numpy-backed module failed to import). "
                 "Other tabs work; reinstall the app dependencies (numpy) to "
                 "restore the clash check.")
        return

    # Guided data entry first — the gate is only honest once the geometry is real,
    # so the friendliest door to the ledger leads. Then the whole-car verdict.
    render_geometry_intake(store, geom)
    render_manufacturing_readiness(geom)
    st.divider()

    # ---- editor: keep-outs and mount points ---- #
    ec = st.columns(2)
    with ec[0]:
        with st.expander("⚙️ Keep-out volumes (reserved by a subsystem's master file)", expanded=False):
          with st.expander("Add / replace a keep-out", expanded=not geom.keepouts):
              kname = st.text_input("Name", key="ko_name", value="main-hoop-tube")
              kowner = st.selectbox("Owned by", _SUBS, index=_SUBS.index("chassis"),
                                    key="ko_owner")
              kl = st.columns(3)
              lo = (unum(kl[0], "lo x (mm)", -10000.0, 10000.0, 1380.0, "mm", key="ko_lox"),
                    unum(kl[1], "lo y (mm)", -10000.0, 10000.0, -180.0, "mm", key="ko_loy"),
                    unum(kl[2], "lo z (mm)", -10000.0, 10000.0, 480.0, "mm", key="ko_loz"))
              kh = st.columns(3)
              hi = (unum(kh[0], "hi x (mm)", -10000.0, 10000.0, 1430.0, "mm", key="ko_hix"),
                    unum(kh[1], "hi y (mm)", -10000.0, 10000.0, 180.0, "mm", key="ko_hiy"),
                    unum(kh[2], "hi z (mm)", -10000.0, 10000.0, 1050.0, "mm", key="ko_hiz"))
              kest = st.checkbox("Estimated geometry", value=False, key="ko_est")
              if st.button("Save keep-out", key="ko_save"):
                  store.set_keepout(KeepOut(kname, kowner, lo_mm=lo, hi_mm=hi,
                                            is_estimate=kest))
                  store.save()
                  st.rerun()
          for name, ko in list(geom.keepouts.items()):
              est = " · est" if ko.is_estimate else ""
              kc = st.columns([5, 1])
              kc[0].markdown(
                  f'<div style="border-left:3px solid var(--line);padding:4px 10px;margin:3px 0;">'
                  f'{_MP_EMOJI.get(ko.owner_subsystem,"")} <b>{name}</b> '
                  f'<span style="color:#8d99a6;font-size:.8rem">{ko.owner_subsystem}{est}</span><br>'
                  f'<span style="font-size:.82rem;color:#8d99a6">'
                  f'{tuple(round(units_mod.from_metric(v,"mm")) for v in ko.lo_mm)} → {tuple(round(units_mod.from_metric(v,"mm")) for v in ko.hi_mm)} {units_mod.label("mm")}</span></div>',
                  unsafe_allow_html=True)
              if kc[1].button("✕", key=f"ko_del_{name}"):
                  store.remove_keepout(name); store.save(); st.rerun()

    with ec[1]:
        with st.expander("⚙️ Mount points (the hardpoints a subteam moves)", expanded=False):
          with st.expander("Add / replace a mount point", expanded=not geom.points):
              pname = st.text_input("Name", key="mp_name", value="rear-wing-upper-mount")
              powner = st.selectbox("Owned by", _SUBS,
                                    index=_SUBS.index("aerodynamics"), key="mp_owner")
              pmounts = st.selectbox("Mounts onto", _SUBS,
                                     index=_SUBS.index("chassis"), key="mp_mounts")
              pc = st.columns(3)
              pxyz = (unum(pc[0], "x (mm)", -10000.0, 10000.0, 1350.0, "mm", key="mp_x"),
                      unum(pc[1], "y (mm)", -10000.0, 10000.0, 120.0, "mm", key="mp_y"),
                      unum(pc[2], "z (mm)", -10000.0, 10000.0, 900.0, "mm", key="mp_z"))
              pclr = unum(st, "Required clearance (mm)", 0.0, 100.0, 8.0, "mm",
                          key="mp_clr")
              pest = st.checkbox("Estimated geometry", value=False, key="mp_est")
              if st.button("Save mount point", key="mp_save"):
                  store.set_mount_point(MountPoint(pname, xyz_mm=pxyz,
                                                   owner_subsystem=powner,
                                                   mounts_on=pmounts,
                                                   min_clearance_mm=pclr,
                                                   is_estimate=pest))
                  store.save()
                  st.rerun()
          for name, mp in list(geom.points.items()):
              est = " · est" if mp.is_estimate else ""
              pc = st.columns([5, 1])
              pc[0].markdown(
                  f'<div style="border-left:3px solid var(--line);padding:4px 10px;margin:3px 0;">'
                  f'{_MP_EMOJI.get(mp.owner_subsystem,"")} <b>{name}</b> '
                  f'<span style="color:#8d99a6;font-size:.8rem">{mp.owner_subsystem} '
                  f'→ {mp.mounts_on}{est}</span><br>'
                  f'<span style="font-size:.82rem;color:#8d99a6">'
                  f'{tuple(round(units_mod.from_metric(v,"mm")) for v in mp.xyz_mm)} {units_mod.label("mm")} · clr {units_mod.from_metric(mp.min_clearance_mm,"mm"):.0f}</span></div>',
                  unsafe_allow_html=True)
              if pc[1].button("✕", key=f"mp_del_{name}"):
                  store.remove_mount_point(name); store.save(); st.rerun()

    # ---- the live "drag a point" propagation ---- #
    if geom.points:
        with st.expander("⚙️ Move a mount point", expanded=False):
          led = interfaces_mod.IntegrationLedger.from_dict(st.session_state.ledger)
          mc = st.columns([2, 3, 1])
          which = mc[0].selectbox("Point", list(geom.points), key="mv_which")
          cur = geom.points[which].xyz_mm
          nx = mc[1].columns(3)
          new_xyz = (nx[0].number_input("→ x", value=float(cur[0]), key="mv_x"),
                     nx[1].number_input("→ y", value=float(cur[1]), key="mv_y"),
                     nx[2].number_input("→ z", value=float(cur[2]), key="mv_z"))
          also_cg = st.checkbox(
              "This point is the subsystem's mass location (shift its CG with the move)",
              value=False, key="mv_cg")
          if mc[2].button("Move →", key="mv_go"):
              res = propagate_mount_move(geom, led, which, new_xyz,
                                         set_by="integration-tab",
                                         update_interface_cg=also_cg)
              if also_cg:
                  publish_ledger(led.as_dict())
              store.save()
              st.session_state["_mp_last"] = res

          res = st.session_state.get("_mp_last")
          if res is not None and res.moved_point == which:
              # Surface the consequence of the move at the point of action: not just
              # "did THIS point clash" but what the move did to the WHOLE-CAR verdict,
              # so a subsystem dragging a mount sees instantly whether it just created
              # or cleared a build stop — without scrolling back to the banner.
              from suspension.interfaces import Severity as _Sev
              _post = geom.check_clashes()
              _has_interf = any(f.check == "clash-interference" for f in _post)
              _has_clear = any(f.check == "clash-clearance" for f in _post)
              if _has_interf:
                  _vtxt, _vcls = "DO NOT MANUFACTURE — interference", "bad"
              elif _has_clear:
                  _vtxt, _vcls = "BUILD WITH OPEN ITEMS — thin clearance", "warn"
              else:
                  _vtxt, _vcls = "CLEAR TO MANUFACTURE", "good"
              st.markdown(
                  f'<p class="hint">{res.summary()}</p>'
                  f'<div style="border-left:3px solid var(--line);padding:6px 12px;margin:4px 0;">'
                  f'<span class="tag {_vcls}">{_vtxt}</span> '
                  f'<span style="font-size:.86rem;color:#8d99a6">after this move '
                  f'(whole-car verdict — see the readiness board up top for the full '
                  f'open-items list)</span></div>',
                  unsafe_allow_html=True)

    # ---- the clash board (same render idiom as the ledger findings) ---- #
    with st.expander("⚙️ Clash board", expanded=False):
      findings = geom.check_clashes()
      # check_clashes() returns an empty list ONLY when there are no mount points at
      # all (a fresh project). Without this guard the board would render as a bare
      # header with nothing beneath it — indistinguishable from a broken tab. Show an
      # explicit empty state so the board always "appears".
      if not findings:
          if not geom.points and not geom.keepouts:
              _msg = ("No mount points or keep-out volumes declared yet. Add at least "
                      "one mount point and one keep-out above (the defaults in the "
                      "forms are a ready-to-save starting pair), then the clash board "
                      "checks every point against every keep-out it must clear.")
          elif not geom.points:
              _msg = ("Keep-out volumes are declared but no mount points exist to check "
                      "against them yet — add a mount point above.")
          else:
              _msg = ("No clashes to report.")
          st.markdown(
              f'<div style="border-left:3px solid var(--line);padding:6px 12px;margin:4px 0;">'
              f'<span class="tag">EMPTY</span> '
              f'<span style="font-size:.92rem;color:#8d99a6">{_msg}</span></div>',
              unsafe_allow_html=True)
      _SEV_CLS = {"fail": "bad", "warning": "warn", "missing": "warn",
                  "info": "", "ok": "good"}
      order = ["fail", "warning", "missing", "info", "ok"]
      for f in sorted(findings, key=lambda x: order.index(x.severity.value)):
          cls = _SEV_CLS.get(f.severity.value, "")
          who = " ↔ ".join(f"{_MP_EMOJI.get(x,'')}{x}" for x in f.subsystems) if f.subsystems else ""
          st.markdown(
              f'<div style="border-left:3px solid var(--line);padding:6px 12px;margin:4px 0;">'
              f'<span class="tag {cls}">{f.severity.value.upper()}</span> '
              f'<b>{f.check}</b> &nbsp;<span style="color:#8d99a6;font-size:.8rem">{who}</span><br>'
              f'<span style="font-size:.92rem">{f.message}</span></div>',
              unsafe_allow_html=True)


def render_pcb_board():
    """
    The electronics layer, live: size copper traces and route the CAN differential
    pair, then run the pre-fab gate — does the worst simultaneous load (brake light
    + both cooling fans at once) melt a trace, overheat it, or brown out the ECU,
    and does the CAN pair run too close to the HV motor-controller net? Traces,
    pairs and aggressors persist with the project, and the worst-case currents are
    rolled up from the integration ledger's declared peak currents — the same
    single source of truth the LV/HV check uses.
    """
    from suspension.electronics import Trace, DiffPair, Aggressor

    _MP_EMOJI = {"aerodynamics": "💛", "brakes": "🧡", "chassis": "💜", "cooling": "🩵",
                 "data-acquisition": "💚", "electrics": "💙", "powertrain": "❤️",
                 "suspension": "🩷", "ecu": "🖥️"}
    _SUBS = ["aerodynamics", "brakes", "chassis", "cooling",
             "data-acquisition", "electrics", "powertrain", "suspension"]
    # Only subsystems that can actually put an electrical load on a board trace
    # belong in the "Loads on <trace>" picker. Aero/chassis/suspension draw no
    # board current, so offering them just invites a nonsensical scenario.
    _LOAD_SUBS = ["brakes", "cooling", "data-acquisition", "electrics", "powertrain"]

    st.markdown(
        '<p class="hint">This is the check an electrical member runs the afternoon '
        'before sending a board to fab: under the worst <b>simultaneous load</b> '
        '(brake light + both cooling fans firing at once), do the thin copper '
        'traces <b>physically melt</b> (Onderdonk fusing), overheat past the board '
        'derate ceiling (IPC-2221), or drop enough voltage to push the rail below '
        'the <b>ECU brown-out</b> threshold and reset the car? And does a CAN '
        '<b>differential pair</b> route close enough to the switching '
        '<b>HV motor-controller</b> net to pick up its noise? It is an '
        '<i>analytic</i> screening check on declared traces and routes — not a PCB '
        'CAD kernel and not a field solver — so the impedance and coupling numbers '
        'are labelled estimates, and the true eye/reflection that need a field '
        'solver are reported as <i>not computed</i> rather than invented.</p>',
        unsafe_allow_html=True)

    store = get_store()
    board = store._ensure_board()
    led = interfaces_mod.IntegrationLedger.from_dict(st.session_state.ledger)

    # ---- board-level brown-out / thermal context ---- #
    with st.expander("⚙️ Board context (rail + ambient the checks run against)", expanded=False):
      bc = st.columns(5)
      board.rail_nominal_v = bc[0].number_input("ECU rail (V)", 1.0, 60.0,
                                                value=float(board.rail_nominal_v), key="pcb_rail")
      board.ecu_brownout_v = bc[1].number_input("Brown-out (V)", 0.5, 60.0,
                                                value=float(board.ecu_brownout_v), key="pcb_bo")
      board.ambient_c = bc[2].number_input("Ambient", -20.0, 150.0,
                                           value=float(board.ambient_c), key="pcb_amb")
      board.max_trace_temp_c = bc[3].number_input("Trace ceiling", 50.0, 200.0,
                                                 value=float(board.max_trace_temp_c), key="pcb_ceil")
      board.fuse_safety_factor = bc[4].number_input("Fuse safety ×", 1.0, 10.0,
                                                   value=float(board.fuse_safety_factor), key="pcb_sf")

      # ---- editors: traces, pairs, aggressors ---- #
      ec = st.columns(3)
      with ec[0]:
          st.markdown("###### Copper traces (power / signal nets you size)")
          with st.expander("Add / replace a trace", expanded=not board.traces):
              tn = st.text_input("Name", key="tr_name", value="main_feed")
              tnet = st.text_input("Net", key="tr_net", value="lv_rail")
              town = st.selectbox("Owned by", _SUBS, index=_SUBS.index("electrics"), key="tr_own")
              tfeed = st.text_input("Feeds", key="tr_feed", value="ecu")
              tg = st.columns(3)
              tw = tg[0].number_input("Width", 0.05, 50.0, value=0.30, key="tr_w")
              toz = tg[1].number_input("Copper (oz)", 0.25, 6.0, value=1.0, key="tr_oz")
              tl = tg[2].number_input("Length", 1.0, 2000.0, value=100.0, key="tr_l")
              text = st.checkbox("Outer layer (external)", value=True, key="tr_ext")
              test = st.checkbox("Estimated geometry", value=False, key="tr_est")
              if st.button("Save trace", key="tr_save"):
                  store.set_trace(Trace(name=tn, net=tnet, owner_subsystem=town,
                                        feeds=tfeed, width_mm=tw, copper_oz=toz,
                                        length_mm=tl, is_external=text, is_estimate=test))
                  save_store(store); st.rerun()
          for name, tr in list(board.traces.items()):
              est = " · est" if tr.is_estimate else ""
              row = st.columns([5, 1])
              row[0].markdown(
                  f'<div style="border-left:3px solid var(--line);padding:4px 10px;margin:3px 0;">'
                  f'{_MP_EMOJI.get(tr.owner_subsystem,"")} <b>{name}</b> '
                  f'<span style="color:#8d99a6;font-size:.8rem">{tr.owner_subsystem} → {tr.feeds}{est}</span><br>'
                  f'<span style="font-size:.82rem;color:#8d99a6">'
                  f'{units_mod.from_metric(tr.width_mm,"mm"):.2f} {units_mod.label("mm")} · {tr.copper_oz:.0f} oz · {units_mod.from_metric(tr.length_mm,"mm"):.0f} {units_mod.label("mm")} · '
                  f'fuses @ {tr.fusing_current_a(ambient_c=board.ambient_c):.1f} A</span></div>',
                  unsafe_allow_html=True)
              if row[1].button("✕", key=f"tr_del_{name}"):
                  store.remove_trace(name); save_store(store); st.rerun()

      with ec[1]:
          st.markdown("###### Differential pairs (CAN H/L routes)")
          with st.expander("Add / replace a pair", expanded=not board.pairs):
              pn = st.text_input("Name", key="dp_name", value="CAN")
              pown = st.selectbox("Owned by", _SUBS, index=_SUBS.index("electrics"), key="dp_own")
              pg = st.columns(3)
              pw = pg[0].number_input("Trace w", 0.05, 5.0, value=0.20, key="dp_w")
              psp = pg[1].number_input("Spacing", 0.05, 5.0, value=0.20, key="dp_s")
              ph = pg[2].number_input("Dielectric h", 0.05, 5.0, value=0.20, key="dp_h")
              pg2 = st.columns(2)
              peps = pg2[0].number_input("eps_r", 1.0, 15.0, value=4.3, key="dp_eps")
              ptz = pg2[1].number_input("Target Zdiff (Ω)", 20.0, 200.0, value=120.0, key="dp_tz")
              ppath = st.text_input("Route (x,y; x,y; …)", key="dp_path", value="0,0; 60,0")
              pest = st.checkbox("Estimated routing", value=False, key="dp_est")
              if st.button("Save pair", key="dp_save"):
                  pts = _parse_path(ppath)
                  store.set_pair(DiffPair(name=pn, owner_subsystem=pown, trace_w_mm=pw,
                                          spacing_mm=psp, height_mm=ph, eps_r=peps,
                                          target_z0_ohm=ptz, path_mm=pts, is_estimate=pest))
                  save_store(store); st.rerun()
          for name, dp in list(board.pairs.items()):
              est = " · est" if dp.is_estimate else ""
              z = dp.differential_z0_ohm()
              row = st.columns([5, 1])
              row[0].markdown(
                  f'<div style="border-left:3px solid var(--line);padding:4px 10px;margin:3px 0;">'
                  f'{_MP_EMOJI.get(dp.owner_subsystem,"")} <b>{name}</b> '
                  f'<span style="color:#8d99a6;font-size:.8rem">{dp.owner_subsystem}{est}</span><br>'
                  f'<span style="font-size:.82rem;color:#8d99a6">'
                  f'~{z:.0f} Ω diff (est) · target {dp.target_z0_ohm:.0f} Ω · {len(dp.path_mm)} pts</span></div>',
                  unsafe_allow_html=True)
              if row[1].button("✕", key=f"dp_del_{name}"):
                  store.remove_pair(name); save_store(store); st.rerun()

      with ec[2]:
          st.markdown("###### Aggressor nets (noisy HV traces to avoid)")
          with st.expander("Add / replace an aggressor", expanded=not board.aggressors):
              an = st.text_input("Name", key="ag_name", value="INV")
              anet = st.text_input("Net", key="ag_net", value="hv_inverter")
              aown = st.selectbox("Owned by", _SUBS, index=_SUBS.index("powertrain"), key="ag_own")
              ag2 = st.columns(2)
              asw = ag2[0].number_input("Switched V", 1.0, 1000.0, value=400.0, key="ag_v")
              aedge = ag2[1].number_input("Edge (V/ns)", 0.1, 100.0, value=5.0, key="ag_e")
              apath = st.text_input("Route (x,y; x,y; …)", key="ag_path", value="0,0.3; 60,0.3")
              aest = st.checkbox("Estimated routing", value=False, key="ag_est")
              if st.button("Save aggressor", key="ag_save"):
                  pts = _parse_path(apath)
                  store.set_aggressor(Aggressor(name=an, net=anet, owner_subsystem=aown,
                                                sw_voltage_v=asw, edge_v_per_ns=aedge,
                                                path_mm=pts, is_estimate=aest))
                  save_store(store); st.rerun()
          for name, ag in list(board.aggressors.items()):
              est = " · est" if ag.is_estimate else ""
              row = st.columns([5, 1])
              row[0].markdown(
                  f'<div style="border-left:3px solid var(--line);padding:4px 10px;margin:3px 0;">'
                  f'{_MP_EMOJI.get(ag.owner_subsystem,"")} <b>{name}</b> '
                  f'<span style="color:#8d99a6;font-size:.8rem">{ag.owner_subsystem} · {ag.net}{est}</span><br>'
                  f'<span style="font-size:.82rem;color:#8d99a6">'
                  f'{ag.sw_voltage_v:.0f} V · {ag.edge_v_per_ns:.0f} V/ns · {len(ag.path_mm)} pts</span></div>',
                  unsafe_allow_html=True)
              if row[1].button("✕", key=f"ag_del_{name}"):
                  store.remove_aggressor(name); save_store(store); st.rerun()

    # ---- the simultaneous-load scenario ---- #
    with st.expander("⚙️ Worst-case simultaneous load", expanded=False):
      st.markdown(
          '<p class="hint">Each trace can carry several loads at once. Pick the '
          'subsystems whose peak currents sum onto it (e.g. cooling + cooling + '
          'brakes = both fans and the brake light). The per-load amps come from the '
          '<b>integration ledger</b> (each subsystem\'s declared peak current), not '
          'retyped here — so this can\'t drift from what TEAM FIT says.</p>',
          unsafe_allow_html=True)
      scenario = {}
      if board.traces:
          for name, tr in board.traces.items():
              # If a previous session stored a selection that's no longer an allowed
              # load (e.g. aerodynamics, before we restricted the picker to
              # current-drawing subsystems), drop it from session state first —
              # Streamlit errors if a persisted value isn't among the options.
              _skey = f"pcb_scn_{name}"
              if _skey in st.session_state:
                  st.session_state[_skey] = [
                      s for s in st.session_state[_skey] if s in _LOAD_SUBS]
              # NB: pass `key` only — Streamlit persists the selection in
              # st.session_state[key] across reruns. Passing `default=` alongside a
              # `key` that already exists makes Streamlit ignore the default and, on
              # rerun, silently reset the selection to [], so the scenario went empty
              # and every trace reported "no declared worst-case current".
              picks = st.multiselect(
                  f"Loads on '{name}'", _LOAD_SUBS,
                  key=_skey,
                  help="Choose the same subsystem twice (e.g. two fans) by it appearing once "
                       "per declared load — duplicates are summed.")
              if picks:
                  scenario[name] = picks
      else:
          st.caption("Add at least one trace to define a load scenario.")

    # ---- the pre-fab gate ---- #
    with st.expander("⚙️ Pre-fab board check", expanded=False):
      res = store.board_check(ledger=led, scenario=scenario)
      if res.findings:
          st.markdown(f'<p class="hint">{res.summary()}</p>', unsafe_allow_html=True)
      else:
          st.caption("Nothing to check yet — declare traces/pairs and a load scenario above.")

      _SEV_CLS = {"fail": "bad", "warning": "warn", "missing": "warn",
                  "info": "", "ok": "good"}
      order = ["fail", "warning", "missing", "info", "ok"]
      for f in sorted(res.findings, key=lambda x: order.index(x.severity.value)):
          cls = _SEV_CLS.get(f.severity.value, "")
          who = " ↔ ".join(f"{_MP_EMOJI.get(x,'')}{x}" for x in f.subsystems) if f.subsystems else ""
          st.markdown(
              f'<div style="border-left:3px solid var(--line);padding:6px 12px;margin:4px 0;">'
              f'<span class="tag {cls}">{f.severity.value.upper()}</span> '
              f'<b>{f.check}</b> &nbsp;<span style="color:#8d99a6;font-size:.8rem">{who}</span><br>'
              f'<span style="font-size:.92rem">{f.message}</span></div>',
              unsafe_allow_html=True)

      # ---- honest SI detail: what's analytic vs what needs a field solver ---- #
      if board.pairs:
          st.markdown("###### Signal-integrity detail (analytic vs field-solver)")
          which = st.selectbox("Pair", list(board.pairs), key="pcb_si_which")
          d = board.si_detail(which)
          sc = st.columns(2)
          sc[0].markdown(
              f"**Computed (analytic, IPC-2141 + edge coupling)**\n\n"
              f"- single-ended Z₀: {d['single_ended_z0_ohm']:.1f} Ω\n"
              f"- differential Z₀: {d['differential_z0_ohm']:.1f} Ω")
          sc[1].markdown(
              "**Not computed — needs a field solver / SPICE**\n\n"
              "- eye height: *not computed*\n"
              "- insertion loss: *not computed*\n"
              "- reflection coeff: *not computed*\n"
              "- coupled noise voltage: *not computed*")
          st.caption(d["note"])


def render_pcb_doctor():
    """
    PCB Doctor — drop the *real* .kicad_pcb in, get the real-life failure list
    (with the guilty component named and the numeric fix attached), then let it
    re-trace the under-sized copper in place and hand back a patched board file
    that reopens in KiCad with the routing intact. Also carries the multi-layer
    Trace Prescriber for boards that don't exist yet.
    """
    from suspension import pcb_doctor as pdr_mod

    st.markdown("---")
    st.markdown("### 🩺 PCB Doctor — import the real board, fix the traces on it")
    st.markdown(
        '<p class="hint">The panel above checks the traces you <i>declare</i>. '
        'This one checks the board you already <i>routed</i>: drop the '
        '<b>.kicad_pcb</b> straight in and the Doctor reads every copper '
        'segment, via, footprint and pour, assigns each net its current from '
        'the <b>integration ledger</b> (every guess labelled and editable), and '
        'runs the physics DRC never sees — IPC-2221 heating at the bottleneck '
        'segment, Onderdonk fusing, the <b>via that chokes a wide trace</b>, '
        'true IR-drop → ECU brown-out by <b>nodal analysis of the actual routed '
        'copper mesh</b>, copper opens the rats-nest missed, IPC-2221 B4 '
        '<b>HV clearance</b>, differential-pair skew, HV nets coupling into '
        'signal pairs, and <b>component-level derating</b> (the electrolytic on '
        'hot copper, the fuse rated under its own net). Every finding says why '
        'the board fails <i>on the car</i> even though it simulated fine, names '
        'the component, and carries the exact numeric fix — then one click '
        '<b>re-traces the existing board</b>: only the under-sized '
        '<code>(width …)</code> tokens are rewritten, byte-for-byte otherwise, '
        'so the patched file reopens in KiCad with everything intact. Analytic '
        'screening on the file you drop in — not a field solver, not a DRC '
        'replacement; anything needing one is reported as <i>not computed</i>, '
        'never invented.</p>',
        unsafe_allow_html=True)

    store = get_store()
    board_ctx = store._ensure_board()
    led = interfaces_mod.IntegrationLedger.from_dict(st.session_state.ledger)

    # ---------------- load: drag a file or one-click demo -------------------- #
    lc = st.columns([3, 1])
    up = lc[0].file_uploader("Drop a KiCad board file (.kicad_pcb)",
                             type=["kicad_pcb"], key="pdr_up",
                             help="KiCad 5–9. The file is only read in this "
                                  "session; nothing is uploaded anywhere.")
    if lc[1].button("Load demo board", key="pdr_demo",
                    help="A small ECU board with three planted real-life "
                         "failures — see the whole loop in one click."):
        st.session_state["pdr_text"] = pdr_mod.demo_kicad_pcb()
        st.session_state["pdr_name"] = "demo_ecu_board.kicad_pcb"
        st.session_state.pop("pdr_assign", None)
    if up is not None:
        raw_bytes = up.getvalue()
        # Guard before decode/parse so one giant upload can't spike RAM for
        # everyone. Checked on bytes, i.e. what actually arrived off the wire.
        if len(raw_bytes) > _PCB_MAX_BYTES:
            st.error(
                f"That file is {len(raw_bytes) / 1e6:.1f} MB — over the "
                f"{_PCB_MAX_BYTES // (1024 * 1024)} MB Doctor limit. Real FSAE "
                "boards are well under this; if yours is genuinely this large, "
                "export just the copper layers or split the board.")
        else:
            raw = raw_bytes.decode("utf-8", errors="replace")
            if raw != st.session_state.get("pdr_text"):
                st.session_state["pdr_text"] = raw
                st.session_state["pdr_name"] = up.name
                st.session_state.pop("pdr_assign", None)

    text = st.session_state.get("pdr_text")
    if not text:
        # the Prescriber works with no board at all — never gate it on a file
        _render_trace_prescriber(pdr_mod, board_ctx)
        return

    # ---------------- parse (process-wide cache, keyed on the text) ---------- #
    # Shared across sessions: the same board opened by several people is parsed
    # once. The cache copies its return, so the board this session then patches
    # in "Re-trace" is its own object, never the shared cached instance.
    try:
        pboard = _cached_parse_kicad(text)
    except ValueError as err:
        st.error(f"Couldn't read that as a KiCad board: {err}")
        return

    st.caption(
        f"**{st.session_state.get('pdr_name','board')}** — "
        f"{len(pboard.segments)} trace segments · {len(pboard.vias)} vias · "
        f"{len(pboard.footprints)} components · "
        f"{len(pboard.routed_net_ids())} routed nets · "
        f"{len(pboard.copper_layers)} copper layers "
        f"({', '.join(pboard.copper_layers)}) · "
        f"{pboard.board_thickness_mm:g} mm thick")

    # ---------------- per-net current/voltage assignments --------------------- #
    if "pdr_assign" not in st.session_state:
        st.session_state["pdr_assign"] = pdr_mod.auto_assign_net_currents(
            pboard, ledger=led)
    assign = st.session_state["pdr_assign"]

    with st.expander("⚡ Net currents & voltages (auto-filled from the ledger — "
                     "the whole diagnosis runs on these)", expanded=False):
        st.markdown(
            '<p class="hint">Name-matched nets take the owning subsystem\'s '
            '<b>declared peak current</b> from the integration ledger; signal '
            'nets default to 50 mA, everything else to 1 A — every guess says '
            'so in <i>source</i>. Edit any number: the diagnosis, the fixes and '
            'the patched file all follow it.</p>', unsafe_allow_html=True)
        import pandas as _pd
        nids = sorted(assign)
        df = _pd.DataFrame([{"net": assign[n]["net"],
                             "current_a": float(assign[n]["current_a"]),
                             "voltage_v": float(assign[n]["voltage_v"]),
                             "source": assign[n]["source"]} for n in nids])
        edited = st.data_editor(
            df, key="pdr_assign_ed", hide_index=True, width='stretch',
            disabled=["net", "source"],
            column_config={
                "current_a": st.column_config.NumberColumn(
                    "current (A)", min_value=0.0, max_value=500.0, step=0.1),
                "voltage_v": st.column_config.NumberColumn(
                    "voltage (V)", min_value=0.0, max_value=1000.0, step=1.0)})
        for i, n in enumerate(nids):
            try:
                assign[n]["current_a"] = float(edited.iloc[i]["current_a"])
                assign[n]["voltage_v"] = float(edited.iloc[i]["voltage_v"])
            except (KeyError, ValueError, IndexError):
                pass

    # ---------------- the diagnosis (runs live, no button) --------------------- #
    copper_oz = st.number_input(
        "Finished copper weight (oz)", 0.25, 6.0,
        value=float(st.session_state.get("pdr_oz", 1.0)), step=0.25, key="pdr_oz",
        help="From your fab's stackup. The rail, brown-out, ambient, ceiling and "
             "fuse-safety numbers come from ⚙️ Board context above — one source "
             "of truth for both panels.")
    pboard.copper_oz = float(copper_oz)
    with st.spinner("Diagnosing the routed copper…"):
        rep = pdr_mod.diagnose(
            pboard, assign,
            rail_v=float(board_ctx.rail_nominal_v),
            brownout_v=float(board_ctx.ecu_brownout_v),
            ambient_c=float(board_ctx.ambient_c),
            max_temp_c=float(board_ctx.max_trace_temp_c),
            fuse_sf=float(board_ctx.fuse_safety_factor))

    counts = rep.counts()
    st.markdown(f'<p class="hint"><b>{rep.summary()}</b></p>',
                unsafe_allow_html=True)

    _SEV_CLS = {"fail": "bad", "warning": "warn", "missing": "warn",
                "info": "", "ok": "good"}
    order = ["fail", "warning", "missing", "info", "ok"]
    with st.expander(
            f"🩺 Diagnosis — {counts['fail']} FAIL · {counts['warning']} WARN "
            f"({len(rep.findings)} findings)", expanded=counts["fail"] > 0):
        for f in sorted(rep.findings, key=lambda x: order.index(x.severity.value)):
            cls = _SEV_CLS.get(f.severity.value, "")
            st.markdown(
                f'<div style="border-left:3px solid var(--line);'
                f'padding:6px 12px;margin:4px 0;">'
                f'<span class="tag {cls}">{f.severity.value.upper()}</span> '
                f'<b>{f.check}</b><br>'
                f'<span style="font-size:.92rem">{f.message}</span></div>',
                unsafe_allow_html=True)

    # ---------------- board viewer — failing copper glows red ------------------ #
    with st.expander("🗺️ Board viewer (copper by layer — segments the fix will "
                     "widen glow red)", expanded=False):
        show = st.multiselect("Layers", pboard.copper_layers,
                              default=pboard.copper_layers, key="pdr_layers")
        st.markdown(pdr_mod.board_svg(pboard, report=rep,
                                      show_layers=show or None),
                    unsafe_allow_html=True)

    # ---------------- re-trace the existing board ------------------------------ #
    auto_n = sum(1 for fx in rep.fixes if fx.auto)
    manual_n = len(rep.fixes) - auto_n
    with st.expander(f"🔧 Re-trace this board — {auto_n} width fix(es) ready, "
                     f"{manual_n} prescription(s) need a human", expanded=auto_n > 0):
        if rep.fixes:
            for fx in rep.fixes:
                tag = ("<span class='tag good'>AUTO</span>" if fx.auto
                       else "<span class='tag warn'>MANUAL</span>")
                note = f" — {fx.note}" if fx.note else ""
                st.markdown(
                    f'<div style="border-left:3px solid var(--line);'
                    f'padding:4px 10px;margin:3px 0;font-size:.9rem">{tag} '
                    f'<b>{fx.net}</b> ({fx.layer}) '
                    f'{fx.old_width_mm:g} → <b>{fx.new_width_mm:g} mm</b>'
                    f'{note}</div>', unsafe_allow_html=True)
        else:
            st.caption("No under-sized copper at the assigned currents — "
                       "nothing to rewrite.")
        if auto_n:
            patched, applied = pdr_mod.apply_fixes(pboard, rep.fixes)
            try:
                board2 = pdr_mod.parse_kicad_pcb(patched)
                board2.copper_oz = pboard.copper_oz
                rep2 = pdr_mod.diagnose(
                    board2, assign,
                    rail_v=float(board_ctx.rail_nominal_v),
                    brownout_v=float(board_ctx.ecu_brownout_v),
                    ambient_c=float(board_ctx.ambient_c),
                    max_temp_c=float(board_ctx.max_trace_temp_c),
                    fuse_sf=float(board_ctx.fuse_safety_factor))
                c2 = rep2.counts()
                st.markdown(
                    f'<p class="hint">Patched board re-diagnosed: '
                    f'<b>{counts["fail"]} → {c2["fail"]} FAIL</b>, '
                    f'{counts["warning"]} → {c2["warning"]} WARN. Only the '
                    f'width tokens changed — nets, routing and everything else '
                    f'are byte-identical. Re-run KiCad DRC on it: a widened '
                    f'trace can newly crowd an LV neighbour.</p>',
                    unsafe_allow_html=True)
            except ValueError:
                st.warning("Patched file failed to re-parse — not offered for "
                           "download. Please report this board.")
                patched = None
            if patched:
                base = (st.session_state.get("pdr_name", "board.kicad_pcb")
                        .replace(".kicad_pcb", ""))
                dl = st.columns(2)
                dl[0].download_button(
                    f"⬇ Patched board ({auto_n} traces re-sized)",
                    data=patched, file_name=f"{base}_doctored.kicad_pcb",
                    mime="text/plain", key="pdr_dl_board")
                dl[1].download_button(
                    "⬇ Fix report (hand-off .md)",
                    data=pdr_mod.fix_report_md(pboard, rep, applied, assign),
                    file_name=f"{base}_fix_report.md",
                    mime="text/markdown", key="pdr_dl_report")
        elif rep.fixes:
            st.download_button(
                "⬇ Prescription report (.md)",
                data=pdr_mod.fix_report_md(pboard, rep, [], assign),
                file_name="pcb_doctor_prescriptions.md",
                mime="text/markdown", key="pdr_dl_rx")

    _render_trace_prescriber(pdr_mod, board_ctx)


def _render_trace_prescriber(pdr_mod, board_ctx):
    """The multi-layer routing answer sheet: how wide, on which layer, at what
    copper weight, and how many vias per layer change — for one current."""
    with st.expander("📏 Trace Prescriber — \"how wide, which layer, how many "
                     "vias?\" (no board file needed)", expanded=False):
        st.markdown(
            '<p class="hint">The three questions that actually confuse people '
            'routing a multi-layer board, answered as one table: the minimum '
            'IPC-2221 width for your current at each copper weight, <b>outer vs '
            'inner</b> (buried copper cools ~half as well, so inner layers need '
            'roughly twice the width), and how many vias every layer change '
            'needs so the barrel — not the trace — doesn\'t become the '
            'fuse.</p>', unsafe_allow_html=True)
        pc = st.columns(4)
        cur = pc[0].number_input("Current (A)", 0.05, 500.0, value=8.0,
                                 step=0.5, key="pdr_rx_i")
        dT = pc[1].number_input("Allowed rise (°C)", 5.0, 100.0, value=20.0,
                                step=5.0, key="pdr_rx_dt",
                                help="10 °C is conservative, 20 °C typical, "
                                     "45 °C aggressive (hot underhood board).")
        ln = pc[2].number_input("Run length (mm)", 5.0, 2000.0, value=120.0,
                                step=5.0, key="pdr_rx_len")
        drill = pc[3].number_input("Via drill (mm)", 0.15, 1.2, value=0.3,
                                   step=0.05, key="pdr_rx_drill")
        p = pdr_mod.prescribe_trace(
            cur, dT_c=dT, length_mm=ln,
            rail_v=float(board_ctx.rail_nominal_v), via_drill_mm=drill)
        rows = "".join(
            f"<tr><td>{r['copper_oz']:g} oz</td><td>{r['layer_class']}</td>"
            f"<td><b>{r['width_mm']:.2f} mm</b></td>"
            f"<td>{r['ir_drop_v']*1000:.0f} mV</td>"
            f"<td>{r['dissipation_w']:.2f} W</td></tr>"
            for r in p["rows"])
        st.markdown(
            f'<table style="width:100%;font-size:.9rem"><tr>'
            f'<th align="left">copper</th><th align="left">layer</th>'
            f'<th align="left">min width</th>'
            f'<th align="left">IR drop @ {ln:g} mm</th>'
            f'<th align="left">heat</th></tr>{rows}</table>',
            unsafe_allow_html=True)
        st.markdown(f'<p class="hint">🔩 <b>Layer changes:</b> {p["via_note"]}. '
                    f'The IR-drop column is the copper alone — connectors and '
                    f'harness add their own on top of the '
                    f'{board_ctx.rail_nominal_v:g} V rail\'s '
                    f'{board_ctx.rail_nominal_v - board_ctx.ecu_brownout_v:.2g} V '
                    f'brown-out margin.</p>', unsafe_allow_html=True)


def _parse_path3d(s: str):
    """Parse 'x,y,z; x,y,z; …' into a list of (x,y,z) float tuples. Tolerant of
    stray whitespace, trailing separators, and 2-D points (z defaults to 0)."""
    pts = []
    for chunk in str(s).replace("\n", ";").split(";"):
        chunk = chunk.strip()
        if not chunk:
            continue
        parts = chunk.replace(",", " ").split()
        if len(parts) >= 2:
            try:
                x = float(parts[0]); y = float(parts[1])
                z = float(parts[2]) if len(parts) >= 3 else 0.0
                pts.append((x, y, z))
            except ValueError:
                continue
    return pts


# ---- harness UI: colours, caching, 3-D view, formboard, editors ---------- #
_HN_SEV_COLOR = {"fail": "#e05252", "warning": "#d9a441", "missing": "#8d99a6",
                 "ok": "#5cb85c"}
_HN_SUB_COLOR = {"aerodynamics": "#d9a441", "brakes": "#e1683c",
                 "chassis": "#b18ad6", "cooling": "#48b8b8",
                 "data-acquisition": "#5cb85c", "electrics": "#4aa3df",
                 "powertrain": "#e05252", "suspension": "#d76a8a",
                 "ecu": "#8d99a6"}


def _harness_check_cached(store):
    """Run store.harness_check() only when the harness or the keep-outs actually
    changed. The check itself is cheap now (exact vectorised clearance), but on
    a Streamlit rerun *nothing* should be recomputed for free — this makes every
    slider drag / text keystroke in the section cost ~zero."""
    import hashlib
    harness = store._ensure_harness()
    geom = getattr(store, "geometry", None)
    keepouts = list(getattr(geom, "keepouts", {}).values()) if geom else []
    payload = json.dumps(
        [harness.as_dict(),
         [(k.name, getattr(k, "owner_subsystem", ""),
           list(k.lo_mm), list(k.hi_mm)) for k in keepouts]],
        sort_keys=True, default=str)
    h = hashlib.md5(payload.encode()).hexdigest()
    cached = st.session_state.get("_hn_check_cache")
    if cached is not None and cached[0] == h:
        return cached[1], keepouts
    res = store.harness_check()
    st.session_state["_hn_check_cache"] = (h, res)
    return res, keepouts


def _harness_wire_severity(res) -> dict:
    """wire name -> worst finding severity ('fail' | 'warning' | None)."""
    rank = {"fail": 2, "warning": 1}
    out: dict = {}
    for f in res.findings:
        wname = (f.detail or {}).get("wire")
        sev = f.severity.value
        if wname and sev in rank:
            if rank[sev] > rank.get(out.get(wname, ""), 0):
                out[wname] = sev
    return out


def _hn_box_mesh(lo, hi, color, name, opacity=0.18):
    """A keep-out AABB as a translucent plotly Mesh3d."""
    x = [lo[0], hi[0], hi[0], lo[0], lo[0], hi[0], hi[0], lo[0]]
    y = [lo[1], lo[1], hi[1], hi[1], lo[1], lo[1], hi[1], hi[1]]
    z = [lo[2], lo[2], lo[2], lo[2], hi[2], hi[2], hi[2], hi[2]]
    tris = [(0, 1, 2), (0, 2, 3), (4, 6, 5), (4, 7, 6),
            (0, 1, 5), (0, 5, 4), (1, 2, 6), (1, 6, 5),
            (2, 3, 7), (2, 7, 6), (3, 0, 4), (3, 4, 7)]
    i, j, k = zip(*tris)
    return go.Mesh3d(x=x, y=y, z=z, i=i, j=j, k=k, color=color,
                     opacity=opacity, name=name, hovertext=name,
                     hoverinfo="text", showlegend=False, flatshading=True)


def _harness_fig3d(harness, res, keepouts, *, color_by="status",
                   selected=None, show_keepouts=True, show_vertices=True,
                   show_labels=True, show_sag=False):
    """The loom, live in car coordinates: every routed conductor, every
    connector, every reserved keep-out volume, and a marker pinned on each
    violation exactly where it happens (tightest bend, deepest keep-out
    penetration, un-anchored endpoint)."""
    from suspension.harness import vertex_bend_radius_mm
    fig = go.Figure()
    wire_sev = _harness_wire_severity(res)

    # keep-outs, tinted red when some wire actually fouls them
    violated = {(f.detail or {}).get("keepout") for f in res.findings
                if f.check == "harness-clearance"
                and f.severity.value in ("fail", "warning")}
    if show_keepouts:
        for ko in keepouts:
            bad = ko.name in violated
            fig.add_trace(_hn_box_mesh(
                np.asarray(ko.lo_mm, float), np.asarray(ko.hi_mm, float),
                "#e05252" if bad else "#8d99a6",
                f"keep-out '{ko.name}' ({getattr(ko, 'owner_subsystem', '?')})",
                opacity=0.22 if bad else 0.12))

    # wires
    for w in sorted(harness.wires.values(), key=lambda x: x.name):
        path = w.as_polyline()
        if path.shape[0] < 2:
            continue
        sev = wire_sev.get(w.name)
        if color_by == "subsystem":
            col = _HN_SUB_COLOR.get(w.owner_subsystem, "#4aa3df")
        else:
            col = _HN_SEV_COLOR.get(sev, "#5cb85c" if not w.is_estimate
                                    else "#7d8c99")
        is_sel = (selected == w.name)
        hover = (f"<b>{w.name}</b> · AWG{w.gauge_awg} · {w.net or '—'}"
                 f"<br>{w.from_conn or '?'} → {w.to_conn or '?'}"
                 f"<br>cut {w.cut_length_mm():.0f} mm · "
                 f"min bend {w.min_bend_radius_mm:.0f} mm · "
                 f"{w.copper_mass_g():.1f} g Cu"
                 + (f"<br><b>{sev.upper()}</b>" if sev else "")
                 + (" · estimated route" if w.is_estimate else ""))
        fig.add_trace(go.Scatter3d(
            x=path[:, 0], y=path[:, 1], z=path[:, 2],
            mode="lines+markers" if show_vertices else "lines",
            line=dict(color=col,
                      width=float(np.clip(2.0 + w.outside_diameter_mm * 1.4,
                                          3.0, 11.0)) + (4.0 if is_sel else 0.0)),
            marker=dict(size=3.5 if is_sel else 2.5, color=col),
            name=w.name + (" ✏️" if is_sel else ""),
            hovertext=hover, hoverinfo="text",
            legendgroup=w.name))
        # supports: the clamp points holding the wire to the car
        sup = [i for i in (w.clamp_idx or []) if 0 < int(i) < path.shape[0] - 1]
        if sup:
            sp = path[[int(i) for i in sup]]
            fig.add_trace(go.Scatter3d(
                x=sp[:, 0], y=sp[:, 1], z=sp[:, 2], mode="markers",
                marker=dict(size=5, symbol="square", color="#e8edf2",
                            line=dict(color=col, width=2)),
                hovertext=[f"{w.name}: clamp / tie (support)"] * sp.shape[0],
                hoverinfo="text", showlegend=False, legendgroup=w.name))
        # draped shape: upper-bound sag at the declared vibration level
        if show_sag:
            from suspension.harness import sagged_polyline_mm
            drp = sagged_polyline_mm(
                w, vib_g=harness.vib_g,
                band_hz=(harness.excitation_lo_hz, harness.excitation_hi_hz))
            if drp is not None and drp.shape[0] >= 2:
                fig.add_trace(go.Scatter3d(
                    x=drp[:, 0], y=drp[:, 1], z=drp[:, 2], mode="lines",
                    line=dict(color=col, width=3, dash="dash"),
                    opacity=0.55,
                    hovertext=(f"{w.name}: drooped shape at "
                               f"{harness.vib_g:g} g (upper stiffness "
                               f"bound)"),
                    hoverinfo="text", showlegend=False, legendgroup=w.name))
        # tightest-bend markers where the route violates the wire's bend limit
        radii = vertex_bend_radius_mm(path)
        if radii.size:
            r_ok = w.min_bend_radius_mm
            for vi, r in enumerate(radii):
                if not np.isfinite(r) or r >= 1.5 * r_ok:
                    continue
                p = path[vi + 1]
                bad = r < r_ok
                fig.add_trace(go.Scatter3d(
                    x=[p[0]], y=[p[1]], z=[p[2]], mode="markers",
                    marker=dict(size=7, symbol="x",
                                color="#e05252" if bad else "#d9a441"),
                    hovertext=(f"{w.name}: formed radius {r:.0f} mm "
                               f"{'<' if bad else '≈'} min {r_ok:.0f} mm"),
                    hoverinfo="text", showlegend=False, legendgroup=w.name))

    # clearance / anchoring violation pins from the findings themselves
    for f in res.findings:
        d = f.detail or {}
        if f.check in ("harness-clearance", "harness-sag-clearance") \
                and d.get("at_mm") \
                and f.severity.value in ("fail", "warning"):
            p = d["at_mm"]
            fig.add_trace(go.Scatter3d(
                x=[p[0]], y=[p[1]], z=[p[2]], mode="markers",
                marker=dict(size=8, symbol="diamond-open",
                            color=_HN_SEV_COLOR[f.severity.value],
                            line=dict(width=3)),
                hovertext=f.message, hoverinfo="text", showlegend=False))
        elif f.check == "harness-anchor" and d.get("endpoint_mm"):
            p, c = d["endpoint_mm"], d.get("connector_mm")
            fig.add_trace(go.Scatter3d(
                x=[p[0]], y=[p[1]], z=[p[2]], mode="markers",
                marker=dict(size=7, symbol="circle-open", color="#d9a441",
                            line=dict(width=3)),
                hovertext=f.message, hoverinfo="text", showlegend=False))
            if c:
                fig.add_trace(go.Scatter3d(
                    x=[p[0], c[0]], y=[p[1], c[1]], z=[p[2], c[2]],
                    mode="lines", line=dict(color="#d9a441", width=2,
                                            dash="dot"),
                    hoverinfo="skip", showlegend=False))

    # connectors
    if harness.connectors:
        cs = sorted(harness.connectors.values(), key=lambda c: c.name)
        fig.add_trace(go.Scatter3d(
            x=[c.xyz_mm[0] for c in cs], y=[c.xyz_mm[1] for c in cs],
            z=[c.xyz_mm[2] for c in cs],
            mode="markers+text" if show_labels else "markers",
            text=[c.name for c in cs], textposition="top center",
            textfont=dict(size=11, color="#e8edf2"),
            marker=dict(size=6, symbol="diamond",
                        color=[_HN_SUB_COLOR.get(c.owner_subsystem, "#e8edf2")
                               for c in cs],
                        line=dict(color="#e8edf2", width=1)),
            hovertext=[f"<b>{c.name}</b> · {c.owner_subsystem}"
                       f"<br>{c.part_number or '—'} · {c.cavities} cav · "
                       f"SR {c.strain_relief_mm:.0f} mm" for c in cs],
            hoverinfo="text", name="connectors", showlegend=False))

    ax = dict(showbackground=False, gridcolor="#2a333c", zerolinecolor="#2a333c",
              color="#8d99a6")
    fig.update_layout(
        scene=dict(xaxis=dict(title="x mm (rearward)", **ax),
                   yaxis=dict(title="y mm (right)", **ax),
                   zaxis=dict(title="z mm (up)", **ax),
                   aspectmode="data",
                   camera=dict(eye=dict(x=1.6, y=-1.6, z=0.9))),
        paper_bgcolor="rgba(0,0,0,0)", plot_bgcolor="rgba(0,0,0,0)",
        margin=dict(l=0, r=0, t=10, b=0), height=540,
        legend=dict(font=dict(size=10), bgcolor="rgba(0,0,0,0)",
                    orientation="h", yanchor="bottom", y=1.0),
        uirevision="harness3d")   # keep the camera through fragment reruns
    return fig


def _formboard_svg(fb, wires=None, width_px: int = 860, height_px: int = 430,
                   true_scale: bool = False) -> str:
    """Render a Formboard as an SVG nail-board drawing.

    Screen mode fits the panel (proportions true). `true_scale=True` emits the
    SVG with physical mm dimensions so it PRINTS 1:1 — the fabricator tapes the
    sheets to the bench and pins the loom straight onto it. Corners that bend
    tighter than the conductor's minimum radius are ringed on the drawing at the
    exact nail position; dashed grey links tie the branches that terminate at an
    already-placed connector back to its single node."""
    ext_w, ext_h = fb.extent_mm
    ext_w = max(ext_w, 1.0)
    ext_h = max(ext_h, 1.0)
    if true_scale:
        pad = 30.0                       # mm of quiet border
        W, H = ext_w + 2 * pad, ext_h + 2 * pad
        head = (f'<svg xmlns="http://www.w3.org/2000/svg" width="{W:.1f}mm" '
                f'height="{H:.1f}mm" viewBox="0 0 {W:.1f} {H:.1f}" '
                f'style="background:#ffffff;">')
        s = 1.0
        ink, sub, bg_line = "#111820", "#5a6672", "#c9d2da"
        fs, lw = 4.0, 0.9
    else:
        pad = 30.0
        sx = (width_px - 2 * pad) / ext_w
        sy = (height_px - 2 * pad) / ext_h
        s = min(sx, sy)                  # uniform: proportions preserved
        W, H = width_px, height_px
        head = (f'<svg viewBox="0 0 {W} {H}" '
                f'style="width:100%;height:auto;background:#0e1419;'
                f'border:1px solid var(--line);border-radius:8px;">')
        ink, sub, bg_line = "#e8edf2", "#8d99a6", "#1a222b"
        fs, lw = 10.0, 2.4

    def tx(p):
        return pad + p[0] * s, pad + (ext_h - p[1]) * s   # flip y for screen

    parts = [head]
    # 100 mm grid so lengths read off the board directly
    gx = 0.0
    while gx <= ext_w + 1e-6:
        x0, _ = tx((gx, 0))
        parts.append(f'<line x1="{x0:.1f}" y1="{pad:.1f}" x2="{x0:.1f}" '
                     f'y2="{pad + ext_h * s:.1f}" stroke="{bg_line}" '
                     f'stroke-width="{lw * 0.3:.2f}"/>')
        gx += 100.0
    gy = 0.0
    while gy <= ext_h + 1e-6:
        _, y0 = tx((0, gy))
        parts.append(f'<line x1="{pad:.1f}" y1="{y0:.1f}" '
                     f'x2="{pad + ext_w * s:.1f}" y2="{y0:.1f}" '
                     f'stroke="{bg_line}" stroke-width="{lw * 0.3:.2f}"/>')
        gy += 100.0
    # scale bar (redundant in true-scale mode but harmless)
    bar = 100.0 * s
    parts.append(f'<line x1="{pad:.1f}" y1="{H - pad * 0.4:.1f}" '
                 f'x2="{pad + bar:.1f}" y2="{H - pad * 0.4:.1f}" '
                 f'stroke="{sub}" stroke-width="{lw:.1f}"/>'
                 f'<text x="{pad:.1f}" y="{H - pad * 0.4 - fs * 0.5:.1f}" '
                 f'fill="{sub}" font-size="{fs:.1f}">100 mm'
                 f'{" — prints 1:1" if true_scale else ""}</text>')

    # same-connector ties first (under the branches)
    for t in getattr(fb, "ties", []) or []:
        (ax_, ay_), (bx_, by_) = tx(t["a_xy"]), tx(t["b_xy"])
        parts.append(f'<line x1="{ax_:.1f}" y1="{ay_:.1f}" x2="{bx_:.1f}" '
                     f'y2="{by_:.1f}" stroke="{sub}" '
                     f'stroke-width="{lw * 0.45:.2f}" '
                     f'stroke-dasharray="{lw * 2:.1f},{lw * 2:.1f}"/>')
        mx, my = (ax_ + bx_) / 2, (ay_ + by_) / 2
        parts.append(f'<text x="{mx:.1f}" y="{my - fs * 0.4:.1f}" fill="{sub}" '
                     f'font-size="{fs * 0.85:.1f}" font-style="italic">'
                     f'= {t["connector"]}</text>')

    palette = ["#4aa3df", "#e1683c", "#5cb85c", "#b18ad6", "#d9a441",
               "#48b8b8", "#d76a8a", "#7d8c99"]
    if true_scale:
        palette = ["#1665a7", "#b34a1f", "#2e7d32", "#6a3fa0", "#9c7414",
                   "#0f7c7c", "#a83a5e", "#4c5a66"]
    for i, b in enumerate(fb.branches):
        col = palette[i % len(palette)]
        pts = " ".join(f"{tx(p)[0]:.1f},{tx(p)[1]:.1f}" for p in b.points_mm)
        parts.append(f'<polyline points="{pts}" fill="none" stroke="{col}" '
                     f'stroke-width="{lw:.1f}" stroke-linejoin="round" '
                     f'stroke-linecap="round" opacity="0.92"/>')
        # ring the corners that bend tighter than the conductor allows
        radii = getattr(b, "corner_radii_mm", None) or []
        r_ok = getattr(b, "min_bend_radius_mm", 0.0) or 0.0
        for vi, r in enumerate(radii):
            if r is None or vi + 1 >= len(b.points_mm):
                continue
            if r_ok > 0 and r < 1.5 * r_ok:
                cx_, cy_ = tx(b.points_mm[vi + 1])
                bad = r < r_ok
                parts.append(
                    f'<circle cx="{cx_:.1f}" cy="{cy_:.1f}" r="{fs * 0.55:.1f}" '
                    f'fill="none" stroke="{"#e05252" if bad else "#d9a441"}" '
                    f'stroke-width="{lw * 0.7:.2f}"/>')
        if b.points_mm:
            mid = b.points_mm[len(b.points_mm) // 2]
            mx, my = tx(mid)
            parts.append(f'<text x="{mx + fs * 0.4:.1f}" y="{my - fs * 0.4:.1f}" '
                         f'fill="{col}" font-size="{fs:.1f}" font-weight="600">'
                         f'{b.wire} · AWG{b.gauge_awg} · cut '
                         f'{b.cut_length_mm:g} mm</text>')
    for name, (x, y) in fb.nodes.items():
        nx, ny = tx((x, y))
        parts.append(f'<circle cx="{nx:.1f}" cy="{ny:.1f}" r="{fs * 0.5:.1f}" '
                     f'fill="{ink}" stroke="{sub}" '
                     f'stroke-width="{lw * 0.6:.2f}"/>'
                     f'<text x="{nx + fs * 0.7:.1f}" y="{ny + fs * 0.3:.1f}" '
                     f'fill="{ink}" font-size="{fs:.1f}" font-weight="700">'
                     f'{name}</text>')
    parts.append("</svg>")
    return "".join(parts)


def _hn_seed_demo(store):
    """Onboarding: one click drops a small but real example loom in, so the 3-D
    view, checks and formboard all show something meaningful immediately."""
    from suspension.harness import Connector, WireRun
    for c in (Connector("ECU", "electrics", xyz_mm=(0, 0, 250), cavities=24,
                        part_number="DTM-24", strain_relief_mm=25.0,
                        mass_g=32.0, is_estimate=False),
              Connector("MOT", "powertrain", xyz_mm=(1500, 0, 220),
                        cavities=8, part_number="HDP-8", strain_relief_mm=40.0,
                        mass_g=85.0, is_estimate=False),
              Connector("DASH", "data-acquisition", xyz_mm=(-350, 0, 480),
                        cavities=12, part_number="DTM-12",
                        strain_relief_mm=25.0, mass_g=18.0),
              Connector("BSPD", "electrics", xyz_mm=(700, 280, 180),
                        cavities=6, part_number="DT-6", strain_relief_mm=25.0,
                        mass_g=12.0)):
        store.set_connector(c)
    for w in (WireRun("MOT_PWR", "powertrain", gauge_awg=10, net="hv_pwr",
                      from_conn="ECU", to_conn="MOT", service_loop_mm=60.0,
                      path_mm=[(0, 0, 250), (120, 0, 250), (700, 0, 240),
                               (1350, 0, 225), (1500, 0, 220)],
                      clamp_idx=[1, 2, 3],
                      carries_current_a=45.0, is_estimate=False),
              WireRun("DASH_CAN", "data-acquisition", gauge_awg=22, net="can1",
                      from_conn="ECU", to_conn="DASH",
                      path_mm=[(0, 0, 250), (-60, 0, 280), (-200, 0, 400),
                               (-350, 0, 480)], clamp_idx=[2]),
              WireRun("BSPD_SIG", "electrics", gauge_awg=22, net="bspd",
                      from_conn="ECU", to_conn="BSPD",
                      path_mm=[(0, 0, 250), (40, 30, 245), (400, 200, 200),
                               (700, 280, 180)]),
              WireRun("MOT_TEMP", "electrics", gauge_awg=24, net="ntc_mot",
                      from_conn="BSPD", to_conn="MOT",
                      path_mm=[(700, 280, 180), (1050, 160, 200),
                               (1500, 0, 220)])):
        store.set_wire(w)


def _hn_rerun():
    """Rerun just the harness fragment when possible (snappy), falling back to
    a full-app rerun when the fragment is executing inside a full run (where
    scope="fragment" is not permitted)."""
    try:
        st.rerun(scope="fragment")
    except Exception:
        st.rerun()


def render_harness():
    """The 3-D wiring harness section (runs as a fragment so interacting with
    it never reruns the rest of the app)."""
    _render_harness_fragment()


@st.fragment
def _render_harness_fragment():
    from suspension.harness import Connector, WireRun
    import pandas as pd

    # deferred widget resets (a widget key cannot be written after the widget
    # instantiated in the same run, so deletions queue the reset for here)
    if st.session_state.pop("_hn_wire_reset", False):
        st.session_state.pop("hn_wire_sel", None)
    if st.session_state.pop("_hn_conn_reset", False):
        st.session_state.pop("hn_conn_sel", None)
    for _k, _v in (st.session_state.pop("_hn_apply_preset", None) or {}).items():
        st.session_state[_k] = _v

    _MP_EMOJI = {"aerodynamics": "💛", "brakes": "🧡", "chassis": "💜",
                 "cooling": "🩵", "data-acquisition": "💚", "electrics": "💙",
                 "powertrain": "❤️", "suspension": "🩷", "ecu": "🖥️"}
    _SUBS = ["aerodynamics", "brakes", "chassis", "cooling",
             "data-acquisition", "electrics", "powertrain", "suspension"]

    st.markdown("---")
    st.markdown("### 🧵 Harness — the physical loom in 3-D car space")
    st.markdown(
        '<p class="hint">The board above is the copper <i>on the PCB</i>; this '
        'is the copper <i>between the boxes</i>. Route each conductor through '
        'the <b>same car coordinates</b> the mount-points and keep-outs live '
        'in, watch it live in 3-D, and read off — before a single wire is cut '
        '— the exact cut length, the 1:1 printable formboard, the automated '
        'BOM, and the copper mass and where it sits. It measures the route you '
        'declare — <b>and</b> flex-solves it: every unsupported stretch '
        'between clamp points is sagged under its own weight and the declared '
        'vibration level (honest low–high stiffness bounds, stranding '
        'assumption stated), its resonant frequency is screened against the '
        'excitation band, and the <i>drooped</i> shape is re-checked against '
        'the same keep-outs the taut route cleared.</p>',
        unsafe_allow_html=True)

    with st.expander("🙋 New here? How this works in 3 steps (no engineering "
                     "background needed)", expanded=False):
        st.markdown(
            "**1 — Place the boxes.**  A *connector* is just \"a plug on a "
            "box\" — the ECU, a sensor, the dash. Give it a name and where it "
            "sits in the car (x = toward the back, y = to the right, z = up, "
            "all in millimetres — measure from the front axle if unsure). "
            "Don't know a number? Guess and tick *Estimated*; every result "
            "will honestly say it came from a guess.\n\n"
            "**2 — Draw the wires.**  Pick which plug a wire starts and ends "
            "at, pick a *wire type preset* (thick power wire, thin sensor "
            "wire…), and press **✨ Auto-route** — the app lays a clean "
            "straight route for you. Drag the numbers in the little table to "
            "steer it around things. Tick **clamp** on a point wherever a "
            "cable tie or clip will hold the wire to the car.\n\n"
            "**3 — Read the answers.**  The coloured banner tells you if "
            "you're ready to cut wire. **Pre-cut check** lists anything wrong "
            "in plain sentences. **Flex & sag** shows how far each "
            "unsupported stretch will droop and shake — with a one-click "
            "*add a support* fix. **Manufacturing** gives cut lengths, the "
            "shopping list (BOM) and the weight; **Formboard** prints a 1:1 "
            "template to build the loom on. Nothing here needs re-typing — "
            "it's all derived from the route you drew.")

    store = get_store()
    harness = store._ensure_harness()
    res, keepouts = _harness_check_cached(store)

    # ---- always-visible status strip ---- #
    n_fail = sum(1 for f in res.findings if f.severity.value == "fail")
    n_warn = sum(1 for f in res.findings if f.severity.value == "warning")
    bom = res.bom or {}
    md = res.mass or {}
    worst_cls = "bad" if n_fail else ("warn" if n_warn else "good")
    worst_txt = "FAIL" if n_fail else ("WARN" if n_warn else "OK")
    plain_txt = (f"🔴 {n_fail} blocker{'s' if n_fail != 1 else ''} to fix "
                 f"before cutting wire" if n_fail else
                 (f"🟡 cuttable, but {n_warn} thing{'s' if n_warn != 1 else ''} "
                  f"worth fixing" if n_warn else
                  ("✅ ready to cut wire" if harness.wires else "")))
    chip_row = st.columns([5, 1])
    chip_row[0].markdown(
        f'<div style="display:flex;gap:14px;flex-wrap:wrap;align-items:center;'
        f'margin:2px 0 6px 0;">'
        f'<span class="tag {worst_cls}">{worst_txt}</span>'
        f'<span style="font-size:.85rem;color:#e8edf2">{plain_txt}</span>'
        f'<span style="font-size:.85rem;color:#8d99a6">{n_fail} fail · '
        f'{n_warn} warn</span>'
        f'<span style="font-size:.85rem;color:#8d99a6">'
        f'{len(harness.wires)} wires · {len(harness.connectors)} connectors'
        f'</span>'
        f'<span style="font-size:.85rem;color:#8d99a6">'
        f'<b>{uval(bom.get("total_wire_m", 0), "m", fmt="{:.2f}")}</b> wire · '
        f'<b>{uval(md.get("total_copper_g", 0), "g_mass", fmt="{:.0f}")}</b> '
        f'copper</span></div>', unsafe_allow_html=True)
    with chip_row[1].popover("⚙ limits"):
        _amb0 = float(harness.ambient_c)
        _cw0 = float(harness.clearance_warn_mm)
        _cf0 = float(harness.clearance_fail_mm)
        _v0 = (float(harness.vib_g), float(harness.excitation_lo_hz),
               float(harness.excitation_hi_hz), float(harness.max_span_mm),
               float(harness.max_sag_mm))
        harness.ambient_c = st.number_input(
            "Ambient (°C)", -20.0, 150.0, value=_amb0, key="hn_amb")
        harness.clearance_warn_mm = st.number_input(
            "Clearance WARN (mm)", 0.0, 100.0, value=_cw0, key="hn_cw")
        harness.clearance_fail_mm = st.number_input(
            "Clearance FAIL (mm)", 0.0, 50.0, value=_cf0, key="hn_cf")
        st.markdown("**Vibration / flex screen**")
        harness.vib_g = st.number_input(
            "Vibration level (g)", 0.5, 30.0, value=_v0[0], step=0.5,
            key="hn_vg", help="How hard the car shakes the loom, as a "
            "multiple of gravity. 3 g is a sane chassis-mounted default; "
            "engine-mounted runs see 10 g+.")
        _b = st.columns(2)
        harness.excitation_lo_hz = _b[0].number_input(
            "Shake band from (Hz)", 1.0, 2000.0, value=_v0[1], key="hn_bl",
            help="The frequency range the car actually excites (road input + "
            "engine orders). A span whose natural frequency lands inside it "
            "can resonate.")
        harness.excitation_hi_hz = _b[1].number_input(
            "to (Hz)", 5.0, 5000.0, value=_v0[2], key="hn_bh")
        harness.max_span_mm = st.number_input(
            "Max unsupported span (mm)", 50.0, 2000.0, value=_v0[3],
            key="hn_ms", help="Longest run allowed between two supports "
            "(cable ties / clips). 300 mm is common loom practice.")
        harness.max_sag_mm = st.number_input(
            "Max allowed sag (mm)", 1.0, 200.0, value=_v0[4], key="hn_sag",
            help="How far a span may droop at the vibration level before "
            "it's flagged.")
        if (harness.ambient_c, harness.clearance_warn_mm,
                harness.clearance_fail_mm) != (_amb0, _cw0, _cf0) or \
                (harness.vib_g, harness.excitation_lo_hz,
                 harness.excitation_hi_hz, harness.max_span_mm,
                 harness.max_sag_mm) != _v0:
            save_store(store)
            _hn_rerun()

    if not harness.wires and not harness.connectors:
        qc = st.columns([3, 2])
        qc[0].info("Nothing routed yet. Add connectors and wires in the "
                   "**Edit loom** tab — or drop in the example loom to see "
                   "the whole workflow at once.")
        if qc[1].button("🚀 Seed an example loom", key="hn_seed"):
            _hn_seed_demo(store)
            save_store(store)
            _hn_rerun()

    if keepouts:
        st.caption(f"Routing against {len(keepouts)} keep-out volume(s) from "
                   f"the geometry ledger: " +
                   ", ".join(f"{_MP_EMOJI.get(getattr(k, 'owner_subsystem', '?'), '')}"
                             f"{k.name}" for k in keepouts))
    else:
        st.caption("No keep-out volumes declared yet — add them in the "
                   "geometry / mount-point tab to clearance-check the loom "
                   "against reserved space.")

    tab3d, tab_edit, tab_chk, tab_flex, tab_mfg, tab_fb = st.tabs(
        ["🧭 3-D loom", "✏️ Edit loom", "✅ Pre-cut check", "🪢 Flex & sag",
         "🏭 Manufacturing", "📐 Formboard"])

    # ------------------------------ 3-D view ------------------------------ #
    with tab3d:
        if not harness.wires and not harness.connectors:
            st.caption("The 3-D view appears once something is routed.")
        else:
            oc = st.columns([1.6, 1, 1, 1, 1])
            color_by = oc[0].radio("Colour by", ["status", "subsystem"],
                                   horizontal=True, key="hn3d_color",
                                   label_visibility="collapsed")
            show_ko = oc[1].toggle("Keep-outs", value=True, key="hn3d_ko")
            show_pts = oc[2].toggle("Route points", value=True, key="hn3d_pts")
            show_lab = oc[3].toggle("Labels", value=True, key="hn3d_lab")
            show_sag = oc[4].toggle(
                "Sagged shape", value=False, key="hn3d_sag",
                help=f"Dashed: how far each unsupported stretch droops at "
                     f"{harness.vib_g:g} g (upper stiffness bound). Squares "
                     f"mark the clamps holding the wire.")
            sel_wire = st.session_state.get("hn_wire_sel")
            fig = _harness_fig3d(
                harness, res, keepouts, color_by=color_by,
                selected=(sel_wire if sel_wire in harness.wires else None),
                show_keepouts=show_ko, show_vertices=show_pts,
                show_labels=show_lab, show_sag=show_sag)
            st.plotly_chart(fig, width="stretch", key="hn3d_plot",
                            config=dict(displaylogo=False))
            st.caption("✕ = bend tighter than the wire can take · ◇ = closest "
                       "approach / penetration of a keep-out · dotted ○ = route "
                       "endpoint floating off its connector · ▢ = clamp/tie "
                       "support · dashed line = drooped shape under vibration. "
                       "The wire being edited is drawn heavier.")

    # ------------------------------ editors ------------------------------- #
    with tab_edit:
        ec = st.columns(2)

        # ---- connector editor ---- #
        with ec[0]:
            st.markdown("**Connectors** *(end-points / branch nodes)*")
            conn_sel = st.selectbox(
                "Connector", ["➕ New connector"] + list(harness.connectors),
                key="hn_conn_sel")
            if st.session_state.get("_hn_conn_loaded") != conn_sel:
                st.session_state["_hn_conn_loaded"] = conn_sel
                c0 = harness.connectors.get(conn_sel)
                st.session_state["cn_name"] = c0.name if c0 else "ECU"
                st.session_state["cn_own"] = (
                    c0.owner_subsystem if c0 and c0.owner_subsystem in _SUBS
                    else "electrics")
                st.session_state["cn_x"] = float(c0.xyz_mm[0]) if c0 else 0.0
                st.session_state["cn_y"] = float(c0.xyz_mm[1]) if c0 else 0.0
                st.session_state["cn_z"] = float(c0.xyz_mm[2]) if c0 else 0.0
                st.session_state["cn_cav"] = int(c0.cavities) if c0 else 12
                st.session_state["cn_sr"] = float(c0.strain_relief_mm) if c0 else 25.0
                st.session_state["cn_mass"] = float(c0.mass_g or 0.0) if c0 else 0.0
                st.session_state["cn_pn"] = c0.part_number if c0 else "DTM-12"
                st.session_state["cn_est"] = bool(c0.is_estimate) if c0 else False
            cn = st.text_input("Name", key="cn_name")
            cown = st.selectbox("Owned by", _SUBS, key="cn_own")
            cg = st.columns(3)
            cx = cg[0].number_input("x (mm)", -5000.0, 5000.0, key="cn_x",
                                    help="Toward the back of the car.")
            cy = cg[1].number_input("y (mm)", -5000.0, 5000.0, key="cn_y",
                                    help="To the driver's right.")
            cz = cg[2].number_input("z (mm)", -5000.0, 5000.0, key="cn_z",
                                    help="Up from the ground/reference.")
            cg2 = st.columns(3)
            ccav = cg2[0].number_input("Cavities", 1, 200, key="cn_cav",
                                       help="How many pin slots the plug has "
                                            "(counts crimp contacts in the "
                                            "BOM).")
            csr = cg2[1].number_input("Strain relief (mm)", 0.0, 200.0,
                                      key="cn_sr",
                                      help="Wire must leave this plug "
                                           "STRAIGHT for this long before "
                                           "its first bend, or it fatigues "
                                           "at the crimp. 25 mm is typical.")
            cmass = cg2[2].number_input("Mass (g, 0=unknown)", 0.0, 2000.0,
                                        key="cn_mass")
            cpn = st.text_input("Part number", key="cn_pn")
            cest = st.checkbox("Estimated", key="cn_est")
            fb_cols = st.columns(2)
            do_save_c = fb_cols[0].button("💾 Save connector", key="cn_save",
                                          type="primary")
            do_del_c = fb_cols[1].button(
                "✕ Delete", key="cn_delete",
                disabled=conn_sel not in harness.connectors)
            if do_save_c and cn.strip():
                store.set_connector(Connector(
                    name=cn.strip(), owner_subsystem=cown, xyz_mm=(cx, cy, cz),
                    cavities=int(ccav), part_number=cpn, strain_relief_mm=csr,
                    mass_g=(None if cmass == 0.0 else cmass), is_estimate=cest))
                save_store(store)
                st.session_state["_hn_conn_loaded"] = None
                _hn_rerun()
            if do_del_c and conn_sel in harness.connectors:
                store.remove_connector(conn_sel)
                save_store(store)
                st.session_state["_hn_conn_loaded"] = None
                st.session_state["_hn_conn_reset"] = True
                _hn_rerun()
            for name, c in list(harness.connectors.items()):
                est = " · est" if c.is_estimate else ""
                mtxt = uval(c.mass_g, "g_mass") if c.mass_g is not None else "mass —"
                st.markdown(
                    f'<div style="border-left:3px solid var(--line);'
                    f'padding:4px 10px;margin:3px 0;">'
                    f'{_MP_EMOJI.get(c.owner_subsystem, "")} <b>{name}</b> '
                    f'<span style="color:#8d99a6;font-size:.8rem">'
                    f'{c.owner_subsystem} · {c.part_number or "—"}{est}</span><br>'
                    f'<span style="font-size:.82rem;color:#8d99a6">'
                    f'({units_mod.from_metric(c.xyz_mm[0], "mm"):.0f}, '
                    f'{units_mod.from_metric(c.xyz_mm[1], "mm"):.0f}, '
                    f'{units_mod.from_metric(c.xyz_mm[2], "mm"):.0f}) '
                    f'{units_mod.label("mm")} · {c.cavities} cav · {mtxt} · '
                    f'SR {units_mod.from_metric(c.strain_relief_mm, "mm"):.0f} '
                    f'{units_mod.label("mm")}</span></div>',
                    unsafe_allow_html=True)

        # ---- wire editor ---- #
        with ec[1]:
            st.markdown("**Wire runs** *(3-D routed conductors)*")
            conn_names = [""] + list(harness.connectors.keys())
            wire_sel = st.selectbox(
                "Wire", ["➕ New wire"] + list(harness.wires),
                key="hn_wire_sel")
            if st.session_state.get("_hn_wire_loaded") != wire_sel:
                st.session_state["_hn_wire_loaded"] = wire_sel
                st.session_state["_hn_path_nonce"] = \
                    st.session_state.get("_hn_path_nonce", 0) + 1
                w0 = harness.wires.get(wire_sel)
                st.session_state["wr_name"] = w0.name if w0 else "MOT_PWR"
                st.session_state["wr_own"] = (
                    w0.owner_subsystem if w0 and w0.owner_subsystem in _SUBS
                    else "electrics")
                st.session_state["wr_awg"] = int(w0.gauge_awg) if w0 else 10
                st.session_state["wr_net"] = w0.net if w0 else "hv_pwr"
                st.session_state["wr_od"] = float(w0.od_mm or 0.0) if w0 else 0.0
                st.session_state["wr_from"] = (
                    w0.from_conn if w0 and w0.from_conn in conn_names else "")
                st.session_state["wr_to"] = (
                    w0.to_conn if w0 and w0.to_conn in conn_names else "")
                st.session_state["wr_mult"] = \
                    float(w0.bundle_min_radius_mult) if w0 else 6.0
                st.session_state["wr_loop"] = float(w0.service_loop_mm) if w0 else 0.0
                st.session_state["wr_strip"] = float(w0.strip_mm) if w0 else 8.0
                st.session_state["wr_cur"] = \
                    float(w0.carries_current_a or 0.0) if w0 else 0.0
                st.session_state["wr_est"] = bool(w0.is_estimate) if w0 else False
                st.session_state["_hn_path_pts"] = (
                    [list(map(float, p)) for p in w0.path_mm] if w0 and w0.path_mm
                    else [[0.0, 0.0, 0.0], [200.0, 0.0, 0.0],
                          [600.0, 0.0, 100.0], [1200.0, 0.0, 100.0]])
                _n_pts = len(st.session_state["_hn_path_pts"])
                _ci = set(int(i) for i in ((w0.clamp_idx if w0 else None) or []))
                st.session_state["_hn_path_clamp"] = [
                    i in _ci for i in range(_n_pts)]

            wn = st.text_input("Name", key="wr_name")
            wown = st.selectbox("Owned by", _SUBS, key="wr_own")
            _WIRE_PRESETS = {
                "⚡ Power feed — thick (AWG 10)":
                    dict(wr_awg=10, wr_mult=6.0, wr_strip=10.0, wr_net="power"),
                "🔋 Power branch (AWG 16)":
                    dict(wr_awg=16, wr_mult=6.0, wr_strip=8.0, wr_net="power"),
                "🕸 CAN / data pair (AWG 22 — gentle bends)":
                    dict(wr_awg=22, wr_mult=8.0, wr_strip=6.0, wr_net="can"),
                "🌡 Sensor signal — thin (AWG 24)":
                    dict(wr_awg=24, wr_mult=6.0, wr_strip=6.0, wr_net="sensor"),
                "🛰 Shielded / coax (AWG 22 — stiff, 10× bends)":
                    dict(wr_awg=22, wr_mult=10.0, wr_strip=8.0, wr_net="shielded"),
            }
            _pr = st.columns([3, 1])
            _pick = _pr[0].selectbox(
                "Wire type preset (optional — fills the numbers below)",
                list(_WIRE_PRESETS), key="wr_preset",
                help="Not sure what gauge or bend limit to use? Pick the "
                     "closest description and hit Apply — you can still edit "
                     "everything afterwards.")
            if _pr[1].button("Apply", key="wr_preset_go"):
                st.session_state["_hn_apply_preset"] = _WIRE_PRESETS[_pick]
                _hn_rerun()
            wg = st.columns(3)
            wawg = wg[0].number_input("Gauge (AWG)", 8, 30, key="wr_awg",
                                      help="Wire thickness. SMALLER number = "
                                           "THICKER wire. 10 ≈ jumper-cable "
                                           "core, 22 ≈ headphone wire.")
            wnet = wg[1].text_input("Net", key="wr_net")
            wod = wg[2].number_input("OD (mm, 0=AWG nom)", 0.0, 30.0,
                                     key="wr_od")
            wg2 = st.columns(2)
            wfrom = wg2[0].selectbox("From connector", conn_names, key="wr_from")
            wto = wg2[1].selectbox("To connector", conn_names, key="wr_to")
            wg3 = st.columns(3)
            wmult = wg3[0].number_input("Min bend ×OD", 1.0, 20.0, key="wr_mult")
            wloop = wg3[1].number_input("Service loop (mm)", 0.0, 1000.0,
                                        key="wr_loop")
            wstrip = wg3[2].number_input("Strip/end (mm)", 0.0, 100.0,
                                         key="wr_strip")
            wg4 = st.columns(2)
            wcur = wg4[0].number_input("Carries current (A, 0=from net)",
                                       0.0, 1000.0, key="wr_cur")
            west = wg4[1].checkbox("Estimated route", key="wr_est")

            st.caption("3-D route (car coordinates, mm) — add / delete / edit "
                       "points directly. Tick **clamp** wherever a cable tie / "
                       "clip will hold the wire to the car; the flex solver "
                       "sags every stretch between supports:")
            nonce = st.session_state.get("_hn_path_nonce", 0)
            _rows = st.session_state.get("_hn_path_pts") or [[0.0, 0.0, 0.0]]
            _cl = list(st.session_state.get("_hn_path_clamp") or [])
            _cl = (_cl + [False] * len(_rows))[:len(_rows)]
            pdf = pd.DataFrame(
                [[*map(float, p), bool(c)] for p, c in zip(_rows, _cl)],
                columns=["x", "y", "z", "clamp"])
            edited = st.data_editor(
                pdf, num_rows="dynamic", width="stretch",
                key=f"wr_pts_{wire_sel}_{nonce}",
                column_config={
                    **{c: st.column_config.NumberColumn(c, format="%.1f")
                       for c in ("x", "y", "z")},
                    "clamp": st.column_config.CheckboxColumn(
                        "clamp", default=False,
                        help="Tie / clip fixing the wire to the car here. The "
                             "two ends are always held by their connectors.")})

            def _pts_from_editor(df):
                pts, clamps = [], []
                for row in df.itertuples(index=False):
                    try:
                        if any(pd.isna(v) for v in (row.x, row.y, row.z)):
                            continue
                        pts.append((float(row.x), float(row.y), float(row.z)))
                        c = getattr(row, "clamp", False)
                        clamps.append(bool(c) and not pd.isna(c))
                    except (TypeError, ValueError):
                        continue
                return pts, clamps

            def _clamp_idx(pts, clamps):
                return [i for i, c in enumerate(clamps)
                        if c and 0 < i < len(pts) - 1]

            with st.expander("Paste a route instead (x,y,z; x,y,z; …)"):
                wpath_txt = st.text_input("Route string", key="wr_path_txt",
                                          value="")
                if st.button("↪ Import into the table", key="wr_path_import"):
                    pts = _parse_path3d(wpath_txt)
                    if pts:
                        st.session_state["_hn_path_pts"] = [list(p) for p in pts]
                        st.session_state["_hn_path_clamp"] = [False] * len(pts)
                        st.session_state["_hn_path_nonce"] = nonce + 1
                        _hn_rerun()

            bc = st.columns(4)
            if bc[0].button("💾 Save wire", key="wr_save", type="primary"):
                pts, clamps = _pts_from_editor(edited)
                store.set_wire(WireRun(
                    name=wn.strip(), owner_subsystem=wown, gauge_awg=int(wawg),
                    path_mm=pts, from_conn=wfrom, to_conn=wto, net=wnet,
                    od_mm=(None if wod == 0.0 else wod),
                    bundle_min_radius_mult=wmult, service_loop_mm=wloop,
                    strip_mm=wstrip,
                    carries_current_a=(None if wcur == 0.0 else wcur),
                    clamp_idx=_clamp_idx(pts, clamps),
                    is_estimate=west))
                save_store(store)
                st.session_state["_hn_wire_loaded"] = None
                _hn_rerun()
            if bc[1].button("✨ Auto-route", key="wr_auto",
                            help="No coordinates needed: lays a clean route "
                                 "from the 'from' plug to the 'to' plug — a "
                                 "straight lead out of each connector (long "
                                 "enough for its strain relief) and a clamped "
                                 "midpoint you can then drag around things."):
                cf = harness.connectors.get(wfrom)
                ct = harness.connectors.get(wto)
                if cf is None or ct is None:
                    st.warning("Pick both a 'from' and a 'to' connector "
                               "first — auto-route draws between them.")
                else:
                    p0 = np.asarray(cf.xyz_mm, float)
                    p3 = np.asarray(ct.xyz_mm, float)
                    d = float(np.linalg.norm(p3 - p0))
                    if d < 1.0:
                        st.warning("Those two connectors sit on top of each "
                                   "other — move one first.")
                    else:
                        u = (p3 - p0) / d
                        ld0 = max(float(cf.strain_relief_mm), 25.0)
                        ld1 = max(float(ct.strain_relief_mm), 25.0)
                        if ld0 + ld1 > 0.6 * d:
                            ld0 = ld1 = 0.3 * d
                        pts = [p0, p0 + u * ld0, (p0 + p3) / 2.0,
                               p3 - u * ld1, p3]
                        st.session_state["_hn_path_pts"] = \
                            [[float(v) for v in p] for p in pts]
                        st.session_state["_hn_path_clamp"] = \
                            [False, False, True, False, False]
                        st.session_state["_hn_path_nonce"] = nonce + 1
                        _hn_rerun()
            if bc[2].button("🧲 Snap ends to connectors", key="wr_snap",
                            help="Move the first route point onto the 'from' "
                                 "connector and the last onto the 'to' "
                                 "connector, so the cut length is measured "
                                 "plug-to-plug."):
                pts, clamps = _pts_from_editor(edited)
                pts = [list(p) for p in pts]
                cf = harness.connectors.get(wfrom)
                ct = harness.connectors.get(wto)
                if pts and cf is not None:
                    pts[0] = [float(v) for v in cf.xyz_mm]
                if pts and ct is not None:
                    pts[-1] = [float(v) for v in ct.xyz_mm]
                st.session_state["_hn_path_pts"] = pts
                st.session_state["_hn_path_clamp"] = clamps
                st.session_state["_hn_path_nonce"] = nonce + 1
                _hn_rerun()
            if bc[3].button("✕ Delete wire", key="wr_del",
                            disabled=wire_sel not in harness.wires):
                store.remove_wire(wire_sel)
                save_store(store)
                st.session_state["_hn_wire_loaded"] = None
                st.session_state["_hn_wire_reset"] = True
                _hn_rerun()

            for name, w in list(harness.wires.items()):
                est = " · est" if w.is_estimate else ""
                st.markdown(
                    f'<div style="border-left:3px solid var(--line);'
                    f'padding:4px 10px;margin:3px 0;">'
                    f'{_MP_EMOJI.get(w.owner_subsystem, "")} <b>{name}</b> '
                    f'<span style="color:#8d99a6;font-size:.8rem">'
                    f'AWG{w.gauge_awg} · {w.net or "—"}{est}</span><br>'
                    f'<span style="font-size:.82rem;color:#8d99a6">'
                    f'{w.from_conn or "?"} → {w.to_conn or "?"} · '
                    f'cut {units_mod.from_metric(w.cut_length_mm(), "mm"):.0f} '
                    f'{units_mod.label("mm")} · '
                    f'{uval(w.copper_mass_g(), "g_mass", fmt="{:.1f}")} Cu · '
                    f'min bend '
                    f'{units_mod.from_metric(w.min_bend_radius_mm, "mm"):.0f} '
                    f'{units_mod.label("mm")} · '
                    f'{len([i for i in (w.clamp_idx or []) if 0 < int(i) < max(len(w.path_mm) - 1, 1)]) or "no"}'
                    f' clamp(s)</span></div>',
                    unsafe_allow_html=True)

    # --------------------------- the pre-cut gate -------------------------- #
    with tab_chk:
        if res.findings:
            st.markdown(f'<p class="hint">{res.summary()}</p>',
                        unsafe_allow_html=True)
        else:
            st.caption("Add connectors and at least one routed wire to run "
                       "the check.")
        _SEV_CLS = {"fail": "bad", "warning": "warn", "missing": "warn",
                    "info": "", "ok": "good"}
        order = ["fail", "warning", "missing", "info", "ok"]
        for f in sorted(res.findings,
                        key=lambda x: order.index(x.severity.value)):
            cls = _SEV_CLS.get(f.severity.value, "")
            who = " ↔ ".join(f"{_MP_EMOJI.get(x, '')}{x}"
                             for x in f.subsystems) if f.subsystems else ""
            st.markdown(
                f'<div style="border-left:3px solid var(--line);'
                f'padding:6px 12px;margin:4px 0;">'
                f'<span class="tag {cls}">{f.severity.value.upper()}</span> '
                f'<b>{f.check}</b> &nbsp;'
                f'<span style="color:#8d99a6;font-size:.8rem">{who}</span><br>'
                f'<span style="font-size:.92rem">{f.message}</span></div>',
                unsafe_allow_html=True)

    # --------------------- cable flex: sag & resonance --------------------- #
    with tab_flex:
        spans = list(res.flex or [])
        if not harness.wires:
            st.caption("Route at least one wire to solve its sag.")
        elif not spans:
            st.caption("No solvable spans yet — each wire needs a route with "
                       "at least 2 points.")
        else:
            st.markdown(
                f'<p class="hint">Every stretch of wire between two supports '
                f'(the connectors at the ends + every point you ticked '
                f'<b>clamp</b>) is solved as a clamped-clamped elastic beam '
                f'under its own exactly-known weight. Because a stranded '
                f'wire\'s stiffness genuinely depends on how freely its '
                f'strands slip, every answer is an honest <b>low–high '
                f'range</b>: the two ends of the range are the physically '
                f'real limits (fused-solid ↔ {19}-strand free-slip). '
                f'Screened at <b>{harness.vib_g:g} g</b> against the '
                f'<b>{harness.excitation_lo_hz:.0f}–'
                f'{harness.excitation_hi_hz:.0f} Hz</b> excitation band '
                f'(change both under ⚙ limits). Slack a route carries hangs '
                f'geometrically no matter how stiff the wire is — the solver '
                f'adds it in. The drooped shape is also re-checked against '
                f'every keep-out the taut route cleared.</p>',
                unsafe_allow_html=True)

            def _span_issues(sf):
                iss = []
                if sf.chord_mm > harness.max_span_mm:
                    iss.append("too long unsupported")
                if sf.sag_total_hi_mm > harness.max_sag_mm:
                    iss.append("sags past limit")
                if sf.resonant:
                    iss.append("can resonate")
                if sf.chord_mm > 0 and sf.slack_mm / sf.chord_mm > 0.02:
                    iss.append("loose slack (whips)")
                return iss

            rows = []
            for sf in spans:
                iss = _span_issues(sf)
                _cap = sf.chord_mm / 4.0            # same "hangs limp" scale
                _lo1 = min(sf.sag_slack_mm + sf.sag_beam_1g_lo_mm, _cap)
                _hi1 = min(sf.sag_slack_mm + sf.sag_beam_1g_hi_mm, _cap)
                rows.append(dict(
                    wire=sf.wire, span=sf.span + 1,
                    free_span_mm=sf.chord_mm, slack_mm=sf.slack_mm,
                    sag_1g_mm=f"{_lo1:.1f}–{_hi1:.1f}",
                    sag_at_vib_mm=f"{sf.sag_total_lo_mm:g}–"
                                  f"{sf.sag_total_hi_mm:g}"
                                  + ("" if sf.beam_valid else " ⚠ limp"),
                    f1_hz=f"{sf.f1_lo_hz:g}–{sf.f1_hi_hz:g}",
                    resonant=("🔔 yes" if sf.resonant else "no"),
                    verdict=("✅ fine" if not iss else "🟡 " + ", ".join(iss)),
                ))
            _fx_df = pd.DataFrame(rows).rename(columns={
                "free_span_mm": "free span (mm)", "slack_mm": "slack (mm)",
                "sag_1g_mm": "sag @1 g (mm)",
                "sag_at_vib_mm": f"sag @{harness.vib_g:g} g (mm)",
                "f1_hz": "f₁ (Hz)"})
            st.dataframe(_fx_df, hide_index=True, width="stretch")
            st.caption("⚠ limp = drooped beyond small-deflection validity — "
                       "the high number is a stated upper bound, not a "
                       "solution. 🔔 = the span's natural frequency lands "
                       "inside the band the car actually shakes in, so "
                       "vibration can pump it up (assumed amplification "
                       "Q = 15, stated, not measured).")

            bad = [sf for sf in spans if _span_issues(sf)]
            if bad:
                st.markdown("**Fix it in one click** — adding a support "
                            "(cable tie / P-clip) at the middle of a span "
                            "halves it, which cuts sag ~16× and roughly "
                            "quadruples its natural frequency:")
                fx = st.columns([3, 2])
                _lbl = {f"{sf.wire} · span {sf.span + 1} "
                        f"({sf.chord_mm:.0f} mm)": sf for sf in bad}
                pick = fx[0].selectbox("Span to support", list(_lbl),
                                       key="hn_fx_pick",
                                       label_visibility="collapsed")
                if fx[1].button("➕ Add a support at midspan",
                                key="hn_fx_add", type="primary"):
                    sf = _lbl[pick]
                    w = harness.wires.get(sf.wire)
                    if w is not None:
                        path = w.as_polyline()
                        sub = path[sf.i0:sf.i1 + 1]
                        seg = np.linalg.norm(np.diff(sub, axis=0), axis=1)
                        half = float(np.sum(seg)) / 2.0
                        acc, j, t = 0.0, 0, 0.5
                        for k, L in enumerate(seg):
                            if acc + L >= half:
                                j, t = k, ((half - acc) / L if L > 0 else 0.5)
                                break
                            acc += L
                        gi = sf.i0 + j          # global segment start index
                        newp = (sub[j] * (1 - t) + sub[j + 1] * t)
                        pts = [list(map(float, p)) for p in w.path_mm]
                        pts.insert(gi + 1, [float(v) for v in newp])
                        old = set(int(i) for i in (w.clamp_idx or []))
                        w.clamp_idx = sorted(
                            {i if i <= gi else i + 1 for i in old} | {gi + 1})
                        w.path_mm = [tuple(p) for p in pts]
                        store.set_wire(w)
                        save_store(store)
                        st.session_state["_hn_wire_loaded"] = None
                        _hn_rerun()
            with st.expander("What exactly is being solved (and what isn't)"):
                st.markdown(
                    "* **Sag** — each free span is a clamped-clamped "
                    "Euler-Bernoulli beam: δ = qL⁴/384EI, with q from the "
                    "wire's exact copper + jacket mass and EI at both "
                    "stranding bounds. Slack (route longer than the straight "
                    "line) hangs as an inextensible cable, δ ≈ "
                    "c·√(3·slack/8c), regardless of stiffness.\n"
                    "* **Vibration** — the declared g-level is applied "
                    "quasi-statically; **f₁** is the span's first "
                    "clamped-clamped mode. A span whose f₁ range overlaps the "
                    "excitation band gets a resonance warning with a "
                    "screening amplitude at an assumed Q of 15.\n"
                    "* **Not solved** (and never faked): large-deflection "
                    "drape past sag ≈ span/8 (reported as a capped upper "
                    "bound and flagged *limp*), and true modal dynamics of "
                    "the whole assembled loom with bundle interaction.")

    # ---------- manufacturing artefacts: cut list + BOM + mass ------------- #
    with tab_mfg:
      if not harness.wires:
        st.caption("Route at least one wire to roll up the cut list, BOM and "
                   "mass.")
      else:
        mc = st.columns([3, 2])
