# --------------------------- TAB DFMEA ------------------------------------- #
with tab_dfmea:
  try:
    render_process_library("general", key_prefix="dfmea_pl")
  except Exception:
    pass
  try:
    import pandas as _pd_d

    st.header("🧯 DFMEA — Design Failure Mode & Effects Analysis")
    st.caption("Your living Powertrain risk log, in the app next to the FEA, "
               "lap-sim, cooling and tractive-safety tools that close the rows. "
               "RPN, risk bands and the dashboard recompute as you type — no "
               "spreadsheet formulas to babysit.")

    # ---- seed on first open --------------------------------------------- #
    if "dfmea_rows" not in st.session_state:
        st.session_state.dfmea_rows = dfmea_mod.seed_rows()

    _help = st.columns([3, 1, 1])
    _help[0].markdown(
        '<p class="hint" style="margin:2px 0 6px;">Pre-loaded with the User-Guide '
        'failure modes <b>plus active projects</b> (cooling test rig, gear '
        'ratio / sprocket, motor &amp; diff mount, accumulator cooling). Edit '
        'any cell; add rows with the <b>＋</b> at the bottom of the table. One '
        'failure mode per row — keep leak, crack and blockage separate.</p>',
        unsafe_allow_html=True)
    if _help[1].button("↻ Re-seed starter log", key="dfmea_reseed",
                       help="Rebuild the example log from the User Guide + active "
                            "projects. Your manual edits are replaced."):
        st.session_state.dfmea_rows = dfmea_mod.seed_rows()
        st.rerun()
    if _help[2].button("🗑 Clear all rows", key="dfmea_clear",
                       help="Empty the log to start from scratch."):
        st.session_state.dfmea_rows = []
        st.rerun()

    # ---- import an existing workbook ------------------------------------ #
    with st.expander("📥 Import an existing DFMEA (.xlsx / .csv) — column names "
                     "are matched automatically", expanded=False):
        _up = st.file_uploader("Spreadsheet with DFMEA rows", type=["xlsx", "csv"],
                               key="dfmea_upload",
                               help="Columns are matched case-insensitively to the "
                                    "User-Guide names; RPN is recomputed. Extra "
                                    "columns are ignored.")
        _imode = st.radio("On import", ["Append to current log", "Replace current log"],
                          horizontal=True, key="dfmea_import_mode")
        if _up is not None and st.button("Import rows", key="dfmea_do_import"):
            try:
                _axn.engage("dfmea", "import_rows")
            except Exception:
                pass
            try:
                if _up.name.lower().endswith(".csv"):
                    _idf = _pd_d.read_csv(_up)
                else:
                    _idf = _pd_d.read_excel(_up)
                _recs = [dfmea_mod.row_from_mapping(r).to_record()
                         for r in _idf.to_dict("records")]
                if _imode.startswith("Replace"):
                    st.session_state.dfmea_rows = _recs
                else:
                    st.session_state.dfmea_rows = (
                        st.session_state.dfmea_rows + _recs)
                st.success(f"Imported {len(_recs)} row(s).")
                try:
                    _axn.complete("dfmea", "import_rows")
                except Exception:
                    pass
                st.rerun()
            except Exception as _e:
                st.error(f"Couldn't read that file: {_e}")
                try:
                    _axn.error("dfmea", _e, kind="import_failed")
                except Exception:
                    pass

    # ---- rating-scale reference (the consistency anchor) ---------------- #
    with st.expander("📊 Rating scales — Severity · Occurrence · Detection (1–10)",
                     expanded=False):
        st.caption("Score on evidence, not optimism. Severity reflects the "
                   "consequence and never drops just because detection is good.")
        _sc1, _sc2, _sc3 = st.columns(3)
        _sc1.markdown("**Severity (S)** — how bad if it reaches the car")
        _sc1.table(_pd_d.DataFrame(
            [(k, v) for k, v in dfmea_mod.SEVERITY_SCALE.items()],
            columns=["S", "Meaning"]).set_index("S"))
        _sc2.markdown("**Occurrence (O)** — likelihood with current controls")
        _sc2.table(_pd_d.DataFrame(
            [(k, v) for k, v in dfmea_mod.OCCURRENCE_SCALE.items()],
            columns=["O", "Meaning"]).set_index("O"))
        _sc3.markdown("**Detection (D)** — chance a check catches it first")
        _sc3.table(_pd_d.DataFrame(
            [(k, v) for k, v in dfmea_mod.DETECTION_SCALE.items()],
            columns=["D", "Meaning"]).set_index("D"))

    # ---- the editable risk log ------------------------------------------ #
    _view = feature_menu("dfmea",
                         ["📝 Risk log", "📈 Dashboard", "✅ Action tracker"],
                         title="DFMEA tools",
                         descriptions={
                             "📝 Risk log": "The editable failure-mode table (RPN, risk band)",
                             "📈 Dashboard": "Risk distribution & top items",
                             "✅ Action tracker": "Open mitigations and owners"})

    # Build the working DataFrame with a live RPN + Risk Band for display.
    _df = _pd_d.DataFrame(st.session_state.dfmea_rows,
                          columns=dfmea_mod.COLUMNS) if st.session_state.dfmea_rows \
        else _pd_d.DataFrame(columns=dfmea_mod.COLUMNS)

    def _recompute(df):
        if df.empty:
            df["RPN"] = []
            df["Risk Band"] = []
            return df
        df = df.copy()
        df["RPN"] = [dfmea_mod.compute_rpn(s, o, d) for s, o, d in
                     zip(df["Severity"], df["Occurrence"], df["Detection"])]
        df["Risk Band"] = [dfmea_mod.classify_risk(s, r).value for s, r in
                           zip(df["Severity"], df["RPN"])]
        return df

    if _view == "📝 Risk log":
        st.markdown(
            '<p class="hint" style="margin:6px 0 2px;"><b>RPN = S × O × D</b>, '
            'recomputed live. A high-Severity row is flagged even at moderate RPN '
            '— review those first. <b>Closed</b> needs evidence in the last '
            'column.</p>', unsafe_allow_html=True)

        _num = st.column_config.NumberColumn  # alias
        _edited = st.data_editor(
            _df, width="stretch", num_rows="dynamic", key="dfmea_editor",
            column_config={
                "Subsystem": st.column_config.SelectboxColumn(
                    "Subsystem", options=dfmea_mod.SUBSYSTEM_OPTIONS, required=True,
                    width="small"),
                "Item / Component": st.column_config.TextColumn(
                    "Item / Component", width="medium"),
                "Function / Requirement": st.column_config.TextColumn(
                    "Function / Requirement", width="medium"),
                "Failure Mode": st.column_config.TextColumn(
                    "Failure Mode", width="medium"),
                "Effect of Failure": st.column_config.TextColumn(
                    "Effect of Failure", width="medium"),
                "Severity": _num("S", min_value=1, max_value=10, step=1,
                                 help="Consequence if it reaches the car (1–10)."),
                "Potential Cause / Mechanism": st.column_config.TextColumn(
                    "Potential Cause / Mechanism", width="medium"),
                "Occurrence": _num("O", min_value=1, max_value=10, step=1,
                                   help="Likelihood with current prevention (1–10)."),
                "Prevention Controls": st.column_config.TextColumn(
                    "Prevention Controls", width="medium"),
                "Detection Controls": st.column_config.TextColumn(
                    "Detection Controls", width="medium"),
                "Detection": _num("D", min_value=1, max_value=10, step=1,
                                  help="Chance current checks catch it first (1–10)."),
                "RPN": _num("RPN", disabled=True, help="S × O × D — auto."),
                "Recommended Action": st.column_config.TextColumn(
                    "Recommended Action", width="medium"),
                "Owner": st.column_config.TextColumn("Owner", width="small",
                                                     help="One accountable person."),
                "Due Date": st.column_config.TextColumn("Due Date", width="small"),
                "Status": st.column_config.SelectboxColumn(
                    "Status", options=dfmea_mod.STATUS_OPTIONS, required=True,
                    width="small"),
                "Evidence / Notes": st.column_config.TextColumn(
                    "Evidence / Notes", width="medium"),
            })

        # Persist edits (store the canonical columns only; RPN is derived).
        _clean = _edited[dfmea_mod.COLUMNS].copy() if not _edited.empty \
            else _pd_d.DataFrame(columns=dfmea_mod.COLUMNS)
        st.session_state.dfmea_rows = _clean.to_dict("records")

        # Live data-quality nudges from the User-Guide "definition of done".
        _stats = dfmea_mod.dashboard_stats(st.session_state.dfmea_rows)
        _flags = []
        if _stats.actions_without_owner:
            _flags.append(f"{_stats.actions_without_owner} open action(s) have "
                          f"**no owner** — assign one accountable person each.")
        if _stats.closed_without_evidence:
            _flags.append(f"{_stats.closed_without_evidence} row(s) marked "
                          f"**Closed** with no evidence — a row isn't closed until "
                          f"it has objective proof.")
        if _flags:
            st.warning("  \n".join("• " + f for f in _flags))
        else:
            st.success("No data-quality flags — every open action has an owner and "
                       "every Closed row has evidence.")

    elif _view == "📈 Dashboard":
        _stats = dfmea_mod.dashboard_stats(st.session_state.dfmea_rows)
        if _stats.total == 0:
            st.info("No rows yet. Add some in the Risk log view (or re-seed the "
                    "starter log).")
        else:
            mc = st.columns(4)
            mc[0].metric("Risks logged", f"{_stats.total}")
            mc[1].metric("Open high-risk", f"{_stats.open_high_risk}",
                         help="Critical/High band rows not yet Closed or Accepted.")
            mc[2].metric("Open high-severity", f"{_stats.high_sev_open}",
                         help="Severity ≥ 7 and not resolved — review separately "
                              "from RPN.")
            mc[3].metric("Closed w/o evidence", f"{_stats.closed_without_evidence}",
                         delta=None,
                         delta_color="inverse")

            gc = st.columns([2, 3])
            # risk-band donut
            _band_order = ["Critical", "High", "Medium", "Low"]
            _band_col = {"Critical": "#ff5a52", "High": "#ffb02e",
                         "Medium": "#37e0d0", "Low": "#5ad17a"}
            _bvals = [_stats.by_band.get(b, 0) for b in _band_order]
            _fb = go.Figure(go.Pie(
                labels=_band_order, values=_bvals, hole=0.55,
                marker=dict(colors=[_band_col[b] for b in _band_order]),
                sort=False))
            _fb.update_layout(
                title="Risk by priority band", height=320,
                paper_bgcolor="rgba(0,0,0,0)", font=dict(color="#cdd6df", size=11),
                margin=dict(l=0, r=0, t=36, b=0),
                legend=dict(bgcolor="rgba(0,0,0,0)"))
            gc[0].plotly_chart(_fb, width="stretch", key="dfmea_band_pie")

            # risk concentration by subsystem (User-Guide §7)
            _bysub = sorted(_stats.by_subsystem.items(),
                            key=lambda kv: kv[1], reverse=True)
            _fs = go.Figure(go.Bar(
                x=[v for _, v in _bysub], y=[k for k, _ in _bysub],
                orientation="h", marker_color="#37e0d0",
                text=[v for _, v in _bysub], textposition="auto"))
            _fs.update_layout(
                title="Risk concentration by subsystem", height=320,
                xaxis_title="rows", paper_bgcolor="rgba(0,0,0,0)",
                plot_bgcolor="rgba(0,0,0,0)", font=dict(color="#cdd6df", size=11),
                margin=dict(l=0, r=0, t=36, b=0))
            _fs.update_yaxes(autorange="reversed")
            gc[1].plotly_chart(_fs, width="stretch", key="dfmea_sub_bar")

            st.markdown("**Top risks — review these first**")
            _topdf = _pd_d.DataFrame(_stats.top_rows)
            if not _topdf.empty:
                _show = _topdf[["Risk Band", "RPN", "Subsystem", "Item / Component",
                                "Failure Mode", "Severity", "Status"]]
                st.dataframe(_show, width="stretch", hide_index=True)

            if _stats.open_high_risk:
                st.warning(f"{_stats.open_high_risk} high-risk item(s) are still "
                           "open. Before competition, every high-severity / "
                           "high-RPN row should have an action, owner and closure "
                           "evidence.")
            else:
                st.success("No open high-risk items — nice. Keep re-scoring after "
                           "each test as real data comes in.")

    else:  # Action tracker
        _items = dfmea_mod.action_items(st.session_state.dfmea_rows)
        st.markdown(
            '<p class="hint" style="margin:2px 0 8px;">Every open row with a '
            'recommended action, sorted by risk. This is the execution list — a '
            'risk is closed when the action has objective evidence, not when the '
            'cell says “done”.</p>', unsafe_allow_html=True)
        if not _items:
            st.success("No open actions — every recommended action is on a Closed "
                       "or Accepted row, or there are no actions yet.")
        else:
            _adf = _pd_d.DataFrame(_items)
            st.dataframe(_adf, width="stretch", hide_index=True,
                         column_config={
                             "RPN": st.column_config.NumberColumn("RPN", disabled=True),
                         })
            _acsv = _adf.to_csv(index=False)
            st.download_button("⬇ Export action tracker (.csv)", _acsv,
                               file_name="powertrain_dfmea_actions.csv",
                               mime="text/csv", key="dfmea_action_export")

    # ---- export (always available, all views) --------------------------- #
    st.markdown('<p class="hint" style="margin:10px 0 2px;border-top:1px solid '
                'var(--grid);padding-top:8px;">Export the full log in the same '
                'column layout as your workbook — drop it straight into the team '
                'sheet or the design-review packet.</p>', unsafe_allow_html=True)
    _outdf = _recompute(_pd_d.DataFrame(st.session_state.dfmea_rows,
                                        columns=dfmea_mod.COLUMNS)) \
        if st.session_state.dfmea_rows else _pd_d.DataFrame(columns=dfmea_mod.COLUMNS)
    _ecols = st.columns(2)
    _full_csv = _outdf.to_csv(index=False)
    _ecols[0].download_button("⬇ Export DFMEA (.csv)", _full_csv,
                              file_name="FSAE_Powertrain_DFMEA.csv",
                              mime="text/csv", key="dfmea_csv_export")
    # Excel export (best-effort; falls back to a caption if no engine).
    try:
        import io as _io_d
        _buf = _io_d.BytesIO()
        with _pd_d.ExcelWriter(_buf, engine="openpyxl") as _xw:
            _outdf.to_excel(_xw, index=False, sheet_name="DFMEA")
        _ecols[1].download_button(
            "⬇ Export DFMEA (.xlsx)", _buf.getvalue(),
            file_name="FSAE_Powertrain_DFMEA.xlsx",
            mime="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
            key="dfmea_xlsx_export")
    except Exception:
        _ecols[1].caption("Install `openpyxl` for .xlsx export (CSV works now).")

    st.caption("DFMEA is a living document — update it whenever the design "
               "changes or a test reveals something new, and re-score "
               "Occurrence/Detection once an action truly reduces the risk.")
  except Exception as _e:
    st.error(f"The DFMEA workbench hit an error: {_e}")
    with st.expander("Details"):
        st.exception(_e)




# =========================================================================== #
#  🗂️  REGISTRY — the component "Source of Truth"                              #
# --------------------------------------------------------------------------- #
#  Replaces the "here's a Drive link, sorry the folder's a mess" workflow with #
#  a dashboard that always shows the CURRENT, verified version of each part,   #
#  the numbers that matter (offset, mass, material…), who signed it off, and a #
#  one-click pull of the exact released file. Ingest parses real provenance    #
#  out of the CAD itself instead of just storing a blob.                       #
# =========================================================================== #
REGISTRY_PATH = os.path.join(os.getcwd(), "registry.json")


def _registry():
    """Load (once per rerun) the on-disk registry into session state."""
    reg = registry_mod.Registry(REGISTRY_PATH)
    return reg


def _status_tag(status):
    cls = {"verified": "good", "unverified": "warn",
           "superseded": "bad", "empty": "tag"}.get(status, "tag")
    label = {"verified": "✓ Verified", "unverified": "● Unverified",
             "superseded": "↩ Superseded", "empty": "○ No file"}.get(
                 status, status)
    return f'<span class="tag {cls}">{label}</span>'


with tab_registry:
    st.markdown(
        '<div class="brand"><span class="mark">Registry</span>'
        '<span class="sub">Source of truth · released CAD</span></div>',
        unsafe_allow_html=True)

    st.markdown(
        '<div class="wt-intro"><div class="ic">◢</div><div>'
        '<p>One table, always current. Each component shows its <b>latest '
        'verified version</b>, the numbers that matter, who signed it off, and '
        'a one-click pull of the exact released file — so a part lives here, not '
        'in a Drive link buried in a chat.</p>'
        '<p>Add a version by dropping the CAD/assembly bundle (or pasting a '
        'link). KinematiK reads the provenance straight out of the file — model '
        'name, units, CAD system, author, FEA mesh — instead of just storing a '
        'blob.</p></div></div>',
        unsafe_allow_html=True)

    try:
        reg = _registry()
        rows = reg.summary_rows()

        # ----- headline metrics ------------------------------------------- #
        _verified = sum(1 for r in rows if r["status"] == "verified")
        _unver = sum(1 for r in rows if r["status"] in ("unverified", "empty"))
        _m1, _m2, _m3 = st.columns(3)
        _m1.markdown(
            f'<div class="metric"><div class="k">Components</div>'
            f'<div class="v">{len(rows)}</div></div>', unsafe_allow_html=True)
        _m2.markdown(
            f'<div class="metric"><div class="k">Verified current</div>'
            f'<div class="v" style="color:var(--cyan)">{_verified}</div></div>',
            unsafe_allow_html=True)
        _m3.markdown(
            f'<div class="metric"><div class="k">Needs sign-off</div>'
            f'<div class="v" style="color:var(--amber)">{_unver}</div></div>',
            unsafe_allow_html=True)

        st.markdown("")

        # ----- the dashboard table ---------------------------------------- #
        if not rows:
            st.markdown(
                '<div class="card"><b>No components yet.</b><br>'
                '<span class="hint">Add your first one below — start with the '
                'part everyone keeps re-sharing (the diff mount is a good '
                'first row).</span></div>', unsafe_allow_html=True)
        else:
            st.markdown("#### Current versions")
            for r in rows:
                cur = reg.get(r["comp_id"]).current()
                with st.container():
                    c_name, c_ver, c_status, c_act = st.columns([3, 2.4, 1.8, 1.4])
                    with c_name:
                        st.markdown(
                            f'**{r["name"]}**  '
                            f'<span class="tag">{r["subteam"]}</span>',
                            unsafe_allow_html=True)
                        if r["owner"]:
                            st.caption(f'Owner · {r["owner"]}')
                    with c_ver:
                        st.markdown(f'`{r["version"]}`')
                        # the specs that matter — shown inline as the golden record
                        if r["specs"]:
                            _spec_txt = "  ·  ".join(
                                f"**{k}** {v}" for k, v in r["specs"].items())
                            st.markdown(
                                f'<span class="hint">{_spec_txt}</span>',
                                unsafe_allow_html=True)
                    with c_status:
                        st.markdown(_status_tag(r["status"]),
                                    unsafe_allow_html=True)
                        if r["verified_by"]:
                            st.caption(f'{r["verified_by"]} · '
                                       f'{r["verified_on"][:10]}')
                    with c_act:
                        # one-click export: pull the verified bytes or open link
                        _bp = reg.blob_path(cur) if cur else None
                        if _bp and os.path.exists(_bp):
                            with open(_bp, "rb") as _fh:
                                if st.download_button(
                                    "⬇ Get file", _fh.read(),
                                    file_name=cur.blob_name or os.path.basename(_bp),
                                    key=f"dl_{r['comp_id']}",
                                    use_container_width=True):
                                    _axn.engage("registry", "pull_file")
                                    _axn.complete("registry", "pull_file")
                        elif r["link"]:
                            st.link_button("↗ Open link", r["link"],
                                           use_container_width=True)
                        else:
                            st.caption("no file")
                    st.markdown(
                        '<hr style="border:none;border-top:1px solid var(--line);'
                        'margin:.35rem 0;">', unsafe_allow_html=True)

        # ----- per-component management ----------------------------------- #
        if rows:
            st.markdown("#### Manage a component")
            _names = {r["name"]: r["comp_id"] for r in rows}
            _sel_name = st.selectbox("Component", list(_names.keys()),
                                     key="reg_manage_sel")
            _cid = _names[_sel_name]
            _comp = reg.get(_cid)
            _cur = _comp.current()

            _mc1, _mc2 = st.columns([1.3, 1])
            with _mc1:
                # --- the golden-record specs editor ----------------------- #
                st.markdown("**Declared numbers** — the golden record")
                st.caption("These show on the dashboard. The diff-mount offset "
                           "lives here so nobody re-reads it off a chat message.")
                if _cur:
                    _sk1, _sk2, _sk3 = st.columns([1.3, 1.3, .6])
                    _new_k = _sk1.text_input("Name", key=f"spec_k_{_cid}",
                                             placeholder="Offset")
                    _new_v = _sk2.text_input("Value", key=f"spec_v_{_cid}",
                                             placeholder="42.0 mm")
                    _sk3.markdown("<div style='height:1.7rem'></div>",
                                  unsafe_allow_html=True)
                    if _sk3.button("Set", key=f"spec_set_{_cid}",
                                   use_container_width=True):
                        if _new_k.strip():
                            reg.set_spec(_cid, _cur.id, _new_k.strip(),
                                         _new_v.strip())
                            reg.save()
                            st.rerun()
                    if _cur.specs:
                        for _k, _v in list(_cur.specs.items()):
                            _r1, _r2 = st.columns([4, .8])
                            _r1.markdown(f"`{_k}` → **{_v}**")
                            if _r2.button("✕", key=f"spec_del_{_cid}_{_k}"):
                                reg.set_spec(_cid, _cur.id, _k, "")
                                reg.save()
                                st.rerun()
                else:
                    st.caption("Add a version first.")

                # --- status-dashboard rules (the metadata validator) ------ #
                st.markdown("**Pass/fail rules** — drives the front-page status")
                st.caption("Declare what “OK” means for the numbers above. No "
                           "CAD parsing — just number-vs-threshold. These turn "
                           "the home page red or green.")
                from suspension import status_dashboard as _sd_mod
                _rules = list(_comp.rules or [])
                # existing rules with delete
                for _ri, _rule in enumerate(_rules):
                    _rc1, _rc2 = st.columns([5, .8])
                    _tgt = _rule.get("value")
                    _tgt_s = (f"[{_tgt[0]}, {_tgt[1]}]"
                              if isinstance(_tgt, (list, tuple)) else _tgt)
                    _rc1.markdown(
                        f'`{_rule.get("param")}` **{_rule.get("op")}** '
                        f'{_tgt_s} {_rule.get("unit","")}')
                    if _rc2.button("✕", key=f"rule_del_{_cid}_{_ri}"):
                        _rules.pop(_ri)
                        reg.set_rules(_cid, _rules)
                        reg.save()
                        st.rerun()
                # add a rule
                _rk1, _rk2, _rk3, _rk4 = st.columns([1.5, .9, 1.2, .7])
                _param = _rk1.text_input("Parameter", key=f"rule_p_{_cid}",
                                         placeholder="Weight",
                                         label_visibility="collapsed")
                _op = _rk2.selectbox("op", ["<=", "<", ">=", ">", "==", "between"],
                                     key=f"rule_op_{_cid}",
                                     label_visibility="collapsed")
                _val = _rk3.text_input("value", key=f"rule_v_{_cid}",
                                       placeholder="2.5  or  41,43",
                                       label_visibility="collapsed")
                _rk4.markdown("<div style='height:.1rem'></div>",
                              unsafe_allow_html=True)
                if _rk4.button("Add", key=f"rule_add_{_cid}",
                               use_container_width=True):
                    if _param.strip() and _val.strip():
                        if _op == "between":
                            _parts = [p for p in re.split(r"[,\s]+", _val.strip())
                                      if p]
                            try:
                                _value = [float(_parts[0]), float(_parts[1])]
                            except (ValueError, IndexError):
                                _value = None
                        else:
                            _value = _sd_mod.coerce_number(_val)
                        if _value is not None:
                            _rules.append({
                                "param": _param.strip(), "op": _op,
                                "value": _value, "unit": "",
                                "label": _param.strip()})
                            reg.set_rules(_cid, _rules)
                            reg.save()
                            st.rerun()
                        else:
                            st.warning("Enter a number (or two for 'between').")
                # quick-add from templates
                _tpl = st.selectbox(
                    "Quick-add a standard rule",
                    ["—"] + list(_sd_mod.DEFAULT_RULE_TEMPLATES.keys()),
                    key=f"rule_tpl_{_cid}")
                if _tpl != "—" and st.button("Add standard rule",
                                             key=f"rule_tpl_add_{_cid}"):
                    _rules.append(_sd_mod.template_for(_tpl))
                    reg.set_rules(_cid, _rules)
                    reg.save()
                    st.rerun()

            with _mc2:
                # --- sign-off -------------------------------------------- #
                st.markdown("**Sign-off**")
                if _cur:
                    st.markdown(_status_tag(_cur.status),
                                unsafe_allow_html=True)
                    _who = st.text_input("Verified by (lead)",
                                         value=_cur.verified_by,
                                         key=f"verby_{_cid}")
                    if st.button("✓ Mark current version verified",
                                 key=f"verify_{_cid}",
                                 use_container_width=True):
                        if _who.strip():
                            reg.verify_version(_cid, _cur.id, _who.strip())
                            reg.save()
                            st.success("Signed off and timestamped.")
                            st.rerun()
                        else:
                            st.warning("Name the lead who checked it first.")
                    st.caption("Confirm with the subsystem lead before relying "
                               "on a part — sign-off records that you did.")

            # --- provenance + FEA read-out (ingest payoff) ---------------- #
            if _cur and (_cur.provenance or _cur.manifest):
                with st.expander("What KinematiK read out of this file", True):
                    _prov = _cur.provenance or {}
                    if _prov:
                        _pcols = st.columns(2)
                        _fields = [
                            ("Model", _prov.get("model_name")),
                            ("CAD system", _prov.get("cad_system")),
                            ("Units", _prov.get("units")),
                            ("Author", _prov.get("author")),
                            ("Exported", _prov.get("exported")),
                            ("Source folder", _prov.get("source_dir")),
                        ]
                        for _i, (_lab, _val) in enumerate(
                                [f for f in _fields if f[1]]):
                            _pcols[_i % 2].markdown(
                                f'<span class="hint">{_lab}</span><br>'
                                f'<code>{_val}</code>', unsafe_allow_html=True)
                    # FEA studies found inside the bundle
                    _man = _cur.manifest or {}
                    _fea = [f for f in _man.get("files", [])
                            if f.get("parsed", {}).get("format", "").startswith(
                                "SW Simulation")]
                    if _fea:
                        st.markdown("**FEA studies in this bundle**")
                        for _f in _fea:
                            _p = _f["parsed"]
                            if "nodes" in _p:
                                st.markdown(
                                    f'<span class="tag good">{_f["name"]}</span> '
                                    f'<span class="hint">{_p.get("nodes","?")} '
                                    f'nodes · {_p.get("elements","?")} elements · '
                                    f'solve {_p.get("solve_time","?")}</span>',
                                    unsafe_allow_html=True)
                            else:
                                st.markdown(
                                    f'<span class="tag">{_f["name"]}</span> '
                                    f'<span class="hint">'
                                    f'{_p.get("study","study")} · '
                                    f'{_p.get("solver_mode","")}</span>',
                                    unsafe_allow_html=True)
                    if _man.get("kinds"):
                        _kt = " · ".join(f"{v} {k}"
                                         for k, v in _man["kinds"].items())
                        st.caption(f"Bundle · {_man.get('file_count', 0)} files "
                                   f"· {ingest_mod.human_size(_man.get('total_bytes', 0))} "
                                   f"· {_kt}")

            # --- version history ------------------------------------------ #
            _hist = _comp.history()
            if _hist:
                with st.expander(f"Version history ({len(_hist)} older)"):
                    for _v in _hist:
                        _h1, _h2 = st.columns([4, 1])
                        _h1.markdown(
                            f'`{_v.label}` {_status_tag(_v.status)} '
                            f'<span class="hint">{_v.created[:16]}</span>',
                            unsafe_allow_html=True)
                        if _h2.button("Make current", key=f"mc_{_v.id}",
                                      use_container_width=True):
                            reg.set_current(_cid, _v.id)
                            reg.save()
                            st.rerun()

        st.markdown("---")

        # ----- add a component / version ---------------------------------- #
        st.markdown("#### Add a version")
        _ac1, _ac2 = st.columns(2)
        with _ac1:
            _existing = ["➕ New component…"] + [r["name"] for r in rows]
            _target = st.selectbox("Component", _existing, key="reg_add_target")
            if _target == "➕ New component…":
                _new_name = st.text_input("New component name",
                                          placeholder="Differential Mount",
                                          key="reg_new_name")
                _new_team = st.selectbox(
                    "Subteam",
                    ["suspension", "powertrain", "aero", "electrics",
                     "cooling", "brakes", "chassis", "dataacq", "cost"],
                    key="reg_new_team")
                _new_owner = st.text_input("Owner (optional)",
                                           key="reg_new_owner")
            _ver_label = st.text_input(
                "Version label",
                value="Rev " + _datetime.date.today().strftime("%b %d %Y"),
                key="reg_ver_label")
            _ver_notes = st.text_area("Notes (optional)", key="reg_ver_notes",
                                      height=70)

        with _ac2:
            _mode = st.radio("Where's the file?",
                             ["Upload CAD bundle", "Just a link"],
                             key="reg_file_mode", horizontal=True)
            _upload = None
            _link = ""
            if _mode == "Upload CAD bundle":
                _upload = st.file_uploader(
                    "Drop a .zip of the folder, or a single CAD file",
                    type=["zip", "sldprt", "sldasm", "slddrw", "igs", "iges",
                          "step", "stp", "stl", "obj", "glb", "x_t", "x_b"],
                    key="reg_upload",
                    help="A zip of the whole released folder is ideal — "
                         "KinematiK parses every file inside it.")
                st.caption("Bytes are stored locally (content-addressed) so the "
                           "exact released file is always one click away.")
            else:
                _link = st.text_input("Link (Drive, etc.)",
                                      placeholder="https://drive.google.com/…",
                                      key="reg_link")

        if st.button("Add to registry", type="primary", key="reg_commit",
                     use_container_width=True):
            # resolve / create the component
            if _target == "➕ New component…":
                _nm = (st.session_state.get("reg_new_name") or "").strip()
                if not _nm:
                    st.warning("Name the component first.")
                    st.stop()
                _comp_obj = reg.get_by_name(_nm) or reg.add_component(
                    _nm,
                    subteam=st.session_state.get("reg_new_team", "suspension"),
                    owner=st.session_state.get("reg_new_owner", ""))
            else:
                _comp_obj = reg.get_by_name(_target)

            _kw = dict(label=_ver_label, notes=_ver_notes)
            if _upload is not None:
                _data = _upload.getvalue()
                _man = ingest_mod.ingest_bundle(_upload.name, _data)
                reg.store_blob(_data, _man["bundle_sha"], _upload.name)
                _kw.update(blob_sha=_man["bundle_sha"], blob_name=_upload.name,
                           provenance=_man["provenance"], manifest=_man)
                # auto-seed obvious specs from provenance so the row isn't empty
                _seed = {}
                _p = _man["provenance"]
                if _p.get("units"):
                    _seed["Units"] = _p["units"]
                if _man.get("file_count"):
                    _seed["Files"] = str(_man["file_count"])
                _kw["specs"] = _seed
            elif _link.strip():
                _kw.update(link=_link.strip())
            else:
                st.warning("Add a file or a link.")
                st.stop()

            _v = reg.add_version(_comp_obj.id, **_kw)
            reg.save()
            _axn.engage("registry", "add_version")
            _axn.complete("registry", "add_version")
            if _upload is not None and _v and _v.provenance.get("model_name"):
                st.success(f"Added — read “{_v.provenance['model_name']}” "
                           f"({_v.provenance.get('cad_system', 'CAD')}, "
                           f"{_man['file_count']} files). Set the verified "
                           f"offset above, then sign it off.")
            else:
                st.success("Added to the registry.")
            st.rerun()

        # ----- export the whole registry ---------------------------------- #
        st.markdown("---")
        _ex1, _ex2 = st.columns([1, 3])
        with _ex1:
            _reg_json = json.dumps(
                {"components": [c.to_dict() for c in reg.components]}, indent=2)
            st.download_button("⬇ Registry (.json)", _reg_json,
                               file_name="registry.json",
                               mime="application/json",
                               key="reg_export",
                               use_container_width=True)
        with _ex2:
            st.caption("The registry persists to `registry.json` in the project "
                       "folder — commit it to the repo and the table travels "
                       "with the car. Stored CAD blobs live alongside it in "
                       "`registry_blobs/`.")

    except Exception as _reg_e:
        _axn.error("registry", _reg_e)
        st.error(f"The Registry hit an error: {_reg_e}")
        with st.expander("Details"):
            st.exception(_reg_e)




# =========================================================================== #
#  📊  ANALYTICS — usage telemetry & ROI dashboard                            #
# --------------------------------------------------------------------------- #
#  Reads the metric views defined in suspension/analytics_schema.sql and turns #
#  months of real event data into the board slide: foot traffic, individual   #
#  use, latency, error rate, retention, time-to-first-result, the adoption    #
#  funnel, and the headline hours-saved -> dollars. Degrades gracefully with  #
#  no Supabase (shows the locally-buffered events so the page is never blank). #
# =========================================================================== #
def _ax_local_events():
    """Read locally-buffered events (offline / pre-Supabase) so the dashboard
    can show *something* real before the DB fills up."""
    path = os.path.join(os.getcwd(), "analytics_buffer.jsonl")
    if not os.path.exists(path):
        return []
    out = []
    try:
        with open(path) as f:
            for line in f:
                line = line.strip()
                if line:
                    out.append(json.loads(line))
    except Exception:
        pass
    return out


def _ax_metric(col, label, value, sub="", color="var(--ink)"):
    col.markdown(
        f'<div class="metric"><div class="k">{label}</div>'
        f'<div class="v" style="color:{color}">{value}</div>'
        f'<div class="u">{sub}</div></div>', unsafe_allow_html=True)


with tab_analytics:
    # Operator debug panels (instrumentation + visitor-identity diagnostics) are
    # hidden from normal users. They render only when the app is opened with the
    # URL parameter ?debug=1 (also accepts debug=true/on/yes). This keeps the
    # tracking-health tools available to whoever runs the deployment without
    # cluttering the page for everyone else.
    try:
        _ax_dbg_val = st.query_params.get("debug", "")
        if isinstance(_ax_dbg_val, (list, tuple)):
            _ax_dbg_val = _ax_dbg_val[0] if _ax_dbg_val else ""
        _ax_debug_on = str(_ax_dbg_val).lower() in ("1", "true", "on", "yes")
    except Exception:
        _ax_debug_on = False

    st.markdown(
        '<div class="brand"><span class="mark">Analytics</span>'
        '<span class="sub">Usage · reliability · ROI</span></div>',
        unsafe_allow_html=True)

    st.markdown(
        '<div class="wt-intro"><div class="ic">◢</div><div>'
        '<p>Every interaction with KinematiK is logged automatically, so by '
        'review season there are <b>months of real data</b> behind the pitch — '
        'not vibes. The headline is <b>hours saved → dollars</b>: completed '
        'workflows × (manual time − in-tool time) × labour rate.</p>'
        '<p class="hint">Anonymous by default (a per-session id). A member name '
        'is recorded only if someone enters one below.</p>'
        '</div></div>', unsafe_allow_html=True)

    _live = False
    try:
        _live = _axn.is_live()
    except Exception:
        _live = False

    # optional: let the member attach their name to this session (opt-in)
    _ac1, _ac2 = st.columns([2, 3])
    with _ac1:
        _nm = st.text_input("Your name (optional — for per-member stats)",
                            value=st.session_state.get("_ax_member", ""),
                            key="_ax_name_field",
                            placeholder="leave blank to stay anonymous")
        if _nm.strip() and _nm.strip() != st.session_state.get("_ax_member"):
            st.session_state["_ax_member"] = _nm.strip()
            try:
                _axn.init(member=_nm.strip())
            except Exception:
                pass
    with _ac2:
        if _live:
            st.markdown('<span class="tag good">● Supabase connected — live data</span>',
                        unsafe_allow_html=True)
            # Write-health: surface whether events are actually LANDING in the
            # DB right now. Silent write failures (buffered to an ephemeral
            # local file, never replayed) are what freeze the date/identity
            # metrics — make that visible instead of guessing.
            try:
                _wh = _axn.write_health()
                if _wh.get("ok") is False:
                    st.markdown(
                        '<span class="tag warn">⚠ Writes FAILING — events are '
                        'being buffered locally, not saved. Metrics will freeze '
                        'until this clears.</span>', unsafe_allow_html=True)
                    if _wh.get("error"):
                        st.caption(f"Last write error: {_wh['error']}")
                    st.caption(f"Buffered this session: {_wh.get('buffered', 0)} "
                               f"event(s). Click replay below once the DB is "
                               f"reachable, or they auto-replay next session.")
                elif _wh.get("ok") is True:
                    st.caption(f"✅ Writes OK — {_wh.get('sent', 0)} event(s) "
                               f"saved this session.")
            except Exception:
                pass
            if st.button("Replay any locally-buffered events", key="ax_replay"):
                n = _axn.replay_local_buffer()
                st.success(f"Replayed {n} buffered events into Supabase.")
        else:
            st.markdown('<span class="tag warn">● No Supabase — showing local buffer. '
                        'Run analytics_schema.sql and set SUPABASE_URL/KEY to go live.</span>',
                        unsafe_allow_html=True)

    st.markdown("---")

    # ----- pull the views (Supabase), cached + minimal --------------------- #
    # Reads go through the 5-minute cache (suspension/analytics_cache.py) so
    # repeated Streamlit reruns don't re-query Supabase. And only the THREE views
    # the minimal tab needs are fetched (ROI, retention, error rate) instead of
    # 11 — roughly a quarter of the read egress. The "Refresh now" button busts
    # the cache for an immediate live pull.
    from suspension.analytics_cache import (
        fetch_view_cached as _fetch_view,
        clear_cache as _clear_view_cache,
    )
    if st.button("\U0001F504 Refresh now", key="ax_refresh_views",
                 help="Fetch the latest numbers from the database right now "
                      "(otherwise refreshes automatically every 5 minutes)."):
        _clear_view_cache()
        st.rerun()

    roi = _fetch_view("v_roi_summary")
    retention = _fetch_view("v_retention")
    errors = _fetch_view("v_error_rate")

    # ---- Headline tiles ---------------------------------------------------- #
    # ACCURACY CONTRACT (why this section looks the way it does):
    #   Two kinds of number, never blended into one tile:
    #     (A) LIVE — measured from analytics_events via the views, covering the
    #         current rolling retention window (the table is capped, so this is a
    #         window figure, not lifetime — see analytics_hard_cap.sql).
    #     (B) BASELINE — the real pre-purge usage recorded from the live dashboard
    #         on 2026-07-10 (user counts), kept as a dated snapshot in its own row.
    #         Its dollar figure is a rounded ESTIMATE (hours back-derived from it),
    #         so it is labelled as an estimate, not presented as measured.
    #   (A) and (B) are shown in SEPARATE rows and never added together.
    _baseline = None
    try:
        _bl = _fetch_view("analytics_baseline")
        if _bl:
            _baseline = _bl[0]
    except Exception:
        _baseline = None

    _base_total = int((_baseline or {}).get("total_users_ever", 0) or 0)
    _base_return = int((_baseline or {}).get("returning_users", 0) or 0)
    _base_dollars = float((_baseline or {}).get("dollars_saved", 0) or 0)
    _base_as_of = str((_baseline or {}).get("as_of", "") or "")

    # ---- LIVE figures (measured, current window only) --------------------- #
    _live_total = 0
    _live_return = 0
    _live_ret_pct = None
    _win_start = None
    _win_end = None
    _have_retention = bool(retention)
    if retention:
        _rt = retention[0]
        _live_total = int(_rt.get("total_users", 0) or 0)
        _live_return = int(_rt.get("returning_users", 0) or 0)
        # Trust the view's own retention_pct when present (it computes it over
        # the same deduplicated user set), else derive it.
        _rp = _rt.get("retention_pct")
        _live_ret_pct = (float(_rp) if _rp is not None
                         else (100.0 * _live_return / _live_total if _live_total else 0.0))
        # Live window bounds (earliest/latest event still retained). Present
        # only if the view exposes them (older deployments may not yet).
        _win_start = _rt.get("window_start")
        _win_end = _rt.get("window_end")

    # ROI view. Distinguish "view returned zero savings" from "view is missing /
    # was dropped by analytics_minimal_views.sql". If v_roi_summary is absent we
    # must NOT quietly fall back to the baseline and imply it is live.
    _roi_available = bool(roi) and (roi[0].get("total_hours_saved") is not None)
    _live_hours = 0.0
    _live_dollars = 0.0
    _rate = 65.0
    if _roi_available:
        _rate = float(roi[0].get("labour_rate_usd_hr") or 65.0)
        _live_hours = float(roi[0].get("total_hours_saved") or 0)
        # Prefer the DB's own dollar figure; fall back to hours × rate.
        _live_dollars = float(roi[0].get("total_dollars_saved")
                              if roi[0].get("total_dollars_saved") is not None
                              else _live_hours * _rate)

    # Reliability — measured; ✓ if error rate <= 2%. No data => nothing broken.
    _reliable = True
    _err_pct = None
    if errors:
        _tot_runs = sum((e.get("attempts", 0) or 0) for e in errors)
        _tot_errs = sum((e.get("failures", 0) or 0) for e in errors)
        _err_pct = (100.0 * _tot_errs / _tot_runs) if _tot_runs else 0.0
        _reliable = _err_pct <= 2.0

    # ===== ROW 1: LIVE (measured, current window) ========================== #
    # Header shows a FIXED cycle-start anchor (the 2026-07-10 purge, from the
    # baseline's as_of) so people know when this counting cycle began — PLUS an
    # honest note that the live tiles count a rolling 30-day window, since the
    # hard cap trims older events. The two together are truthful: a fixed anchor
    # for context, and a clear statement of what the number actually covers.
    _cycle_start = _base_as_of or "2026-07-10"   # fixed anchor: when tracking reset
    _win_note = ""
    if _win_start:
        _win_note = (f" · live tiles below count the current window "
                     f"({_win_start} – {_win_end or 'today'})")
    st.markdown(
        '<div class="k" style="opacity:.75;margin:.2rem 0 .4rem;">'
        f'Live · measured from event data · <b>counting cycle started '
        f'{_cycle_start}</b>{_win_note}</div>',
        unsafe_allow_html=True)
    st.caption("The cycle started on the fixed date above (when tracking was "
               "reset). The live figures show a rolling 30-day window — older "
               "events are trimmed to keep the database small — so they reflect "
               "recent activity, not the whole cycle since that date.")
    _c1, _c2, _c3, _c4 = st.columns(4)

    if _have_retention:
        _ax_metric(_c1, "Active users", f"{_live_total}", "last 30 days")
        _ax_metric(_c2, "Returning", f"{_live_ret_pct:.0f}%",
                   f"{_live_return} of {_live_total} · last 30 days", "var(--cyan)")
    else:
        _ax_metric(_c1, "Active users", "—", "no live data yet")
        _ax_metric(_c2, "Returning", "—", "no live data yet", "var(--cyan)")

    if _roi_available:
        _ax_metric(_c3, "Value (est.)", f"${_live_dollars:,.0f}",
                   f"≈{_live_hours:,.0f} h × ${_rate:,.0f}/hr · estimate",
                   "var(--amber)")
    else:
        # v_roi_summary missing/empty — say so instead of showing the baseline
        # here as though it were live.
        _ax_metric(_c3, "Value (est.)", "n/a",
                   "ROI view not available — run analytics_schema.sql",
                   "var(--amber)")

    if _err_pct is not None:
        _ax_metric(_c4, "Reliability", "✓" if _reliable else "✗",
                   f"{_err_pct:.1f}% error rate",
                   "var(--cyan)" if _reliable else "var(--amber)")
    else:
        _ax_metric(_c4, "Reliability", "✓", "no errors recorded", "var(--cyan)")

    st.caption("“Value” is an estimate: completed workflows × (assumed manual "
               "time − in-tool time) × labour rate, using the per-feature time "
               "baselines in feature_baselines. It is only as accurate as those "
               "assumptions.")





# ========================================================================== #
#  🧭 FRAMES & DATUMS — team coordinate convention charter, live datum watch,
#  frame Rosetta, migration wizard and sign-convention linter.
#
#  Why this tab exists (verbatim from a real team's Discord): "should i
#  change my model to sae coordinates?... it might be a full redo", "wait
#  what are we defining as x and y", "we won't rly know the center of
#  gravity until the master assembly is completely put together... the
#  chassis changes length sometimes, so relativity to the front axle
#  changes too". One declared frame, one watched origin, one-click
#  migration. Logic lives in coordinate_frames.py (pure, self-tested).
# ========================================================================== #
with tab_frames:
    try:
        import coordinate_frames as _cframes

        def _live_hardpoints():
            """Current hardpoint set as {name: (x,y,z)} in the KinematiK
            internal frame (mm, front-axle datum). Scalar design-intent keys
            (static_camber etc.) are filtered out; only 3-vectors pass."""
            hp = st.session_state.get("hp", {}) or {}
            labels = dict(POINTS + ROCKER_POINTS)
            out = {}
            for k, v in hp.items():
                if isinstance(v, (list, tuple)) and len(v) == 3:
                    try:
                        out[labels.get(k, k)] = (float(v[0]), float(v[1]),
                                                 float(v[2]))
                    except (TypeError, ValueError):
                        continue
            if not out:
                raise ValueError("no 3-vector hardpoints in session yet — "
                                 "open the Kinematics tab once first")
            return out, "the live suspension hardpoint editor"

        _cframes.render(get_store=get_store, points_provider=_live_hardpoints)
    except Exception as _cf_err:
        # The convention tool must never take the studio down with it.
        st.error(f"Frames & Datums failed to load: {_cf_err}")

st.markdown('<p class="hint" style="padding-top:.4rem;">Open source · AGPL-3.0. '
            '<i>Tip: on the hosted app, save your project before closing the tab — '
            'geometry tweaks aren\'t auto-saved the way the handover log is.</i></p>',
            unsafe_allow_html=True)

# --- End-of-run memory hygiene (bottom of the script) --------------------- #
# Bound the one unbounded-growth structure (the activity log) and run a
# THROTTLED collection: a full gc.collect() only every Nth rerun instead of on
# every single interaction, so we keep memory flat without adding a stall to
# every click. See suspension/mem_utils.py for the thresholds.
_mem.cap_session_log()
_mem.maybe_collect()
